INSERT INTO `jeux` (`id_jeu`, `nom_jeu`, `annee`, `age_requis`, `nb_succes`, `nb_avis_pos`, `nb_avis_neg`, `temps_jeu_moyen`, `prix`, `description`, `configuration`, `ventes_AN`, `ventes_EU`, `ventes_JP`, `ventes_Autre`, `ventes_Global`) VALUES
(1, 'grand theft auto v', '2015', 18, 77, 329061, 139308, 9837, 24.99, 'Los Santos is a city of bright lights, long nights and dirty secrets, and they don’t come brighter, longer or dirtier than in GTA Online: After Hours. The party starts now.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li>Requires a 64-bit processor and operating system<br></li><li><strong>OS:</strong> Windows 10 64 Bit, Windows 8.1 64 Bit, Windows 8 64 Bit, Windows 7 64 Bit Service Pack 1<br></li><li><strong>Processor:</strong> Intel Core 2 Quad CPU Q6600 @ 2.40GHz (4 CPUs) / AMD Phenom 9850 Quad-Core Processor (4 CPUs) @ 2.5GHz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA 9800 GT 1GB / AMD HD 4870 1GB (DX 10, 10.1, 11)<br></li><li><strong>Storage:</strong> 72 GB available space<br></li><li><strong>Sound Card:</strong> 100% DirectX 10 compatible<br></li><li><strong>Additional Notes:</strong> Over time downloadable content and programming changes will change the system requirements for this game. Please refer to your hardware manufacturer and <a href=\"https://steamcommunity.com/linkfilter/?url=http://www.rockstargames.com/support\" target=\"_blank\" rel=\"noopener\" >www.rockstargames.com/support</a> for current compatibility information. Some system components such as mobile chipsets, integrated, and AGP graphics cards may be incompatible. Unlisted specifications may not be supported by publisher. Other requirements: Installation and online play requires log-in to Rockstar Games Social Club (13+) network; internet connection required for activation, online play, and periodic entitlement verification; software installations required including Rockstar Games Social Club platform, DirectX , Chromium, and Microsoft Visual C++ 2008 sp1 Redistributable Package, and authentication software that recognizes certain hardware attributes for entitlement, digital rights management, system, and other support purposes. SINGLE USE SERIAL CODE REGISTRATION VIA INTERNET REQUIRED; REGISTRATION IS LIMITED TO ONE ROCKSTAR GAMES SOCIAL CLUB ACCOUNT (13+) PER SERIAL CODE; ONLY ONE PC LOG-IN ALLOWED PER SOCIAL CLUB ACCOUNT AT ANY TIME; SERIAL CODE(S) ARE NON-TRANSFERABLE ONCE USED; SOCIAL CLUB ACCOUNTS ARE NON-TRANSFERABLE. Partner Requirements: Please check the terms of service of this site before purchasing this software.</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li>Requires a 64-bit processor and operating system<br></li><li><strong>OS:</strong> Windows 10 64 Bit, Windows 8.1 64 Bit, Windows 8 64 Bit, Windows 7 64 Bit Service Pack 1<br></li><li><strong>Processor:</strong> Intel Core i5 3470 @ 3.2GHz (4 CPUs) / AMD X8 FX-8350 @ 4GHz (8 CPUs)<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GTX 660 2GB / AMD HD 7870 2GB<br></li><li><strong>Storage:</strong> 72 GB available space<br></li><li><strong>Sound Card:</strong> 100% DirectX 10 compatible<br></li><li><strong>Additional Notes:</strong> </li></ul>\'}', '23,46', '23,04', '1,39', '8,03', '55,92'),
(2, 'grand theft auto san andreas', '2008', 18, 0, 26877, 3243, 807, 9.99, 'Five years ago Carl Johnson escaped from the pressures of life in Los Santos, San Andreas... a city tearing itself apart with gang trouble, drugs and corruption. Where filmstars and millionaires do their best to avoid the dealers and gangbangers. Now, it\'s the early 90s. Carl\'s got to go home.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Microsoft® Windows® 2000/XP<br></li><li><strong>Processor:</strong> 1Ghz Pentium III or AMD Athlon Processor<br></li><li><strong>Memory:</strong> 256MB of RAM<br></li><li><strong>Graphics:</strong> 64MB Video Card (Geforce 3 or better)<br></li><li><strong>Hard Drive:</strong> 3.6GB of free hard disk space (minimal install)<br></li><li><strong>Other Requirements:</strong> Software installations required including DirectX and Sony DADC SecuROM<br></li><li><strong>Partner Requirements:</strong> Please check the terms of service of this site before purchasing this software.</li></ul>\', \'recommended\': \'Recommended:<br><ul class=\"bb_ul\"><li><strong>Processor:</strong> Intel Pentium 4 or AMD Athlon XP Processor<br></li><li><strong>Memory:</strong> 384MB of RAM (the more the better!)<br></li><li><strong>Graphics:</strong> 128MB (or greater) Video Card (Geforce 6 Series Recommended)<br></li><li><strong>Hard Drive:</strong> 4.7GB of free hard disk space (full install)<br></li><li><strong>Sound Card:</strong> DirectX 9 compatible Sound Card (Sound Blaster Auidgy 2 Recommended)</li></ul>\'}', '10,77', '1,96', '0,41', '10,72', '23,86'),
(3, 'grand theft auto vice city', '2011', 18, 0, 9817, 819, 209, 5.99, 'Welcome to Vice City. Welcome to the 1980s. From the decade of big hair, excess and pastel suits comes a story of one man\'s rise to the top of the criminal pile.', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Microsoft® Windows® 2000/XP<br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 800 MHz Intel Pentium III or 800 MHz AMD Athlon or 1.2GHz Intel Celeron or 1.2 GHz AMD Duron processor<br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 128 MB of RAM<br>\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 32 MB video card with DirectX 9.0 compatible drivers (&quot;GeForce&quot; or better)<br>\\t\\t\\t\\t\\t</li><li><strong>DirectX Version:</strong> Microsoft DirectX® 9.0<br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 915 MB of free hard disk space (+ 635 MB if video card does NOT support DirectX Texture Compression)<br>\\t\\t\\t\\t\\t</li><li><strong>Sound Card:</strong> Sound Card with DirectX 9.0</li></ul><strong>Recommended:</strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>Processor:</strong> Intel Pentium IV or AMD Athlon XP processor 256(+) MB of RAM<br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1.55 GB of free hard disk space(+ 635 MB if video card does NOT support DirectX Texture Compression)<br>\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 64(+) MB video card with DirectX 9.0 compatible drivers (&quot;GeForce 3&quot; / &quot;Radeon 8500&quot; or better with DirectX Texture Compression support)</li></ul>\'}', '8,41', '5,52', '0,47', '1,79', '16,19'),
(4, 'call of duty black ops', '2010', 18, 68, 14201, 1839, 2672, 29.99, 'The biggest first-person action series of all time and the follow-up to critically acclaimed Call of Duty®: Modern Warfare 2 returns with Call of Duty®: Black Ops.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® Vista / XP / 7<br>\\t\\t\\t\\t\\t\\t\\t\\t </li><li><strong>Processor:</strong> Intel® Core™2 Duo E6600 or AMD Phenom™ X3 8750 or better<br>\\t\\t\\t\\t\\t\\t\\t\\t </li><li><strong>Memory:</strong> 2GB<br>\\t\\t\\t\\t\\t\\t\\t\\t </li><li><strong>Graphics:</strong> Shader 3.0 or better 256MB NVIDIA® GeForce® 8600GT / ATI Radeon® X1950Pro or better<br>\\t\\t\\t\\t\\t\\t\\t \\t </li><li><strong>DirectX®:</strong> DirectX® 9.0c<br>\\t\\t\\t\\t\\t\\t\\t\\t </li><li><strong>Hard Drive:</strong> 12GB*<br>\\t\\t\\t\\t\\t\\t\\t\\t </li><li><strong>Sound:</strong> DirectX® 9.0c-compatible<br>\\t\\t\\t\\t\\t\\t\\t </li></ul>\\t\\t\\t\\t\\t\\t\\t *Call of Duty®: Black Ops requires an initial hard drive space of approximately 24GB to download and install the game via digital download (8GB of compressed files, 8GB of decompressed files and 8GB of installed files). Upon installing the game, 16GB (compressed and decompressed files) may be deleted from the hard drive. Please make note of where the compressed and decompressed files are being saved on your hard drive in order to later locate these temporary files for removal.\'}', '17,59', '9,5', '0,59', '3,36', '31,03'),
(5, 'call of duty black ops ii', '2012', 18, 35, 25827, 4658, 524, 39.99, 'Pushing the boundaries of what fans have come to expect from the record-setting entertainment franchise, Call of Duty®: Black Ops II propels players into a near future Cold War', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista SP2 or Windows 7. <strong>Windows XP is not supported</strong><br></li><li><strong>Processor:</strong> Intel Core2 Duo E8200 2.66 GHz or AMD Phenom X3 8750 2.4 GHz<br></li><li><strong>Memory:</strong> 2 GB for 32-bit OS or 4 GB for 64-bit OS<br></li><li><strong>Graphics:</strong> Nvidia GeForce 8800GT 512 MB or ATI Radeon HD 3870 512 MB<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Hard Drive:</strong> 16 GB<br></li><li><strong>Sound:</strong> DirectX 11.0c compatible<br></li><li><strong>Additional:</strong> Broadband connection required for activation and multiplayer gameplay<br></li><li><strong>Note:</strong> <strong>Windows XP Operating System is not supported</strong><br></li><li><strong>Further information:</strong> Available <a href=\"https://steamcommunity.com/linkfilter/?url=http://community.callofduty.com/community/call_of_duty/english/black_ops_2/blog/2012/09/02/pc-specifications-technology-enhancements-intel\" target=\"_blank\" rel=\"noopener\" >here</a></li></ul>\'}', '14,08', '11,05', '0,72', '3,88', '29,72'),
(6, 'call of duty modern warfare 2', '2009', 0, 50, 30006, 2826, 999, 19.99, 'The most-anticipated game of the year and the sequel to the best-selling first-person action game of all time, Modern Warfare 2 continues the gripping and heart-racing action as players face off against a new threat dedicated to bringing the world to the brink of collapse.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Microsoft Windows XP or Windows Vista (Windows 95/98/ME/2000 are unsupported)<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Pentium 4 3.2 GHz or AMD Athlon 64 3200+ processor or better supported<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1 GB RAM<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 256 MB NVIDIA GeForce 6600GT or better or ATI Radeon 1600XT or better<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> Microsoft DirectX(R) 9.0c<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 12GB of free hard drive space<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> 100% DirectX 9.0c compatible sound card<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Internet:</strong> Broadband connection and service required for Multiplayer Connectivity. Internet Connection required for activation.<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Co-op/Multiplayer Hosting:</strong> To host Co-op or MP matches, a 2Ghz dual-core or better processor is recommended.<br>\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '13,52', '8,11', '0,46', '3,01', '25,09'),
(7, 'grand theft auto iii', '2008', 18, 0, 4718, 750, 98, 5.99, 'Welcome to Liberty City. Where it all began. With stellar voice acting, a darkly comic storyline, a stunning soundtrack and revolutionary open-world gameplay, Grand Theft Auto III is the game that defined the open world genre for a generation.', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Microsoft® Windows® 2000/XP<br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Pentium III® 450 MHz CPU<br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 96 MB RAM<br>\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 16 MB Direct 3D Video Card<br>\\t\\t\\t\\t\\t</li><li><strong>DirectX Version:</strong> Microsoft DirectX® 8.1<br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 500 MB uncompressed free hard disk space<br>\\t\\t\\t\\t\\t</li><li><strong>Sound Card:</strong>Fully DirectX compatible Sound Card</li></ul><strong>Recommended:</strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>Processor:</strong> 700 MHz CPU<br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 128 MB RAM<br>\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 32 MB Direct3D Video Card</li></ul>\'}', '6,99', '4,52', '0,3', '1,3', '13,11'),
(8, 'grand theft auto iv', '2008', 0, 0, 35240, 18926, 1255, 19.99, 'What does the American dream mean today? For Niko Bellic fresh off the boat from Europe, it is the hope he can escape from his past. For his cousin, Roman, it is the vision that together they can find fortune in Liberty City, gateway to the land of opportunity.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista - Service Pack 1 / Windows XP - Service Pack 3 <br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Core 2 Duo 1.8GHz, AMD Athlon X2 64 2.4GHz <br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1.5GB XP / 1.5GB Vista <br>\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 256MB Nvidia 7900 / 256MB ATI X1900 <br>\\t\\t\\t\\t\\t</li><li><strong>DirectX Version:</strong> DirectX 9.0c Compliant Card <br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 16GB of Hard Disc Space <br>\\t\\t\\t\\t\\t</li><li><strong>Sound Card:</strong> 5.1 Channel Audio Card <br>\\t\\t\\t\\t\\t</li><li><strong>Other Requirements:</strong> Initial activation requires internet connection; Online play requires log-in to Games For Windows - Live and Rockstar Games Social Club (13+ to register); software installations required including Adobe Flash, DirectX, Microsoft’s .NET Framework 3.0, Games For Windows - LIVE, and Internet Explorer. </li></ul>\'}', '11,53', '7,65', '0,58', '2,73', '22,47'),
(9, 'call of duty ghosts', '2014', 16, 40, 14892, 10757, 266, 39.99, 'Outnumbered and outgunned, but not outmatched.Call of Duty®: Ghosts is an extraordinary step forward for one of the largest entertainment franchises of all-time. This new chapter in the Call of Duty® franchise features a new dynamic where players are on the side of a crippled nation fighting not for freedom, or liberty, but simply to...', '{\'minimum\': \'<strong> Minimum</strong><br><br><ul class=\"bb_ul\"><li><strong>OS</strong>: Windows 7 64-Bit / Windows 8 64-Bit<br><strong>CPU</strong>: Intel® Core™ 2 Duo E8200 2.66 GHZ / AMD Phenom™ X3 8750 2.4 GHZ or better<br><strong>RAM</strong>: 6 GB RAM<br><strong>HDD</strong>\\t: 40 GB HD space<br><strong>Video</strong>: NVIDIA® GeForce™ GTS 450 / ATI® Radeon™ HD 5870 or better<br><strong>Sound</strong>: DirectX® compatible sound card<br><strong>DirectX®</strong>: DirectX® 11<br><strong>Internet</strong>: Broadband connection and service required for Multiplayer Connectivity. Internet connection required for activation.</li></ul>\', \'recommended\': \'<strong> Recommended</strong><br><br><ul class=\"bb_ul\"><li><strong>OS</strong>: Windows 7 64-Bit / Windows 8 64-Bit<br><strong>CPU</strong>: Intel® Core™ i5 – 680 @ 3.6GHz <br><strong>RAM</strong>: 8 GB RAM<br><strong>HDD</strong>\\t: 40 GB HD space<br><strong>Video</strong>: NVIDIA® GeForce™ GTX 760 @ 4GB <br><strong>Sound</strong>: DirectX® compatible sound card<br><strong>DirectX®</strong>: DirectX® 11<br><strong>Internet</strong>: Broadband connection and service required for Multiplayer Connectivity. Internet connection required for activation.</li></ul>\'}', '14,92', '9,05', '0,48', '2,92', '27,38'),
(10, 'final fantasy vii', '2013', 12, 36, 11722, 878, 2443, 9.99, 'In Midgar, a city controlled by the mega-conglomerate Shinra Inc., the No. 1 Mako Reactor has been blown up by a rebel group, AVALANCHE.AVALANCHE was secretly formed to wage a rebellion against Shinra Inc., an organisation which is absorbing Mako energy, destroying the natural resources of the planet.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong>Microsoft Windows XP/Vista/7 (32/64bits)<br>\\t</li><li><strong>Processor:</strong>2GHz<br>\\t</li><li><strong>Memory:</strong>1 GB RAM<br>\\t</li><li><strong>Graphics:</strong>DirectX 9.0c-compatible graphic card<br>\\t</li><li><strong>DirectX®:</strong>9.0c<br>\\t</li><li><strong>Hard Drive:</strong>3 GB HD space</li></ul><i>Requires a Square Enix account.</i>\'}', '3,01', '2,47', '3,28', '0,96', '9,72'),
(11, 'call of duty 4 modern warfare', '2007', 0, 0, 8725, 821, 1417, 19.99, 'The new action-thriller from the award-winning team at Infinity Ward, the creators of the Call of Duty® series, delivers the most intense and cinematic action experience ever. Call of Duty 4: Modern Warfare arms gamers with an arsenal of advanced and powerful modern day firepower and transports them to the most treacherous hotspots...', '{\'minimum\': \'<strong>Minimum: </strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>Supported OS: </strong>Microsoft® Windows® XP/Vista (Windows 95/98/ME/2000 are unsupported)<br>\\t\\t\\t\\t\\t</li><li><strong>DirectX Version: </strong>Microsoft DirectX 9.0c (included)<br>\\t\\t\\t\\t\\t</li><li><strong>Processor: </strong>Intel® Pentium® 4 2.4 Ghz / AMD(R) 64 (TM) 2800+ / Intel® and AMD® 1.8 Ghz Dual Core Processor or better supported<br>\\t\\t\\t\\t\\t</li><li><strong>Memory: </strong>512MB RAM (Windows® XP), 768MB RAM (Vista®)<br>\\t\\t\\t\\t\\t</li><li><strong>Graphics: </strong>NVIDIA Geforce 6600 or better or ATI Radeon® 9800Pro or better<br>\\t\\t\\t\\t\\t</li><li><strong>Sound: </strong>100% DirectX 9.0c compatible sound card<br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive: </strong>8GB of free hard drive space<br>\\t\\t\\t\\t\\t</li><li><strong>Internet: </strong>Broadband connection and service required for multiplayer connectivity</li></ul>\'}', '9,97', '5,82', '0,42', '2,05', '18,25'),
(12, 'the elder scrolls v skyrim', '2011', 16, 75, 237303, 14951, 7089, 9.99, 'EPIC FANTASY REBORN The next chapter in the highly anticipated Elder Scrolls saga arrives from the makers of the 2006 and 2008 Games of the Year, Bethesda Game Studios. Skyrim reimagines and revolutionizes the open-world fantasy epic, bringing to life a complete virtual world open for you to explore any way you choose.', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7/Vista/XP PC (32 or 64 bit)<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Dual Core 2.0GHz or equivalent processor<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2GB System RAM<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space:</strong> 6GB free HDD Space<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Video Card:</strong> Direct X 9.0c compliant video card with 512 MB of RAM<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX compatible sound card<br>\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br>\\t\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>Processor:</strong> Quad-core Intel or AMD CPU<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 4GB System RAM<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Video Card:</strong> DirectX 9.0c compatible NVIDIA or AMD ATI video card with 1GB of RAM (Nvidia GeForce GTX 260 or higher; ATI Radeon 4890 or higher)<br>\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '8,73', '7,66', '0,35', '2,54', '19,28'),
(13, 'the sims 3', '2011', 0, 0, 11679, 2493, 4730, 24.99, 'New content for The Sims 3 is now available!', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP (Service Pack 2) or Windows Vista (Service Pack 1)<br>\\t</li><li><strong>Processor:</strong> (XP) 2.0 GHz P4 processor or equivalent; (Vista) 2.4 GHz P4 processor or equivalent <br>\\t</li><li><strong>Memory:</strong> (XP) 1 GB; (Vista) 1.5 GB<br>\\t</li><li><strong>Graphics:</strong> 128 MB Video Card with support for Pixel Shader 2.0<br> \\t</li><li><strong>DirectX®:</strong> <br>\\t</li><li><strong>Hard Drive:</strong> At least 6.5 GB of hard drive space with at least 1 GB additional space for custom content<br>\\t</li><li><strong>Sound:</strong><br>\\t</li><li><strong>Built-in Graphics:</strong><ul class=\"bb_ul\"><li>Intel Integrated Chipset, GMA X3000 or above. <br> \\t</li><li>2.6 GHz Pentium D CPU, or 1.8 GHz Core 2 Duo, or equivalent <br> \\t</li><li>0.5 GB additional RAM</li></ul></li><li><strong>Supported Video Cards:</strong>Nvidia GeForce series: FX5900 or greater, G100, GT 120, GT 130, GTS 150, GTS 250, GTX 260, GTX 275, GTX 280, GTX 285, GTX 295; ATI Radeon™ series: ATI Radeon 9500 series of greater, X300, X600, X700, X800, X850, X1300, X1600, X1800, X1900, X1950, 2400, 2600, 2900, 3450, 3650, 3850, 3870, 4850, 4870 series or greater; Intel® Graphics Media Accelerator (GMA): GMA 3-Series, GMA 4-Series <br>\\t</li><li>*Please note that the GeForce 6100 and 7100 cards are not supported</li></ul>\'}', '4,28', '9,6', '0,05', '1,53', '15,45'),
(14, 'final fantasy viii', '2013', 16, 45, 5323, 682, 2145, 9.99, 'It is a time of war. Galbadia, a Global Superpower, has declared war on Dollet, a country whose training academy is home to two personalities: the hot-headed Seifer and the \'lone wolf\', Squall Leonhart. Both are equally at conflict with each other as their country is with Galbadia; to others, Squall appears lacking in team spirit, while...', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Microsoft Windows XP/Vista/7/8 (32/64-bit)<br></li><li><strong>Processor:</strong> 1Core CPU 2GHz or faster<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> DirectX 9.0c compatible card<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 4 GB available space<br></li><li><strong>Sound Card:</strong> Integrated sound chip or more</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Microsoft Windows Vista/7/8 (32/64-bit)<br></li><li><strong>Processor:</strong> Intel® Core™2 Duo CPU 3GHz or faster<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce 9600 GT or faster<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 4 GB available space<br></li><li><strong>Sound Card:</strong> Integrated sound chip or more</li></ul>\'}', '2,28', '1,72', '3,63', '0,23', '7,86'),
(15, 'call of duty world at war', '2008', 16, 0, 19595, 1483, 2331, 19.99, 'Call of Duty is back, redefining war like you\'ve never experienced before. Building on the Call of Duty 4®: Modern Warfare engine, Call of Duty: World at War immerses players into the most gritty and chaotic WWII combat ever experienced.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>Supported OS: </strong>Windows XP/Vista/7 <br>\\t\\t\\t\\t\\t</li><li><strong>Processor: </strong>Pentium 4 @ 3 GHz/AMD 64 3200+ <br>\\t\\t\\t\\t\\t</li><li><strong>Memory: </strong>512 MB (1 GB for Vista) <br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive: </strong>8 GB Free <br>\\t\\t\\t\\t\\t</li><li><strong>DirectX version: </strong>DirectX 9.0c <br>\\t\\t\\t\\t\\t</li><li><strong>Sound: </strong>on-board or better <br>\\t\\t\\t\\t\\t</li><li><strong>Graphics Card: </strong>256 MB (nVidia GeForce 6600/ATI Radeon X1600) </li></ul>\'}', '9,3', '4,75', '0', '1,83', '15,87'),
(16, 'fallout 4', '2015', 18, 84, 110376, 45377, 4822, 19.99, 'Bethesda Game Studios, the award-winning creators of Fallout 3 and The Elder Scrolls V: Skyrim, welcome you to the world of Fallout 4 – their most ambitious game ever, and the next generation of open-world gaming.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li>Requires a 64-bit processor and operating system<br></li><li><strong>OS:</strong> Windows 7/8/10 (64-bit OS required)<br></li><li><strong>Processor:</strong> Intel Core i5-2300 2.8 GHz/AMD Phenom II X4 945 3.0 GHz or equivalent<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GTX 550 Ti 2GB/AMD Radeon HD 7870 2GB or equivalent<br></li><li><strong>Storage:</strong> 30 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li>Requires a 64-bit processor and operating system<br></li><li><strong>OS:</strong> Windows 7/8/10 (64-bit OS required)<br></li><li><strong>Processor:</strong> Intel Core i7 4790 3.6 GHz/AMD FX-9590 4.7 GHz or equivalent<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GTX 780 3GB/AMD Radeon R9 290X 4GB or equivalent<br></li><li><strong>Storage:</strong> 30 GB available space</li></ul>\'}', '5,42', '5,04', '0,25', '1,57', '12,28'),
(17, 'lego star wars the complete saga', '2009', 0, 0, 3033, 256, 243, 15.49, 'Kick Some Brick in I through VI! Play through all six Star Wars movies in one videogame! Adding new characters, new levels, new features and for the first time ever, the chance to build and battle your way through a fun Star Wars galaxy on your PC!', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP SP2/Vista<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel P3 1.0GHz or AMD Athlon XP or higher<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 156MB of RAM, 512MB required for Vista<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 128MB Graphics card with Shader Model 2.0 Capability<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 5GB of free space<br>\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '9,1', '5,01', '0', '1,62', '15,75'),
(18, 'final fantasy xiii', '2014', 16, 35, 7016, 2769, 1497, 10.99, 'Final Fantasy XIII is a fantasy RPG in which a band of brave humans struggle against fate in the utopian sky city of Cocoon and the primeval world of Pulse. Follow stylish heroine Lightning\'s fast paced battles and high adventure in a mysterious new world.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® XP SP2 or later<br></li><li><strong>Processor:</strong> 2GHz Dual Core CPU<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA® Geforce® 8 Series/ ATI Radeon™ HD 2000 series VRAM 256MB or later<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 60 GB available space<br></li><li><strong>Sound Card:</strong> Sound card compatible with DirectX® 9.0c<br></li><li><strong>Additional Notes:</strong> </li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® Vista/ 7/ 8<br></li><li><strong>Processor:</strong> Intel® Core™ 2 Quad (2.66 GHz)/ AMD Phenom™ II X4 (2.8 GHz) processor<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA® Geforce® GTX™ 460/ ATI Radeon™ HD 5870<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 60 GB available space<br></li><li><strong>Sound Card:</strong> DirectX® 9.0C compatible sound card<br></li><li><strong>Additional Notes:</strong> </li><li>*Maximum supported frame rate: 60fps </li><li>*A game controller using Xinput is recomended for this game. (If using a DirectInput based controller, please use the driver side key configuration to adjust settings as required )</li></ul>\'}', '3,01', '1,92', '1,88', '0,72', '7,53'),
(19, 'final fantasy ix', '2016', 12, 85, 3875, 325, 1911, 15.99, 'Selling over five million copies since its release in 2000, FINAL FANTASY IX proudly returns on Steam! Now you can relive the adventures of Zidane and his crew on PC !', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Vista /7/8/8.1/10<br></li><li><strong>Processor:</strong> Intel Core 2 Duo 2GHz or higher<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce 8600GTS or ATI Radeon HD4650 or higher<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 7 GB available space<br></li><li><strong>Sound Card:</strong> DirectSound® compatible sound card（DirectX®9.0c or later）</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7/8/8.1/10 (32bit / 64bit)<br></li><li><strong>Processor:</strong> Core i5 2520 2.5GHz or better<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 20 GB available space<br></li><li><strong>Sound Card:</strong> DirectSound® compatible sound card（DirectX®9.0c or later）</li></ul>\'}', '1,62', '0,77', '2,78', '0,14', '5,3'),
(20, 'tomb raider ii', '2012', 12, 0, 805, 115, 3, 4.99, 'The second instalment in the Tomb Raider series invites you to join Lara as she travels around the globe to retrieve a precious artefact before it falls into the wrong hands. The legendary artefact, the Dagger of Xian, is said to give its possessor the power of a fire breathing dragon.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong>Windows XP / Windows Vista / Windows 7<br>\\t</li><li><strong>Processor:</strong>1.8 GHz Processor<br>\\t</li><li><strong>Memory:</strong>512 MB RAM<br>\\t</li><li><strong>Graphics:</strong>3D graphics card compatible with DirectX 9<br>\\t</li><li><strong>DirectX®:</strong>9.0<br>\\t</li><li><strong>Hard Drive:</strong>2 GB HD space</li></ul>\'}', '3,21', '3,71', '0,2', '0,41', '7,53'),
(21, 'fallout 3', '2008', 0, 0, 9921, 2709, 588, 7.99, 'Vault-Tec engineers have worked around the clock on an interactive reproduction of Wasteland life for you to enjoy from the comfort of your own vault. Included is an expansive world, unique combat, shockingly realistic visuals, tons of player choice, and an incredible cast of dynamic characters.', '{\'minimum\': \'<strong>Minimum:</strong> <br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>Operating system: </strong>Windows XP/Vista <br>\\t\\t\\t\\t\\t</li><li><strong>Processor: </strong>2.4 Ghz Intel Pentium 4 or equivalent processor <br>\\t\\t\\t\\t\\t</li><li><strong>Memory: </strong>1 GB (XP)/ 2 GB (Vista) <br>\\t\\t\\t\\t\\t</li><li><strong>Hard disk space: </strong>7 GB <br>\\t\\t\\t\\t\\t</li><li><strong>Video: </strong>Direct X 9.0c compliant video card with 256MB RAM (NVIDIA 6800 or better/ATI X850 or better) <br>\\t\\t\\t\\t\\t</li><li><strong>Sound: </strong>DirectX®: 9.0c <br>\\t\\t\\t\\t\\t</li><li><strong>Controller support: </strong> Xbox 360 controller <br>\\t\\t\\t\\t\\t</li><li><strong>Other Requirements:</strong> Online play requires log-in to Games For Windows - Live </li></ul><strong>Supported Video Card Chipsets: </strong> <br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>NVIDIA</strong> GeForce 200 series, Geforce 9800 series, Geforce 9600 series, Geforce 8800 series, Geforce 8600 series, Geforce 8500 series, Geforce 8400 series, Geforce 7900 series, Geforce 7800 series, Geforce 7600 series, Geforce 7300 series, GeForce 6800 series <br>\\t\\t\\t\\t\\t</li><li><strong>ATI</strong> HD 4800 series, HD 4600 series, HD 3800 series, HD 3600 series, HD 3400 series, HD 2900 series, HD 2600 series, HD 2400 series, X1900 series, X1800 series, X1600 series, X1300 series, X850 series </li></ul>\', \'recommended\': \'<strong>Recommended:</strong> <br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>Operating system: </strong>Windows XP/Vista <br>\\t\\t\\t\\t\\t</li><li><strong>Processor: </strong>Intel Core 2 Duo processor <br>\\t\\t\\t\\t\\t</li><li><strong>Memory: </strong>2 GB System RAM <br>\\t\\t\\t\\t\\t</li><li><strong>Hard disk space: </strong>7 GB <br>\\t\\t\\t\\t\\t</li><li><strong>Video: </strong>Direct X 9.0c compliant video card with 512MB RAM (NVIDIA 8800 series, ATI 3800 series) <br>\\t\\t\\t\\t\\t</li><li><strong>Sound: </strong>DirectX®: 9.0c <br>\\t\\t\\t\\t\\t</li><li><strong>Controller support: </strong> Xbox 360 controller </li></ul>\'}', '5,56', '3,11', '0,16', '1,11', '9,96'),
(22, 'tomb raider', '2013', 18, 50, 93509, 4103, 527, 14.99, 'Tomb Raider explores the intense origin story of Lara Croft and her ascent from a young woman to a hardened survivor.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong>Windows XP Service Pack 3, Windows Vista,7,8 (32bit/64bit)<br>\\t</li><li><strong>Processor:</strong>Dual core CPU: AMD Athlon64 X2 2.1 Ghz (4050+), Intel Core2 Duo 1.86 Ghz (E6300)<br>\\t</li><li><strong>Memory:</strong>1GB Memory (2GB on Vista)<br><br>\\t</li><li><strong>Graphics:</strong>DirectX 9 graphics card with 512Mb Video RAM: AMD Radeon HD 2600 XT, nVidia 8600<br>\\t</li><li><strong>DirectX®:</strong>9.0c<br>\\t</li><li><strong>Hard Drive:</strong>12 GB HD space<br>\\t</li><li><strong>Other Requirements:</strong>Broadband Internet connection</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong>Windows Vista, Windows 7 or Windows 8<br>\\t</li><li><strong>Processor:</strong>Quad core CPU: AMD Phenom II X4 955, Intel Core i5-750<br>\\t</li><li><strong>Memory:</strong>4 GB RAM<br>\\t</li><li><strong>Graphics:</strong>DirectX 11 graphics card with 1GB Video RAM: AMD Radeon HD 5870, nVidia GTX 480<br>\\t</li><li><strong>DirectX®:</strong>11<br>\\t</li><li><strong>Hard Drive:</strong>12 GB HD space<br>\\t</li><li><strong>Other Requirements:</strong>Broadband Internet connection</li></ul>\'}', '3,25', '2,04', '0,13', '0,24', '5,66'),
(23, 'assassins creed revelations', '2011', 16, 0, 5912, 1055, 1153, 12.49, 'Ezio Auditore walks in the footsteps of the legendary mentor Altair, on a dangerous journey of discovery and revelation.', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® XP SP3 / Windows Vista® SP2 /Windows® 7 SP1<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel® Core™2 Duo E4400 @ 2.0 GHz or AMD Athlon™ 64 X2 4000+ @ 2.1GHz<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1.5 GB Windows® XP / 2 GB Windows Vista, 7<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 256 MB DirectX® 9.0–compliant card with Shader Model 4.0 or higher (see supported list)*<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX® June2010 or newer<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 12 GB<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX 9.0–compliant sound card<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Peripherals:</strong> Keyboard, mouse, optional controller<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Internet:</strong> Temporary broadband connection required for one-time product registration at first launch, permanent broadband connection required for multi-player.<br>\\t\\t\\t\\t\\t\\t\\t\\t*This product does not support Windows® 98/ME/2000/NT<br>Supported Video Cards at Time of Release:<br><br>\\t\\t\\t\\t\\t\\t\\t\\tAMD Radeon™ HD2600XT or better/3000/4000/5000/6000 desktop series<br><br>\\t\\t\\t\\t\\t\\t\\t\\tNVIDIA® GeForce® 8600GTS or better/9/GT200/GT400/GT500 desktop series<br><br>\\t\\t\\t\\t\\t\\t\\t\\tLaptop versions of these cards may work but are NOT officially supported. These chipsets are the only ones that will run this game. For the most up-to-date minimum requirement listings, please visit the FAQ for this game on our support website at <a href=\"https://steamcommunity.com/linkfilter/?url=http://support.ubi.com\" target=\"_blank\" rel=\"noopener\" >http://support.ubi.com</a>.<br>\\t\\t\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br>\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® XP SP3 / Windows Vista® SP2 /Windows® 7 SP1<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel® Core™2 Duo E6700 @ 2.6 GHz or AMD Athlon™ 64 X2 6000+ @ 3.0 GHz or better<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2 GB Windows® XP / Windows Vista® / Windows® 7<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 512 MB DirectX® 9.0–compliant card with Shader Model 5.0 or higher (see supported list)*<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX® June2010 or newer <br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 12 GB<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> Surround Sound 5.1 capable sound card<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Peripherals:</strong> Keyboard, mouse, joystick optional (Xbox 360® Controller for Windows recommended)<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Internet:</strong> Temporary broadband connection required for one-time product registration at first launch, permanent broadband connection required for multi-player.<br>\\t\\t\\t\\t\\t\\t\\t\\t*This product does not support Windows® 98/ME/2000/NT<br>Supported Video Cards at Time of Release:<br><br>\\t\\t\\t\\t\\t\\t\\t\\tAMD Radeon™ HD2600XT or better/3000/4000/5000/6000 desktop series<br><br>\\t\\t\\t\\t\\t\\t\\t\\tNVIDIA® GeForce® 8600GTS or better/9/GT200/GT400/GT500 desktop series<br><br>\\t\\t\\t\\t\\t\\t\\t\\tLaptop versions of these cards may work but are NOT officially supported. These chipsets are the only ones that will run this game. For the most up-to-date minimum requirement listings, please visit the FAQ for this game on our support website at <a href=\"https://steamcommunity.com/linkfilter/?url=http://support.ubi.com\" target=\"_blank\" rel=\"noopener\" >http://support.ubi.com</a>.<br>\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '3,8', '3,97', '0,14', '1,29', '9,19'),
(24, 'street fighter iv', '2009', 0, 0, 295, 126, 0, 13.99, 'Street Fighter® IV brings the legendary fighting series back to its roots by taking the beloved fighting moves and techniques of the original Street Fighter® II, and infusing them with Capcom\'s latest advancements in next generation technology.', '{\'minimum\': \'<strong>Minimum:</strong><br> <ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP/Vista<br>\\t </li><li><strong>Processor:</strong> Intel Pentium 4 2.0 GHz and up <br>\\t </li><li><strong>Memory:</strong> 1 GB RAM<br>\\t </li><li><strong>Graphics:</strong> DirectX 9.0c/Shader3.0 and up supported (operation on-board is not guaranteed) <br>\\t\\t\\t \\t\\t\\t\\t\\t\\t</li><li><strong>Video:</strong> NVIDIA GeForce 6600 and up (except for NVIDIA GeForce 7300), VRAM: 256MB and up (operation sharing with main memory is not guaranteed) <br>\\t </li><li><strong>Hard Drive:</strong> 4.5 GB free hard drive space<br>\\t </li><li><strong>Sound:</strong> DirectSound, DirectX9.0c Compatible Audio<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Other Requirements:</strong> Online play requires software installation of and log-in to Games For Windows - LIVE <br><br> </li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br> <ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista<br>\\t </li><li><strong>Processor:</strong> Intel Core2 Duo 2.0 GHz and up <br>\\t </li><li><strong>Memory:</strong> 2 GB RAM<br>\\t </li><li><strong>Graphics:</strong> DirectX 9.0c/Shader3.0 and up supported (operation on-board is not guaranteed) <br>\\t\\t\\t </li><li><strong>Video:</strong> NVIDIA GeForce 8600 and up, VRAM: 512MB and up (operation sharing with main memory is not guaranteed) <br>\\t </li><li><strong>Hard Drive:</strong> 4.5 GB free hard drive space<br>\\t </li><li><strong>Sound:</strong> DirectSound, DirectX9.0c Compatible Audio<br> </li></ul>\'}', '3,91', '1,81', '0,73', '0,81', '7,27'),
(25, 'halflife', '1998', 0, 0, 27755, 1100, 1300, 7.19, 'Named Game of the Year by over 50 publications, Valve\'s debut title blends action and adventure with award-winning technology to create a frighteningly realistic world where players must think to survive. Also includes an exciting multiplayer mode that allows you to play against friends and enemies around the world.', '{\'minimum\': \'\\r\\n\\t\\t\\t<p><strong>Minimum:</strong> 500 mhz processor, 96mb ram, 16mb video card, Windows XP, Mouse, Keyboard, Internet Connection<br /></p>\\r\\n\\t\\t\\t<p><strong>Recommended:</strong> 800 mhz processor, 128mb ram, 32mb+ video card, Windows XP, Mouse, Keyboard, Internet Connection<br /></p>\\r\\n\\t\\t\\t\'}', '4,32', '0,23', '0,09', '0,08', '4,72'),
(26, 'fallout new vegas', '2010', 18, 75, 66756, 3149, 2485, 7.99, 'Welcome to Vegas. New Vegas. Enjoy your stay!', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7/Vista/XP <br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Dual Core 2.0GHz<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2GB RAM<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space:</strong> 10GB free space<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Video Card:</strong> NVIDIA GeForce 6 series, ATI 1300XT series<br>\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '4,75', '2,59', '0,14', '0,94', '8,41'),
(27, 'far cry 4', '2014', 0, 0, 17082, 4740, 1062, 25.99, 'Hidden in the towering Himalayas lies Kyrat, a country steeped in tradition and violence. You are Ajay Ghale. Traveling to Kyrat to fulfill your mother’s dying wish, you find yourself caught up in a civil war to overthrow the oppressive regime of dictator Pagan Min.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® 7 (SP1) / Windows® 8 / Windows® 8.1 / (64-bit only)<br></li><li><strong>Processor:</strong> 2.6 GHz Intel® Core™ i5-750 or 3.2 GHz AMD Phenom™ II X4 955<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 460 or AMD Radeon HD5850 (1 GB VRAM)<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 30 GB available space<br></li><li><strong>Sound Card:</strong> DirectX-compatible (5.1 surround sound recommended)<br></li><li><strong>Additional Notes:</strong> Windows-compatible keyboard, mouse, optional controller (Xbox 360 Controller for Windows recommended)</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® 7 (SP1) / Windows® 8 / Windows® 8.1 / (64-bit only)<br></li><li><strong>Processor:</strong> 2.5 GHz Intel® Core™ i5-2400S or 4.0 GHz AMD FX-8350 or better<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 680 or AMD Radeon R9 290X or better (2 GB VRAM)<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 30 GB available space<br></li><li><strong>Sound Card:</strong> DirectX-compatible (5.1 surround sound recommended)<br></li><li><strong>Additional Notes:</strong> Supported video cards at the time of release: NVIDIA GeForce GTX 460 or better, GeForce GTX 700 series; AMD Radeon HD5850 or better, Radeon R9 series. Note: Laptop versions of these cards may work but are NOT officially supported.</li></ul>\'}', '2,84', '4,45', '0,19', '1,18', '8,68'),
(28, 'left 4 dead 2', '2009', 0, 70, 251789, 8418, 1615, 7.19, 'Set in the zombie apocalypse, Left 4 Dead 2 (L4D2) is the highly anticipated sequel to the award-winning Left 4 Dead, the #1 co-op game of 2008. This co-operative action horror FPS takes you and your friends through the cities, swamps and cemeteries of the Deep South, from Savannah to New Orleans across five expansive campaigns.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® 7 32/64-bit / Vista 32/64 / XP<br></li><li><strong>Processor:</strong> Pentium 4 3.0GHz<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> Video card with 128 MB, Shader model 2.0. ATI X800, NVidia 6600 or better<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 13 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c compatible sound card</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® 7 32/64-bit / Vista 32/64 / XP<br></li><li><strong>Processor:</strong> Intel core 2 duo 2.4GHz<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> Video Card Shader model 3.0. NVidia 7600, ATI X1600 or better<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 13 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c compatible sound card</li></ul>\'}', '2,67', '1,21', '0,05', '0,41', '4,36'),
(29, 'assassins creed unity', '2014', 0, 0, 12350, 7354, 1686, 25.99, 'Assassin’s Creed® Unity tells the story of Arno, a young man who embarks upon an extraordinary journey to expose the true powers behind the French Revolution. In the brand new co-op mode, you and your friends will also be thrown in the middle of a ruthless struggle for the fate of a nation.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 SP1, Windows 8/8.1 (64-bit operating system required)<br></li><li><strong>Processor:</strong> Intel Core i5-2500K @ 3.3 GHz or AMD FX-8350 @ 4.0 GHz<br></li><li><strong>Memory:</strong> 6 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 680 or AMD Radeon HD 7970 (2 GB VRAM)<br></li><li><strong>Storage:</strong> 50 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c compatible sound card with latest drivers<br></li><li><strong>Additional Notes:</strong> Windows-compatible keyboard and mouse required, optional controller</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 SP1, Windows 8/8.1 (64-bit operating system required)<br></li><li><strong>Processor:</strong> Intel Core i7-3770 @ 3.4 GHz or AMD FX-8350 @ 4.0 GHz or better<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 780 or AMD Radeon R9 290X (3 GB VRAM)<br></li><li><strong>Storage:</strong> 50 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c compatible sound card with latest drivers<br></li><li><strong>Additional Notes:</strong> Supported video cards at the time of release: NVIDIA GeForce GTX 680 or better, GeForce GTX 700 series; AMD Radeon HD7970 or better, Radeon R9 200 series Note: Laptop versions of these cards may work but are NOT officially supported.</li></ul>\'}', '3,61', '3,18', '0,08', '1,05', '7,93'),
(30, 'assassins creed iv black flag', '2013', 0, 0, 23904, 3362, 3234, 16.99, 'The year is 1715. Pirates rule the Caribbean and have established their own lawless Republic where corruption, greediness and cruelty are commonplace.Among these outlaws is a brash young captain named Edward Kenway.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista SP2 or Windows 7 SP1 or Windows 8 (both 32/64bit versions)<br></li><li><strong>Processor:</strong> Intel Core2Quad Q8400 @ 2.6 GHz or AMD Athlon II X4 620 @ 2.6 GHz<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> Nvidia Geforce GTX 260 or AMD Radeon HD 4870 (512MB VRAM with shader Model 4.0 or higher)<br></li><li><strong>Storage:</strong> 30 GB available space<br></li><li><strong>Sound Card:</strong> DirectX Compatible Sound Card with latest drivers<br></li><li><strong>Additional Notes:</strong> Windows-Compatible keyboard and mouse required, controller optional.</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista SP2 or Windows 7 SP1 or Windows 8 (both 32/64bit versions)<br></li><li><strong>Processor:</strong> Intel Core i5 2400S @ 2.5 GHz or better or AMD Phenom II x4 940 @ 3.0 GHz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> Nvidia GeForce GTX 470 or AMD Radeon HD 5850 (1024MB VRAM with Shader Model 5.0) or better<br></li><li><strong>Storage:</strong> 30 GB available space<br></li><li><strong>Sound Card:</strong> DirectX Compatible Sound Card with latest drivers<br></li><li><strong>Additional Notes:</strong> Supported video cards at the time of release: Nvidia GeForce GTX 260 or better and GeForce GTX 400, GTX 500, GTX 600 and GTX 700 series. AMD Radeon HD4870 or better and Radeon HD5000, HD6000 and HD7000 series. Note: Latest GeForce drivers tested: 327.23 for all series. Latest Radeon drivers tested: 13.1 for Radeon HD4000, 13.4 for Radeon HD5000, HD6000 and HD7000 series on Vista and 13.9 for Radeon HD5000, HD6000 and HD7000 series on Win7 and Win8. Laptop versions of these cards may work but are NOT officially supported.</li></ul>\'}', '6,17', '5,18', '0,2', '1,65', '13,16');
INSERT INTO `jeux` (`id_jeu`, `nom_jeu`, `annee`, `age_requis`, `nb_succes`, `nb_avis_pos`, `nb_avis_neg`, `temps_jeu_moyen`, `prix`, `description`, `configuration`, `ventes_AN`, `ventes_EU`, `ventes_JP`, `ventes_Autre`, `ventes_Global`) VALUES
(31, 'batman arkham knight', '2015', 18, 113, 33121, 12981, 1266, 15.99, 'Batman™: Arkham Knight brings the award-winning Arkham trilogy from Rocksteady Studios to its epic conclusion. Developed exclusively for New-Gen platforms, Batman: Arkham Knight introduces Rocksteady\'s uniquely designed version of the Batmobile.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li>Requires a 64-bit processor and operating system<br></li><li><strong>OS:</strong> Win 7 SP1, Win 8.1 (64-bit Operating System Required)<br></li><li><strong>Processor:</strong> Intel Core i5-750, 2.67 GHz | AMD Phenom II X4 965, 3.4 GHz<br></li><li><strong>Memory:</strong> 6 GB RAM<br></li><li><strong>Graphics:</strong> Graphics: NVIDIA GeForce GTX 660 (2 GB Memory Minimum) | AMD Radeon HD 7870 (2 GB Memory Minimum)<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 45 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li>Requires a 64-bit processor and operating system<br></li><li><strong>OS:</strong> Win 7 SP1, Win 8.1 (64-bit Operating System Required)<br></li><li><strong>Processor:</strong> Intel Core i7-3770, 3.4 GHz | AMD FX-8350, 4.0 GHz<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 760 - 3 GB Memory Recommended | AMD Radeon HD 7950 - 3 GB Memory Recommended<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 55 GB available space</li></ul>\'}', '2,43', '2,07', '0,1', '0,75', '5,37'),
(32, 'lego indiana jones the original adventures', '2009', 0, 0, 305, 87, 0, 15.49, 'Build, Battle and Brawl your way out of trouble! Play through all three classic Indiana Jones™ movies and relive your favorite Indy adventures in the tongue-in-cheek worlds of LEGO®. Explore and Discover - Battle enemies, solve puzzles, and seek out the world\'s greatest treasures.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP or Vista<br>\\t\\t\\t</li><li><strong>Processor:</strong> Intel Pentium 3 1GHz or AMD Athlon XP<br>\\t\\t\\t</li><li><strong>Memory:</strong> 256 MB (XP), 512 MB (Vista)<br>\\t\\t\\t</li><li><strong>Graphics:</strong> 128 MB Graphics card with Shader Model 2.0 Capability<br>\\t\\t\\t</li><li><strong>DirectX®:</strong> 9.0c<br>\\t\\t\\t</li><li><strong>Hard Drive:</strong> 4 GB<br>\\t\\t\\t</li></ul>\'}', '6,82', '3,23', '0', '2,03', '12,05'),
(33, 'the witcher 3 wild hunt', '2015', 0, 78, 202930, 4798, 3068, 24.99, 'As war rages on throughout the Northern Realms, you take on the greatest contract of your life — tracking down the Child of Prophecy, a living weapon that can alter the shape of the world.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> 64-bit Windows 7, 64-bit Windows 8 (8.1) or 64-bit Windows 10<br></li><li><strong>Processor:</strong> Intel CPU Core i5-2500K 3.3GHz / AMD CPU Phenom II X4 940<br></li><li><strong>Memory:</strong> 6 GB RAM<br></li><li><strong>Graphics:</strong> Nvidia GPU GeForce GTX 660 / AMD GPU Radeon HD 7870<br></li><li><strong>Storage:</strong> 35 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> 64-bit Windows 7, 64-bit Windows 8 (8.1) or 64-bit Windows 10<br></li><li><strong>Processor:</strong> Intel CPU Core i7 3770 3.4 GHz / AMD CPU AMD FX-8350 4 GHz<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> Nvidia GPU GeForce GTX 770 / AMD GPU Radeon R9 290<br></li><li><strong>Storage:</strong> 35 GB available space</li></ul>\'}', '1,82', '2,89', '0,21', '0,72', '5,64'),
(34, 'tom clancys the division', '2016', 18, 0, 49832, 25607, 4252, 41.99, 'After a deadly pandemic sweeps through New York, it\'s up to Agents to save what remains. Complete missions, explore the Dark Zone, and fight back enemy factions alone or with 3 friends. Experience a full endgame offering you new PvP and PvE modes.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® 7, Windows 8.1, Windows 10 (64-bit versions only)<br></li><li><strong>Processor:</strong> Intel Core i5-2400 | AMD FX-6100, or better<br></li><li><strong>Memory:</strong> 6 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 560 with 2 GB VRAM (current equivalent NVIDIA GeForce GTX 760) | AMD Radeon HD 7770 with 2 GB VRAM, or better - See supported List*<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 40 GB available space<br></li><li><strong>Additional Notes:</strong> Laptop models of these desktop cards may work as long as they are on-par in terms of performance with at least the minimum configuration. For an up-to-date list of supported hardware, please visit the FAQ for this game on our website: <a href=\"https://steamcommunity.com/linkfilter/?url=http://support.ubi.com.*Supported\" target=\"_blank\" rel=\"noopener\" >http://support.ubi.com.*Supported</a> NVIDIA cards at time of release: GeForce GTX500 series: GeForce GTX560 (2 GB VRAM) or better • GeForce GTX600 series: GeForce GTX660 or better • GeForce GTX700 series: GeForce GTX760 or better • GeForce GTX900 Titan series: GeForce GTX960 or better • Supported AMD cards at time of release: Radeon HD7000 series: Radeon HD7770 (2 GB VRAM) or better • Radeon 200 series: Radeon R7 270 or better • Radeon 300/Fury X series: Radeon R7 370 or better.</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® 7, Windows 8.1, Windows 10 (64-bit versions only)<br></li><li><strong>Processor:</strong> Intel Core i7-3770 | AMD FX-8350, or better<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 970 | AMD Radeon R9 290, or better - See supported List*<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 40 GB available space<br></li><li><strong>Additional Notes:</strong> Laptop models of these desktop cards may work as long as they are on-par in terms of performance with at least the minimum configuration. For an up-to-date list of supported hardware, please visit the FAQ for this game on our website: <a href=\"https://steamcommunity.com/linkfilter/?url=http://support.ubi.com.*Supported\" target=\"_blank\" rel=\"noopener\" >http://support.ubi.com.*Supported</a> NVIDIA cards at time of release: GeForce GTX500 series: GeForce GTX560 (2 GB VRAM) or better • GeForce GTX600 series: GeForce GTX660 or better • GeForce GTX700 series: GeForce GTX760 or better • GeForce GTX900 Titan series: GeForce GTX960 or better • Supported AMD cards at time of release: Radeon HD7000 series: Radeon HD7770 (2 GB VRAM) or better • Radeon 200 series: Radeon R7 270 or better • Radeon 300/Fury X series: Radeon R7 370 or better.</li></ul>\'}', '2,68', '2,37', '0,15', '0,78', '5,99'),
(35, 'left 4 dead', '2008', 0, 73, 17951, 948, 897, 7.19, 'From Valve (the creators of Counter-Strike, Half-Life and more) comes Left 4 Dead, a co-op action horror game for the PC and Xbox 360 that casts up to four players in an epic struggle for survival against swarming zombie hordes and terrifying mutant monsters.', '{\'minimum\': \'<strong>Minimum:</strong> <br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>Supported OS:</strong> Windows® 7 32/64-bit / Vista 32/64 / XP <br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Pentium 4 3.0GHz <br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1 GB <br>\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 128 MB, Shader model 2.0, ATI 9600, NVidia 6600 or better <br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> At least 7.5 GB of free space <br>\\t\\t\\t\\t\\t</li><li><strong>Sound Card:</strong> DirectX 9.0c compatible sound card </li></ul>\', \'recommended\': \'<strong>Recommended:</strong> <br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>Supported OS:</strong> Windows® 7 32/64-bit / Vista 32/64 / XP <br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel core 2 duo 2.4GHz <br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1 GB <br>\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> Shader model 3.0, NVidia 7600, ATI X1600 or better </li></ul>\'}', '2,66', '0,52', '0,05', '0,3', '3,54'),
(36, 'assassins creed brotherhood', '2011', 18, 0, 6676, 929, 600, 12.49, 'Now Available on Mac! It’s time to join the Brotherhood.', '{\'minimum\': \'<strong>Minimum</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® XP (32-64 bits) /Windows Vista®(32-64 bits)/Windows 7® (32-64 bits) <br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Core® 2 Duo 1.8 GHZ or AMD Athlon X2 64 2.4GHZ<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1.5 GB Windows® XP / 2 GB Windows Vista® - Windows 7®<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 256 MB DirectX® 9.0–compliant card with Shader Model 3.0 or higher (see supported list*)<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 9.0<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 8 GB<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX 9.0 –compliant sound card<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Peripherals:</strong> Keyboard, mouse, optional controller<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Supported Video Cards:</strong> ATI® RADEON® HD 2000/3000/4000/5000/6000 series, NVIDIA GeForce® 8/9/100/200/300/400/500 series<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li>Note* * This product does not support Windows® 98/ME/2000/NT<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\tRequires a Uplay account.<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<strong>Recommended</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® XP (32-64 bits) /Windows Vista®(32-64 bits)/Windows 7® (32-64 bits) <br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Core® 2 Duo E6700 2.6 GHz or AMD Athlon 64 X2 6000+ or better<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1.5 GB Windows® XP / 2 GB Windows Vista® - Windows 7®<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> GeForce 8800 GT or ATI Radeon HD 4700 or better<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 9.0<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 8 GB<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> 5.1 sound card<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Peripherals:</strong> Keyboard, mouse, joystick optional (Xbox 360® Controller for Windows recommended)<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Supported Video Cards:</strong> ATI® RADEON® HD 2000/3000/4000/5000/6000 series, NVIDIA GeForce® 8/9/100/200/300/400/500 series<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li>Note* * This product does not support Windows® 98/ME/2000/NT<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\tRequires a Uplay account.<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '4,86', '1,3', '0,14', '0,64', '6,93'),
(37, 'battlefield bad company 2', '2010', 0, 0, 23093, 3877, 1200, 14.99, 'Battlefield: Bad Company 2™ brings the award-winning Battlefield gameplay to the forefront of PC gaming with best-in-class vehicular combat and unexpected &quot;Battlefield moments.&quot; New vehicles like the ATV and a transport helicopter allow for all-new multiplayer tactics on the Battlefield. With the Frostbite-enabled Destruction 2.', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP<br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Core 2 Duo @ 2.0GHz<br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2GB<br>\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 256 MB Video Card (GeForce 7800 GT / ATI X1900)<br>\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX 9, 10, and 11 support<br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 15 GB<br>\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista or Windows 7<br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Core 2 Quad or higher<br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2GB<br>\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 512 MB Video Card (GeForce GTX 260/ ATI Radeon 4870)<br>\\t\\t\\t\\t\\t</li><li><strong>Controller Support:</strong> Support for Logitech G15 and G19 keyboard LCDs in multiplayer<br>\\t\\t\\t\\t\\t</li></ul>\'}', '3,61', '2,67', '0,12', '0,77', '7,16'),
(38, 'far cry 3', '2012', 0, 0, 46331, 5622, 836, 16.99, 'Discover the dark secrets of a lawless island ruled by violence and take the fight to the enemy as you try to escape. You’ll need more than luck to escape alive!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong>Windows XP, Windows Vista and Windows 7<br>\\t</li><li><strong>Processor:</strong>Intel Core®2 Duo E6700 @ 2.6 GHz or AMD Athlon64 X2 6000+ @ 3.0Ghz or better<br>\\t</li><li><strong>Memory:</strong>4 GB RAM<br>\\t</li><li><strong>Graphics:</strong>512MB Video RAM (1GB Video RAM), DirectX9c (DirectX11) Shader Model 3.0 (Shader Model 5.0)<br>\\t</li><li><strong>DirectX®:</strong>9.0c<br>\\t</li><li><strong>Hard Drive:</strong>15 GB HD space<br>\\t</li><li><strong>Sound:</strong>DirectX Compatible (Recommended Surround Sound 5.1 capable)<br>\\t</li><li><strong>Other Requirements:</strong>Broadband Internet connection<br>\\t</li><li><strong>Additional:</strong>*Supported Video Cards at Time of Release: AMD Radeon™ HD 2900 / 3000 / 4000 / 5000 / 6000 / 7000 series, NVIDIA® GeForce® 8800 GTX / 9 / 200 / 400 / 500 / 600 series. Laptop versions of these cards may work, but are not supported. These chipsets are the only ones that will run this game. For the most up-to-date minimum requirement listings, please visit the FAQ on our support website at <a href=\"https://steamcommunity.com/linkfilter/?url=http://support.ubi.com\" target=\"_blank\" rel=\"noopener\" >http://support.ubi.com</a>.<br>Requires a UPlay account</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>Memory:</strong>4 GB RAM<br>\\t</li><li><strong>Graphics:</strong>512MB Video RAM (1GB Video RAM), DirectX9c (DirectX11) Shader Model 3.0 (Shader Model 5.0)<br>\\t</li><li><strong>DirectX®:</strong>11<br>\\t</li><li><strong>Hard Drive:</strong>15 GB HD space<br>\\t</li><li><strong>Sound:</strong>DirectX Compatible (Recommended Surround Sound 5.1 capable)<br>\\t</li><li><strong>Other Requirements:</strong>Broadband Internet connection<br>\\t</li><li><strong>Additional:</strong>*Supported Video Cards at Time of Release: AMD Radeon™ HD 2900 / 3000 / 4000 / 5000 / 6000 / 7000 series, NVIDIA® GeForce® 8800 GTX / 9 / 200 / 400 / 500 / 600 series. Laptop versions of these cards may work, but are not supported. These chipsets are the only ones that will run this game. For the most up-to-date minimum requirement listings, please visit the FAQ on our support website at <a href=\"https://steamcommunity.com/linkfilter/?url=http://support.ubi.com\" target=\"_blank\" rel=\"noopener\" >http://support.ubi.com</a>.<br>Requires a UPlay account</li></ul>\'}', '2,47', '3,72', '0,12', '1,14', '7,47'),
(39, 'grand theft auto 2', '2008', 0, 0, 184, 17, 3, 0.00, 'Grand Theft Auto is back. The cars are faster. The streets are busier. The bad guys are nastier. The police are angrier. And now, the FBI and the Army are getting involved... Seven ruthless gangs are involved in a ruthless power struggle and it is up to you to make a name for yourself. Respect is earned, not given.', '0', '1,13', '2,07', '0', '0,22', '3,42'),
(40, 'final fantasy iii', '2014', 12, 18, 1029, 250, 138, 10.99, 'FINAL FANTASY® III, one of the best-loved games from the epic RPG series, is now available on Steam.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista, 7, 8<br></li><li><strong>Processor:</strong> Pentium 4, 2.4 GHz<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Storage:</strong> 800 MB available space</li></ul>\'}', '1,77', '0,05', '5,12', '0,12', '7,05'),
(41, 'lego batman the videogame', '2008', 0, 0, 1050, 242, 490, 14.99, 'When all the villains in Arkham Asylum team up and break loose, only the dynamic duo is bold enough to take them on to save Gotham City. The fun of LEGO, the drama of Batman and the uniqueness of the combination makes for a comical and exciting adventure in LEGO Batman: The Videogame.', '{\'minimum\': \'<strong>Minimum:</strong> <br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>Supported OS: </strong>Windows Vista®/XP <br>\\t\\t\\t\\t\\t</li><li><strong>Processor: </strong>Intel® P3 1.5 GHz or AMD Athlon™ XP <br>\\t\\t\\t\\t\\t</li><li><strong>Memory: </strong>256 MB RAM, 512 MB RAM required for Windows Vista® <br>\\t\\t\\t\\t\\t</li><li><strong>Graphics: </strong>128 MB with Shader Model 2.0 capability (Shader Model 3.0 recommended) </li></ul>\'}', '7,71', '4,05', '0', '1,9', '13,67'),
(42, 'metal gear solid v the phantom pain', '2015', 18, 42, 38643, 4954, 3007, 24.99, 'Ushering in a new era for the METAL GEAR franchise with cutting-edge technology powered by the Fox Engine, METAL GEAR SOLID V: The Phantom Pain, will provide players a first-rate gaming experience as they are offered tactical freedom to carry out open-world missions.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7x64, Windows 8x64, Windows 10x64 (64-bit OS Required)<br></li><li><strong>Processor:</strong> Intel Core i5-4460 (3.40 GHz) or better; Quad-core or better<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 650 (2GB) or better (DirectX 11 card Required)<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 28 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c compatible sound card</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7x64, Windows 8x64, Windows 10x64 (64-bit OS Required)<br></li><li><strong>Processor:</strong> Intel Core i7-4790 (3.60GHz) or better; Quad-core or better<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 760 (DirectX 11 graphic card required)<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 28 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c compatible sound card (Surround Sound 5.1)</li></ul>\'}', '1,78', '1,94', '0,71', '0,63', '5,08'),
(43, 'max payne', '2008', 18, 0, 3926, 435, 316, 5.99, 'Max Payne is a man with nothing to lose in the violent, cold urban night. A fugitive undercover cop framed for murder, hunted by cops and the mob, Max is a man with his back against the wall, fighting a battle he cannot hope to win.', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Microsoft® Windows® 2000/XP (only)<br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 450MHz AMD / Intel Processor<br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 96 MB RAM (128 MB RAM or greater recommended)<br>\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 16MB Direct3D Compatible Graphics Card<br>\\t\\t\\t\\t\\t</li><li><strong>DirectX Version:</strong> DirectX 8.0<br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 830 MB Hard Drive Space for full install, 530 MB for minimum install<br>\\t\\t\\t\\t\\t</li><li><strong>Sound Card:</strong> DirectSound compatible sound card</li></ul>\'}', '2,99', '1,27', '0,05', '0,27', '4,58'),
(44, 'assassins creed syndicate', '2015', 0, 0, 7203, 2391, 564, 33.99, 'London, 1868. In the heart of the Industrial Revolution, lead your underworld organization and grow your influence to fight those who exploit the less privileged in the name of...', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 SP1 or Windows 8.1 or Windows 10 (64bit versions)<br></li><li><strong>Processor:</strong> Intel Core i5 2400s @ 2.5 GHz / AMD FX 6350 @ 3.9 GHz<br></li><li><strong>Memory:</strong> 6 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 660 / AMD Radeon R9 270 (2GB VRAM with Shader Model 5.0)<br></li><li><strong>Sound Card:</strong> DirectX Compatible Sound Card with latest drivers</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 SP1 or Windows 8.1 or Windows 10 (64bit versions)<br></li><li><strong>Processor:</strong> Intel Core i7 3770 @ 3.5 GHz / AMD FX 8350 @ 4.0 GHz<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 760 (4GB) or the newer GTX 970 (4GB) / AMD Radeon R9 280X (3GB of VRAM) or better<br></li><li><strong>Sound Card:</strong> DirectX Compatible Sound Card with latest drivers<br></li><li><strong>Additional Notes:</strong> *Technical Notice from the developer: For a recommended experience, the game requires a video card with at least 3GB of VRAM when playing at a full HD resolution. While we encourage you to fiddle with the advanced options to fully customize your gaming experience, please keep an eye out for the VRAM meter usage when you adjust these settings.</li></ul>\'}', '1,51', '2,56', '0,06', '0,63', '4,76'),
(45, 'la noire', '2011', 18, 60, 14096, 2315, 428, 19.99, 'L.A. Noire is a violent crime thriller that blends breathtaking action with true detective work to deliver an unprecedented interactive experience. Search for clues, chase down suspects and interrogate witnesses as you struggle to find the truth in a city where everyone has something to hide.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Intel CPUs:</strong> Core 2.2 GHz to Quad Core 3.2GHz<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>AMD CPUs:</strong> Dual Core 2.4Ghz to Quad Core 3.2Ghz <br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>RAM:</strong> 2GB to 8GB<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space:</strong> 16GB<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Video Card:</strong> NVIDIA GeForce 8600 GT 512MB to NVIDIA GeForce GTX 580 1536MB or Radeon HD3000 512MB to Radeon HD 6850 1024MB<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> 100% DirectX 9 Compatible<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t </li><li><strong>Additional:</strong> Please refer to your hardware manufacturer and <a href=\"https://steamcommunity.com/linkfilter/?url=http://www.rockstargames.com/support\" target=\"_blank\" rel=\"noopener\" >http://www.rockstargames.com/support</a> for current compatibility information. Some system components such as integrated graphics cards may be incompatible. Unlisted specifications may not be supported by publisher. <br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Additional:</strong> Initial activation requires internet connection and Rockstar Games Social Club (13+ to register); software installation required including GameShield IronWrap &amp; Patcher; DirectX, and Microsoft\\\'s Windows .NET Framework, and Microsoft Visual C++ 2008 SP1 Redistributable Package (x86).<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '2,79', '2,27', '0,14', '0,75', '5,95'),
(46, 'killer instinct', '2017', 0, 464, 1301, 175, 203, 29.99, 'The legendary fighting franchise is back with over-the-top action, a wild cast of combatants, rocking reactive music, and C-C-C-COMBO BREAKERS!!! Choose your ultimate combatants each with fluid animations, unique combat tactics, and enthralling special attacks.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7<br></li><li><strong>Processor:</strong> Intel Core i5-750 @ 2.67 GHz or AMD Phenom II X4 965 @ 3.4 GHz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 480 or AMD Radeon HD 5850<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 48 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 10<br></li><li><strong>Processor:</strong> Intel Core i5-4670K @ 3.4GHz or AMD FX-4300 @ 3.8 GHz<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 670 or AMD Radeon HD 7950<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 48 GB available space</li></ul>\'}', '2,26', '0,72', '0,12', '0,1', '3,2'),
(47, 'star wars episode i racer', '2018', 0, 0, 280, 45, 0, 7.19, 'Two Engines. One Champion. No Limits.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 or newer<br></li><li><strong>Processor:</strong> 1.8 GHz<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> 3D graphics card compatible with DirectX 9.0c and 256 MB VRAM<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 550 MB available space<br></li><li><strong>Sound Card:</strong> 16-bit sound card<br></li><li><strong>Additional Notes:</strong> Mouse, Keyboard</li></ul>\'}', '2,31', '0,62', '0,14', '0,04', '3,12'),
(48, 'mass effect 2', '2010', 0, 0, 10675, 542, 1087, 19.99, 'Recruit. Explore. Control.Two years after Commander Shepard repelled invading Reapers bent on the destruction of organic life, a mysterious new enemy has emerged. On the fringes of known space, something is silently abducting entire human colonies.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP SP3 / Windows Vista SP1 / Windows 7<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 1.8GHz Intel Core 2 Duo or equivalent AMD CPU<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1 GB RAM for Windows XP / 2 GB RAM for Windows Vista and Windows 7<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 256 MB (with Pixel Shader 3.0 support)<br>\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX 9.0c August 2008 (included)<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 15 GB<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX 9.0c compatible<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Supported Chipsets:</strong> NVIDIA GeForce 6800 or greater; ATI Radeon X1600 Pro or greater. Please note that NVIDIA GeForce 7300, 8100, 8200, 8300, 8400, and 9300; ATI Radeon HD3200, and HD4350 are below minimum system requirements. Updates to your video and sound card drivers may be required.<br>\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP SP3 / Windows Vista SP1 / Windows 7<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 2.6+ GHz Core 2 Duo Intel or equivalent AMD CPU<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2 GB RAM<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> ATI Radeon HD 2900 XT, NVIDIA GeForce 8800 GT, or better recommended<br>\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX 9.0c August 2008 (included)<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 15 GB<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX 9.0c compatible<br>\\t\\t\\t\\t\\t</li></ul>\'}', '2,78', '1,61', '0,06', '0,54', '4,99'),
(49, 'borderlands 2', '2012', 18, 69, 144595, 11021, 3276, 19.99, 'The Ultimate Vault Hunter’s Upgrade lets you get the most out of the Borderlands 2 experience.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP SP3<br>\\t</li><li><strong>Processor:</strong> 2.4 GHz Dual Core Processor<br>\\t</li><li><strong>Memory:</strong> 2 GB(XP)/ 2 GB(Vista)<br>\\t</li><li><strong>Hard Disk Space:</strong> 13 GB free<br>\\t</li><li><strong>Video Memory:</strong> 256 MB<br>\\t</li><li><strong>Video Card:</strong> NVIDIA GeForce 8500 /ATI Radeon HD 2600<br>\\t</li><li><strong>Sound:</strong> DirectX 9.0c Compatible<br>\\t</li><li><strong>Other Requirements:</strong>Initial installation requires one-time internet connection for Steam authentication; software installations required (included with the game) include Steam Client, DirectX 9, Microsoft .NET 4 Framework, Visual C++ Redistributable 2005, Visual C++ Redistributable 2008, Visual C++ Redistributable 2010, and AMD CPU Drivers (XP Only/AMD Only)</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP SP3/Vista/Win 7<br>\\t</li><li><strong>Processor:</strong> 2.3 GHz Quad Core processor<br>\\t</li><li><strong>Memory:</strong> 2 GB<br>\\t</li><li><strong>Hard Disk Space:</strong> 20 GB free<br>\\t</li><li><strong>Video Memory:</strong> 512MB<br>\\t</li><li><strong>Video Card:</strong> NVIDIA GeForce GTX 560 / ATI Radeon HD 5850<br>\\t</li><li><strong>Sound:</strong> DirectX 9.0c Compatible<br>\\t</li><li><strong>Other Requirements:</strong>Initial installation requires one-time internet connection for Steam authentication; software installations required (included with the game) include Steam Client, DirectX 9, Microsoft .NET 4 Framework, Visual C++ Redistributable 2005, Visual C++ Redistributable 2008, Visual C++ Redistributable 2010, and AMD CPU Drivers (XP Only/AMD Only)</li></ul>\'}', '3,79', '2,3', '0,15', '0,9', '7,11'),
(50, 'saints row 2', '2009', 0, 0, 9442, 2881, 322, 9.99, 'Saints Row 2 brings true freedom to open-world gaming. Players can play as who they want, how they want, and with whomever they want in this sequel to the much acclaimed and tremendously successful Saints Row.', '{\'minimum\': \'<strong>Minimum:</strong> <br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>Supported OS:</strong>Windows XP or Vista. <br>\\t\\t\\t\\t\\t</li><li><strong>Processor: </strong>2.0 GHz Intel Dual-Core Pentium IV or equivalent or AMD Dual-Core Athlon XP or equivalent <br>\\t\\t\\t\\t\\t</li><li><strong>Memory: </strong>1 GB system RAM <br>\\t\\t\\t\\t\\t</li><li><strong>Graphics: </strong>128MB 3D graphics card with Shader Model 3.0 support (i.e. 7600 NVidia card or better, ATI X1300 card or better) <br>\\t\\t\\t\\t\\t</li><li><strong>DirectX Version: </strong>DirectX 9.0c <br>\\t\\t\\t\\t\\t</li><li><strong>Sound: </strong>DirectX 9.0c compatible 16-bit sound card <br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive: </strong>15 GB of Hard Drive Space <br>\\t\\t\\t\\t\\t</li><li><strong>Display: </strong>DirectX compatible display capable of 640x480 in 16-bit color <br>\\t\\t\\t\\t </li></ul>\', \'recommended\': \'<strong>Recommended:</strong> <br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>Supported OS:</strong>Windows XP or Vista. <br>\\t\\t\\t\\t\\t</li><li><strong>Processor: </strong>3.2 GHz Intel Dual-Core Pentium IV or equivalent or AMD Dual-Core Athlon XP or equivalent <br>\\t\\t\\t\\t\\t</li><li><strong>Memory: </strong>2 GB system RAM <br>\\t\\t\\t\\t\\t</li><li><strong>Graphics: </strong>256MB 3D graphics card with Shader Model 3.0 support (i.e. 8800 NVidia card or better, ATI HD3850 card or better) <br>\\t\\t\\t\\t\\t</li><li><strong>DirectX Version: </strong>DirectX 9.0c <br>\\t\\t\\t\\t\\t</li><li><strong>Sound: </strong>DirectX 9.0c compatible 16-bit sound card <br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive: </strong>15 GB of Hard Drive Space <br>\\t\\t\\t\\t\\t</li><li><strong>Display: </strong>DirectX compatible display capable of 640x480 in 16-bit color <br>\\t\\t\\t\\t\\t </li></ul>\'}', '2,82', '1,37', '0,04', '0,53', '4,76'),
(51, 'tom clancys splinter cell', '2008', 0, 0, 900, 147, 28, 4.29, 'Infiltrate terrorists\' positions, acquire critical intelligence by any means necessary, execute with extreme prejudice, and exit without a trace! You are Sam Fisher, a highly trained secret operative of the NSA\'s secret arm: Third Echelon.', '{\'minimum\': \'<strong>Minimum: </strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>Supported OS: </strong>Microsoft Windows® 2000/XP<br>\\t\\t\\t\\t\\t</li><li><strong>Processor: </strong>Pentium® III or AMD Athlon™ 800 MHz <br>\\t\\t\\t\\t\\t</li><li><strong>System Memory: </strong>256 MB of RAM or above <br>\\t\\t\\t\\t\\t</li><li><strong>Video Card: </strong>32 MB 3D video card (64<br>\\t\\t\\t\\t\\t</li><li><strong>Sound Card: </strong>Direct X 8.1 compliant sound card (<br>\\t\\t\\t\\t\\t</li><li><strong>DirectX Version: </strong>DirectX® version 8.1 or higher<br>\\t\\t\\t\\t\\t</li><li><strong>Hard Disk: </strong>1.5 GB available hard disk space <br>\\t\\t\\t\\t\\t</li><li><strong>Multiplayer: </strong>Broadband Internet connection </li></ul>\', \'recommended\': \'<strong>Recommended: </strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>Supported OS: </strong>Microsoft Windows® 2000/XP<br>\\t\\t\\t\\t\\t</li><li><strong>Processor: </strong>Pentium® III or AMD Athlon™ 1.0 GHz <br>\\t\\t\\t\\t\\t</li><li><strong>System Memory: </strong>256 MB of RAM or above <br>\\t\\t\\t\\t\\t</li><li><strong>Video Card: </strong>64 MB 3D video card/<br>\\t\\t\\t\\t\\t</li><li><strong>Sound Card: </strong>Direct X 8.1 compliant sound card with surround system<br>\\t\\t\\t\\t\\t</li><li><strong>DirectX Version: </strong>Direct X 8.1 <br>\\t\\t\\t\\t\\t</li><li><strong>Hard Disk: </strong>2.1 GB available hard disk space<br>\\t\\t\\t\\t\\t</li><li><strong>Note:</strong> For an up-to-date list of supported chipsets, video cards, and operating systems, please visit the FAQ for this game at: <a href=\"https://steamcommunity.com/linkfilter/?url=http://support.ubi.com\" target=\"_blank\" rel=\"noopener\" >http://support.ubi.com</a>.</li></ul>\'}', '3,25', '2,23', '0', '0,54', '6'),
(52, 'hitman 2 silent assassin', '2007', 16, 0, 1514, 260, 63, 8.29, 'Enter the realm of a retired assassin, forced back into action by treason. You may be a hired killer but you still have a sense of loyalty and justice. Visit the dark recesses of a world corrupted by crime, greed, degradation and dishonor. And a past that catches up with you.', '{\'minimum\': \'<strong>Minimum: </strong>Microsoft Windows 98/ME/XP, Pentium 3 450 MHz or equivalent, 100% DirectX 8.1 compatible video card with at least 16 megabytes of video memory, 128 MB system RAM, 100% DirectX 8.1 compatible sound card, 800 MB uncompressed free hard drive space, 100% Windows 98/ME/XP compatible mouse and keyboard <br>\\t\\t\\t\\t\\t<strong>Recommended: </strong>Pentium 3 1GHz equivalent or greater, 256 MB system RAM, 100% DirectX 8.1 compatible 3D Accelerator video card with 32 MB video RAM, 100% DirectX 8.1 compatible EAX Advanced HD Sound Card\'}', '2,22', '1,56', '0,04', '0,46', '4,28'),
(53, 'mass effect', '2008', 0, 0, 10107, 666, 612, 7.99, 'As Commander Shepard, you lead an elite squad on a heroic, action-packed adventure throughout the galaxy. Discover the imminent danger from an ancient threat and battle the traitorous Saren and his deadly army to save civilization. The fate of all life depends on your actions!', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>Supported OS:</strong> Microsoft Windows® XP with SP2 or Windows Vista<strong>*</strong> <br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel P4 2.4 Ghz or faster / AMD 2.0 Ghz <br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1.0 GB RAM or more (2.0 GB for Vista) <br>\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> DirectX 9.0c compatible, ATI X1300 XT or greater (ATI X1300, X1300 Pro, X1600 Pro, Radeon 2600 HD, and HD 2400 are below minimum system requirements); NVidia GeForce 6800 or greater (7300, 7600 GS, 8500 are below minimum system requirements) <br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 12.0 GB or more free hard drive space <br>\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX 9.0c compatible <br>\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 9.0c </li></ul>* WINDOWS VISTA OR WINDOWS 7 USERS: Launching “Mass Effect” from Steam requires the setting “Run as Administrator”. If the User Account Control feature of Windows Vista is enabled, launching “Mass Effect” from Steam will result in failure. For users with User Account Control enabled, launch Steam using the “Run as Administrator” option or launch from the windows shortcut. <br><ul class=\"bb_ul\"><li>INTERNET CONNECTION AND END USER LICENSE AGREEMENT REQUIRED TO PLAY. MORE INFORMATION IS AVAILABLE AT <a href=\"https://steamcommunity.com/linkfilter/?url=http://WWW.EA.COM\" target=\"_blank\" rel=\"noopener\" >WWW.EA.COM</a>.</li></ul>\'}', '1,83', '1,39', '0,03', '0,36', '3,61'),
(54, 'medal of honor', '2010', 0, 0, 3209, 1370, 133, 14.99, 'This is a new war. There is a new warrior. He is Tier 1.', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP, Vista, Windows 7<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Pentium D 3.0GHz / Core 2 Duo 2.0GHz / Athlon X2<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2GB<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> GeForce 7800 GT / ATI X1900<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics Memory:</strong> 256MB<br>\\t\\t\\t\\t\\t\\t</li></ul>\'}', '4,47', '3,18', '0,11', '0,85', '8,61'),
(55, 'need for speed hot pursuit', '2010', 0, 0, 11405, 2775, 467, 14.99, 'Become Seacrest County\'s top cop or most wanted racer!', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP SP3, Windows XP 64-bit SP2, Windows Vista SP2 (32- or 64-bit), or Windows 7 (32- or 64-bit). (Not Supported - Windows 95, Windows 98, Windows ME, Windows NT 4.0, and Windows 2000 are not supported.)<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Core® 2 Duo 2.0 GHZ or AMD Athlon X2 64 2.4GHZ; 1.5 GB Windows® XP / 2 GB Windows Vista® - Windows 7®<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1GB (XP), 1.5GB (Vista), 1.5 GB (Windows 7)<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space:</strong> 8 GB free hard disk space. Additional space required for DirectX 9.0c installation and for saved games<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Video Card:</strong> DirectX® 9.0c Compatible 3D-accelerated 256 MB video card with Shader Model 3.0* or higher<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound Card:</strong> DirectX 9.0c Compatible Sound Card<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DVD-ROM:</strong> 8X speed DVD-ROM drive (Disc Users only)<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Online Gameplay:</strong> Broadband connection for online activation and online gameplay - 512 Kbps or faster<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Direct X®:</strong> DirectX 9.0c<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '2,38', '2,67', '0,03', '0,8', '5,89'),
(56, 'saints row the third', '2011', 18, 83, 44810, 1877, 1848, 6.99, 'Get ready for the most out-landish gameplay scenarios ever seen as the Third Street Saints take on the Syndicate!', '{\'minimum\': \'<strong>Minimum:</strong><br><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® XP<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 2GHz Dual Core Processor (Intel® Core 2 Duo or AMD Athlon™ X2) or higher<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2GB System RAM or more<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 320MB Video RAM GPU w/ Shader Model 3.0 support. NVIDIA® GeForce® 8800 series or better. ATI Radeon™ HD3800 series or better<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 9.0c<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 10GB<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> 100% DirectX® 9.0C compliant sound card or equivalent onboard sound<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Co-Op Play:</strong>NVIDIA® GeForce® 8800 cards require 640MB of Video RAM. ATI Radeon™ HD3800 cards require 1GB of Video RAM<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li></ul><strong></strong>\', \'recommended\': \'<strong>Recommended:</strong><br><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Microsoft® Windows® 7<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Any Quad Core Processor (Intel® Core i5 or AMD Phenom™ II X4) or 3.0+ Dual Core CPU<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 4GB System RAM or more<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 1GB Video RAM GPU w/ Shader Model 4.0 support. NVIDIA® GeForce® GTX 400 series or better. ATI Radeon™ HD5000 series or better <br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX® 11<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 10 GB<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> 100% DirectX® 9.0C compliant sound card or equivalent onboard sound<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '2,27', '2,37', '0,25', '0,75', '5,64'),
(57, 'onimusha warlords', '', 0, 0, 0, 0, 0, 0.00, '0', '0', '0,99', '0,48', '1,09', '0,14', '2,7'),
(58, 'mortal kombat x', '2015', 18, 73, 21484, 7154, 1030, 15.99, 'Experience the Next Generation of the #1 Fighting Franchise. Mortal Kombat X combines unparalleled, cinematic presentation with all new gameplay.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> 64-bit: Vista, Win 7, Win 8, Win 10<br></li><li><strong>Processor:</strong> Intel Core i5-750, 2.67 GHz | AMD Phenom II X4 965, 3.4 GHz<br></li><li><strong>Memory:</strong> 3 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 460 | AMD Radeon HD 5850<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 36 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> 64-bit: Win 7, Win 8, Win 10<br></li><li><strong>Processor:</strong> Intel Core i7-3770, 3.4 GHz | AMD FX-8350, 4.0 GHz<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 660 | AMD Radeon HD 7950<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 44 GB available space</li></ul>\'}', '2,48', '1,01', '0', '0,6', '4,1'),
(59, 'need for speed shift', '2009', 0, 0, 1101, 415, 339, 9.99, 'Need for Speed™ SHIFT is an award-winning authentic racing game that combines the true driver’s experience with real-world physics, pixel-perfect car models, and a wide range of authentic race tracks. Need for Speed SHIFT takes players in a different direction to create a simulation experience that replicates the true feeling of driving...', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP (Service Pack 3) / Windows Vista (Service Pack 2) / Windows 7<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 1.6GHz Intel Core2 or faster/AMD X2 3800+ or faster<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> (Windows XP) 1 GB RAM; (Windows Vista/Windows 7) 1.5 GB RAM<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 256 MB Video Card, with support for Pixel Shader 3.0*<br>\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX 9.0c compatible<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 6 GB<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX 9.0c compatible<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Controller Support:</strong> USB Steering Wheel/Dual Analog Gamepad<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Online Multiplayer:</strong> 512 Kbps or faster; 2-8 players<br></li><li>INTERNET CONNECTION, ONLINE AUTHENTICATION AND ACCEPTANCE OF END USER LICENSE AGREEMENT REQUIRED TO PLAY. TO ACCESS ONLINE FEATURES, YOU MUST REGISTER ONLINE. ONLY ONE REGISTRATION IS AVAILABLE PER GAME. EA ONLINE TERMS &amp; CONDITIONS AND FEATURE UPDATES CAN BE FOUND AT <a href=\"https://steamcommunity.com/linkfilter/?url=http://WWW.EA.COM\" target=\"_blank\" rel=\"noopener\" >WWW.EA.COM</a>. YOU MUST BE 13+ TO REGISTER WITH EA ONLINE. EA MAY RETIRE ONLINE FEATURES AFTER 30 DAYS NOTICE POSTED ON <a href=\"https://steamcommunity.com/linkfilter/?url=http://WWW.EA.COM\" target=\"_blank\" rel=\"noopener\" >WWW.EA.COM</a>.<br>\\t\\t\\t\\t\\t</li></ul>\'}', '1,58', '2,81', '0,06', '0,97', '5,42'),
(60, 'final fantasy xiii2', '2014', 16, 31, 1843, 1199, 713, 12.99, 'It is no longer about facing destiny. Create a new future and change the world! Now enhanced for Windows PC.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® XP SP2 or later<br></li><li><strong>Processor:</strong> 2GHz Dual Core CPU<br></li><li><strong>Memory:</strong> 1500 MB RAM<br></li><li><strong>Graphics:</strong> NVIDIA® Geforce® 8 Series/ ATI Radeon™ HD 4000 series VRAM 256MB or later<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 30 GB available space<br></li><li><strong>Sound Card:</strong> Sound card compatible with DirectX® 9.0c<br></li><li><strong>Additional Notes:</strong> </li><li>*Please be aware that save data processing may take longer than usual while SteamCloud is active, due to synchronisation with the server.</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® Vista/ 7/ 8<br></li><li><strong>Processor:</strong> Intel® Core™ 2 Quad (2.66 GHz)/ AMD Phenom™ II X4 (2.8 GHz) processor<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA® Geforce® GTX™ 460/ ATI Radeon™ HD 5870<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 30 GB available space<br></li><li><strong>Sound Card:</strong> DirectX® 9.0C compatible sound card<br></li><li><strong>Additional Notes:</strong> </li><li>*Maximum supported frame rate: 60fps</li><li>*Graphic Options</li><li>*Screen Resolution Options</li><li>*A game controller using Xinput is recomended for this game. (If using a DirectInput based controller, please use the driver side key configuration to adjust settings as required )</li></ul>\'}', '1,14', '1,05', '0,91', '0,32', '3,42'),
(61, 'star wars shadows of the empire', '2017', 0, 0, 197, 67, 33, 4.79, 'As Luke Skywalker and the Rebel Alliance struggle to defeat Darth Vader and the Empire, a new threat arises. Dark Prince Xizor aspires to take Darth Vader\'s place at the Emperor\'s side. As Dash Rendar, it\'s up to you to protect Luke and help the Alliance. May the Force be with you!', '{\'minimum\': \'<strong>最低:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 / 8 / 10<br></li><li><strong>プロセッサー:</strong> 1.8 GHz Processor<br></li><li><strong>メモリー:</strong> 1 GB RAM<br></li><li><strong>グラフィック:</strong> DirectX 9.0c Compatible Video Card w/ 256 MB RAM<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>ストレージ:</strong> 329 MB 利用可能</li></ul>\'}', '2', '0,5', '0,12', '0,03', '2,65');
INSERT INTO `jeux` (`id_jeu`, `nom_jeu`, `annee`, `age_requis`, `nb_succes`, `nb_avis_pos`, `nb_avis_neg`, `temps_jeu_moyen`, `prix`, `description`, `configuration`, `ventes_AN`, `ventes_EU`, `ventes_JP`, `ventes_Autre`, `ventes_Global`) VALUES
(62, 'dragon age origins', '2009', 0, 0, 6207, 468, 2061, 14.99, 'You are a Grey Warden, one of the last of a legendary order of guardians. With the return of an ancient foe and the kingdom engulfed in civil war, you have been chosen by fate to unite the shattered lands and slay the archdemon once and for all.', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP (SP3) or Windows Vista (SP1) or Windows 7<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Core 2 Single 1.6 Ghz Processor (or equivalent) or AMD 64 2.0 GHz Processor (or equivalent)<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1GB (1.5 GB Vista and Windows 7)<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> ATI Radeon X850 256MB or NVIDIA GeForce 6600 GT 128MB or greater (Windows Vista: Radeon X1550 256 MB or NVidia GeForce 7600GT 256MB)<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX (November 2007)<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 20 GB HD space<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> Direct X Compatible Sound Card<br>\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br>\\t\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP (SP3) or Windows Vista (SP1) or Windows 7<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Core 2 Duo 2.4 Ghz or AMD Phenom II X2 Dual-Core 2.7 Ghz Processor or equivalent<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2 GB (3GB Vista and Windows 7)<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> ATI 3850 512 MB or NVidia 8800GTS 512MB or greater<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX (November 2007)<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 20 GB HD space<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> Direct X Compatible Sound Card<br>\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '2,72', '1,46', '0,11', '0,5', '4,77'),
(63, 'crazy taxi', '2011', 0, 12, 1240, 273, 17, 5.59, 'Hey hey, come on over and have some fun with Crrrrrazy Taxi! Barrel through traffic packed streets, hurdle off parking garages, and Crazy Combo your way to Crazy Money in a wild frantic race to scare up the most fares. In Crazy Taxi, time is money, and only the Craziest Cabbies come out victorious.', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® XP<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 3.0 GHz Intel Pentium 4<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2GB RAM<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> DirectX 9.0c compatible, NVIDIA GeForce 7300 series, ATI Radeon™ X1600 Video Card with 256MB RAM<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX 9.0c<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 240MB Hard Drive space<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX 9.0c compatible Sound Card<br>\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® 7<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 2.0 GHz Intel Core 2 Duo<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2GB RAM or more<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> DirectX 9.0c/Shader3.0 compatible, NVIDIA GeForce 8800 series or higher, ATI Radeon™ X1900 Video Card with 512MB RAM<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX 9.0c<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 4GB Hard Drive space<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX 9.0c compatible Sound Card<br>\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '2,59', '1,72', '0,2', '0,31', '4,82'),
(64, 'lego harry potter years 14', '2010', 0, 0, 1672, 460, 518, 9.99, 'Build the adventure from Privet Drive to the Triwizard Tournament and experience the magic of the first four Harry Potter stories – LEGO style! Explore Hogwarts™ School of Witchcraft and Wizardry, learn spells, brew potions and relive the adventures like never before with tongue-in-cheek humor and creative customization that is unique to...', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP/Vista<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel P4 1.8 GHz/AMD Athlon XP 2200+<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>RAM:</strong> 512MB<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics Card:</strong> ATI X1300/NVIDIA GeForce FX 5800 (256 MB RAM)<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound Card:</strong> 100% DirectX®9.0c compatible audio device<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Input Devices:</strong> Keyboard; Xbox 360 Controller for Windows supported<br>\\t\\t\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br>\\t\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP/Vista<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Core 2 Duo/AMD Athlon 64, 2.8GHz<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>RAM:</strong> 2GB<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics Card:</strong> ATI HD 2900/NVIDIA GeForce 8800<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound Card:</strong> 100% DirectX®9.0c compatible audio device<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Input Devices:</strong> Keyboard; Xbox 360 Controller for Windows supported<br>\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '4,01', '3,5', '0', '1,01', '8,53'),
(65, 'final fantasy v', '2015', 12, 96, 489, 198, 0, 10.99, 'Return to the classic medieval tale of magic, monsters and friendship as FINAL FANTASY V comes to PC!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Win Vista 32-bit<br></li><li><strong>Processor:</strong> Pentium 4, 2.4 GHz<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>DirectX:</strong> Version 10</li></ul>\'}', '0', '0', '2,59', '0,03', '2,62'),
(66, 'riven the sequel to myst', '2010', 0, 0, 288, 103, 0, 3.99, 'Prepare to enter a world &quot;torn asunder&quot; by timeless, unresolved conflicts--a world of incomparable beauty, intrigue, and betrayal. Prepare to go to Riven. Journey through vast, awe-inspiring landscapes, where clouds sit nestled in a deep blue sky and the rolling sea waters shimmer from bright morning sunlight.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 / 8 / 10<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 1.8 GHz<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 512 MB RAM<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space:</strong> 7 GB available HD space<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Video:</strong> DirectX® 9.0c compatible or better<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX® 9.0 compatible<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX 9.0c or greater<br>\\t\\t\\t\\t\\t\\t</li></ul>\'}', '1,7', '0,94', '0', '0,12', '2,75'),
(67, 'tom clancys rainbow six vegas 2', '2008', 0, 0, 2582, 456, 1349, 8.59, 'Tom Clancy\'s Rainbow Six® Vegas 2 - the sequel to the award-winning next-generation first-person shooter - returns to Sin City. Tom Clancy\'s Rainbow Six Vegas 2 is your last chance to rescue America\'s sexiest city from an escalating terrorist siege that will force you into heart-pounding action from beginning to end.', '{\'minimum\': \'<strong>Minimum: </strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>Supported OS:</strong> Windows® XP/Vista (only)<br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 3 GHz Pentium 4 or AMD Athlon 3000 (3.5 GHz Pentium 4 or AMD Athlon 3500 recommended) <br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1 GB of RAM<br>\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 128 MB DirectX 9.0c-compliant, Shader 3.0-enabled video card (256 MB recommended) (see supported list*) <br>\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX 9.0c-compliant sound card (NVIDIA nForce or other motherboards/soundcards containing the Dolby Digital Interactive Content Encoder required for Dolby Digital audio.)<br>\\t\\t\\t\\t\\t</li><li><strong>DirectX:</strong> DirectX 9.0c<br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 7 GB free <br>\\t\\t\\t\\t\\t</li><li><strong>Peripherals supported:</strong> Windows-compliant keyboard and mouse, Xbox 360 Controller for Windows <br>\\t\\t\\t\\t\\t</li><li><strong>Multiplayer:</strong> Broadband Internet connection with 128 kbps Kbps upstream or faster. <br>\\t\\t\\t\\t\\t</li><li><strong>*Supported video cards: </strong> ATI RADEON X1600-1950 / HD 2000 / 3000 series, NVIDIA GeForce 6600-6800 / 7 / 8 series ; Laptop versions of these cards are not fully supported. These chipsets are the only ones that will run this game. </li></ul>\'}', '2,22', '1,08', '0,06', '0,44', '3,79'),
(68, 'batman arkham origins', '2013', 16, 60, 20365, 3519, 538, 0.00, 'As of December 4, 2016, the online services portion of Batman: Arkham Origins will be retired. We thank those that have joined us to battle over the last 3 years. The Single player campaign may still be played and enjoyed offline.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong>32-bit: Vista, Win 7, Win 8<br>\\t</li><li><strong>Processor:</strong>Intel Core 2 Duo, 2.4 GHz / AMD Athlon X2, 2.8 GHz<br>\\t</li><li><strong>Memory:</strong>2 GB RAM<br>\\t</li><li><strong>Graphics:</strong>NVIDIA GeForce 8800 GTS / AMD Radeon HD 3850 or better with 512 MB of VRAM<br>\\t</li><li><strong>DirectX®:</strong>9.0c<br> </li><li><strong>Hard Drive Space:</strong>20 GB<br> </li><li><strong>Other Requirements:</strong>Broadband Internet connection<br> </li><li><strong>Additional Notes:</strong>Windows XP and DirectX® 9.0b and below not supported</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong>64-bit: Vista, Win 7, Win 8<br>\\t</li><li><strong>Processor:</strong>Intel Core i5-750, 2.67 GHz / AMD Phenom II X4 965, 3.4 GHz<br>\\t</li><li><strong>Memory:</strong>4 GB RAM<br>\\t</li><li><strong>Graphics:</strong>NVIDIA GeForce GTX 560 / AMD Radeon HD 6950 or better with 768 MB+ of VRAM (DirectX 11 Compatible)<br>\\t</li><li><strong>DirectX®:</strong>11<br> </li><li><strong>Hard Drive Space:</strong>20 GB<br> </li><li><strong>Other Requirements:</strong>Broadband Internet connection<br> </li><li><strong>Additional Notes:</strong>Windows XP and DirectX® 9.0b and below not supported</li></ul>\'}', '2,55', '1,73', '0,04', '0,64', '4,97'),
(69, 'halflife 2', '2004', 0, 33, 67902, 2419, 691, 7.19, '1998. HALF-LIFE sends a shock through the game industry with its combination of pounding action and continuous, immersive storytelling. Valve\'s debut title wins more than 50 game-of-the-year awards on its way to being named \"Best PC Game Ever\" by PC Gamer, and launches a franchise with more than eight million retail units sold worldwide.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7, Vista, XP<br></li><li><strong>Processor:</strong> 1.7 Ghz<br></li><li><strong>Memory:</strong> 512 MB RAM<br></li><li><strong>Graphics:</strong> DirectX 8.1 level Graphics Card (requires support for SSE)<br></li><li><strong>Storage:</strong> 6500 MB available space</li></ul>\'}', '2,65', '0,23', '0,08', '0,03', '2,98'),
(70, 'grand theft auto', '2008', 0, 0, 199, 30, 7, 0.00, 'Drive dozens of varied vehicles around three of America\'s toughest cities. Only the best will be able to tame the fastest cars. Only the smartest will know all the short-cuts and the whereabouts of the hottest wheels. Only the toughest will be able to take on the world and finish the job like a professional...', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> DOS 6.0, Windows 95, Windows 98<br>\\t</li><li><strong>Processor:</strong> 75 MHz Pentium or equivalent<br>\\t</li><li><strong>Memory:</strong> 16 Mb of RAM<br>\\t</li><li><strong>Hard Disk Space:</strong> 80 MB of Hard Disk Space<br>\\t</li><li><strong>Video Card:</strong> 1MB VESA compatible SVGA graphics card<br>\\t</li><li><strong>Sound:</strong> Sound Card</li></ul>\'}', '0,96', '1,41', '0,04', '0,14', '2,56'),
(71, 'chrono trigger', '2018', 0, 13, 1121, 376, 0, 11.99, 'The timeless RPG classic returns loaded with upgrades! Journey to the forgotten past, to the far future, and to the end of time.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7/8/8.1/10 (32bit/64bit)<br></li><li><strong>Processor:</strong> Intel Core i3 2.3GHz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> INTEL HD Graphics 530<br></li><li><strong>Storage:</strong> 2 GB available space<br></li><li><strong>Additional Notes:</strong> Supported resolutions: 800x600, 1024x768, 1280x960, 1280x720, 1360x768, 1600x900, 1920x1080.</li></ul>\'}', '0,97', '0,2', '2,51', '0,1', '3,78'),
(72, 'lego marvel super heroes', '2013', 0, 45, 8797, 691, 4034, 14.99, 'LEGO® Marvel™ Super Heroes features an original story crossing the entire Marvel Universe. Players take control of Iron Man, Spider-Man, the Hulk, Captain America, Wolverine and many more Marvel characters as they unite to stop Loki and a host of other Marvel villains from assembling a super-weapon capable of destroying the world.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows®XP SP3, Windows Vista/7/8 with latest service packs and updates installed<br></li><li><strong>Processor:</strong> AMD Athlon 64 X2 EE 3800+ (2*2000 Mhz) or similar Intel CPU, such as Intel Pentium Dual Core E2180 (2*2000 Mhz)<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce 7600 GS or ATI Radeon X1950 Pro or better<br></li><li><strong>DirectX:</strong> Version 10<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 7 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP/Vista/7/8<br></li><li><strong>Processor:</strong> AMD or Intel Quad Core running at 4*2600 Mhz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 480 or ATI Radeon HD 5850 or better<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 8 GB available space</li></ul>\'}', '4,41', '4,14', '0,08', '1,23', '9,86'),
(73, 'prince of persia the sands of time', '2009', 0, 0, 831, 122, 167, 8.59, 'Amidst the scorched sands of ancient Persia, there is a legend spun in an ancient tongue. It speaks of a time borne by blood and ruled by deceit. Drawn to the dark powers of a magic dagger, a young Prince is led to unleash a deadly evil upon a beautiful kingdom.', '{\'minimum\': \'<p><strong>Minimum: </strong></p>\\n\\t\\t\\t\\t\\t<ul>\\n\\t\\t\\t\\t\\t<li><strong>Supported OS: </strong>Windows&reg; 2000/XP (only)</li>\\n\\t\\t\\t\\t\\t<li><strong>Processor: </strong>800 MHz Pentium&reg; III or AMD Athlon&trade;</li>\\n\\t\\t\\t\\t\\t<li><strong>System Memory: </strong>256 MB of RAM</li>\\n\\t\\t\\t\\t\\t<li><strong>Video Card: </strong>64 MB GeForce&trade; 3 or higher, or ATI&reg; Radeon&trade; 8500 or higher, Matrox Parhelia&trade;. (GeForce4 MX not supported)</li>\\n\\t\\t\\t\\t\\t<li><strong>Sound Card: </strong>DirectX&reg; 9.0 or higher compliant sound card</li>\\n\\t\\t\\t\\t\\t<li><strong>DirectX Version: </strong>DirectX&reg; version 9.0c or higher</li>\\n\\t\\t\\t\\t\\t<li><strong>Hard Disk: </strong>1.5 GB available hard disk space</li>\\n\\t\\t\\t\\t\\t<li><strong>Supported Peripherals: </strong>ThrustMaster FIRESTORM Dual Analog 3</li>\\n\\t\\t\\t\\t\\t<li><strong>Note:</strong> For an up-to-date list of supported chipsets, video cards, and operating systems, please visit the FAQ for this game at: http://support.ubi.com.</li></ul>\'}', '1,81', '1,46', '0', '0,36', '3,63'),
(74, 'star wars knights of the old republic', '2009', 0, 0, 11569, 1590, 660, 7.19, 'It is four thousand years before the Galactic Empire and hundreds of Jedi Knights have fallen in battle against the ruthless Sith. You are the last hope of the Jedi Order. Can you master the awesome power of the Force on your quest to save the Republic? Or will you fall to the lure of the dark side?', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP and Windows Vista<br>\\t\\t\\t</li><li><strong>Processor:</strong> Intel Pentium 3 1Ghz or AMD Athlon 1GHz<br>\\t\\t\\t</li><li><strong>Memory:</strong> 256 RAM<br>\\t\\t\\t</li><li><strong>Graphics:</strong> 32 MB with Hardware T&amp;L<br>\\t\\t\\t</li><li><strong>DirectX®:</strong> Directx 9.0b or better<br>\\t\\t\\t</li><li><strong>Hard Drive:</strong> 3.5 GB<br>\\t\\t\\t</li><li><strong>Sound:</strong> Directx 9.0b compatible<br>\\t\\t\\t</li></ul>\'}', '1,69', '0,54', '0', '0,1', '2,33'),
(75, 'hitman absolution', '2012', 18, 47, 23277, 2478, 650, 14.99, 'The original assassin is back! Betrayed by the Agency and hunted by the police, Agent 47 finds himself pursuing redemption in a corrupt and twisted world.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista, 7<br>\\t</li><li><strong>Processor:</strong> True dual core CPU (Intel, AMD) <br>\\t</li><li><strong>Hard Drive Space:</strong> 24GB<br>\\t</li><li><strong>Memory:</strong> 2 GB RAM <br>\\t</li><li><strong>Video Card:</strong> NV8600 512 Mb RAM, or AMD equivalent<br>\\t</li><li><strong>DirectX®:</strong> 10</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 64-bit<br>\\t</li><li><strong>Processor:</strong> Intel Core i7 or AMD Athlon II X4<br>\\t</li><li><strong>Hard Drive Space:</strong> 24GB<br>\\t</li><li><strong>Memory:</strong> 4 GB RAM <br>\\t</li><li><strong>Video Card:</strong> NVIDIA GeForce GTX 260 or ATI Radeon HD 5770<br>\\t</li><li><strong>DirectX®:</strong> 11</li></ul>\'}', '1,3', '2,14', '0,08', '0,66', '4,2'),
(76, 'tom clancys rainbow six siege', '2015', 0, 0, 251178, 59620, 7504, 16.99, 'Tom Clancy\'s Rainbow Six Siege is the latest installment of the acclaimed first-person shooter franchise developed by the renowned Ubisoft Montreal studio.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7, Windows 8.1, Windows 10 (64bit versions required)<br></li><li><strong>Processor:</strong> Intel Core i3 560 @ 3.3 GHz or AMD Phenom II X4 945 @ 3.0 GHz<br></li><li><strong>Memory:</strong> 6 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 460 or AMD Radeon HD 5870 (DirectX-11 compliant with 1GB of VRAM)<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 61 GB available space<br></li><li><strong>Sound Card:</strong> DirectX® 9.0c compatible sound card with latest drivers<br></li><li><strong>Additional Notes:</strong> SUPPORTED VIDEO CARDS AT TIME OF RELEASE: GeForce GTX 460 or better, GTX 560 or better, GTX 650 or better, GTX 750 or better, or any card from the GT900 and Titan Series, Radeon HD5870 or better, HD6870 or better, HD7770 or better, R7 260X or better, or any card from the R-300 series and Fury X. Laptop models of these cards may work but are not supported. These chipsets are the only ones that will run this game. Additional chipsets may be supported after release. For an up-to-date list of supported chipsets, please visit the FAQ for this game on our support website: <a href=\"https://steamcommunity.com/linkfilter/?url=http://support.ubi.com\" target=\"_blank\" rel=\"noopener\" >http://support.ubi.com</a>. Game contains FairFight <a href=\"https://steamcommunity.com/linkfilter/?url=http://(https://www.gameblocks.com/products)\" target=\"_blank\" rel=\"noopener\" >(https://www.gameblocks.com/products)</a> and BattleEye <a href=\"https://steamcommunity.com/linkfilter/?url=http://(https://www.battleye.com/)\" target=\"_blank\" rel=\"noopener\" >(https://www.battleye.com/)</a> anti-cheat technology.</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 SP1, Windows 8.1, Windows 10 (64bit versions required)<br></li><li><strong>Processor:</strong> Intel Core i5-2500K @ 3.3 GHz or better or AMD FX-8120 @ 3.1 Ghz or better<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 670 (or GTX 760 / GTX 960) or AMD Radeon HD 7970 (or R9 280x [2GB VRAM] / R9 380 / Fury X)<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 61 GB available space<br></li><li><strong>Sound Card:</strong> DirectX® 9.0c compatible sound card 5.1 with latest drivers<br></li><li><strong>Additional Notes:</strong> SUPPORTED VIDEO CARDS AT TIME OF RELEASE: GeForce GTX 460 or better, GTX 560 or better, GTX 650 or better, GTX 750 or better, or any card from the GT900 and Titan Series, Radeon HD5870 or better, HD6870 or better, HD7770 or better, R7 260X or better, or any card from the R-300 series and Fury X. Laptop models of these cards may work but are not supported. These chipsets are the only ones that will run this game. Additional chipsets may be supported after release. For an up-to-date list of supported chipsets, please visit the FAQ for this game on our support website: <a href=\"https://steamcommunity.com/linkfilter/?url=http://support.ubi.com\" target=\"_blank\" rel=\"noopener\" >http://support.ubi.com</a>. Game contains FairFight <a href=\"https://steamcommunity.com/linkfilter/?url=http://(https://www.gameblocks.com/products)\" target=\"_blank\" rel=\"noopener\" >(https://www.gameblocks.com/products)</a> and BattleEye <a href=\"https://steamcommunity.com/linkfilter/?url=http://(https://www.battleye.com/)\" target=\"_blank\" rel=\"noopener\" >(https://www.battleye.com/)</a> anti-cheat technology.</li></ul>\'}', '1,39', '1,68', '0,13', '0,46', '3,66'),
(77, 'mahjong', '2017', 0, 10, 34, 11, 0, 6.99, 'Play a Zen game! Rediscover the famous traditional Chinese game. Find all the matching pairs of tiles, being careful not to become blocked in, to get to the end of each level. Concentration and perceptiveness are needed to finish the gorgeous boards that we have produced for you.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7<br></li><li><strong>Processor:</strong> Intel Pentium Dual-Core E5200 (2.5GHz)<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> Intel HD Graphics 4000<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 460 MB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 10<br></li><li><strong>Processor:</strong> Intel Core i5<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> Nvidia Geforce GT 730 / AMD Radeon R7 250<br></li><li><strong>DirectX:</strong> Version 12<br></li><li><strong>Storage:</strong> 460 MB available space</li></ul>\'}', '0,01', '0', '2,13', '0', '2,14'),
(78, 'mahjong', '2017', 0, 10, 34, 11, 0, 6.99, 'Play a Zen game! Rediscover the famous traditional Chinese game. Find all the matching pairs of tiles, being careful not to become blocked in, to get to the end of each level. Concentration and perceptiveness are needed to finish the gorgeous boards that we have produced for you.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7<br></li><li><strong>Processor:</strong> Intel Pentium Dual-Core E5200 (2.5GHz)<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> Intel HD Graphics 4000<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 460 MB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 10<br></li><li><strong>Processor:</strong> Intel Core i5<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> Nvidia Geforce GT 730 / AMD Radeon R7 250<br></li><li><strong>DirectX:</strong> Version 12<br></li><li><strong>Storage:</strong> 460 MB available space</li></ul>\'}', '0,01', '0', '2,13', '0', '2,14'),
(79, 'far cry primal', '2016', 18, 0, 8428, 2633, 949, 41.99, 'The award-winning Far Cry franchise returns with its innovative open world gameplay, bringing together massive beasts, breathtaking environments, and unpredictable savage encounters. Welcome to the Stone Age, a time of danger and adventure.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7, Windows 8.1, Windows 10 (64-bit versions only)<br></li><li><strong>Processor:</strong> Intel Core i3-550 | AMD Phenom II X4 955 or equivalent<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 460 (1GB VRAM) | AMD Radeon HD 5770 (1GB VRAM) or equivalent<br></li><li><strong>Storage:</strong> 20 GB available space<br></li><li><strong>Additional Notes:</strong> Windows-compatible keyboard, mouse, headset, optional controller. Supported Video Cards at Time of Release: AMD Radeon™ HD 5770 (1 GB VRAM) or better, HD 7000 / 200 / 300 / Fury X series, NVIDIA® GeForce® GTX 460 (1 GB VRAM) or better, GTX 500 / 600 / 700 / 900 / TITAN series. Note: This product supports 64-bit operating systems only. Laptop versions of these cards may work, but are not officially supported. For the most up-to-date requirement listings, please visit the FAQ on our support website at <a href=\"https://steamcommunity.com/linkfilter/?url=http://support.ubi.com\" target=\"_blank\" rel=\"noopener\" >support.ubi.com</a>. HIGH SPEED INTERNET ACCESS AND A VALID UPLAY ACCOUNT REQUIRED TO ACTIVATE THE GAME AFTER INSTALLATION, TO AUTHENTICATE YOUR SYSTEM AND CONTINUE GAMEPLAY AFTER ANY RE-ACTIVATION, TO ACCESS ONLINE FEATURES AND TO UNLOCK EXCLUSIVE CONTENT. SUCH CONTENT MAY ONLY BE UNLOCKED ONE SINGLE TIME WITH A UNIQUE KEY. YOU MUST BE AT LEAST 13 TO CREATE A UPLAY ACCOUNT WITHOUT PARENTAL CONSENT. UBISOFT MAY CANCEL ACCESS TO ONE OR MORE SPECIFIC ONLINE FEATURES UPON 30-DAYS PRIOR NOTICE, PUBLISHED AT <a href=\"https://steamcommunity.com/linkfilter/?url=http://www.farcrygame.com\" target=\"_blank\" rel=\"noopener\" >www.farcrygame.com</a>. Game contains Denuvo <a href=\"https://steamcommunity.com/linkfilter/?url=http://(https://www.denuvo.com/)\" target=\"_blank\" rel=\"noopener\" >(https://www.denuvo.com/)</a> anti-tamper technology.</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7, Windows 8.1, Windows 10 (64-bit versions only)<br></li><li><strong>Processor:</strong> Intel Core i7-2600K | AMD FX-8350 or equivalent<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 780 | AMD Radeon R9 280X or equivalent<br></li><li><strong>Storage:</strong> 20 GB available space<br></li><li><strong>Additional Notes:</strong> Windows-compatible keyboard, mouse, headset, optional controller. Supported Video Cards at Time of Release: AMD Radeon™ HD 5770 (1 GB VRAM) or better, HD 7000 / 200 / 300 / Fury X series, NVIDIA® GeForce® GTX 460 (1 GB VRAM) or better, GTX 500 / 600 / 700 / 900 / TITAN series. Note: This product supports 64-bit operating systems only. Laptop versions of these cards may work, but are not officially supported. For the most up-to-date requirement listings, please visit the FAQ on our support website at <a href=\"https://steamcommunity.com/linkfilter/?url=http://support.ubi.com\" target=\"_blank\" rel=\"noopener\" >support.ubi.com</a>. HIGH SPEED INTERNET ACCESS AND A VALID UPLAY ACCOUNT REQUIRED TO ACTIVATE THE GAME AFTER INSTALLATION, TO AUTHENTICATE YOUR SYSTEM AND CONTINUE GAMEPLAY AFTER ANY RE-ACTIVATION, TO ACCESS ONLINE FEATURES AND TO UNLOCK EXCLUSIVE CONTENT. SUCH CONTENT MAY ONLY BE UNLOCKED ONE SINGLE TIME WITH A UNIQUE KEY. YOU MUST BE AT LEAST 13 TO CREATE A UPLAY ACCOUNT WITHOUT PARENTAL CONSENT. UBISOFT MAY CANCEL ACCESS TO ONE OR MORE SPECIFIC ONLINE FEATURES UPON 30-DAYS PRIOR NOTICE, PUBLISHED AT <a href=\"https://steamcommunity.com/linkfilter/?url=http://www.farcrygame.com\" target=\"_blank\" rel=\"noopener\" >www.farcrygame.com</a>. Game contains Denuvo <a href=\"https://steamcommunity.com/linkfilter/?url=http://(https://www.denuvo.com/)\" target=\"_blank\" rel=\"noopener\" >(https://www.denuvo.com/)</a> anti-tamper technology.</li></ul>\'}', '1,09', '1,57', '0,06', '0,41', '3,12'),
(80, 'portal 2', '2011', 0, 51, 138220, 1891, 1102, 7.19, 'The &quot;Perpetual Testing Initiative&quot; has been expanded to allow you to design co-op puzzles for you and your friends!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 / Vista / XP<br></li><li><strong>Processor:</strong> 3.0 GHz P4, Dual Core 2.0 (or higher) or AMD64X2 (or higher)<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> Video card must be 128 MB or more and with support for Pixel Shader 2.0b (ATI Radeon X800 or higher / NVIDIA GeForce 7600 or higher / Intel HD Graphics 2000 or higher).<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 8 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c compatible</li></ul>\'}', '2,57', '1,46', '0,03', '0,53', '4,6'),
(81, 'dead rising', '2016', 0, 50, 1595, 190, 166, 15.99, 'You are Frank West. A hard-edged photojournalist hellbent on investigating the mystery at Willamette Mall. It\'s swarming with zombies. You have 72 hours. Chop \'till you drop!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7/8/10 64-bit versions<br></li><li><strong>Processor:</strong> Intel® Core™ 2 Duo 2.4 Ghz or better, AMD Athlon™ X2 2.8 Ghz or better<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA® GeForce® 550TI/ AMD 6770<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 8 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7/8/10 64-bit versions<br></li><li><strong>Processor:</strong> Intel® Core i5 family or AMD equivalent<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA® GeForce® GTX 560 or better / AMD 7790 or better<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 8 GB available space</li></ul>\'}', '1,17', '0,65', '0,08', '0,2', '2,11'),
(82, 'need for speed undercover', '2008', 0, 0, 2351, 1081, 916, 9.99, 'Chase or Be Chased. You never thought it would turn out like thisan all-out chase where you\'re the hunted. And the hunter. Now you must get behind the wheel and risk everything to infiltrate a ruthless international crime syndicate and take them down.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>Supported OS:</strong> Microsoft Windows® Windows XP (SP2), Windows Vista<br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Pentium® 4 or equivalent, 3.0 GHz or faster<br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 5XP: 512 MB RAM / Vista: 1 GB RAM<br>\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 128 MB or more, NVIDIA GeForce (6600 or better); ATI Radeon (9500 or better); Intel G45 Express Chipset<br>\\t\\t\\t\\t\\t</li><li><strong>Drivers:</strong> DirectX® 9.0c (included) and latest video drivers<br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 6.0 GB free space <br>\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX 9.0c compatible sound card </li></ul><ul class=\"bb_ul\"><li>INTERNET CONNECTION, ONLINE AUTHENTICATION AND ACCEPTANCE OF END USER LICENSE AGREEMENT REQUIRED TO PLAY. TO ACCESS ONLINE FEATURES, YOU MUST REGISTER ONLINE. ONLY ONE REGISTRATION IS AVAILABLE PER GAME. EA ONLINE TERMS &amp; CONDITIONS AND FEATURE UPDATES CAN BE FOUND AT <a href=\"https://steamcommunity.com/linkfilter/?url=http://WWW.EA.COM\" target=\"_blank\" rel=\"noopener\" >WWW.EA.COM</a>. YOU MUST BE 13+ TO REGISTER WITH EA ONLINE. EA MAY RETIRE ONLINE FEATURES AFTER 30 DAYS NOTICE POSTED ON <a href=\"https://steamcommunity.com/linkfilter/?url=http://WWW.EA.COM\" target=\"_blank\" rel=\"noopener\" >WWW.EA.COM</a>.</li></ul>\'}', '2,48', '2,55', '0,12', '1,79', '6,92'),
(83, 'dead space', '2009', 0, 0, 9136, 1049, 295, 14.99, 'Only the Dead Survive. A massive deep-space mining ship goes dark after unearthing a strange artifact on a distant planet. Engineer Isaac Clarke embarks on the repair mission, only to uncover a nightmarish blood bath  the ship\'s crew horribly slaughtered and infected by alien scourge.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>Supported OS:</strong> Microsoft Windows® XP SP2 or Vista <br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 2.8 GHz or faster <br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1 GB RAM or more for Windows XP (2 GB for Vista) <br>\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> DirectX® 9.0c compatible video card, Shader Model 3.0 required, 256 MB or better, NVIDIA GeForce 6800 or better (7300, 7600 GS, and 8500 are below minimum system requirements), ATI X1600 Pro or better (X1300, X1300 Pro and HD2400 are below minimum system requirements) <br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 7.5 GB free space <br>\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX® 9.0c compatible sound card </li></ul><ul class=\"bb_ul\"><li>INTERNET CONNECTION, ONLINE AUTHENTICATION AND ACCEPTANCE OF END USER LICENSE AGREEMENT REQUIRED TO PLAY. EA MAY RETIRE ONLINE FEATURES AFTER 30 DAYS NOTICE POSTED ON <a href=\"https://steamcommunity.com/linkfilter/?url=http://WWW.EA.COM\" target=\"_blank\" rel=\"noopener\" >WWW.EA.COM</a>.</li></ul>\'}', '1,94', '1,6', '0', '0,49', '4,03'),
(84, 'call of duty 2', '2006', 0, 0, 2434, 236, 750, 14.99, 'Call of Duty® 2 redefines the cinematic intensity and chaos of battle as seen through the eyes of ordinary soldiers fighting together in epic WWII conflicts. The sequel to 2003\'s Call of Duty, winner of over 80 Game of the Year awards, Call of Duty 2 offers more immense, more intense, more realistic battles than ever before, thanks to...', '{\'minimum\': \'<strong>Minimum:</strong> 3D hardware accelerator card required - 100% DirectX 9.0c compatible 64MB hardware accelerator video card and the latest drivers*, Microsoft Windows 2000/XP, Pentium IV 1.4GHz or AMD Athlon XP 1700+ processor or higher, 256MB RAM (512MB RAM recommended), 100% DirectX 9.0c compatible 16-bit sound card and latest drivers, 100% Windows 2000/XP compatible mouse, keyboard and latest drivers, 4.0GB of uncompressed free hard disk space (plus 600MB for Windows 2000/XP swap file)<br>\\t\\t\\t\\t\\tMulti-player Requirements:<br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li>Internet (TCP/IP) and LAN (TCP/IP) play supported<br>\\t\\t\\t\\t\\t</li><li>Internet play requires broadband connection and latest drivers<br>\\t\\t\\t\\t\\t</li><li>LAN play requires network interface card and latest drivers</li></ul>Important Notice: *Some 3D accelerator cards with the chipset listed here may not be compatible with the 3D acceleration features utilized by Call of Duty. Please refer to your hardware manufacturer for 100% DirectX 9.0c compatibility.<br>\\t\\t\\t\\t\\tSupported Chipsets<br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li>ATI Radeon 8500<br>\\t\\t\\t\\t\\t</li><li>ATI Radeon 9000<br>\\t\\t\\t\\t\\t</li><li>ATI Radeon 9200<br>\\t\\t\\t\\t\\t</li><li>ATI Radeon 9500<br>\\t\\t\\t\\t\\t</li><li>ATI Radeon 9600<br>\\t\\t\\t\\t\\t</li><li>ATI Radeon 9700<br>\\t\\t\\t\\t\\t</li><li>ATI Radeon 9800<br>\\t\\t\\t\\t\\t</li><li>ATI Radeon X300<br>\\t\\t\\t\\t\\t</li><li>ATI Radeon X550<br>\\t\\t\\t\\t\\t</li><li>ATI Radeon X600<br>\\t\\t\\t\\t\\t</li><li>ATI Radeon X700<br>\\t\\t\\t\\t\\t</li><li>ATI Radeon X800<br>\\t\\t\\t\\t\\t</li><li>ATI Radeon X850<br>\\t\\t\\t\\t\\t</li><li>nVidia GeForce 2 Ultra<br>\\t\\t\\t\\t\\t</li><li>All nVidia GeForce 3/Ti Series<br>\\t\\t\\t\\t\\t</li><li>All nVidia GeForce 4/Ti Series<br>\\t\\t\\t\\t\\t</li><li>All nVidia GeForce FX Series<br>\\t\\t\\t\\t\\t</li><li>All nVidia GeForce 6 Series<br>\\t\\t\\t\\t\\t</li><li>Recommend nVidia GeForce 7 Series or higher</li></ul>\'}', '1,81', '0,1', '0,01', '0,16', '2,08'),
(85, 'bioshock infinite', '2013', 18, 80, 79442, 3846, 614, 19.99, 'Indebted to the wrong people, with his life on the line, veteran of the U.S. Cavalry and now hired gun, Booker DeWitt has only one opportunity to wipe his slate clean. He must rescue Elizabeth, a mysterious girl imprisoned since childhood and locked up in the flying city of Columbia.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista Service Pack 2 32-bit<br>\\t</li><li><strong>Processor:</strong> Intel Core 2 DUO 2.4 GHz / AMD Athlon X2 2.7 GHz<br>\\t</li><li><strong>Memory:</strong> 2GB<br>\\t</li><li><strong>Hard Disk Space:</strong> 20 GB free<br>\\t</li><li><strong>Video Card:</strong> DirectX10 Compatible ATI Radeon HD 3870 / NVIDIA 8800 GT / Intel HD 3000 Integrated Graphics<br>\\t</li><li><strong>Video Card Memory:</strong> 512 MB\\t<br>\\t</li><li><strong>Sound:</strong> DirectX Compatible</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 Service Pack 1 64-bit<br>\\t</li><li><strong>Processor:</strong> Quad Core Processor<br>\\t</li><li><strong>Memory:</strong> 4GB<br>\\t</li><li><strong>Hard Disk Space:</strong> 30 GB free<br>\\t</li><li><strong>Video Card:</strong> DirectX11 Compatible, AMD Radeon HD 6950 / NVIDIA GeForce GTX 560<br>\\t</li><li><strong>Video Card Memory:</strong> 1024 MB\\t<br>\\t</li><li><strong>Sound:</strong> DirectX Compatible</li></ul>\'}', '2,22', '1,56', '0,06', '0,54', '4,39'),
(86, 'tom clancys rainbow six vegas', '2008', 0, 0, 371, 106, 0, 8.59, 'Tom Clancy\'s Rainbow Six makes its next-generation hardware debut in the most dramatic installment of the renowned first-person shooter franchise to date. Rainbow operatives take to the chaotic streets of Las Vegas as an escalating terrorist siege in \'Sin City\' threatens to take world terrorism to new, uncontrollable heights.', '{\'minimum\': \'<p><strong>Minimum: </strong></p>\\n\\t\\t\\t\\t\\t<ul>\\n\\t\\t\\t\\t\\t<li><strong>Supported OS:</strong> Windows&reg; XP (only)</li>\\n\\t\\t\\t\\t\\t<li><strong>Processor:</strong> 3 GHz Pentium 4 or AMD Athlon 3000 (3.5 GHz Pentium 4 or Athlon 3500 recommended) </li>\\n\\t\\t\\t\\t\\t<li><strong>Memory:</strong> 1 GB (2 GB recommended) </li>\\n\\t\\t\\t\\t\\t<li><strong>Graphics:</strong> 128 MB DirectX 9.0c-compliant, Shader 3.0-enabled video card (256MB recommended) (see supported list*) </li>\\n\\t\\t\\t\\t\\t<li><strong>Sound:</strong> DirectX 9-compliant sound card (PC audio solution containing Dolby Digital Live required for Dolby Digital audio) </li>\\n\\t\\t\\t\\t\\t<li><strong>DirectX:</strong> DirectX 9 or higher</li>\\n\\t\\t\\t\\t\\t<li><strong>Hard Drive:</strong> 7 GB free</li> \\n\\t\\t\\t\\t\\t<li><strong>Peripherals supported:</strong> Windows-compatible mouse and keyboard, Xbox 360 Controller (with additional software download) </li> \\n\\t\\t\\t\\t\\t<li><strong>Multiplayer:</strong> Broadband Internet connection with 128 kbps Kbps upstream or faster. </li> \\n\\t\\t\\t\\t\\t<li><strong>*Supported video cards</strong> NVIDIA GeForce 6600GT / 6800 / 7300 / 7600 / 7800 / 7900, ATI Radeon X1600 / X1800 / X1900 families; Laptop versions of these cards are not fully supported. For an up-to-date list of supported chipsets, video cards, and operating systems, please visit the FAQ for this game at: http://support.ubi.com.</li> </ul>\'}', '1,98', '1,37', '0,05', '0,56', '3,95'),
(87, 'star wars dark forces', '2009', 0, 0, 1501, 171, 99, 4.79, 'Behind a veil of secrecy the evil Empire is creating a doomsday army - one that, if finished, will become the final cog in the Empire\'s arsenal of terror and domination. Your Mission? Join the Rebel Alliance\'s covert operations division, infiltrate the Empire.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 2000, XP or Vista<br>\\t\\t\\t</li><li><strong>Processor:</strong> 486 or higher<br>\\t\\t\\t</li><li><strong>Memory:</strong> 16 MB<br>\\t\\t\\t</li><li><strong>Graphics:</strong> DirectX<br>\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX 5.2<br>\\t\\t\\t</li><li><strong>Hard Drive:</strong> 80 MB<br>\\t\\t\\t</li><li><strong>Sound:</strong> 16-bit sound card<br>\\t\\t\\t<br></li><li><strong>Note:</strong> Due to the age of the title, users may run into a few compatibility issues from use of current hardware. Please see the <a href=\"http://forums.steampowered.com/forums/showthread.php?t=967990\" target=\"_blank\" rel=\"noreferrer\" >forums</a> for more information.<br>\\t\\t\\t</li></ul>\'}', '1,4', '0,98', '0', '0,13', '2,5'),
(88, 'tom clancys ghost recon', '2008', 0, 0, 536, 45, 476, 8.59, 'Eastern Europe, 2008. War has broken out on the borders of Russia and the fate of the world hangs in the balance. That\'s when the call goes out for the Ghostsan elite handful of specially trained Green Berets, armed with the latest technology and trained to use the deadliest weapons.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® 2000/XP (only) <br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 450 MHz Pentium® 2 or equivalent <br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 128 MB <br>\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 16 MB DirectX®-compliant 3D card (see supported list*) <br>\\t\\t\\t\\t\\t</li><li><strong>DirectX Version:</strong> DirectX 8.0 or higher (included) <br>\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX 8-compliant sound card <br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 1 GB <br>\\t\\t\\t\\t\\t</li><li><strong>*Supported Video Cards at Time of Release:</strong> ATI® Rage 128 and RADEON® chips, Intel® 82810 or higher, Matrox Parhelia™, NVIDIA® TNT2 and GeForce™ chips, S3 Pro Savage and UniChrome <br>\\t\\t\\t\\t\\t</li><li>Laptop versions of these chipsets may work but are not supported. These chipsets are currently the only ones that will run this game. </li></ul>\'}', '2,87', '0,9', '0', '0,2', '3,99'),
(89, 'red faction', '2009', 0, 0, 1327, 151, 79, 4.99, 'JOIN THE REVOLUTION! Lured to Mars by the Ultor Corporation\'s promise of a better life, thousands have come to seek their fortune and work for the massive mining company. But all is not as it seems. A deadly plague is sweeping through the barracks, and miners suffer daily abuse at the hands of the Ultor guards.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>Operating System: </strong>Windows® 2000/XP <br> </li><li><strong>DirectX Version: </strong>DirectX 8<br> </li><li><strong>Processor: </strong>Pentium II 400 MHz or greater <br> </li><li><strong>Memory: </strong>64 MB RAM <br> </li><li><strong>Video Card: </strong>3D Graphics Accelerator Card (8MB) <br> </li><li><strong>Sound: </strong>Direct X Certified audio hardware <br> </li></ul>\'}', '0,76', '0,96', '0', '0,2', '1,92'),
(90, 'lego star wars iii the clone wars', '2011', 0, 0, 825, 140, 196, 15.49, 'LEGO Star Wars III: The Clone Wars will allow fans to explore endlessly and laugh their way through the Star Wars galaxy in the most humorous, accessible and action-packed LEGO game to date.', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP SP3, Windows Vista® SP2, or Windows 7<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel P4 2.24 GHz or AMD Athlon 64<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 512 MB RAM<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space:</strong> 8GB<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Video Card:</strong> 256 MB Video Memory with Shader 3.0 support; ATI Radeon X1300 / NVIDIA GeForce FX 5800 /Intel GMA 3-Series<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> 100% DirectX 9.0c compatible Audio Device<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>Processor:</strong> Intel Core 2 Duo or AMD Athlon 64 X2<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Video Card:</strong> 256 MB Video Memory with Shader 3.0 support; ATI Radeon HD 2900 / NVIDIA GeForce 9800<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '3,95', '2,81', '0', '0,82', '7,56'),
(91, 'max payne 3', '2012', 0, 67, 21581, 4374, 464, 14.99, 'No longer a New York City cop, Max Payne moves to São Paulo to protect a wealthy family in an effort to finally escape his troubled past. Combining cutting edge shooting mechanics with a dark and twisted story, Max Payne 3 is a seamless, highly detailed, cinematic experience from Rockstar Games.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 32/64 Service Pack 1<br>\\t</li><li><strong>Processor:</strong> Intel Dual Core 2.4 GHZ - \\xa0i7 3930K 6 Core \\xa0x 3.06 GHZ / AMD Dual Core 2.6 GHZ - FX8150 8 Core x 3.6 GHZ<br>\\t</li><li><strong>Memory:</strong> 2GB - 16GB<br>\\t</li><li><strong>Hard Disk Space:</strong> 35 Gigs<br>\\t</li><li><strong>Video Card:</strong> NVIDIA® 8600 GT 512MB VRAM – NVIDIA® GeForce® GTX 680 2GB VRAM / Radeon HD 3400 512MB VRAM - Radeon HD 7970 3GB VRAM<br>\\t</li><li><strong>Sound Card:</strong> 100% Direct X 9.0 compatible – Direct X 9.0 compatible supporting Dolby Digital Live<br></li><li><strong>Additional:</strong>Please refer to your hardware manufacturer and <a href=\"https://steamcommunity.com/linkfilter/?url=http://support.rockstargames.com/home\" target=\"_blank\" rel=\"noopener\" >http://support.rockstargames.com/home</a> for current compatibility information. Some system components such as mobile chipsets, <br>Integrated, and AGP graphics cards may be incompatible. Unlisted specifications may not be supported by publisher.<br></li><li><strong>Other Requirements:</strong> Initial activation requires internet connection and a valid Rockstar Social Club account (13+ to register); Online play requires log-in to Rockstar Social Club (13+); software installation required including GameShield IronWrap; DirectX and Microsoft Visual C++ 2008 SP1 Redistributable Package (x86).</li></ul>\'}', '1,6', '1,78', '0,07', '0,52', '3,99'),
(92, 'turok 2 seeds of evil', '2017', 0, 14, 983, 58, 0, 14.99, 'Having defeated the Campaigner, Turok throws the Chronocepter into a waiting volcano to destroy it. Unfortunately the blast awakens an even deadlier force - The Primagen. Once again a Turok is tasked with restoring peace to the land and stopping the Primagen from merging Earth with the nether world.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li>Requires a 64-bit processor and operating system<br></li><li><strong>OS:</strong> Windows 7 (64-bit required)<br></li><li><strong>Processor:</strong> Intel or AMD Dual-Core at 2.0 GHz<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> GPU with OpenGL 3.2 or DirectX 10 support<br></li><li><strong>Storage:</strong> 1 GB available space<br></li><li><strong>Sound Card:</strong> 100% DirectX compatible sound card or onboard sound<br></li><li><strong>Additional Notes:</strong> Intel CPUs rendering graphics may not be OpenGL 3.2+ compatible.</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li>Requires a 64-bit processor and operating system<br></li><li><strong>OS:</strong> Windows 10 (64-bit required)<br></li><li><strong>Processor:</strong> Intel Core i5-2300 2.8 GHz/AMD Phenom II X4 945 3.0 GHz or equivalent<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Storage:</strong> 1 GB available space<br></li><li><strong>Sound Card:</strong> 100% DirectX compatible sound card or onboard sound<br></li><li><strong>Additional Notes:</strong> Intel CPUs rendering graphics may not be OpenGL 3.2+ compatible.</li></ul>\'}', '1,37', '0,41', '0,04', '0,04', '1,86');
INSERT INTO `jeux` (`id_jeu`, `nom_jeu`, `annee`, `age_requis`, `nb_succes`, `nb_avis_pos`, `nb_avis_neg`, `temps_jeu_moyen`, `prix`, `description`, `configuration`, `ventes_AN`, `ventes_EU`, `ventes_JP`, `ventes_Autre`, `ventes_Global`) VALUES
(93, 'pinball', '2017', 0, 0, 1, 3, 0, 3.99, '3D Pinball game with an amazing feature: a Table Editor for you to create and play your own tables.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li>Requires a 64-bit processor and operating system<br></li><li><strong>OS:</strong> XP<br></li><li><strong>Processor:</strong> Intel Single Core<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> 2004 GPU<br></li><li><strong>Storage:</strong> 200 MB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li>Requires a 64-bit processor and operating system<br></li><li><strong>OS:</strong> 7<br></li><li><strong>Processor:</strong> Intel Multi Core<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> 2010 GPU<br></li><li><strong>Storage:</strong> 400 MB available space</li></ul>\'}', '0,8', '0,19', '0,83', '0,03', '1,85'),
(94, 'just cause 3', '2015', 18, 66, 37747, 14024, 2086, 11.99, 'With over 1000 km² of complete freedom from sky to seabed, Rico Rodriguez returns to unleash chaos in the most creative and explosive ways imaginable.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Vista SP2 / Windows 7.1 SP1 / Windows 8.1 (64-bit Operating System Required)<br></li><li><strong>Processor:</strong> Intel Core i5-2500k, 3.3GHz / AMD Phenom II X6 1075T 3GHz<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 670 (2GB) / AMD Radeon HD 7870 (2GB)<br></li><li><strong>Storage:</strong> 54 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Vista SP2 / Windows 7.1 SP1 / Windows 8.1 (64-bit Operating System Required)<br></li><li><strong>Processor:</strong> Intel Core i7-3770, 3.4 GHz / AMD FX-8350, 4.0 GHz<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 780 (3GB) / AMD R9 290 (4GB)<br></li><li><strong>Storage:</strong> 54 GB available space</li></ul>\'}', '0,91', '1,51', '0,07', '0,36', '2,85'),
(95, 'secret of mana', '2018', 7, 37, 936, 518, 244, 29.99, 'The memorable adventure of Randi, Primm and Popoi is reborn as Secret of Mana! Originally released in 1993, Secret of Mana is by far the most popular title in the “Mana” series and has now undergone a much-awaited full 3D remake!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 / 8.1 / 10 (64-bit)<br></li><li><strong>Processor:</strong> INTEL Core i3 2.4GHz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> GeForce GT730 / RADEON R7 240<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 11 GB available space<br></li><li><strong>Additional Notes:</strong> Supported resolutions: 960*540, 1280*720, 1920*1080, 2560*1440, 3840*2160. Full Controller Support except if you wish to rename characters</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 / 8.1 / 10 (64-bit)<br></li><li><strong>Processor:</strong> INTEL Core i5 2.00GHz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> GeForce GTX 750 / RADEON R7 260X<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 11 GB available space</li></ul>\'}', '0,25', '0,07', '1,49', '0,02', '1,83'),
(96, 'air combat', '2018', 0, 5, 4, 5, 0, 0.79, 'Board the XF-97 prototype and enjoy a large air battle with a lot of ally and enemy fighters!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7,8,10(64bit)<br></li><li><strong>Processor:</strong> Intel Dual-Core 2GHz or AMD Dual-Core 2GHz<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 1700 MB available space<br></li><li><strong>Sound Card:</strong> </li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7,8,10(64bit)<br></li><li><strong>Processor:</strong> Intel Quad-Core or AMD Octo-Core<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> Nvidia GTX 1050ti,AMD Radeon RX560 or higher<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 1700 MB available space<br></li><li><strong>Sound Card:</strong> </li></ul>\'}', '0,92', '0,33', '0,52', '0,05', '1,83'),
(97, 'the evil within', '2014', 18, 71, 10581, 2363, 635, 14.99, 'Developed by Shinji Mikami -- creator of the seminal Resident Evil series -- and the talented team at Tango Gameworks, The Evil Within embodies the meaning of pure survival horror. Highly-crafted environments, horrifying anxiety, and an intricate story are combined to create an immersive world that will bring you to the height of tension.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> 64-bit Windows 7 SP1/Windows 8.1<br></li><li><strong>Processor:</strong> i7 or an equivalent with four plus core processor<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> GTX 460 or equivalent 1 GB VRAM card<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 50 GB available space<br></li><li><strong>Additional Notes:</strong> It’s worth noting that the 50 GB of space required is for the PC install. When the installation is complete, the game will take up ~41 GB of HDD space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> 64-bit Windows 7 SP1/Windows 8.1<br></li><li><strong>Processor:</strong> i7 with four plus cores<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> GeForce GTX 670 or equivalent with 4GBs of VRAM<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 50 GB available space<br></li><li><strong>Additional Notes:</strong> It’s worth noting that the 50 GB of space required is for the PC install. When the installation is complete, the game will take up ~41 GB of HDD space</li></ul>\'}', '1,5', '1,84', '0,24', '0,56', '4,15'),
(98, 'disneys the lion king', '2017', 0, 0, 37, 25, 14, 6.99, 'Disney The Lion King brings to life the majesty and mystery of Africa through the tale of Simba, a lion cub faced with the challenging transition to maturity. Now, you too can be part of the adventure!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 / 8 / 10<br></li><li><strong>Processor:</strong> 1.8 GHz Processor<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> DirectX 9.0c Compatible Video Card w/ 256 MB RAM<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 9 MB available space</li></ul>\'}', '2,23', '0,76', '0,11', '0,11', '3,2'),
(99, 'just cause 2', '2010', 18, 50, 33636, 3231, 519, 9.99, 'Dive into an adrenaline-fuelled free-roaming adventure with 400 square miles of rugged terrain and hundreds of weapons and vehicles.', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Microsoft Windows Vista (Windows XP is unsupported)<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Dual-core CPU with SSE3 (Athlon 64 X2 4200 / Pentium D 3GHz)<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2GB System Memory<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 10GB of free drive space<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> DX10 compatible graphics card with 256 MB of memory<br>\\t\\t\\t\\t\\t(Nvidia GeForce 8800 series/ ATI Radeon HD 2600 Pro)<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> 100% DirectX 10 compatible sound card<br>\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> Microsoft DirectX 10\\t<br>\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Microsoft Windows Vista SP1 or Windows 7<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Core® 2 Duo 2.6 GHz or AMD Phenom X3 2.4GHz or equivalen<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 3GB system Memory<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> <br>\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> DX10 compatible graphics card with 512 MB of memory<br>\\t\\t\\t\\t\\t(Nvidia GeForce GTS 250 series/ ATI Radeon HD 5750 series) <br>\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> 100% DirectX 10 compatible Dolby Digital 5.1 sound card<br>\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> Microsoft DirectX 10.1\\t<br>\\t\\t\\t\\t\\t</li></ul>\'}', '1,04', '1,89', '0,08', '0,53', '3,53'),
(100, 'star wars starfighter', '2009', 0, 0, 221, 235, 6, 4.79, 'Join three heroic starfighter pilots in harrowing deep space and planetary missions to save the planet of Naboo. Rookie Naboo pilot Rhys Dallows, mercenary Vana Sage and alien pirate Nym form an unlikely alliance as they join together against an unexpected assault on the peaceful planet.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP/Vista/7/8/10<br>\\t\\t\\t</li><li><strong>Processor:</strong> 350 MHz Pentium II, Athlon class, or equivalent CPU<br>\\t\\t\\t</li><li><strong>Memory:</strong> 64 MB RAM Required. 128 MB RAM Required for Windows 2000 and XP.<br>\\t\\t\\t</li><li><strong>Graphics:</strong> 16 MB DirectX 8 compatible PCI or AGP video card<br>\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX 8.0 or greater<br>\\t\\t\\t</li><li><strong>Hard Drive:</strong> 620 MB<br>\\t\\t\\t</li><li><strong>Sound:</strong> 16-bit<br>\\t\\t\\t</li></ul>\'}', '0,61', '0,87', '0,02', '0,26', '1,76'),
(101, 'disneys aladdin', '2017', 0, 0, 22, 12, 2, 6.99, 'Join Aladdin and his pet monkey, Abu, as they race through the marketplace toward their date with destiny. Now, Aladdin will have the chance to spoil Jafar’s devious plans and win the hand of the beautiful princess Jasmine.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 / 8 / 10<br></li><li><strong>Processor:</strong> 1.8 GHz Processor<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> DirectX 9.0c Compatible Video Card w/ 256 MB RAM<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 9 MB available space</li></ul>\'}', '0,96', '0,35', '0,21', '0,27', '1,78'),
(102, 'dishonored', '2012', 0, 80, 41756, 1269, 749, 7.99, 'Dishonored is an immersive first-person action game that casts you as a supernatural assassin driven by revenge. With Dishonored’s flexible combat system, creatively eliminate your targets as you combine the supernatural abilities, weapons and unusual gadgets at your disposal.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista / Windows 7<br>\\t</li><li><strong>Processor:</strong> 3.0 GHz dual core or better<br>\\t</li><li><strong>Memory:</strong> 3 GB system RAM<br>\\t</li><li><strong>Hard Disk Space:</strong> 9 GB<br>\\t</li><li><strong>Video Card:</strong> DirectX 9 compatible with 512 MB video RAM or better (NVIDIA GeForce GTX 460 / ATI Radeon HD 5850)<br>\\t</li><li><strong>Sound:</strong> Windows compatible sound card</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista / Windows 7 (enhanced for 64-bit OS)<br>\\t</li><li><strong>Processor:</strong> 2.4 GHz quad core or better (enhanced for multi-core processors)<br>\\t</li><li><strong>Memory:</strong> 4 GB system RAM<br>\\t</li><li><strong>Hard Disk Space:</strong> 9 GB<br>\\t</li><li><strong>Video Card:</strong> DirectX 9 compatible with 768 MB video RAM or better (NVIDIA GeForce GTX 460 / ATI Radeon HD 5850)<br>\\t</li><li><strong>Sound:</strong> Windows compatible sound card</li></ul>\'}', '2,23', '1,48', '0,07', '0,52', '4,3'),
(103, 'the elder scrolls online', '2017', 18, 0, 33719, 11672, 10659, 14.99, 'Join over 10 million players in the award-winning online multiplayer RPG and experience limitless adventure in a persistent Elder Scrolls world. Battle, craft, steal, or explore, and combine different types of equipment and abilities to create your own style of play. No game subscription required.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 64-bit<br></li><li><strong>Processor:</strong> Intel® Core i3 540 or AMD A6-3620 or higher<br></li><li><strong>Memory:</strong> 3 GB RAM<br></li><li><strong>Graphics:</strong> Direct X 11.0 compliant video card with 1GB RAM (NVidia GeForce 460 or AMD Radeon 6850)<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 85 GB available space<br></li><li><strong>Sound Card:</strong> DirectX compatible sound card</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 64-bit<br></li><li><strong>Processor:</strong> Intel® Core i5 2300 or AMD FX4350<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> Direct X 11.0 compliant video card with 2GB RAM (NVIDIA® GeForce® GTX 750 or AMD Radeon™ HD 7850) or higher<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 85 GB available space<br></li><li><strong>Sound Card:</strong> DirectX compatible sound card</li></ul>\'}', '1,75', '1,64', '0', '0,49', '3,89'),
(104, 'the crew', '2014', 0, 0, 9479, 4636, 657, 25.99, 'The Crew is a revolutionary action-driving MMO, developed exclusively for next-gen consoles and high-end PCs that leverage new hardware capabilities to connect players online like never before. The Crew takes you and your friends on a wild ride across a massive, open-world recreation of the United States that is loaded with exciting...', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 SP1, Windows 8/8.1 (64bit versions)<br></li><li><strong>Processor:</strong> Intel Core2Quad Q9300 @ 2.5 GHz or better AMD Phenom II X4 945 @ 3 GHz or better<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> nVidia GeForce GTX 460 or AMD Radeon HD5870 (1024MB VRAM with Shader Model 5.0 or higher)<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 30 GB available space<br></li><li><strong>Sound Card:</strong> DirectX Compatible Sound Card with latest drivers<br></li><li><strong>Additional Notes:</strong> Keyboard required, XBOX 360 controller optional (or compatible controller). Game contains VMProtect <a href=\"https://steamcommunity.com/linkfilter/?url=http://(http://vmpsoft.com/support/user-manual/introduction/what-is-vmprotect/)\" target=\"_blank\" rel=\"noopener\" >(http://vmpsoft.com/support/user-manual/introduction/what-is-vmprotect/)</a> anti-piracy technology.</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 8/8.1 (64bit)<br></li><li><strong>Processor:</strong> Intel Core2Quad Q9300 @ 2.5 GHz or better AMD Phenom II X4 945 @ 3 GHz or better<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX580 or AMD Radeon HD6950 (1024MB VRAM with Shader Model 5.0 or higher)<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 30 GB available space<br></li><li><strong>Sound Card:</strong> DirectX-compatible<br></li><li><strong>Additional Notes:</strong> Peripherals Supported: Windows-compatible keyboard, mouse, racing wheel, headset, optional controller (Xbox One Controller or Xbox 360 Controller for Windows recommended) Multiplayer: 1024 kbps or faster broadband connection *Supported Video Cards at Time of Release: AMD Radeon™ HD 4870 / 5000 / 6000 / 7000 / R7 / R9 series, NVIDIA® GeForce® GTX 260 / 400 / 500 / 600 / 700 / TITAN series. Game contains VMProtect <a href=\"https://steamcommunity.com/linkfilter/?url=http://(http://vmpsoft.com/support/user-manual/introduction/what-is-vmprotect/)\" target=\"_blank\" rel=\"noopener\" >(http://vmpsoft.com/support/user-manual/introduction/what-is-vmprotect/)</a> anti-piracy technology.</li></ul>\'}', '0,64', '1,75', '0,03', '0,34', '2,75'),
(105, 'saints row iv', '2013', 16, 73, 54091, 4945, 1279, 10.99, 'The US President must save the Earth from alien overlord Zinyak using an arsenal of superpowers and strange weapons in the wildest open world game ever.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista (x86 or x64)<br></li><li><strong>Processor:</strong> Intel Core 2 Quad Q6600 | AMD Athlon II x3<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GTX 260 | AMD Radeon HD 5800 series<br></li><li><strong>DirectX:</strong> Version 10<br></li><li><strong>Storage:</strong> 10 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 (x86 or x64)<br></li><li><strong>Processor:</strong> Intel i3 2100T | AMD Phenom II x4 or higher<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GTX 560 | AMD Radeon HD 6800 series or higher<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 10 GB available space</li></ul>\'}', '1,91', '1,29', '0,13', '0,45', '3,76'),
(106, 'sid meiers civilization v', '2010', 0, 286, 129030, 5565, 4760, 19.99, 'Create, discover, and download new player-created maps, scenarios, interfaces, and more!', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® Vista SP2/ Windows® 7 <br>\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Core 2 Duo 1.8 GHz or AMD Athlon X2 64 2.0 GHz<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2GB RAM <br>\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong>256 MB ATI HD2600 XT or better, 256 MB nVidia 7900 GS or better, or Core i3 or better integrated graphics <br>\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX® version 9.0c <br>\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 8 GB Free <br>\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX 9.0c-compatible sound card <br>\\t\\t\\t\\t\\t\\t</li><li><strong>Note:</strong> Optimized for the touch-screen Ultrabook™ device<br>\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® Vista SP2/ Windows® 7 <br>\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 1.8 GHz Quad Core CPU <br>\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 4 GB RAM <br>\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 512 MB ATI 4800 series or better, 512 MB nVidia 9800 series or better<br>\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX® version 11<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 8 GB Free <br>\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX 9.0c-compatible sound card <br>\\t\\t\\t\\t\\t\\t</li><li><strong>Note:</strong> Optimized for the touch-screen Ultrabook™ device<br>\\t\\t\\t\\t\\t</li></ul>\'}', '0,98', '0,52', '0', '0,19', '1,69'),
(107, 'lego batman 2 dc super heroes', '2012', 0, 0, 969, 129, 988, 14.99, 'Legends Unite! The Dynamic Duo of Batman and Robin join other famous super heroes from the DC Universe including Superman, Wonder Woman and Green Lantern to save Gotham City from destruction at the hands of the notorious villains Lex Luthor and the Joker.', '{\'minimum\': \'<strong> Minimum</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP, Windows Vista or Windows 7<br> </li><li><strong>Processor:</strong> Intel Core 2 Duo 2 GHz or AMD Athlon 64 X2 3800+ - 2x 2000 MHz<br> </li><li><strong>Memory:</strong> 1 GB RAM<br> </li><li><strong>Hard Disk Space:</strong> 10 GB <br> </li><li><strong>Video Card:</strong> NVIDIA 7600, 7800, 8xxx or better, ATI 1950 or better<br> </li><li><strong>DirectX®:</strong> 100% DirectX 9.0c compatible Audio Device <br> </li><li><strong>Sound:</strong> DirectX 9.0c compatible<br> </li><li><strong>Additional:</strong> 100% DirectX 9.0c compatible computer required </li></ul>\', \'recommended\': \'<strong> Recommended</strong><br><ul class=\"bb_ul\"><li><strong>Processor:</strong> Quad core CPU 2.7 GHz<br> </li><li><strong>Memory:</strong> 2 GB RAM <br> </li><li><strong>Video Card:</strong> NVIDIA GeForce 8800 or better; ATI HD3870 or better<br> </li><li><strong>Additional:</strong> 100% DirectX 9.0c compatible computer required </li></ul>\'}', '3,4', '2,31', '0', '0,65', '6,37'),
(108, 'knack', '2018', 0, 150, 10, 3, 0, 0.79, 'Minimalistic arcade platformer. You are able to move only in one direction, can you get through it?', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7, 8, 10<br></li><li><strong>Processor:</strong> Intel Pentium 4 2Ghz<br></li><li><strong>Memory:</strong> 512 MB RAM<br></li><li><strong>Graphics:</strong> 512 MB video memory<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 125 MB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7, 8, 10<br></li><li><strong>Processor:</strong> Intel Pentium 4 2Ghz<br></li><li><strong>Memory:</strong> 512 MB RAM<br></li><li><strong>Graphics:</strong> 1024 MB video memory<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 125 MB available space</li></ul>\'}', '0,43', '0,67', '0,42', '0,15', '1,67'),
(109, 'dying light', '2015', 18, 68, 78192, 6176, 2033, 24.99, 'First-person action survival game set in a post-apocalyptic open world overrun by flesh-hungry zombies. Roam a city devastated by a mysterious virus epidemic. Scavenge for supplies, craft weapons, and face hordes of the infected.', '{\'minimum\': \'<strong>MINIMUM:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® 7 64-bit / Windows® 8 64-bit / Windows® 8.1 64-bit<br>\\t</li><li><strong>Processor:</strong> Intel® Core™ i5-2500 @3.3 GHz / AMD FX-8320 @3.5 GHz<br>\\t</li><li><strong>Memory:</strong> 4 GB RAM DDR3<br>\\t</li><li><strong>Hard Drive:</strong> 40 GB free space<br>\\t</li><li><strong>Graphics:</strong> NVIDIA® GeForce® GTX 560 / AMD Radeon™ HD 6870 (1GB VRAM)<br> </li><li><strong>DirectX®:</strong> Version 11<br> </li><li><strong>Sound:</strong> DirectX® compatible<br> </li><li><strong>Additional Notes:</strong> Laptop versions of graphics cards may work but are NOT officially supported.<br><br>Windows-compatible keyboard, mouse, optional controller (Xbox 360 Controller for Windows recommended)</li></ul>\', \'recommended\': \'<strong>RECOMMENDED:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® 7 64-bit / Windows® 8 64-bit / Windows® 8.1 64-bit<br>\\t</li><li><strong>Processor:</strong> Intel® Core™ i5-4670K @3.4 GHz / AMD FX-8350 @4.0 GHz <br>\\t</li><li><strong>Memory:</strong> 8 GB RAM DDR3<br>\\t</li><li><strong>Hard Drive:</strong> 40 GB free space<br>\\t</li><li><strong>Graphics:</strong> NVIDIA® GeForce® GTX 780 / AMD Radeon™ R9 290 (2GB VRAM)<br> </li><li><strong>DirectX®:</strong> Version 11<br> </li><li><strong>Sound:</strong> DirectX® compatible<br> </li><li><strong>Additional Notes:</strong> Laptop versions of graphics cards may work but are NOT officially supported.<br><br>Windows-compatible keyboard, mouse, optional controller (Xbox 360 Controller for Windows recommended)</li></ul>\'}', '1,17', '1,02', '0,12', '0,35', '2,65'),
(110, 'lego pirates of the caribbean the video game', '2014', 0, 0, 435, 102, 144, 15.49, 'LEGO® Pirates of the Caribbean: The Video Game is an action adventure game that brings the Pirates of the Caribbean world and all its colorful characters to life in LEGO Brick form. Players experience all the memorable scenes from all four films in the humorous and quirky LEGO Video Games style.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Microsoft Windows 7 / XP SP3<br></li><li><strong>Processor:</strong> 2.7 GHz Intel Pentium 4 class or AMD Athlon or equivalent processor<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> 256 MB 3D video card supporting Shaders 3.0 (NVIDIA 8800 GT or higher, ATI Radeon HD 3870 or higher)<br></li><li><strong>Additional Notes:</strong> Onboard (built-in) integrated chipsets are not supported (e.g., Intel on-board 8xx/9xx series chipsets, SiS and S3 series, ATI Mobility Radeon 7500 and X1300)</li></ul>\'}', '2,45', '2,52', '0', '0,67', '5,65'),
(111, 'prince of persia warrior within', '2009', 0, 0, 657, 101, 307, 8.59, 'Enter the dark underworld of Prince of Persia Warrior Within, the sword-slashing sequel to the critically acclaimed Prince of Persia: The Sands of Time&trade;. Hunted by Dahaka, an immortal incarnation of Fate seeking divine retribution, the Prince embarks upon a path of both carnage and mystery to defy his preordained death.', '{\'minimum\': \'<p><strong>Minimum: </strong></p>\\n\\t\\t\\t\\t\\t<ul>\\n\\t\\t\\t\\t\\t<li><strong>Supported OS:</strong> Windows&reg; 2000/XP (only)</li>\\n\\t\\t\\t\\t\\t<li><strong>Processor:</strong> 1 GHz Pentium&reg; III, AMD Athlon&trade;, or equivalent</li>\\n\\t\\t\\t\\t\\t<li><strong>Memory:</strong> 256 MB (512 MB recommended)</li>\\n\\t\\t\\t\\t\\t<li><strong>Graphics:</strong> NVIDIA GeForce 3 or higher, ATI Radeon 7500 or higher, Intel 915G (NVIDIA GeForce 4 or ATI Radeon 9500, or higher recommended)*</li>\\n\\t\\t\\t\\t\\t<li><strong>Sound:</strong> DirectX 9.0-compliant sound card</li>\\n\\t\\t\\t\\t\\t<li><strong>DirectX:</strong> DirectX 9.0c</li>\\n\\t\\t\\t\\t\\t<li><strong>Hard Disk Space:</strong> 1.5 GB available space for minimum installation, 2.2 GB available space for full installation</li>\\n\\t\\t\\t\\t\\t<li><strong>Supported peripherals:</strong> Windows-compatible mouse (required), Dual analog gamepad</li>\\n\\t\\t\\t\\t\\t<li><strong>*Note: </strong>For an up-to-date list of supported chipsets, video cards, and operating systems, please visit the FAQ for this game at: http://support.ubi.com.</li></ul>\'}', '1,17', '1,2', '0', '0,27', '2,64'),
(112, 'rage', '2011', 16, 60, 9394, 2882, 559, 7.99, 'Powered by id’s revolutionary id Tech® 5 technology, RAGE is an intense first-person shooter with breakneck vehicle combat, an expansive world to explore, and jaw-dropping graphics!', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Win XP SP3, Vista, Win 7<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Core 2 Duo or Equivalent AMD<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2GB<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space:</strong> 25GB\\t<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Video Card:</strong> GeForce 8800, Radeon HD 4200<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Win XP SP3, Vista, Win 7<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Core 2 Quad or Equivalent AMD<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 4GB<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space:</strong> 25GB\\t<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Video Card:</strong> GeForce 9800 GTX, Radeon HD 5550<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '1,43', '1,38', '0,09', '0,42', '3,32'),
(113, 'no mans sky', '2016', 0, 27, 63444, 56488, 2004, 39.99, 'No Man\'s Sky is a game about exploration and survival in an infinite procedurally generated universe.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li>Requires a 64-bit processor and operating system<br></li><li><strong>OS:</strong> Windows 7/8.1/10 (64-bit versions)<br></li><li><strong>Processor:</strong> Intel Core i3<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> nVidia GTX 480, AMD Radeon 7870<br></li><li><strong>Storage:</strong> 10 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li>Requires a 64-bit processor and operating system</li></ul>\'}', '0,58', '0,74', '0,02', '0,26', '1,6'),
(114, 'devil may cry 4', '2009', 0, 0, 1620, 144, 789, 15.99, 'Devil May Cry® 4 immerses gamers in a gothic supernatural world, where a new protagonist clashes with a familiar hero. As the new leading man, Nero, players will unleash incredible attacks and non-stop combos using a unique new gameplay mechanic, his powerful &quot;Devil Bringer&quot; arm.', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP Service Pack 2<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel 4 Pentium processor or better<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 512 MB<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> NVIDIA GeForce 6600 series or better<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 8GB of free space<br>\\t\\t\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br>\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Core 2 Duo processor or better<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1GB<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> NVIDIA GeForce 8600 series or better<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 8GB of free space<br>\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '1,39', '0,82', '0,5', '0,35', '3,07'),
(115, 'wolfenstein the new order', '2014', 18, 50, 26727, 3011, 539, 14.99, 'Wolfenstein®: The New Order reignites the series that created the first-person shooter genre. Under development at Machine Games, a studio comprised of a seasoned group of developers recognized for their work creating story-driven games, Wolfenstein offers a deep game narrative packed with action, adventure and first-person combat.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li>Requires a 64-bit processor and operating system<br></li><li><strong>OS:</strong> 64-bit Windows 7/Windows 8<br></li><li><strong>Processor:</strong> Intel Core i7 or equivalent AMD<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> GeForce 460, ATI Radeon HD 6850<br></li><li><strong>Storage:</strong> 50 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li>Requires a 64-bit processor and operating system<br></li><li><strong>Additional Notes:</strong> AMD Radeon users: Please install AMD Catalyst™ 14.4</li></ul>\'}', '1,24', '1,81', '0,05', '0,53', '3,63'),
(116, 'conflict desert storm', '2012', 0, 0, 376, 93, 0, 4.99, 'Take charge of the most feared special operations forces in the world: the elite British SAS or the US Delta Force squads. You\'re the best trained, best equipped and best organised. The area that has been assigned to you is yours for the taking. Seek, locate and destroy enemy targets and personnel.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP or Windows Vista<br>\\t</li><li><strong>Processor:</strong> 1.8 GHz Processor<br>\\t</li><li><strong>Memory:</strong> 512MB RAM (1 GB recommended)<br>\\t</li><li><strong>Hard Disk Space:</strong> 2GB HDD<br>\\t</li><li><strong>Video Card:</strong> 3D graphics card compatible with DirectX 7 (compatible with DirectX 9 recommended)<br>\\t</li><li><strong>DirectX®:</strong> 7</li></ul>\'}', '1,52', '0,92', '0', '0,08', '2,52'),
(117, 'dark souls iii', '2016', 0, 43, 100412, 9953, 4222, 39.99, 'Dark Souls continues to push the boundaries with the latest, ambitious chapter in the critically-acclaimed and genre-defining series. Prepare yourself and Embrace The Darkness!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 SP1 64bit, Windows 8.1 64bit Windows 10 64bit<br></li><li><strong>Processor:</strong> Intel Core i3-2100 / AMD® FX-6300<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA® GeForce GTX 750 Ti / ATI Radeon HD 7950<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 25 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 11 sound device<br></li><li><strong>Additional Notes:</strong> Internet connection required for online play and product activation</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 SP1 64bit, Windows 8.1 64bit Windows 10 64bit<br></li><li><strong>Processor:</strong> Intel Core i7-3770 / AMD® FX-8350<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA® GeForce GTX 970 / ATI Radeon R9 series<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 25 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 11 sound device<br></li><li><strong>Additional Notes:</strong> Internet connection required for online play and product activation</li></ul>\'}', '0,81', '0,58', '0,33', '0,24', '1,96'),
(118, 'mafia ii', '2011', 18, 67, 31445, 1855, 1029, 19.99, 'Vito Scaletta has started to make a name for himself on the streets of Empire Bay as someone who can be trusted to get a job done. Together with his buddy Joe, he is working to prove himself to the Mafia, quickly escalating up the family ladder with crimes of larger reward, status and consequence… the life as a wise guy isn’t quite as...', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Microsoft Windows XP (SP2 or later) / Windows Vista / Windows 7<br></li><li><strong>Processor:</strong> Pentium D 3Ghz or AMD Athlon 64 X2 3600+ (Dual core) or higher<br></li><li><strong>RAM:</strong> 1.5 GB RAM<br></li><li><strong>Hard Disk Space:</strong> 8GB<br></li><li><strong>Video Card:</strong> nVidia GeForce 8600 / ATI HD2600 Pro or better<br></li><li><strong>Sound Card:</strong> 100% DirectX 9.0c compatible sound card<br></li><li><strong>Peripherals:</strong> Keyboard and mouse or Windows compatible gamepad<br></li><li><strong>Other Requirements:</strong> Initial installation requires one-time internet connection for Steam authentication; software installations required (included with the game)include nVidia PhysX_drivers 10.04.02_9.10.0522and nVidia GPU drivers 197.13 or latest, Steam Client and Microsoft DirectX.</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Microsoft Windows XP (SP2 or later) / Windows Vista / Windows 7<br></li><li><strong>Processor:</strong> 2.4 GHz Quad Core processor<br></li><li><strong>RAM:</strong> 2GB<br></li><li><strong>Hard Disk Space:</strong> 10GB<br></li><li><strong>Video Card:</strong> nVidia GeForce 9800 GTX / ATI Radeon HD 3870 or better<br></li><li><strong>Sound Card:</strong> 100% DirectX 9.0c compatible sound card<br></li><li><strong>Peripherals:</strong> Keyboard and mouse or Windows compatible gamepad</li></ul>\'}', '1,51', '1,45', '0,04', '0,47', '3,47'),
(119, 'star wars the force unleashed ii', '2010', 0, 0, 1880, 1348, 249, 15.49, 'The Star Wars® Saga continues with Star Wars®: The Force Unleashed™ II, the highly anticipated sequel to the fastest-selling Star Wars game ever created.', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP SP3, Windows Vista® SP2, or Windows 7<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Core 2 Duo 2.4 GHz or AMD Athlon X2 5200+<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2 GB RAM (XP, Vista, or 7)<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space:</strong> 10GB + 1GB Swapfile<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Video:</strong> 256 MB Video Memory with Shader 3.0 support; ATI Radeon HD 2600 / NVIDIA GeForce 8600 GT<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> 100% DirectX 9.0c compatible Audio Device<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Direct®:</strong> DirectX 9.0c (March 2009)<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>Processor:</strong> Intel Core 2 Duo 2.8 GHz or AMD Athlon X2 6000+<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Video:</strong> ATI Radeon HD 4800 / NVIDIA GeForce GTX 260<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '2,5', '1,16', '0', '0,42', '4,08'),
(120, 'dead space 2', '2011', 0, 0, 8943, 493, 292, 14.99, 'THE NIGHTMARE RETURNS.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>Processor:</strong> 2.8 GHz processor or equivalent<br>\\t</li><li><strong>Memory:</strong> 1 GB RAM (XP), 2 GB RAM (Vista or Windows 7)<br>\\t</li><li><strong>Hard Disk Space:</strong> At least 10GB of hard drive space for installation, plus additional space for saved games<br>\\t</li><li><strong>Video Card:</strong> NVIDIA GeForce 6800 or better (7300, 7600 GS, and 8500 are below minimum system requirements), ATI X1600 Pro or better (X1300, X1300 Pro and HD2400 are below minimum system requirements), 256MB Video Card and Shader Model 3.0 required<br>\\t</li><li><strong>DirectX®:</strong> DirectX 9.0c</li></ul>\'}', '1,8', '1,1', '0', '0,39', '3,29'),
(121, 'sonic & sega allstars racing', '2010', 0, 0, 614, 173, 759, 4.99, 'SONIC AND SEGA ALL-STARS RACE FOR VICTORY IN A HIGH SPEED HIGH SKILL RACETRACK SHOWDOWN! TAKE TO THE TRACK BY CAR, MONSTER TRUCK, BIKE AND EVEN AEROPLANE IN SONIC &amp; SEGA ALL-STARS RACING. Explore stunning new circuits including Sonic Seaside Hill, Curien Mansion and Blizzard Castle as you zip around medieval castle ramparts, hurtle...', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP/Vista. (if running Windows Vista SP1 is recommended)<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 3.2 GHz Intel Pentium 4/Athlon 64 3000+ or equivalent processor<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1GB RAM (2GB on Vista)<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> DirectX 9.0c compliant video card with 256 MB RAM (NVIDIA 7600 or better, ATI X1300 or better)<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX 9.0c<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 6 GB Hard Drive Space<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX Compatible Sound Card<br>\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br>\\t\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>Processor:</strong> Intel Core 2 Duo @ 2.4Ghz or Athlon 64 X2 4200+ or better<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1.5GB RAM<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> GeForce 8800 or ATI Radeon HD 3800 series with 512 MB of VRAM or better<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 7 GB Hard Drive Space<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> Creative Sound Blaster X-Fi Sound Card<br>\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '1,45', '1,71', '0', '0,43', '3,58'),
(122, 'red faction ii', '2009', 0, 0, 354, 313, 0, 4.99, 'Twenty-second century Earth. Five years after the rebellion on Mars. For the last 15 years, Sopot, the corrupt dictator, has oppressed the people of the Commonwealth. His relentless pursuit of unification with the neighboring United Republic has left the country soaked in unnecessary bloodshed and poverty.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>Operating System: </strong>Windows® 2000/XP <br> </li><li><strong>DirectX Version: </strong>DirectX 8.1<br> </li><li><strong>Processor: </strong>Pentium III 500 MHz or greater<br> </li><li><strong>Memory: </strong>128 MB RAM <br> </li><li><strong>Video Card: </strong>3D Graphics Accelerator Card (16 MB)<br> </li><li><strong>Sound: </strong>DirectX 8.1 Certified Sound Card <br> </li></ul>\'}', '0,61', '0,82', '0', '0,23', '1,65'),
(123, 'dead rising 2', '2010', 18, 50, 2713, 934, 1108, 14.99, 'The sequel to the million-plus selling Dead Rising, Dead Rising 2 takes the zombie survival horror to Fortune City, America’s latest and greatest entertainment playground.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista®/XP, Windows 7<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Core 2 Duo 2.4 Ghz or better, AMD Athlon X2 2.2 Ghz or better<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2 GB RAM<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> NVIDIA® GeForce® 8800GTS or better, ATI Radeon™ HD 3850 or better<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX® 9.0c or greater<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 8.5 GB free hard drive space<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> Standard audio device<br>\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '1,28', '1,12', '0,24', '0,35', '3,02'),
(124, 'metal gear rising revengeance', '2014', 18, 60, 13722, 1157, 863, 19.99, 'Developed by Kojima Productions and PlatinumGames, METAL GEAR RISING: REVENGEANCE takes the renowned METAL GEAR franchise into exciting new territory with an all-new action experience. The game seamlessly melds pure action and epic story-telling that surrounds Raiden – a child soldier transformed into a half-human, half-cyborg ninja who...', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> XP or Vista or 7 or 8<br></li><li><strong>Processor:</strong> Intel Core i5 2400<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> Nvidia Geforce GTS 450<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 25 GB available space<br></li><li><strong>Sound Card:</strong> DirectX compatible sound card</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> XP or Vista or 7 or 8<br></li><li><strong>Processor:</strong> Intel Core i7 3770<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> Nvidia Geforce GTX 650<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 25 GB available space<br></li><li><strong>Sound Card:</strong> DirectX compatible sound card</li></ul>\'}', '0,74', '0,56', '0,44', '0,22', '1,97'),
(125, 'tom clancys ghost recon future soldier', '2012', 0, 0, 2178, 1153, 229, 12.49, 'Join an elite team of special-ops soldiers in the globe’s most deadly warzones to hunt down the highest value targets.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista® (with Service Pack 2)/ Windows 7® (with Service pack 1), both 32 bit &amp; 64 bit versions.<br>\\t</li><li><strong>Processor:</strong> Intel Pentium D 3.0 Ghz or AMD Athlon64 X2 4400+ 2.2Ghz<br>\\t</li><li><strong>Memory:</strong> 2GB Windows Vista or Windows 7<br>\\t</li><li><strong>Graphics:</strong> 512 MB DirectX–compliant, Shader 4.0–enabled video card based on nVidia GeForce 8600 GTS/AMD Radeon HD 4650<br>\\t</li><li><strong>DirectX®:</strong> DirectX 11<br>\\t</li><li><strong>Hard Drive:</strong> 25 GB <br>\\t</li><li><strong>Sound:</strong> DirectX 11 – compliant sound card</li></ul>\', \'recommended\': \'<strong>Recommneded:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista® (with Service Pack 2)/ Windows 7® (with Service pack 1), both 32 bit &amp; 64 bit versions.<br>\\t</li><li><strong>Processor:</strong> Intel Core2 Quad Q9450/ AMD Phenom II X4 940 or higher<br>\\t</li><li><strong>Memory:</strong> 3 GB Windows Vista® &amp; 7®<br>\\t</li><li><strong>Graphics:</strong> 1024 MB DirectX–compliant, Shader 4.0–enabled video card based on nVidia GeForce GTX 460 or AMD/ATi HD 5850 or better. <br>\\t</li><li><strong>DirectX®:</strong> DirectX 11<br>\\t</li><li><strong>Hard Drive:</strong> 25 GB <br>\\t</li><li><strong>Sound:</strong> DirectX 11 – compliant sound card</li></ul>\'}', '1,39', '0,83', '0,11', '0,27', '2,6'),
(126, 'homefront', '2011', 0, 47, 5506, 3685, 1772, 14.99, 'The Rock Map Pack is Now Available! Join the Resistance, stand united and fight for freedom against an overwhelming military force.', '{\'minimum\': \'<strong>Minimum</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP, Windows Vista or Windows 7<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Pentium Core 2 Duo 2.4 GHz or AMD Athlon X2 2.8GHz<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2 GB RAM <br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> Shader Model 3.0 graphics card with 256MB of memory, NVIDIA GeForce 7900GS or ATI Radeon 1900XT<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> <br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 10GB of free hard drive space <br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> <br>\\t\\t\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<strong>Recommended</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista or Windows 7<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel or AMD Quad Core 2 GHz+ CPU<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2 GB RAM<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> NVIDIA GeForce 260 or ATI Radeon 4850 <br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> <br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 10GB of free hard drive space <br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong><br>\\t\\t\\t\\t\\t\\t\\t</li></ul><strong>NVIDIA 3D Vision Recommended </strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista or Windows 7<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Core i7 processor<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2 GB RAM<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 3D Compatible NVIDIA GeForce 480/570 Series GPU, NVIDIA 3D Vision Kit<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> <br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 10GB of free hard drive space <br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong><br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Other:</strong> 3D Vision-Ready Display<br>\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '1,26', '0,98', '0,06', '0,3', '2,61'),
(127, 'lego city undercover', '2017', 0, 48, 779, 327, 1868, 24.99, 'Join the Chase! In LEGO® CITY Undercover, play as Chase McCain, a police officer who\'s been tasked with going undercover to hunt down the notorious – and recently escaped – criminal Rex Fury and putting an end to his city-wide crime wave.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7/8/8.1/10 x64<br></li><li><strong>Processor:</strong> Intel Core i5-760 (4 * 2800) or equivalent, AMD Athlon X4 740 (2 * 3200) or equivalent<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> GeForce 560 Ti (1024 MB), Radeon HD 5850 (1024 MB)<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 18 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7/8/8.1/10 x64<br></li><li><strong>Processor:</strong> Intel Core i7-950 (4 * 3000) or equivalent, AMD FX-6100 (6 * 3300) or equivalent<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> GeForce GTX 660 (2048 MB), Radeon HD 7850 (2048 MB)<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 18 GB available space</li></ul>\'}', '0,98', '1,15', '0,2', '0,2', '2,54');
INSERT INTO `jeux` (`id_jeu`, `nom_jeu`, `annee`, `age_requis`, `nb_succes`, `nb_avis_pos`, `nb_avis_neg`, `temps_jeu_moyen`, `prix`, `description`, `configuration`, `ventes_AN`, `ventes_EU`, `ventes_JP`, `ventes_Autre`, `ventes_Global`) VALUES
(128, 'anno 2070', '2011', 0, 0, 5653, 3686, 879, 16.99, 'Build your society of the future, colonize islands, and create sprawling megacities with multitudes of buildings, vehicles, and resources to manage.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® XP / Windows Vista® / Windows® 7<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 2 GHz Intel® Core™2 Duo or AMD Athlon™ 64 X2 or better<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2 GB (4 GB recommended)<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 512 MB DirectX® 9.0c–compatible with Shader Model 3.0 or higher (see supported list)*<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 9.0c<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 5 GB<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX 9.0c–compliant<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Peripherals:</strong> Windows-compatible mouse and keyboard<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Internet Connection:</strong> Temporary broadband connection for product registration, permanent broadband connection for multiplayer.<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t<strong>*Supported Video Cards at Time of Release:</strong><br><br>\\t\\t\\t\\t\\t\\t\\t\\t\\tATI Radeon™ X1000/HD 2000/3000/4000/5000/6000 series<br><br>\\t\\t\\t\\t\\t\\t\\t\\t\\tNVIDIA® GeForce® 7/8/9/100/200/300/400/500 series<br><br><br>\\t\\t\\t\\t\\t\\t\\t\\t\\tLaptop versions of these cards may work, but are not supported. These chipsets are the only ones that will run this game. For the most up-to-date minimum requirement listings, please visit the FAQ on our support website at: <a href=\"https://steamcommunity.com/linkfilter/?url=http://support.ubi.com/\" target=\"_blank\" rel=\"noopener\" >http://support.ubi.com/</a>.<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t<br>Requires a UPlay account<br>\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0', '1,13', '0', '0,32', '1,45'),
(129, 'rayman raving rabbids', '2008', 0, 0, 239, 80, 29, 4.29, 'Hordes of crazed out-of control bunnies have invaded, enslaving Rayman and forcing him to participate in \'gladiator\' style trials. Help Rayman win his freedom back by entertaining and outwitting these fury foes. Use the most hilarious fighting moves imaginable.', '{\'minimum\': \'<p><strong>Minimum: </strong></p>\\n\\t\\t\\t\\t\\t<ul>\\n\\t\\t\\t\\t\\t<li><strong>Supported OS: </strong>Microsoft Windows&reg; XP (only)</li>\\n\\t\\t\\t\\t\\t<li><strong>Processor: </strong>Intel Pentium&reg; IV 1.0 GHz or AMD Athlon processors (2.5 GHz or better recommended)</li>\\n\\t\\t\\t\\t\\t<li><strong>System Memory: </strong>256 MB of RAM or above (512 MB recommended)</li>\\n\\t\\t\\t\\t\\t<li><strong>Video Card: </strong>64 MB DirectX 8.1-compliant video card (128 MB video card recommended)(*see supported list)</li>\\n\\t\\t\\t\\t\\t<li><strong>Sound Card: </strong>Direct X 8.1-compliant sound card</li>\\n\\t\\t\\t\\t\\t<li><strong>DirectX Version: </strong>DirectX&reg; version 9.0c or higher</li>\\n\\t\\t\\t\\t\\t<li><strong>Hard Disk: </strong>1.5 GB available hard disk space</li>\\n\\t\\t\\t\\t\\t<li><strong>Supported Peripherals: </strong>Keyboard and mouse, Windows-compatible gamepads</li>\\n\\t\\t\\t\\t\\t<li><strong>Supported video cards at time of retail release: </strong>NVIDIA GeForce FX/6/7/ series, ATI Radeon 9000/X series. Laptop versions of these cards may work but are not supported. These chipsets are the only ones that will run this game. For an up-to-date list of supported chipsets, video cards, and operating systems, please visit the FAQ for this game at http://support.ubi.com.</li></ul>\'}', '1,54', '0,1', '0,02', '0,14', '1,81'),
(130, 'lego indiana jones 2 the adventure continues', '2010', 0, 0, 163, 58, 0, 15.49, 'LEGO® Indy is back in his biggest adventure yet. Battle through all four movies, including all-new levels from the original adventures and your favorite new moments from The Kingdom of the Crystal Skull... or in true LEGO® fashion, get creative and build your own levels to play with friends!', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP or Vista<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel P4 1.8 Ghz or AMD Athlon XP 2200+<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 256MB of ram, 512MB for Vista<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> ATI X1300 with 256MB of ram, or Nvidia FX5800<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 5.0 GB<br>\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '2,89', '1,72', '0', '0,62', '5,23'),
(131, 'disney princess enchanted journey', '2014', 0, 0, 15, 3, 0, 15.49, 'In Disney Princess: Enchanted Journey, players are transported to environments based on classic films as they discover the courage, trust, and friendship needed to become a real princess, while attempting to save each kingdom from evil.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP<br></li><li><strong>Processor:</strong> Pentium 4 or AMD Athlon XP 1.4GHz Processor<br></li><li><strong>Memory:</strong> 256 MB RAM<br></li><li><strong>Graphics:</strong> 128MB DirectX 9 Compatible Video Card<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 1844 MB available space<br></li><li><strong>Sound Card:</strong> DirectX 9 Compatible Sound Card</li></ul>\'}', '1,35', '0,13', '0', '0,12', '1,61'),
(132, 'assassins creed rogue', '2015', 0, 0, 4303, 992, 1240, 16.99, 'Introducing Assassin’s Creed® Rogue, the darkest chapter in the Assassin’s Creed franchise yet. As Shay, you will experience the slow transformation from Assassin to Assassin Hunter. Follow your own creed and set off on an extraordinary journey through New York City, the wild river valley, and far away to the icy cold waters of the North...', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 SP1 or Windows 8/8.1 (64bit versions only)<br></li><li><strong>Processor:</strong> Intel Core2Quad Q6600 @ 2.4 GHz or AMD Athlon II X4 620 @ 2.6 GHzH<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> nVidia GeForce GTS450 or AMD Radeon HD5670 (1024MB VRAM) or Intel HD4600<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 12 GB available space<br></li><li><strong>Sound Card:</strong> DirectX Compatible Sound Card with latest driver<br></li><li><strong>Additional Notes:</strong> Supported Video Cards at time of release: NVIDIA GeForce GTS 450 or better, GeForce 500, 600, 700, 900 series / AMD Radeon HD 5670 or better, Radeon HD 6000, 7000, R7, R9 series / Intel HD4600, HD5200 / Note: Laptop versions of these cards may work but are NOT officially supported.</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 SP1 or Windows 8/8.1 (64bit versions only)<br></li><li><strong>Processor:</strong> Intel Core i5 2400s @ 2.5 GHz or better / AMD FX-6100 @ 3.3 GHz or better<br></li><li><strong>Graphics:</strong> nVidia GeForce GTX 560Ti (1024 VRAM) or better / AMD Radeon HD 6870 (1024 VRAM) or better<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 12 GB available space<br></li><li><strong>Sound Card:</strong> DirectX Compatible Sound Card with latest driver</li></ul>\'}', '1,08', '1,02', '0,06', '0,33', '2,49'),
(133, 'star wars knights of the old republic ii the sith lords', '2012', 0, 57, 8047, 978, 990, 7.19, '5 years after the events of the award winning original, the Sith are on the verge of crushing the Old Republic. As a lone Jedi, will you follow the light side or succumb to the dark?', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 or newer<br>\\t</li><li><strong>Processor:</strong> Intel Core i3 (2 Cores), AMD A10<br> </li><li><strong>CPU Speed:</strong> 2.2 GHz<br> </li><li><strong>Memory:</strong> 4GB RAM<br>\\t</li><li><strong>Hard Disk Space:</strong> 10 GB<br>\\t</li><li><strong>Video Card (ATI):</strong> Radeon HD 5450<br>\\t</li><li><strong>Video Card (NVidia):</strong> GeForce 260<br>\\t</li><li><strong>Video Card (Intel):</strong> HD 4400<br> </li><li><strong>Video Memory (VRam):</strong> 256MB<br> </li><li><strong>Controller Support:</strong> Microsoft® Xbox® 360 Controller for Windows® (Wired), Microsoft® Xbox® 360 Games for Windows® Wireless Controller with Adapter, Microsoft® Xbox® One Controller (Wired), Razor Sabertooth – Gaming Controller for Xbox 360, Thrustmaster GPX, Logitech Gamepad F310, Logitech Wireless Gamepad F710</li></ul><br>Important Note: For users that prefer the original version of the game or for users on old hardware that can no longer run KOTOR II in its updated form, we have created a &quot;legacy branch&quot; that will allow users to access the original released content. Click on the support link and our team will walk you through the process.\'}', '1', '0,37', '0', '0,06', '1,43'),
(134, 'ryse son of rome', '2014', 18, 73, 14966, 2939, 225, 11.99, '“Ryse: Son of Rome” tells the story of Marius Titus, a young Roman soldier who witnesses the murder of his family at the hands of barbarian bandits, then travels with the Roman army to Britannia to seek revenge.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® Vista 64-bit / Windows® 7 64-bit / Windows® 8 64-bit<br></li><li><strong>Processor:</strong> Dual core with HyperThreading technology or quad core CPU (4+ logical processors)<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> DirectX 11 graphics card with 1 GB video RAM<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 26 GB available space<br></li><li><strong>Sound Card:</strong> DirectX compatible Sound Card with latest drivers</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® Vista 64-bit / Windows® 7 64-bit / Windows® 8 64-bit<br></li><li><strong>Processor:</strong> Quad Core or Six Core CPU (6+ logical processors)<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> DirectX 11 graphics card with 2 GB video RAM<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 26 GB available space<br></li><li><strong>Sound Card:</strong> DirectX compatible Sound Card with latest drivers</li></ul>\'}', '0,82', '0,42', '0', '0,11', '1,36'),
(135, 'lego harry potter years 57', '2012', 0, 0, 628, 104, 1904, 14.99, 'LEGO Harry Potter: Years 5-7 takes players through Harry Potter\'s heroic adventures in the Muggle and wizarding worlds.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP SP3 Vista or Windows 7<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Dual Core CPU @ 2GHz (Pentium D or better)<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1GB RAM<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space:</strong> 8.5 GB free HDD space<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Video Card:</strong> Shader Model 3 graphics card (NVIDIA GeForce 6800, 7800, 8xxx or better; ATI X1950 or better)<br>\\t\\t\\t\\t\\t\\t</li></ul>\'}', '2,4', '2,15', '0', '0,63', '5,17'),
(136, 'alan wake', '2012', 0, 67, 22962, 2163, 239, 11.39, 'A Dark Presence stalks the small town of Bright Falls, pushing Alan Wake to the brink of sanity in his fight to unravel the mystery and save his love.', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP SP2<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Dual Core 2GHz Intel or 2.8GHz AMD<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2 GB RAM<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> DirectX 10 compatible with 512MB RAM<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 9.0c<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 8 GB HD space<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX 9.0c compatible<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Quad Core 2.66GHz Intel or 3.2GHz AMD<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 4 GB RAM<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> DirectX 10 compatible or later with 1GB RAM <br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 10<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 8 GB HD space<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX 9.0c compatible<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0,66', '0,57', '0,05', '0,14', '1,42'),
(137, 'lost planet extreme condition', '2007', 0, 0, 569, 178, 74, 9.99, 'Driven to the brink of extinction on ice-covered wastelands, humankind fights to survive. Battle to survive against gargantuan alien Akrid and treacherous Snow Pirates on the vast and frozen landscape of EDN III.', '{\'minimum\': \'<strong>Minimum: </strong>Windows® XP, Intel® Pentium® 4 supporting HT technology or AMD Athlon™ 64 3500+ or greater, 512 MB RAM (Windows XP) / 1 GB RAM (Windows Vista), 8.0 GB free disk space, 640x480 minimum resolution, 256 MB VRAM, DirectX®9.0c / Shader3.0*, NVIDIA® GeForce® 6600 or greater**, DirectSound compatible. DirectX®9.0c, Mouse, Keyboard, Broadband connection (Internet connection required to play.)<br>\\t\\t\\t\\t\\t<strong>Recommended: </strong>Windows Vista™, Intel® Core™2 Duo, 1 GB RAM (Windows XP) / 2 GB RAM (Windows Vista), 1280x720 or higher resolution, 256 MB VRAM, NVIDIA® GeForce® 8600 or greater, Gamepad, Xbox 360™ Controller for Windows®<br>\\t\\t\\t\\t\\t<strong>* </strong>Operation not assured if VRAM is shared with Main Memory.<br><strong>**</strong> NVIDIA® GeForce® 7300 is not supported.\'}', '1,4', '0,21', '0,17', '0,2', '1,98'),
(138, 'doom 3', '2007', 0, 0, 2633, 376, 362, 0.00, 'A massive demonic invasion has overwhelmed the Union Aerospace Corporation\'s (UAC) Mars Research Facility, leaving only chaos and horror in its wake. As one of only a few survivors, you must fight your way to hell and back against a horde of evil monsters.', '{\'minimum\': \'<ul>\\n\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>OS:</strong> Microsoft&reg; Windows&reg; 2000/XP (Does not support Windows Vista/7)</li>\\n\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>Processor:</strong> Pentium&reg;IV 1.5 GHz or Athlon&reg; XP 1500+ processor or higher</li>\\n\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>Memory:</strong> 384 MB RAM</li>\\n\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>Graphics:</strong> 100% DirectX&reg; 9.0b compatible 64MB Hardware Accelerated video card and the lateset drivers</li>\\n\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>DirectX&reg;:</strong> DirectX&reg; 9.0b (included)</li>\\n\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>Hard Drive:</strong> 2.2GB of uncompressed free hard disk space (plus 400MB for Windows&reg; swap file)</li>\\n\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>Sound:</strong> 100% DirectX&reg; 9.0b compatible 16-bit sound card and the latest drivers</li>\\n\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>Multiplayer Requirements:</strong> Internet (TCP/IP) and LAN (TCP/IP) play supported, Internet play requires broadband connection and latest drivers, LAN play requires network interface card and latest drivers</li>\\n\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>Supported Chipsets:</strong> ATI&reg; RadeonTM 8500, ATI&reg; RadeonTM 9000, ATI&reg; RadeonTM 9200, ATI&reg; RadeonTM 9500, ATI&reg; RadeonTM 9600, ATI&reg; RadeonTM 9700, ATI&reg; RadeonTM 9800, all nVidia&reg; GeForceTM 3/Ti series, all nVidia&reg; GeForceTM 4MX series, all nVidia&reg; GeForceTM 4/Ti series, all nVidia&reg; GeForceTM FX series, nVidia&reg; GeForceTM 6800*Important Note: Some 3D accelerator cards with the chipset listed here may not be compatible with the 3D accelerator features utilized by Doom 3. Please refer to your hardware manufacturer for 100% DirectX 9.0b compatibility. This product does not support Microsoft&reg; Windows&reg; 95/98/ME or NT.</li>\\n\\t\\t\\t\\t\\t\\t\\t</ul>\\n\\t\\t\\t\\t\\t\\t\\t\'}', '0,9', '0,47', '0', '0,07', '1,44'),
(139, 'max payne 2 the fall of max payne', '2008', 18, 0, 2506, 172, 175, 5.99, 'Max Payne 2: The Fall of Max Payne is a violent, film-noir love story. Dark, tragic and intense, the in-depth story is a thrill-ride of shocking twists and revelations. Love hurts.', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Microsoft® Windows® 2000/XP<br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 1Ghz PIII/Athlon or 1.2Ghz Celeron/Duron processor<br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 256MB RAM<br>\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 32MB AGP graphics card with hardware transform &amp; lighting support<br>\\t\\t\\t\\t\\t</li><li><strong>DirectX Version:</strong> DirectX 9.0<br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 1.5 GB hard drive space<br>\\t\\t\\t\\t\\t</li><li><strong>Sound Card:</strong> DirectSound compatible sound card<br>\\t\\t\\t\\t\\t</li><li><strong>Input:</strong> Keyboard and mouse</li></ul><strong>Recommended: </strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Microsoft® Windows® 2000/XP<br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 1Ghz PIII/Athlon or 1.2Ghz Celeron/Duron processor<br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 512MB RAM<br>\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 64MB DirectX 9 compatible AGP graphics card with hardware T&amp;L support<br>\\t\\t\\t\\t\\t</li><li><strong>DirectX Version:</strong> DirectX 9.0<br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 1.5 GB hard drive space<br>\\t\\t\\t\\t\\t</li><li><strong>Sound Card:</strong> DirectSound compatible sound card<br>\\t\\t\\t\\t\\t</li><li><strong>Input:</strong> Keyboard and mouse</li></ul>\'}', '1,12', '0,68', '0', '0,19', '2,01'),
(140, 'dark souls ii', '2014', 16, 38, 30008, 3799, 2377, 29.99, 'Developed by FROM SOFTWARE, DARK SOULS™ II is the highly anticipated sequel to the gruelling 2011 breakout hit Dark Souls. The unique old-school action RPG experience captivated imaginations of gamers worldwide with incredible challenge and intense emotional reward.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista SP2, Windows 7 SP1, Windows 8<br></li><li><strong>Processor:</strong> AMD® Phenom II™ X2 555 3.2Ghz or Intel® Pentium Core ™ 2 Duo E8500 3.17Ghz<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA® GeForce® 9600GT, ATI Radeon™ HD 5870<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 12 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9 sound device<br></li><li><strong>Additional Notes:</strong> Controller support: Microsoft Xbox 360® Controller for Windows® (or equivalent) recommended</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 SP1, Windows 8<br></li><li><strong>Processor:</strong> Intel® CoreTM i3 2100 3.10GHz or AMD® A8 3870K 3.0GHz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA® GeForce® GTX 750 or ATI Radeon™ HD 6870 or higher<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 15 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9 sound device<br></li><li><strong>Additional Notes:</strong> Controller support: Microsoft Xbox 360® Controller for Windows® (or equivalent) recommended</li></ul>\'}', '1,29', '0,93', '0,49', '0,35', '3,07'),
(141, 'the lego movie videogame', '2014', 0, 48, 1825, 374, 570, 14.99, 'Join Emmet and an unlikely group of resistance fighters in their heroic quest to thwart Lord Business’ evil plans—a mission that Emmet is hopelessly and hilariously unprepared for. It’s a wild ride with a surprising mix of over 90 playable characters including Batman, Superman, Wonder Woman, the Green Ninja, Gandalf, Shakespeare,...', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows®XP SP3, Windows Vista/7/8 with latest service packs and updates installed<br></li><li><strong>Processor:</strong> AMD Athlon 64 X2 EE 3800+ (2*2000 Mhz) or similar Intel CPU, such as Intel Pentium Dual Core E2180 (2*2000 Mhz)<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce 7600 GS or ATI Radeon X1950 Pro or better<br></li><li><strong>DirectX:</strong> Version 10<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 10 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP/Vista/7/8<br></li><li><strong>Processor:</strong> AMD or Intel Quad Core running at 4*2600 Mhz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 480 or ATI Radeon HD 5850 or better<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 10 GB available space</li></ul>\'}', '2,3', '2,28', '0,11', '0,65', '5,33'),
(142, '[prototype]', '', 0, 0, 0, 0, 0, 0.00, '0', '0', '1,49', '0,76', '0', '0,31', '2,55'),
(143, 'rise of the tomb raider', '2016', 18, 143, 49004, 3838, 817, 39.99, 'Rise of the Tomb Raider: 20 Year Celebration includes the base game and Season Pass featuring all-new content. Explore Croft Manor in the new “Blood Ties” story, then defend it against a zombie invasion in “Lara’s Nightmare”.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 64bit<br></li><li><strong>Processor:</strong> Intel Core i3-2100 or AMD equivalent<br></li><li><strong>Memory:</strong> 6 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GTX 650 2GB or AMD HD7770 2GB<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 25 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 10 64 bit<br></li><li><strong>Processor:</strong> Intel Core i7-3770K<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GTX 980Ti 2560x1440 or NVIDIA GTX 970 1920x1080<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 25 GB available space</li></ul>\'}', '0,7', '0,92', '0,02', '0,14', '1,8'),
(144, 'valkyria chronicles', '2014', 0, 20, 8862, 838, 892, 14.99, 'The critically acclaimed Valkyria Chronicles is now available on PC in 1080p True HD, including all previously released DLC!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista/Windows 7<br></li><li><strong>Processor:</strong> Intel Core2 Duo @ 2.0GHz (or equivalent)<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTS 240 (or equivalent)<br></li><li><strong>Storage:</strong> 25 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7<br></li><li><strong>Processor:</strong> Intel Core2 Duo @ 2.8GHz (or equivalent)<br></li><li><strong>Memory:</strong> 3 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 280 (or equivalent)<br></li><li><strong>Storage:</strong> 25 GB available space</li></ul>\'}', '0,77', '0,24', '0,29', '0,15', '1,46'),
(145, 'metal gear solid v ground zeroes', '2014', 18, 16, 7953, 1692, 320, 16.99, 'World-renowned Kojima Productions brings the Metal Gear Solid franchise to Steam with METAL GEAR SOLID V: GROUND ZEROES. Play as the legendary hero Snake and infiltrate a Cuban military base to rescue the hostages. Can you make it out alive?', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista SP2 x64, Windows 7 x64, Windows 8 x64 (64-bit OS Required)<br></li><li><strong>Processor:</strong> Core i5-4460 (3.20GHz) or better *Quad-Core or better<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 650 (2GB) or better (DirectX 11 graphics card required)<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 4 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c compatible sound card</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 x64, Windows 8 x64 (64-bit OS Required)<br></li><li><strong>Processor:</strong> Core i7-4790 (3.60GHz) or better *Quad-Core or better<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 760 (DirectX 11 graphics card required)<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 4 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c compatible sound card (Surround Sound 5.1)</li></ul>\'}', '0,81', '0,77', '0,45', '0,29', '2,33'),
(146, 'manhunt', '2008', 18, 0, 816, 433, 99, 5.99, 'You awake to the sound of your own panicked breath. In Manhunt, you must run, hide and fight to survive. If you can stay alive long enough, you may find out who did this to you. This is a brutal blood sport.', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Microsoft® Windows® 2000/XP Only<br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 1GHz Intel Pentium III or AMD Athlon processor or equivalent<br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 192 MB RAM <br>\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 32 MB 3D card <br>\\t\\t\\t\\t\\t</li><li><strong>DirectX Version:</strong> Microsoft DirectX® 8.1<br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 2.3 GB uncompressed free hard disk space</li></ul><strong>Recommended:</strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>Processor:</strong> 2GHz Intel Pentium 4 or AMD Athlon XP 2000+ processor (or better) or equivalent<br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 512MB RAM<br>\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 64MB 3D card <br>\\t\\t\\t\\t\\t</li><li><strong>Sound Card:</strong> DirectX 8.1 compatible sound card with hardware positional sound</li></ul>\'}', '0,77', '0,53', '0', '0,17', '1,47'),
(147, 'tomb raider underworld', '2008', 16, 0, 1779, 594, 313, 6.99, 'Tomb Raider: Underworld represents a new advancement in exploration-based gameplay. As fearless adventurer Lara Croft explore exotic locations around the world, each designed with an incredible attention to detail resulting in breathtaking high-definition visual fidelity that creates a truly believable world and delivers a new level of...', '{\'minimum\': \'Minimum<br> <ul class=\"bb_ul\"><li><strong>Supported OS: </strong>Microsoft Windows XP (admin rights required)/Microsoft Windows Vista (admin rights required)<br> </li><li><strong>Processor: </strong>Intel Pentium 4 3+GHz or AMD Athlon 2.5+GHz <br> </li><li><strong>Memory: </strong>1GB (Windows XP) / 2GB (Windows Vista) system memory <br> </li><li><strong>Graphics Card: </strong>NVIDIA GeForce 6 series 6800GT (or better) / ATI 1800XT (or better)<br> </li><li><strong>Sound Card: </strong>Direct X 9.0c compatible sound card and drivers<br> </li><li><strong>Hard Drive Space: </strong>8 GB Free Space<br> </li></ul>\', \'recommended\': \'Recommended<br> <ul class=\"bb_ul\"><li><strong>Supported OS: </strong>Microsoft Windows XP (admin rights required)/Microsoft Windows Vista (admin rights required)<br> </li><li><strong>Processor: </strong>Intel Core 2 Duo 2.2 GHz or Athlon 64 X2 4400+<br> </li><li><strong>Memory: </strong>2 GB system memory<br> </li><li><strong>Graphics Card: </strong>NVIDIA GeForce 9800 GTX or ATI HD4800<br> </li><li><strong>Sound Card: </strong>Direct X 9.0c compatible sound card and drivers<br> </li><li><strong>Hard Drive Space: </strong>8 GB Free Space<br> </li><li><strong>Controller: </strong>Microsoft Xbox360 Controller<br> </li></ul>\'}', '1,37', '1,4', '0,06', '0,48', '3,29'),
(148, 'final fantasy iv', '2014', 12, 58, 877, 183, 1818, 10.99, 'FINAL FANTASY IV makes its debut on PC! Lose yourself in this timeless tale of heroes, betrayal, love and redemption.', '{\'minimum\': \'<strong>Mínimo:</strong><br><ul class=\"bb_ul\"><li><strong>SO:</strong> Windows Vista, 7, 8<br></li><li><strong>Procesador:</strong> Pentium 4 2.4 GHz<br></li><li><strong>Memoria:</strong> 2 GB de RAM<br></li><li><strong>DirectX:</strong> Versión 10<br></li><li><strong>Almacenamiento:</strong> 750 MB de espacio disponible</li></ul>\'}', '0,54', '0,05', '0,91', '0,07', '1,57'),
(149, 'oddworld abes oddysee', '2008', 0, 0, 2739, 442, 387, 1.99, 'Selected by the fickle finger of fate, Abe™, floor-waxer first class for RuptureFarms, was catapulted into a life of adventure when he overheard plans by his boss, Molluck the Glukkon™, to turn Abe and his fellow Mudokons into Tasty Treats as part of a last-ditch effort to rescue Molluck\'s failing meat-packing empire.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>Supported OS: </strong>A 100% Windows 2000/XP-compatible computer system (only) <br>\\t\\t\\t\\t\\t</li><li><strong>Processor: </strong>166 MHz Pentium processor (200 MHz recommended) <br>\\t\\t\\t\\t\\t</li><li><strong>Memory: </strong>16 MB (32 MB or higher recommended) <br>\\t\\t\\t\\t\\t</li><li><strong>Direct X: </strong>6 <br>\\t\\t\\t\\t\\t</li><li><strong>Sound: </strong>100% Soundblaster compatible <br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive: </strong>700 MB Free </li></ul>\'}', '0,75', '0,44', '0', '0,06', '1,24'),
(150, 'medal of honor airborne', '2009', 0, 0, 1725, 461, 28, 9.99, 'Step into the boots of Boyd Travers, Private First Class of the “All-American” 82nd Airborne Division, and revolutionize the way the war is fought. From a rocky beginning in Sicily to war winning triumphs in the heart of Germany, fight the epic WWII battles that turned America’s first paratroopers into combat legends.', '{\'minimum\': \'\\n\\t\\t\\t\\t\\t<ul>\\n\\t\\t\\t\\t\\t\\t<li><strong>OS:</strong> Windows XP or Vista (32-bit) (64-Bit versions of Windows not supported)</li>\\n\\t\\t\\t\\t\\t\\t<li><strong>Processor:</strong> Intel 2.8 GHz or faster (3.0 Ghz or faster for Vista) or AMD Athlon 2800+ for Windows XP / AMD Athlon 3800+ for Windows Vista</li>\\n\\t\\t\\t\\t\\t\\t<li><strong>Memory:</strong> 1 GB or more</li>\\n\\t\\t\\t\\t\\t\\t<li><strong>Graphics:</strong> Video card with 128 MB or more memory, Pixel Shader 3.0 support, and one of these chipsets is required: ATI Radeon X1300 Pro or greater, NVIDIA GeForce 6600 GT or greater. NOTE: NVIDIA 6800XT/LE, 7100GS, 7200GS/LE, 7300 GS/GT are not supported. NVIDIA SLI and ATI Crossfire modes are not supported.</li>\\n\\t\\t\\t\\t\\t\\t<li><strong>DirectX&reg;:</strong> DirectX 9.0c compatible</li>\\n\\t\\t\\t\\t\\t\\t<li><strong>Hard Drive:</strong> 9.0 GB or more free space</li>\\n\\t\\t\\t\\t\\t\\t<li><strong>Sound:</strong> DirectX 9.0c compatible (For Creative Sound Blaster Audigy cards running under Windows Vista you should expect lower performance)</li>\\n\\t\\t\\t\\t\\t\\t\\t<li><strong>Special Requirements:</strong> 2-12 players and 24 with dedicated server; Cable, DSL, or faster connection</li><br>\\n\\t\\t\\t\\t\\t<li>INTERNET CONNECTION, ONLINE AUTHENTICATION AND ACCEPTANCE OF END USER LICENSE AGREEMENT REQUIRED TO PLAY. TO ACCESS ONLINE FEATURES, YOU MUST REGISTER ONLINE. ONLY ONE REGISTRATION IS AVAILABLE PER GAME. EA ONLINE TERMS & CONDITIONS AND FEATURE UPDATES CAN BE FOUND AT WWW.EA.COM. YOU MUST BE 13+ TO REGISTER WITH EA ONLINE. EA MAY RETIRE ONLINE FEATURES AFTER 30 DAYS NOTICE POSTED ON WWW.EA.COM.</li>\\n\\t\\t\\t\\t\\t</ul>\\n\\t\\t\\t\\t\\t\'}', '0,7', '1,27', '0,04', '0,38', '2,38'),
(151, 'bayonetta', '2017', 18, 50, 8866, 843, 232, 14.99, 'PlatinumGames’ universally acclaimed action masterpiece finally comes to PC. Experience the over-the-top stylish action in 60fps at unlocked HD resolutions. The definitive way to play: being bad never felt so good.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Microsoft Windows 7 / 8 (8.1)/ 10<br></li><li><strong>Processor:</strong> Core i3 3220<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> Radeon HD6950 / GeForce GTX 570 (VRAM 768MB)<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 20 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 / 8 (8.1)/ 10<br></li><li><strong>Processor:</strong> Core i5 4460<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> Radeon HD7870 / Geforce GTX 760 or more (VRAM 2GB or more)<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 20 GB available space</li></ul>\'}', '0,95', '0,67', '0,3', '0,25', '2,17'),
(152, 'naruto shippuden ultimate ninja storm 2', '2017', 0, 50, 323, 78, 3, 14.99, 'NARUTO SHIPPUDEN: Ultimate Ninja STORM 2 is a tour de force of Naruto thrills and spills. Impressively faithful to the universe of the anime, the game takes players through the Shippuden story arc. Ultimate Ninja STORM 2 has been remastered in HD.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li>Requires a 64-bit processor and operating system<br></li><li><strong>OS:</strong> Windows (64bit) 7 or higher up to date<br></li><li><strong>Processor:</strong> Intel Core2 Duo, 3.0GHz - AMD Athlon 64 X2 Dual Core 6400+ 3.2GHz<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> 1024 MB video card<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 8 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li>Requires a 64-bit processor and operating system</li></ul>\'}', '0,85', '0,74', '0,16', '0,25', '2,01'),
(153, 'f1 2011', '2011', 0, 0, 232, 108, 3, 9.99, 'The official FORMULA ONE™ game returns with new circuits, split-screen and co-op Championship modes plus all the cars and stars from the 2011 season. Debut ahead of the drivers at India’s Buddh International Circuit, race the iconic Nürburgring circuit for the first time in High Definition and take on Abu Dhabi with a spectacular new day...', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP/Vista/7<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Core 2 Duo @ 2.4Ghz or AMD Athlon X2 5400+<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2GB Ram<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> GeForce 7800/Radeon X1800 or higher<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX 9.0c<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong>12.5 GB HD space<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX Compatible Soundcard or onboard audio<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Other Requirements:</strong> Online play requires log-in to Games For Windows - Live. Click <a href=\"https://steamcommunity.com/linkfilter/?url=http://www.xbox.com/en-US/live/countries.htm\" target=\"_blank\" rel=\"noopener\" >here</a> for a list of countries/regions with service.<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li></ul><strong>Network Requirements:</strong><br>\\t\\t\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li>Broadband internet connection required (512kbps+ recommended)<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li>TCP/IP Network<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li></ul><strong>Supported Graphics Cards:</strong><br>\\t\\t\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li>ATI Radeon x1800, x1900, x1950, HD2400, HD2600, HD2900, HD3XXX Series, HD4XXX Series, HD5XXX Series, HD6XXX Series<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li>NVIDIA Geforce 7800, 7900, 7950, 7950Gx2, 8400, 8600, 8800, 9600, 9800, 9800Gx2, GeForce 210, GT220, GTS250, GTX2XX Series, GTX4XX Series, GTX5XX Series<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li>Not compatible with all integrated sound/graphics solutions (inc. laptops).<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<strong>Recommended for DX11:</strong><br>\\t\\t\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Core i5 or AMD Phenom II x4<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong>4GB Ram GB RAM<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> GeForce GTX460 or ATI Radeon HD 5850<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 11<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong>12.5 GB HD space<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong>DirectX Compatible Soundcard or onboard audio<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0,33', '1,57', '0,13', '0,43', '2,45'),
(154, 'wwe 2k16', '2016', 16, 55, 1725, 1026, 1024, 34.99, 'The newest addition to the flagship WWE video game franchise will deliver fun, authentic and hard-hitting action, including returning fan-favourite features and game modes, new innovations and more!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> 64-bit: Windows® Vista SP2<br></li><li><strong>Processor:</strong> Intel i3-2105 / Phenom II X2 550<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> GeForce GTX 460 / Radeon HD 5870<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 44 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0x compatible sound card</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> 64-bit: Windows® 7 / Windows® 8<br></li><li><strong>Processor:</strong> Intel Core i5-3550 / AMD FX 8150<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> GeForce GTX 660 / Radeon HD 7850<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 44 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0x compatible sound card<br></li><li><strong>Additional Notes:</strong> At least 2 GB DDR Video Memory</li></ul>\'}', '1,2', '1,28', '0', '0,37', '2,86'),
(155, 'nba 2k17', '2016', 0, 49, 4353, 3893, 4672, 39.99, 'Following the record-breaking launch of NBA 2K16, the NBA 2K franchise continues to stake its claim as the most authentic sports video game with NBA 2K17. As the franchise that “all sports video games should aspire to be” (GamesRadar), NBA 2K17 will take the game to new heights and continue to blur the lines between video game and...', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 64-bit, Windows 8.1 64-bit or Windows 10 64-bit<br></li><li><strong>Processor:</strong> Intel® Core™ i3-530 @ 2.93 GHz / AMD Phenom™ II X4 805 @ 2.50 GHz or better<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA® GeForce® GT 430 1GB / ATI® Radeon™ HD 6450 1GB or better<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 70 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0x compatible<br></li><li><strong>Additional Notes:</strong> Dual-analog gamepad; Additional Notes: Initial installation requires one-time internet connection for Steam authentication; software installations required (included with the game) include DirectX and Visual C++ Redistributable 2012</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 64-bit, Windows 8.1 64-bit or Windows 10 64-bit<br></li><li><strong>Processor:</strong> Intel® Core™ i5-4430 @ 3 GHz / AMD FX-8370 @ 3.4 GHz or better<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA® GeForce® GTX 770 2GB / ATI® Radeon™ R9 270 2GB or better<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 70 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c compatible sound card<br></li><li><strong>Additional Notes:</strong> Dual-analog gamepad</li></ul>\'}', '1,44', '0,19', '0', '0,31', '1,93'),
(156, 'resident evil operation raccoon city', '2012', 0, 0, 1171, 1079, 237, 22.99, 'Experience the Fear: Set in the terrifying world of Resident Evil.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista(R)/XP, Windows 7<br>\\t</li><li><strong>Processor:</strong> Intel(R) Core(TM)2 Duo 2.4 Ghz or better, AMD Athlon(TM) X2 2.8 Ghz or better<br>\\t</li><li><strong>Memory:</strong> 2 GB RAM<br>\\t</li><li><strong>Hard Disk Space:</strong> 8 GB free hard drive space\\t<br>\\t</li><li><strong>Video Card:</strong> NVIDIA(R) GeForce(R) 8800GTS or better, ATI Radeon(TM) HD 3850 or better <br>\\t</li><li><strong>DirectX®:</strong> 9.0c or greater<br>\\t</li><li><strong>Sound:</strong> Standard audio device<br>\\t </li><li><strong>Other Requirements:</strong> Online play requires software installation of and log-in to Games For Windows - LIVE</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista(R)/XP, Windows 7<br>\\t</li><li><strong>Processor:</strong> Intel(R) Core(TM)2 Quad 2.7 Ghz or better, AMD Phenom(TM)II X4 3 Ghz or better<br>\\t</li><li><strong>Memory:</strong> 4 GB RAM<br>\\t</li><li><strong>Hard Disk Space:</strong> 8 GB free hard drive space\\t<br>\\t</li><li><strong>Video Card:</strong> NVIDIA(R) GeForce(R) GTX 560 or better</li></ul>\'}', '1,03', '0,43', '0,39', '0,17', '2'),
(157, 'spore', '2008', 0, 0, 15101, 2014, 1142, 14.99, 'From Single Cell to Galactic God, evolve your creature in a universe of your own creations. Play through Spore\'s five evolutionary stages: Cell, Creature, Tribe, Civilization, and Space. Each stage has its own unique style, challenges, and goals.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>Supported OS:</strong> Microsoft Windows® XP with Service Pack 1 and Vista<br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 2.0 GHz Intel Pentium® 4 or equivalent<br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 512 MB RAM (768 MB RAM for Vista)<br>\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 128 MB Video Card, with support for Pixel Shader 2.0<br>\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> The latest version of DirectX 9.0c or higher<br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> At least 4 GB of hard drive space, with at least 1 GB additional space for creations </li></ul><strong>For computers using built-in graphics chipsets under Windows, the game requires at least:</strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li>Intel Integrated Chipset, 945GM or above<br>\\t\\t\\t\\t\\t</li><li>2.6 GHz Pentium D CPU, or 1.8 GHz Core 2 Duo, or equivalent<br>\\t\\t\\t\\t\\t</li><li>768 MB RAM</li></ul><ul class=\"bb_ul\"><li>INTERNET CONNECTION, ONLINE AUTHENTICATION, END USER LICENSE AGREEMENT REQUIRED TO PLAY. TO ACCESS ONLINE FEATURES, YOU MUST REGISTER ONLINE. ONLY ONE REGISTRATION AVAILABLE PER GAME. EA TERMS &amp; CONDITIONS AND FEATURE UPDATES CAN BE FOUND AT <a href=\"https://steamcommunity.com/linkfilter/?url=http://WWW.EA.COM\" target=\"_blank\" rel=\"noopener\" >WWW.EA.COM</a>. YOU MUST BE 13+ TO REGISTER ONLINE. EA MAY RETIRE ONLINE FEATURES AFTER 30 DAYS NOTICE POSTED ON <a href=\"https://steamcommunity.com/linkfilter/?url=http://www.ea.com\" target=\"_blank\" rel=\"noopener\" >www.ea.com</a>.</li></ul>\'}', '0,03', '1,06', '0', '0,09', '1,17'),
(158, 'gun', '2006', 0, 0, 740, 87, 462, 9.99, 'When life robs Colton White of all that matters, the only thing left he can trust is his GUN. From award-winning developer, Neversoft, and accomplished screenwriter, Randall Jahnson (The Mask of Zorro, The Doors), GUN follows Colton on his quest for discovery as he seeks to exact vengeful justice on those who have wronged him.', '{\'minimum\': \'<strong>Minimum</strong> 3D hardware accelerator card required - 100% DirectX(R) 9.0c-compliant 32 MB Hardware T&amp;L - capable video card and the latest drivers*, English version of Microsoft(R) Windows(R) 2000/XP, Pentium(R) III 1.8 GHz or Athlon(TM) XP 1800+ or higher processor, 256 MB of RAM, 2.8 GB of uncompressed hard disk space (plus 320 MB for the Windows swap file), A 100% Windows 2000/XP-compatible computer system including: <br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li>DirectX 9.0c (Included) <br>\\t\\t\\t\\t\\t</li><li>100% DirectX 9.0c-compliant true 16-bit sound card and drivers <br>\\t\\t\\t\\t\\t</li><li>100% Windows 2000/XP-compatible mouse, keyboard and drivers <br>\\t\\t\\t\\t\\t</li><li>100% Windows 2000/XP-compatible gamepad (optional) (Game controller with 10 or more buttons and dual analog thumb sticks required) </li></ul>*Supported Chipsets for Windows 2000/XP<br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li>NVIDIA® GeForce™ 3/Ti series<br>\\t\\t\\t\\t\\t</li><li>NVIDIA® GeForce™ 4/Ti series<br>\\t\\t\\t\\t\\t</li><li>NVIDIA® GeForce™ FX 5700 and later series<br>\\t\\t\\t\\t\\t</li><li>NVIDIA® GeForce™ 6800 and later<br>\\t\\t\\t\\t\\t</li><li>ATI® Radeon™ 8500<br>\\t\\t\\t\\t\\t</li><li>ATI® Radeon™ 9000<br>\\t\\t\\t\\t\\t</li><li>ATI® Radeon™ 9600<br>\\t\\t\\t\\t\\t</li><li>ATI® Radeon™ 9800 and later</li></ul>*Important Note: Some 3D accelerator cards with the chipsets listed here may not be compatible with the 3D acceleration features utilized by GUN. Please refer to your hardware manufacturer for 100% DirectX 9.0c compatibility.\'}', '1,74', '0,21', '0', '0,2', '2,14'),
(159, 'ty the tasmanian tiger', '2016', 0, 39, 1676, 26, 117, 10.99, 'G\'day Mate. Are you ready to explore the wilds of the Australian Outback in this remastered version of the classic game, TY the Tasmanian Tiger? Join TY on a RIPPER of an adventure to free his family from the Dreaming, through 17 levels of the Australian Outback, in their old-school 3D platforming glory!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® 7 SP1, Windows® 8/8.1 (32bit and 64bit), Windows® 10 (32bit and 64bit)<br></li><li><strong>Processor:</strong> Intel Core i3/i5/i7 1.8 GHz CPU dual-core. AMD 2.0 GHz dual-core.<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce 260 / Radeon HD 4000 Series / Intel HD Graphics 4000 with OpenGL 3.0 minimum.<br></li><li><strong>Storage:</strong> 3 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c-compliant<br></li><li><strong>Additional Notes:</strong> Xinput controller compliant</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® 7 SP1, Windows® 8/8.1 (32bit and 64bit), Windows® 10 (32bit and 64bit)<br></li><li><strong>Processor:</strong> Intel quad-core 3.0 GHz or dual-core 3.2 GHz. AMD quad-core 3.4 Ghz.<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 770 2GB / Radeon HD 7970 3GB with OpenGL 3.0 minimum.<br></li><li><strong>Storage:</strong> 3 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c-compliant<br></li><li><strong>Additional Notes:</strong> Xinput controller compliant</li></ul>\'}', '0,92', '0,54', '0', '0,17', '1,62'),
(160, 'romancing saga 2', '2017', 7, 42, 72, 50, 0, 19.99, 'Sit upon the throne of the Varennes Empire and control several generations of rulers in a valiant battle against the Seven Heroes.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li>Requires a 64-bit processor and operating system<br></li><li><strong>OS:</strong> Windows 7/8/8.1/10(64bit)<br></li><li><strong>Processor:</strong> Intel Core i3 1.6GHz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> Intel HD Graphics 3000 (onboard CPU)<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 2 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li>Requires a 64-bit processor and operating system</li></ul>\'}', '0', '0', '1,17', '0', '1,17');
INSERT INTO `jeux` (`id_jeu`, `nom_jeu`, `annee`, `age_requis`, `nb_succes`, `nb_avis_pos`, `nb_avis_neg`, `temps_jeu_moyen`, `prix`, `description`, `configuration`, `ventes_AN`, `ventes_EU`, `ventes_JP`, `ventes_Autre`, `ventes_Global`) VALUES
(161, 'mirrors edge', '2009', 0, 0, 17880, 2341, 260, 9.99, 'In a city where information is heavily monitored, agile couriers called Runners transport sensitive data away from prying eyes. In this seemingly utopian paradise, a crime has been committed, your sister has been framed and now you are being hunted.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>Supported OS:</strong> Microsoft Windows® XP SP2 or Vista <br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 3.0 GHz or faster <br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1 GB RAM or more <br>\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> DirectX® 9.0c compatible video card, Shader Model 3.0 required. Video card must have 256 MB, NVIDIA GeForce 6800 or better <br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 8 GB free space <br>\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX® 9.0c compatible sound card </li></ul><ul class=\"bb_ul\"><li>INTERNET CONNECTION, ONLINE AUTHENTICATION AND ACCEPTANCE OF END USER LICENSE AGREEMENT REQUIRED TO PLAY. TO ACCESS ONLINE FEATURES, YOU MUST REGISTER ONLINE. ONLY ONE REGISTRATION IS AVAILABLE PER GAME. EA ONLINE TERMS &amp; CONDITIONS AND FEATURE UPDATES CAN BE FOUND AT <a href=\"https://steamcommunity.com/linkfilter/?url=http://www.ea.com\" target=\"_blank\" rel=\"noopener\" >www.ea.com</a>. YOU MUST BE 13+ TO REGISTER WITH EA ONLINE.</li></ul>\'}', '0,82', '1,15', '0,03', '0,36', '2,37'),
(162, 'sniper ghost warrior', '2010', 0, 24, 2143, 1728, 113, 5.99, 'As a Ghost Warrior, an elite sniper in a highly trained special ops unit, your unique skills in the art of stalking, target detection, surveillance and shooting accuracy will determine mission success.', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® XP (SP3) / Vista™ (SP1) / 7<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Pentium 4 3,2 GHz, Intel Pentium D 2,66 GHz, AMD Athlon 64 3500+<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1GB for XP / 2GB for Vista and 7<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 256 MB RAM compatible with DX10.0 or DX9.0c, Shader Model 3.0<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Cards:</strong> GeForce ( 6800/7600-7950/8600-8800/9600-9800/GTX 260-280 ) or Radeon (X1650-1950/ HD2400-2900 / 3650 <br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX® 9.0c<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 6.5GB<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> Compatible with DirectX® 9.0c<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0,8', '1', '0,04', '0,29', '2,12'),
(163, 'rocksmith', '2012', 0, 60, 869, 80, 1371, 25.99, 'Rocksmith’s innovative game design makes playing music visually intuitive and will engage experienced musicians as well as those who have never picked up a guitar in their lives.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong>Windows Vista, Windows 7<br>\\t</li><li><strong>Processor:</strong>2.0 GHz Intel® Core™2 Duo E4400 or 2.0 GHz AMD Athlon™ 64 X2 3800+<br>\\t</li><li><strong>Memory:</strong>2 GB RAM<br>\\t</li><li><strong>Graphics:</strong>256 MB DirectX 9 / NVIDIA® GeForce® 8600 GT or ATI Radeon™ HD 2600 XT<br>\\t</li><li><strong>DirectX®:</strong>9.0<br>\\t</li><li><strong>Hard Drive:</strong>12 GB HD space<br>\\t</li><li><strong>Sound:</strong>DirectX 9.0c-compliant</li></ul>\'}', '1,42', '0,62', '0,1', '0,26', '2,4'),
(164, 'omerta city of gangsters', '2013', 0, 60, 1029, 632, 209, 10.99, 'Omerta - City of Gangsters is a simulation game with tactical turn-based combat. Taking the role of a fresh-from-the-boat immigrant, with dreams of the big life, the player will work his way up the criminal hierarchy of 1920’s Atlantic City.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP SP3 32-bit, Vista SP2, Windows 7<br>\\t</li><li><strong>Processor:</strong> 2 GHz Dual Core<br>\\t</li><li><strong>Memory:</strong> 2 GB RAM<br>\\t</li><li><strong>Graphics:</strong> Geforce 8800, Radeon HD 2000, Pixel Shader 3.0, 256 MB discrete RAM<br>\\t</li><li><strong>DirectX®:</strong> 9.0c<br>\\t</li><li><strong>Hard Drive:</strong> 5 GB HD space<br>\\t</li><li><strong>Sound:</strong> DirectX compatible</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 64-bit<br>\\t</li><li><strong>Processor:</strong> 2 GHz Quad Core<br>\\t</li><li><strong>Memory:</strong> 4 GB RAM<br>\\t</li><li><strong>Graphics:</strong> Geforce 400 series, Radeon HD 5000 series, 512 MB discrete RAM</li></ul>\'}', '0,94', '0,69', '0', '0,23', '1,86'),
(165, 'alien isolation', '2014', 18, 50, 24534, 1958, 563, 29.99, 'Discover the true meaning of fear in Alien: Isolation, a survival horror set in an atmosphere of constant dread and mortal danger.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 (32bit)<br></li><li><strong>Processor:</strong> 3.16Ghz Intel Core 2 Duo E8500<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> 1GB (AMD Radeon HD 5550 or Nvidia GeForce GT 430)<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 35 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 (64bit)<br></li><li><strong>Processor:</strong> AMD: Phenom II X4 955 - 4 Core, 3.2 GHz or Intel: Core 2 Quad Q9650 - 4 Core, 3.0 GHz<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> 2GB (AMD GPU: AMD Radeon R9 200 Series or Nvidia GPU: Nvidia GeForce GTX660)<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 35 GB available space</li></ul>\'}', '0,83', '1,25', '0,04', '0,34', '2,45'),
(166, 'counterstrike', '2000', 0, 0, 124534, 3339, 17612, 7.19, 'Play the world\'s number 1 online action game. Engage in an incredibly realistic brand of terrorist warfare in this wildly popular team-based game. Ally with teammates to complete strategic missions. Take out enemy sites. Rescue hostages. Your role affects your team\'s success. Your team\'s success affects your role.', '{\'minimum\': \'\\r\\n\\t\\t\\t<p><strong>Minimum:</strong> 500 mhz processor, 96mb ram, 16mb video card, Windows XP, Mouse, Keyboard, Internet Connection<br /></p>\\r\\n\\t\\t\\t<p><strong>Recommended:</strong> 800 mhz processor, 128mb ram, 32mb+ video card, Windows XP, Mouse, Keyboard, Internet Connection<br /></p>\\r\\n\\t\\t\\t\'}', '0,85', '0,23', '0', '0,04', '1,11'),
(167, 'sunset overdrive', '2018', 16, 80, 2421, 274, 300, 14.99, 'Sunset Overdrive transforms an open-world apocalypse into your tactical playground. Zip, grind and wall-run across Sunset City with an unconventional arsenal. Hyper-agility, unique weapons, and customizable abilities deliver an explosive and irreverent adventure in the end times.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li>Requires a 64-bit processor and operating system<br></li><li><strong>OS:</strong> Windows 8 or higher<br></li><li><strong>Processor:</strong> Intel Core i5 3470 @ 3.0hz || AMD-FX-6300<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> Geforce 750 Ti || AMD Radeon R7 260X<br></li><li><strong>Storage:</strong> 30 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li>Requires a 64-bit processor and operating system<br></li><li><strong>OS:</strong> Windows 10<br></li><li><strong>Processor:</strong> Intel Core i5 4690 @ 3.5hz || AMD-FX-8350<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> Geforce 970 or Geforce GTX 1060 || AMD Radeon R9 290x or Radeon RX 480<br></li><li><strong>Storage:</strong> 30 GB available space</li></ul>\'}', '0,62', '0,4', '0', '0,08', '1,11'),
(168, 'tom clancys splinter cell chaos theory', '2009', 0, 0, 1777, 140, 22, 8.59, 'The year is 2008. Citywide blackouts ... stock exchange sabotage ... electronic hijacking of national defense systems ... this is information warfare. To prevent these attacks, operatives must infiltrate deep into hostile territory and aggressively collect critical intelligence, closer than ever to enemy soldiers.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>Supported OS: </strong>Microsoft Windows® 2000/XP<br>\\t\\t\\t\\t\\t</li><li><strong>Processor: </strong>Intel Pentium III or AMD Athlon, 1.4 GHz (Pentium IV or Athlon 2.2 GHz recommended)<br>\\t\\t\\t\\t\\t</li><li><strong>System Memory: </strong>256 MB of RAM or above (512 MB recommended)<br>\\t\\t\\t\\t\\t</li><li><strong>Video Card: </strong>64 MB DirectX 9.0c compliant graphics card (128 MB recommended) <br>\\t\\t\\t\\t\\t</li><li><strong>Sound Card: </strong>DirectX 9.0c compliant sound card (EAX 2.0 or higher recommended)<br>\\t\\t\\t\\t\\t</li><li><strong>DirectX Version: </strong>DirectX® version 9.0c or higher<br>\\t\\t\\t\\t\\t</li><li><strong>Hard Disk: </strong>4 GB available hard disk space<br>\\t\\t\\t\\t\\t</li><li><strong>Supported Peripherals: </strong>Windows compatible mouse and keyboard, joystick for Solo and Co-op modes<br>\\t\\t\\t\\t\\t</li><li><strong>Multiplay: </strong>Broadband with 64 Kbps data transfer upload rate (128 kbps recommended)<br>\\t\\t\\t\\t\\t</li><li><strong>Note:</strong> For the most up-to-date minimum requirement listings, please visit the FAQ for this game on our support website at: <a href=\"https://steamcommunity.com/linkfilter/?url=http://support.ubi.com\" target=\"_blank\" rel=\"noopener\" >http://support.ubi.com</a>.</li></ul>\'}', '1,18', '0,85', '0', '0,2', '2,23'),
(169, 'tales of symphonia', '2016', 0, 39, 1911, 436, 223, 14.99, 'FIRST TIME ON STEAM – Based on the PlayStation®3 port of the original GameCube game, this RPG classic is finally available for PC.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista 32/64<br></li><li><strong>Processor:</strong> Intel Core 2 Duo 2.4Ghz / AMD Athlon 64 X2 5200+, 2.6GHz<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> Nvidia GeForce 8800GT / ATI Radeon HD 4830<br></li><li><strong>DirectX:</strong> Version 9.0<br></li><li><strong>Storage:</strong> 7 GB available space<br></li><li><strong>Additional Notes:</strong> Gamepad support</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 (x64) / Windows 8 (x64)<br></li><li><strong>Processor:</strong> Intel Core i3-530, 2.93 GHz / AMD Phenom II X4 940, 3.0GHz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> Nvidia GeForce GTX 560 Ti / AMD Radeon HD 7850<br></li><li><strong>Storage:</strong> 7 GB available space<br></li><li><strong>Additional Notes:</strong> Gamepad support</li></ul>\'}', '0,75', '0,34', '0,44', '0,1', '1,64'),
(170, 'lightning returns final fantasy xiii', '2015', 16, 42, 2135, 527, 2639, 12.99, 'Lightning Returns is the concluding chapter of the Final Fantasy XIII saga and series heroine Lightning\'s final battle. The grand finale of the trilogy brings a world reborn as well as free character customization and stunning action based battles.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® XP SP2 or later<br></li><li><strong>Processor:</strong> 2GHz Dual Core CPU<br></li><li><strong>Memory:</strong> 1500 MB RAM<br></li><li><strong>Graphics:</strong> NVIDIA® Geforce® 8800GT / ATI Radeon™ HD 4770 VRAM 512MB or later<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 22 GB available space<br></li><li><strong>Sound Card:</strong> Sound card compatible with DirectX® 9.0c<br></li><li><strong>Additional Notes:</strong> </li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® Vista/ 7/ 8<br></li><li><strong>Processor:</strong> Intel® Core™ 2 Quad (2.66 GHz)/ AMD Phenom™ II X4 (2.8 GHz) processor<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA® Geforce® GTX™ 460/ ATI Radeon™ HD 5770<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 22 GB available space<br></li><li><strong>Sound Card:</strong> Sound card compatible with DirectX® 9.0c<br></li><li><strong>Additional Notes:</strong> </li><li>*Maximum supported frame rate: 60fps</li><li>*Graphic Options</li><li>*A game controller using Xinput is recomended for this game. (If using a DirectInput based controller, please use the driver side key configuration to adjust settings as required )</li></ul>\'}', '0,46', '0,32', '0,46', '0,14', '1,39'),
(171, 'prince of persia', '2008', 0, 0, 948, 266, 305, 8.59, 'The critically acclaimed Prince of Persia® franchise returns for the first time on next-generation platforms with an all-new epic journey. Built by the same award-winning Ubisoft Montreal studio that created Assassin\'s Creed™, Prince of Persia has been in development for over three years to deliver a whole new action-adventure gaming...', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® XP/Windows Vista® (only) <br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Dual core processor 2.6 GHz Intel® Pentium® D or AMD Athlon™ 64 X2 3800+ (Intel Core® 2 Duo 2.2 GHz or AMD Athlon 64 X2 4400+ or better recommended) <br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1 GB Windows XP/2 GB Windows Vista <br>\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 256 MB DirectX® 10.0–compliant video card or DirectX 9.0–compliant card with Shader Model 3.0 or higher (see supported list)* <br>\\t\\t\\t\\t\\t</li><li><strong>DirectX Version:</strong> DirectX 9.0 or 10.0 libraries <br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 9 GB <br>\\t\\t\\t\\t\\t</li><li><strong>Sound Card:</strong> DirectX 9.0 or 10.0–compliant sound card (5.1 sound card recommended) <br>\\t\\t\\t\\t\\t</li><li><strong>Input:</strong> Windows-compliant keyboard, mouse, optional controller (Xbox 360® Controller for Windows recommended) </li></ul>*Supported Video Cards at Time of Release:<br> ATI® RADEON® X1600*/1650*-1950/HD 2000–4000 series<br> NVIDIA GeForce® 6800*/7/8/9/GTX 260–280 series<br> *PCI Express only supported <br>\\t\\t\\t\\t\\tLaptop versions of these cards may work but are NOT supported. These chipsets are the only ones that will run this game. For the most up-to-date minimum requirement listings, please visit the FAQ for this game on our support website at: <a href=\"https://steamcommunity.com/linkfilter/?url=http://support.ubi.com\" target=\"_blank\" rel=\"noopener\" >http://support.ubi.com</a>. <br>\\t\\t\\t\\t\\tNVIDIA® nForce™ or other motherboards/soundcards containing the Dolby® Digital Interactive Content Encoder required for Dolby Digital audio.\'}', '1,01', '0,76', '0,05', '0,28', '2,09'),
(172, 'joust', '2019', 0, 0, 5, 1, 0, 3.99, 'Joust - casual slasher of knightly tournaments. Competition among players for the maximum passage of levels. Playing on the side of the Vikings or knights, boss fights. Become the best player in the world!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7/Vista/8/10<br></li><li><strong>Processor:</strong> 2.2 GHz<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> Intel HD Graphics 4000 / AMD Radeon 46XX / NVIDIA GeForce GT 520 (DirectX 10.1 level video card and drivers, The minimum supported resolution for the game is 720p)<br></li><li><strong>DirectX:</strong> Version 10<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 2 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 64bit /Vista 64bit /8 64bit /10 64bit<br></li><li><strong>Processor:</strong> Intel Core i5<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 650 or higher, AMD Radeon series 77XX or higher (DirectX 11 level video card and drivers)<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 2 GB available space</li></ul>\'}', '1,01', '0,06', '0', '0,01', '1,08'),
(173, 'naruto ultimate ninja storm', '2017', 0, 50, 469, 314, 0, 14.99, 'NARUTO: Ultimate Ninja STORM allows players to battle in full 3D across massive environments. Players will unleash powerful jutsu attacks, perform acrobatic evasive maneuvers and even run up walls. NARUTO: Ultimate Ninja STORM has been remastered in HD.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li>Requires a 64-bit processor and operating system<br></li><li><strong>OS:</strong> Windows (64bit) 7 or higher up to date<br></li><li><strong>Processor:</strong> Intel Core2 Duo, 3.0GHz - AMD Athlon 64 X2 Dual Core 6400+ 3.2GHz<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> 1024 MB video card<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 8 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li>Requires a 64-bit processor and operating system</li></ul>\'}', '0,49', '0,35', '0,09', '0,16', '1,08'),
(174, 'bully scholarship edition', '2008', 0, 0, 8504, 1764, 319, 9.99, 'Bully tells the story of mischievous 15-year-old Jimmy Hopkins as he goes through the hilarity and awkwardness of adolescence. Beat the jocks at dodge ball, play pranks on the preppies, save the nerds, kiss the girl and navigate the social hierarchy in the worst school around.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP / Windows Vista <br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Pentium 4 (3+ GHZ) / AMD Athlon 3000+ <br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1 GB RAM <br>\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> DirectX 9.0c Shader 3.0 supported, Nvidia 6800 or 7300 or better, ATI Radeon X1300 or better <br>\\t\\t\\t\\t\\t</li><li><strong>DirectX Version:</strong> DirectX 9.0c <br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 4.7 GB free space <br>\\t\\t\\t\\t\\t</li><li><strong>Sound Card:</strong> DX9-compatible <br>\\t\\t\\t\\t\\t</li><li><strong>Input:</strong> Keyboard, Mouse, Xbox 360 Controller supported </li></ul>\'}', '0,7', '0,71', '0,03', '0,17', '1,62'),
(175, 'f1 2012', '2012', 0, 49, 1447, 176, 1623, 14.99, 'The next game in the BAFTA-winning series featuring all the official drivers, teams and circuits from the 2012 FIA FORMULA ONE WORLD CHAMPIONSHIP™.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong>Windows Vista or Windows 7<br>\\t</li><li><strong>Processor:</strong>Intel Core 2 Duo @ 2.4Ghz or AMD Athlon X2 5400+<br>\\t</li><li><strong>Memory:</strong>2 GB RAM<br>\\t</li><li><strong>Graphics:</strong>AMD HD2600 or NVIDIA Geforce 8600<br>\\t</li><li><strong>DirectX®:</strong>11<br>\\t</li><li><strong>Hard Drive:</strong>15 GB HD space<br>\\t</li><li><strong>Sound:</strong>Direct X compatible soundcard<br>\\t</li><li><strong>Other Requirements:</strong>Broadband Internet connection<br>\\t</li><li><strong>Additional:</strong>Supported Graphics Cards: AMD Radeon HD2600 or higher, HD3650 or higher, HD4550 or higher, HD5000 Series, HD6000 Series, HD7000 Series. nVidia GeForce 8600 or higher, 9500 or higher, GTX220 or higher, GTX400 Series, GTX500 Series, GTX600 Series. Intel HD Graphics 3000 or higher, AMD Fusion A8 or higher.</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong>Windows Vista or Windows 7 64 bit<br>\\t</li><li><strong>Processor:</strong>Intel Core i7/AMD Bulldozer<br>\\t</li><li><strong>Memory:</strong>4 GB RAM<br>\\t</li><li><strong>Graphics:</strong>AMD HD6000 Series/Nvidia GTX500 Series minimum 1GB RAM<br>\\t</li><li><strong>DirectX®:</strong>11<br>\\t</li><li><strong>Hard Drive:</strong>15 GB HD space<br>\\t</li><li><strong>Sound:</strong>Direct X compatible soundcard<br>\\t</li><li><strong>Other Requirements:</strong>Broadband Internet connection<br>\\t</li><li><strong>Additional:</strong>Supported Graphics Cards: AMD Radeon HD2600 or higher, HD3650 or higher, HD4550 or higher, HD5000 Series, HD6000 Series, HD7000 Series. nVidia GeForce 8600 or higher, 9500 or higher, GTX220 or higher, GTX400 Series, GTX500 Series, GTX600 Series. Intel HD Graphics 3000 or higher, AMD Fusion A8 or higher.</li></ul>\'}', '0,23', '1,1', '0,05', '0,34', '1,72'),
(176, 'disney universe', '2014', 0, 0, 72, 22, 0, 15.49, 'For the first time, suit up in an off-the-wall multiplayer adventure where iconic Disney characters and legendary Disney worlds collide. Discover the mixed-up humor of this ever-expanding universe as you team up with friends to overcome challenges and defeat enemies.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP/7<br></li><li><strong>Processor:</strong> 3.0GHz Intel Pentium 4 Class or AMD Athlon 64 3500+ Processor<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> 256MB 3D Video Card Supporting Shaders 4.0, NVIDIA Geforce 8400, ATI Radeon 2900<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 4 GB available space<br></li><li><strong>Sound Card:</strong> 16-bit DirectX 9.0c-Compatible Sound Card</li></ul>\'}', '1,34', '0,68', '0', '0,24', '2,27'),
(177, 'aliens vs predator', '2010', 0, 50, 9448, 1186, 170, 9.99, 'Survive, hunt and prey in the deadly jungles and swamps in distinctly new and thrilling first person gameplay.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP/Vista<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 3.4 GHz Intel Pentium 4 or equivalent processor<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1 GB System RAM (XP)/ 2 GB System RAM (Vista)<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> DirectX 9.0c compliant video card with 128 MB RAM (NVIDIA 7900 or better, ATI X1800 or better)<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 16 GB free hard drive space<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX 9.0c<br>\\t\\t\\t\\t\\t\\t\\t\\t</li></ul><img src=\"https://cdn.steampowered.com/v/gfx/apps/10680/extras/eyefinitylogo.jpg\" >\'}', '0,96', '1,04', '0', '0,31', '2,3'),
(178, 'worms armageddon', '2013', 0, 0, 3517, 231, 246, 10.99, 'Those intrepid invertebrates return with a vengeance in the much-loved Worms™ Armageddon. It’s a whole new can of worms! It’s hilarious fun that you can enjoy on your own or with all your friends.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP or above<br>\\t</li><li><strong>Processor:</strong> Intel Core 2 Duo, AMD 64x2 or above<br>\\t</li><li><strong>Memory:</strong> 2 GB RAM<br>\\t</li><li><strong>Graphics:</strong> Nvidia GeForce 8600GT (256MB), AMD/ATI Radeon HD3650 (256MB), Intel HD3000 or above<br>\\t</li><li><strong>DirectX®:</strong> 9.0<br>\\t</li><li><strong>Hard Drive:</strong> 2 GB HD space<br>\\t</li><li><strong>Sound:</strong> DirectX 9 compliant sound card or above<br>\\t</li><li><strong>Other Requirements:</strong> Broadband Internet connection</li></ul>\'}', '0,21', '0,82', '0', '0,08', '1,1'),
(179, 'naruto shippuden ultimate ninja storm 4', '2016', 0, 53, 17336, 3456, 767, 24.99, 'The latest opus in the acclaimed STORM series is taking you on a colourful and breathtaking ride. Take advantage of the totally revamped battle system and prepare to dive into the most epic fights you’ve ever seen !', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows (64bit) 7 or higher up to date<br></li><li><strong>Processor:</strong> Intel Core2 Duo, 3.0GHz - AMD Athlon 64 X2 Dual Core 6400+ 3.2GHz<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> 1024 MB video card<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 40 GB available space</li></ul>\'}', '0,58', '0,47', '0,1', '0,19', '1,34'),
(180, 'dragon ball xenoverse', '2015', 0, 50, 12601, 1680, 2575, 31.99, 'DRAGON BALL XENOVERSE revisits famous battles from the series through your custom Avatar and other classic characters. New features include the mysterious Toki Toki City, new gameplay mechanics, new animations and many other amazing features!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista (x64) / Windows 7 (x64)<br></li><li><strong>Processor:</strong> Intel Core 2 Duo 2.4Ghz / AMD Athlon 64 X2 5200+, 2.6GHz<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> 512 MB Nvidia GeForce 8800 / ATI Radeon HD 3870<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 10 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista (x64) / Windows 7 (x64) / Windows 8 (x64)<br></li><li><strong>Processor:</strong> Intel Core i3-530, 2.93 GHz / AMD Phenom II X4 940, 3.0GHz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> 1 GB Nvidia GeForce GTX 550Ti / AMD Radeon HD 6790<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 10 GB available space</li></ul>\'}', '0,79', '0,87', '0,26', '0,27', '2,18'),
(181, 'legacy of kain soul reaver', '2012', 16, 0, 798, 302, 77, 4.99, 'As Raziel, stalk the shadows of Nosgoth preying upon your former vampire brethren in your quest to destroy your creator- Kain. After being betrayed and executed by Kain, return to Nosgoth on an epic mission of revenge. A milestone in 3D adventure.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong>Windows XP / Windows Vista / Windows 7<br>\\t</li><li><strong>Processor:</strong>1.8 GHz Processor<br>\\t</li><li><strong>Memory:</strong>512 MB RAM<br>\\t</li><li><strong>Graphics:</strong>3D graphics card compatible with DirectX 7<br>\\t</li><li><strong>DirectX®:</strong>7.0<br>\\t</li><li><strong>Hard Drive:</strong>2 GB HD space</li></ul>\'}', '0,58', '0,4', '0', '0,07', '1,04'),
(182, 'disney tangled', '2014', 0, 0, 17, 13, 0, 15.49, 'Disney Tangled: The Video Game takes kids 6-11 on a film-inspired , hair-raising adventure. In this story-based journey kids will venture into a kingdom filled with colorful 3D environments , creative play, fun quests and competitive challenges.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP/Vista/7<br></li><li><strong>Processor:</strong> Intel Pentium 4 @ 2.4 GHz / AMD Athlon XP 3000+<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> nVidia GeForce FX 5600 / ATI Radeon 9600<br></li><li><strong>DirectX:</strong> Version 9.0<br></li><li><strong>Storage:</strong> 2 GB available space<br></li><li><strong>Sound Card:</strong> DirectX Compatible</li></ul>\'}', '1,05', '0,54', '0', '0,14', '1,73'),
(183, 'brink', '2011', 0, 43, 3493, 2331, 181, 0.00, 'You decide the combat role you want to assume in the world of Brink as you fight to save yourself and mankind’s last refuge!', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> XP(SP3)/Vista/Windows 7<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Core 2 Duo 2.4GHz or equivalent<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2GB RAM<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 8GB of free space<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> NVIDIA 8800GS / ATI Radeon HD 2900 Pro or equivalent<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> XP(SP3)/Vista/Windows 7<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Quad Core i5<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 3GB RAM<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 8GB of free space<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> Nvidia GeForce GTX 460 / ATI Radeon™ HD 5850<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0,94', '0,76', '0,02', '0,24', '1,96'),
(184, 'project cars', '2015', 0, 45, 8618, 2720, 232, 23.39, 'Project CARS is the ultimate driver journey!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista, Windows 7 with latest Service Packs<br></li><li><strong>Processor:</strong> 2.66 GHz Intel Core 2 Quad Q8400, 3.0 GHz AMD Phenom II X4 940<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> nVidia GTX 260, ATI Radeon HD 5770<br></li><li><strong>DirectX:</strong> Version 9.0<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 25 GB available space<br></li><li><strong>Sound Card:</strong> DirectX compatible sound card<br></li><li><strong>Additional Notes:</strong> For racing wheel support check: <a href=\"https://steamcommunity.com/linkfilter/?url=http://www.projectcarsgame.com/beyond-reality.html\" target=\"_blank\" rel=\"noopener\" >http://www.projectcarsgame.com/beyond-reality.html</a></li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 with latest Service Packs<br></li><li><strong>Processor:</strong> 3.5 GHz Intel Core i7 3700, 4.0 GHz AMD FX-8350<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> GT600 series, AMD Radeon HD7000 series<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 25 GB available space<br></li><li><strong>Sound Card:</strong> DirectX compatible sound card<br></li><li><strong>Additional Notes:</strong> For racing wheel support check: <a href=\"https://steamcommunity.com/linkfilter/?url=http://www.projectcarsgame.com/beyond-reality.html\" target=\"_blank\" rel=\"noopener\" >http://www.projectcarsgame.com/beyond-reality.html</a></li></ul>\'}', '0,25', '0,92', '0,02', '0,18', '1,38'),
(185, 'mx vs atv unleashed', '2015', 0, 0, 181, 88, 0, 8.99, 'Take on the racing world in an attempt to knock off motocross and ATV riders in over 50 technical supercross and rugged outdoor tracks.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 2000 / XP / Vista / 7 / 8 32 or 64 bit<br></li><li><strong>Processor:</strong> 1.2Ghz Pentium III or equivalent AMD Athlon XP processor<br></li><li><strong>Memory:</strong> 512 MB RAM<br></li><li><strong>Graphics:</strong> GeForce 2 – ATI 7500 or better with at least 64 MB of Video RAM<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 1500 MB available space<br></li><li><strong>Sound Card:</strong> DirectX compatible card<br></li><li><strong>Additional Notes:</strong> The game does not feature Internet Multiplayer any more!</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP / Vista / 7 / 8 32 or 64 bit<br></li><li><strong>Processor:</strong> 2.4 GHz Intel Pentium 4 or equivalent<br></li><li><strong>Memory:</strong> 512 MB RAM<br></li><li><strong>Graphics:</strong> nVidia GeForce 3 or ATI Radeon 8500 or equivalent with 64 MB of Video RAM<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 1500 MB available space<br></li><li><strong>Sound Card:</strong> DirectX compatible card<br></li><li><strong>Additional Notes:</strong> The game does not feature Internet Multiplayer any more!</li></ul>\'}', '1,18', '0,1', '0', '0,15', '1,43'),
(186, 'rayman origins', '2012', 0, 0, 1509, 114, 266, 8.59, 'Experience the magical universe of Rayman with legendary 2D gameplay that has captured the hearts of millions of fans!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® XP / Windows Vista® / Windows® 7 (only)<br>\\t</li><li><strong>Processor:</strong> 3.0 GHz Intel® Pentium® 4 or 1.8 GHz AMD Athlon™ 64 3000+<br>\\t</li><li><strong>Memory:</strong> 1 GB Windows XP / 1.5 GB Windows Vista, 7 \\t<br>\\t</li><li><strong>Video Card:</strong> 128 MB DirectX® 9.0c-compliant video card or higher* (see supported list)<br>\\t</li><li><strong>Sound:</strong> DirectX 9.0c-compliant\\t<br> </li><li><strong>Peripherals Supported:</strong> Windows-compatible keyboard, mouse, optional controller (Xbox 360® Controller for Windows recommended)</li></ul><strong>*Supported Video Cards at Time of Release:</strong><br><ul class=\"bb_ul\"><li>ATI Radeon™ X600 XT – HD 2600 XT series<br></li><li>NVIDIA® GeForce® 6800 GT – 8600 GT series</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® XP / Windows Vista® / Windows® 7 (only)<br>\\t</li><li><strong>Processor:</strong> 2.0 GHz Intel® Core™2 Duo E4400 or 2.0 GHz AMD Athlon™ X2 3800+ or better<br>\\t</li><li><strong>Memory:</strong> 2 GB recommended<br></li><li><strong>Video Card:</strong> 128 MB DirectX® 9.0c-compliant video card or higher* (see supported list)<br>\\t</li><li><strong>Sound:</strong> DirectX 9.0c-compliant\\t<br> </li><li><strong>Peripherals Supported:</strong> Windows-compatible keyboard, mouse, optional controller (Xbox 360® Controller for Windows recommended)</li></ul><strong>*Supported Video Cards at Time of Release:</strong><br><ul class=\"bb_ul\"><li>ATI Radeon™ X600 XT – HD 2600 XT series<br></li><li>NVIDIA® GeForce® 6800 GT – 8600 GT series</li></ul>\'}', '1,13', '1,63', '0,01', '0,46', '3,22'),
(187, 'tom clancys splinter cell blacklist', '2013', 0, 0, 10016, 1982, 669, 16.99, 'The United States has a military presence in two-thirds of countries around the world, and some of them have had enough. A group of terrorists calling themselves The Engineers initiate a terror ultimatum called the Blacklist - a deadly countdown of escalating attacks on U.S. interests.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong>Windows® XP (SP3) / Windows Vista® (SP2) / Windows® 7 (SP1) / Windows® 8<br>\\t</li><li><strong>Processor:</strong>2.53 GHz Intel® Core™2 Duo E6400 or 2.80 GHz AMD Athlon™ 64 X2 5600+ or better<br>\\t</li><li><strong>Memory:</strong>2 GB RAM<br>\\t</li><li><strong>Graphics:</strong>512 MB DirectX® 10–compliant with Shader Model 4.0 or higher<br>\\t</li><li><strong>DirectX®:</strong>9<br>\\t</li><li><strong>Hard Drive:</strong>25 GB HD space<br>\\t</li><li><strong>Sound:</strong>DirectX 10–compliant DirectX 9.0c–compliant<br>\\t</li><li><strong>Additional:</strong>Peripherals Supported: Windows-compatible keyboard, mouse, headset, optional controller (Xbox 360 Controller for Windows recommended). Requires UPLAY account.</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>Processor:</strong>2.66 GHz Intel® Core™2 Quad Q8400 or 3.00 GHz AMD Phenom™ II X4 940 or better<br>\\t</li><li><strong>Memory:</strong>4 GB RAM<br>\\t</li><li><strong>DirectX®:</strong>11<br>\\t</li><li><strong>Hard Drive:</strong>25 GB HD space<br>\\t</li><li><strong>Sound:</strong>(5.1 surround sound recommended)<br>\\t</li><li><strong>Other Requirements:</strong>Broadband Internet connection<br>\\t</li><li><strong>Additional:</strong>Peripherals Supported: Windows-compatible keyboard, mouse, headset, optional controller (Xbox 360 Controller for Windows recommended). Requires UPLAY account..</li></ul>\'}', '1', '0,95', '0,07', '0,3', '2,28'),
(188, 'oddworld abes exoddus', '2008', 0, 0, 806, 48, 67, 1.99, 'Abe\'s peaceful retirement was shattered when visited by a vision from the Mudokon Spirit Guides. Abe™ learned the Magog Cartel was mining Necrum, the sacred Mudokon city of the dead, to collect bones to make super-addictive SoulStorm Brew.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>Supported OS: </strong>A 100% Windows 2000/XP-compatible computer system (only) <br>\\t\\t\\t\\t\\t</li><li><strong>Processor: </strong>166 MHz Pentium processor (200 MHz recommended) <br>\\t\\t\\t\\t\\t</li><li><strong>Memory: </strong>16 MB (32 MB or higher recommended) <br>\\t\\t\\t\\t\\t</li><li><strong>Direct X: </strong>6 <br>\\t\\t\\t\\t\\t</li><li><strong>Sound: </strong>100% Soundblaster compatible <br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive: </strong>700 MB Free </li></ul>\'}', '0,55', '0,38', '0', '0,06', '0,99'),
(189, 'south park the stick of truth', '2014', 0, 50, 35896, 911, 1045, 25.99, 'From the perilous battlefields of the fourth-grade playground, a young hero will rise, destined to be South Park’s savior. From the creators of South Park, Trey Parker and Matt Stone, comes an epic quest to become… cool. Introducing South Park™: The Stick of Truth™.For a thousand years, the battle has been waged.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> WindowsXP SP3, Windows Vista SP2, Windows 7 SP1, Windows 8 (both 32/64bit versions)<br></li><li><strong>Processor:</strong> Intel Pentium Dual-Core E2180 @ 2.0 GHz or AMD Athlon64 X2 3800+ @ 2.0 GHz<br></li><li><strong>Memory:</strong> 2 GB GB RAM<br></li><li><strong>Graphics:</strong> nVidia GeForce 8800GT or AMD Radeon HD2600XT (512MB VRAM with Shader Model 4.0 or higher)<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 6 GB available space<br></li><li><strong>Sound Card:</strong> DirectX Compatible Sound Card with latest drivers</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> WindowsXP SP3, Windows Vista SP2, Windows 7 SP1, Windows 8 (both 32/64bit versions)<br></li><li><strong>Processor:</strong> Intel Core2Duo E4400 @ 2.0 GHz or AMD Athlon64 X2 4400+ @ 2.3 GHz or better<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> nVidia GeForce 9800GT or AMD Radeon HD4870 (512MB VRAM with Shader Model 4.0) or better<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 6 GB available space<br></li><li><strong>Sound Card:</strong> DirectX Compatible Sound Card with latest drivers</li></ul>\'}', '1,06', '0,78', '0', '0,27', '2,13'),
(190, 'brutal legend', '2013', 0, 59, 12816, 905, 461, 10.99, 'Brütal Legend is an action-adventure that marries visceral action combat with open-world freedom. Set in a universe somewhere between Lord of the Rings and Spinal Tap, it’s a fresh take on the action/driving genre, which in this case is full of imitation cover bands, demons intent on enslaving humanity and Heavy metal tunes.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong>Windows XP SP3<br>\\t</li><li><strong>Processor:</strong>Intel Core 2 Duo at 2.2 GHz, or AMD Athlon 64 at 2.2 GHz<br>\\t</li><li><strong>Memory:</strong>1 GB RAM<br>\\t</li><li><strong>Graphics:</strong>512 MB GeForce 220, Radeon 4550, Intel HD 3000 Graphics<br>\\t</li><li><strong>DirectX®:</strong>9.0c<br>\\t</li><li><strong>Hard Drive:</strong>8 GB HD space<br>\\t</li><li><strong>Sound:</strong>DirectX Compatible Sound Card<br>\\t</li><li><strong>Other Requirements:</strong>Broadband Internet connection</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong>Windows 7<br>\\t</li><li><strong>Processor:</strong>Intel i5 Duo at 2.5 GHz, or AMD FX 3.5 GHz<br>\\t</li><li><strong>Memory:</strong>2 GB RAM<br>\\t</li><li><strong>Graphics:</strong>512 MB GeForce 650, Radeon 7000<br>\\t</li><li><strong>DirectX®:</strong>9.0c<br>\\t</li><li><strong>Hard Drive:</strong>8 GB HD space<br>\\t</li><li><strong>Sound:</strong>DirectX Compatible Sound Card<br>\\t</li><li><strong>Other Requirements:</strong>Broadband Internet connection</li></ul>\'}', '1,16', '0,55', '0', '0,22', '1,93'),
(191, 'de blob', '2017', 0, 23, 86, 4, 0, 17.99, 'The evil I.N.K.T. Corporation has declared \'Color is a Crime!\' and leeched Chroma City of all its beauty and interest. The race to rescue Chroma City has just begun, and only de Blob can save the world from a black-and-white future with his unique abilities to color the world back to life.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 (32 or 64bit), Windows 8, Windows 10<br></li><li><strong>Processor:</strong> Dual Core CPU 2.50 GHz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> GeForce 310 with 1 GB VRAM<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 10 GB available space<br></li><li><strong>Sound Card:</strong> DirectX compatible</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 (32 or 64bit), Windows 8, Windows 10<br></li><li><strong>Processor:</strong> Dual Core CPU 3 GHz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> GeForce 650 with 2 GB VRAM<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 10 GB available space<br></li><li><strong>Sound Card:</strong> DirectX compatible card</li></ul>\'}', '0,5', '0,37', '0', '0,1', '0,97'),
(192, 'lost planet 2', '2010', 0, 0, 998, 504, 879, 12.99, 'Lost Planet 2, the sequel to Lost Planet™: Extreme Condition, the landmark third-person shooter that sold over 2.3 million units worldwide, is now available on Steam!', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP, Vista<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Core 2 Duo, AMD Athlon X2, or faster<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1GB+ (Windows XP); 2GB+ (Vista)<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> Shader Model 3.0 or higher; NVIDIA GeForce 7800 Series, ATI Radeon HD 2400 Pro, or higher<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>VRAM:</strong> 256MB or more (Not guaranteed to run when shared with main memory)<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX 9.0c or higher<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 13.0GB free space<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectSound Support (DirectX 9.0c or higher)<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Other Requirements:</strong> Internet connectivity<br>\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>Internet connection required for game activation.<br><br>\\t\\t\\t\\t\\t\\t\\t\\tTo play online, activate an online account using a product key. Limit one account per key. One product key included.<br>\\t\\t\\t\\t\\t\\t\\t\\t<br>Games for Windows–LIVE System Requirements: Multiplayer play and other LIVE features included at no charge; games may offer additional downloads that may require additional fees. LIVE is not available in all countries, visit <a href=\"https://steamcommunity.com/linkfilter/?url=http://www.gamesforwindows.com/live/countries\" target=\"_blank\" rel=\"noopener\" >http://www.gamesforwindows.com/live/countries</a> for more information.<br>\\t\\t\\t\\t\\t\\t\\t\\tFeatures and system requirements may change without notice. Subject to Terms of Use (at <a href=\"https://steamcommunity.com/linkfilter/?url=http://www.gamesforwindows.com/live/termsofuse\" target=\"_blank\" rel=\"noopener\" >http://www.gamesforwindows.com/live/termsofuse</a>). Broadband Internet service required (sold separately). Some broadband services may not work with LIVE and performance may vary. Under 13 requires parental consent. See <a href=\"https://steamcommunity.com/linkfilter/?url=http://www.gamesforwindows.com/live\" target=\"_blank\" rel=\"noopener\" >http://www.gamesforwindows.com/live</a> for full details.<br>\\t\\t\\t\\t\\t\\t\\t\\t<br>You must accept the enclosed License Agreement.\'}', '0,67', '0,6', '0,28', '0,2', '1,75'),
(193, 'lego jurassic world', '2015', 0, 49, 2558, 431, 502, 15.99, 'Following the epic storylines of Jurassic Park, The Lost World: Jurassic Park and Jurassic Park III, as well as the highly anticipated Jurassic World, LEGO Jurassic World™ is the first videogame where players will be able to relive and experience all four Jurassic films.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows®XP SP3, Windows Vista/7/8 with latest service packs and updates installed<br></li><li><strong>Processor:</strong> Intel Core 2 Duo or equivalent AMD dual core CPU<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce 7600GS or ATI Radeon 1950, 256 Mb RAM<br></li><li><strong>DirectX:</strong> Version 10<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 10 GB available space<br></li><li><strong>Additional Notes:</strong> Windows XP and DirectX® 9.0b and below not supported</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP/Vista/7/8<br></li><li><strong>Processor:</strong> Intel i5, 4 x 2.6 GHz or AMD equivalent<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 480 or ATI Radeon HD 5850 or better, 1Gb RAM<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 10 GB available space<br></li><li><strong>Additional Notes:</strong> Windows XP and DirectX® 9.0b and below not supported</li></ul>\'}', '2,16', '2,16', '0,06', '0,61', '4,98'),
(194, 'lego batman 3 beyond gotham', '2014', 0, 70, 2269, 375, 443, 19.99, 'The Caped Crusader joins forces with the super heroes of the DC Comics universe and blasts off to outer space to stop the evil Brainiac from destroying Earth.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows®XP SP3, Windows Vista/7/8 with latest service packs and updates installed<br></li><li><strong>Processor:</strong> Intel Core 2 Duo or equivalent AMD dual core CPU<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce 7600GS or ATI Radeon 1950, 256 Mb RAM<br></li><li><strong>DirectX:</strong> Version 10<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 10 GB available space<br></li><li><strong>Additional Notes:</strong> Windows XP and DirectX® 9.0b and below not supported</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP/Vista/7/8<br></li><li><strong>Processor:</strong> Intel i5, 4 x 2.6 GHz or AMD equivalent<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 480 or ATI Radeon HD 5850 or better, 1Gb RAM<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 10 GB available space<br></li><li><strong>Additional Notes:</strong> Windows XP and DirectX® 9.0b and below not supported</li></ul>\'}', '1,94', '2,06', '0', '0,6', '4,58'),
(195, 'operation flashpoint dragon rising', '2009', 0, 0, 1024, 580, 413, 6.99, 'Operation Flashpoint: Dragon Rising is a game about a fictitious conflict on one of the Sakhalin islands.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP (SP2 or later), Windows 10 not supported.<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 2.4GHz Dual Core Processor<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1 GB RAM<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> Nvidia 7600GT 256mb or ATI X1800XL 256mb<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX 9.0c<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 8 GB<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX compatible sound output<br>\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0,6', '0,94', '0,07', '0,28', '1,9');
INSERT INTO `jeux` (`id_jeu`, `nom_jeu`, `annee`, `age_requis`, `nb_succes`, `nb_avis_pos`, `nb_avis_neg`, `temps_jeu_moyen`, `prix`, `description`, `configuration`, `ventes_AN`, `ventes_EU`, `ventes_JP`, `ventes_Autre`, `ventes_Global`) VALUES
(196, 'brothers in arms hells highway', '2008', 0, 0, 823, 98, 346, 8.59, 'Brothers in Arms Hell\'s Highway brings the critically acclaimed squad-based WWII shooter into the next generation of gaming with amazing graphics and sound, new cutting-edge gameplay features and a totally redesigned online component.', '{\'minimum\': \'<strong>Recommended:</strong> <br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>Supported OS: </strong>Windows XP SP3/Windows Vista SP1 (only) <br>\\t\\t\\t\\t\\t</li><li><strong>Processor: </strong>2.6 GHz dual-core (3 GHz for Intel Pentium D 925) <br>\\t\\t\\t\\t\\t</li><li><strong>Memory: </strong>1 GB (2 GB Recommended) <br>\\t\\t\\t\\t\\t</li><li><strong>Graphics: </strong>128 MB DirectX 9.0c compliant, Shader 3.0–enabled (see supported list*) <br>\\t\\t\\t\\t\\t</li><li><strong>DirectX Version: </strong>DirectX 9.0 or 10.0 <br>\\t\\t\\t\\t\\t</li><li><strong>Sound: </strong>DirectX 9.0 or 10.0 compliant <br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive: </strong> 8 GB free hard disk space <br>\\t\\t\\t\\t\\t</li><li><strong>Multiplay: </strong>Broadband internet connection with 384 Kbps upstream <br>\\t\\t\\t\\t\\t</li><li><strong>*Supported Video Cards at Time of Release: </strong> ATI RADEON X1600/1650–1950/HD 2000/3000 series, NVIDIA GeForce 6800/7/8/9 series. <br>\\t\\t\\t\\t\\t</li><li>Laptop versions of these cards may work but are NOT supported. These chipsets are the only ones that will run this game. </li></ul>\'}', '0,91', '0,67', '0', '0,24', '1,82'),
(197, 'tom clancys endwar', '2009', 0, 0, 276, 108, 384, 8.59, 'Live the thrilling career of an army commander and lead your army to victory in a massive online World War III! Take control of the U.S.-led Joint Strike Force, the European Enforcers Corps, or the Russian Spetsnaz Guards Brigade in a persistent ongoing World War.', '{\'minimum\': \'<strong>Minimum:</strong> <br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® XP (with SP2) or Windows Vista® (with SP1) <br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel® Core® 2 Duo E4400 2.0 GHz or 3.0 GHz AMD Athlon™ 64 X2 Dual Core 6000+ or better <br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1 GB Windows XP / 2 GB Windows Vista <br>\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 256 MB DirectX® 9.0c–compliant video card with Shader Model 3.0 or higher (see supported list*) <br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 10 GB free hard disk space <br>\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX 9.0c–compatible sound card <br>\\t\\t\\t\\t\\t</li><li><strong>Network:</strong> Broadband connection with 256 kbps upstream or faster and service required for multiplayer mode <br>\\t\\t\\t\\t\\t</li><li><strong>Peripherals:</strong> Windows-compatible mouse required. </li></ul>*Supported Video Cards at Time of Release<br> ATI® RADEON® X1800XT / X1900XT / HD 2000 / 3000 / 4000 series<br> NVIDIA® GeForce® 7800 GT / 7950 GT / 8 / 9 / 200 series <br>\\t\\t\\t\\t\\tLaptop versions of these cards may work but are NOT supported. These chipsets are the only ones that will run this game. For the most up-to-date minimum requirement listings, please visit the FAQ for this game on our support website at: <a href=\"https://steamcommunity.com/linkfilter/?url=http://support.ubi.com\" target=\"_blank\" rel=\"noopener\" >http://support.ubi.com</a>. <br>\\t\\t\\t\\t\\tNVIDIA® nForce™ or other motherboards/soundcards containing the Dolby® Digital Interactive. Content Encoder required for Dolby Digital audio.\', \'recommended\': \'<strong>Recommended:</strong> <br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® XP (with SP2) or Windows Vista® (with SP1) <br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel® Core® 2 Duo E6600 2.4GHz, Intel® Core® 2 Quad Q6600 2.4GHz, or 2.5 GHz AMD Quad-Core Phenom™ X4 9850 or better <br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2 GB <br>\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 512 MB DirectX® 9.0c–compliant video card with Shader Model 3.0 or higher* <br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 10 GB free hard disk space <br>\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX 9.0c–compatible sound card with latest drivers <br>\\t\\t\\t\\t\\t</li><li><strong>Network:</strong> Broadband connection with 256 kbps upstream or faster and service required for multiplayer mode <br>\\t\\t\\t\\t\\t</li><li><strong>Peripherals:</strong> Windows-compatible mouse required. Windows-compatible headset required for voice command. </li></ul>\'}', '1,08', '0,5', '0,02', '0,21', '1,79'),
(198, 'mx vs atv reflex', '2010', 0, 48, 1599, 359, 1024, 14.99, 'Think fast and hang on to your ride as you take independent control of the rider and take the ultimate test of mettle. Dual controls let you tear it up with death-defying tricks and high-flying freestyle action. Fight for traction and dig up the track to leave your mark.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP, Vista, Windows 7<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Athlon 64 Processor 3800+ 2.4Ghz or better, Intel Pentium 4 530 3.0 Ghz Processor or better<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1GB XP, 2GB Vista/Windows 7<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> NVIDIA GeForce 8000 series 256MB graphics card or better, ATI Radeon HD 2000 series 256MB graphics card or better<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> Latest 9.0c or better<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 8GB<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> Windows compatible sound card<br>\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '1,35', '0,44', '0', '0,22', '2,02'),
(199, 'call of juarez bound in blood', '2009', 0, 0, 1121, 232, 13, 8.59, 'THE OLD WEST, 1864. In order to save their family, the McCall brothers will kill anyone who stands between them and the legendary Gold of Juarez. But when the allure of women and money tests their bond as brothers, will the blood they share prove to be thicker?', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® XP SP2 and SP3/Windows Vista® (only)<br>\\t </li><li><strong>Processor:</strong> 3.2 GHz Intel® Pentium® 4 or 2.66 GHz Pentium D/AMD® Athlon™64 3500+<br>\\t </li><li><strong>Memory:</strong> 1024 MB RAM (2 GB recommended)<br>\\t </li><li><strong>Graphics:</strong> 256 MB DirectX 10.0/9.0-compliant video card with Shader Model 3.0 or higher (see supported list*)<br>\\t </li><li><strong>DirectX®:</strong> 9.0c/10.0 (included)<br>\\t </li><li><strong>Hard Drive:</strong> 4 GB free<br>\\t </li><li><strong>Sound:</strong> DirectX 9-compatible sound card<br>\\t </li><li><strong>Peripherals Supported:</strong> Windows-compliant keyboard, mouse, gamepads<br>\\t </li><li><strong>Multiplayer:</strong> Broadband connection with 128 kbps upstream or faster<br> </li></ul>*Supported Video Cards at Time of Release<br> <ul class=\"bb_ul\"><li>ATI RADEON X1650-1950 / HD 2400-2900 / 3650-3870 / 4650-4870 series<br> </li><li>NVIDIA GeForce 6800 / 7600-7950 / 8600-8800 / GTX 260-280 series<br> </li></ul>Laptop versions of these cards may work but are NOT supported. These chipsets are the only ones that will run this game. For the most up-to-date minimum requirement listings, please visit the FAQ for this game on our support website at: <a href=\"https://steamcommunity.com/linkfilter/?url=http://support.ubi.com\" target=\"_blank\" rel=\"noopener\" >http://support.ubi.com</a>.\'}', '0,65', '0,65', '0,01', '0,23', '1,53'),
(200, 'kingdoms of amalur reckoning', '2012', 16, 61, 8523, 1201, 252, 19.99, 'The Legend of Dead Kel DLC is now available! The legendary pirate Dead Kel and his Hanged Men have returned to haunt the seas of northern Amalur.', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP SP3 / Windows Vista SP2 / Windows 7 SP1\\t \\t<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 2.2GHz Intel Core 2 Duo or 2.6GHz AMD Athlon 64 X2 5000+\\t \\t<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1 GB RAM for Windows XP / 2 GB Windows Vista and Windows 7\\t \\t<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space:</strong> 10.5 GB\\t \\t<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Video:</strong> NVIDIA GeForce 8800 / 512MB RAM or better, ATI Radeon HD3850 / 512MB RAM (with Pixel Shader 3.0 support), 1280x720 minimum supported resolution\\t \\t<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX 9.0c compatible\\t \\t<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX 9.0c\\t \\t<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<strong>Recommended:</strong>\\t \\t<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP SP3 / Windows Vista SP2 / Windows 7 SP1\\t \\t<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 2.4GHz Intel Core 2 Quad or 2.6GHz AMD Phenom X4\\t \\t<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 3 GB RAM for Windows XP / 4 GB Windows Vista and Windows 7\\t \\t<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space:</strong> 10.5 GB\\t \\t<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Video:</strong> NVIDIA GeForce GTX260 / 1GB RAM or better, ATI Radeon HD4850 / 1GB RAM (with Pixel Shader 3.0 support), 1280x720 minimum supported resolution\\t \\t<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX 9.0c compatible\\t \\t<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX 9.0c\\t \\t<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '1,06', '0,68', '0,1', '0,22', '2,07'),
(201, 'tomb raider anniversary', '2007', 16, 0, 1964, 389, 239, 6.99, 'Tomb Raider: Anniversary retraces Lara Croft\'s original genre-defining adventure  globe-trotting 3rd person action-adventure in pursuit of the legendary Scion artifact. Using an enhanced \'Tomb Raider: Legend\' game engine, the graphics, technology and physics bring Lara\'s adventure and pursuit of a mystical artifact known only as the...', '{\'minimum\': \'<strong>Minimum: </strong>Microsoft Windows Vista, 2000, or XP, Pentium 3 1.4Ghz or Athlon XP 1500+, 4GB free space, 100% DirectX 9.0c compatible 64 MB 3D Accelerated Card with TnL (GeForce 3TI / Radeon 9 series), 512MB RAM (Windows Vista) or 256MB RAM (Windows 2000/XP), Microsoft Windows 2000/XP/Vista compatible sound card (100% DirectX 9.0c -compatible), 100% Windows 2000/XP/Vista compatible mouse and keyboard<br>\\t\\t\\t\\t\\t<strong>Recommended: </strong>Microsoft Windows XP, Vista, Pentium 4 3.0Ghz or Athlon 64 3000+, Microsoft Windows XP/Vista compatible sound card (100% DirectX 9.0c -compatible), 1GB RAM, 100% DirectX 9.0c compatible 64MB 3D Accelerated Card with Pixel Shader 2.0 (GeForce 6000 series / Radeon X series)\'}', '0,86', '1,14', '0', '0,37', '2,37'),
(202, 'devil may cry hd collection', '2018', 16, 99, 1217, 211, 125, 24.99, 'The popular stylish action games Devil May Cry, Devil May Cry 2, and Devil May Cry 3 Special Edition return in one collection!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> WINDOWS® 7 (64bit)<br></li><li><strong>Processor:</strong> Intel® Core™ i3 series (dual-core) or AMD equivalent or better<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA® GeForce® GTX 760 or AMD Radeon™ R7 260x<br></li><li><strong>DirectX:</strong> Version 9.0<br></li><li><strong>Storage:</strong> 12 GB available space<br></li><li><strong>Sound Card:</strong> DirectSound (DirectX® 9.0c or better)<br></li><li><strong>Additional Notes:</strong> *Recommended Controller Xbox 360 Controller (Windows®7/8/8.1) Xbox One Wireless Controller (Windows®10) <br><br>*Internet connection required for game activation. <br><br>*Non-multi-thread supported CPUs are not guaranteed to operate correctly.</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> WINDOWS®10 (64bit)<br></li><li><strong>Processor:</strong> Intel® Core™ i7 3770 3.4GHz or AMD equivalent or better<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA® GeForce® GTX 960<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 12 GB available space<br></li><li><strong>Sound Card:</strong> DirectSound (DirectX® 9.0c or better)<br></li><li><strong>Additional Notes:</strong> *Recommended Controller<br> Xbox 360 Controller (Windows®7/8/8.1)<br> Xbox One Wireless Controller (Windows®10)<br><br> *Internet connection required for game activation.</li></ul>\'}', '0,7', '0,32', '0,12', '0,13', '1,28'),
(203, 'street fighter x tekken', '2012', 0, 0, 858, 697, 136, 22.99, 'The long awaited dream match-up between the two titans of fighting is here!', '{\'minimum\': \'<strong>Minimum Requirements at 800x600 resolution @ 30FPS):</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP<br>\\t</li><li><strong>Processor:</strong> Intel Dual Core 1.8GHz (or higher) or AMD Athlon II X2 (or higher) <br>\\t</li><li><strong>Memory:</strong> 1GB (or higher)<br>\\t</li><li><strong>Hard Disk Space:</strong> 10GB of free space \\t<br>\\t</li><li><strong>Video Card:</strong> nVidia GF6600 (or higher) or ATi X1600 (or higher) with 256MB of RAM<br>\\t</li><li><strong>DirectX®:</strong> 9.0c<br>\\t</li><li><strong>Sound:</strong> DirectSound compatible, DirectX 9.0c (or higher) compatible\\t<br> </li><li><strong>Other Requirements:</strong> Online play requires software installation of and log-in to Games For Windows - LIVE</li></ul>\', \'recommended\': \'<strong>Recommended Requirements at 1280x720 resolution @ 60FPS):</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista, 7<br>\\t</li><li><strong>Processor:</strong> Intel Core2 Duo 2.60GHz (or higher) or AMD Phenom II X2 (or higher)<br>\\t</li><li><strong>Memory:</strong> 2GB<br>\\t</li><li><strong>Hard Disk Space:</strong> 10GB of free space\\t<br>\\t</li><li><strong>Video Card:</strong> nVidia GF8800 (or higher) or ATi X1950 (or higher) with 512MB of RAM <br>\\t</li><li><strong>DirectX®:</strong> 9.0c<br>\\t</li><li><strong>Sound:</strong> DirectSound compatible, DirectX 9.0c (or higher) compatible</li></ul>\'}', '0,87', '0,39', '0,14', '0,17', '1,57'),
(204, 'duke nukem forever', '2011', 18, 62, 4433, 2243, 434, 14.99, 'The King arrives with an arsenal of over-the-top weapons, giant explosions and pure unadulterated fun!', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP/Vista/7<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Core 2 Duo @ 2.0 Ghz / AMD Athlon 64 X2 @ 2.0 Ghz<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1 Gb<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space:</strong> 10 Gb free<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Video Memory:</strong> 256 MB<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Video Card:</strong> nVidia GeForce 7600 / ATI Radeon HD 2600<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound Card:</strong> DirectX Compatible<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>OTHER REQUIREMENTS &amp; SUPPORTS:</strong> Initial installations required (included with the game) are Microsoft DirectX, Visual C++ 2005 Redistributable (ATL), Visual C++ 2008 Redistributable, and AMD Dual Core Optimizer. (AMD optimizer required only for specific AMD processors to run the game correctly, but installs for all of them.)<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>OTHER REQUIREMENTS &amp; SUPPORTS:</strong> Does not support Windows XP 64<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP/Vista/7\\t<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Core 2 Duo @ 2.4 Ghz / AMD Athlon 64 X2 @ 2.6 Ghz<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2GB<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space:</strong> 10 Gb free<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Video Memory:</strong> 512 MB<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Video Card:</strong> nVidia GeForce 8800 GTS / ATI Radeon HD 3850<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound Card:</strong> DirectX Compatible<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>OTHER REQUIREMENTS &amp; SUPPORTS:</strong> Initial installations required (included with the game) are Microsoft DirectX, Visual C++ 2005 Redistributable (ATL), Visual C++ 2008 Redistributable, and AMD Dual Core Optimizer. (AMD optimizer required only for specific AMD processors to run the game correctly, but installs for all of them.)<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '1,03', '0,73', '0', '0,25', '2,02'),
(205, 'the game of life', '2013', 0, 0, 23, 47, 0, 6.99, 'It’s Your Life – Where Do You Want to Go? Spin the wheel and choose your path – the possibilities are endless! Stay single or say “I do”. Retire rich or lose it all. Anything can happen in THE GAME OF LIFE! Choose your car and take a spin on the winding road of life. Play it safe with sensible choices like college, marriage and kids.', '{\'minimum\': \'<p><strong>Minimum:</strong></p>\\n<ul>\\n\\t<li><strong>OS:</strong>Windows XP SP3/Vista/7</li>\\n\\t<li><strong>Processor:</strong>1.4+GHz</li>\\n\\t<li><strong>Memory:</strong>2+ GB RAM</li>\\n\\t<li><strong>Graphics:</strong>256+MB</li>\\n\\t<li><strong>DirectX&reg;:</strong>9.0c</li>\\n\\t<li><strong>Hard Drive:</strong>1+ GB HD space</li>\\n</ul>\', \'recommended\': \'<p><strong>Recommended:</strong></p>\\n<ul>\\n\\t<li><strong>Graphics:</strong>512+MB</li>\\n</ul>\'}', '0,46', '0,31', '0', '0,05', '0,83'),
(206, 'the game of life', '2013', 0, 0, 23, 47, 0, 6.99, 'It’s Your Life – Where Do You Want to Go? Spin the wheel and choose your path – the possibilities are endless! Stay single or say “I do”. Retire rich or lose it all. Anything can happen in THE GAME OF LIFE! Choose your car and take a spin on the winding road of life. Play it safe with sensible choices like college, marriage and kids.', '{\'minimum\': \'<p><strong>Minimum:</strong></p>\\n<ul>\\n\\t<li><strong>OS:</strong>Windows XP SP3/Vista/7</li>\\n\\t<li><strong>Processor:</strong>1.4+GHz</li>\\n\\t<li><strong>Memory:</strong>2+ GB RAM</li>\\n\\t<li><strong>Graphics:</strong>256+MB</li>\\n\\t<li><strong>DirectX&reg;:</strong>9.0c</li>\\n\\t<li><strong>Hard Drive:</strong>1+ GB HD space</li>\\n</ul>\', \'recommended\': \'<p><strong>Recommended:</strong></p>\\n<ul>\\n\\t<li><strong>Graphics:</strong>512+MB</li>\\n</ul>\'}', '0,46', '0,31', '0', '0,05', '0,83'),
(207, 'star wars the clone wars republic heroes', '2009', 0, 0, 166, 279, 2, 15.49, 'Star Wars The Clone Wars: Republic Heroes lets Star Wars fans young and old live out the sweeping galactic adventures of the Clone Wars. For the first time ever, players can fight as their favorite Jedi and Clone Troopers from the preeminent animated television...', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP or Windows Vista<br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel P4 3.0GHz AMD XP 3000+ or higher<br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1GB Ram, 2GB for Windows Vista<br>\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> Nvidia 7300 GS or better, ATI X1600 or better*<br>\\t\\t\\t\\t\\t*Requirement of 256MB or more video memory<br>\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX 9.0c<br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 8GB<br>\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> 100% DirectX 9.0c compatible audio Device<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Controller Support:</strong> Yes<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Other Requirements:</strong> Requires login to Games for Windows - LIVE<br>\\t\\t\\t\\t</li></ul>\'}', '1,42', '0,96', '0', '0,39', '2,79'),
(208, 'street fighter v', '2016', 0, 45, 8300, 8498, 793, 15.99, 'Experience the intensity of head-to-head battles with Street Fighter® V! Choose from 16 iconic characters, then battle against friends online or offline with a robust variety of match options.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 64-bit<br></li><li><strong>Processor:</strong> Intel Core i3-4160 @ 3.60GHz<br></li><li><strong>Memory:</strong> 6 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA® GeForce® GTX 480, GTX 570, GTX 670, or better<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Sound Card:</strong> DirectX compatible soundcard or onboard chipset<br></li><li><strong>Additional Notes:</strong> Compatible with XInput and DirectInput USB devices including gamepads and arcade sticks based on Xbox 360, Xbox One, and DualShock controllers. Steam Controller also supported.</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> WINDOWS® 7, 8, 8.1, 10 (64-BIT Required)<br></li><li><strong>Processor:</strong> Intel Core i5-4690K @3.50GHz or AMD FX-9370<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA® GeForce® GTX 960 or AMD Radeon R7 370<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Sound Card:</strong> DirectX compatible soundcard or onboard chipset<br></li><li><strong>Additional Notes:</strong> Compatible with XInput and DirectInput USB devices including gamepads and arcade sticks based on Xbox 360, Xbox One, and DualShock controllers. Steam Controller also supported.</li></ul>\'}', '0,35', '0,31', '0,08', '0,13', '0,87'),
(209, 'dmc devil may cry', '2013', 16, 58, 14820, 956, 533, 23.99, 'In this retelling of Dante\'s origin story which is set against a contemporary backdrop, DmC Devil May Cry™ retains the stylish action.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong>Windows Vista(R)/XP, Windows 7, Windows 8<br>\\t</li><li><strong>Processor:</strong>Intel(R) Core(TM)2 Duo 2.4 Ghz or better, AMD Athlon(TM) X2 2.8 Ghz or better<br>\\t</li><li><strong>Memory:</strong>2 GB RAM<br>\\t</li><li><strong>Graphics:</strong>NVIDIA(R) GeForce(R) 8800GTS or better, ATI Radeon(TM) HD 3850 or better<br>\\t</li><li><strong>DirectX®:</strong>9.0c<br>\\t</li><li><strong>Hard Drive:</strong>9 GB HD space<br>\\t</li><li><strong>Sound:</strong>Standard audio device</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong>Windows Vista(R)/XP, Windows 7, Windows 8<br>\\t</li><li><strong>Processor:</strong>Intel(R) Core(TM)2 Quad 2.7 Ghz or better, AMD Phenom(TM)II X4 3 Ghz or better<br>\\t</li><li><strong>Memory:</strong>4 GB RAM<br>\\t</li><li><strong>Graphics:</strong>ATI Radeon(TM) HD 6950 or better<br>\\t</li><li><strong>DirectX®:</strong>9.0c<br>\\t</li><li><strong>Hard Drive:</strong>9 GB HD space<br>\\t</li><li><strong>Sound:</strong>Standard audio device</li></ul>\'}', '0,7', '0,58', '0,2', '0,22', '1,69'),
(210, 'hitman contracts', '2014', 16, 0, 1000, 195, 15, 8.29, 'Enter the world of a HITMAN - a world of crime, sin and greed. Delve into the mind of Agent 47 and encounter his greatest adversaries, completing the work that made him so brutally efficient and shaped him as an assassin. Eliminate your targets by any means necessary. There are no rules... only the contract, signed in blood.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 98/2000/ME/XP<br></li><li><strong>Processor:</strong> Pentium III 800MHz<br></li><li><strong>Memory:</strong> 256 MB RAM<br></li><li><strong>Graphics:</strong> 100% DirectX 8.1 compatible 3D accelerator video card with at least 32Mb RAM<br></li><li><strong>DirectX:</strong> Version 8.1<br></li><li><strong>Storage:</strong> 2 GB available space</li></ul>\'}', '0,65', '0,38', '0', '0,11', '1,14'),
(211, '[prototype 2]', '', 0, 0, 0, 0, 0, 0.00, '0', '0', '0,91', '0,55', '0', '0,19', '1,65'),
(212, 'tom clancys splinter cell double agent', '2009', 0, 0, 356, 454, 0, 8.59, 'The best-selling Tom Clancy\'s Splinter Cell® saga takes on an entirely new direction. In the highly anticipated sequel to the 2005 game of the year, Tom Clancy\'s Splinter Cell Double Agent™, play as a double agent spy for the first time ever.', '{\'minimum\': \'<strong>Minimum: </strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>Supported OS: </strong>Microsoft Windows® XP<br>\\t\\t\\t\\t\\t</li><li><strong>Processor: </strong>3 Ghz Pentium 4 or AMD Athlon 3000 (3.5 Ghz Pentium 4 or Athlon 3500 recommended) - Game optimized for dual-processor-enabled computers. <br>\\t\\t\\t\\t\\t</li><li><strong>System Memory: </strong>1 GB or above (1.5 GB recommended) <br>\\t\\t\\t\\t\\t</li><li><strong>Video Card: </strong>DirectX 9.0c-compliant, Shader 3.0-enabled 128 MB video card (256 MB recommended) (see supported list*) <br>\\t\\t\\t\\t\\t</li><li><strong>Sound Card: </strong>DirectX 9.0c-compatible (EAX recommended) - PC audio solution containing Dolby Digital Live required for Dolby Digital audio. <br>\\t\\t\\t\\t\\t</li><li><strong>DirectX Version: </strong>DirectX® version 9.0c or higher<br>\\t\\t\\t\\t\\t</li><li><strong>Hard Disk: </strong>8 GB available hard disk space<br>\\t\\t\\t\\t\\t</li><li><strong>Multiplay: </strong>Broadband connection with 128 kbps upstream or faster <br>\\t\\t\\t\\t\\t</li><li><strong>*Supported video cards at time of retail release: </strong>Single Player: ATI X1300 / X1600 / X1800 / X1900, NVIDIA 6200 / 6600 / 6800 / 7300 / 7600 / 7800 / 7900 | Multiplayer: ATI X1600 / X1800 / X1900, NVIDIA 6600 / 6800 /7300 / 7600 / 7800 / 7900<br>\\t\\t\\t\\t\\t</li><li><strong>Note:</strong>Laptop versions of these cards may work but are NOT supported. These chipsets are the only ones that will run this game. For the most up-to-date minimum requirement listings, please visit the FAQ for this game on our support website at: <a href=\"https://steamcommunity.com/linkfilter/?url=http://support.ubi.com\" target=\"_blank\" rel=\"noopener\" >http://support.ubi.com</a>.</li></ul>\'}', '1,01', '0,1', '0,01', '0,1', '1,23'),
(213, 'yars revenge', '2011', 0, 12, 29, 20, 0, 6.99, 'Take flight as you explore exotic alien worlds and seek to avenge your fallen race', '{\'minimum\': \'<ul>\\n\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>OS:</strong> Windows XP SP2, Vista SP2, 7\\n\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>Processor:</strong> Intel Core 2 Duo E4300 or AMD Athlon X2 4400+\\n\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>Memory:</strong> 1 GB\\n\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>Graphics:</strong> : Radeon ATI Radeon HD 2600 or NVIDIA GeForce 8600 or faster. <i>Other integrated graphics, such as the Intel G43/G45 Express, are not supported.</i>\\n\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>DirectX&reg;:</strong> 9.0c\\n\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>Hard Drive:</strong> 1.5 GB free\\n\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>Sound:</strong> DirectX 9.0c-compatible\\n\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</ul>\'}', '0,73', '0,04', '0', '0,01', '0,78'),
(214, 'doom', '2016', 18, 54, 68536, 5156, 751, 14.99, 'Now includes all three premium DLC packs (Unto the Evil, Hell Followed, and Bloodfall), maps, modes, and weapons, as well as all feature updates including Arcade Mode, Photo Mode, and the latest Update 6.66, which brings further multiplayer improvements as well as revamps multiplayer progression.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7/8.1/10 (64-bit versions)<br></li><li><strong>Processor:</strong> Intel Core i5-2400/AMD FX-8320 or better<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GTX 670 2GB/AMD Radeon HD 7870 2GB or better<br></li><li><strong>Storage:</strong> 55 GB available space<br></li><li><strong>Additional Notes:</strong> Requires Steam activation and broadband internet connection for Multiplayer and SnapMap</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7/8.1/10 (64-bit versions)<br></li><li><strong>Processor:</strong> Intel Core i7-3770/AMD FX-8350 or better<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GTX 970 4GB/AMD Radeon R9 290 4GB or better<br></li><li><strong>Storage:</strong> 55 GB available space<br></li><li><strong>Additional Notes:</strong> Requires Steam activation and broadband internet connection for Multiplayer and SnapMap</li></ul>\'}', '0,55', '0,34', '0', '0,05', '0,95'),
(215, 'puzzler world', '2010', 0, 14, 299, 37, 0, 4.99, 'Puzzler World brings over 1200 puzzles of 8 popular puzzle types to your PC. Conceptis picture logic puzzle fans will be happy to know that in addition to Crossword, Wordsearch, Fitword, Sudoku, Codeword, Spot the Difference and Silhouette puzzles, Puzzler World also offers 83 Conceptis Link-a-Pix available in sizes of 10x10, 20x20 and...', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Microsoft Windows 2000/ Microsoft Windows XP/ Microsoft Windows Vista (admin rights required) 95/98/ME/NT4 no longer supported.<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Pentium 3 1GHz or Athlon XP equivalent<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>RAM:</strong> 256MB system Memory (XP); 512MB system Memory (Vista)<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 32MB DirectX 9.0c video card<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 700MB Free Space<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> Direct X 9.0c compatible sound card<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Input Devices:</strong> Keyboard and mouse<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics Cards Supported:</strong> All DirectX 9.0c graphics cards, GeForce, GeForce 2, GeForce 3, GeForce 4, GeForce MX, GeForce FX, GeForce 5 Series GeForce 6 Series, GeForce 7 Series, GeForce 8 Series, Radeon, Radeon 8 Series, Radeon 9 Series, Radeon X Series.<br>\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br>\\t\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Microsoft Windows 2000/ Microsoft Windows XP/ Microsoft Windows Vista (admin rights required) 95/98/ME/NT not supported.<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Pentium 4 2GHz or Athlon XP/64bit Equivalent<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>RAM:</strong> 1GB system Memory<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 128MB DirectX 9.0c video card<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 700MB Free Space<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> Direct X 9.0c compatible sound card<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Input Devices:</strong> Keyboard and 3 button mouse<br>\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0,41', '0,3', '0', '0,07', '0,78'),
(216, 'turok', '2015', 0, 10, 1614, 73, 2092, 14.99, 'A world where time has no meaning - and evil knows no bounds. Torn from a world long gone, the time traveling warrior Turok has found himself thrust into a savage land torn by conflict.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 32-bit<br></li><li><strong>Processor:</strong> Dual-core from Intel or AMD at 2.0 GHz<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> Intel 787 Express or equivalent supporting OpenGL 2.1 Core<br></li><li><strong>Storage:</strong> 800 MB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7/8/10<br></li><li><strong>Processor:</strong> Intel Core i5-2300 2.8 GHz/AMD Phenom II X4 945 3.0 GHz or equivalent<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce 7800/7900/8600 series, ATI/AMD Radeon HD 2600/3600 or X1800/X1900 series supporting OpenGL 2.1 Core<br></li><li><strong>Storage:</strong> 800 MB available space</li></ul>\'}', '0,81', '0,44', '0,02', '0,17', '1,44'),
(217, 'splitsecond', '2014', 0, 0, 717, 207, 143, 15.49, 'Split/Second is an intense action racing game set within a reality TV show. Competitors vie to be the first to the finish line in a set rigged to blow. Players don’t just collide with other vehicles to knock them from the track, but can also trigger devastating events that alter the race dynamics.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Microsoft Windows 7 / Vista SP2 / XP SP3<br></li><li><strong>Processor:</strong> 3.0 GHz Intel Pentium D processor (Windows 7 / Vista) / 2.6 GHz Intel Pentium D processor (Windows XP) or 2.0 GHz AMD Athlon 64 X2 or equivalent processor<br></li><li><strong>Memory:</strong> 2560 MB RAM<br></li><li><strong>Graphics:</strong> 256 MB DirectX 9.0c-compatible, 3D video card supporting Shaders 3.0 (NVIDIA GeForce 7600 or better, ATI Radeon X1600 or better)<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 6656 MB available space<br></li><li><strong>Sound Card:</strong> 16-bit DirectX 9.0c-compatible sound card<br></li><li><strong>Additional Notes:</strong> Onboard (built-in) integrated chipsets are not supported</li></ul>\'}', '0,7', '0,6', '0,01', '0,21', '1,51'),
(218, 'borderlands the presequel', '2014', 18, 63, 16909, 5076, 1661, 29.99, 'Launch into the Borderlands universe and shoot ‘n’ loot your way through a brand new adventure that rockets you onto Pandora’s moon in Borderlands: The Pre-Sequel!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP SP3<br></li><li><strong>Processor:</strong> 2.4 GHz Dual Core Processor<br></li><li><strong>Memory:</strong> 2048 MB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce 8500 / ATI Radeon HD 2600<br></li><li><strong>DirectX:</strong> Version 9.0<br></li><li><strong>Storage:</strong> 13 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9 Compliant<br></li><li><strong>Additional Notes:</strong> Other Requirements &amp; Supports: Initial installation requires one time internet connection for Steam authentication; software installations required (included with the game) include Steam Client, directX 9, Microsoft .NET 4 Framework, Visual C++ Redistributable 2005, Visual C++ Redistributable 2008, Visual C++ Redistributable 2010, and AMD CPU Drivers (XP Only/AMD Only). Windows Imaging Component (Windows XP 64-Bit only)</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP SP3/Vista/Win 7/Win 8<br></li><li><strong>Processor:</strong> 2.3 GHz Quad Core processor<br></li><li><strong>Memory:</strong> 2048 MB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 560 / ATI Radeon HD 5850<br></li><li><strong>DirectX:</strong> Version 10<br></li><li><strong>Storage:</strong> 20 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0 c Compliant</li></ul>\'}', '0,82', '0,63', '0,06', '0,2', '1,71'),
(219, 'oddworld munchs oddysee', '2010', 0, 38, 437, 155, 3, 3.99, 'New port for 2016! 60 FPS, higher res textures, higher poly models, improved audio, numerous fixes and improvements, and trading cards, badges, emotes and backgrounds!', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 or higher<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Core2 +<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1GB<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> nVidia Geforce 6600 128MB<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DX9<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 3.8 GB<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX®9<br>\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0,58', '0,18', '0', '0,03', '0,79'),
(220, 'full spectrum warrior', '2007', 0, 0, 106, 60, 124, 7.99, 'The U.S. Army is the most powerful ground force in the entire world. The backbone of a ground invasion is the U.S. Army Infantry, and in the midst of combat, their skills, courage, and teamwork are put to the test. While readiness continues to be the U.S. Army\'s top priority, how it goes about its business is changing.', '{\'minimum\': \'<strong>Minimum: </strong>Windows 2000/XP (only), AMD Athlon 1 GHz or Pentium III 1 GHz, 256 MB RAM, DirectX 9.0b-compatible graphics card from NVIDIA or ATI, GeForce 3 and higher, ATI Radeon 8500 and higher, DirectX 9.0b-compatible sound card, 1.5 GB Free Hard Drive Space, Broadband Internet Connection (for multiplayer)<br>\\t\\t\\t\\t\\t<br>\\t\\t\\t\\t\\t<strong>Recommended: </strong>Windows XP, AMD Athlon XP 2000+ and above OR Pentium 4 2GHz and above, 512 MB RAM or greater, GeForce 4 Ti and higher or ATI Radeon 9500 and higher, DirectX 9.0b-compatible sound card, SoundBlaster Audigy preferred\'}', '0,69', '0,27', '0', '0,07', '1,03'),
(221, 'xcom enemy unknown', '2012', 12, 85, 36630, 2072, 1470, 14.99, 'The XCOM: Enemy Unknown - Slingshot Pack is Now Available!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong>Windows Vista<br>\\t</li><li><strong>Processor:</strong>2 GHz Dual Core <br>\\t</li><li><strong>Memory:</strong>2 GB RAM<br>\\t</li><li><strong>Graphics:</strong>NVIDIA GeForce 8600 GT / ATI Radeon HD 2600 XT or greater <br>\\t</li><li><strong>DirectX®:</strong>9.0<br>\\t</li><li><strong>Hard Drive:</strong>20 GB HD space<br>\\t</li><li><strong>Sound:</strong>DirectX Compatible<br>\\t</li><li><strong>Other Requirements:</strong>Broadband Internet connection<br>\\t</li><li><strong>Additional:</strong>Initial installation requires one-time internet connection for Steam authentication; software installations required (included with the game) include Steam Client, Visual C++ 2008 Redistributable, DirectX and Microsoft .NET 4.</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong>Windows 7 <br>\\t</li><li><strong>Processor:</strong>2 GHz Dual Core (Intel Core 2 Duo 2.4 GHz or Athlon X2 2.7 GHz)<br>\\t</li><li><strong>Memory:</strong>4 GB RAM<br>\\t</li><li><strong>Graphics:</strong>NVIDIA GeForce 9000 series / ATI Radeon HD 3000 series or greater<br>\\t</li><li><strong>DirectX®:</strong>9.0<br>\\t</li><li><strong>Hard Drive:</strong>20 GB HD space<br>\\t</li><li><strong>Sound:</strong>DirectX Compatible<br>\\t</li><li><strong>Other Requirements:</strong>Broadband Internet connection<br>\\t</li><li><strong>Additional:</strong>Initial installation requires one-time internet connection for Steam authentication; software installations required (included with the game) include Steam Client, Visual C++ 2008 Redistributable, DirectX and Microsoft .NET 4.</li></ul>\'}', '0,86', '0,84', '0', '0,26', '1,96'),
(222, 'terraria', '2011', 0, 88, 255600, 7797, 5585, 6.99, 'Dig, fight, explore, build! Nothing is impossible in this action-packed adventure game. Four Pack also available!', '{\'minimum\': \'<h2 class=\"bb_tag\"><strong>REQUIRED</strong></h2><ul class=\"bb_ul\"><li><strong>OS: Windows Xp, Vista, 7, 8/8.1, 10</strong> <br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor: 2.0 Ghz</strong> <br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory: 2.5GB</strong><br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space: 200MB </strong> \\t<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Video Card: 128mb Video Memory, capable of Shader Model 2.0+</strong> <br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®: 9.0c or Greater</strong> \\t<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<h2 class=\"bb_tag\"><strong>RECOMMENDED</strong></h2><ul class=\"bb_ul\"><li><strong>OS: Windows 7, 8/8.1, 10</strong> <br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor: Dual Core 3.0 Ghz</strong> <br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory: 4GB</strong><br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space: 200MB </strong> \\t<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Video Card: 256mb Video Memory, capable of Shader Model 2.0+</strong> <br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®: 9.0c or Greater</strong> \\t<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0,42', '0,85', '0,23', '0,16', '1,68'),
(223, 'crysis', '2008', 0, 0, 6075, 1277, 313, 9.99, 'Adapt to Survive  An epic story thrusts players into an ever-changing environment, forcing them to adapt their tactics and approach to conquer battlefields ranging from newly frozen jungle to zero-gravity alien environments. Suit up!  A high-tech Nanosuit allows gamers to augment their abilities in real time on the battlefield.', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>Supported OS: </strong>Windows XP or Windows Vista***<br>\\t\\t\\t\\t\\t</li><li><strong>Processor: </strong>2.8 GHz or faster (XP) or 3.2 GHz or faster* (Vista)<br>\\t\\t\\t\\t\\t</li><li><strong>Memory: </strong>1.0 GB RAM (XP) or 1.5 GB RAM (Vista)<br>\\t\\t\\t\\t\\t</li><li><strong>Graphics: </strong>256 MB**<br>\\t\\t\\t\\t\\t</li><li><strong>DirectX Version: </strong>DirectX 9.0c (included)<br>\\t\\t\\t\\t\\t</li><li><strong>Sound: </strong>DirectX 9.0c compatible<br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive: </strong>12GB<br>\\t\\t\\t\\t\\t</li><li>* Supported Processors: Intel Pentium 4 2.8 GHz (3.2 GHz for Vista) or faster, Intel Core 2.0 GHz (2.2 GHz for Vista) or faster, AMD Athlon 2800+ (3200+ for Vista) or faster.<br>\\t\\t\\t\\t\\t</li><li>** Supported chipsets: NVIDIA GeForce 6800 GT or greater; ATI Radeon 9800 Pro (Radeon X800 Pro for Vista) or greater. Laptop versions of these chipsets may work but are not supported. Integrated chipsets are not supported. Updates to your video and sound card drivers may be required.<br>\\t\\t\\t\\t\\t</li><li>*** Currently only the 32-bit version is available.</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>Supported OS: </strong>Windows XP or Windows Vista<br>\\t\\t\\t\\t\\t</li><li><strong>Processor: </strong>Intel Core 2 DUO @ 2.2GHz or AMD Athlon 64 X2 4400+<br>\\t\\t\\t\\t\\t</li><li><strong>Memory: </strong>2.0 GB RAM<br>\\t\\t\\t\\t\\t</li><li><strong>Graphics: </strong>NVIDIA GeForce 8800 GTS/640 or similar</li></ul>\'}', '0', '0,69', '0', '0,03', '0,72'),
(224, 'final fantasy xx2 hd remaster', '2016', 12, 69, 6334, 723, 596, 19.99, 'FINAL FANTASY X/X-2 HD Remaster celebrates two of the most cherished and beloved entries to the world-renowned franchise, completely remastered in gorgeous High Definition &amp; now available on PC / Windows!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista or later<br></li><li><strong>Processor:</strong> 2GHz Dual Core CPU<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA Geforce 9600GT VRAM 512MB or later / ATI Radeon HD 2600XT VRAM 512MB or later<br></li><li><strong>Storage:</strong> 37 GB available space<br></li><li><strong>Sound Card:</strong> DirectX Compatible Sound Card</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista or later<br></li><li><strong>Processor:</strong> 2.4GHz quad-core CPU<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA Geforce GTX 450 / AMD Radeon HD 5750 with 512MB<br></li><li><strong>Storage:</strong> 40 GB available space<br></li><li><strong>Sound Card:</strong> DirectX Compatible Sound Card</li></ul>\'}', '0,29', '0,25', '0,06', '0,11', '0,71'),
(225, 'prince of persia the forgotten sands', '2010', 0, 0, 511, 263, 328, 8.59, 'Prince of Persia The Forgotten Sands is the next chapter in the fan-favorite Sands of Time universe. Visiting his brother\'s kingdom following his adventure in Azad, the Prince finds the royal palace under siege from a mighty army bent on its destruction.', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP (SP3) / Windows Vista (SP2) / Windows 7<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 2.6 GHz dual-core Intel Pentium D or AMD Athlon 64 X2 3800+ (2.2 GHz Intel Core 2 Duo or AMD Athlon 64 X2 4400+ or higher recommended)<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1 GB Windows XP / 2 GB Windows Vista, Windows 7 (2 GB / 4 GB recommended)<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 256 MB DirectX 9.0c–compliant card with Shader Model 3.0 or higher (512 MB recommended) (see supported list*)<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX 9.0c<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 8 GB<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX 9.0c–compliant sound card (5.1 sound card recommended)<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Peripherals Supported:</strong> Windows-compliant keyboard, mouse, optional controller (Xbox 360 Controller for Windows recommended)<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Internet Connection:</strong> Broadband Internet connection with 128 kbps or faster<br>\\t\\t\\t\\t\\t\\t</li></ul>*Supported Video Cards at Time of Release:<br><br>\\t\\t\\t\\t\\t\\tNVIDIA GeForce 6800 / 7 / 8 / 9 / 100 / 200 / GTX series<br><br>\\t\\t\\t\\t\\t\\tATI RADEON X1600 / HD 2000 / HD 3000 / HD 4000 / HD 5000 series<br><br>\\t\\t\\t\\t\\t\\tLaptop versions of these cards may work but are NOT supported. These chipsets are the only ones that will run this game.\'}', '0,83', '0,95', '0,02', '0,32', '2,13'),
(226, 'world of zoo', '2009', 0, 0, 115, 30, 115, 4.99, 'What would you do if you had the keys to the zoo? World of Zoo is the only life sim game that pushes you past the fences and into a world of your own zoo. Create and customize your zoo experience and develop hands on relationships to earn the trust and love of your animals.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Microsoft Windows XP/Vista<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Pentium IV processor running at 2 GHz, AMD 64, Core 2 duo 1.6Ghz or equivalent <br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 512 MB RAM (1 GB RAM on Vista)<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> Nvidia GeForce 6600 GT or ATI Radeon x1600 with at least 64MB of memory (video cards with Pixel Shader version 1.1 or better are required)<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Display:</strong> DirectX-compatible display capable of 800x600 resolution in 16-bit color<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX 9.0c and above<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 2GB of hard drive space<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> Sound: 16-bit Sound Blaster Compatible<br>\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0,84', '0,38', '0', '0,12', '1,36'),
(227, 'mafia', '2002', 0, 0, 1727, 180, 32, 7.99, 'It’s 1930. After an inadvertent brush with the mafia, cabdriver Tommy Angelo is reluctantly thrust into the world of organized crime. Initially, he is uneasy about falling in with the Salieri family, but soon the rewards become too big to ignore.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP / Vista / 7 / 8 / 10<br></li><li><strong>Processor:</strong> 1.4 GHz or faster<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> 3D Graphics card compatible with DirectX 9.0<br></li><li><strong>DirectX:</strong> Version 9.0<br></li><li><strong>Storage:</strong> 3 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c compatible sound card <ul class=\"bb_ul\"></ul><strong>Compatibility notice:</strong> Windows 8 and above require DirectPlay. Windows XP 64-bit is not supported.</li></ul>\'}', '0,51', '0,36', '0', '0,11', '0,98');
INSERT INTO `jeux` (`id_jeu`, `nom_jeu`, `annee`, `age_requis`, `nb_succes`, `nb_avis_pos`, `nb_avis_neg`, `temps_jeu_moyen`, `prix`, `description`, `configuration`, `ventes_AN`, `ventes_EU`, `ventes_JP`, `ventes_Autre`, `ventes_Global`) VALUES
(228, 'disneys chicken little', '2015', 0, 0, 111, 21, 0, 7.19, 'Based on Walt Disney’s feature 3D animation film Chicken Little, Chicken Little the action-packed video game catapults you into the hair-raising adventures of the movie and beyond.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Microsoft® Windows® XP SP2<br></li><li><strong>Processor:</strong> Pentium™ 4 class processor 1.4 GHz<br></li><li><strong>Memory:</strong> 256 MB RAM<br></li><li><strong>Graphics:</strong> 64MB DirectX™ -compatible video card, 32-bit color (NVIDIA GeForce 3 or equivalent)<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 1536 MB available space<br></li><li><strong>Sound Card:</strong> 16-bit DirectX™ -compatible sound card</li></ul>\'}', '1,13', '0,51', '0', '0,1', '1,76'),
(229, 'prince of persia the two thrones', '2009', 0, 0, 365, 109, 205, 8.59, 'The Prince of Persia, a seasoned warrior, returns from the Island of Time to Babylon with his love, Kaileena. Instead of the peace that he longs for, he finds his homeland ravaged by war and the kingdom turned against him.', '{\'minimum\': \'<p><strong>Minimum: </strong></p>\\n\\t\\t\\t\\t\\t<ul>\\n\\t\\t\\t\\t\\t<li><strong>Supported OS:</strong> Windows&reg; 2000/XP (only)</li>\\n\\t\\t\\t\\t\\t<li><strong>Processor:</strong> 1.0 GHz AMD Athlon or Intel Pentium III (1.5 GHz Pentium IV or AMD Athlon recommended) </li>\\n\\t\\t\\t\\t\\t<li><strong>Memory:</strong> 256 MB (512 MB recommended) </li>\\n\\t\\t\\t\\t\\t<li><strong>Graphics:</strong>32 MB DirectX 9.0c compliant (128 MB recommended) (see supported list*) </li>\\n\\t\\t\\t\\t\\t<li><strong>DirectX:</strong> DirectX 9.0c</li>\\n\\t\\t\\t\\t\\t<li><strong>Sound</strong> DirectX 9.0c compliant (Dolby Digital Live required for Dolby Digital audio)\\n\\t\\t\\t\\t\\t<li><strong>Hard Drive:</strong>1.5 GB</li> \\n\\t\\t\\t\\t\\t<li><strong>Peripherals:</strong> Windows-compatible gamepad</li> \\n\\t\\t\\t\\t\\t<li><strong>*Supported video cards at time of retail release:</strong> ATI 7500/8500/9000/X series, NVIDIA GeForce 3/4/FX/6/7 series (GeForce 4 MX not supported); Laptop versions of these chipsets may work but are not supported. For an up-to-date list of supported chipsets, video cards, and operating systems, please visit the FAQ for this game at: http://support.ubi.com.</li> </ul>\\n\'}', '1,01', '0,27', '0', '0,12', '1,41'),
(230, 'sniper elite 3', '2014', 0, 77, 12737, 3297, 321, 22.99, 'Sniper Elite 3 is a tactical third-person shooter that combines stealth, gameplay choice and genre-defining ballistics with huge, open levels and the exotic terrain of World War 2 North Africa.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Microsoft® Windows® Vista (Service Pack 2) or Windows® 7 (Service Pack 1) or Windows® 8 or Windows 8.1. Windows® XP is NOT supported.<br></li><li><strong>Processor:</strong> Dual-core CPU with SSE3 (Intel® Pentium® D 3GHz / AMD Athlon™ 64 X2 4200) or better<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> Microsoft® DirectX® 10.0 compatible graphics card with 256 MB of memory (NVIDIA® GeForce® 8800 series / ATI Radeon™ HD 3870) or better<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 18 GB available space<br></li><li><strong>Sound Card:</strong> Microsoft® DirectX® 10.0 compatible sound card or better<br></li><li><strong>Additional Notes:</strong> Windows® XP is NOT supported. Ensure graphics and audio drivers are up to date.</li></ul>\'}', '0,67', '0,73', '0', '0,25', '1,64'),
(231, 'the darkness', '2017', 0, 0, 2, 16, 0, 2.89, 'The Darkness is the Game that will keep you in constant tension. You have to play for Wilson Walker who decided to return to his old country house, away from the big city. But then our hero discovers that in his house there are some oddities.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7/8/10<br></li><li><strong>Processor:</strong> Intel Dual-Core 2.4 GHz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> 1GB of VRAM Shader Model 3.0 and above<br></li><li><strong>DirectX:</strong> Version 10<br></li><li><strong>Storage:</strong> 3 GB available space<br></li><li><strong>Sound Card:</strong> DirectX®-compatible<br></li><li><strong>Additional Notes:</strong> 32bit windows users need to ensure they have at least 4gb of ram usable on their system.</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7/8/10<br></li><li><strong>Processor:</strong> Quad Core Processor<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> 2GB of VRAM Shader Model 3.0 and above<br></li><li><strong>Storage:</strong> 3 GB available space<br></li><li><strong>Sound Card:</strong> DirectX®-compatible</li></ul>\'}', '0,56', '0,38', '0,01', '0,17', '1,11'),
(232, 'star wars republic commando', '2009', 0, 0, 6392, 379, 369, 7.19, 'You are the leader of an elite squad of Republic Commandos, your mission is to infiltrate, dominate, and ultimately, annihilate the enemy. Your squad will follow your orders and your lead, working together as a team - instinctively, intelligently, instantly. You are their leader. They are your weapon.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 2000, XP or Vista<br>\\t\\t\\t</li><li><strong>Processor:</strong> Pentium III or Athlon 1.0 GHz or faster CPU<br>\\t\\t\\t</li><li><strong>Memory:</strong> 256MB RAM<br>\\t\\t\\t</li><li><strong>Graphics:</strong> 64MB 3D Graphics card with Vertex Shader and Pixel Shader (VS/PS) capability<br>\\t\\t\\t</li><li><strong>DirectX®:</strong> 9.0b<br>\\t\\t\\t</li><li><strong>Hard Drive:</strong> 2.0GB<br>\\t\\t\\t</li><li><strong>Sound:</strong> 100% Directx 9.0c<br>\\t\\t\\t</li></ul>\'}', '0,48', '0,21', '0', '0,03', '0,72'),
(233, 'rift', '2011', 0, 0, 6885, 2326, 4104, 0.00, 'Dive into a world of epic adventure! Create your perfect hero thanks to a uniquely customizable class system. Collect, craft, and customize your gear. Go it alone or group up to challenge dungeons, raids, dynamic open-world content, and your fellow players.', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP, Vista or 7<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Dual Core 2.0 GHz or better<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2 GB<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> Nvidia GeForce FX 5900, ATI/AMD Radeon X300, Intel GMA X4500 or better.<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 9.0c, June 2010 update<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 15.0 GB available <br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX 8.1 compliant card<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Other</strong>: Broadband internet connection (DSL, cable modem or other high speed connection)<br>\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0,44', '0,16', '0', '0,07', '0,67'),
(234, 'command & conquer red alert 3', '2009', 0, 0, 4390, 855, 575, 9.99, 'The desperate leadership of a doomed Soviet Union travels back in time to change history and restore the glory of Mother Russia. The time travel mission goes awry, creating an alternate timeline where technology has followed an entirely different evolution, a new superpower has been thrust on to the world stage, and World War III is...', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>Supported OS:</strong> Microsoft Windows® XP SP2, Windows Vista (32-bit) <br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Any Intel Core Duo machine; XP: Intel Pentium 4 2.2 GHz or better, AMD Athlon XP 2100+ or better; Vista: Intel Pentium 4 2.6 GHz or better, AMD Athlon XP 2800+ or better <br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1 GB RAM <br>\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> DirectX® 9.0c compatible video card, NVIDIA GeForce 6800 or better, ATI Radeon X800 or better <br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> At least 10 GB of free space <br>\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX® 9.0c compatible sound card (Yamaha Xwave-512 is not supported) <br>\\t\\t\\t\\t\\t</li><li><strong>Multiplayer:</strong> 2 - 6 players with optional voice support, network or Internet connection required (Cable, DSL or faster connection). </li></ul><ul class=\"bb_ul\"><li>INTERNET CONNECTION, ONLINE AUTHENTICATION AND ACCEPTANCE OF END USER LICENSE AGREEMENT REQUIRED TO PLAY. TO ACCESS ONLINE FEATURES, YOU MUST REGISTER ONLINE. ONLY ONE REGISTRATION IS AVAILABLE PER GAME. EA ONLINE TERMS &amp; CONDITIONS AND FEATURE UPDATES CAN BE FOUND AT <a href=\"https://steamcommunity.com/linkfilter/?url=http://WWW.EA.COM\" target=\"_blank\" rel=\"noopener\" >WWW.EA.COM</a>. YOU MUST BE 13+ TO REGISTER WITH EA ONLINE. EA MAY RETIRE ONLINE FEATURES AFTER 30 DAYS NOTICE POSTED ON <a href=\"https://steamcommunity.com/linkfilter/?url=http://WWW.EA.COM\" target=\"_blank\" rel=\"noopener\" >WWW.EA.COM</a>.</li></ul>\'}', '0,19', '0,87', '0', '0,07', '1,13'),
(235, 'darkstone', '2014', 0, 0, 160, 56, 27375, 3.99, 'Lord Draak\'s henchmen are spreading chaos in Uma. Are you going to let them get away with it?', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® XP / Vista™ / Windows® 7 /8<br></li><li><strong>Processor:</strong> 2,4 GHz CPU<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>DirectX:</strong> Version 9.0c</li></ul>\'}', '0,37', '0,25', '0', '0,04', '0,66'),
(236, 'brothers in arms road to hill 30', '2008', 0, 0, 624, 100, 69, 4.29, 'Based on a true story. Set during the famous airdrop before the invasion at Normandy, where Sgt. Matt Baker and his squad of 101st Airborne Paratroopers were scattered over the French countryside.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>Supported OS: </strong>Windows® 2000/XP (only)<br>\\t\\t\\t\\t\\t</li><li><strong>Processor: </strong>1 GHz Pentium® III or AMD Athlon™ (2.5 GHz Pentium IV or AMD recommended)<br>\\t\\t\\t\\t\\t</li><li><strong>Memory: </strong>512 MB (1 GB recommended)<br>\\t\\t\\t\\t\\t</li><li><strong>Graphics: </strong>32 MB DirectX® 9.0c compliant (see supported list*)<br>\\t\\t\\t\\t\\t</li><li><strong>DirectX Version: </strong>DirectX 9.0c (included)<br>\\t\\t\\t\\t\\t</li><li><strong>Sound: </strong>16-bit DirectX 9.0c compliant sound card<br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive: </strong>5 GB<br>\\t\\t\\t\\t\\t</li><li><strong>Peripherals: </strong>Windows keyboard and mouse only<br>\\t\\t\\t\\t\\t</li><li>*Video cards supported at time of release: ATI® Radeon® 8500/9000/X series, NVIDIA® GeForce™ 4/FX/6 series (GeForce 4 MX not supported)</li></ul>\'}', '0,87', '0,15', '0', '0,08', '1,12'),
(237, 'f1 2015', '2015', 0, 45, 3834, 2720, 305, 29.99, 'Race like a champion in F1™ 2015 A stunning new game engine and all-new ‘broadcast presentation’ puts you in the heart of the action.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 64 bit or Windows 8 64 bit<br></li><li><strong>Processor:</strong> Intel Core 2 Quad @ 3.0GHz or AMD Phenom II X4 @ 3.2GHz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> Intel 4th Gen Iris Graphics or AMD HD5770 or NVIDIA GTS450<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 20 GB available space<br></li><li><strong>Sound Card:</strong> DirectX Compatible soundcard<br></li><li><strong>Additional Notes:</strong> Supported Graphics Cards: DirectX 11 Graphics Card Required Intel: 4th Gen Iris or Higher, Intel Iris Pro Series AMD: HD5770 or Higher, HD6770 or Higher, HD7750 or Higher, R7 250 or Higher, R9 Series Nvidia: GTS450 or Higher, GT545 or Higher, GT640 or Higher, GT740 or Higher, GTX900 Series</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 64 bit or Windows 8 64 bit<br></li><li><strong>Processor:</strong> Intel Core i7 4770 or AMD FX 9370<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> Intel 5th Gen Iris Pro or AMD R9 290 or Nvidia GTX970<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 20 GB available space<br></li><li><strong>Sound Card:</strong> Direct X compatible soundcard<br></li><li><strong>Additional Notes:</strong> Intel, the Intel logo and Iris are trademarks of Intel Corporation in the U.S. and/or other countries. <h2 class=\"bb_tag\"> </h2><img src=\"https://i.imgur.com/w0n0cfe.png?1\" ></li></ul>\'}', '0,17