(238, 'lego marvels avengers', '2016', 0, 70, 1898, 384, 59, 24.99, 'Avengers Assemble! The best-selling LEGO® MARVEL videogame franchise returns with a new action-packed, Super Hero adventure.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP/Vista/7/8/10<br></li><li><strong>Processor:</strong> Intel Core 2 Quad Q6600 (2.4 GHz) / AMD Phenom x4 9850 (2.5 GHz)<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> GeForce GT 430 (1024 MB)/ Radeon HD 6850 (1024 MB)<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 14 GB available space<br></li><li><strong>Sound Card:</strong> DirectX compatible<br></li><li><strong>Additional Notes:</strong> Windows XP and DirectX® 9.0b and below not supported</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP/Vista/7/8/10<br></li><li><strong>Processor:</strong> Intel i5, 4 x 2.6 GHz or AMD equivalent<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 480 or ATI Radeon HD 5850 or better, 1Gb RAM<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 14 GB available space<br></li><li><strong>Sound Card:</strong> DirectX compatible<br></li><li><strong>Additional Notes:</strong> Windows XP and DirectX® 9.0b and below not supported</li></ul>\'}', '0,96', '1', '0,01', '0,29', '2,26'),
(239, 'vanquish', '2017', 18, 50, 2360, 327, 490, 14.99, 'PlatinumGames’ revolutionary sci-fi action shooter slide-boosts onto PC. Battle legions of future-tech enemies using a vast arsenal of weapons, including all DLC. Fully unlocked framerate and gorgeous HD resolutions up to 4K. The definitive way to play: war has accelerated.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Microsoft Windows 7 / 8 (8.1) / 10<br></li><li><strong>Processor:</strong> Intel Core i3 (2.9 GHz) or AMD equivalent<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> Dx9 compliant video card with 1 GB VRAM (Nvidia GeForce 460 or AMD Radeon 5670)<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 20 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> OS: Microsoft Windows 7 / 8 (8.1) / 10<br></li><li><strong>Processor:</strong> Intel Core i5 (3.4 GHz) or AMD equivalent<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> Dx11 compliant video card with 2 GB RAM (Nvidia GeForce 660 Ti or AMD Radeon R9 270)<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 20 GB available space</li></ul>\'}', '0,4', '0,39', '0,14', '0,13', '1,04'),
(240, 'scribblenauts unlimited', '2013', 0, 25, 6661, 588, 630, 14.99, 'The best-selling, award-winning franchise is back – on your home PC in gorgeous HD for the first time.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP or higher<br>\\t</li><li><strong>Processor:</strong> AMD Atholon 64 X2 Dual-Core 4000+ or better / Intel Core 2 Duo Processor 2.0GHz or better<br>\\t</li><li><strong>Memory:</strong> 2 GB RAM<br>\\t</li><li><strong>Graphics:</strong> ATI X1800 or better / nVidia 7800 or better / Intel 4100 or better. 256MB Video RAM. Shader 3.0 or better<br>\\t</li><li><strong>DirectX®:</strong> 9.0c<br>\\t</li><li><strong>Hard Drive:</strong> 2 GB HD space<br>\\t</li><li><strong>Other Requirements:</strong> Broadband Internet connection</li></ul>\'}', '0,81', '0,1', '0', '0,07', '0,98'),
(241, 'kane & lynch 2 dog days', '2010', 18, 59, 2822, 1919, 282, 7.99, 'Pure adrenaline of non-stop action in Single Player, Online Co-op and Multiplayer. Double the pleasure and mayhem with new multiplayer DLCs!', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP/Vista/7<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel 3.0 GHz or AMD 2.5 GHz or higher<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1 GB (XP), 2 GB (Vista)<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> Nvidia 7800 / ATI X1800 or better (Shader Model 3.0, 512 MB Video Memory)<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 9.0c<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX 9.0c Compatible Sound Card<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Controller Support:</strong> Xbox 360 Controller<br>\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0,37', '0,57', '0,06', '0,16', '1,15'),
(242, 'payday 2', '2013', 18, 1130, 308657, 56523, 3975, 7.49, 'PAYDAY 2 is an action-packed, four-player co-op shooter that once again lets gamers don the masks of the original PAYDAY crew - Dallas, Hoxton, Wolf and Chains - as they descend on Washington DC for an epic crime spree.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong>Windows 7<br>\\t</li><li><strong>Processor:</strong>2 GHz Intel Dual Core Processor<br>\\t</li><li><strong>Memory:</strong>4 GB RAM<br>\\t</li><li><strong>Graphics:</strong>Nvidia &amp; AMD (512MB VRAM)<br>\\t</li><li><strong>DirectX®:</strong>9.0c<br>\\t</li><li><strong>Hard Drive:</strong>31 GB HD space <br>\\t</li><li><strong>Sound:</strong>DirectX 9.0c compatible</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong>Windows 10<br>\\t</li><li><strong>Processor:</strong>2.3 GHz Intel Quad Core Processor<br>\\t</li><li><strong>Memory:</strong>8 GB RAM<br>\\t</li><li><strong>Graphics:</strong>Nvidia &amp; AMD (1GB VRAM)<br>\\t</li><li><strong>DirectX®:</strong>9.0c<br>\\t</li><li><strong>Hard Drive:</strong>45 GB HD space<br>\\t</li><li><strong>Sound:</strong>DirectX 9.0c compatible</li></ul>\'}', '0,75', '0,57', '0', '0,18', '1,52'),
(243, 'tales of zestiria', '2015', 0, 56, 5300, 972, 1445, 39.99, 'In a world torn by war and political skirmishes, accept the burden of the Shepherd and fight human darkness to protect your world from Malevolence and reunite humans and Seraphim.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista, 7, 8, 10<br></li><li><strong>Processor:</strong> Intel Core 2 Duo 2.4Ghz / AMD Athlon 64 X2 5200+, 2.6GHz<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> Nvidia GeForce 8800GT / ATI Radeon HD 4830 or equivalent<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 12 GB available space<br></li><li><strong>Additional Notes:</strong> Gamepad support</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 (x64) / Windows 8 (x64) / Windows 10 (x64)<br></li><li><strong>Processor:</strong> Intel Core i3-530, 2.93 GHz / AMD Phenom II X4 940, 3.0GHz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> Nvidia GeForce GTX 560 Ti / AMD Radeon HD 7850 or equivalent<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 12 GB available space<br></li><li><strong>Additional Notes:</strong> Gamepad support</li></ul>\'}', '0,21', '0,24', '0,44', '0,09', '0,97'),
(244, 'doom 3 bfg edition', '2012', 18, 65, 3957, 772, 644, 14.99, 'The ultimate collection of games that defined the first person shooter, the BFG Edition includes the entire DOOM series and a remastered version of DOOM 3!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong>Windows vista/ Windows 7<br>\\t</li><li><strong>Processor:</strong>2.0 GHz dual core<br>\\t</li><li><strong>Memory:</strong>3 GB RAM<br>\\t</li><li><strong>Graphics:</strong>NVIDIA GeForce 9800 GT / ATI Radeon HD 5750, 512 MB video RAM<br>\\t</li><li><strong>Hard Drive:</strong>11 GB<br>\\t</li><li><strong>Sound:</strong>Windows compatible sound card</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong>Windows Vista-64/ Windows 7-64<br>\\t</li><li><strong>Processor:</strong>2.4 GHz dual core<br>\\t</li><li><strong>Memory:</strong>3 GB system RAM<br>\\t</li><li><strong>Graphics:</strong>NVIDIA GeForce GTX 260 / ATI Radeon HD 5850, 768 MB video RAM<br>\\t</li><li><strong>Hard Drive:</strong>11 GB<br>\\t</li><li><strong>Sound:</strong>Windows compatible sound card<br>\\t</li><li><strong>Additional:</strong>3D Monitor + compatible glasses</li></ul>\'}', '0,54', '0,41', '0', '0,15', '1,11'),
(245, 'blazblue calamity trigger', '2014', 0, 0, 1843, 301, 174, 6.99, 'The first hi-res 2D fighter from the creators of the Guilty Gear series! BlazBlue is a traditional 2D fighter where two characters participate in a duel.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7<br></li><li><strong>Processor:</strong> Intel Core2 Duo<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> nVidia Geforce 7900 / AMD Radeon X1900<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 10 GB available space<br></li><li><strong>Sound Card:</strong> Direct Sound</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 / 8 / Vista<br></li><li><strong>Processor:</strong> Intel Core i5 / i7<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> nVidia Geforce 8800 / AMD Radeon HD3700<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 10 GB available space<br></li><li><strong>Sound Card:</strong> Direct Sound</li></ul>\'}', '0,57', '0,19', '0,1', '0,09', '0,95'),
(246, 'rooms the main building', '2014', 0, 0, 128, 26, 1, 7.19, 'Use object inside rooms and move the rooms to escape. 100 challenging sliding puzzles with a twist! The solution is only a doorstep away!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP<br></li><li><strong>Processor:</strong> 1 GHZ or higher<br></li><li><strong>Memory:</strong> 256 MB RAM<br></li><li><strong>DirectX:</strong> Version 7.0<br></li><li><strong>Storage:</strong> 79 MB available space<br></li><li><strong>Sound Card:</strong> DirectSound compatible sound card</li></ul>\'}', '0,16', '0,41', '0,01', '0,06', '0,64'),
