(248, 'defiance', '2014', 18, 0, 9150, 2808, 953, 0.00, 'Join the futuristic online open-world shooter where thousands of players scour a transformed Earth competing for alien technology.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP SP2<br>\\t</li><li><strong>Processor:</strong> Intel Core 2 Duo 2.0 GHz CPU or better<br>\\t</li><li><strong>Memory:</strong> 2 GB System RAM<br>\\t</li><li><strong>Graphics:</strong> 512MB video card (NVIDIA GeForce 8600, ATI Radeon HD 2900, or Intel HD 4000 integrated graphics or better)<br>\\t</li><li><strong>DirectX®:</strong> 9.0c<br>\\t</li><li><strong>Hard Drive:</strong> 15 GB free hard drive space<br>\\t</li><li><strong>Sound:</strong> DirectX 8.1 compatible sound card<br>\\t</li><li><strong>Internet:</strong> Broadband internet connection</li></ul>\'}', '0,71', '0,3', '0', '0,11', '1,14'),
(249, 'spec ops the line', '2012', 18, 50, 32361, 2613, 293, 19.99, 'A Third-Person modern military Shooter designed to challenge players\' morality by putting them in the middle of unspeakable situations.', '{\'minimum\': \'<strong> Minimum</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP SP3<br> </li><li><strong>Processor:</strong> Intel Core 2 Duo @ 2Ghz / AMD Athlon 64 X2 equivalent<br> </li><li><strong>Memory:</strong> 2 GB RAM<br> </li><li><strong>Hard Disk Space:</strong> 6 GB free <br> </li><li><strong>Video Card:</strong> NVIDIA GeForce 8600 / ATI Radeon HD 2600XT (256 MB memory) <br> </li><li><strong>DirectX®:</strong> 9.0<br> </li><li><strong>Sound:</strong> DirectX Compatible<br></li><li><strong>Additional:</strong> Initial installation requires one-time internet connection for Steam authentication; software installations required (included with the game) include: STEAM Client, Microsoft Direct X, Visual C++ 2008 Redistributable, Visual C++ 2005 SP1 RedistributableCompatible <br> </li></ul>\', \'recommended\': \'<strong> Recommended</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista/7<br> </li><li><strong>Processor:</strong> 2.4 GHz Quad Core processor<br> </li><li><strong>Memory:</strong> 3 GB RAM<br> </li><li><strong>Hard Disk Space:</strong> 10 GB free <br> </li><li><strong>Video Card:</strong> NVIDIA GeForce 9800 GTX/ATI Radeon HD 4850 (512+ MB memory) <br> </li><li><strong>DirectX®:</strong> 9.0<br> </li><li><strong>Sound:</strong> DirectX Compatible <br></li><li><strong>Additional:</strong> Initial installation requires one-time internet connection for Steam authentication; software installations required (included with the game) include: STEAM Client, Microsoft Direct X, Visual C++ 2008 Redistributable, Visual C++ 2005 SP1 RedistributableCompatible </li></ul>\'}', '0,51', '0,53', '0,04', '0,16', '1,23'),
