(253, 'lego star wars the force awakens', '2016', 0, 69, 1828, 422, 1399, 24.99, 'The No. 1 LEGO® videogame franchise triumphantly returns with a fun-filled, humorous journey based on the blockbuster film. The game will also feature brand new story content from the Star Wars Universe that explores the time between Star Wars: Return of the Jedi and Star Wars: The Force Awakens.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP/Vista/7/8/10<br></li><li><strong>Processor:</strong> Intel Core 2 Quad Q6600 (2.4 GHz) / AMD Phenom x4 9850 (2.5 GHz)<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> GeForce GT 430 (1024 MB)/ Radeon HD 6850 (1024 MB)<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 14 GB available space<br></li><li><strong>Sound Card:</strong> DirectX compatible<br></li><li><strong>Additional Notes:</strong> Windows XP and DirectX® 9.0b and below not supported</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP/Vista/7/8/10<br></li><li><strong>Processor:</strong> Intel i5, 4 x 2.6 GHz or AMD equivalent<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 480 or ATI Radeon HD 5850 or better, 1Gb RAM<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 14 GB available space<br></li><li><strong>Sound Card:</strong> DirectX compatible<br></li><li><strong>Additional Notes:</strong> Windows XP and DirectX® 9.0b and below not supported</li></ul>\'}', '0,41', '0,68', '0', '0,16', '1,26'),
(254, 'legacy of kain defiance', '2012', 16, 0, 429, 61, 522, 4.99, 'Take control of two powerful and highly evolved vampires: Kain, an all-powerful demigod, and Raziel, a demonic angel of death. Each equipped with a legendary sword, Kain &amp; Raziel must battle through a world loaded with conflict and intrigue as they attempt to unravel their destinies and defeat the dark forces that seek to condemn...', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong>Windows XP/ Windows Vista / Windows 7<br>\\t</li><li><strong>Processor:</strong>1.8Ghz processor<br>\\t</li><li><strong>Memory:</strong>1 GB RAM<br>\\t</li><li><strong>Graphics:</strong>3D graphics compatible with DirectX 9<br>\\t</li><li><strong>DirectX®:</strong>9.0b<br>\\t</li><li><strong>Hard Drive:</strong>2 GB HD space</li></ul>\'}', '0,4', '0,25', '0', '0,08', '0,73'),
(255, 'winning post', '', 0, 0, 0, 0, 0, 0.00, '0', '0', '0', '0', '0,53', '0', '0,53'),
(256, 'fear 2 project origin', '2009', 0, 0, 3274, 509, 301, 9.99, 'Deployed just minutes before the blast triggered by the original F.E.A.R. team, you assume the role of Special Forces Sgt. Michael Becket as your routine mission quickly turns into a fight for survival against the wrath of Alma Wade.', '{\'minimum\': \'Minimum <br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>Operating System: </strong>Windows® XP SP2/Vista SP1 <br>\\t\\t\\t\\t\\t</li><li><strong>Processor: </strong> P4 2.8GHz (3.2GHz Vista)/Athlon® 64 3000+ (3200+ Vista) <br>\\t\\t\\t\\t\\t</li><li><strong>Memory: </strong>1GB (1.5GB Vista) <br>\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space: </strong>12GB Available Hard Disk Space <br>\\t\\t\\t\\t\\t</li><li><strong>Video Card: </strong>Fully DX9-compliant graphics card with 256MB (SM 2.0b). NVIDIA 6800 or ATI X700 <br>\\t\\t\\t\\t\\t</li><li><strong>DirectX® Version: </strong>9.0c <br>\\t\\t\\t\\t\\t</li><li><strong>Sound: </strong>DX9.0c compliant <br>\\t\\t\\t\\t\\t</li><li><strong>Internet Connection: </strong>Broadband </li></ul>\', \'recommended\': \'Recommended <br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>Operating System: </strong>Windows® XP SP3/Vista SP1 <br>\\t\\t\\t\\t\\t</li><li><strong>Processor: </strong> Core 2 Duo 2.2GHz processor family/Athlon 64 X2 4400+ (required for MP host) <br>\\t\\t\\t\\t\\t</li><li><strong>Memory: </strong>1.5GB <br>\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space: </strong>12GB Available Hard Disk Space <br>\\t\\t\\t\\t\\t</li><li><strong>Video Card: </strong>Fully DX9-compliant graphics card with 512MB (SM 3.0). NVidia® 8600 GTS or ATI® HD 2900 XT <br>\\t\\t\\t\\t\\t</li><li><strong>DirectX® Version: </strong>9.0c <br>\\t\\t\\t\\t\\t</li><li><strong>Sound: </strong>DX9.0c compliant <br>\\t\\t\\t\\t\\t</li><li><strong>Internet Connection: </strong>Broadband (768kbit/sec upstream required to host 16 players) </li></ul>\'}', '0,52', '0,41', '0,01', '0,14', '1,09'),
(257, 'way of the samurai 3', '2016', 0, 50, 206, 59, 815, 14.99, 'Honour, sacrifice, betrayal… Your choices make you who you are. How will history remember you? Choose your friends and enemies carefully in a game where every decision has far-reaching consequences, and where finishing the game is just the beginning of your...', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7<br></li><li><strong>Processor:</strong> 2.13GHz Intel Core2 Duo or equivalent<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> DirectX 9.0c compatible graphics card with 512Mb RAM and support for v3 shaders<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 2 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c compatible sound card</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 or later<br></li><li><strong>Processor:</strong> 3GHz Intel i3 or equivalent<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> DirectX 9.0c compatible graphics card with 1GB RAM and support for v3 shaders<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 2 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c compatible sound card</li></ul>\'}', '0,3', '0,13', '0,24', '0,06', '0,73'),
(258, 'dc universe online', '2011', 0, 169, 10138, 2654, 2990, 0.00, 'DC Universe Online is a Free-to-Play, massive multiplayer online action game set in the popular DC Comics universe. Become one of a new breed of Heroes or Villains and wield incredible powers as you go to war with legendary characters such as Batman, Superman, Lex Luthor and The Joker.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 or newer<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> P4 3.0GHz or AMD equivalent<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1GB RAM<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space:</strong> 30 GB of Free Hard Drive Space<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Video:</strong> NVIDIA 7800GTX+ or ATI 1950+ Video Card<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Audio:</strong> on Board<br> </li><li><strong>Network:</strong> Broadband Internet Connection required<br>\\t\\t\\t\\t\\t</li></ul>\'}', '0,51', '0,18', '0', '0,08', '0,76'),
(259, 'tomb raider legend', '2007', 16, 0, 1656, 243, 714, 4.99, 'Follow Lara Croft down a path of discovery as she travels the globe to remote, exotic locales in search of one of history\'s greatest artifacts, that unleashes unwelcome figures from Lara\'s mysterious past.', '{\'minimum\': \'<strong>Minimum: </strong>Microsoft Windows 2000, XP, Pentium 3 1.0Ghz or Athlon XP Equivalent, 256MB RAM, 100% DirectX 9.0c -compatible 64 MB 3D Accelerated Card with TnL (GeForce 3Ti / Radeon 9 series), Microsoft Windows 2000/XP compatible sound card (100% DirectX 9.0c -compatible), 9.9GB free disk space, 100% Windows 2000/XP compatible mouse and keyboard<br>\\t\\t\\t\\t\\t<strong>Recommended: </strong>Pentium 4 2.0Ghz or Athlon XP Equivalent, 512MB RAM, 100% DirectX 9.0c -compatible 256MB 3D Accelerated Card (Nvidia GeForce 5900 / Ati 9800XT), Microsoft Windows 2000/XP compatible sound card (100% DirectX 9.0c -compatible), 9.9GB free disk space<br>\\t\\t\\t\\t\\t<strong>Optimal: </strong>Pentium 4 3.0Ghz or Athlon XP/64bit Equivalent, 1GB RAM, 100% DirectX 9.0c -compatible 512 MB 3D Accelerated Card (Nvidia GeForce 7800 / Ati X-1800)\'}', '0,81', '0,59', '0,03', '0,22', '1,67'),
(260, 'lords of the fallen', '2014', 16, 56, 7393, 4963, 456, 23.79, 'The Demonic Rhogar army is re-emerging from its dark realm. Harkyn, a convicted criminal rejected by society is the world’s last hope for salvation. Plunge into a fast paced action RPG using powerful magic alongside a complex and satisfying melee combat system.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista (SP2), Windows 7 (SP1) or Windows 8 (only 64 bit OSs<br></li><li><strong>Processor:</strong> Intel Core 2 Quad Q8400 @ 2.66Ghz or AMD Phenom II X4 940 @ 3.0Ghz<br></li><li><strong>Memory:</strong> 6 GB RAM<br></li><li><strong>Graphics:</strong> GeForce GTX 460 or better<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 25 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c Compatible Sound Card with Latest Drivers</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista (SP2), Windows 7 (SP1) or Windows 8 (only 64 bit OSs<br></li><li><strong>Processor:</strong> Intel Core i7-3770 @3.5 GHz or AMD FX-8350 X8 @ 4 GHz<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> GeForce GTX 560 ti or better<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 25 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c Compatible Sound Card with Latest Drivers</li></ul>\'}', '0,27', '0,36', '0,02', '0,11', '0,76'),
(261, 'summoner', '2014', 0, 0, 225, 45, 0, 4.49, 'Summoners have toppled empires and challenged gods. They are venerated as saviours and feared as destroyers. With rings crafted by the ancient Khosani, the gifted can call forth demons, dragons, and elementals, but only the strongest can control the forces they unleash.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP / Vista / 7 / 8<br></li><li><strong>Processor:</strong> 1.8 GHz Processor<br></li><li><strong>Memory:</strong> 512 MB RAM<br></li><li><strong>Graphics:</strong> 3D graphics card compatible with DirectX 9.0c<br></li><li><strong>DirectX:</strong> Version 9.0<br></li><li><strong>Storage:</strong> 800 MB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c or better compatible sound card</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP / Vista / 7 / 8<br></li><li><strong>Processor:</strong> 1.8 GHz Processor<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> 3D graphics card compatible with DirectX 9.0c<br></li><li><strong>DirectX:</strong> Version 9.0<br></li><li><strong>Storage:</strong> 1 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c or better compatible sound card</li></ul>\'}', '0,25', '0,2', '0', '0,07', '0,51'),
(262, 'sega bass fishing', '2011', 0, 12, 325, 62, 6, 5.59, 'Explore the exciting sport of Bass fishing! Based on the Dreamcast hit, motor out to eight different fishing locations to catch the biggest and baddest Bass possible! Choose between fourteen different lures, and compete in four tournaments. Start off as an amateur, and work your way up to the pros in the Masters Classic tournament.', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® XP<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 3.0 GHz Intel Pentium 4<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2GB RAM<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> DirectX 9.0c compatible, NVIDIA GeForce 7300 series, ATI Radeon™ X1600 Video Card with 256MB RAM<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX 9.0c<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 410MB Hard Drive space<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX 9.0c compatible Sound Card<br>\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® 7<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 2.0 GHz Intel Core 2 Duo<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2GB RAM or more<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> DirectX 9.0c/Shader3.0 compatible, NVIDIA GeForce 8800 series or higher, ATI Radeon™ X1900 Video Card with 512MB RAM<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX 9.0c<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 4GB Hard Drive space<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX 9.0c compatible Sound Card<br>\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0,46', '0,01', '0,09', '0,04', '0,6'),
(263, 'quantum break', '2016', 0, 42, 10249, 1929, 331, 29.99, 'From Remedy Entertainment, the masters of cinematic action games, comes Quantum Break, a time-amplified suspenseful blockbuster. The Quantum Break experience is part game, part live action show—where decisions in one dramatically affect the other.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 - 64 bit<br></li><li><strong>Processor:</strong> Intel Core i5-4460, 2.70GHz or AMD FX-6300<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 760 or AMD Radeon R7 260x<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 68 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 10 - 64 bit<br></li><li><strong>Processor:</strong> Intel Core i5 4690, 3.9GHz or AMD equivalent<br></li><li><strong>Memory:</strong> 16 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 970 or AMD Radeon R9 390<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 68 GB available space</li></ul>\'}', '0,27', '0,19', '0,01', '0,04', '0,51'),
(264, 'euro truck simulator', '2013', 0, 0, 3772, 973, 315, 3.99, 'The original Euro Truck Simulator - the game which has become the classic of the genre and is still relevant today. The first truck simulation game in a European setting, with European long haul trucks! Drive freight from London to Rome to Berlin to Madrid to Prague - and many more cities - in realistic vehicles.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP<br>\\t</li><li><strong>Processor:</strong> 2.4 GHz<br>\\t</li><li><strong>Memory:</strong> 1 GB RAM<br>\\t</li><li><strong>Graphics:</strong> 256 MB<br>\\t</li><li><strong>DirectX®:</strong> 9.0c<br>\\t</li><li><strong>Hard Drive:</strong> 2 GB HD space<br>\\t</li><li><strong>Sound:</strong> Any DirectX compatible<br>\\t</li><li><strong>Additional:</strong> Gamepad or steering wheel recommended</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>Additional:</strong> Gamepad or steering wheel recommended</li></ul>\'}', '0', '0,42', '0', '0,09', '0,51'),
(265, 'hitman blood money', '2007', 18, 0, 5864, 391, 435, 9.29, 'Money Talks. Silence Pays. Prepare to Make a Killing. When assassins from Agent 47\'s contract agency, The ICA, are eliminated in a series of hits, it seems a larger, more powerful agency has entered the fray. Sensing he may be a target, 47 travels to America, and prepares to make a killing.', '{\'minimum\': \'<strong>Minimum: </strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li>Microsoft Windows® 2000/XP (Windows 95/98/ME/NT Not Supported)<br>\\t\\t\\t\\t\\t</li><li>Pentium 4 1.5Ghz or Athlon XP Equivalent<br>\\t\\t\\t\\t\\t</li><li>512MB RAM<br>\\t\\t\\t\\t\\t</li><li>100% DirectX 9.0c compatible video card which supports Hardware TnL and Pixel Shader 2.0 (GeForce FX / Radeon 9500 or higher)<br>\\t\\t\\t\\t\\t</li><li>100% DirectX 9.0c Compatible Sound Card<br>\\t\\t\\t\\t\\t</li><li>5.0GB free disk space<br>\\t\\t\\t\\t\\t</li><li>100% Windows 2000/XP compatible Mouse and Keyboard (Gamepads and controller are not supported)</li></ul><strong>Recommended: </strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li>Pentium 4 2.4Ghz or Athlon XP/64-bit equivalent <br>\\t\\t\\t\\t\\t</li><li>1024MB RAM<br>\\t\\t\\t\\t\\t</li><li>ATI X800 series, Nvidia GeForce 6800 series or higher video card<br>\\t\\t\\t\\t\\t</li><li>100% DirectX 9.0c Compatible Sound Card, Sound Blaster X-Fi series<br>\\t\\t\\t\\t\\t</li><li>5.0GB free disk space </li></ul>\'}', '0,65', '0,31', '0,01', '0,11', '1,08'),
(266, 'sonic lost world', '2015', 0, 100, 1000, 612, 11, 19.99, 'When the Deadly Six threaten to destroy his world, Sonic’s new moves &amp; power-ups are the only way to defeat them before it’s too late!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Microsoft Windows 7 / 8 / 10<br></li><li><strong>Processor:</strong> Intel Pentium Dual-Core T4200 (2x2.0GHz) or AMD equivalent<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce 8800 (512MB) / ATI Radeon HD 2900 (512MB)<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 8 GB available space<br></li><li><strong>Sound Card:</strong> Sound: 9.0c compatible.<br></li><li><strong>Additional Notes:</strong> Memory: 2GB RAM (XP)/3GB RAM (Windows 7 / Vista)</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Microsoft Windows 7<br></li><li><strong>Processor:</strong> Intel Core i5 @ 2.66 GHz / AMD Phenom II X4 @ 3.0 GHz<br></li><li><strong>Memory:</strong> 3 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 460 (1GB) / ATI Radeon HD 5850 (1GB)<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 8 GB available space<br></li><li><strong>Sound Card:</strong> Sound: 9.0c compatible.</li></ul>\'}', '0,48', '0,27', '0,08', '0,06', '0,89');
INSERT INTO `jeux` (`id_jeu`, `nom_jeu`, `annee`, `age_requis`, `nb_succes`, `nb_avis_pos`, `nb_avis_neg`, `temps_jeu_moyen`, `prix`, `description`, `configuration`, `ventes_AN`, `ventes_EU`, `ventes_JP`, `ventes_Autre`, `ventes_Global`) VALUES
(267, 'alone in the dark', '2013', 0, 0, 199, 304, 86, 6.99, 'The game that started the popular survival horror genre returns better than ever! Players control Edward Carnby, the main character from the original Alone in the Dark, on a thrilling journey through a dark and terrifying re-creation of New York\'s Central Park where Carnby must discover the truth behind a dark conspiracy.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® XP/Vista 32, 64 bit<br></li><li><strong>Processor:</strong> Intel Pentium® D 2.6 GHz, AMD Athlon™ X2 3800+<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce 7600, ATI Radeon X1650 XT<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 9 GB available space<br></li><li><strong>Additional Notes:</strong> An internet connection is needed at install, first launch and to revoke license.</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® XP/Vista 32, 64 bit<br></li><li><strong>Processor:</strong> Intel® Core™2 Duo 2.2 GHz<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce 8800 GTS, ATI Radeon HD3850<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 9 GB available space<br></li><li><strong>Additional Notes:</strong> An internet connection is needed at install, first launch and to revoke license.</li></ul>\'}', '0,26', '0,41', '0', '0,08', '0,74'),
(268, 'sniper art of victory', '2014', 16, 0, 324, 775, 7, 1.99, 'BECOME THE EYE WITNESS OF THE FALL OF THE THIRD REICHWW II was a theatre of war for many specialized combat units, working together to ensure an army’s victory. Among them a unique role was played by hidden and deadly marksmen.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP/Vista<br></li><li><strong>Processor:</strong> 1,6 GHz CPU<br></li><li><strong>Memory:</strong> 512 MB RAM<br></li><li><strong>Graphics:</strong> ATI Radeon 8500or GeForce3 class gfx card (or better recommended)<br></li><li><strong>DirectX:</strong> Version 9.0<br></li><li><strong>Storage:</strong> 2 GB available space<br></li><li><strong>Sound Card:</strong> 16-bit DirectX 9 compatible sound card</li></ul>\'}', '0', '0,45', '0', '0,03', '0,49'),
(269, 'f1 2014', '2014', 0, 49, 1113, 317, 1508, 19.99, 'Feel the power of new turbocharged FORMULA ONE™ cars in the most accessible FORMULA 1™ video game yet. Features all the cars, drivers and circuits from the 2014 FIA FORMULA ONE WORLD CHAMPIONSHIP™!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista, Windows 7 or Windows 8<br></li><li><strong>Processor:</strong> Intel Core 2 Duo @ 2.4Ghz or AMD Athlon X2 5400+<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> AMD HD2600 or NVIDIA Geforce 8600<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 10 GB available space<br></li><li><strong>Sound Card:</strong> DirectX Compatible soundcard<br></li><li><strong>Additional Notes:</strong> Supported Graphics Cards: •AMD Radeon HD2600 or higher, HD3650 or higher, HD4550 or higher, HD5000 Series, HD6000 Series, HD7000 Series, R7 Series and R9 Series. •nVidia GeForce 8600 or higher, 9500 or higher, GTX220 or higher, GTX400 Series, GTX500 Series, GTX600 Series, GTX700 Series. Intel HD Graphics 3000 or higher, AMD Fusion A8 or higher.</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista 64 bit, Windows 7 64 bit or Windows 8 64 bit<br></li><li><strong>Processor:</strong> Intel Core i7 or AMD FX Series<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> AMD HD6000 Series/Nvidia GTX500 Series minimum 1GB RAM<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 10 GB available space<br></li><li><strong>Sound Card:</strong> Direct X compatible soundcard</li></ul>\'}', '0,15', '0,55', '0,02', '0,11', '0,85'),
(270, 'dark sector', '2009', 0, 0, 337, 96, 0, 6.99, 'Dark Sector thrusts players into the role of Hayden Tenno, a covert operative sent on a dangerous mission into Lasria, an Eastern European city on the brink of ruin that hides a deadly Cold War secret. In the midst of this mission, Hayden is attacked by an unknown enemy and infected by the Technocyte Virus, a brutal bio-weapon that...', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>Operating System: </strong>Microsoft® Windows XP SP2 or Windows Vista 32bit <br>\\t\\t\\t\\t\\t</li><li><strong>Processor: </strong>Pentium® 4 2.4 GHz or similar Athlon® 64™<br>\\t\\t\\t\\t\\t</li><li><strong>Memory: </strong>XP 1 GB RAM<br>\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space: </strong>6.5 GB Available<br>\\t\\t\\t\\t\\t</li><li><strong>Video Card: </strong>DirectX 9.0 compatible, with shaders 3.0 support (nVidia GeForce 6600 or ATI X1300 or higher)<br>\\t\\t\\t\\t\\t</li><li><strong>Sound Card: </strong>DirectX 9.0c compatible sound card <br>\\t\\t\\t\\t\\t</li><li><strong>DirectX® Version: </strong>9.0c<br>\\t\\t\\t\\t\\t</li><li><strong>Controller support: </strong>XInput-controllers (Microsoft Xbox 360 Controller or Logitech Chillstream) </li></ul>\'}', '0,45', '0,36', '0,02', '0,12', '0,95'),
(271, 'dragon age origins awakening', '2010', 0, 0, 92, 7, 0, 9.99, 'From the Makers of the Best RPG of 2009, Dragon Age&trade;: Origins, comes the first official expansion pack. For centuries, the Grey Wardens—the ancient order of guardians, sworn to unite and defend the lands—have been battling the darkspawn forces.', '{\'minimum\': \'<p><strong>Minimum:</strong></p>\\n\\t\\t\\t\\t\\t\\t\\t\\t<ul>\\n\\t\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>OS:</strong> Windows XP (SP3) or Windows Vista (SP1) or Windows 7</li>\\n\\t\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>Processor:</strong> Intel Core 2 Single 1.6 Ghz Processor (or equivalent) or AMD 64 2.0 GHz Processor (or equivalent)</li>\\n\\t\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>Memory:</strong> 1GB (1.5 GB Vista and Windows 7)</li>\\n\\t\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>Graphics:</strong> ATI Radeon X850 256MB or NVIDIA GeForce 6600 GT 128MB or greater (Windows Vista: Radeon X1550 256 MB or NVidia GeForce 7600GT 256MB)</li>\\n\\t\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>DirectX&reg;:</strong> DirectX (November 2007)</li>\\n\\t\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>Hard Drive:</strong> 20 GB HD space</li>\\n\\t\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>Sound:</strong> Direct X Compatible Sound Card</li>\\n\\t\\t\\t\\t\\t\\t\\t\\t</ul>\', \'recommended\': \'<p><strong>Recommended:</strong></p>\\n\\t\\t\\t\\t\\t\\t\\t\\t<ul>\\n\\t\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>OS:</strong> Windows XP (SP3) or Windows Vista (SP1) or Windows 7</li>\\n\\t\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>Processor:</strong> Intel Core 2 Duo 2.4 Ghz or AMD Phenom II X2 Dual-Core 2.7 Ghz Processor or equivalent</li>\\n\\t\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>Memory:</strong> 2 GB (3GB Vista and Windows 7)</li>\\n\\t\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>Graphics:</strong> ATI 3850 512 MB or NVidia 8800GTS 512MB or greater</li>\\n\\t\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>DirectX&reg;:</strong> DirectX (November 2007)</li>\\n\\t\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>Hard Drive:</strong> 20 GB HD space</li>\\n\\t\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>Sound:</strong> Direct X Compatible Sound Card</li>\\n\\t\\t\\t\\t\\t\\t\\t\\t</ul>\'}', '0,58', '0,2', '0', '0,08', '0,87'),
(272, 'naruto shippuden ultimate ninja storm revolution', '2014', 0, 50, 4152, 995, 969, 19.99, 'THE REVOLUTIONARY STORM SERIES RETURNS! Live a new experience in the deep &amp; rich NARUTO environment. Tons of new techniques, enhanced mechanics, over 100 playable characters &amp; Support Ninjas, and a brand new exclusive character (Mecha-Naruto) designed by Masashi Kishimoto.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP or higher with latest Service Pack<br></li><li><strong>Processor:</strong> 2.3 GHz Dual Core or AMD<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> 512 MB video cards Pixel Shader 4.0 (Geforce 8xxx-ATI HD2xxx)<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 8 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 or higher with latest Service Pack<br></li><li><strong>Processor:</strong> Intel i3-530, 2.93Ghz / AMD Phenom II X4 940, 3.0GHz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> 1024 MB video card, Pixel Shader 4.0, DirectX10 GPU<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 8 GB available space</li></ul>\'}', '0,28', '0,24', '0,09', '0,1', '0,7'),
