(274, 'fear 3', '2011', 18, 50, 5349, 2030, 310, 12.99, 'F.E.A.R. 3 delivers all the hallmarks that define the F.E.A.R. brand: terrifying paranormal experience, frenetic combat and a dramatic storyline.', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Core 2 Duo 2.4Ghz, AMD Athlon X2 4800+<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Drive Space:</strong> 4.4GB\\t\\t\\t\\t\\t\\t<br>\\t\\t\\t\\t\\t\\t</li><li><strong>RAM:</strong> 2GB<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Video Card:</strong> NVIDIA 8800 GT 512MB RAM, ATI 3850HD 512Mb RAM or better<br>\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 9.0c<br>\\t\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br>\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Core 2 Duo 2.93Ghz+, Intel quad core 2.66Ghz+, AMD Phenom II X2 550, 3.1Ghz+<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Drive Space:</strong> 10.0GB\\t<br>\\t\\t\\t\\t\\t\\t</li><li><strong>RAM:</strong> 4GB<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Video Card:</strong> NVIDIA 9800 GTX+ 512MB RAM, ATI 5750HD 512Mb RAM or better<br>\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 11<br>\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0,55', '0,36', '0,02', '0,14', '1,06'),
(275, 'brothers in arms earned in blood', '2008', 0, 0, 303, 53, 164, 4.29, 'With its unprecedented combination of authenticity, compelling story and squad-based action, the Brothers in Arms franchise has established itself as a benchmark for military action games, receiving the highest average review scores of any console WWII game to date (www.gamerankings.com).', '{\'minimum\': \'<strong>Minimum:</strong> <br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 2000/XP (ONLY) <br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 1 GHz Pentium III or AMD Athlon (2.5 GHz Pentium IV or AMD recommended) <br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 512 MB (1 GB recommended) <br>\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 32 MB Direct X 9.0c compliant (64 MB recommended)* <br>\\t\\t\\t\\t\\t</li><li><strong>DirectX Version:</strong> DirectX 9.0c (included) <br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 3.5 GB hard drive space <br>\\t\\t\\t\\t\\t</li><li><strong>Sound Card:</strong>16 bit DirectX 9.0c compliant sound card (EAX recommended; PC audio solutions containing Dolby Digital Live required for Dolby Digital audio) <br>\\t\\t\\t\\t\\t</li><li><strong>Multiplayer: </strong>Broadband with 64 kbps upstream (128 kbps recommended) </li></ul>*Supported video cards at time of release: ATI Radeon 8500/9000/X series NVIDIA GeForce 4/FX/6 series (GeForce 4 MX not supported)<br> These chipsets are the only ones that will run this game. Laptop models of these cards not supported.\'}', '0,61', '0,08', '0', '0,07', '0,77'),
(276, 'sword art online lost song', '2018', 0, 43, 208, 60, 0, 15.99, 'Enter the VRMMO world of the much-loved anime SWORD ART ONLINE! In Alfheim Online, a world of fairies and magic, you become the hero of the series, Kirito, and together with your wondrous friends try to conquer the floating land of Svart Alfheim.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li>Requires a 64-bit processor and operating system<br></li><li><strong>OS:</strong> Windows 7, 8.1, 10 (64-bit)<br></li><li><strong>Processor:</strong> Intel Core i3-2100 / AMD A8-5600K<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> GeForce GTX 650 / Radeon HD 7770<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 7 GB available space<br></li><li><strong>Sound Card:</strong> DirectX compatible soundcard or onboard chipset</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li>Requires a 64-bit processor and operating system<br></li><li><strong>OS:</strong> Windows 7, 8.1, 10 (64-bit)<br></li><li><strong>Processor:</strong> Intel Core i5-4460 / Ryzen 3 2200G<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> GeForce GTX 670 / Radeon R9 280X<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 7 GB available space<br></li><li><strong>Sound Card:</strong> DirectX compatible soundcard or onboard chipset</li></ul>\'}', '0,17', '0,2', '0,33', '0,09', '0,79'),
(277, 'delta force black hawk down', '2009', 0, 0, 258, 23, 0, 0.00, 'In late 1993, the United States launched dual military operations in Mogadishu Somalia. Delta Force Operatives and Army Rangers were sent in to capture Somali warlords and restore order. Experience the intense combat of Operation Restore Hope in this ground breaking first person shooter.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 2000, XP &amp; Vista<br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Pentium III 733MHz or better<br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 256MB minimum<br>\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> Direct3D with 32MB or better<br>\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX version 8.1 or higher (included)<br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 860MB Free<br>\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX-compliant<br>\\t\\t\\t\\t\\t</li></ul>\'}', '0,47', '0,24', '0', '0,07', '0,8'),
(278, 'red faction armageddon', '2011', 18, 58, 2674, 1005, 307, 14.99, 'Red Faction: Armageddon Path to War includes 4 new missions, 2 unlockable items and 10 new achievements!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® XP<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 2GHz Dual Core Processor (Intel Core 2 Duo or AMD Athlon™ X2) or higher<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2GB System RAM or more<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 320MB Video RAM, GPU w/ Shader Model 3.0 support, NVIDIA® GeForce® 88xx series or better, ATI Radeon™ HD30xx series or better<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 9.0c<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 7.5 GB<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> 100% DirectX® 9.0C compliant sound card or equivalent onboard sound<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Microsoft® Windows® 7<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Any Quad Core Processor(Intel® Core i5 or AMD Phenom™ II X4) or 3.0+ Dual Core CPU<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 4GB System RAM or more<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 1GB Video RAM, GPU w/ Shader Model 4.0 support, NVIDIA® GeForce® GTX 400 series or better, ATI Radeon™ HD5000 series or better<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 11<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 7.5 GB<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> 100% DirectX® 9.0C compliant sound card or equivalent onboard sound<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0,43', '0,35', '0,04', '0,12', '0,94'),
