(280, 'thrillville off the rails', '2009', 0, 0, 272, 38, 17, 7.19, 'Thrillville™: Off the Rails lives up to its name with 20 death-defying rides! Players can build incredible coasters to leap from one track to another, launch through the air like cannonballs, blast through a burning rings of fire and more!', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 2000/XP/Vista<br>\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Pentium III 1.0 GHz or Athlon XP<br>\\t\\t\\t\\t</li><li><strong>Memory:</strong> 256 RAM<br>\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 64 MB 3D graphics with Vertex Shader and Pixel Shader capability<br>\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 9.0c<br>\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 3.9 GB<br>\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX 9.0c<br>\\t\\t\\t\\t</li></ul>\'}', '0,84', '0,21', '0', '0,1', '1,18'),
(281, 'one piece pirate warriors 3', '2015', 0, 40, 4456, 962, 311, 31.99, 'Enjoy the original story of ONE PIECE from Fuschia Village to the mysterious kingdom of Dressrosa. Will your resolution be strong enough to defeat the most dangerous pirates, including Doflamingo and many more?', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 / 8 / 8.1<br></li><li><strong>Processor:</strong> Core2Duo 2.4GHz<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> 512 MB Nvidia GeForce 8800 / ATI Radeon HD 3870<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 13 GB available space<br></li><li><strong>Sound Card:</strong> DirectX® 9.0c or higher<br></li><li><strong>Additional Notes:</strong> Game pad support</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 / 8 / 8.1<br></li><li><strong>Processor:</strong> Core i7 2600 3.4GHz minimum<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> 1.3 GB Nvidia GeForce GTX570 / 2.0 GB AMD Radeon HD 6950<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 13 GB available space<br></li><li><strong>Sound Card:</strong> DirectX® 9.0c or higher<br></li><li><strong>Additional Notes:</strong> Game pad support</li></ul>\'}', '0,08', '0,38', '0,42', '0,08', '0,96'),
(282, 'sphinx and the cursed mummy', '2017', 0, 34, 169, 15, 0, 13.99, 'Sphinx and The Cursed Mummy is an original 3rd person action-adventure inspired by the mythology of ancient Egypt. Travelling the world via magical portals to foil the evil plans of Set. Sphinx\'s Journey will require all his wits, agility, and special powers.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP / Vista / 7 / 8 / 10 32 or 64 bit<br></li><li><strong>Processor:</strong> Intel or AMD 1.5 GHz supporting SSE2 instructions<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> OpenGL 3.0 Core Profile compatible like GeForce 8600<br></li><li><strong>Storage:</strong> 1 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP / Vista / 7 / 8 / 10 32 or 64 bit<br></li><li><strong>Processor:</strong> Intel or AMD 2 GHz supporting SSE2 instructions<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> OpenGL 3.0 Core Profile compatible like GeForce 8800<br></li><li><strong>Storage:</strong> 2 GB available space<br></li><li><strong>Additional Notes:</strong> Having ARB_clip_control improves depth precision over large distances.</li></ul>\'}', '0,42', '0,22', '0', '0,06', '0,71'),
(283, 'viking battle for asgard', '2012', 18, 50, 856, 1013, 43, 9.99, 'A fierce struggle is taking place within Asgard, the realm of the Norse Gods.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong>Windows XP Service Pack 2, Windows Vista, Windows 7<br>\\t</li><li><strong>Processor:</strong>Intel Core 2 Duo 2.2 GHz or AMD Athlon™ 64 X2 3800 or better<br>\\t</li><li><strong>Memory:</strong>2 GB RAM<br>\\t</li><li><strong>Graphics:</strong>GeForce 8600 GS, Radeon 3400 or better<br>\\t</li><li><strong>DirectX®:</strong>9.0c<br>\\t</li><li><strong>Hard Drive:</strong>6 GB HD space<br>\\t</li><li><strong>Sound:</strong>Direct X 9.0c compatible sound card and drivers<br>\\t</li><li><strong>Additional:</strong>Keyboard, mouse, optional controller</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong>Windows XP Service Pack 2, Windows Vista, Windows 7<br>\\t</li><li><strong>Processor:</strong>Intel Core 2 Duo 2.6 GHz or AMD Athlon 64 X2 4400 or better<br>\\t</li><li><strong>Memory:</strong>4 GB RAM<br>\\t</li><li><strong>Graphics:</strong>GeForce 9400 GT, Radeon 4350 or better<br>\\t</li><li><strong>DirectX®:</strong>9.0c<br>\\t</li><li><strong>Hard Drive:</strong>6 GB HD space<br>\\t</li><li><strong>Sound:</strong>Direct X 9.0c compatible sound card and drivers<br>\\t</li><li><strong>Additional:</strong>Keyboard, mouse, optional controller</li></ul>\'}', '0,3', '0,42', '0', '0,12', '0,84'),
(284, 'silent hill homecoming', '2009', 0, 0, 480, 437, 58, 17.99, 'In Silent Hill Homecoming, Alex Shepherd has returned to his hometown of Shepherd\'s Glen to investigate the sudden disappearance of his brother. From Shepherd\'s Glen to the foggy streets of Silent Hill, Alex will face the darkest of horrors while struggling with his own grip on reality.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP / Vista <br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Dual core CPU such as Intel Core 2 Duo E6400 or AMD Athlon 64 X2 4200+ <br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1 GB (XP) or 2 GB (Vista) <br>\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> DirectX 9.0c compliant video card such as ATI Radeon HD-series graphics card (minimum 256 MB) or NVIDIA GeForce 7800-series graphics card (minimum 256 MB) <br>\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong>DirectX®: 9.0c compatible sound card <br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 10 GB Free space <br>\\t\\t\\t\\t\\t</li><li><strong>Controller Support:</strong>Mouse, Keyboard, Xbox 360 controller </li></ul>\'}', '0,43', '0,31', '0', '0,1', '0,85'),
(285, 'petz horsez 2', '2009', 0, 0, 76, 38, 0, 4.29, 'Saddle up for fun in a game that combines your passion for horses with thrills and adventure! You\'ll be rewarded for raising horses, training champions, and saving the ranch in Petz horsez 2. Raise horses from birth and learn to feed, clean, and take care of them Earn money to buy new horses and accessories by entering challenging...', '{\'minimum\': \'<ul>\\n\\t\\t\\t\\t\\t<li><strong>Supported OS: </strong>Windows&reg; Vista / XP (only)</li>\\n\\t\\t\\t\\t\\t<li><strong>Processor: </strong>1.0 GHz Intel Pentium 4 or AMD Athlon (2.0 GHz Pentium 4 or AMD Athlon recommended)</li>\\n\\t\\t\\t\\t\\t<li><strong>Memory: </strong>512 MB (1 GB recommended for XP and required for Vista)</li>\\n\\t\\t\\t\\t\\t<li><strong>Graphics: </strong>64 MB DirectX 9.0c-compliant video card (128 MB video card recommended) (see supported list*)</li>\\n\\t\\t\\t\\t\\t<li><strong>DirectX Version: </strong>DirectX 9.0</li>\\n\\t\\t\\t\\t\\t<li><strong>Sound: </strong>Direct X 9.0c compliant sound card</li>\\n\\t\\t\\t\\t\\t<li><strong>Hard Drive: </strong>6 GB</li>\\n\\t\\t\\t\\t\\t<li><strong>Peripherals: </strong>Windows keyboard and mouse only</li>\\n\\t\\t\\t\\t\\t<li>*Video cards supported at time of release: Nvidia&#174; GeForce&#153; 4/FX/6/7/8 series (GeForce 4 MX NOT supported) ATI&#174; Radeon&#174; 8000/9000/X600-X1900/HD 2400-2900 series</li></ul>\'}', '0,93', '0,1', '0', '0,09', '1,13'),
(286, 'alpha protocol', '2010', 16, 0, 3113, 785, 267, 9.99, 'Loyalty carries a price and no one knows this more than agent Michael Thorton. A talented young agent cast out by his government, Thorton is the only one with the information needed to stop an impending international catastrophe. To do so means he must cut himself off from the very people he is sworn to protect.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>Supported OS:</strong> Microsoft Windows XP® or Windows Vista® <br>\\t\\t\\t</li><li><strong>Processor:</strong> 2.4+ GHZ Intel® or 2.0+ GHZ AMD™ <br>\\t\\t\\t</li><li><strong>Memory:</strong> 1 GB RAM (Windows XP®,) 2 GB RAM (Windows Vista®) <br>\\t\\t\\t</li><li><strong>Graphics:</strong> NVIDIA® GeForce 6 series (6800GT or better,) ATI™ 1300XT series or greater (X1550, X1600 Pro and HD2400 are below minimum system requirements) <br>\\t\\t\\t</li><li><strong>Hard Drive:</strong> At least 12 GB of free space <br>\\t\\t\\t</li><li><strong>Sound Card:</strong> DirectX® 9.0c compatible sound card and drivers <br>\\t\\t\\t</li><li><strong>DirectX®:</strong> 9.0c <br>\\t\\t</li></ul>\'}', '0,42', '0,34', '0', '0,12', '0,87'),
(287, 'trials fusion', '2014', 0, 0, 1141, 615, 418, 16.99, 'Trials Fusion is the gold-standard platform racer for the next-generation of gaming. Built upon the Trials franchise’s proven gameplay foundations, Fusion challenges players endlessly in both classic and all-new ways.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista SP2, Windows 7 SP1, Windows 8 or Windows 8.1<br></li><li><strong>Processor:</strong> Intel Core i3 550 @ 3.2 GHz or AMD Athlon II X4 620 @ 2.6 GHz<br></li><li><strong>Memory:</strong> 3 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTS450 or AMD Radeon HD5770 (1024MB VRAM with Shader Model 5.0 or higher)<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 8 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 10.1 Compatible Sound Card<br></li><li><strong>Additional Notes:</strong> DirectX 10.1 or higher required</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista SP2, Windows 7 SP1, Windows 8 or Windows 8.1<br></li><li><strong>Processor:</strong> Intel Core i5 2400s @ 2.5 GHz or AMD Phenom II X4 955 @ 3.2 GHz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 560 Ti or better / AMD Radeon HD7850 or better<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 8 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 10.1 Compatible Sound Card<br></li><li><strong>Additional Notes:</strong> DirectX 10.1 or higher required</li></ul>\'}', '0,25', '0,34', '0,01', '0,1', '0,7'),
(288, 'nights into dreams', '2012', 0, 13, 553, 79, 9, 5.59, 'Slip off into the dream world and go on an aerial adventure as NiGHTS in this classic Saturn remake. Collect Ideya (colored orbs), rack up points, and battle bosses to help Elliot and Claris save Nightopia from Wizeman the Wicked.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong>Windows XP SP3/Vista/Win7/Win 8<br>\\t</li><li><strong>Processor:</strong>Pentium 4 @ 3.2 GHz/Athlon 64 3000+ or Equivalent &amp; above<br>\\t</li><li><strong>Memory:</strong>1 GB RAM<br>\\t</li><li><strong>Graphics:</strong>256 MB (NVIDIA GeForce 8600/AT Radeon HD3650) &amp; above<br>\\t</li><li><strong>DirectX®:</strong>9.0c<br>\\t</li><li><strong>Hard Drive:</strong>4 GB HD space<br>\\t</li><li><strong>Sound:</strong>DirectX Compatible<br>\\t</li><li><strong>Additional:</strong>2GB Memory required on Vista</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong>Windows 7/Windows 8<br>\\t</li><li><strong>Processor:</strong>Intel Core 2 DUO @ 2.4 GHz/Athlon 64 X2 4200+ &amp; above<br>\\t</li><li><strong>Memory:</strong>2 GB RAM<br>\\t</li><li><strong>Graphics:</strong>512 MB (NVIDIA GeForce GTS250/ATI Radeon HD 4850) &amp; above<br>\\t</li><li><strong>DirectX®:</strong>11<br>\\t</li><li><strong>Hard Drive:</strong>4 GB HD space<br>\\t</li><li><strong>Sound:</strong>DirectX Compatible<br>\\t</li><li><strong>Additional:</strong>2GB Memory required on Vista</li></ul>\'}', '0', '0', '0,44', '0', '0,44'),
(289, 'command & conquer 3 tiberium wars', '2009', 0, 0, 2292, 295, 646, 9.99, 'The year is 2047. A massive nuclear fireball explodes high in the night sky, marking the dramatic beginning of the Third Tiberium War and the long-awaited return of the most groundbreaking Real-Time Strategy franchise of all time.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP/Vista<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 2GHz AMD Athlon™ processor or equivalent<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 512MB RAM <br>\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> ATI Radeon 8500 or Nvidia GeForce 4 or higher video card<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 8GB<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX 9.0c-compatible sound card<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Other Requirements:</strong> Internet service required to access online features, Broadband modem required for 3 to 8 players and voice support<br>\\t\\t\\t\\t\\t\\t</li><li>INTERNET CONNECTION, ONLINE AUTHENTICATION AND ACCEPTANCE OF END USER LICENSE AGREEMENT REQUIRED TO PLAY. TO ACCESS ONLINE FEATURES, YOU MUST REGISTER ONLINE. ONLY ONE REGISTRATION IS AVAILABLE PER GAME. EA ONLINE TERMS &amp; CONDITIONS AND FEATURE UPDATES CAN BE FOUND AT <a href=\"https://steamcommunity.com/linkfilter/?url=http://WWW.EA.COM\" target=\"_blank\" rel=\"noopener\" >WWW.EA.COM</a>. YOU MUST BE 13+ TO REGISTER WITH EA ONLINE. EA MAY RETIRE ONLINE FEATURES AFTER 30 DAYS NOTICE POSTED ON <a href=\"https://steamcommunity.com/linkfilter/?url=http://WWW.EA.COM\" target=\"_blank\" rel=\"noopener\" >WWW.EA.COM</a>.<br>\\t\\t\\t\\t\\t</li></ul>\'}', '0,35', '0,11', '0', '0,04', '0,5'),
(290, 'wolfenstein the old blood', '2015', 18, 50, 6627, 862, 245, 14.99, 'Wolfenstein®: The Old Blood™ is a standalone prequel to the critically acclaimed first-person action-adventure shooter, Wolfenstein®: The New Order. This adventure spans eight chapters and features the hallmarks of MachineGames – thrilling action, immersive story, and intense FPS combat.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> 64-bit Windows 7/Windows 8<br></li><li><strong>Processor:</strong> Intel® Core™ i5-2500 @ 3.3 GHz / AMD FX-8320 @ 3.5 GHz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA® GeForce® GTX 560 / AMD Radeon™ HD 6870 (1GB VRAM)<br></li><li><strong>Storage:</strong> 38 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> 64-Bit Windows 7/Windows 8<br></li><li><strong>Processor:</strong> Intel® Core™ i7 / AMD FX-8350<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA® GeForce® GTX 660 / AMD Radeon™ R9 280 (3GB or more VRAM)<br></li><li><strong>Storage:</strong> 38 GB available space</li></ul>\'}', '0,16', '0,4', '0,02', '0,07', '0,65'),
(291, 'condemned criminal origins', '2012', 18, 0, 1243, 221, 312, 9.99, 'What twists the mind of an ordinary human into a serial killer? Assigned to the Serial Crimes Unit, Agent Ethan Thomas must answer this question, and bring the worst of society to justice. His solve rate is the best in the bureau....perhaps too good.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong>Windows XP<br>\\t</li><li><strong>Processor:</strong>2.0 GHz Intel Pentium 4 or AMD Athlon equivalent (2.4 GHz recommended) <br>\\t</li><li><strong>Memory:</strong>512 MB RAM<br>\\t</li><li><strong>Graphics:</strong>DirectX 9.0 compatible video card with at least 128 MB video RAM<br>\\t</li><li><strong>DirectX®:</strong>9.0<br>\\t</li><li><strong>Hard Drive:</strong>8 GB HD space<br>\\t</li><li><strong>Sound:</strong>DirectX 9.0 compatible sound card<br>\\t</li><li><strong>Additional:</strong>No controller support. </li></ul>\'}', '0,36', '0,03', '0', '0,03', '0,42'),
(292, 'bloodrayne', '2006', 0, 0, 369, 110, 111, 6.99, 'In the years between the World Wars, Agent BloodRayne works as a killing machine for The Brimstone Society--a top secret fraternity that hunts down and destroys supernatural threats. Starring heroine Rayne, this original action horror game unleashed the red headed dhampir on the world.', '{\'minimum\': \'<strong>Minimum:</strong> Windows 98/2000/XP, 733 MHz processor, 128MB RAM, 200MB virtual memory, 2 GB free hard disc space, DirectX 8.1 or higher (included with game), DirectX compatible sound card, 100% DirectX 8.1 compatible video card, ATI Radeon, GeForce 2 or higher, with Hardware T&amp;L (Transform &amp; Lighting). Excludes GeForce MX and Go series cards. See full list below.<br>\\t\\t\\t\\t\\tExcluded cards:<br>- TnT/TnT 2<br>- ATI Rage (any kind) <br>- ATI Radeon VE and Radeon 7000 <br>- ATI Mobility Radeon (original, laptop) <br>- Kyro 1 &amp; 2 (example, Hercules 3D Prophet 4000/4500) <br>- any Voodoo card <br>- any Intel card <br>- any Matrox card (except the Parhelia) <br>- any kind of integrated graphics (except the nForce) <br><br>\\t\\t\\t\\t\\t<strong>Recommended:</strong> Windows XP, Pentium 4 2.53 GHz or AMD equivalent, 512 MB RAM, 200MB virtual memory, 2 GB free hard disc space, 64MB nVidia GeForce 3, GeForce 4 Ti or ATI Radeon 8500 video card, DirectX 8.1 or higher (included with game), Sound Blaster Audigy sound card\'}', '0,45', '0,23', '0', '0,06', '0,74'),
(293, 'timeshift', '2009', 0, 0, 623, 159, 0, 9.99, 'Master time to become the ultimate weapon! Dr. Aiden Krone has made a Time Jump across the space-time continuum - a reckless act with frightening consequences. Now, a disturbing alternate reality has evolved within the bleak and rain-soaked Alpha District.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows(R) XP with latest service pack installed or Windows Vista™<br>\\t</li><li><strong>Processor:</strong> Intel(R) Pentium(R) 4 2.0 GHz or AMD(R) equivalent <br>\\t</li><li><strong>Memory:</strong> 1 GB RAM<br>\\t</li><li><strong>Graphics:</strong> NVIDIA(R) GeForce(R) 6600 128 MB DirectX(R) 9.0c-compatible card with Pixel Shaders 2.0b support or equivalent (ATI(R) Radeon(R) x700) with latest DirectX drivers<br>\\t</li><li><strong>DirectX:</strong> DirectX(R) 9.0c<br>\\t</li><li><strong>Hard Drive:</strong> 8 GB free hard drive space<br>\\t</li><li><strong>Sound:</strong> DirectX 9.0c-compatible sound card<br>\\t</li><li><strong>Note:</strong> TimeShift only supports multiplayer connectivity over LAN or direct connection</li></ul>\'}', '0,51', '0,03', '0', '0,04', '0,58'),
(294, 'danganronpa trigger happy havoc', '2016', 0, 38, 5714, 167, 1636, 14.99, 'Investigate murders, search for clues and talk to your classmates to prepare for trial. There, you\'ll engage in deadly wordplay, going back and forth with suspects. Dissect their statements and fire their words back at them to expose their lies! There\'s only one way to survive—pull the trigger.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7<br></li><li><strong>Processor:</strong> 2.8 GHz Intel Core 2 Duo or better<br></li><li><strong>Memory:</strong> 3 GB RAM<br></li><li><strong>Graphics:</strong> OpenGL 3.2 or DirectX 9.0c compatible GPU with at least 1GB of VRAM<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 5 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7<br></li><li><strong>Processor:</strong> Intel(R) Core(TM) i5-3470 or better<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> OpenGL 3.2 or DirectX 9.0c compatible GPU with at least 1GB of VRAM<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 6 GB available space</li></ul>\'}', '0,14', '0,07', '0,39', '0,06', '0,65'),
(295, 'quake ii', '2007', 0, 0, 1369, 107, 291, 3.99, 'Shortly after landing on an alien surface, you learn that hundreds of your men have been reduced to just a few. Now you must fight your way through heavily fortified military installations, lower the city\'s defenses and shut down the enemy\'s war machine. Only then will the fate of humanity be known.', '{\'minimum\': \'<strong>Minimum: </strong>A 100% Windows XP/Vista-compatible computer system\'}', '0,47', '0,22', '0', '0,03', '0,71'),
(296, 'tom clancys rainbow six lockdown', '2009', 0, 0, 80, 79, 20, 4.29, 'Engineered specifically for the PC by Red Storm Entertainment, Rainbow Six returns to deliver the tensest close-quarters battles ever experienced online. In this episode, Rainbow faces independent terrorist threats, tied together by one common element - the Legion virus.', '{\'minimum\': \'<p><strong>Minimum: </strong></p>\\n\\t\\t\\t\\t\\t<ul>\\n\\t\\t\\t\\t\\t<li><strong>Supported OS: </strong>Microsoft Windows&reg; 2000/XP</li>\\n\\t\\t\\t\\t\\t<li><strong>Processor: </strong>1.5 GHz Pentium&reg; IV or AMD Athlon&trade; equivalents or better</li>\\n\\t\\t\\t\\t\\t<li><strong>System Memory: </strong>512 MB (1 GB recommended) </li>\\n\\t\\t\\t\\t\\t<li><strong>Video Card: </strong>64 MB AGP or PCI DirectX&reg; 9.0c-compliant video card supporting pixel shaders and vertex shaders (see supported list*)</li>\\n\\t\\t\\t\\t\\t<li><strong>Display: </strong>monitor capable of 1024x768 resolution at 60 Hz</li>\\n\\t\\t\\t\\t\\t<li><strong>Sound Card: </strong>DirectX 9.0 compliant (EAX recommended; PC audio solution containing Dolby&reg; Digital Live required for Dolby Digital audio)</li>\\n\\t\\t\\t\\t\\t<li><strong>DirectX Version: </strong>DirectX&reg; version 9.0 or higher</li>\\n\\t\\t\\t\\t\\t<li><strong>Hard Disk: </strong>7 GB available hard disk space</li>\\n\\t\\t\\t\\t\\t<li><strong>Supported Peripherals: </strong>keyboard and mouse, microphone (for voice commands), Logitech G15 keyboard</li>\\n\\t\\t\\t\\t\\t<li><strong>Multiplay: </strong>Broadband with 64 kbps upstream (128 kbps recommended)</li>\\n\\t\\t\\t\\t\\t<li><strong>Supported video cards at time of retail release:</strong> ATI&reg; RADEON&reg; 8500/9000/X families, NVIDIA&reg; GeForce&trade; 3/4/FX/6/7 families (GeForce 4 MX cards are NOT supported. Laptop models of these cards may work but are not considered supported. These chipsets are the only ones that will run this game. Additional chipsets may be supported after release. For an up-to-date list of supported chipsets, video cards, and operating systems, please visit the FAQ for this game at: http://support.ubi.com.</li></ul>\'}', '0,47', '0,27', '0', '0,06', '0,81'),
(297, 'overlord', '2009', 0, 0, 3439, 276, 304, 3.49, 'Prepare to be tempted, mesmerized and thrilled, become the Overlord, how corrupt you become depends on how you handle any given situation. Your actions impact the game world. With incredible power at your disposal and a team of evil minded minions to do your evil bidding, how will you resist the temptation to be incredibly despotic?', '{\'minimum\': \'<strong>MINIMUM</strong><br><ul class=\"bb_ul\"><li><strong>Supported OS: </strong>Microsoft(R) Windows(R) XP<br></li><li><strong>Processor: </strong>Pentium 4 2.4 GHz or Athlon XP 2400+<br></li><li><strong>RAM: </strong>512MB RAM<br></li><li><strong>Hard Drive: </strong>4.5 GB available<br></li><li><strong>Video: </strong>GeForce FX5900 / Radeon 9500 or above <br></li><li><strong>DirectX Version: </strong>DirectX 9c<br></li><li><strong>Sound: </strong>DirectX compatible sound card</li></ul><br>Multiplayer is no longer available<br><br><strong>SUPPORTED GRAPHICS CARDS</strong><br><ul class=\"bb_ul\"><li><strong>ATi Radeon: </strong>9500, 9600, 9700, 9800, X300, X600, X700, X800, X1300, X1600, X1800, X1900, X1950<br></li><li><strong>nVidia: </strong>GeForce FX5900, FX5950, 6600, 6800, 7100, 7300, 7600, 7800, 7900, 7950, 8800</li></ul><br>Not compatible with all integrated sound/graphics solutions (inc. Laptops)\', \'recommended\': \'<strong>RECOMMENDED</strong><br><ul class=\"bb_ul\"><li><strong>Supported OS: </strong>Microsoft® Windows® XP/Vista<br></li><li><strong>Processor: </strong>Intel Core 2 Duo or Athlon 64 X2<br></li><li><strong>RAM: </strong>1GB RAM<br></li><li><strong>Video: </strong>GeForce 7800 or Radeon X1800</li></ul>\'}', '0,34', '0,05', '0,01', '0,03', '0,42'),
(298, 'sherlock holmes the mystery of the mummy', '2009', 0, 0, 59, 130, 0, 0.00, 'Inspired by The adventures of Sherlock Holmes Written by Sir Arthur Conan Doyle. After Lord Montcalfe\'s death, his daughter Elisabeth turns to the famous detective Sherlock Holmes to solve the mystery that surrounds her father\'s death.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 98 / ME / 2000 / XP <br>\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> CPU PII 350 Mhz<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 64 MB<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 8 Mb DirectX 7 compatible <br>\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 130 MB Free <br>\\t\\t\\t\\t\\t</li></ul>\'}', '0,06', '0,3', '0', '0,04', '0,4'),
(299, 'grid 2', '2013', 0, 60, 11953, 3009, 340, 19.98, 'Be fast, be first and be famous as the race returns in GRID 2, the sequel to the BAFTA-award winning, multi-million selling Race Driver: GRID.', '{\'minimum\': \'<strong> Minimum</strong> <br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista, Windows 7, Windows 8<br> </li><li><strong>Processor:</strong> Intel Core 2 Duo @ 2.4Ghz or AMD Athlon X2 5400+<br> </li><li><strong>Memory:</strong> 2 GB RAM<br> </li><li><strong>Hard Disk Space:</strong> 15 GB HD space <br> </li><li><strong>Video Card:</strong> Intel HD Graphics 3000 / AMD HD2600 / NVIDIA Geforce 8600<br> </li><li><strong>DirectX®:</strong> 11<br> </li><li><strong>Sound:</strong> Direct X compatible soundcard<br> </li><li><strong>Additional:</strong> Broadband Internet connection <br> </li><li><strong>Additional Supported Graphics Cards:</strong> Intel HD Graphics 3000, Intel HD Graphics 4000, Intel Graphics 5200.<br>AMD Radeon HD2600 or higher, HD3650 or higher, HD4550 or higher, HD5000 Series, HD6000 Series, HD7000 Series.<br>NVIDIA GeForce 8600 or higher, 9500 or higher, GTX220 or higher, GTX400 Series, GTX500 Series, GTX600 Series: AMD Fusion A8 or higher.<br> </li></ul>\', \'recommended\': \'<strong> Recommended</strong> <br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista 64 Bit, Windows 7 64 Bit, Windows 8 64 bit<br> </li><li><strong>Processor:</strong> Intel Core i7/AMD Bulldozer<br> </li><li><strong>Memory:</strong> 4 GB RAM<br> </li><li><strong>Hard Disk Space:</strong> 15 GB HD space <br> </li><li><strong>Video Card:</strong> Intel Graphics 5200 / AMD HD6000 Series / Nvidia GTX500 Series minimum 1GB RAM<br> </li><li><strong>DirectX®:</strong> 11<br> </li><li><strong>Sound:</strong> Direct X compatible soundcard<br> </li><li><strong>Additional:</strong> Broadband Internet connection </li></ul>\'}', '0,15', '0,46', '0,01', '0,13', '0,75'),
(300, 'the darkness ii', '2012', 18, 50, 11992, 1234, 191, 19.99, 'An intense first person shooter that delivers a twisted and gripping narrative of tragedy, modern crime drama, and supernatural horror.', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP/Vista/7<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Core 2 @ 2GHz / AMD Athlon 64 X2 4200+<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1.5GB RAM <br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space:</strong> 10GB<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Video Card:</strong> 256MB NVIDIA GeForce 8600 / ATI Radeon HD 2600<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX Compatible<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Additional:</strong> Requires installation of Visual C++ 2008 Redistributable, DirectX and nVidia PhysX version 9.11.1107 (included with download)<br>\\t\\t\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br>\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP/Vista/7<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 2.4 GHz Quad Core processor<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2GB RAM <br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space:</strong> 10GB<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Video Card:</strong> 512+ MB NVIDIA GeForce 9800 GTX <br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX Compatible<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Additional:</strong> Requires installation of Visual C++ 2008 Redistributable, DirectX and nVidia PhysX version 9.11.1107 (included with download)<br>\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0,48', '0,29', '0', '0,09', '0,86'),
(301, 'god eater 2 rage burst', '2016', 0, 47, 2576, 738, 942, 39.99, 'Swear your oath as a GOD EATER and drive back the supernatural harbingers of Earth’s destruction. Buy GOD EATER 2 Rage Burst and get GOD EATER Resurrection FOR...', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7<br></li><li><strong>Processor:</strong> Intel Core 2 Duo E7500 2.93 GHz / AMD Athlon 64 X2 Dual Core Processor 5600+ 2.9GHz<br></li><li><strong>Memory:</strong> 3 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce 9800 GT 1GB / AMD Radeon HD 6670<br></li><li><strong>DirectX:</strong> Version 9.0<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 15 GB available space<br></li><li><strong>Sound Card:</strong> DirectX compatible or onboard chipset</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7, 8, 10<br></li><li><strong>Processor:</strong> Intel Core i3 4130 3.4 GHZ / AMD FX-4100 Quad-Core Processor 3.6GHz<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> GEFORCE GTX560 1GB / AMD Radeon HD 6850 1 GB<br></li><li><strong>DirectX:</strong> Version 9.0<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 15 GB available space<br></li><li><strong>Sound Card:</strong> DirectX compatible or onboard chipset</li></ul>\'}', '0', '0,02', '0,46', '0', '0,48'),
(302, 'flatout', '2007', 0, 0, 1977, 186, 78, 4.99, 'FlatOut is adrenaline-filled muscle car racing game packed with explosive physics, spectacular effects and graphics, innovative game play mechanics and good old fun! Eight players or AI cars on track for close pack racing Single player Career, Quick race and Time trial modes Multiplayer mayhem with up to 8 players 16 different fully...', '{\'minimum\': \'<strong>Minimum: </strong>1.5 GHz Pentium 4 or AMD Equivalent, 256 MB RAM, 64 MB Graphics Card,DirectX Compatible Sound Card, 1.1 GB of free Hard Drive Space, Win 98/ME/2000/XP, DirectX9.0c<br>\\t\\t\\t\\t\\t<strong>Recommended: </strong>2.0 GHz Pentium 4 or AMD 2000+, 512 MB RAM, 128 MB GraphicsCard, DirectX Compatible Sound Card, Gamepad or Steering Wheel, Windows XP SP2\'}', '0,31', '0,19', '0', '0,06', '0,55');
INSERT INTO `jeux` (`id_jeu`, `nom_jeu`, `annee`, `age_requis`, `nb_succes`, `nb_avis_pos`, `nb_avis_neg`, `temps_jeu_moyen`, `prix`, `description`, `configuration`, `ventes_AN`, `ventes_EU`, `ventes_JP`, `ventes_Autre`, `ventes_Global`) VALUES
(303, 'mini ninjas', '2009', 0, 0, 1612, 270, 27, 7.99, 'Mini Ninjas is a game that combines furious action with stealth and exploration for an experience that appeals to a wide audience across age groups and preferences. It’s an action-adventure with a strong focus on allowing the player freedom to explore the world and has the depth to allow for very varied gameplay and approaches to getting...', '{\'minimum\': \'<strong>Minimum:</strong><br> <ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP and Vista<br>\\t </li><li><strong>Processor:</strong> PIV/Athlon 3.2ghz or higher processor<br>\\t </li><li><strong>Memory:</strong> 512MB system RAM (1GB Vista)<br>\\t </li><li><strong>Graphics:</strong> ATI Radeon X1300 or higher / Nvidia Geforce 6600 or higher (shader model 3 required) graphics card<br>\\t </li><li><strong>Hard Drive:</strong> 5.85GB free space<br>\\t </li><li><strong>Sound:</strong> DirectX 9 compatible sound card<br> </li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br> <ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP and Vista<br>\\t </li><li><strong>Processor:</strong> Intel/Athlon Dual Core Processor<br>\\t </li><li><strong>Memory:</strong> 1024MB system RAM (2GB Vista)<br>\\t </li><li><strong>Graphics:</strong> ATI Radeon X1300 or higher / Nvidia Geforce 6600 or higher with 512MB video RAM (shader model 3 required)<br>\\t </li><li><strong>Hard Drive:</strong> 5.85GB free space<br>\\t </li><li><strong>Sound:</strong> DirectX 9 compatible sound card<br> </li></ul>\'}', '0,6', '0,64', '0', '0,17', '1,38'),
(304, 'bionic commando', '2009', 0, 0, 649, 247, 20, 6.49, 'The first true sequel to the classic 1988 Nintendo Entertainment System original, Bionic Commando sees the return of the bionically-enhanced Nathan &quot;R.A.D.&quot; Spencer. Time has not been kind to Spencer: Five years after his heroic defeat of the Imperials, he has been betrayed by the government he swore to serve, imprisoned for...', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>Supported OS: </strong>Windows® XP Service Pack 2 or Windows Vista® (service pack is optional) <br>\\t\\t\\t\\t\\t\\t</li><li><strong>Processor: </strong>Dual-core processor (Intel® Core™2 Duo 2.4 GHz or AMD Athlon™ X2 5200+ 2.6 GHz) <br>\\t\\t\\t\\t\\t\\t</li><li><strong>Memory: </strong>1.5 GB RAM <br>\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics: </strong>DirectX®9.0c/Shader3.0 compatible, VRAM 512 MB (NVIDIA® GeForce&amp;reg 7800 series or ATI Radeon™ X1900) <br>\\t\\t\\t\\t\\t\\t</li><li><strong>Sound: </strong>DirectX®9.0c compatible sound cards <br>\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®: </strong>DirectX®9.0c <br>\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive: </strong>8.0 GB free space <br>\\t\\t\\t\\t\\t\\t</li><li><strong>Peripherals: </strong>Keyboard and Xbox 360 controller supported <br>\\t\\t\\t\\t\\t</li></ul>\'}', '0,24', '0,29', '0,02', '0,1', '0,65'),
(305, 'bottom of the 9th', '2017', 0, 17, 11, 2, 0, 4.99, 'Play the most exciting moment of baseball in this fast-paced dice and card game!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP SP2+<br></li><li><strong>Processor:</strong> SSE2 instruction set support<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> DX9 (shader model 3.0) or DX11 with feature level 9.3 capabilities, 1024x768 resolution<br></li><li><strong>Storage:</strong> 500 MB available space</li></ul>\'}', '0,45', '0,05', '0', '0,01', '0,51'),
(306, 'sid meiers civilization beyond earth', '2014', 0, 90, 9555, 8224, 932, 29.99, 'Sid Meier’s Civilization: Beyond Earth is a new science-fiction-themed entry into the award winning Civilization series. As part of an expedition sent to find a home beyond Earth, lead your people into a new frontier, explore and colonize an alien planet and create a new civilization in space.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® Vista SP2/ Windows® 7<br></li><li><strong>Processor:</strong> Intel Core 2 Duo 1.8 GHz or AMD Athlon X2 64 2.0 GHz<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> 256 MB ATI HD3650 or better, 256 MB nVidia 8800 GT or better, or Intel HD 3000 or better integrated graphics<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 8 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c‐compatible sound card<br></li><li><strong>Additional Notes:</strong> Other Requirements: Initial installation requires one-time Internet connection for Steam authentication; software installations required (included with the game) include Steam Client, Microsoft Visual C++2012 Runtime Libraries and Microsoft DirectX.</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® Vista SP2 / Windows® 7<br></li><li><strong>Processor:</strong> 1.8 GHz Quad Core CPU<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> AMD HD5000 series or better (or ATI R9 series for Mantle support), nVidia GT400 series or better, or Intel IvyBridge or better integrated graphics<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 8 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c‐compatible sound card<br></li><li><strong>Additional Notes:</strong> DirectX: DirectX version 11, or Mantle (with supported video card)</li></ul>\'}', '0,11', '0,22', '0', '0,03', '0,37'),
(307, 'bejeweled 3', '2010', 0, 65, 2670, 126, 85, 4.25, 'The biggest, brightest Bejeweled ever! Discover all-new ways to play the world’s #1 puzzle game. Find your perfect match with 8 breathtaking game modes that meet all your moods — ease into Classic Bejeweled for cascades of fun, journey through 40 challenging Quest puzzles, charge into the electrifying Lightning for non-stop action, and...', '{\'minimum\': \'<ul>\\n\\t\\t\\t\\t\\t\\t\\t<li><strong>OS:</strong> Windows XP SP2/Vista/7\\n\\t\\t\\t\\t\\t\\t\\t<li><strong>Processor:</strong> 1.2+GHz processor\\n\\t\\t\\t\\t\\t\\t\\t<li><strong>Memory:</strong> 1+GB of RAM\\n\\t\\t\\t\\t\\t\\t\\t<li><strong>Graphics:</strong> 128+MB of video memory (256+MB recommended)\\n\\t\\t\\t\\t\\t\\t\\t<li><strong>DirectX&reg;:</strong> 9.0c or higher\\n\\t\\t\\t\\t\\t\\t\\t<li><strong>Hard Drive:</strong> 320+MB of free hard drive space\\n\\t\\t\\t\\t\\t\\t\\t<li><strong>Sound:</strong> DirectX 9.0c or higher sound\\n\\t\\t\\t\\t\\t\\t</ul>\'}', '0,6', '0,07', '0', '0,06', '0,72'),
(308, 'tropico 4', '2011', 0, 70, 8740, 827, 518, 12.49, 'The world is changing and Tropico is moving with the times - geographical powers rise and fall and the world market is dominated by new players with new demands and offers - and you, as El Presidente, face a whole new set of challenges.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP SP3 (32-bit), Vista / 7 (32 or 64-bit)<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 2 GHz Dual Core CPU<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1 GB RAM<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> Shader Model 3.0 (Geforce 6600 or higher, Radeon X1600-Series), 256 MB, DirectX 9.0c<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 9.0c<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 5 GB free hard disk space<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX compatible<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista / 7 (32 or 64-bit)<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 2 GHz Quad Core CPU<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2 GB RAM<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> Shader Model 3.0 (Geforce 8800 or higher, Radeon HD4000-Series or higher), 512 MB, DirectX 9.0c<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 9.0c<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 5 GB free hard disk space<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX compatible<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0,3', '0,26', '0', '0,07', '0,63'),
(309, 'dark void', '2010', 0, 0, 218, 230, 143, 6.49, 'Dark Void™ is a sci-fi action-adventure game that combines an adrenaline-fueled blend of aerial and ground-pounding combat.', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP, Windows Vista or Windows 7<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel 2.4Ghz or AMD 2.0Ghz<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1 GB RAM<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> GeForce 7900 or Radeon HD 3850 series<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX 9.0c / Shader 3.0<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 10 GB free<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectSound Compatible<br>\\t\\t\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br>\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>Processor:</strong> Intel Quad Core 2.66Ghz or AMD Phenom X4<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2 GB RAM<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 9800 series or ATI 4800 series<br>\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0,37', '0,22', '0', '0,09', '0,69'),
(310, 'company of heroes 2', '2013', 18, 452, 32548, 12038, 1846, 14.99, 'Experience the ultimate WWII RTS platform with COH2 and its standalone expansions. This package includes the base game, which you can then upgrade by purchasing The Western Front Armies, Ardennes Assault and/or The British Forces. More info in the &quot;About This Game&quot; section below.', '{\'minimum\': \'Minimum:<br><ul class=\"bb_ul\"><li><strong>Memory:</strong> 2GB RAM<br>\\t</li><li><strong>Processor:</strong> 2Ghz Intel Core2 Duo or equivalent<br>\\t</li><li><strong>Graphics:</strong> 512MB Direct3D 10 capable video card (GeForce 8800 GT or Radeon HD 2900XT)<br>\\t</li><li><strong>OS:</strong> 32bit Vista<br> </li><li><strong>Internet:</strong> Broadband Internet connection<br>\\t</li><li><strong>Hard Drive:</strong> 30GB free Hard disc space</li></ul>\', \'recommended\': \'Recommended:<br><ul class=\"bb_ul\"><li><strong>Memory:</strong> 4GB RAM<br></li><li><strong>Processor:</strong> 3Ghz Intel i5 quad core or equivalent<br></li><li><strong>Graphics:</strong> 1024 MB Direct3D 11 capable video card (GeForce GTX 470 or Radeon HD 5850)<br></li><li><strong>OS:</strong> 64bit Windows 7 and above<br></li><li><strong>Internet:</strong> Broadband Internet connection<br></li><li><strong>Hard Drive:</strong> 30GB free Hard disc space</li></ul>\'}', '0,06', '0,25', '0', '0,05', '0,36'),
(311, 'remember me', '2013', 16, 50, 9080, 1815, 276, 22.99, 'Remember Me™ is a 3rd person action adventure where players take on the role of Nilin, a former elite memory hunter with the ability to break into people’s minds and steal or even alter their memories.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong>Windows Vista®/XP, Windows 7, Windows 8<br>\\t</li><li><strong>Processor:</strong>Intel® CoreTM2 Duo 2.4 Ghz or better, AMD Athlon™ X2 2.8 Ghz or better<br>\\t</li><li><strong>Memory:</strong>2 GB RAM<br>\\t</li><li><strong>Graphics:</strong>NVIDIA® GeForce® 8800GTS or better, ATI Radeon™ HD 3850 or better<br>\\t</li><li><strong>Hard Drive:</strong>9 GB HD space<br>\\t</li><li><strong>Sound:</strong>Standard audio device<br>\\t</li><li><strong>Other Requirements:</strong>Broadband Internet connection</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong>Windows Vista®, Windows 7, Windows 8<br>\\t</li><li><strong>Processor:</strong>Intel® Core™ Quad 2.7 Ghz or better, AMD Phenom™ II X4 3 Ghz or better<br>\\t</li><li><strong>Memory:</strong>4 GB RAM<br>\\t</li><li><strong>Graphics:</strong>NVIDIA® GeForce® GTX 560 or better<br>\\t</li><li><strong>Hard Drive:</strong>9 GB HD space<br>\\t</li><li><strong>Sound:</strong>Standard audio device\\t<br>\\t</li><li><strong>Other Requirements:</strong>Broadband Internet connection</li></ul>\'}', '0,2', '0,3', '0', '0,1', '0,59'),
(312, 'sniper ghost warrior 2', '2013', 18, 38, 6775, 2724, 234, 6.99, 'Sniper: Ghost Warrior 2 takes the bulls-eye precision of its predecessor to new and exciting heights!', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP, Vista or Windows 7, with the latest Service Pack<br> </li><li><strong>Processor:</strong> Intel Core 2 Duo at 2Ghz, or AMD Athlon 64 x2 2Ghz, or better<br> </li><li><strong>Memory:</strong> 2GB<br> </li><li><strong>Hard Disk Space:</strong> 9Gb <br> </li><li><strong>Video Card:</strong>NVidia 8800GT with 512Mb RAM or better<br><br> </li><li><strong>DirectX®:</strong> 9.0c<br> </li><li><strong>Sound:</strong> DirectX Compatible Sound Card<br> </li></ul>\'}', '0,13', '0,37', '0,03', '0,1', '0,65'),
(313, 'supreme commander 2', '2010', 0, 47, 5336, 903, 1834, 8.99, 'Includes 47 Steam achievements, leaderboards, and stats!', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP/Vista/Windows 7<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 3.0 GHz or better, AMD or Intel CPU<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1GB RAM (XP) 1.5GB RAM (Vista / Win 7)<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 256 MB VRAM with Pixel Shader 3.0<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX 9.0<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 4-5 GB for full install &amp; DirectX<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> No accelerated sound hardware required<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Other requirements:</strong> Internet Connection with Cable / Broadband<br>\\t\\t\\t\\t\\t\\t\\t</li></ul><img src=\"https://cdn.steampowered.com/v/gfx/apps/40100/extras/alienwarelogo.jpg\" >\', \'recommended\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP/Vista/Windows 7<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 2.6 GHz or better, Dual Core AMD or Intel CPU<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2GB RAM (XP) 2GB RAM (Vista / Win 7)<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 256 MB VRAM DX9 compliant with Pixel Shader 3.0<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX 9.0<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 4-5 GB for full install &amp; DirectX<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> No accelerated sound hardware required<br>\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0,23', '0,25', '0', '0,07', '0,54'),
(314, 'f1 race stars', '2012', 0, 64, 689, 215, 42, 10.99, 'F1 RACE STARS™ is a brand new world of FORMULA ONE™ fun as you’ve never seen it before!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista or Windows 7<br>\\t</li><li><strong>Processor:</strong>Intel Core 2 Duo 2.4GHz or AMD Athlon X2 5400+<br>\\t</li><li><strong>Memory:</strong>2 GB RAM<br>\\t</li><li><strong>Graphics:</strong>AMD HD2600 or NVIDIA Geforce 8600<br>\\t</li><li><strong>Hard Drive:</strong>5 GB HD space space<br> </li><li><strong>DirectX®:</strong> 11<br></li><li><strong>Sound:</strong> DirectX® compatible sound card<br><br>\\t</li><li><strong>Other Requirements:</strong>Broadband Internet connection<br><br></li><li><strong>Additional:</strong>Supported Graphics Cards: AMD Radeon HD2600 or higher, HD3650 or higher, HD4550 or higher, HD5000 Series, HD6000 Series, HD7000 Series. nVidia GeForce 8600 or higher, 9500 or higher, GTX220 or higher, GTX400 Series, GTX500 Series, GTX600 Series. Intel HD Graphics 3000 or higher, AMD Fusion A8 or higher.<br><br></li><li><strong>Note:</strong> Not compatible with all integrated sound/graphics solutions (inc. Laptops).</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong>Windows Vista or Windows 7 64 bit<br>\\t</li><li><strong>Processor:</strong>Intel Core i7/AMD Bulldozer<br>\\t</li><li><strong>Memory:</strong>4 GB RAM<br>\\t</li><li><strong>Graphics:</strong>AMD HD6000 Series/Nvidia GTX500 Series<br>\\t</li><li><strong>Hard Drive:</strong>5 GB HD space<br> </li><li><strong>DirectX®:</strong> 11<br></li><li><strong>Sound:</strong> DirectX® compatible sound card<br>\\t<br>\\t</li><li><strong>Other Requirements:</strong>Broadband Internet connection<br></li><li><strong>Additional:</strong>AMD Radeon HD2600 or higher, HD3650 or higher, HD4550 or higher, HD5000 Series, HD6000 Series, HD7000 Series. nVidia GeForce 8600 or higher, 9500 or higher, GTX220 or higher, GTX400 Series, GTX500 Series, GTX600 Series. Intel HD Graphics 3000 or higher, AMD Fusion A8 or higher.</li></ul>\'}', '0,13', '0,41', '0', '0,11', '0,66'),
(315, 'iron storm', '2014', 0, 0, 46, 23, 0, 1.99, 'Western Germany, March 1964... The last Great War rages on. Madness at the front lines. Men butchering each other. War-torn Europe stands ripped apart by a front line that runs straight through the heart of Germany where American and Western European troops battle against enemy forces.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP, Vista, 7, 8<br></li><li><strong>Processor:</strong> 1 GHz<br></li><li><strong>Memory:</strong> 512 MB RAM<br></li><li><strong>Graphics:</strong> DirectX compatible Sound Card<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 1 GB available space<br></li><li><strong>Sound Card:</strong> DirectX compatible Sound Card<br></li><li><strong>Additional Notes:</strong> Mouse, Keyboard</li></ul>\'}', '0', '0', '0,34', '0', '0,34'),
(316, 'ninja blade', '2009', 0, 0, 128, 72, 0, 6.99, 'It was July 7th, 2011. While investigating reports of unlawful weapons trafficking, peacekeeping forces encountered an unclassified carnivorous species occupying a small village in Northern Africa. These rabid creatures were easily provoked and resistant to conventional attack.', '{\'minimum\': \'\\n\\t\\t\\t\\t\\t\\t<ul>\\n\\t\\t\\t\\t\\t\\t\\t<li><strong>OS:</strong> Microsoft® Windows® XP/Vista</li>\\n\\t\\t\\t\\t\\t\\t\\t<li><strong>Processor:</strong> Pentium® 4 3,2 GHz or similar Athlon® 64</li>\\n\\t\\t\\t\\t\\t\\t\\t<li><strong>Memory:</strong> 1 GB RAM</li>\\n\\t\\t\\t\\t\\t\\t\\t<li><strong>Graphics:</strong> 3D Video card with 256 MB VRAM, DirectX® 9.0c compatible (GeForce 8600GTS/Radeon HD2600XT or higher)</li>\\n\\t\\t\\t\\t\\t\\t\\t<li><strong>DirectX&reg;:</strong> 9.0c</li>\\n\\t\\t\\t\\t\\t\\t\\t<li><strong>Hard Drive:</strong> 5 GB free disk space</li>\\n\\t\\t\\t\\t\\t\\t\\t<li><strong>Sound:</strong> DirectX® 9.0с compatible sound card</li>\\n\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>Controller Support:</strong> Keyboard, mouse, gamepad (Microsoft X-Box 360 Controller Compatible)</li>\\n\\t\\t\\t\\t\\t\\t</ul>\\n\\t\\t\\t\\t\\t\\t\'}', '0,14', '0,14', '0,02', '0,03', '0,33'),
(317, 'binary domain', '2012', 0, 49, 4416, 742, 639, 9.99, 'Set in futuristic Tokyo, take control of the robotic community before they control everything!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Microsoft Windows 7/Vista/XP<br>\\t</li><li><strong>Processor:</strong> Intel Core 2 Duo @ 2.66 GHz or AMD equivalent<br>\\t</li><li><strong>Memory:</strong> 2GB RAM (XP)/3GB RAM (Windows 7 / Vista)<br>\\t</li><li><strong>Graphics:</strong> NVIDIA GeForce GT220 (512MB) / ATI Radeon HD 2600 XT (512MB)<br>\\t</li><li><strong>Hard Drive:</strong> 8 GB free hard drive space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Microsoft Windows 7<br>\\t</li><li><strong>Processor:</strong> Intel Core i5 @ 2.66 GHz or AMD equivalent<br>\\t</li><li><strong>Memory:</strong> 3GB RAM<br>\\t</li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 460 (1GB) / ATI Radeon HD 5750 (1GB)<br>\\t</li><li><strong>Hard Drive:</strong> 8 GB free hard drive space</li></ul>\'}', '0,18', '0,15', '0,16', '0,05', '0,52'),
(318, 'ultimate marvel vs capcom 3', '2017', 0, 47, 1386, 201, 54, 19.99, 'Marvel and Capcom join forces to deliver the most frenetic 3 vs 3 tag battles ever with Ultimate Marvel VS Capcom 3. This release comes fully loaded, including all previous DLC, Marvel VS. Capcom : Official Complete Works.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® 7 SP1/ 8/ 8.1 (64-BIT Required)<br></li><li><strong>Processor:</strong> Intel® Core™ 2 Duo 2.4 GHz, or better<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA® GeForce® GTX260, or better<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 4 GB available space<br></li><li><strong>Sound Card:</strong> DirectSound compatible (must support DirectX 9.0c or higher)<br></li><li><strong>Additional Notes:</strong> Genuine Xbox 360 PC compatible controller recommended.</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® 7 SP1/ 8/ 8.1/ 10 (64-BIT Required)<br></li><li><strong>Processor:</strong> Intel® Core™ 2 Quad 2.7 GHz, or better<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA® GeForce® GTX 560, or better<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 4 GB available space<br></li><li><strong>Sound Card:</strong> DirectSound compatible (must support DirectX 9.0c or higher)<br></li><li><strong>Additional Notes:</strong> Genuine Xbox 360 PC compatible controller recommended.</li></ul>\'}', '0,2', '0,16', '0,08', '0,06', '0,5'),
(319, 'deus ex invisible war', '2007', 16, 0, 649, 433, 24, 4.99, 'Approximately 20 years after the events depicted in Deus Ex, The World is only beginning to recover from a Catastrophic worldwide depression. In the Chaotic period of recovery, several religious and political factions see an opportunity to re-shape a worldwide government to their agendas, understanding that the right moves now could...', '{\'minimum\': \'<strong>Minimum: </strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li>IBM PC or 100% compatible<br>\\t\\t\\t\\t\\t</li><li>Microsoft Windows 2000/XP<br>\\t\\t\\t\\t\\t</li><li>Pentium IV, 1.3GHz (Or AMD Athlon XP equivalent) processor<br>\\t\\t\\t\\t\\t</li><li>100% DirectX 9 32MB 3D Accelerated video card with Pixel Shader v1.1 Capability<br>\\t\\t\\t\\t\\t</li><li>256 MB System RAM<br>\\t\\t\\t\\t\\t</li><li>100% DirectX 9 Compatible Sound Card<br>\\t\\t\\t\\t\\t</li><li>2GB free uncompressed hard drive space (additional space may be necessary for saved games) <br>\\t\\t\\t\\t\\t</li><li>100% Windows 2000/XP compatible Mouse and Keyboard<br>\\t\\t\\t\\t\\t<strong>Recommended: </strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li>Pentium IV, 1.5 Ghz (or AMD Athlon XPequivalent) or greater processor<br>\\t\\t\\t\\t\\t</li><li>512 MB System RAM<br>\\t\\t\\t\\t\\t</li><li>100% DirectX 9 128MB 3D Graphics Card<br>\\t\\t\\t\\t\\t</li><li>2GB of Hard Drive Space</li></ul>Supported Video Chipsets:<br>nVidia GeForce 3Ti/4Ti/FX - Note: GeForce MX series is NOT SUPPORTED. ATI Radeon 8500/9xxx or higher.</li></ul>\'}', '0,25', '0,07', '0', '0,01', '0,33'),
(320, 'deus ex mankind divided', '2016', 18, 81, 16023, 7344, 798, 19.99, 'Now an experienced covert operative, Adam Jensen is forced to operate in a world that has grown to despise his kind. Armed with a new arsenal of state-of-the-art weapons and augmentations, he must choose the right approach, along with who to trust, in order to unravel a vast worldwide conspiracy.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7.1SP1 or above (64-bit Operating System Required)<br></li><li><strong>Processor:</strong> Intel Core i3-2100 or AMD equivalent<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> AMD Radeon HD 7870 (2GB) or NVIDIA GeForce GTX 660 (2GB)<br></li><li><strong>Storage:</strong> 45 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 10 64-bit<br></li><li><strong>Processor:</strong> Intel Core i7-3770K or AMD FX 8350 Wraith<br></li><li><strong>Memory:</strong> 16 GB RAM<br></li><li><strong>Graphics:</strong> AMD Radeon RX 480 - 1920 x 1080 or NVIDIA GTX 970 - 1920 x 1080<br></li><li><strong>Storage:</strong> 55 GB available space<br></li><li><strong>Additional Notes:</strong> 55GB HD space includes DLC</li></ul>\'}', '0,18', '0,26', '0', '0,06', '0,5'),
(321, 'battlestations pacific', '2009', 0, 0, 1028, 542, 132, 6.99, 'Experience one war through two epic sagas where you will be a part of history or change it. Feel the power of the historically authentic and decisive battles of the Pacific War. Relive some of the grandest and most critical naval battles of recent history and for the first time, choose to lead your fleet to a completely different ending...', '{\'minimum\': \'<strong>Minimum:</strong><br> <ul class=\"bb_ul\"><li><strong>OS:</strong> Microsoft Windows XP (admin rights required)/Microsoft Windows Vista (admin rights required)<br>\\t </li><li><strong>Processor:</strong> Intel Pentium 4 3+GHz or AMD Athlon 2.5+GHz <br>\\t </li><li><strong>Memory:</strong> 1GB (Windows XP) / 2GB (Windows Vista) system memory <br>\\t </li><li><strong>Graphics:</strong> NVIDIA GeForce 6 series 6800GT (or better) / ATI 1800XT (or better)<br>\\t </li><li><strong>Hard Drive:</strong> 8 GB Free Space <br>\\t </li><li><strong>Sound:</strong> Direct X 9.0c compatible sound card and drivers<br> </li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br> <ul class=\"bb_ul\"><li><strong>OS:</strong> Microsoft Windows XP (admin rights required)/Microsoft Windows Vista (admin rights required)<br>\\t </li><li><strong>Processor:</strong> Intel Core 2 Duo 2.2 GHz or Athlon 64 X2 4400+<br>\\t </li><li><strong>Memory:</strong> 2 GB system memory<br>\\t </li><li><strong>Graphics:</strong> nVidia GeForce 9800 GTX or ATI HD4800<br>\\t </li><li><strong>Hard Drive:</strong> 8 GB Free Space<br>\\t </li><li><strong>Sound:</strong> Direct X 9.0c compatible sound card and drivers<br>\\t </li><li><strong>Input Devices:</strong> Keyboard and mouse / Xbox 360 Controller for Windows<br> </li></ul>\'}', '0,17', '0,14', '0,01', '0,03', '0,36'),
(322, 'dead rising 2 off the record', '2011', 18, 50, 1387, 376, 435, 14.99, 'You are Frank West – photojournalist and original hero of the Dead Rising Willamette incident – taking center stage experiencing the re-imagined Fortune City outbreak.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista®/XP, Windows 7<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Core 2 Duo 2.4 Ghz or better, AMD Athlon X2 2.2 Ghz or better<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2 GB RAM<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> NVIDIA® GeForce® 8800GTS or better, ATI Radeon™ HD 3850 or better<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX® 9.0c or greater<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 8.5 GB free hard drive space<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> Standard audio device<br>\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0,32', '0,19', '0,1', '0,06', '0,67'),
(323, 'overlord ii', '2009', 0, 0, 2116, 306, 197, 6.99, 'Overlord II, sequel to the critically acclaimed cult hit, sees the return of the chaotic Minions and their new Dark Master. Bigger, badder and more beautifully destructive, Overlord 2 has a Glorious Empire to smash, a massive Netherworld to revive, Minion mounts to mobilize, a trio of mistresses to woo, War Machines to crush opposition...', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong>Windows XP SP2+<br></li><li><strong>Processor:</strong> Pentium 4 3.0Ghz/Athlon 64bit 3000+<br></li><li><strong>Memory:</strong> 1GB<br></li><li><strong>Graphics:</strong> GeForce 6800+/ATI X1600+ with 256MB<br></li><li><strong>DirectX®:</strong> DirectX 9.0c<br></li><li><strong>Hard Drive:</strong> 5GB<br></li><li><strong>Sound:</strong> DirectX Compatible Sound Card</li></ul><br>Multiplayer is no longer available\'}', '0,26', '0,32', '0', '0,1', '0,67'),
(324, 'prey', '2017', 0, 58, 17808, 2144, 738, 19.99, 'In Prey, you awaken aboard Talos I, a space station orbiting the moon in the year 2032. You are the key subject of an experiment meant to alter humanity forever – but things have gone terribly wrong. The space station has been overrun by hostile aliens and you are now being hunted.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li>Requires a 64-bit processor and operating system<br></li><li><strong>OS:</strong> Windows 7/8/10 (64-bit versions)<br></li><li><strong>Processor:</strong> Intel i5-2400, AMD FX-8320<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> GTX 660 2GB, AMD Radeon 7850 2GB<br></li><li><strong>Storage:</strong> 20 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li>Requires a 64-bit processor and operating system<br></li><li><strong>OS:</strong> Windows 7/8/10 (64-bit versions)<br></li><li><strong>Processor:</strong> Intel i7-2600K, AMD FX-8350<br></li><li><strong>Memory:</strong> 16 GB RAM<br></li><li><strong>Graphics:</strong> GTX 970 4GB, AMD R9 290 4GB<br></li><li><strong>Storage:</strong> 20 GB available space</li></ul>\'}', '0,27', '0,06', '0', '0,04', '0,35'),
(325, 'murdered soul suspect', '2014', 16, 48, 8658, 1647, 282, 19.99, 'MURDERED: SOUL SUSPECT™ takes players into a whole new realm of mystery where the case is personal and the clues just out of reach, challenging gamers to solve the hardest case of all… their own murder.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista 64bit with Platform Update for Windows Vista<br></li><li><strong>Processor:</strong> High-Performance Dual Core CPU or Quad Core CPU<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> AMD Radeon™ HD 3870 512MB RAM / Nvidia GeForce 8800GT<br></li><li><strong>DirectX:</strong> Version 10<br></li><li><strong>Storage:</strong> 12 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 64bit / Windows 8 64bit<br></li><li><strong>Processor:</strong> AMD FX-8000 series or better / Intel Quad i7 Core CPU<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> AMD Radeon™ TM R9 270 or better / Nvidia GTX 660 series or better<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 12 GB available space</li></ul>\'}', '0,28', '0,38', '0,04', '0,1', '0,8'),
(326, 'trackmania turbo', '2016', 0, 0, 742, 441, 8159, 33.99, 'Trackmania offers you the ultimate arcade racing universe where everything is about reaching the perfect racing time. Test your skills in over 200 tracks, experience immediate fun by challenging your friends at home (offline splitscreen) or online.', '{\'minimum\': \'<strong>最低:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista or Windows 7 SP1 or Windows 8.1 or Windows 10<br></li><li><strong>プロセッサー:</strong> Dual core from Intel or AMD at 2 GHz or better<br></li><li><strong>メモリー:</strong> 2 GB RAM<br></li><li><strong>グラフィック:</strong> Video card must be 512 MB or more and should be a DirectX 10 - compatible or DirectX 11 - compatible<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>ストレージ:</strong> 5 GB 利用可能<br></li><li><strong>サウンドカード:</strong> DirectX Compatible Sound Card with latest drivers</li></ul>\'}', '0,05', '0,28', '0', '0,05', '0,39'),
(327, 'singularity', '2010', 18, 0, 2766, 227, 148, 14.99, 'FIGHT THE PAST TO SAVE THE FUTURE. STOP THE SINGULARITY. Learn the truth behind a massive cover-up of the catastrophic SINGULARITY, an event that fractured time and threatens the world as we know it. Armed with powerful, advanced weaponry and the experimental Time Manipulation Device, fight enemies from the past, the present, and...', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® XP/Vista/Windows 7 (Does not support Windows 2000)<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Dual Core 2.8 GHz or AMD Ahtlon 64 x2 Dual-Core 4800+ or better<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1GB for XP, 2GB for Vista/Win7<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 3D hardware accelerator card required - 100% DirectX® 9.0c-compliant 256 MB video card and drivers*<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX® 9.0c (Included)<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 8GB of uncompressed hard disk space (plus 400 MB for the Windows® swap file and 12 KB free for saved games)<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> 100% DirectX® 9.0c-compliant true 16-bit sound card and drivers<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Other Requirements:</strong> A 100% Windows® XP/Vista/Windows 7-compatible computer system<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Keyboard/Mouse:</strong>100% Windows® XP/Vista/Windows 7-compatible mouse, keyboard and drivers<br>\\t\\t\\t\\t\\t\\t\\t</li></ul>*Supported Chipsets for Windows® XP/Vista/Windows 7<br><br>\\t\\t\\t\\t\\t\\t\\t&amp;nbsp - All NVIDIA® GeForce® 8800 GT 256 MB RAM and better chipsets (excluding 9400 cards)<br><br>\\t\\t\\t\\t\\t\\t\\t&amp;nbsp - All ATI Radeon™ X1800 256 MB RAM and better (excludes X1800 GTO, HD2400, HD2600, and HD3450)<br><br>\\t\\t\\t\\t\\t\\t\\t&amp;nbsp - Motherboard integrated video chipsets not supported\'}', '0,41', '0,13', '0,01', '0,06', '0,61'),
(328, 'dirt rally', '2015', 0, 170, 17632, 2496, 488, 24.99, 'DiRT Rally is the most authentic and thrilling rally game ever made, road-tested over 80 million miles by the DiRT community. It perfectly captures that white knuckle feeling of racing on the edge as you hurtle along dangerous roads, knowing that one crash could irreparably harm your stage time.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> 64bit Versions of Windows 7, Windows 8, Windows 10<br></li><li><strong>Processor:</strong> AMD FX Series or Intel Core i3 Series<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> AMD HD5450 or Nvidia GT430 or Intel HD4000 with 1GB of VRAM (DirectX 11 graphics card required)<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 50 GB available space<br></li><li><strong>Sound Card:</strong> DirectX Compatible soundcard<br></li><li><strong>Additional Notes:</strong> Supported Graphics Cards: AMD HD5000 Series, HD6000 Series, HD7000 Series, R7 Series, R9 Series Nvidia GTX400 Series, GTX500 Series, GTX600 Series, GTX700 Series, GTX900 Series Intel HD4000 Series, HD5000 Series</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> 64bit Versions of Windows 7, Windows 8, Windows 10<br></li><li><strong>Processor:</strong> AMD FX-8150 or Intel Core i5 4670K<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> AMD R9 290 or Nvidia GTX780<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 50 GB available space<br></li><li><strong>Sound Card:</strong> Direct X compatible soundcard<br></li><li><strong>Additional Notes:</strong> Supported Graphics Cards: AMD HD5000 Series, HD6000 Series, HD7000 Series, R7 Series, R9 Series Nvidia GTX400 Series, GTX500 Series, GTX600 Series, GTX700 Series, GTX900 Series Intel HD4000 Series, HD5000 Series, HD6000 Series</li></ul>\'}', '0,06', '0,35', '0', '0,06', '0,46'),
(329, '7 wonders ii', '2008', 0, 0, 92, 29, 0, 6.99, 'Journey back in time with the 7 Wonders series to when magnificent structures were being built in far away lands. Enjoy challenging match-3 gameplay in a newly enhanced interactive environment where you not only learn about marvelous new wonders such as Stonehenge and Taj Mahal, but also watch them come to life piece by piece before your...', '{\'minimum\': \'<ul>\\n\\t\\t\\t\\t\\t<li><strong>OS:</strong> 2000/XP</li>\\n\\t\\t\\t\\t\\t<li><strong>Processor:</strong> Pentium III 1GHz Processor</li>\\n\\t\\t\\t\\t\\t<li><strong>Memory:</strong> 256MB RAM</li>\\n\\t\\t\\t\\t\\t<li><strong>Graphics:</strong> DirectX Compatible 16 or 32-bit Video Card with 64MB VRAM</li>\\n\\t\\t\\t\\t\\t<li><strong>DirectX Version:</strong> 8.1 or higher</li>\\n\\t\\t\\t\\t\\t<li><strong>Sound:</strong> DirectSound-compatible sound card</li>\\n\\t\\t\\t\\t\\t<li><strong>Hard Drive:</strong> 65MB free HD space</li></ul>\'}', '0,14', '0,15', '0', '0,03', '0,32'),
(330, 'homefront the revolution', '2016', 18, 74, 6396, 5102, 408, 24.99, 'Homefront®: The Revolution is an open-world first person shooter where you must lead the Resistance movement in guerrilla warfare against a superior military force.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7/8/10 all x64<br></li><li><strong>Processor:</strong> Intel Core i5-4570T (2.9 GHz) or equivalent or AMD FX-6100 (3.3 GHz) or equivalent<br></li><li><strong>Memory:</strong> 6144 MB RAM<br></li><li><strong>Graphics:</strong> GeForce GTX 560 TI (1024 MB) or equivalent or Radeon R7 260X (2048 MB) or equivalent<br></li><li><strong>Storage:</strong> 38 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7/8/10 all x64<br></li><li><strong>Processor:</strong> Intel Core i5-2500K (3.3 GHz) or equivalent or AMD FX-8320 (3.5 GHz) or equivalent<br></li><li><strong>Memory:</strong> 8192 MB RAM<br></li><li><strong>Graphics:</strong> GeForce GTX 760 (2048 MB) or equivalent or Radeon HD 7870 (2048 MB) or equivalent<br></li><li><strong>Storage:</strong> 38 GB available space</li></ul>\'}', '0,1', '0,28', '0,03', '0,05', '0,45'),
(331, 'star wars jedi knight ii jedi outcast', '2009', 0, 0, 2020, 219, 127, 7.19, 'The Legacy of Star Wars Dark Forces™ and Star Wars® Jedi Knight lives on in the intense first-person action of Jedi Outcast.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 2000, XP or Vista<br>\\t\\t\\t</li><li><strong>Processor:</strong> Pentium II or Athlon 350 MHz<br>\\t\\t\\t</li><li><strong>Memory:</strong> 64 MB<br>\\t\\t\\t</li><li><strong>Graphics:</strong> 16 MB OpenGL compatible<br>\\t\\t\\t</li><li><strong>DirectX®:</strong> 9.0c<br>\\t\\t\\t</li><li><strong>Hard Drive:</strong> 800 MB<br>\\t\\t\\t</li><li><strong>Sound:</strong> Direct X 8.0a<br> \\t\\t\\t</li><li><strong>Multiplayer Requirements:</strong> Pentium II or Athlon 400MHz<br>\\t\\t\\t</li></ul>\'}', '0,41', '0,12', '0', '0,02', '0,54'),
(332, 'little kings story', '2016', 0, 41, 112, 61, 0, 12.99, 'Once upon a time, a little boy from our world found himself in another, more mystical world where a magical crown made him ruler over a floundering kingdom called Alpoko. You are this little boy, and it\'s your duty to make Alpoko great...so you can then expand its dominion and take over the world!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP, Windows 7, Windows 8.1<br></li><li><strong>Processor:</strong> Intel Core i3-530 @ 2.93 GHz<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA Geforce 450<br></li><li><strong>DirectX:</strong> Version 9.0<br></li><li><strong>Storage:</strong> 5 GB available space<br></li><li><strong>Sound Card:</strong> Compatible with DirectX</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7, Windows 8.1<br></li><li><strong>Processor:</strong> Intel Core i5-3350 @ 3.7 GHz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA Geforce 650<br></li><li><strong>DirectX:</strong> Version 9.0<br></li><li><strong>Storage:</strong> 5 GB available space<br></li><li><strong>Sound Card:</strong> Compatible with DirectX</li></ul>\'}', '0,15', '0,11', '0,02', '0,02', '0,31'),
(333, '40 winks', '2018', 0, 0, 3, 7, 0, 10.29, '40 Winks is an action platformer where you control brother and sister, Ruff and Tumble. Your goal is to collect 40 Winks scattered around the world to stop an evil man called Nitekap. Nitekap wants to turn the winks into hood-winks who are responsible for giving children nightmares.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7, Windows 8, Windows 10<br></li><li><strong>Processor:</strong> Pentium 4, Athlon 64 or later<br></li><li><strong>Memory:</strong> 750 MB RAM<br></li><li><strong>Graphics:</strong> Athlon 64 or later<br></li><li><strong>DirectX:</strong> Version 10<br></li><li><strong>Storage:</strong> 799 MB available space</li></ul>\'}', '0,17', '0,12', '0', '0,02', '0,31'),
(334, 'the legend of heroes trails of cold steel', '2017', 0, 51, 2030, 92, 75, 29.99, 'At Thors Military Academy, Erebonia’s best learn everything from the art of war to liberal arts. First year Rean Schwarzer learns he’s been selected to join the controversial Class VII, and they’ll need to deal with more than just class warfare--they’ll need to safeguard their country from chaos.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 or later<br></li><li><strong>Processor:</strong> Intel Atom x7-Z8700 2.4 GHz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> Shader Model 5 (GeForce 400 / Radeon HD 5000 / Intel post-2012 series)<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 17 GB available space<br></li><li><strong>Additional Notes:</strong> 1280x720 / 30 FPS with portable settings</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 or later<br></li><li><strong>Processor:</strong> Intel i3 3 GHz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> Geforce GTX 770 / Radeon R9 280X<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 17 GB available space<br></li><li><strong>Additional Notes:</strong> 1920x1080 / 60 FPS with high settings</li></ul>\'}', '0,13', '0,09', '0,26', '0,06', '0,53'),
(335, 'toukiden kiwami', '2015', 0, 50, 734, 370, 1532, 49.99, '&quot;Toukiden: Kiwami&quot; is a hunting action game where players take on the role of a Slayer possessing unique abilities, and battle the Oni to save mankind from destruction. To defeat these huge Oni, players band together to sever, pierce, and crush parts of the Oni using the Targeted Destruction System!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista/7/8/8.1 (64bit required)<br></li><li><strong>Processor:</strong> Core i7 870 2.8GHz or better<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> 640*480 pixel over, High Color<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 21 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c over</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista/7/8/8.1 (64bit required)<br></li><li><strong>Processor:</strong> Core i7 2600 3.4GHz or better<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> 1980*1080 pixel over, True Color<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 21 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c over</li></ul>\'}', '0,1', '0,12', '0,24', '0,05', '0,52'),
(336, 'tropico 5', '2014', 0, 70, 7878, 2482, 292, 14.99, 'Return to the remote island nation of Tropico and expand your Dynasty’s reign from the early colonial period to beyond the 21st Century, facing new challenges including advanced trading mechanics, technology and scientific research, as well as cooperative and competitive MULTIPLAYER.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista SP2, Windows 7, Windows 8<br></li><li><strong>Processor:</strong> 2 GHz Dual Core CPU<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> GeForce 400 or higher, AMD Radeon HD 4000 or higher, Intel HD 4000 or higher (DirectX 11 hardware support required)<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 4 GB available space<br></li><li><strong>Sound Card:</strong> DirectX compatible</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 (64 bit), Windows 8 (64 bit)<br></li><li><strong>Processor:</strong> 2.5 GHz Quad Core CPU<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> GeForce 500 or higher, AMD Radeon HD 5000 or higher<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 4 GB available space</li></ul>\'}', '0,1', '0,28', '0,05', '0,06', '0,49'),
(337, 'front mission evolved', '2010', 0, 27, 481, 310, 312, 7.99, 'Experience piloting and customizing massive armored units called Wanzers while engaging in high-intensity battles driven by a compelling story. The battle begins now!', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP, Vista, Windows 7<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Pentium D 1.8 GHz or AMD Athlon 64 x2 1.8 GHz<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1GB RAM (XP), 2GB RAM (Vista/7)<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 512MB NVIDIA GeForce 7800 series graphics card or equivalent<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 9.0c<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 11 GB Free Space<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX® 9.0c compatible sound card <br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Controller Support:</strong> Mouse, Keyboard, Xbox 360 Controller<br>\\t\\t\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br>\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP, Vista, Windows 7<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Core 2 Duo 2.4 GHz or AMD Athlon 64 x2 2.4 GHz<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2GB RAM (XP), 3GB RAM (Vista/7)<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 512MB NVIDIA GeForce 8800 series graphics card or better<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 9.0c<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 11 GB Free Space<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX® 9.0c compatible sound card <br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Controller Support:</strong> Mouse, Keyboard, Xbox 360 Controller<br>\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0,24', '0,14', '0,13', '0,05', '0,54');
INSERT INTO `jeux` (`id_jeu`, `nom_jeu`, `annee`, `age_requis`, `nb_succes`, `nb_avis_pos`, `nb_avis_neg`, `temps_jeu_moyen`, `prix`, `description`, `configuration`, `ventes_AN`, `ventes_EU`, `ventes_JP`, `ventes_Autre`, `ventes_Global`) VALUES
(338, 'the bureau xcom declassified', '2013', 16, 41, 6661, 2923, 201, 14.99, 'The year is 1962 and the Cold War has the nation gripped by fear. A top-secret government unit called The Bureau begins investigating a series of mysterious attacks by an enemy more powerful than communism.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista Service Pack 2 32-bit<br></li><li><strong>Processor:</strong> Intel Core 2 DUO 2.4 GHz / AMD Athlon X2 2.7 GHz<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> DirectX9 Compatible ATI Radeon HD 3870 / NVIDIA 8800 GT<br></li><li><strong>Storage:</strong> 12 GB available space<br></li><li><strong>Sound Card:</strong> DirectX Compatible<br></li><li><strong>Additional Notes:</strong> Incompatible with Intel HD 3000 Integrated Graphics</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 Service Pack 1 64-bit<br></li><li><strong>Processor:</strong> Quad Core Processor<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> DirectX11 Compatible, AMD Radeon HD 6950 / NVIDIA GeForce GTX 560<br></li><li><strong>Storage:</strong> 12 GB available space<br></li><li><strong>Sound Card:</strong> DirectX Compatible<br></li><li><strong>Additional Notes:</strong> Incompatible with Intel HD 3000 Integrated Graphics</li></ul>\'}', '0,18', '0,33', '0', '0,08', '0,58'),
(339, 'ys memories of celceta', '2018', 0, 52, 148, 11, 0, 19.99, 'World-famous red-haired adventurer Adol Christin awakens in the unfamiliar land of Celceta, remembering nothing more than his name. Join Adol and his new friends as he embarks on an adventure to map the wilderness and reclaim his memories in this beloved action RPG from Nihon Falcom.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7<br></li><li><strong>Processor:</strong> Intel Core i3<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> AMD Radeon HD 6570<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 3 GB available space<br></li><li><strong>Sound Card:</strong> Compatible with DirectX 11.0</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 10<br></li><li><strong>Processor:</strong> Intel Core i5 (4-core 3.30Ghz)<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> AMD Radeon R7 200 Series<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 3 GB available space<br></li><li><strong>Sound Card:</strong> Compatible with DirectX 11.0</li></ul>\'}', '0,15', '0,01', '0,1', '0,04', '0,29'),
(340, 'deathsmiles', '2016', 0, 48, 276, 7, 688, 14.99, 'Deathsmiles is CAVE\'s bullet-hell shoot-\'em-up where you take the role of one of five Angels to defend the magical land of Gilverado from an invasion by Hell itself! Eradicate this devilish assault!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7/8/8.1/10<br></li><li><strong>Processor:</strong> Intel Core i3 2GHz or higher<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> Intel HD Graphics 5000, Geforce 9500GT, Radeon HD 3650 or better<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 3 GB available space<br></li><li><strong>Sound Card:</strong> DirectSound-compatible sound card</li></ul>\'}', '0,15', '0,06', '0,05', '0,02', '0,28'),
(341, 'one piece burning blood', '2016', 0, 50, 1504, 496, 453, 39.99, 'The game that all One Piece fans have been waiting for. One Piece Burning Blood is a dynamic and colourful new fighting game featuring the world’s most famous pirate: Monkey D. Luffy.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 64-bit<br></li><li><strong>Processor:</strong> Intel Core i3-4170 @ 3.70GHz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA@ GeForce@ GTX 460 or better<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 15 GB available space<br></li><li><strong>Sound Card:</strong> DirectX compatible soundcard or onboard chipset</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 64-bit<br></li><li><strong>Processor:</strong> Intel Core i5-4690K @3.50GHz<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA@ GeForce@ GTX 960<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 20 GB available space<br></li><li><strong>Sound Card:</strong> DirectX compatible soundcard or onboard chipset</li></ul>\'}', '0,13', '0,12', '0,14', '0,05', '0,43'),
(342, 'polaris', '2017', 0, 0, 4, 3, 0, 0.72, 'Polaris is a casual game, where you tasked to overcome the level, using 2 synchronously moving circles and sent to the next level!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7<br></li><li><strong>Processor:</strong> Intel Core i3 6100<br></li><li><strong>Memory:</strong> 500 MB RAM<br></li><li><strong>Graphics:</strong> GeForce 210<br></li><li><strong>Storage:</strong> 100 MB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 8<br></li><li><strong>Processor:</strong> Intel Core i7 7700<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> GeForce GT710<br></li><li><strong>Storage:</strong> 100 MB available space</li></ul>\'}', '0,26', '0,02', '0', '0', '0,28'),
(343, 'driver parallel lines', '2009', 0, 0, 367, 46, 0, 8.59, 'You were the fastest wheelman on the street. You were a legend. You were money. Until they set you up and sent you down. Twenty-eight years inside for someone else\'s crime. Now you\'re getting out. Guess what? You got a new job, it\'s called getting revenge.', '{\'minimum\': \'<p><strong>Minimum:</strong></p> \\n\\t\\t\\t\\t\\t<ul> \\n\\t\\t\\t\\t\\t<li><strong>Supported OS: </strong>Windows® XP (SP 1 required)/Vista (only)</li> \\n\\t\\t\\t\\t\\t<li><strong>Processor: </strong> 2.0 GHz Pentium 4 or AMD Athlon</li> \\n\\t\\t\\t\\t\\t<li><strong>Memory: </strong>256 MB </li> \\n\\t\\t\\t\\t\\t<li><strong>Graphics: </strong>64 MB DirectX 9.0c-compliant supporting Shader Model 1.1(*see supported list)</li> \\n\\t\\t\\t\\t\\t<li><strong>DirectX Version: </strong>DirectX 9.0c </li> \\n\\t\\t\\t\\t\\t<li><strong>Sound: </strong>DirectX 9.0c-compliant sound card</li> \\n\\t\\t\\t\\t\\t<li><strong>Hard Drive: </strong> 4.8GB free hard disk space </li> \\n\\t\\t\\t\\t\\t<li><strong>*Supported Video Cards at Time of Release: </strong>ATI RADEON 8500/9000/X families,NVIDIA GeForce 3/4/FX/6/7 families (GeForce 4MX NOT supported)</li> \\n\\t\\t\\t\\t\\t<li>Laptop versions of these cards may work but are NOT supported. These chipsets are the only ones that will run this game. </li> </ul> \', \'recommended\': \'<p><strong>Recommended:</strong></p> \\n\\t\\t\\t\\t\\t<ul> \\n\\t\\t\\t\\t\\t<li><strong>Supported OS: </strong>Windows® XP (SP 1 required)/Vista (only)</li> \\n\\t\\t\\t\\t\\t<li><strong>Processor: </strong> 3.4 GHz Pentium 4 or AMD Athlon</li> \\n\\t\\t\\t\\t\\t<li><strong>Memory: </strong>512 MB </li> \\n\\t\\t\\t\\t\\t<li><strong>Graphics: </strong>128 MB DirectX 9.0c-compliant supporting Shader Model 2.0(*see supported list)</li> \\n\\t\\t\\t\\t\\t<li><strong>DirectX Version: </strong>DirectX 9.0c </li> \\n\\t\\t\\t\\t\\t<li><strong>Sound: </strong>DirectX 9.0c-compliant sound card</li> \\n\\t\\t\\t\\t\\t<li><strong>Hard Drive: </strong> 4.8GB free hard disk space </li> \\n\\t\\t\\t\\t\\t<li><strong>*Supported Video Cards at Time of Release: </strong>ATI RADEON 8500/9000/X families,NVIDIA GeForce 3/4/FX/6/7 families (GeForce 4MX NOT supported)</li> \\n\\t\\t\\t\\t\\t<li>Laptop versions of these cards may work but are NOT supported. These chipsets are the only ones that will run this game. </li> </ul> \'}', '0,18', '0,12', '0,03', '0,03', '0,38'),
(344, 'danganronpa another episode ultra despair girls', '2017', 0, 35, 901, 76, 818, 22.99, 'Komaru Naegi has been imprisoned inside a mysterious apartment for over a year. Her rescue is derailed when hundreds of Monokumas suddenly attack. She teams up with Toko Fukawa to survive the rampaging Monokumas, escape the crafty Monokuma Kids, and uncover the secrets of the city.', '{\'minimum\': \'<strong>最低:</strong><br><ul class=\"bb_ul\"><li>64 ビットプロセッサとオペレーティングシステムが必要です<br></li><li><strong>OS:</strong> Windows 7 64-bit<br></li><li><strong>プロセッサー:</strong> Intel Core i3-530 CPU 2.93GHz or above<br></li><li><strong>メモリー:</strong> 4 GB RAM<br></li><li><strong>グラフィック:</strong> NVIDIA GeForce GTX650 1GB or AMD HD 7700 1GB(DirectX 11 graphic card required)<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>ストレージ:</strong> 18 GB 利用可能<br></li><li><strong>サウンドカード:</strong> DirectX 9.0c compatible sound card</li></ul>\', \'recommended\': \'<strong>推奨:</strong><br><ul class=\"bb_ul\"><li>64 ビットプロセッサとオペレーティングシステムが必要です<br></li><li><strong>OS:</strong> Windows 7 64-bit<br></li><li><strong>プロセッサー:</strong> Intel Core i3-530 CPU 2.93GHz or above<br></li><li><strong>メモリー:</strong> 8 GB RAM<br></li><li><strong>グラフィック:</strong> NVIDIA GeForce GTX650 1GB or AMD HD 7700 1GB(DirectX 11 graphic card required)<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>ストレージ:</strong> 18 GB 利用可能<br></li><li><strong>サウンドカード:</strong> DirectX 9.0c compatible sound card</li></ul>\'}', '0,1', '0,03', '0,12', '0,04', '0,28'),
(345, 'myst iii exile', '2018', 0, 0, 28, 3, 0, 11.39, 'The story of Myst continues... Return to this strange and wondrous universe, where books become portals into worlds, and where the lessons of the past may yet hold meaning for today...', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> 7 / 8 / 10<br></li><li><strong>Processor:</strong> 1.8 GHz Processor<br></li><li><strong>Memory:</strong> 512 MB RAM<br></li><li><strong>Graphics:</strong> 8 MB 3D graphics card compatible with DirectX 9<br></li><li><strong>DirectX:</strong> Version 9.0<br></li><li><strong>Storage:</strong> 5 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9 compliant audio device<br></li><li><strong>Additional Notes:</strong> Peripherals: Mouse, Keyboard</li></ul>\'}', '0,18', '0,12', '0', '0,04', '0,34'),
(346, 'gunship', '2014', 0, 0, 26, 32, 0, 4.99, 'Fly low and strike deep in the re-invention of the Gunship flight combat franchise. In Gunship! Players take control one of the worlds deadliest weapons in a simulator that is unmatched.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP or higher<br></li><li><strong>Processor:</strong> Pentium MMX 233 MHz or higher<br></li><li><strong>Memory:</strong> 32 MB RAM<br></li><li><strong>Graphics:</strong> SVGA video card with 2 MB video memory<br></li><li><strong>DirectX:</strong> Version 7.0<br></li><li><strong>Storage:</strong> 150 MB available space<br></li><li><strong>Sound Card:</strong> Sound card</li></ul>\'}', '0,15', '0,1', '0', '0,02', '0,27'),
(347, 'the club', '2008', 0, 0, 47, 50, 0, 9.99, 'The Club™, created by critically acclaimed developer Bizarre Creations, is a new breed of third-person shooter, combining fast-paced run and gun gameplay, destructive environments, and lethal weapons. You will fight to survive in a shadowy underground blood-sport controlled by a faceless, obscenely wealthy and influential elite who place...', '{\'minimum\': \'<strong>Minimum: </strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>Supported OS: </strong> Microsoft® Windows® 2000 or XP with latest service packs installed<br>\\t\\t\\t\\t\\t</li><li><strong>Processor: </strong> 2.0 Ghz Intel Pentium 4, AMD Athlon XP 2000+ processor<br>\\t\\t\\t\\t\\t</li><li><strong>Graphics: </strong> 100% DirectX 9.0c compatible 64MB video card with latest manufacturer drivers<br>\\t\\t\\t\\t\\t</li><li><strong>DirectX Version: </strong>DirectX 9.0c<br>\\t\\t\\t\\t\\t</li><li><strong>Memory: </strong> 512 MB RAM<br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive: </strong> 6 GB uncompressed free hard disk space</li></ul><strong>Recommended:</strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>Processor: </strong> 2.5 Ghz Intel Pentium 4, AMD Athlon XP 2500+ processor<br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1 GB RAM <br>\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> ATI Radeon X800 series or higher video card with latest manufacturer drivers </li></ul>\'}', '0,29', '0,17', '0', '0,05', '0,5'),
(348, 'bridge', '2015', 0, 0, 7, 21, 0, 4.99, 'Bridge! lets you be a structural engineer and a construction manager in one. Master the mystery to bridge with a limited budget and limited numbers of parts to divide and to ensure a smooth operation.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7/8<br></li><li><strong>Processor:</strong> 2 GHz Dual-Core<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> 1024 MB<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 600 MB available space</li></ul>\'}', '0,25', '0,02', '0', '0', '0,27'),
(349, 'bloodrayne 2', '2006', 0, 0, 259, 103, 771, 6.99, 'BloodRayne is a dhampir, born from the unnatural union of vampire and human. Blessed with the powers of a vampire but cursed with the thirst for blood and a weakness to sunlight, Rayne is challenged with her most personal battle yet as she hunts down her siblings.', '{\'minimum\': \'<strong>Minimum:</strong> Windows 98 SE/2000/XP, 1.2 GHz processor, 256MB RAM, 200MB virtual memory, 5 GB free hard disc space, DirectX 8.1 or higher (included with game), DirectX compatible sound card, 100% DirectX 8.1 compatible video card, GeForce 3 or higher, with Hardware T&amp;L (Transform &amp; Lighting). Excludes GeForce MX and Go series cards. See full list below.<br>\\t\\t\\t\\t\\tExcluded cards:<br>- ATI Rage (all), Radeon VE and Radeon 7000, 7500, 9000 <br>- ATI Mobility Radeon (original, laptop) <br>- NVidia GeForce 4 MX 420 or 440 PCI <br>- Nvidia Quadro NVS <br>- Nvidia GeForce 2 series <br>- Nvidia Geforce4 440 Go 64M (laptop users) <br>- Kyro 3D Prophet <br>- Matrox <br>- 3D Labs <br>- Intel Onboard (all versions) <br><br>\\t\\t\\t\\t\\t<strong>Recommended:</strong> Windows XP, Pentium 4 2.0 GHz or AMD equivalent, 512 MB RAM, 200MB virtual memory, 5 GB free hard disc space, 100% DirectX 8.1 compatible video card, Matrox Pahrelia, Nvidia GeForce 6800, ATI Radeon X800, 9600, 9700, 9800 or better, DirectX 8.1 or higher, DirectX compatible sound card\'}', '0,24', '0,13', '0', '0,04', '0,42'),
(350, 'shadow man', '2013', 16, 0, 409, 55, 48, 3.99, 'He is coming, stalking criminals in the spirit world and the real world. A possessed man is coming, a voodoo mask in his chest and lines of power in his back. Shadow Man is coming, trailing evil from Liveside to Deadside. To stop an apocalypse. To save your soul.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP / Vista / 7<br></li><li><strong>Processor:</strong> Pentium 200 Mhz<br></li><li><strong>Memory:</strong> 32 MB RAM<br></li><li><strong>Graphics:</strong> Direct3D compatible 3D accelerator card<br></li><li><strong>DirectX:</strong> Version 6.1<br></li><li><strong>Storage:</strong> 3 GB available space<br></li><li><strong>Sound Card:</strong> DirectX compatible sound card<br></li><li><strong>Additional Notes:</strong> Mask of Shadows Not Included</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7<br></li><li><strong>Processor:</strong> Pentium 400 Mhz<br></li><li><strong>Memory:</strong> 64 MB RAM<br></li><li><strong>Graphics:</strong> Direct3D compatible 3D accelerator card<br></li><li><strong>DirectX:</strong> Version 6.1<br></li><li><strong>Storage:</strong> 3 GB available space<br></li><li><strong>Sound Card:</strong> DirectX compatible sound card</li></ul>\'}', '0,32', '0,17', '0', '0,03', '0,52'),
(351, 'final doom', '2007', 0, 0, 573, 82, 120, 3.99, 'Two New, 32-Level DOOM II Episodes. Evilution: Far from earth, the UAC recommenced their experiments on on of the moons of Jupiter. A spaceship, mistaken for a supply vexxel on radar, hovered above the base. Hideous demons poured out, blanketing the base with death. All your comrades were quickly slaughtered or zombified.', '{\'minimum\': \'<strong>Minimum: </strong>A 100% Windows XP/Vista-compatible computer system\'}', '0,15', '0,1', '0', '0,02', '0,27'),
(352, 'fish tycoon', '2008', 0, 0, 35, 8, 0, 5.99, 'Fish Tycoon is a virtual fish breeding game. The object is to breed and cross breed fish until you find the 7 Magic Fish and solve the genetic puzzle. You will have to buy supplies like meds, eggs and special plants and then sell some of your fish in your virtual pet store.', '{\'minimum\': \'<ul>\\n\\t\\t\\t\\t\\t<li><strong>Supported OS: </strong>Windows 2000/XP/Vista</li>\\n\\t\\t\\t\\t\\t<li><strong>Processor: </strong>Pentium III 500</li>\\n\\t\\t\\t\\t\\t<li><strong>Memory: </strong>96 MB </li>\\n\\t\\t\\t\\t\\t<li><strong>Graphics: </strong>16MB of VRAM</li>\\n\\t\\t\\t\\t\\t<li><strong>DirectX Version: </strong>DirectX 7.0 or later</li>\\n\\t\\t\\t\\t\\t<li><strong>Hard Drive: </strong>200 MB</li></ul>\'}', '0,24', '0', '0', '0,02', '0,27'),
(353, 'battlestations midway', '2007', 0, 0, 316, 113, 0, 4.99, 'Battlestations: Midway is an immense action game that drops players into massive air, sea, and undersea battles from Pearl Harbor to the Battle of Midway.', '0', '0,21', '0,03', '0', '0,02', '0,27'),
(354, 'danganronpa 2 goodbye despair', '2016', 0, 47, 4677, 148, 1909, 14.99, 'Jabberwock Island—You and your classmates were ready for fun in the sun until Monokuma returned to restart his murderous game! Trapped in a kill-or-be-killed situation, your only hope rests in solving the island’s mysteries.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7<br></li><li><strong>Processor:</strong> 2.8 GHz Intel Core 2 Duo or better<br></li><li><strong>Memory:</strong> 3 GB RAM<br></li><li><strong>Graphics:</strong> OpenGL 3.2 compatible GPU with at least 1GB of VRAM<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 5 GB available space<br></li><li><strong>Additional Notes:</strong> PS4 or Xbox 360 Controller or Direct Input compatible controller</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7<br></li><li><strong>Processor:</strong> Intel(R) Core(TM) i5-3470 or better<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> OpenGL 3.2 compatible GPU with at least 1GB of VRAM<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 6 GB available space<br></li><li><strong>Additional Notes:</strong> PS4 or Xbox 360 Controller or Direct Input compatible controller</li></ul>\'}', '0,13', '0,07', '0,19', '0,06', '0,45'),
(355, 'the testament of sherlock holmes', '2012', 0, 32, 1488, 301, 1, 14.99, 'As the greatest detective of all time you must find clues, interrogate suspects &amp; unveil a mystery in a story full of twists!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong>WINDOWS XP SP3/WINDOWS VISTA SP2/WINDOWS 7<br>\\t</li><li><strong>Processor:</strong>AMD/INTEL DUAL-CORE 2 GHZ<br>\\t</li><li><strong>Memory:</strong>2048 MB RAM<br>\\t</li><li><strong>Graphics:</strong>256 MB 100% DIRECTX 9 AND SHADERS 3.0 COMPATIBLE ATI RADEON HD 2600 XT/NVIDIA GEFORCE 8600 GT OR HIGHER<br>\\t</li><li><strong>DirectX®:</strong>9.0c<br>\\t</li><li><strong>Hard Drive:</strong>14 GB HD space<br>\\t</li><li><strong>Sound:</strong>DIRECTX 9 COMPATIBLE</li></ul>\'}', '0,05', '0,23', '0', '0,07', '0,35'),
(356, 'game of thrones', '2012', 0, 50, 1407, 587, 1042, 10.99, 'Experience an amazing adventure in one of the most fascinating universes! Amidst conspiracy and betrayal, try to survive the orchestrated machinations around the Iron Throne.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> WINDOWS XP SP3/WINDOWS VISTA SP2/WINDOWS 7<br>\\t</li><li><strong>Processor:</strong> AMD/INTEL DUAL-CORE 2.2 GHZ<br>\\t</li><li><strong>Memory:</strong> 2048 MB<br>\\t</li><li><strong>Graphics:</strong> 256 MB 100% DIRECTX 9 AND SHADERS 3.0 COMPATIBLE. ATI RADEON HD 2600 XT/NVIDIA GEFORCE 7900 GTX OR HIGHER<br>\\t</li><li><strong>DirectX®:</strong> 9<br>\\t</li><li><strong>Hard Drive:</strong> 7 GB<br>\\t</li><li><strong>Sound:</strong> DIRECTX 9 COMPATIBLE<br>\\t</li><li><strong>Internet:</strong> INTERNET CONNECTION REQUIRED THE GAME ACTIVATION</li></ul>\'}', '0,25', '0,26', '0', '0,07', '0,59'),
(357, 'legendary', '2008', 0, 0, 1095, 1000, 90, 1.69, 'All creatures of ancient myth, legend and lore are real  they\'ve just been sealed away for thousands of years inside Pandora\'s Box, waiting... When a thief named Deckard is hired to steal an ancient artifact, he unwittingly triggers a war between man and myth.', '{\'minimum\': \'<strong>Minimum:</strong> <br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP SP2 or Windows Vista <br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 2.0+ GHZ Single Core Processor <br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 512MB of System RAM <br>\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> Nvidia 6200+ or ATI Radeon 9600+ Video Card <br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 10GB of Free Hard Drive Space </li></ul>\', \'recommended\': \'<strong>Recommended:</strong> <br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP SP2 or Windows Vista <br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 2.4+ GHZ Dual Core Processor <br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1GB of System RAM <br>\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> Nvidia 7800GTX+ or ATI x1300+ Video Card <br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 10GB of Free Hard Drive Space </li></ul>\'}', '0,16', '0,19', '0', '0,05', '0,41'),
(358, 'hunted the demons forge', '2011', 0, 0, 498, 213, 28, 3.99, 'It will take the combined efforts of two great warriors to explore menacing dungeons, overgrown ruins, and downtrodden towns … and discover the secrets of the Demon’s Forge.', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP/Vista/7<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 2.0 GHz dual core or better<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2 GB system RAM<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space:</strong> 12 GB<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Video Card:</strong> 512 MB video RAM or better (GeForce 9800 GTX or better/Radeon HD 4330 or better)<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> Windows compatible sound card<br>\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista/7<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Quad Core i5 or equivalent<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 3 GB system RAM<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space:</strong> 12 GB<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Video Card:</strong> NVIDIA GeForce GTX 460 / ATI Radeon HD 5830<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> Windows compatible sound card<br>\\t\\t\\t\\t\\t</li></ul>\'}', '0,28', '0,16', '0,02', '0,07', '0,53'),
(359, 'silent hunter 5 battle of the atlantic', '2010', 0, 0, 516, 752, 1520, 25.99, 'Step behind the periscope of a German U-boat and take on the Allied Forces in famous battles across the vast Atlantic Ocean and Mediterranean Sea. The best-selling submarine series of all time continues with the highly anticipated Silent Hunter: Battle of the Atlantic.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® XP (Service Pack 3), Windows Vista® (Service Pack 2), Windows® 7<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel® Core™2 Duo E4400 2 GHz / AMD Athlon™ 64 X2 4000+ 2.1 GHz or higher (Intel Core™2 Quad Q6600 2.4 GHz / AMD Athlon 64 X2 5200+ 2.6 GHz or higher recommended)<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1 GB (Windows XP) / 2 GB (Windows Vista, Windows 7) (2 GB recommended)<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 512 MB DirectX® 9.0c-compliant video card(*see supported list)<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> <br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 10 GB (15 GB recommended)<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX 9.0c-compliant sound card<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Peripherals Supported:</strong> Windows-compliant mouse, keyboard<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Internet Connection: </strong> 256 kbps Broadband connection (512 kbps connection or better recommended)<br>\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>Supported Video Cards at Time of Release:<br><br>\\t\\t\\t\\t\\t\\t\\t\\tNVIDIA GeForce 8800GT / 9 / GTX 200 series<br><br>\\t\\t\\t\\t\\t\\t\\t\\tATI Radeon HD 2600 / HD 3000 / HD 4000 / HD 5000 series<br><br>\\t\\t\\t\\t\\t\\t\\t\\tNVIDIA SLI &amp; ATI Crossfire\'}', '0', '0,21', '0', '0,05', '0,26'),
(360, 'men of valor', '2016', 0, 0, 157, 71, 0, 8.99, 'Vietnam, 1965. You are Dean Shepard, a &quot;cherry&quot; to the \'Nam with zero war experience other than standard boot camp training at Parris Island, SC. Along with your platoon, you will fight the NVA and the Vietcong in true historic locales and battles.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP / Vista / 7 / 8 / 10 32 or 64 bit<br></li><li><strong>Processor:</strong> 1,5 GHz<br></li><li><strong>Memory:</strong> 512 MB RAM<br></li><li><strong>Graphics:</strong> DirectX compatible video card with 64 MB VRAM<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 4 GB available space<br></li><li><strong>Sound Card:</strong> DirectX compatible Sound card</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP / Vista / 7 / 8 /10 32 or 64 bit<br></li><li><strong>Processor:</strong> AMD/Intel dual-core processor running at 2 GHz or higher<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> DirectX compatible video card with 128 MB VRAM<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 4 GB available space<br></li><li><strong>Sound Card:</strong> DirectX compatible Sound card</li></ul>\'}', '0,19', '0,05', '0', '0,01', '0,25'),
(361, 'anno 2205', '2015', 0, 198, 2141, 1245, 1930, 33.99, 'In Anno 2205™, you join humankind‘s next step into the future with the promise to build a better tomorrow. You conquer Earth, establishing rich, bustling cities and grand industrial complexes, but to secure the prosperity of your people, you must travel into space.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 SP1 or Windows 8.1 or Windows 10(64bit versions)<br></li><li><strong>Processor:</strong> Intel Core i5 750 @ 2.6 GHz or AMD Phenom II X4 @ 3.2 GHz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> nVidia GeForce GTX460 or AMD Radeon HD5870 (1024MB VRAM with Shader Model 5.0)<br></li><li><strong>Storage:</strong> 35 GB available space<br></li><li><strong>Sound Card:</strong> DirectX Compatible Sound Card with latest drivers<br></li><li><strong>Additional Notes:</strong> Game contains Denuvo <a href=\"https://steamcommunity.com/linkfilter/?url=http://(https://www.denuvo.com/)\" target=\"_blank\" rel=\"noopener\" >(https://www.denuvo.com/)</a> anti-tamper technology.</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 SP1, Windows 8, Windows 10 (64 bit versions only)<br></li><li><strong>Processor:</strong> Intel Core i5 2400s @ 2.5 GHz or AMD FX 4100 @ 3.6<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> nVidia GeForce GTX 680 or AMD Radeon HD7970 or better (2048MB VRAM or more, with Shader Model 5.0)<br></li><li><strong>Storage:</strong> 35 GB available space<br></li><li><strong>Sound Card:</strong> DirectX Compatible Sound Card with latest drivers<br></li><li><strong>Additional Notes:</strong> Game contains Denuvo <a href=\"https://steamcommunity.com/linkfilter/?url=http://(https://www.denuvo.com/)\" target=\"_blank\" rel=\"noopener\" >(https://www.denuvo.com/)</a> anti-tamper technology.</li></ul>\'}', '0,02', '0,22', '0', '0,01', '0,25'),
(362, 'cradle of rome', '2010', 0, 0, 16, 2, 0, 6.99, 'Build the heart of the Ancient Roman Empire and become its Emperor! This legendary city was one of the most beautiful and powerful capitals to have ever existed in the ancient world! Resurrect the masterpieces of Roman architecture. The Coliseum will make a good training school for your brave gladiators.', '{\'minimum\': \'<ul>\\n\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>OS:</strong> Windows 98/ME/2000/XP</li>\\n\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>Processor:</strong> 1000 MHz CPU</li>\\n\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>Memory:</strong> 256 MB RAM</li>\\n\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>Graphics:</strong> 32 MB Video Card</li>\\n\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>DirectX&reg;:</strong> 8</li>\\t\\n\\t\\t\\t\\t\\t\\t\\t</ul>\\n\\t\\t\\t\\t\\t\\t\\t\'}', '0,06', '0,16', '0', '0,03', '0,25'),
(363, 'command & conquer 3 kanes wrath', '2009', 0, 0, 1070, 76, 0, 9.99, 'In the name of Kane! The Command &amp; Conquer™ series continues to thrive with Command &amp; Conquer™ 3: Kane’s Wrath. As the expansion pack to the critically-acclaimed and fan favorite, Command &amp; Conquer 3 Tiberium Wars™, this Real-time Strategy (RTS) game returns to the Tiberium Universe with Kane at the center of an epic new...', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP/Vista (64-bit not supported)<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 2GHz (2.2GHz Vista)<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 512 MB (1GB Vista)<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> nVIDIA GeForce 4, ATI Radeon 8500 or greater (ATI Radeon 9200 and 9250 PCI, nVIDIA Geforce 4 MX cards not supported.); for Vista NVIDIA GeForce 6100 or ATI Radeon 9500 or greater<br>\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX 9.0 compatible<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 6GB of free space<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX 9.0 compatible<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Controller Support:</strong> Keyboard, mouse, optional controller (Xbox 360® Controller for Windows)<br>\\t\\t\\t\\t\\t</li><li>INTERNET CONNECTION, ONLINE AUTHENTICATION AND ACCEPTANCE OF END USER LICENSE AGREEMENT REQUIRED TO PLAY. TO ACCESS ONLINE FEATURES, YOU MUST REGISTER ONLINE. ONLY ONE REGISTRATION IS AVAILABLE PER GAME. EA ONLINE TERMS &amp; CONDITIONS AND FEATURE UPDATES CAN BE FOUND AT <a href=\"https://steamcommunity.com/linkfilter/?url=http://WWW.EA.COM\" target=\"_blank\" rel=\"noopener\" >WWW.EA.COM</a>. YOU MUST BE 13+ TO REGISTER WITH EA ONLINE. EA MAY RETIRE ONLINE FEATURES AFTER 30 DAYS NOTICE POSTED ON <a href=\"https://steamcommunity.com/linkfilter/?url=http://WWW.EA.COM\" target=\"_blank\" rel=\"noopener\" >WWW.EA.COM</a>.<br>\\t\\t\\t\\t\\t</li></ul>\'}', '0,16', '0,07', '0', '0,02', '0,26'),
(364, 'risen 2 dark waters', '2012', 0, 49, 2987, 891, 1278, 7.99, 'Set several years after the end of Risen, raging titans have devastated the world and pushed humanity to the brink of existence. Subsequently, monstrous creatures have risen from the watery depths of the sea and their attacks have brought all seafaring to a grinding halt.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP (with Servicepack 2)<br>\\t</li><li><strong>Processor:</strong> Dual Core with 2.1 GHz<br>\\t</li><li><strong>Memory:</strong> 2 GB System RAM<br>\\t</li><li><strong>Hard Disk Space:</strong> 5.5 GB\\t<br>\\t</li><li><strong>Video Card:</strong> 512 MB Radeon 3870 / GeForce 8800 GTX<br>\\t</li><li><strong>DirectX®:</strong> 9.1c<br>\\t</li><li><strong>Sound:</strong> DirectX compatible soundcard<br>\\t</li><li><strong>Additional:</strong> Keyboard/mouse or gamepad required Internet Connection required for online activation</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP (with Servicepack 3), Windows Vista (with Servicepack 1), Windows 7<br>\\t</li><li><strong>Processor:</strong> Dual Core with 3 GHz<br>\\t</li><li><strong>Memory:</strong> 4 GB System RAM<br>\\t</li><li><strong>Video Card:</strong> 1024 MB Radeon 4890 / GeForce GTX 260</li></ul>\'}', '0,09', '0,41', '0,01', '0,1', '0,62'),
(365, 'onechanbara z2 chaos', '2016', 16, 44, 384, 119, 0, 29.99, 'Onechanbara Z2: Chaos is the latest entry in the Onechanbara series. Two sets of buxom vampire sisters battle through over a dozen stages of high-octane real-time swordplay. Fight off the invasion in gruesome detail, occasionally transforming into a demon for short bursts of added power and speed.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 SP1 / 8 / 8.1 /10 (64bit)<br></li><li><strong>Processor:</strong> IntelR Core i3-4130 / AMD FX-4170 Quad-Core<br></li><li><strong>Memory:</strong> 6 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 650/RADEON R7 370 (1GB VRAM)<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 10 GB available space<br></li><li><strong>Additional Notes:</strong> GamePad：Xinput , Require to Login Steam client</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 SP1 / 8 / 8.1 /10 (64bit)<br></li><li><strong>Processor:</strong> IntelR Core i5-4670 / AMD FX-8350 Eight-Core<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 750/RADEON R9 280 (1GB VRAM)<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 12 GB available space<br></li><li><strong>Additional Notes:</strong> GamePad：Xinput , Require to Login Steam client</li></ul>\'}', '0,13', '0,02', '0,04', '0,04', '0,24'),
(366, 'total war attila', '2015', 0, 118, 12297, 4469, 2147, 29.99, 'Against a darkening background of famine, disease and war, a new power is rising in the great steppes of the East. With a million horsemen at his back, the ultimate warrior king approaches, and his sights are set on Rome… The next instalment in the multi award-winning PC series that combines turn-based strategy with real-time tactics,...', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista*<br></li><li><strong>Processor:</strong> Intel Core 2 Duo 3 GHz<br></li><li><strong>Memory:</strong> 3 GB RAM<br></li><li><strong>Graphics:</strong> 512 MB NVIDIA GeForce 8800 GT, AMD Radeon HD 2900 XT or Intel HD 4000<br></li><li><strong>DirectX:</strong> Version 10<br></li><li><strong>Storage:</strong> 35 GB available space<br></li><li><strong>Additional Notes:</strong> PC integrated graphics chipsets require 64 bit Windows, e.g. Intel HD series.</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7*<br></li><li><strong>Processor:</strong> 2nd Generation Intel Core i5<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> 2 GB NVIDIA GeForce GTX 560 Ti or AMD Radeon HD 5870<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 35 GB available space<br></li><li><strong>Additional Notes:</strong> PC integrated graphics chipsets require 64 bit Windows, e.g. Intel HD series.</li></ul>\'}', '0,09', '0,13', '0', '0,02', '0,23'),
(367, 'rocket league', '2015', 0, 88, 242561, 21816, 5825, 14.99, 'Rocket League is a high-powered hybrid of arcade-style soccer and vehicular mayhem with easy-to-understand controls and fluid, physics-driven competition. Rocket League includes casual and competitive Online Matches, a fully-featured offline Season Mode, special “Mutators” that let you change the rules entirely, hockey and...', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 or Newer<br></li><li><strong>Processor:</strong> 2.4 GHz Dual core<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GTX 260 or ATI 4850<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 7 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 or Newer<br></li><li><strong>Processor:</strong> 2.5+ GHz Quad core<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GTX 660 or better, ATI 7950 or better<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 7 GB available space<br></li><li><strong>Additional Notes:</strong> Gamepad or Controller Recommended</li></ul>\'}', '0,06', '0,24', '0', '0,08', '0,37'),
(368, 'blowout', '2018', 0, 0, 0, 1, 0, 5.19, 'Lead your team to a space station that has been overrun by mutated alien parasites. Take out the enemy before they have a chance to zero in on the station\'s control center and threaten colonized space. Secure the station by eliminating the alien threat.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> XP<br></li><li><strong>Processor:</strong> Pentium 4 2.53 GHz or AMD equivalent<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> GeForce4 Ti 4600 or Radeon 9800 video card<br></li><li><strong>Storage:</strong> 1 GB available space<br></li><li><strong>Additional Notes:</strong> Microsoft DirectX 8.1 or higher</li></ul>\'}', '0,15', '0,1', '0', '0,03', '0,28'),
(369, 'senran kagura estival versus', '2017', 0, 50, 2837, 127, 1993, 24.99, 'Thrust into a parallel dimension, our buxom shinobi prepare for a new kind of beach-side battle. Can the islands’ hosts be trusted? Will the other schools play fair? Will there be time to enjoy the beach before the fighting starts? Will anyone manage to keep their clothes intact?', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7+<br></li><li><strong>Processor:</strong> Intel Core i3-550 @ 3.2 GHz (2-core)<br></li><li><strong>Memory:</strong> 6 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTS 450<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 19 GB available space<br></li><li><strong>Sound Card:</strong> Compatible with DirectX 11.0</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7+<br></li><li><strong>Processor:</strong> Intel Core i5-6400 @ 3.2 GHz / AMD A8-6500 @ 3.50 GHz<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 950 / AMD Radeon R7 360<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 19 GB available space<br></li><li><strong>Sound Card:</strong> Compatible with DirectX 11.0</li></ul>\'}', '0,13', '0,05', '0,17', '0,05', '0,4'),
(370, 'ys seven', '2017', 0, 21, 225, 22, 0, 19.99, 'Experience the first “modern-era” Ys game, now off the small screen for its worldwide PC debut! Features a full party system, dozens of unique combat skills, and a massive overworld to explore. Uncover the secret of the Five Great Dragons, and help Adol Christin save the day once again!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7, 8, 10<br></li><li><strong>Processor:</strong> Intel® Core™i5\\u30002.4GHz or higher<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> 1280x720 Intel® HD Graphics 4400<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 2 GB available space<br></li><li><strong>Sound Card:</strong> HD Audio</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7, 8, 10<br></li><li><strong>Processor:</strong> Intel® Core™i5-6400 CPU @2.70GHz (4 CPUs), ~2.7GHz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> 1920x1080 NVIDIA® Geforce® GTX950 or higher<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 2 GB available space<br></li><li><strong>Sound Card:</strong> HD Audio</li></ul>\'}', '0,14', '0', '0,08', '0,01', '0,22'),
(371, 'a boy and his blob', '2016', 0, 21, 253, 118, 108, 6.99, 'When Blobolonia is threatened by an evil Emperor, the blob comes to Earth looking for help. Instead, he finds a young boy. Help the blob dethrone the evil Emperor that\'s terrorizing Blobolonia and establish a friendship with the blob that will last a lifetime.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7-32Bit or Windows 8-32Bit<br></li><li><strong>Processor:</strong> AMD Athlon 64 X2 Dual Core Processor 4600+, 2.4GHz / Intel Pentium D 805 2.66GHz or higher<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce 9600 GT 512 MB / ATI Radeon HD 4650 1GB or higher | Shader Model 3+<br></li><li><strong>Storage:</strong> 3 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7-64Bit or Windows 8-64Bit<br></li><li><strong>Processor:</strong> AMD Athlon 7850 Dual Core Processor 2.8GHz / Intel Core 2 Duo E7500 2.93 GHz<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce 9600 GT 1GB / ATI Radeon HD 4650 1GB | Shader Model 3+<br></li><li><strong>Storage:</strong> 3 GB available space</li></ul>\'}', '0,19', '0,02', '0', '0,02', '0,22'),
(372, 'battleborn', '2016', 0, 60, 5692, 3494, 652, 0.00, 'FREE PVP TRIAL AVAILABLE NOW! A tremendous band of badass heroes fight to protect the universe’s very last star from a mysterious evil in this Hero Shooter by the creators of Borderlands.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® 7 x64-bit or Later<br></li><li><strong>Processor:</strong> Intel i5-750 / AMD Phenom IIx4 945<br></li><li><strong>Memory:</strong> 6 GB RAM<br></li><li><strong>Graphics:</strong> AMD HD 6870/ NVIDIA GeForce GTX 460 or better, PhysX support<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 30 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 11 Compliant<br></li><li><strong>Additional Notes:</strong> Initial installation requires an internet connection for Steam authentication, and gameplay; software installations require (included with the game) include Steam Client, DirectX 11, NVidia PhysX, .Net Framework 4.5, Visual C++ Redistributable 2010, and Visual C++ Redistributable 2012.</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® 7 x64-bit or Later<br></li><li><strong>Processor:</strong> Intel i5-750 / AMD Phenom IIx4 945<br></li><li><strong>Memory:</strong> 6 GB RAM<br></li><li><strong>Graphics:</strong> AMD HD 7850/ NVIDIA GeForce GTX 660 or better, PhysX support<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 50 GB available space</li></ul>\'}', '0,2', '0,15', '0,01', '0,06', '0,42'),
(373, 'castlevania lords of shadow 2', '2014', 16, 56, 2390, 479, 732, 24.99, 'Dracula, weak and yearning release from immortality, must reclaim his powers and defeat Satan. An epic fantasy adventure set in an expansive modern-day world!Awoken after centuries of slumber, weakened and yearning for release from his immortal bonds, Dracula must reclaim his powers and make a pact with Death, to defeat Satan and gain...', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP Service Pack 3<br></li><li><strong>Processor:</strong> 2.4Ghz Intel Core 2 Duo or AMD equivalent<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> Direct X9 compatible video card 512Mb RAM<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 10 GB available space<br></li><li><strong>Sound Card:</strong> DirectSound supported with Direct X9.0c or better<br></li><li><strong>Additional Notes:</strong> Keyboard &amp; Mouse</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 or higher<br></li><li><strong>Processor:</strong> Quad Core CPU<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> Direct X11 compatible video card with 1024Mb RAM<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 10 GB available space<br></li><li><strong>Sound Card:</strong> DirectSound supported with Direct X9.0c or better<br></li><li><strong>Additional Notes:</strong> For the best experience we highly recommend using a XInput compatible Gamepad.</li></ul>\'}', '0,06', '0,23', '0,02', '0,05', '0,36'),
(374, 'tropico 3', '2009', 0, 0, 1338, 176, 291, 7.99, 'Become the dictator of a remote island during the Cold War. Charm, persuade, intimidate, oppress, or cheat your people to stay in power! Are you a kind and generous leader? A corrupt and ruthless tyrant ruling with an iron fist?', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>Operating System: </strong>Microsoft® Windows® XP/Vista/7<br> </li><li><strong>Processor: </strong>CPU with 2.5 GHz<br> </li><li><strong>Memory: </strong>1 GB RAM<br> </li><li><strong>Hard Disk Space: </strong>5 GB Available HDD Space<br> </li><li><strong>Video Card: </strong>128 MB 3D Graphic Card with Shader Model 3.0 support<br> </li><li><strong>Sound Card: </strong>16-bit Sound Card<br> </li><li><strong>DirectX® Version: </strong>DirectX® 9.0c<br> </li></ul>\'}', '0,15', '0,06', '0,03', '0,03', '0,27'),
(375, 'tales of berseria', '2017', 0, 51, 7427, 536, 2398, 39.99, 'Players embark on a journey of self-discovery as they assume the role of Velvet, a young woman whose once kind demeanor has been replaced and overcome with a festering anger and hatred after a traumatic experience three years prior to the events within Tales of Berseria.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li>Requires a 64-bit processor and operating system<br></li><li><strong>OS:</strong> Windows 7, 8, 10 (64-bit)<br></li><li><strong>Processor:</strong> Intel Core 2 Duo E8400 3.0GHz or AMD Phenom II X2 550, 3.1GHz<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> GeForce 9800 GTX or AMD Radeon HD 4850<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 15 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 11 compatible</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li>Requires a 64-bit processor and operating system<br></li><li><strong>OS:</strong> Windows 7, 8, 10 (64-bit)<br></li><li><strong>Processor:</strong> Intel Core i5-750, 2.66GHz or AMD Phenom II X4 965, 3.2GHz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> GeForce GTX 560 or Radeon HD 7870<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 15 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 11 compatible</li></ul>\'}', '0', '0', '0,33', '0', '0,33');
INSERT INTO `jeux` (`id_jeu`, `nom_jeu`, `annee`, `age_requis`, `nb_succes`, `nb_avis_pos`, `nb_avis_neg`, `temps_jeu_moyen`, `prix`, `description`, `configuration`, `ventes_AN`, `ventes_EU`, `ventes_JP`, `ventes_Autre`, `ventes_Global`) VALUES
(376, 'lost planet 3', '2013', 0, 50, 1597, 1002, 155, 19.99, 'The extreme and unpredictable conditions that characterized the Lost Planet series return, harsher than ever before. Lost Planet 3 reveals new truths about the foreboding planet and the colonial history of E.D.N. III.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP<br></li><li><strong>Processor:</strong> Dual core CPU 2.5 GHz<br></li><li><strong>Memory:</strong> 3 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA® GeForce® 9800 or better, ATI Radeon™ HD 4770 or better<br></li><li><strong>Storage:</strong> 16 GB available space<br></li><li><strong>Sound Card:</strong> Standard audio device</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7<br></li><li><strong>Processor:</strong> Quad core 2.7 GHz or better<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA® GeForce® GTX 460 or better<br></li><li><strong>Storage:</strong> 16 GB available space<br></li><li><strong>Sound Card:</strong> Standard audio device</li></ul>\'}', '0,14', '0,13', '0,07', '0,05', '0,38'),
(377, 'eve online', '2010', 0, 0, 8317, 2832, 5123, 0.00, 'EVE Online is a community-driven spaceship MMO where players can play free, choosing their own path from countless options. Experience space exploration, immense PvP and PvE battles, mining, industry and a thriving player economy in an ever-expanding sandbox.', '{\'minimum\': \'<strong>Minimum: </strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7<br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Dual Core @ 2.0 GHz, AMD Dual Core @ 2.0 GHz)<br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2 GB<br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 20 GB Free Space <br>\\t\\t\\t\\t\\t</li><li><strong>Video:</strong> AMD Radeon 2600 XT or NVIDIA GeForce 8600 GTS<br>\\t\\t\\t\\t\\t</li><li><strong>Network:</strong> ADSL connection (or faster)</li></ul>\', \'recommended\': \'<strong>Recommended: </strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 10<br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel i7-7700 or AMD Ryzen 7 1700 @ 3.6 GHz or greater<br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 16 GB or greater<br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 20 GB free space <br>\\t\\t\\t\\t\\t</li><li><strong>Video:</strong> NVIDIA Geforce GTX 1060, AMD Radeon RX 580 or better with at least 4 GB VRAM<br>\\t\\t\\t\\t\\t</li><li><strong>Network:</strong> ADSL connection or faster</li></ul>\'}', '0', '0,19', '0', '0,02', '0,22'),
(378, 'ride', '2015', 0, 50, 1053, 361, 0, 14.99, 'Bikes from the world\'s most beloved motorcycle manufacturers, breathtaking races, and a round-the-world trip taking in 15 different locations, all this and more in the new videogame: RIDE.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista SP2 / Windows 7 SP1 / Windows 8 / Windows 8.1<br></li><li><strong>Processor:</strong> Intel Core i3-530 @ 2.93 GHz / AMD Phenom II X4 810 @ 2.60 GHz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 460 @ 1GB / ATI Radeon HD 6790 @ 1GB*<br></li><li><strong>DirectX:</strong> Version 10<br></li><li><strong>Storage:</strong> 35 GB available space<br></li><li><strong>Sound Card:</strong> DirectX compatible<br></li><li><strong>Additional Notes:</strong> *Laptop versions of graphics cards may work but are not officially supported.</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 SP1 64-Bit / Windows 8 64-Bit / Windows 8.1 64-Bit<br></li><li><strong>Processor:</strong> Intel Core i7-3770 @ 3.4 GHz / AMD FX-8350 @ 4.0 GHz<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 780 / AMD Radeon R9 290X*<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Additional Notes:</strong> *Laptop versions of graphics cards may work but are not officially supported.</li></ul>\'}', '0,07', '0,29', '0,04', '0,05', '0,45'),
(379, 'steins;gate', '2016', 0, 42, 5720, 130, 2628, 23.99, 'Developed by 5pb. and Nitroplus, STEINS;GATE was awarded Famitsu magazine\'s coveted annual Game of Excellence award and was voted one of the most emotionally charged “tear-inducing games” ever made, in a Famitsu poll. It is a gripping and moving Visual Novel, which has already spawned manga and anime adaptations.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows7/8.1/10<br></li><li><strong>Processor:</strong> Core i3 of Sandy Bridge generation or better<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> Intel HD Graphics Series (It needs 1GB memory allocation)<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 13 GB available space<br></li><li><strong>Sound Card:</strong> Sound Devices compartible Direct Sound<br></li><li><strong>Additional Notes:</strong> 1280x720 or better required (Recommended 1920x1080)</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows7/8.1/10 (64bit ver)<br></li><li><strong>Processor:</strong> Core i5 of Ivy Bridge generation or better<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> Geforce (VRAM 1GB or better)<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 13 GB available space<br></li><li><strong>Sound Card:</strong> Sound Devices compartible Direct Sound<br></li><li><strong>Additional Notes:</strong> 1280x720 or better required (Recommended 1920x1080)</li></ul>\'}', '0,08', '0,13', '0,27', '0,06', '0,54'),
(380, 'akibas trip undead & undressed', '2015', 0, 46, 2112, 297, 409, 14.99, 'In Tokyo’s popular ”Electric Town” district, Akihabara, vampires called “Synthisters” walk among us. You must identify and dispose of them the only way you know how – by engaging them in hand-to-hand combat in order to strip them of their clothes so their bodies melt away in the sunlight.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista (SP2)<br></li><li><strong>Processor:</strong> Intel Core i3-530 @ 2.93 GHz / AMD Phenom II X4 810 @ 2.60 GHz<br></li><li><strong>Memory:</strong> 6 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTS 450 / ATI Radeon HD 5870 (1GB VRAM)<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 3 GB available space<br></li><li><strong>Sound Card:</strong> Compatible with DirectX 11</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista (SP2), Windows 7, Windows 8<br></li><li><strong>Processor:</strong> Intel Core i5-2500K @ 3.3 GHz<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 760 (4GB VRAM)<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 3 GB available space<br></li><li><strong>Sound Card:</strong> Compatible with DirectX 11</li></ul>\'}', '0,22', '0,03', '0,13', '0,06', '0,43'),
(381, 'the bards tale', '2009', 0, 51, 644, 188, 43, 6.99, 'You are the Bard, a selfish rogue weary of pointless sub-quests and rat-infested cellars. Now includes original classic games The Bard’s Tale 1, 2 &amp; 3!', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7<br></li><li><strong>Processor:</strong> Pentium 4 2Ghz / AMD AthlonXP 2400<br></li><li><strong>Memory:</strong> 512Mb<br></li><li><strong>Graphics:</strong> GeForce FX5700 or better / ATI Radeon 9600 or better<br></li><li><strong>DirectX®:</strong> 9.0c<br></li><li><strong>Hard Drive:</strong> 6GB of free space<br></li><li><strong>Sound:</strong> DirectX 9 Compatible Sound Card</li></ul>\'}', '0,18', '0,1', '0', '0,03', '0,31'),
(382, 'de blob 2', '2017', 0, 25, 29, 5, 0, 17.99, 'In de Blob 2 Comrade Black and the Inkies are back with a whole new plot to rid the world of color. Set off on an action-packed color adventure where custom paints, patterns and music bring the world to life. De Blob 2 is a creative evolution driven by your imagination.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 (32 or 64bit), Windows 8, Windows 10<br></li><li><strong>Processor:</strong> Dual-Core CPU 3.0GHz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> GeForce 440 with 1 GB VRAM<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 12 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 (32 or 64bit), Windows 8, Windows 10<br></li><li><strong>Processor:</strong> Quad-Core CPU 3.0GHz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> GeForce 760 with 2 GB VRAM<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 12 GB available space</li></ul>\'}', '0,41', '0,19', '0', '0,07', '0,66'),
(383, 'grid autosport', '2014', 0, 60, 4969, 1610, 228, 24.99, 'It’s all about the teams, the rivals and the race as you become driver for hire, specialising in your favourite disciplines or conquering them all in an intense world of professional motorsport.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista, Windows 7 or Windows 8<br></li><li><strong>Processor:</strong> Intel Core 2 Duo @ 2.4Ghz or AMD Athlon X2 5400+<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> Intel HD3000 or AMD HD2000 Series or NVIDIA Geforce 8000 Series Series<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 15 GB available space<br></li><li><strong>Sound Card:</strong> Direct X compatible soundcard<br></li><li><strong>Additional Notes:</strong> Supported Graphics Cards •Intel HD3000 Series, HD4000 Series, HD5000 Series •\\tAMD Radeon HD2000 Series, HD3000 Series, HD4000 Series, HD5000 Series, HD6000 Series, HD7000 Series, R7 Series, R9 Series •\\tNVIDIA GeForce 8000 Series, 9000 Series, GTX200 Series, GTX400 Series, GTX500 Series, GTX600 Series, GTX700 Series •\\tAMD Fusion A8 or higher</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista 64 bit, Windows 7 64 bit or Windows 8 64 bit<br></li><li><strong>Processor:</strong> Intel Core i7 or AMD FX Series<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> Intel HD5200 or AMD HD7000 Series or NVIDIA GTX600 Series minimum 1GB RAM<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 20 GB available space<br></li><li><strong>Sound Card:</strong> Direct X compatible soundcard</li></ul>\'}', '0,08', '0,19', '0,01', '0,05', '0,34'),
(384, 'project snowblind', '2007', 0, 0, 175, 61, 0, 3.99, 'Experience the dramatic intensity of the frontlines of a war through the eyes of the first of a new breed of super soldiers in this gritty and epic first-person action game. An augmented super-soldier must stop a renegade regime from eradicating the civilized world. Hong Kong, 2065. 2nd Lt.', '{\'minimum\': \'<p><strong>Minimum: </strong>IBM PC or 100% compatible, Microsoft Windows 2000/XP, Pentium IV, 1.5 GHz (Or AMD Athlon XP equivalent) processor, 100% DirectX 64 MB 3D Accelerated video card with Pixel Shader v1.1 Capability, 256 MB System RAM, 100% DirectX 9 Compatible Sound Card, 3GB free uncompressed hard drive space (additional space may be necessary for saved games), 100% Windows 2000/XP compatible Mouse and Keyboard</p>\\r\\n\\t\\t\\t\\t\\t<p>As stated on the Project: Snowblind box, laptops and integrated video chips may work with Project: Snowblind, but are not supported. Should you incur problems while running the game on an integrated video chip, Eidos Tech Support will not be able to help you.</p>\\r\\n\\t\\t\\t\\t\\t<p><strong>Recommended: </strong>Pentium IV, 2.4 Ghz (or AMD Athlon XPequivalent) or greater processor, 512 MB System RAM, 100% DirectX 9 128MB 3D Graphics Card with Pixel Shader 2.0 support, 3GB of Hard Drive Space</p>\\r\\n\\t\\t\\t\\t\\t<p>Supported Video Chipsets:<br>nVidia GeForce 3Ti/4Ti/FX/6000 series - <em>Note: GeForce MX series is NOT SUPPORTED.</em> ATI Radeon 8500/9xxx or higher. </p>\'}', '0,18', '0,1', '0', '0,03', '0,32'),
(385, 'the wolf among us', '2013', 16, 35, 21127, 517, 675, 11.99, 'From the makers of the 2012 Game of the Year: The Walking Dead, comes a gritty, violent and mature thriller based on the award-winning Fables comic books (DC Comics/Vertigo). As Bigby Wolf - THE big bad wolf - you will discover that a brutal, bloody murder is just a taste of things to come in a game series where your every decision can...', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP Service Pack 3<br></li><li><strong>Processor:</strong> Core 2 Duo 2GHz or equivalent<br></li><li><strong>Memory:</strong> 3 GB RAM<br></li><li><strong>Graphics:</strong> ATI or NVidia card w/ 512 MB RAM<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 2 GB available space<br></li><li><strong>Sound Card:</strong> Direct X 9.0c sound device<br></li><li><strong>Additional Notes:</strong> Not recommended for Intel integrated graphics</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7<br></li><li><strong>Processor:</strong> Core 2 Duo 2.3 Ghz or equivalent<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> ATI or NVidia card w/ 1024 MB RAM<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 2 GB available space<br></li><li><strong>Sound Card:</strong> Direct X 9.0c sound device<br></li><li><strong>Additional Notes:</strong> Not recommended for Intel integrated graphics</li></ul>\'}', '0,26', '0,15', '0', '0,08', '0,49'),
(386, 'fairy fencer f', '2015', 0, 29, 1997, 208, 229, 15.49, 'Long ago, the Vile God and the Goddess waged war with each other. Equally matched, they were sealed away in another world… Now a lazy young man named Fang somehow finds himself a key part of this war he’d really rather not deal with, but fate beckons in this uncommon RPG!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP<br></li><li><strong>Processor:</strong> 2.13GHz Intel Core2 Duo or equivalent<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> DirectX 9.0c compatible graphics card with 512Mb RAM and support for v3 shaders<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 5 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c compatible sound card</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 or later<br></li><li><strong>Processor:</strong> 3GHz Intel i3 or equivalent<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> DirectX 9.0c compatible graphics card with 1GB RAM and support for v3 shaders<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 5 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c compatible sound card</li></ul>\'}', '0,05', '0,05', '0,09', '0,02', '0,2'),
(387, 'earth defense force insect armageddon', '2011', 0, 50, 731, 95, 253, 6.99, 'Thousands of giant insects and aliens once again ravage the earth, and only the Earth Defense Force can stop them.', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP SP3, Windows Vista SP1, Windows 7<br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 2.0Ghz Dual core CPU (any Core 2 Duo or AMD X2 or better)<br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1GB (XP), 2GB (Vista), 2GB (Windows 7)<br>\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space:</strong> 6 GB space free \\t<br>\\t\\t\\t\\t\\t</li><li><strong>Video Card:</strong> 512MB Video Card using Shader Model 3 or higher (Performance equivalent to an AMD Radeon 4350 or NVIDIA GeForce 7900)<br>\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 9.0c\\t<br>\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Any Quad-core Intel or AMD Processor<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1GB (XP), 2GB (Vista), 2GB (Windows 7)<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space:</strong> 6 GB space free \\t<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Video Card:</strong> 1 GB Video Card using Shader Model 3 or higher (Performance equivalent to an NVIDIA 9800 or better)<br>\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 9.0c<br>\\t\\t\\t\\t\\t</li></ul>\'}', '0,16', '0,09', '0,11', '0,03', '0,39'),
(388, 'xcom 2', '2016', 0, 88, 28774, 7018, 1891, 34.99, 'XCOM 2 is the sequel to XCOM: Enemy Unknown, the 2012 award-winning strategy game of the year. Earth has changed and is now under alien rule. Facing impossible odds you must rebuild XCOM, and ignite a global resistance to reclaim our world and save humanity.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® 7, 64-bit<br></li><li><strong>Processor:</strong> Intel Core 2 Duo E4700 2.6 GHz or AMD Phenom 9950 Quad Core 2.6 GHz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> 1GB ATI Radeon HD 5770, 1GB NVIDIA GeForce GTX 460 or better<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 45 GB available space<br></li><li><strong>Sound Card:</strong> DirectX compatible sound card<br></li><li><strong>Additional Notes:</strong> Initial installation requires one-time Internet connection for Steam authentication; software installations required (included with the game) include Steam Client, Microsoft Visual C++2012 and 2013 Runtime Libraries and Microsoft DirectX.</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® 7, 64-bit<br></li><li><strong>Processor:</strong> 3GHz Quad Core<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> 2GB ATI Radeon HD 7970, 2GB NVIDIA GeForce GTX 770 or better<br></li><li><strong>Storage:</strong> 45 GB available space<br></li><li><strong>Sound Card:</strong> DirectX compatible sound card</li></ul>\'}', '0,11', '0,13', '0', '0,03', '0,26'),
(389, 'way of the samurai 4', '2015', 0, 50, 927, 248, 0, 18.99, 'Way of the Samurai 4 takes place in the humble port town of Amihama during the mid 19th Century, several years after the arrival of the “black ships” from the West ended Japan’s long history of cultural isolation.', '{\'minimum\': \'<strong>Минимальные:</strong><br><ul class=\"bb_ul\"><li><strong>ОС:</strong> Windows 7<br></li><li><strong>Процессор:</strong> 2.13GHz Intel Core2 Duo or equivalent<br></li><li><strong>Оперативная память:</strong> 1 GB ОЗУ<br></li><li><strong>Видеокарта:</strong> DirectX 9.0c compatible graphics card with 64Mb RAM and support for v3 shaders<br></li><li><strong>DirectX:</strong> Версии 9.0c<br></li><li><strong>Место на диске:</strong> 7 GB<br></li><li><strong>Звуковая карта:</strong> DirectX 9.0c compatible sound card</li></ul>\', \'recommended\': \'<strong>Рекомендованные:</strong><br><ul class=\"bb_ul\"><li><strong>ОС:</strong> Windows 7 or later<br></li><li><strong>Процессор:</strong> 3GHz Intel i3 or equivalent<br></li><li><strong>Оперативная память:</strong> 4 GB ОЗУ<br></li><li><strong>Видеокарта:</strong> DirectX 9.0c compatible graphics card with 128Mb RAM and support for v3 shaders<br></li><li><strong>DirectX:</strong> Версии 9.0c<br></li><li><strong>Место на диске:</strong> 7 GB<br></li><li><strong>Звуковая карта:</strong> DirectX 9.0c compatible sound card</li></ul>\'}', '0', '0,03', '0,16', '0,01', '0,2'),
(390, 'mdk', '2009', 0, 0, 138, 45, 0, 6.99, 'ON A GOOD DAY, ONLY 2.5 MILLION PEOPLE WILL DIE. As vast alien mining cities suck the power and minerals from every major metropolis on Earth simultaneously, time is of the essence as millions of civilians are expiring by the second.', '{\'minimum\': \'\\n\\t\\t\\t\\t\\t\\t\\t<ul>\\n\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>OS:</strong> Windows</li>\\n\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>Processor:</strong> Pentium 300Mhz</li>\\n\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>Memory:</strong> 64MB</li>\\n\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>Graphics:</strong> DirectX</li>\\n\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>DirectX&reg;:</strong> 7</li>\\n\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>Hard Drive:</strong> 650MB</li>\\n\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>Sound:</strong> DirectSound</li>\\n\\t\\t\\t\\t\\t\\t\\t</ul>\\n\\t\\t\\t\\t\\t\\t\\t\'}', '0,11', '0,08', '0', '0,01', '0,2'),
(391, 'code of princess', '2016', 0, 14, 125, 90, 0, 10.99, 'Code of Princess offers players an exciting yet unconventional experience, deftly blending the combo-heavy fighting gameplay of beat ‘em ups with the stat-boosting character customization of RPGs.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 / 8.1 / 10<br></li><li><strong>Processor:</strong> Intel Core 2 Duo 2 GHz or faster processor<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> OpenGL 1.5 compliant video card<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 4 GB available space<br></li><li><strong>Sound Card:</strong> DirectSound<br></li><li><strong>Additional Notes:</strong> Controller recommended.</li></ul>\'}', '0,16', '0', '0,03', '0,01', '0,2'),
(392, 'sid meiers pirates!', '', 0, 0, 0, 0, 0, 0.00, '0', '0', '0,4', '0,06', '0', '0,04', '0,5'),
(393, 'mega man legacy collection', '', 0, 0, 0, 0, 0, 0.00, '0', '0', '0,19', '0', '0,05', '0,03', '0,27'),
(394, 'zombie army trilogy', '2015', 0, 68, 8472, 1330, 400, 29.99, 'The cult horror shooter series comes to an apocalyptic conclusion with an epic new third chapter, a heart-pumping new horde mode, and remastered editions of the best-selling Nazi Zombie Army 1 &amp; 2.', '{\'minimum\': \'<strong>最低配置:</strong><br><ul class=\"bb_ul\"><li><strong>操作系统:</strong> Microsoft® Windows® Vista (Service Pack 2) or Windows® 7 or Windows® 8. Windows® XP is NOT supported.<br></li><li><strong>处理器:</strong> Dual-core CPU with SSE3 (Intel® Pentium® D 3GHz / AMD Athlon™ 64 X2 4200) or better<br></li><li><strong>内存:</strong> 2 GB RAM<br></li><li><strong>图形:</strong> Microsoft® DirectX® 10.0 compatible graphics card with 512 MB of memory (ATI Radeon™ HD 5870) or better<br></li><li><strong>DirectX 版本:</strong> 11<br></li><li><strong>存储空间:</strong> 需要 15 GB 可用空间<br></li><li><strong>声卡:</strong> Microsoft® DirectX® 10.0 compatible sound card or better<br></li><li><strong>附注事项:</strong> Windows® XP is NOT supported. Ensure graphics and audio drivers are up to date.</li></ul>\'}', '0,08', '0,17', '0', '0,04', '0,3'),
(395, 'the great escape', '2016', 0, 0, 18, 9, 240, 2.79, 'The Great Escape is a infinity runner where player guides a spaceship through a narrow tunnel filled with incoming obstacles. The more you advance harder the hazards become.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP, Vista or 7<br></li><li><strong>Processor:</strong> 1GHz or faster processor<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 500 MB available space</li></ul>\'}', '0,15', '0,08', '0', '0,02', '0,26'),
(396, 'the great escape', '2016', 0, 0, 18, 9, 240, 2.79, 'The Great Escape is a infinity runner where player guides a spaceship through a narrow tunnel filled with incoming obstacles. The more you advance harder the hazards become.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP, Vista or 7<br></li><li><strong>Processor:</strong> 1GHz or faster processor<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 500 MB available space</li></ul>\'}', '0,15', '0,08', '0', '0,02', '0,26'),
(397, 'bound by flame', '2014', 0, 41, 1843, 943, 731, 14.99, 'You are a mercenary possessed by a flame demon in a desperate world ravaged by seven Ice Lords. In this RPG where every choice counts, you will have to choose between unleashing the powers of the beast within and rejecting its demonic influence.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> WINDOWS XP SP3/WINDOWS VISTA SP2/WINDOWS 7/WINDOWS 8<br></li><li><strong>Processor:</strong> AMD/INTEL DUAL-CORE 2.2 GHZ<br></li><li><strong>Memory:</strong> 2048 MB RAM<br></li><li><strong>Graphics:</strong> 512 MB 100% DIRECTX 9 AND SHADERS 4.0 COMPATIBLE ATI RADEON HD 4850/NVIDIA GEFORCE 8800 GT OR HIGHER<br></li><li><strong>Storage:</strong> 6 GB available space<br></li><li><strong>Sound Card:</strong> DIRECTX 9 COMPATIBLE<br></li><li><strong>Additional Notes:</strong> INTERNET CONNECTION REQUIRED FOR THE GAME ACTIVATION</li></ul>\'}', '0,07', '0,09', '0', '0,04', '0,2'),
(398, 'conflict denied ops', '2008', 0, 0, 89, 103, 0, 3.99, '*This is a single player only title*Venezuela is left in a state of civil war after the government was brutally overthrown by a military coup. With factions fighting to reinstate democracy, the U.S. government has offered their assistance, though the new government regime has threatened to deploy nuclear weapons if the U.S.', '{\'minimum\': \'<strong>Minimum: </strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>Supported OS: </strong> Microsoft® Windows® XP, 2000 or Vista (admin rights required)<br>\\t\\t\\t\\t\\t</li><li><strong>Processor: </strong> 2.0 Ghz Intel Pentium 4, AMD Athlon XP or equivalent processor<br>\\t\\t\\t\\t\\t</li><li><strong>Graphics: </strong> 128 MB DirectX 9.0c card with full Shader 3.0 support<br>\\t\\t\\t\\t\\t</li><li><strong>DirectX Version: </strong>DirectX 9.0c<br>\\t\\t\\t\\t\\t</li><li><strong>Memory: </strong> 1024 MB RAM<br>\\t\\t\\t\\t\\t</li><li><strong>Sound: </strong> DirectX 9.0c compatible sound card<br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive: </strong> 7 GB uncompressed free hard disk space<br>\\t\\t\\t\\t\\t</li><li><strong>input Devices:</strong> Keyboard and mouse or Xbox 360 Controller</li></ul><strong>Recommended:</strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>Processor:</strong> Intel Core 2 Duo / Athlon 64 X2 or Equivalent Multi-core CPU<br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2 GB RAM (required for 8-player multiplayer games)<br>\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 256mb Direct X 9.0c card with full Shader 3.0 support (NVIDIA 7900GS or better)<br>\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> Sound Blaster® X-Fi™ series<br>\\t\\t\\t\\t\\t</li><li><strong>Input devices:</strong> Keyboard and 3 button mouse or Xbox 360 Controller</li></ul><strong>Graphics Cards supported:</strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li>All DirectX 9.0c graphics cards with full Shader Model 3.0 support.<br>\\t\\t\\t\\t\\t</li><li>GeForce 6800, 7300, 7600, 7800, 7900, 7950, 8400, 8500, 8600, 8800<br>\\t\\t\\t\\t\\t</li><li>Radeon X1300, X1600, X1800, X1900, X2400, X2600, X2900</li></ul><strong>Graphics Cards not supported:</strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li>Any graphics card which does not support DirectX 9.0c or Shader Model 3.0 fully.</li></ul>\'}', '0,13', '0,2', '0', '0,05', '0,39'),
(399, 'sniper elite', '2009', 0, 0, 1181, 377, 262, 5.59, 'As World War II draws to a close, the first covert battles of the Cold War begin. Caught in the life and death struggle between Soviets and Germans in war-torn Berlin, you control the fate of a lone American OSS Sniper.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP / Vista<br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 1GHz Pentium CPU or equivalent<br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 256Mb RAM<br>\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> GeForce2 32Mb or equivalent<br>\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX 9.0c<br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 4Gb free hard disk space<br>\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> Windows compatible sound card<br>\\t\\t\\t\\t\\t</li></ul>\'}', '0,25', '0,13', '0', '0,03', '0,42'),
(400, 'air conflicts secret wars', '2011', 0, 25, 167, 111, 20, 4.79, 'Soar through the unfriendly skies in Air Conflicts: Secret Wars - an arcade flight simulation set in World War I and II era. Buy before July 21st and save!', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> WINDOWS XP/WINDOWS 7/WINDOWS VISTA<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> INTEL/AMD CPU (1.1GHZ+)<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1 GB RAM<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> SHADER 3.0 COMPATIBLE GRAPHICS CARD WITH 256 MB RAM<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 4.5GB HDD SPACE<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> WINDOWS XP/WINDOWS 7/WINDOWS VISTA<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> INTEL/AMD CPU (1.8GHZ+)<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1.5 GB RAM<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> GEFORCE 9X, OR HIGHER GRAPHICS CARD WITH 512MB RAM<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 4.5GB HDD SPACE<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0,16', '0,1', '0', '0,05', '0,3'),
(401, 'risen', '2009', 0, 0, 3848, 585, 994, 7.99, 'The island Faranga needs a new hero, you! Delve into a gritty, raw and atmospheric fantasy world in which every action has a consequence. In the epic world of Risen, filled with mysterious earthquakes, fearsome monsters and unimaginable treasures, forge your path with the sword, learn the art of staff fighting or become a powerful mage.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP™ (with Service Pack 3)<br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 2 GHz Intel® Pentium™ 4 Single-core Processor<br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1 GB RAM<br>\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 256 MB DirectX™ 9.0c compatible graphics card (nVidia® GeForce® 7900/ATI Radeon™ X1800 or better)<br>\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX™ 9.0c compatible graphic card driver<br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 2.5 GB free Hard Drive space<br>\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> 100% DirectX™ 9.0c compatible sound card<br>\\t\\t\\t\\t\\t</li><li><strong>Controller Support:</strong> Keyboard, Mouse<br>\\t\\t\\t\\t\\t</li></ul>\'}', '0,07', '0,22', '0', '0,04', '0,33'),
(402, 'revolt', '2016', 0, 0, 5, 6, 0, 3.99, 'Revolt is a 3D dual stick shooter set in the future, where a devastating virus has wiped out most of humanity, and machines have risen up to exterminate the remains of the population. You must take control of Guy, a resistance fighter who has infiltrated into enemy territory, to battle against the robotic hordes and blast through a...', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP<br></li><li><strong>Storage:</strong> 250 MB available space</li></ul>\'}', '0,25', '0,11', '0', '0,01', '0,37'),
(403, 'conception ii children of the seven stars', '2016', 0, 51, 389, 67, 137, 14.99, 'It\'s time for classmating! Monsters have invaded the world of Aterra, and only a few special individuals, imbued with the power of the Star God, are equipped to fight it. Combine your Star power to make magical Star Children to boost up your forces in battle!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7<br></li><li><strong>Processor:</strong> Intel Core i3-530 CPU 2.93 GHz or better<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX650 1GB or AMD HD 7700 1GB(DirectX 11 graphic card required)<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 8 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c compatible sound card</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7<br></li><li><strong>Processor:</strong> Intel Core i5-3570K CPU 3.40GHz<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX650 1GB or AMD HD 7700 1GB(DirectX 11 graphic card required)<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 8 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c compatible sound card</li></ul>\'}', '0,22', '0', '0,07', '0,03', '0,31'),
(404, 'descent', '2014', 0, 0, 263, 10, 0, 7.19, 'Prepare To Start Your Descent.Sensory overload in 360° 3-D.Welcome to Descent™ - 27 levels of the most mind-bending, stomach-churning action game ever. Featuring true 3-Dimensional worlds with light source shading, texture mapping, 3-D morphing, directional sound effects and sizzling music, this is technology taken to the limit.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP, 7, 8<br></li><li><strong>Processor:</strong> 1 Gigahertz or faster<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> 3D graphics card compatible with DirectX 7 or better<br></li><li><strong>DirectX:</strong> Version 7.0<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 32 MB available space<br></li><li><strong>Sound Card:</strong> Sound Blaster compatible<br></li><li><strong>Additional Notes:</strong> Please visit Interplay\\\'s support site for the optimal settings for Descent 3\\\'s setup.</li></ul>\'}', '0,11', '0,07', '0', '0,01', '0,19'),
(405, 'might & magic clash of heroes', '2011', 0, 14, 1293, 157, 1595, 8.59, 'Scattered across five different regions, five special heroes must travel their own dangerous paths to grow in strength, unravel a demonic plot & ultimately save the world from chaos.', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® XP / Windows Vista® / Windows® 7<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 3.0 GHz Pentium 4 or 1.8 GHz AMD Athlon64 3000+<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1 GB Windows XP / 1 GB Windows Vista – Windows 7<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 256 MB DirectX® 9.0-compliant card with Shader Model 3.0 or higher (*see supported list)<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX 9.0c or higher<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 1.6 GB<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX 9.0-compliant sound card<br>*Supported Video Cards at Time of Release: ATI Radeon™ HD 2000/ HD 3000/ HD 4000/ HD 5000/ HD 6000 series<br><br>\\t\\t\\t\\t\\t\\t\\tNVIDIA® GeForce® 7600GS / 8 / 9 / 100 / 200 / 300 / 400 / 500 series<br>\\t\\t\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br>\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 2.0 GHz Intel® Core™2 Duo or AMD Athlon™ 64 X2 6000+ or better<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2 GB<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 512 MB DirectX 9.0-compliant card with Shader Model 3.0 or higher (*see supported list)<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX 9.0c or higher<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 1.6 GB<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX 9.0-compliant sound card<br>*Supported Video Cards at Time of Release: ATI Radeon™ HD 2000/ HD 3000/ HD 4000/ HD 5000/ HD 6000 series<br><br>\\t\\t\\t\\t\\t\\t\\tNVIDIA® GeForce® 7600GS / 8 / 9 / 100 / 200 / 300 / 400 / 500 series<br>\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0,16', '0,02', '0', '0,01', '0,19'),
(406, 'sudeki', '2014', 0, 0, 413, 70, 217, 4.99, 'Sudeki, a world torn apart into light, shadow and dark. Rent asunder by deceit and betrayal, the land cries out for a peace that only four united heroes can bring. Beyond the protective walls of Illumina Castle lie miles of pastoral, rolling countryside, though once a serene landscape, the Aklorian forces have transformed the countryside...', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP<br></li><li><strong>Processor:</strong> 1.8GHz<br></li><li><strong>Memory:</strong> 512 MB RAM<br></li><li><strong>Graphics:</strong> 128MB Pixel Shader 2.0 capable graphics card or better<br></li><li><strong>Storage:</strong> 5.6 GB available space<br></li><li><strong>Sound Card:</strong> DirectX Compatible</li></ul>\'}', '0,14', '0,04', '0', '0,01', '0,19'),
(407, 'quake', '2007', 0, 0, 2618, 136, 167, 3.99, 'Rage through 32 single player levels and 6 deathmatch levels of sheer terror and fully immersive sound and lighting. Arm yourself against the cannibalistic Ogre, fiendish Vore and indestructible Schambler using lethal nails, fierce Thunderbolts and abominable Rocket and Grenade Launchers.', '{\'minimum\': \'<strong>Minimum: </strong>A 100% Windows XP/Vista-compatible computer system\'}', '0,15', '0,04', '0', '0', '0,19'),
(408, 'escape the museum', '2014', 0, 0, 17, 25, 0, 3.99, 'Can you help Susan get back to Caitlin and escape the museum together?', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP/Vista<br></li><li><strong>Processor:</strong> 1.0 GHz<br></li><li><strong>Memory:</strong> 512 MB RAM<br></li><li><strong>DirectX:</strong> Version 8.1<br></li><li><strong>Storage:</strong> 183 MB available space</li></ul>\'}', '0,16', '0,13', '0', '0,03', '0,31'),
(409, 'call of juarez', '2007', 0, 0, 793, 198, 46, 8.59, 'Call of Juarez is an epic adventure western themed FPS game. The player alternately assumes the roles of two distinct, antagonistic characters: a sneaking fugitive Billy and his hunter the reverend Ray. Apart from the highly interesting, emotional and psychological aspect of the link between the two characters, the player will experience...', '{\'minimum\': \'Windows® 2000/XP (only), 2.2 GHz Pentium® 4, AMD Athlon™ 2400+, or 2.4 GHz Celeron or better (3 GHz Pentium 4, AMD Athlon 3000+, or 3 GHz Celeron or better recommended), 512 MB RAM (1 GB recommended), nVidia: GF6600, ATI: Radeon 9800 or better video card*, DirectX 9-compliant sound device, DirectX 9.0c or higher, 2 GB Hard Drive Space, Windows-compliant mouse and keyboard<br>\\t\\t\\t\\t\\t<strong>*Supported Video Cards at Time of Release:</strong> nVidia GeForce 6600, 6800, 7600, 7800, 7900 ATI Radeon: 9800, X800, X1300, X1600, X1800. X1900\'}', '0,14', '0,03', '0', '0,01', '0,2'),
(410, 'indiana jones and the emperors tomb', '2018', 0, 0, 130, 6, 0, 4.79, 'As Indiana Jones, you’ll travel to 1935 China to prevent a powerful artifact from falling into evil hands. This globe-spanning adventure pits you against evil Nazis and the Asian underworld. It’ll take more than just a trusty whip and pistol to avoid the perils of the Emperor’s Tomb.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP or newer<br></li><li><strong>Processor:</strong> 1.4 GHz<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> 3D graphics card compatible with DirectX 9.0c and 256 MB VRAM<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 2 GB available space<br></li><li><strong>Sound Card:</strong> 16-bit sound card<br></li><li><strong>Additional Notes:</strong> Mouse, Keyboard</li></ul>\'}', '0,14', '0,04', '0', '0,01', '0,18'),
(411, 'dynasty warriors 8 empires', '2015', 0, 48, 561, 318, 0, 39.99, 'DYNASTY WARRIORS 8 Empires is the latest installment of the &quot;Empires&quot; series, in which you aim to conquer ancient China using both strategy and the one warrior versus one thousand tactical action the WARRIORS series is known for.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® Vista, Windows® 7, Windows® 8, Windows® 8.1<br></li><li><strong>Processor:</strong> Core2 DUO 2.4 GHz or better<br></li><li><strong>Memory:</strong> 512 MB RAM<br></li><li><strong>Graphics:</strong> 640*480 pixel over<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 10 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c over</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® Vista, Windows® 7, Windows® 8, Windows® 8.1<br></li><li><strong>Processor:</strong> Core i7 860 or better<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> 1280*720 pixel over\\u3000※No 4K compatible<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 10 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c over</li></ul>\'}', '0,1', '0,09', '0,14', '0,03', '0,36'),
(412, 'guilty gear xrd sign', '2015', 0, 48, 1900, 153, 185, 22.99, 'Kept you waitin\'. GUILTY GEAR Xrd -SIGN- is finally here on Steam!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 / 8 / 8.1<br></li><li><strong>Processor:</strong> Intel Core i5, 2.0 GHz<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> Nvidia GeForce GTX 560 / Radeon HD 7770<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 12 GB available space</li></ul>\'}', '0,19', '0', '0,11', '0,04', '0,34'),
(413, 'ridge racer unbounded', '2012', 0, 50, 541, 450, 0, 7.99, 'The latest title in the RIDGE RACER franchise, RIDGE RACER Unbounded gears up to carve its own destructive path with a new breed of arcade racing.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong>Windows XP, Vista SP2 32-bit, 7. [Windows up to date and latest service pack installed]<br>\\t</li><li><strong>Processor:</strong>Dual Core Athlon x2 2.6 GHz or Intel Equivalent<br>\\t</li><li><strong>Memory:</strong>2 GB RAM<br>\\t</li><li><strong>Graphics:</strong>512 MB RAM, ATI Radeon 4850 or higher, NVIDIA GeForce 8800 GT or higher<br>\\t</li><li><strong>DirectX®:</strong>9.0c<br>\\t</li><li><strong>Hard Drive:</strong>3 GB HD space<br>\\t</li><li><strong>Sound:</strong>DirectX Compatible <br>\\t</li><li><strong>Other Requirements:</strong>Broadband Internet connection</li></ul>\'}', '0,1', '0,17', '0', '0,04', '0,32'),
(414, 'heavy fire afghanistan', '2014', 0, 27, 154, 136, 96, 1.99, 'Heavy Fire: Afghanistan is a super fast playing on-rails shooter set in modern-day Afghanistan featuring tanks, assault vehicles and helicopters. The game offers 60 awards, one machine co-op for up to four, Steam Cloud, Leaderboards and Trading Cards.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP<br></li><li><strong>Processor:</strong> Intel® Pentium® 4 CPU 3.00GHz or similar AMD Athlon 64<br></li><li><strong>Memory:</strong> 1500 MB RAM<br></li><li><strong>Graphics:</strong> Direct3D 10 capable video card (NVIDIA® Geforce 8800 GT or AMD® Radeon™ HD 3870 or above) with at least 512 MB video memory. Some low-end integrated cards may not work.<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 3 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9 Compatible Audio</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 8<br></li><li><strong>Processor:</strong> Core 2 Duo or similar AMD Athlon X2<br></li><li><strong>Memory:</strong> 4000 MB RAM<br></li><li><strong>Graphics:</strong> Direct3D 11 capable video card (NVIDIA® Geforce GTS 450 or AMD® Radeon™ HD 5670 or above) with at least 512 MB video memory. Low-end integrated and laptop cards are not recommended.<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 3 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9 Compatible Audio</li></ul>\'}', '0,3', '0', '0', '0,02', '0,31'),
(415, 'commandos 2 men of courage', '2007', 0, 0, 1333, 238, 201, 3.99, 'Commandos 2: Men of Courage is a tactical action/strategy game set against the backdrop of World War II. Take control of an elite group of commandos who must venture deep into enemy territory and utilize their combined expertise to complete a series of mission-based objectives.', '{\'minimum\': \'<strong>Minimum:</strong> IBM PC or 100% compatible, Windows 9X/ME, Pentium II 300 MHz (or equivalent), 64 MB RAM, 100% DirectX® 8 compatible 3D Accelerator card with at least 12 MB VRAM, 100% DirectX® 8 compatible (or higher) Sound card, DirectX® 8 (DirectX 8.0a included), 2 GB uncompressed hard drive space, 100% Windows 95/98 compatible Keyboard and Mouse<br>\\t\\t\\t\\t\\t<strong>Recommended:</strong> Pentium II 450 MHz, Windows 98SE/ME, 128 MB RAM, 100% DirectX® 8 compatible 3D Accelerator card with 32 MB VRAM, 3 GB uncompressed hard drive space\'}', '0,14', '0,09', '0', '0,02', '0,25'),
(416, 'velvet assassin', '2009', 0, 0, 1219, 832, 9, 1.69, 'Inspired by the fascinating story and unbreakable spirit of British secret agent Violette Szabo, players take control of Violette Summer, a beautiful World War II spy deep behind enemy lines with no support or official backing from the British Government.', '{\'minimum\': \'<strong>Minimum:</strong><br> <ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP / Vista<br>\\t </li><li><strong>Processor:</strong> Singlecore CPU with 3GHZ<br>\\t </li><li><strong>Memory:</strong> 512MB RAM<br>\\t </li><li><strong>Graphics:</strong> Pixel Shader 3 Graphics Card with 256 MB VRAM (Geforce 6800 or ATI X1600)<br>\\t </li><li><strong>Hard Drive:</strong> 5GB Free Hard Disk Space<br>\\t </li><li><strong>Sound:</strong> Stereo Sound<br> </li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br> <ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP / Vista<br>\\t </li><li><strong>Processor:</strong> Dual core CPU with 2Ghz<br>\\t </li><li><strong>Memory:</strong> 1GB RAM<br>\\t </li><li><strong>Graphics:</strong> Geforce7900gt or ATI X1900 xt<br>\\t </li><li><strong>Hard Drive:</strong> 5GB free Hard Disk Space<br>\\t </li><li><strong>Sound:</strong> 5.1 Surround Sound<br> </li></ul>\'}', '0,14', '0,02', '0,01', '0,01', '0,18');
INSERT INTO `jeux` (`id_jeu`, `nom_jeu`, `annee`, `age_requis`, `nb_succes`, `nb_avis_pos`, `nb_avis_neg`, `temps_jeu_moyen`, `prix`, `description`, `configuration`, `ventes_AN`, `ventes_EU`, `ventes_JP`, `ventes_Autre`, `ventes_Global`) VALUES
(417, 'hyperdimension neptunia u action unleashed', '2016', 0, 35, 2394, 176, 335, 19.49, 'Choose your tag team and rip through massive hordes of enemies with exciting aerial and ground-based combos. Look out, though - take too many hits and your clothes and defense will end up shredded!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 (64bit)<br></li><li><strong>Processor:</strong> 3 GHz Intel i3 or equivalent<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> DirectX 10.x or OpenGL 3.3 or better graphics card with 1 GB RAM and support for v4 shaders<br></li><li><strong>DirectX:</strong> Version 10<br></li><li><strong>Storage:</strong> 7 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c compatible sound card<br></li><li><strong>Additional Notes:</strong> Caution: ATI Mobility Radeon HD 5xxx, 1GB VRAM 5000 series, AMD processor may not work properly with this game.</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 8.1 (64bit) or later<br></li><li><strong>Processor:</strong> 3.1 GHz Intel i5 or equivalent<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> DirectX 10.x or OpenGL 3.3 or better graphics card with 2 GB RAM and support for v4 shaders<br></li><li><strong>DirectX:</strong> Version 10<br></li><li><strong>Storage:</strong> 7 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c compatible sound card<br></li><li><strong>Additional Notes:</strong> Caution: ATI Mobility Radeon HD 5xxx, 1GB VRAM 5000 series, AMD processor may not work properly with this game.</li></ul>\'}', '0,07', '0,02', '0,06', '0,03', '0,17'),
(418, 'age of empires iii complete collection', '2012', 0, 0, 13759, 1801, 902, 29.99, 'Microsoft Studios brings you three epic Age of Empires III games in one monumental collection for the first time.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong>Windows XP<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong>Intel Core 2 Duo 2.2 GHz or AMD Athlon 64 X2 2.0 GHz<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong>2 GB RAM<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong>64 MB NVIDIA GeForce 6800 or ATI Radeon X1300<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong>dx90c<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong>12 GB HD space<br>\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0,01', '0,12', '0', '0,03', '0,17'),
(419, 'thief deadly shadows', '2007', 0, 0, 1135, 210, 254, 6.99, 'You are Garrett, the master thief. Rarely seen and never caught, Garrett is the best that ever was. Able to sneak past any guard, pick any lock, and break into the most ingeniously secured residences. Garrett steals from the wealthy and gives to himself, making his living in the dark and foreboding City.', '{\'minimum\': \'<strong>Minimum: </strong>IBM PC or 100% compatible, Windows 2000 or Windows XP, Intel Pentium IV 1.5 GHz (or AMD Athlon XP equivalent), 256 MB system memory, 64 MB video memory, Direct3D 9.0, and Pixel Shader 1.1, 100% DirectSound 9 compatible sound card, 3,000 MB free hard disk space, Keyboard and mouse<br>\\t\\t\\t\\t\\t<strong>Recommended: </strong>Intel Pentium IV 2.0 GHz (or AMD Athlon XP equivalent), 512 MB system memory, 128 MB video memory, Direct3D 9.0, and Pixel Shader 1.1<br>\\t\\t\\t\\t\\tThief: Deadly Shadows does not support play on laptop computers.\'}', '0,13', '0,04', '0', '0,01', '0,17'),
(420, 'luxor 3', '2008', 0, 0, 52, 14, 102, 5.99, 'A brave young Pharaoh, killed prematurely by a fierce sandstorm and embodied by the gods as a skillful scarab, must battle the powerful god of Chaos, Set, to free the essences of other Egyptian gods contained within colorful magical spheres.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>Supported OS: </strong>Microsoft® Windows® 2000/XP/Vista<br>\\t\\t\\t\\t\\t</li><li><strong>DirectX Version: </strong>32 MB DirectX 8.1 compatible graphics card or better<br>\\t\\t\\t\\t\\t</li><li><strong>Processor: </strong>Pentium II 700MHz<br>\\t\\t\\t\\t\\t</li><li><strong>Memory: </strong>256MB RAM<br>\\t\\t\\t\\t\\t</li><li><strong>Sound: </strong>DirectSound-compatible sound card<br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive: </strong>60MB free HD space</li></ul>\'}', '0,16', '0', '0', '0,01', '0,17'),
(421, 'sid meiers civilization iv', '2006', 0, 0, 1394, 129, 49, 9.99, 'With over 6 million units sold and unprecedented critical acclaim from fans and press around the world, Sid Meier\'s Civilization is recognized as one of the greatest PC game franchises of all-time. Now, Sid Meier and Firaxis Games will take this incredibly fun and addictive game to new heights by adding new ways to play and win, new...', '{\'minimum\': \'<strong>Minimum:</strong> Windows 2000/XP, 1.2GHz Intel Pentium 4 or AMD Athlon processor or equivalent, 256MB RAM, 64 MB Video Card w/ Hardware T&amp;L (GeForce 2/Radeon 7500 or better) DirectX7 compatible sound card, 1.7GB of free hard drive space, DirectX9.0c (included)<br>\\t\\t\\t\\t\\t<strong>Recommended:</strong> Windows 2000/XP, 1.8GHz Intel Pentium 4 or AMD Athlon processor or equivalent/better, 512 MB RAM, 128 MB Video Card w/ DirectX 8 support (pixel and vertex shaders), DirectX7 compatible sound card, 1.7GB of free hard drive space, DirectX9.0c (included)\'}', '0,02', '0,12', '0', '0,03', '0,17'),
(422, 'reloaded', '2015', 0, 0, 3, 7, 0, 3.99, 'If you like your games violent, you’re in for a sick treat with Re-Loaded, the sequel to the popular blood-fest shooter Loaded. Re-Loaded is set over a number of 3D levels each more harrowing than the last. The sound effects will have you cringing, and the character animations show each minuscule trait of the six maniacs.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP or newer<br></li><li><strong>Graphics:</strong> Dedicated Video Graphics<br></li><li><strong>Storage:</strong> 600 MB available space</li></ul>\'}', '0,09', '0,06', '0', '0,01', '0,17'),
(423, 'sword of the samurai', '2014', 0, 0, 102, 8, 0, 18.99, 'Enter Japan in the age of warring states. At the center of this role-playing, action-adventure simulation of combat, statesmanship and intrigue, you are a samurai warrior struggling for honor!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP / Vista / 7<br></li><li><strong>Processor:</strong> 1.0 GHz Processor<br></li><li><strong>Memory:</strong> 512 MB RAM<br></li><li><strong>Graphics:</strong> 100% DirectX compatible graphics<br></li><li><strong>Storage:</strong> 500 MB available space<br></li><li><strong>Sound Card:</strong> 100% DirectX compatible card or onboard sound</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7<br></li><li><strong>Processor:</strong> 1.5 GHz Processor<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> 100% DirectX compatible graphics<br></li><li><strong>Storage:</strong> 500 MB available space<br></li><li><strong>Sound Card:</strong> 100% DirectX compatible card or onboard sound</li></ul>\'}', '0', '0', '0,17', '0', '0,17'),
(424, 'wolfenstein 3d', '2007', 0, 0, 1773, 87, 69, 2.99, 'Maybe it was the fact that people got to blow away Nazis. Maybe it was the sheer challenge of it all. For whatever reason, Wolfenstein 3D and Spear of Destiny, pioneered the first-person shooter genre and brought its legendary creators, id Software, worldwide notoriety and numerous awards.', '{\'minimum\': \'<strong>Minimum: </strong>A 100% Windows XP/Vista-compatible computer system\'}', '0,12', '0,04', '0', '0', '0,17'),
(425, 'gunslingers', '2015', 0, 1, 176, 148, 0, 0.00, 'A unique turn-based tactical game in a Space Western setting', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7, Windows 8 Classic or Windows 10<br></li><li><strong>Processor:</strong> 2.33GHz or faster x86-compatible processor, or Intel Atom™ 1.6GHz or faster processor for netbook class devices<br></li><li><strong>Memory:</strong> 512 MB RAM<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 600 MB available space</li></ul>\'}', '0,08', '0,06', '0', '0,02', '0,16'),
(426, 'around the world in 80 days', '2018', 0, 0, 3, 2, 0, 1.69, 'Accept the challenge and go around the world in 80 days!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP, Vista, 7, 8, 10<br></li><li><strong>Processor:</strong> 1 GHz<br></li><li><strong>Memory:</strong> 512 MB RAM<br></li><li><strong>Graphics:</strong> 128 Mo<br></li><li><strong>DirectX:</strong> Version 8.1</li></ul>\'}', '0,03', '0,15', '0', '0,02', '0,21'),
(427, 'n2o nitrous oxide', '2015', 0, 10, 24, 3, 0, 3.99, 'N2O: Nitrous Oxide\'s gameplay is pure shooter, reminiscent of the arcade classic TEMPEST. You\'re stuck on the perimeter of a tube and you job is to shoot at everything in your way.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP or newer<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> Dedicated Video Graphics<br></li><li><strong>Storage:</strong> 600 MB available space</li></ul>\'}', '0,09', '0,06', '0', '0,01', '0,16'),
(428, 'bladestorm nightmare', '2015', 0, 46, 177, 118, 0, 49.99, 'BLADESTORM: Nightmare is the newest evolution of 2007’s BLADESTORM: The Hundred Years’ War using the latest technologies and introducing many new elements. These technologies have made possible not only visual improvements, but also many new game elements. BLADESTORM: Nightmare offers an entirely new gameplay experience.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista/7/8/8.1 (64bit required)<br></li><li><strong>Processor:</strong> Core i7 870 2.8GHz or better<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> 640*480 pixel over, High Color<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 12 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c over</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista/7/8/8.1 (64bit required)<br></li><li><strong>Processor:</strong> Core i7 2600 3.4GHz or better<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> 1980*1080 pixel over, True Color, 16:9 display<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 12 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c over</li></ul>\'}', '0,1', '0,06', '0,06', '0,02', '0,24'),
(429, 'puzzle quest galactrix', '2009', 0, 0, 120, 136, 0, 6.99, 'The puzzle game of the future has arrived! The original best-selling new Puzzle franchise is back in an all new dimension with its signature Match-3, turn based battles in an insanely addictive and masterful hybrid of RPG and Puzzle genres.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>Operating System: </strong>Microsoft® Windows® XP/Vista <br>\\t\\t\\t\\t\\t</li><li><strong>Processor: </strong>Intel® Core 2 @ 1.8 Ghz / AMD Athlon 64 X2 2.0 Ghz <br>\\t\\t\\t\\t\\t</li><li><strong>Memory: </strong>1 GB RAM <br>\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space: </strong>300 MB Available HDD Space <br>\\t\\t\\t\\t\\t</li><li><strong>Video Card: </strong>256 Mb (GeForce® 7 / Radeon® X800) <br>\\t\\t\\t\\t\\t</li><li><strong>Sound Card: </strong>DirectX® 9 Compatible Sound Card <br>\\t\\t\\t\\t\\t</li><li><strong>DirectX® Version: </strong>DirectX® 9.0c </li></ul>\'}', '0,15', '0', '0', '0,01', '0,16'),
(430, 'alone in the dark the new nightmare', '2013', 0, 0, 149, 103, 6, 4.99, 'From the moment Edward Carnby and Aline Cedrac set foot on Shadow Island, they are confronted by mysterious, evil creatures intent on thwarting their progress to recover 3 ancient tablets believed to hold the secret key to some incredible menacing phenomena. Danger threatens from every corner.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® 98 SE/Me/2000 Pro/XP<br></li><li><strong>Processor:</strong> Intel Pentium® II 300 MHz<br></li><li><strong>Memory:</strong> 64 MB RAM<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 400 MB available space</li></ul>\'}', '0,09', '0,06', '0', '0,01', '0,16'),
(431, 'vegas party', '2018', 0, 20, 1, 4, 0, 3.99, 'The game takes the player into the gambling-friendly universe of this over-the-top version of Las Vegas city. Played as a race, the goal is to reach the end of the Strip before anyone else. Trust no one and forget the meaning of the word &quot;mercy&quot; because it does not apply here!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® Vista/7/8 with latest service packs<br></li><li><strong>Processor:</strong> Intel Core 2 Duo, AMD Athlon X2 or better<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA® GeForce® 6150SE or equivalent<br></li><li><strong>DirectX:</strong> Version 9.0c</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® 7/8/10 with latest service packs<br></li><li><strong>Processor:</strong> Intel® Core™ i5 or equivalent<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA® GeForce® GTX 460 1GB or equivalent<br></li><li><strong>DirectX:</strong> Version 11</li></ul>\'}', '0,15', '0', '0', '0,01', '0,16'),
(432, 'flatout 2', '2006', 0, 0, 5438, 343, 293, 5.99, 'DRIVING THIS RECKLESS IS NO ACCIDENT! But you might want to cause a few. In these high-speed races, the more damage you inflict, the better. The ultimate in turbo-charged cars and the craziest competitor drivers are waiting to test your best destructive streak. Responsible drivers need not apply.', '{\'minimum\': \'<strong>Minimum: </strong>Windows XP/2000 XP SP2 / 2000 SP4, 256 MB RAM, 64 MB* video card, 2.0 GHz Pentium® 4 or AMD® 2000+ processor, DirectX compatible sound card, 3.5 GB free hard drive space, DirectX 9.0c, TCP/IP required for LAN play, 512kbs minimum, Broadband connection required<br>\\t\\t\\t\\t\\tFlatOut 2 supports gamepads. Gamepad with 8 buttons minimum (to support all configurable game commands) is recommended.<br>* FlatOut 2 supports the following Chipsets, nVidia Geforce FX 5/6/7 series, ATI Radeon 9600 Pro/XT and above, ATI Radeon X200 and above. On-board/ integrated graphics cards and laptops not supported.\'}', '0,11', '0,07', '0', '0,02', '0,2'),
(433, 'mugen souls', '2015', 0, 51, 171, 74, 0, 14.99, 'Mugen Souls features a free-roaming battle map, turn-based combat, and massive amounts of customization and growth to maximize the fun players can have with the game.', '{\'minimum\': \'<strong>最低配置:</strong><br><ul class=\"bb_ul\"><li><strong>操作系统:</strong> Windows XP<br></li><li><strong>处理器:</strong> 2.13GHz Intel Core2 Duo or equivalent<br></li><li><strong>内存:</strong> 4 GB RAM<br></li><li><strong>图形:</strong> DirectX 9.0c compatible graphics card with 512Mb RAM and support for v3 shaders<br></li><li><strong>DirectX 版本:</strong> 9.0c<br></li><li><strong>存储空间:</strong> 需要 4 GB 可用空间<br></li><li><strong>声卡:</strong> DirectX 9.0c compatible sound card</li></ul>\', \'recommended\': \'<strong>推荐配置:</strong><br><ul class=\"bb_ul\"><li><strong>操作系统:</strong> Windows 7 or later<br></li><li><strong>处理器:</strong> 3GHz Intel i3 or equivalent<br></li><li><strong>内存:</strong> 4 GB RAM<br></li><li><strong>图形:</strong> DirectX 9.0c compatible graphics card with 1GB RAM and support for v3 shaders<br></li><li><strong>DirectX 版本:</strong> 9.0c<br></li><li><strong>存储空间:</strong> 需要 4 GB 可用空间<br></li><li><strong>声卡:</strong> DirectX 9.0c compatible sound card</li></ul>\'}', '0,04', '0,03', '0,08', '0,01', '0,16'),
(434, 'yakuza kiwami', '2019', 0, 55, 1449, 116, 1225, 14.99, 'SEGA’s critically-acclaimed entry that started a legend. Become Kazuma Kiryu, an up-and-coming yakuza who takes the fall for the murder of a crime boss, only to emerge from prison ten years later to a changed world. Remastered from the ground up, now in 4K and uncapped framerates on PC.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li>Requires a 64-bit processor and operating system<br></li><li><strong>OS:</strong> Windows 7 64Bit<br></li><li><strong>Processor:</strong> Intel Core i5-3470 | AMD FX-6300<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> Nvidia GeForce GTX 560 | AMD Radeon HD 6870<br></li><li><strong>Additional Notes:</strong> PU with a gpumark of : 2600 to 3100, CPU with a cpumark of 4500 to 6300</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li>Requires a 64-bit processor and operating system</li></ul>\'}', '0', '0', '0,28', '0', '0,28'),
(435, 'space invaders extreme', '2018', 0, 70, 69, 7, 0, 15.49, 'The critically acclaimed update to the Space Invaders franchise has arrived to invade Steam with greatly improved graphics and audio! Packed with pulsing, vibrant visuals enhanced further by interactive sound. The invaders have evolved, the question is: can you keep up?', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li>Requires a 64-bit processor and operating system<br></li><li><strong>OS:</strong> Windows7/8.1/10 (64bit)<br></li><li><strong>Processor:</strong> Intel(R) Core(TM) i5-2410M 2.30GHz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> 64MB<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 600 MB available space<br></li><li><strong>Sound Card:</strong> DirectSound-compatible<br></li><li><strong>Additional Notes:</strong> Requires an internet connection. Controller must be activated in Steam.</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li>Requires a 64-bit processor and operating system</li></ul>\'}', '0,18', '0,02', '0,02', '0,02', '0,24'),
(436, 'deponia', '2012', 0, 19, 7208, 840, 217, 6.99, 'In Deponia, the world has degenerated into a vast garbage dump, in which the crotchety Rufus ekes out his sorry existence.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong>Windows Vista/7<br>\\t</li><li><strong>Processor:</strong>2.5 GHz (Single Core) or 2 GHz (Dual Core)<br>\\t</li><li><strong>Memory:</strong>2 GB RAM<br>\\t</li><li><strong>Graphics:</strong>OpenGL 2.0 compatible with 512 MB RAM (Shared Memory is not recommended)<br>\\t</li><li><strong>DirectX®:</strong>9.0c<br>\\t</li><li><strong>Hard Drive:</strong>5 GB HDD space<br>\\t</li><li><strong>Sound:</strong>DirectX compatible</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong>Windows Vista/7<br>\\t</li><li><strong>Processor:</strong>2.5 GHz (Single Core) or 2 GHz (Dual Core)<br>\\t</li><li><strong>Memory:</strong>4 GB RAM<br>\\t</li><li><strong>Graphics:</strong>OpenGL 2.0 compatible with 512 MB RAM (Shared Memory is not recommended)<br>\\t</li><li><strong>DirectX®:</strong>9.0c<br>\\t</li><li><strong>Hard Drive:</strong>5 GB HDD space<br>\\t</li><li><strong>Sound:</strong>DirectX compatible</li></ul>\'}', '0', '0,13', '0', '0,03', '0,15'),
(437, 'killer7', '2018', 0, 0, 432, 12, 0, 15.49, 'Sneak into a world of underground assassins as Harman Smith, a man who manifests 7 deadly personalities, the killer7. Take control of this distinct murderers\' row as they hunt down the sinister Kun Lan to thwart his plan of world dominance.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 or later<br></li><li><strong>Processor:</strong> 2GHz Dual Core<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> Intel HD Graphics<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 3 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 or later<br></li><li><strong>Processor:</strong> 3GHz Dual Core<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> 512MB, Dedicated Graphics Card<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 3 GB available space</li></ul>\'}', '0,16', '0,06', '0', '0,01', '0,24'),
(438, 'shadow ops red mercury', '2014', 0, 0, 138, 29, 0, 4.99, 'Race against time and terrorism as a member of the elite counter terrorist team in this all-out first person shooter. Your duty is to hunt down a terrorist overlord carrying a nuclear device before untold disaster is unleashed.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP or higher<br></li><li><strong>Processor:</strong> Pentium III or AMD Athlon 1 GHz<br></li><li><strong>Memory:</strong> 256 MB RAM<br></li><li><strong>Graphics:</strong> 64 MB Windows XP compatible,<br></li><li><strong>DirectX:</strong> Version 9.0<br></li><li><strong>Storage:</strong> 4 GB available space<br></li><li><strong>Sound Card:</strong> Windows X-compatible</li></ul>\'}', '0,11', '0,03', '0', '0,01', '0,15'),
(439, 'mind zero', '2016', 0, 36, 31, 32, 0, 14.99, 'Mind Zero is an action-packed dungeon-crawler RPG. Play as Kei, a high school student whose life turns upside down when he forms a contract with a “MIND,” a weapon/being with deadly powers.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 / 8 / 8.1<br></li><li><strong>Processor:</strong> Intel Core2 Duo<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> nVidia GeForce 7900 GT or better / AMD Radeon X1900 / nVidia GeForce GT 620 (Windows 8.1)<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 3 GB available space<br></li><li><strong>Sound Card:</strong> Direct Sound<br></li><li><strong>Additional Notes:</strong> Compatibility with Xbox 360 Controller</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 / 8 / 8.1<br></li><li><strong>Processor:</strong> Intel Core i5 / i7<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> nVidia GeForce 8800 GT or better / AMD Radeon HD3700 / nVidia GeForce GT 650 (Windows 8.1)<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 3 GB available space<br></li><li><strong>Sound Card:</strong> Direct Sound<br></li><li><strong>Additional Notes:</strong> Compatibility with Xbox 360 Controller</li></ul>\'}', '0,08', '0', '0,04', '0,02', '0,15'),
(440, 'saint seiya soldiers soul', '2015', 0, 50, 1588, 152, 0, 39.99, 'The 12 Gold Saints are coming back to burn their cosmos with outstanding graphics, solid gameplay, characters from the whole series… and so much more to discover!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista/7/8/8.1<br></li><li><strong>Processor:</strong> Intel Core 2 Duo 2.4Ghz / AMD Athlon 64 X2 5200+, 2.6GHz<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> 512 MB Nvidia GeForce 8800 / ATI Radeon HD 3870<br></li><li><strong>DirectX:</strong> Version 9.0<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 12 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista/7/8/8.1<br></li><li><strong>Processor:</strong> Intel Core i3-530, 2.93 GHz / AMD Phenom II X4 940, 3.0GHz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> 1 GB Nvidia GeForce GTX 470 / AMD Radeon HD 5870<br></li><li><strong>DirectX:</strong> Version 9.0<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 12 GB available space</li></ul>\'}', '0', '0,09', '0,08', '0,02', '0,19'),
(441, 'the legend of heroes trails of cold steel ii', '2018', 0, 51, 872, 36, 0, 29.99, 'Civil war has broken out across Erebonia. After his narrow escape from Trista, Rean will take up his sword again on a journey with his Divine Knight, Valimar, in search of his friends from Class VII and a way to end the conflict before its price becomes far too dear...', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>Betriebssystem:</strong> Windows 7 or later; 64 bit OS required<br></li><li><strong>Prozessor:</strong> Intel Atom x7-Z8700 2.4 GHz<br></li><li><strong>Arbeitsspeicher:</strong> 4 GB RAM<br></li><li><strong>Grafik:</strong> Shader Model 5 (GeForce 400 / Radeon HD 5000 / Intel post-2012 series)<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Speicherplatz:</strong> 19 GB verfügbarer Speicherplatz<br></li><li><strong>Zusätzliche Anmerkungen:</strong> 1280x720 / 30 FPS with portable settings</li></ul>\', \'recommended\': \'<strong>Empfohlen:</strong><br><ul class=\"bb_ul\"><li><strong>Betriebssystem:</strong> Windows 7 or later; 64 bit OS required<br></li><li><strong>Prozessor:</strong> Intel i3 3 GHz<br></li><li><strong>Arbeitsspeicher:</strong> 6 GB RAM<br></li><li><strong>Grafik:</strong> Geforce GTX 770 / Radeon R9 280X<br></li><li><strong>Speicherplatz:</strong> 19 GB verfügbarer Speicherplatz<br></li><li><strong>Zusätzliche Anmerkungen:</strong> 1920x1080 / 60 FPS with high settings</li></ul>\'}', '0,03', '0', '0,24', '0,01', '0,27'),
(442, 'nancy drew the white wolf of icicle creek', '2009', 0, 0, 27, 9, 0, 5.19, 'Follow a Trail to Hidden Secrets and Sabotage!', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Window XP/Vista<br>\\t </li><li><strong>Processor:</strong> 1 GHz or greater Pentium or equivalent class CPU<br>\\t </li><li><strong>Memory:</strong> 128 MB of RAM<br>\\t </li><li><strong>Graphics:</strong> 32 MB DirectX 9.0 compatible video card<br>\\t </li><li><strong>DirectX:</strong> 9.0<br>\\t </li><li><strong>Hard Drive:</strong> 1 GB or more of hard drive space<br>\\t </li><li><strong>Sound:</strong> 16 bit DirectX compatible sound card<br> </li></ul>\'}', '0,14', '0', '0', '0,01', '0,15'),
(443, 'safecracker the ultimate puzzle adventure', '2007', 0, 0, 256, 172, 1, 4.49, 'As an expert safecracker, you are hired by the wealthy family of a recently deceased to search his mansion for his last will and testament. Duncan W. Adams was an avid safe collector and an \'eccentric,\' to say the least. Adams has hidden the deed to his vast fortunes in one of 35 safes.', '{\'minimum\': \'<strong>Minimum: </strong>Windows® 2000/XP, 800 MHz Pentium® III or equivalent/ faster processor, 64 MB of RAM, DirectX 9.0c or higher, 64 MB DirectX® 9.0c compliant video card, DirectX® 9.0c compatible sound card, mouse, keyboard<br>\\t\\t\\t\\t\\t<strong>Recommended: </strong>Windows XP, 1 GHz Intel Pentium 4 or equivalent/faster, 128 RAM, 64 MB DirectX® 9.0c Compliant Video Card, DirectX 9.0c, 3D Compatible sound card, mouse, keyboard\'}', '0,14', '0,07', '0', '0,02', '0,23'),
(444, 'making history the great war', '2015', 0, 1, 259, 89, 0, 22.99, 'The Great War is a turn-based grand strategy game based on the epic struggles of the WWI era. Experience the battles of attrition and punishing artillery barrages. Play as any nation of the period as the modern world of industrialized warfare replaces an age of kings with a struggle of ideologies.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 10 / Windows 8 / Windows 7 / Windows Vista / Windows XP with Service Pack 2<br></li><li><strong>Processor:</strong> Pentium 4 or better<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> 256 MB DirectX 9.0c-Compliant, Shader 2.0 3D Video Card<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 2 GB available space<br></li><li><strong>Additional Notes:</strong> Windows-Compliant Keyboard &amp; Mouse</li></ul>\'}', '0', '0', '0,27', '0', '0,27'),
(445, 'guilty gear x2 #reload', '2014', 0, 0, 390, 47, 320, 7.99, 'As humanity endeavored to better themselves, they created the biological marvel known as Gears. Originally intended as the next step of human evolution, they were instead fitted for war and turned against their own creators.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP/Vista/7/8<br></li><li><strong>Processor:</strong> Pentium III 700Mhz<br></li><li><strong>Memory:</strong> 256 MB RAM<br></li><li><strong>Graphics:</strong> 64MB or better<br></li><li><strong>DirectX:</strong> Version 8.1</li></ul>\'}', '0,11', '0,03', '0', '0,01', '0,15'),
(446, 'ys the oath in felghana', '2012', 0, 33, 936, 57, 635, 9.99, 'An Action RPG driven by fast-paced combat and paired with an intricate puzzle-filled world.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP<br>\\t</li><li><strong>Processor:</strong> Pentium III 800 MHz<br>\\t</li><li><strong>Memory:</strong> 1 GB RAM<br>\\t</li><li><strong>Graphics:</strong> 32 MB VRAM, 3D accelerator compatible w/ DirectX 9.0c<br>\\t</li><li><strong>DirectX®:</strong> 8.0<br>\\t</li><li><strong>Hard Drive:</strong> 1 GB HD space<br>\\t</li><li><strong>Sound:</strong> Compatible with DirectX 9.0c</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP, Vista, 7<br>\\t</li><li><strong>Processor:</strong> Pentium III 1 GHz or higher<br>\\t</li><li><strong>Memory:</strong> 1 GB RAM<br>\\t</li><li><strong>Graphics:</strong> 32 MB VRAM, 3D accelerator compatible w/ DirectX 9.0c<br>\\t</li><li><strong>DirectX®:</strong> 9.0c<br>\\t</li><li><strong>Hard Drive:</strong> 2 GB HD space<br>\\t</li><li><strong>Sound:</strong> Compatible with DirectX 9.0c</li></ul>\'}', '0,09', '0', '0,04', '0,01', '0,14'),
(447, 'lost dimension', '2017', 0, 36, 64, 15, 0, 19.49, 'In the near future a terrorist mastermind, known only as ‘The End’, threatens humanity with nuclear armageddon. A special task force, the S.E.A.L.E.D team, are the only ones who can stop him: a group of young combatants with incredible abilities and each with a mysterious past.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 (64-bit)<br></li><li><strong>Processor:</strong> Intel Core 2 Quad 2.4GHz or comparable<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce 8800 or comparable<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 1100 MB available space<br></li><li><strong>Sound Card:</strong> Windows compatible sound card</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 10<br></li><li><strong>Processor:</strong> Intel i5 3.3 GHz or comparable<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 960 or comparable<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 1100 MB available space<br></li><li><strong>Sound Card:</strong> Windows compatible sound card</li></ul>\'}', '0,12', '0,04', '0,02', '0,04', '0,22'),
(448, 'haunted house', '2010', 0, 0, 9, 13, 0, 4.79, 'Dare to be scared! After 30 years, Atari\'s classic groundbreaking game is back - with all-new scream-worthy chills and thrills!', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP SP2, Vista SP2, 7 32-bit only (64-bit operating systems are not supported)<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Core2 Duo E4300 or AMD Athlon X2 +3800<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1GB<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> ATI Radeon X1800, Intel Core i3/i5 HD 733mhz, NVIDIA GeForce 7950 (Intel GMA G43/G45/X4500 or lower video cards not supported)<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX 9.0c-compatible<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 1GB free<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX 9.0c-compatible<br>\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0,13', '0', '0', '0,01', '0,14'),
(449, 'dream pinball 3d', '2012', 0, 0, 164, 379, 273, 4.99, 'FINGER-FLIPPIN’, POWERFUL PINBALL!No room for a pinball machine? So what! With DREAM PINBALL 3D you can transform your PC or console into 6 different, multilevel, 3D pinball machines! Clever gameplay, plus balls made of different materials – and each material has special ballistic properties that affect how those balls roll!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong>Windows XP SP2 / Vista / 7 / 8<br>\\t</li><li><strong>Processor:</strong>2.0 GHz Single Core <br>\\t</li><li><strong>Memory:</strong>1 GB RAM<br>\\t</li><li><strong>Graphics:</strong>Shader 1.3 graphics card with 128 MB <br>\\t</li><li><strong>Hard Drive:</strong>900 MB HD space<br>\\t</li><li><strong>Other Requirements:</strong>Broadband Internet connection<br>\\t</li><li><strong>Additional:</strong>Internet connection is needed to upload highscore</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong>Windows XP SP2 / Vista / 7 / 8<br>\\t</li><li><strong>Processor:</strong>Intel or AMD Multicore CPU <br>\\t</li><li><strong>Memory:</strong>2 GB RAM<br>\\t</li><li><strong>Graphics:</strong>Shader 2.0 graphics card with 256 MB <br>\\t</li><li><strong>Hard Drive:</strong>900 MB HD space<br>\\t</li><li><strong>Other Requirements:</strong>Broadband Internet connection<br>\\t</li><li><strong>Additional:</strong>Internet connection is needed to upload highscore</li></ul>\'}', '0,13', '0,03', '0', '0,01', '0,17'),
(450, 'dragon age origins ultimate edition', '2010', 0, 0, 8808, 726, 686, 19.99, 'Dragon Age: Origins - Ultimate Edition includes Dragon Age: Origins, Dragon Age: Origins - Awakening and all nine content packs.', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP (SP3) or Windows Vista (SP1) or Windows 7<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Core 2 Single 1.6 Ghz Processor (or equivalent) or AMD 64 2.0 GHz Processor (or equivalent)<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1GB (1.5 GB Vista and Windows 7)<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> ATI Radeon X850 256MB or NVIDIA GeForce 6600 GT 128MB or greater (Windows Vista: Radeon X1550 256 MB or NVidia GeForce 7600GT 256MB)<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX (November 2007)<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 20 GB HD space<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> Direct X Compatible Sound Card<br>\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br>\\t\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP (SP3) or Windows Vista (SP1) or Windows 7<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Core 2 Duo 2.4 Ghz or AMD Phenom II X2 Dual-Core 2.7 Ghz Processor or equivalent<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2 GB (3GB Vista and Windows 7)<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> ATI 3850 512 MB or NVidia 8800GTS 512MB or greater<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX (November 2007)<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 20 GB HD space<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> Direct X Compatible Sound Card<br>\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0', '0,12', '0', '0,02', '0,14'),
(451, 'just cause', '2007', 16, 0, 1732, 846, 20, 4.99, 'Your world...Your rules! In Just Cause, you are a Latin field operative and specialist in regime change backed by top secret US government agency who will overthrow the corrupt government of San Esperito.', '{\'minimum\': \'<strong>Minimum: </strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li>Microsoft Windows® 2000/XP. (Windows® 95/98/ME/NT not supported)<br>\\t\\t\\t\\t\\t</li><li>Pentium IV 1.4GHz (or AMD AthlonXP 1700+ processor or higher).<br>\\t\\t\\t\\t\\t</li><li>256MB System Memory.<br>\\t\\t\\t\\t\\t</li><li>3D Hardware Accelerator Card Required - 100% DirectX® 9.0c compatible with 128 MB and Shader model 2.0. (GF FX 5700 or ATI 9500) <br>\\t\\t\\t\\t\\t</li><li>100% DirectX® 9.0c compatible 16-bit sound card and latest drivers<br>\\t\\t\\t\\t\\t</li><li>4.0GB of uncompressed free disk space (plus 600MB for Windows® 2000/XP swap file)<br>\\t\\t\\t\\t\\t</li><li>100% Windows® 2000/XP compatible mouse, keyboard and latest drivers.</li></ul><strong>Recommended: </strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li>Pentium® IV 2.8GHz with Dual Core Technology (or Athlon 64 series).<br>\\t\\t\\t\\t\\t</li><li>512MB System Memory.<br>\\t\\t\\t\\t\\t</li><li>3D Hardware Accelerator Card Required - 100% DirectX® 9.0c compatible with 256 MB and Shader model 2.0. All nVidia® GeForce™ 7 series or higher.<br>\\t\\t\\t\\t\\t</li><li>Sound Blaster® X-Fi series or higher.</li></ul><strong>Optimal: </strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li>Pentium® D Processor with Dual Core Technology (or Athlon 64 X2 series).<br>\\t\\t\\t\\t\\t</li><li>1GB System Memory.<br>\\t\\t\\t\\t\\t</li><li>All nVidia® GeForce™ 7800 series or higher.<br>\\t\\t\\t\\t\\t</li><li>Sound Blaster® X-Fi series or higher.</li></ul>\'}', '0,11', '0,05', '0,01', '0,01', '0,18'),
