(515, 'burnout paradise the ultimate box', '2009', 0, 0, 9739, 1487, 431, 9.99, 'Download Burnout™ Paradise: The Ultimate Box today. Paradise City is the largest and most dangerous setting yet for the best-selling Burnout series. The massive setting gives players an open-ended world to explore, as they race their vehicles through hundreds of miles of roads and underground passages with more than 70 different cars.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>Supported OS: </strong>Windows XP (SP2), Windows Vista<br>\\t\\t\\t\\t\\t</li><li><strong>Processor: </strong>2.8 GHz Pentium 4 XP / 3.2 GHz Pentium 4 Vista<br>\\t\\t\\t\\t\\t</li><li><strong>Memory: </strong>1 GB RAM XP / 1.5 GB Vista (2 GB recommended)<br>\\t\\t\\t\\t\\t</li><li><strong>Graphics: </strong>DirectX 9.0c compatible with Shader Model 3.0, requires 128 MB or more and contain one of these chipsets: Nvidia 6600 or greater, Radeon X1300 or greater<br>\\t\\t\\t\\t\\t</li><li><strong>Sound: </strong>DirectX 9.0c compatible<br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive: </strong> 4 GB of free space or more <br></li><li>ACCEPTANCE OF END USER LICENSE AGREEMENT REQUIRED TO PLAY. ACCESS TO ONLINE FEATURES AND/OR SERVICES REQUIRES AN EA ONLINE ACCOUNT AND REGISTRATION. REGISTRATION FOR ONLINE FEATURES IS LIMITED TO ONE EA ACCOUNT PER GAME AND IS NON-TRANSFERABLE. EA ONLINE TERMS &amp; CONDITIONS CAN BE FOUND AT <a href=\"https://steamcommunity.com/linkfilter/?url=http://www.ea.com\" target=\"_blank\" rel=\"noopener\" >www.ea.com</a>. YOU MUST BE 13+ TO REGISTER FOR AN EA ONLINE ACCOUNT.<br><br>EA MAY RETIRE ONLINE FEATURES AFTER 30 DAYS NOTICE POSTED ON <a href=\"https://steamcommunity.com/linkfilter/?url=http://www.ea.com\" target=\"_blank\" rel=\"noopener\" >www.ea.com</a>.<br><br>INCLUDES SOFTWARE THAT COLLECTS DATA ONLINE NECESSARY TO PROVIDE INGAME ADVERTISING.</li></ul>\'}', '0', '0,17', '0,01', '0,03', '0,23'),
(516, 'ultra street fighter iv', '2014', 0, 67, 8247, 1141, 835, 22.99, 'The world’s greatest fighting game evolves to a whole new level with Ultra Street Fighter IV.', '{\'minimum\': \'<strong> Minimum</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista<br> </li><li><strong>Processor:</strong> Intel Core 2 Duo 2.0 GHz or better<br> </li><li><strong>Memory:</strong> 1 GB RAM<br> </li><li><strong>Hard Disk Space:</strong> 12 GB free hard drive space <br> </li><li><strong>Video Card:</strong> NVIDIA GeForce 6600 or better (except NVIDIA GeForce 7300)<br> </li><li><strong>DirectX®:</strong> 9.0c or greater<br> </li><li><strong>Sound:</strong> DirectSound, DirectX9.0c Compatible Audio</li></ul>\', \'recommended\': \'<strong> Recommended</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista, Windows 7, Windows 8<br> </li><li><strong>Processor:</strong> Intel Core 2 Quad 2.66 GHz or better<br> </li><li><strong>Memory:</strong> 2 GB RAM<br> </li><li><strong>Hard Disk Space:</strong> 12 GB free hard drive space <br> </li><li><strong>Video Card:</strong> NVIDIA GeForce 8600 or better<br> </li><li><strong>DirectX®:</strong> 9.0c or greater<br> </li><li><strong>Sound:</strong> DirectSound, DirectX9.0c Compatible Audio</li></ul>\'}', '0', '0,08', '0', '0,01', '0,1'),
(517, 'guilty gear isuka', '2014', 0, 0, 148, 145, 147, 6.99, 'A new Gear arises, its name Leopaldon. As they threaten to lay waste to the world, you prepare to mount your offense. The good news? You won\'t have to face them alone. Guilty Gear Isuka introduces the brand new mechanic of cooperative gameplay to the tried and true fighting madness of the Guilty Gear XX series.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP / Windows Vista / Windows 7<br></li><li><strong>Processor:</strong> Intel Celeron 500MHz or faster<br></li><li><strong>Memory:</strong> 256 MB RAM<br></li><li><strong>Graphics:</strong> Direct3D compatible VRAM32MB or faster 3D Accelerator Card<br></li><li><strong>DirectX:</strong> Version 8.1<br></li><li><strong>Storage:</strong> 900 MB available space<br></li><li><strong>Sound Card:</strong> DirectSound compatible sound card</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP / Windows Vista / Windows 7<br></li><li><strong>Processor:</strong> Intel PentiumIII 800MHz or faster<br></li><li><strong>Memory:</strong> 512 MB RAM<br></li><li><strong>Graphics:</strong> Direct3D compatible VRAM64MB or faster 3D Accelerator Card<br></li><li><strong>DirectX:</strong> Version 8.1<br></li><li><strong>Storage:</strong> 900 MB available space<br></li><li><strong>Sound Card:</strong> DirectSound compatible sound card</li></ul>\'}', '0,05', '0,04', '0', '0,01', '0,1'),
(518, 'darkest of days', '2010', 0, 0, 158, 63, 0, 14.99, 'Have you ever wondered what could happen if time travel was a reality? Have you ever thought about the possibility of going back in time to rewrite history for the better? That possibility is a reality in Darkest of Days, where players will travel back and forth through the annals of time to relive some of mankind\'s most dire hours.', '{\'minimum\': \'\\n\\t\\t\\t\\t\\t<p><strong>Minimum:</strong></p>\\n\\t\\t\\t\\t\\t<ul>\\n\\t\\t\\t\\t\\t\\t<li><strong>OS:</strong> Windows XP (Service Pack 2)</li>\\n\\t\\t\\t\\t\\t\\t<li><strong>Processor:</strong> 2.0 Ghz</li>\\n\\t\\t\\t\\t\\t\\t<li><strong>Memory:</strong> 768 MB </li>\\n\\t\\t\\t\\t\\t\\t<li><strong>Graphics:</strong> nVIDIA GeForce 6600 or ATI Radeon 9800 with at least 128 MB of video memory</li>\\n\\t\\t\\t\\t\\t\\t<li><strong>DirectX&reg;:</strong> 9.0c</li>\\n\\t\\t\\t\\t\\t\\t<li><strong>Hard Drive:</strong> 5 GB available </li>\\n\\t\\t\\t\\t\\t\\t<li><strong>Sound:</strong> a working sound device</li>\\n\\t\\t\\t\\t\\t</ul>\\n\\t\\t\\t\\t\\t\', \'recommended\': \'\\n\\t\\t\\t\\t\\t<p><strong>Recommended:</strong></p>\\n\\t\\t\\t\\t\\t<ul>\\n\\t\\t\\t\\t\\t\\t<li><strong>OS:</strong> Windows XP (Service Pack 2) / Vista</li>\\n\\t\\t\\t\\t\\t\\t<li><strong>Processor:</strong> 2.0 Ghz or better dual-core CPU</li>\\n\\t\\t\\t\\t\\t\\t<li><strong>Memory:</strong> 2.0 GB </li>\\n\\t\\t\\t\\t\\t\\t<li><strong>Graphics:</strong> nVIDIA GeForce 8800 or newer/ATI Radeon 3000 or newer</li>\\n\\t\\t\\t\\t\\t\\t<li><strong>DirectX&reg;:</strong> 9.0c</li>\\n\\t\\t\\t\\t\\t\\t<li><strong>Hard Drive:</strong> 5 GB available </li>\\n\\t\\t\\t\\t\\t\\t<li><strong>Sound:</strong> a working sound device</li>\\n\\t\\t\\t\\t\\t</ul>\\n\\t\\t\\t\\t\\t\'}', '0,09', '0', '0', '0,01', '0,09'),
(519, 'dungeons', '2011', 0, 0, 214, 266, 112, 6.99, 'Assume the role of a mighty (and mighty evil) Dungeon Lord and create your own diabolical demesnes underground. 10 different classes of heroes dare to enter your dungeon where 15 different monsters lurk in the dark.', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7/Vista/ XP SP2<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 2.0 GHz Dual Core<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2 GB<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 256 MB DirectX 9.0c Graphics card with Shader Model 3.0<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 2 GB free HDD<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> Windows-compatible Soundcard<br>\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0,07', '0,02', '0', '0,01', '0,09'),
(520, 'chess', '2017', 0, 0, 1, 14, 0, 3.99, 'The classic strategy game with gorgeous graphics, online gaming and intuitive interface.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li>Requires a 64-bit processor and operating system<br></li><li><strong>OS:</strong> XP<br></li><li><strong>Processor:</strong> Intel single core<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> 2004 GPU<br></li><li><strong>Storage:</strong> 300 MB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li>Requires a 64-bit processor and operating system<br></li><li><strong>OS:</strong> 7<br></li><li><strong>Processor:</strong> Intel multi core<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> 2010 GPU<br></li><li><strong>Storage:</strong> 500 MB available space</li></ul>\'}', '0,05', '0,04', '0', '0,01', '0,09'),
(521, 'pacman and the ghostly adventures', '2014', 0, 25, 126, 33, 0, 29.99, 'Pac is back in an all-new experience for a whole new generation of fans. Featuring an original storyline inspired by the show as well as all the charming characters from the highly anticipated PAC-MAN and the Ghostly Adventures animated series created and produced by Avi Arad, acclaimed director and founder of Marvel Studios.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP, Vista, Seven, 8<br></li><li><strong>Processor:</strong> 2Ghz Dual Core or AMD equivalent<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> 512MB video cards Pixel Shader 3.0<br></li><li><strong>DirectX:</strong> Version 9.0<br></li><li><strong>Storage:</strong> 4 GB available space<br></li><li><strong>Sound Card:</strong> DirectX sound device</li></ul>\'}', '0,16', '0,12', '0', '0,03', '0,31'),
(522, 'xcom ufo defense', '2008', 0, 0, 2165, 136, 2235, 2.99, 'You are in control of X-COM: an organization formed by the world\'s governments to fight the ever-increasing alien menace.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>Supported OS: </strong>Microsoft® 2000/XP/Vista® <br>\\t\\t\\t\\t\\t</li><li><strong>Processor: </strong>80386 processor or better <br>\\t\\t\\t\\t\\t</li><li><strong>Memory: </strong>4Mb RAM <br>\\t\\t\\t\\t\\t</li><li><strong>Sound Cards Supported: </strong>AdLib compatible cards, SoundBlaster compatible cards and the Roland LAPC-1. </li></ul>\'}', '0,05', '0,04', '0', '0,01', '0,09'),
(523, 'star wars empire at war gold pack', '2010', 0, 0, 6526, 396, 395, 15.49, 'Command or corrupt an entire galaxy in the definitive Star Wars strategy collection. It is a time of galactic civil war. Will you take up the reins of the Rebellion, assume control of the Empire, or rule the Star Wars Underworld?', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>Computer:</strong> 100% DirectX 9.0c compatible computer<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Pentium III 1.0GHz or AMD Athlon 1.0 GHz<br>\\t\\t\\t\\t\\t\\t</li><li><strong>OS:</strong> Windows XP SP3, Windows Vista SP2, Windows 7<br>\\t\\t\\t\\t\\t\\t</li><li><strong>RAM:</strong> 512 MB<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics Card:</strong> 64 MB graphics card with Shader Model 2.0 support / ATI Radeon 9600 / NVIDIA 7200 / Intel 965<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Sound Card:</strong> 100% DirectX 9.0c compatible PCI, USB, or Onboard Audio Device<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Internet:</strong> 56kbps or faster connection (required for multiplayer only)<br>\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>Computer:</strong> 100% DirectX 9.0c compatible computer<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Pentium Dual Core CPU<br>\\t\\t\\t\\t\\t\\t</li><li><strong>OS:</strong> Windows XP SP3, Windows Vista SP2, Windows 7<br>\\t\\t\\t\\t\\t\\t</li><li><strong>RAM:</strong> 1 GB<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics Card:</strong> 256 MB graphics card with Shader Model 3.0 support / ATI Radeon X1900 / NVIDIA 8600<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Sound Card:</strong> 100% DirectX 9.0c compatible PCI, USB, or Onboard Audio Device<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Internet:</strong> 1.5Mb DSL/Cable connection (required for multiplayer only)<br>\\t\\t\\t\\t\\t</li></ul>\'}', '0,01', '0,06', '0', '0,01', '0,09'),
(524, 'locks quest', '2017', 0, 27, 22, 22, 0, 13.99, 'Build Defenses and Battle against the Clockwork horde in this 2D Action RPG / Tower Defense hybrid. Experience a gripping story, which unfolds as you progress through 75 Days of warfare, aided by a collection of turrets, traps and special attacks.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7<br></li><li><strong>Processor:</strong> 2.0 Ghz or above<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> DX11 with feature level 9.3 capabilities<br></li><li><strong>DirectX:</strong> Version 9.0<br></li><li><strong>Storage:</strong> 2 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 10<br></li><li><strong>Processor:</strong> 2.7 Ghz or above<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> DX11 with feature level 9.3 capabilities<br></li><li><strong>DirectX:</strong> Version 12<br></li><li><strong>Storage:</strong> 2 GB available space</li></ul>\'}', '0,08', '0', '0', '0,01', '0,09'),
(525, 'metal slug x', '2014', 0, 15, 1544, 164, 533, 5.59, '“METAL SLUG X”, one of the most highly praised titles in the series among Metal Slug fans for its refined balance and game volume, heads out to the Steam gaming platform!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista, 7, 8<br></li><li><strong>Processor:</strong> Pentium 4 2.4Ghz<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> Intel HD Graphics<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 500 MB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista, 7, 8<br></li><li><strong>Processor:</strong> 2 GHz Dual Core<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GT 640<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 500 MB available space</li></ul>\'}', '0,05', '0,03', '0', '0,01', '0,09'),
(526, 'cake mania main street', '2010', 0, 0, 13, 5, 0, 4.99, 'Take a trip back to Jill Evans\'&trade; hometown of Bakersfield in Cake Mania Main Street&trade;, the highly anticipated fourth chapter in one of the most popular time management series of all time! Help Jill and her closest friends earn enough money to revitalize Main Street by opening, managing, and upgrading four unique downtown shops...', '{\'minimum\': \'<ul>\\n\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>OS:</strong> Windows XP/Vista/7\\n\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>Processor:</strong> Pentium III 800MHz or better (1.0 GHz Vista)\\n\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>Memory:</strong> 256 MB System RAM (512 MB Vista)\\n\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>Graphics:</strong> 32MB Video RAM\\n\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>DirectX&reg;:</strong> Direct-X 8.1 (10 Vista)\\n\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>Other Requirements:</strong> Internet Explorer 5.0+, AOL 5,6 or MSN browsers\\n\\t\\t\\t\\t\\t\\t\\t\\t</ul>\'}', '0,09', '0', '0', '0,01', '0,09'),
(527, 'damnation', '2009', 0, 0, 132, 182, 0, 6.99, 'Evolving the shooter genre with its unique and exhilarating combination of fluid action and combat, Damnation features huge, open environments, frenetic combat, daredevil acrobatics and high-octane vehicle-based stunts.', '{\'minimum\': \'<strong>Minimum:</strong><br> <ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP/Vista . (if running Windows Vista SP1 is recommended)<br>\\t </li><li><strong>Processor:</strong> 2.8 Ghz Pentium or AMD™ equivalent<br>\\t </li><li><strong>Memory:</strong> 1 GB RAM<br>\\t </li><li><strong>Graphics:</strong> GeForce 7600 / Radeon X1300 or above<br>\\t </li><li><strong>DirectX®:</strong> 9.0c<br>\\t </li><li><strong>Hard Drive:</strong> 10 GB Hard Drive Space<br>\\t </li><li><strong>Sound:</strong> DirectX Compatible Sound Card<br>\\t </li><li><strong>Supported Controller: </strong>Microsoft X360 controller for Windows<br> </li></ul>Supported Hardware<br> <ul class=\"bb_ul\"><li>ATI Radeon x1300, x1600, x1800, x1900, x1950, HD2400, HD2600, HD2900, HD3450, HD3470, HD3650, HD3850, HD3870. HD4850, HD4870, HD4870X2<br> </li><li>NVIDIA Geforce 7600, 7800, 7900, 7950, 8500, 8600, 8800, 9600, 9800, 9800GX2, GTX260, GTX280 <br> </li><li>Not compatible with all integrated sound/graphics solutions (inc.Laptops) <br> </li><li>This product uses a copyright protection system. Please visit <a href=\"https://steamcommunity.com/linkfilter/?url=http://www.codemasters.com\" target=\"_blank\" rel=\"noopener\" >www.codemasters.com</a> for further details.<br> </li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br> <ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP/Vista. (if running Windows Vista SP1 is recommended)<br>\\t </li><li><strong>Processor:</strong> Intel Core 2 Duo @ 2.66Ghz or Athlon X2 3800+ <br>\\t </li><li><strong>Memory:</strong> 2GB RAM<br>\\t </li><li><strong>Graphics:</strong> GeForce 8800GTX or above, or Radeon 3800 series or above<br>\\t </li><li><strong>DirectX®:</strong> 9.0c<br>\\t </li><li><strong>Hard Drive:</strong> 11 GB Hard Drive Space<br>\\t </li><li><strong>Sound:</strong> Creative Sound Blaster X-Fi Sound Card.<br> </li></ul>\'}', '0,13', '0,03', '0', '0,02', '0,17'),
(528, 'tunnel b1', '2018', 0, 0, 5, 7, 0, 5.19, 'Speed through a set of tunnels on a mission to destroy your enemy\'s ultimate weapon. The tunnels are filled with enemy vehicles, choppers and sentry guns which you must either take out or avoid.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7, Windows 8, Windows 10<br></li><li><strong>Processor:</strong> Pentium 4n<br></li><li><strong>Memory:</strong> 256 MB RAM<br></li><li><strong>Graphics:</strong> Athlon 64 or later<br></li><li><strong>Storage:</strong> 256 MB available space</li></ul>\'}', '0,05', '0,03', '0', '0,01', '0,09'),
(529, 'supreme commander', '2011', 0, 0, 1065, 162, 306, 8.99, 'For a thousand years, three opposing forces have waged war for what they believe is true. There can be no room for compromise: their way is the only way. Dubbed The Infinite War, this devastating conflict has taken its toll on a once-peaceful galaxy and has only served to deepen the hatred between the factions.', '{\'minimum\': \'<strong>Recommended:</strong><br>\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® XP Service Pack 2, Windows® Vista<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 3.0 GHz Intel or equivalent AMD processor or better<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1 GB RAM or better<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space:</strong> 8GB available hard drive space\\t<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Video Card:</strong> 256 MB video RAM, with DirectX 9 Vertex Shader / Pixel Shader 2.0 support (Nvidia 6800 or better)<br>\\t\\t\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® XP Service Pack 2, Windows® Vista<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 1.8 GHz processor <br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 512 MB RAM<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space:</strong> 8GB available hard drive space\\t<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Video Card:</strong> 128 MB video RAM or greater, with DirectX 9 Vertex Shader / Pixel Shader 2.0 support (ATI 9600+, Nvidia 6200+)<br>\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0,07', '0,05', '0', '0,02', '0,14'),
(530, 'ikaruga', '2014', 0, 25, 1398, 70, 454, 6.99, 'Shoot! Dodge! and... Get Hit!? &quot;Ikaruga&quot; is a vertical shoot \'em up that features an unique polarity-switching gameplay. Switch the ship\'s polarity and &quot;get hit and absorb&quot; enemy bullets! Achieve High Score with the chain bonus!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 8 / 7 / Vista / XP<br></li><li><strong>Processor:</strong> Intel Core2 Duo / Athron64 X2<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> DirectX 9.0c support (256 MB VRAM)<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 512 MB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c support</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7<br></li><li><strong>Processor:</strong> Intel or AMD multicore processor recently 5 years<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA or AMD in recently 5 years<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 512 MB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c support</li></ul>\'}', '0,07', '0,02', '0', '0', '0,09'),
(531, 'escape dead island', '2014', 16, 60, 549, 383, 0, 10.99, 'Escape Dead Island is a Survival-Mystery adventure that lets players delve into the Dead Island universe and unravel the origins of the zombie outbreak.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista x86 SP2 with DirectX 11 Update Installed, Windows 7 or Windows 8<br></li><li><strong>Processor:</strong> Intel Core 2 Duo E4600 or AMD Athlon 64 X2 4800+<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> Radeon HD 5450 (1 GB) or GeForce GT 430 (1 GB)<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 10 GB available space<br></li><li><strong>Sound Card:</strong> DirectX compatible sound card<br></li><li><strong>Additional Notes:</strong> There is no support for Windows XP or DirectX 9 and below.</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 (64-bit) or Windows 8 (64-bit)<br></li><li><strong>Processor:</strong> Intel Core 2 Quad Q6600 or AMD Phenom 9850<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> Radeon HD 6850 (1 GB) or GeForce GTX 460 (1 GB)<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 10 GB available space<br></li><li><strong>Sound Card:</strong> DirectX compatible sound card</li></ul>\'}', '0,06', '0,09', '0', '0,02', '0,17'),
(532, 'counterstrike source', '2004', 0, 147, 76640, 3497, 6842, 7.19, 'Just updated to include player stats, achievements, new scoreboards and more!', '{\'minimum\': \'\\r\\n\\t\\t\\t<p><strong>Minimum: </strong>1.7 GHz Processor, 512MB RAM, DirectX&reg; 8.1 level Graphics Card (Requires support for SSE), Windows&reg; 7 (32/64-bit)/Vista/XP, Mouse, Keyboard, Internet Connection</p>\\r\\n\\t\\t\\t<p><strong>Recommended: </strong>Pentium 4 processor (3.0GHz, or better), 1GB RAM, DirectX&reg; 9 level Graphics Card, Windows&reg; 7 (32/64-bit)/Vista/XP, Mouse, Keyboard, Internet Connection</p>\\r\\n\\t\\t\\t\'}', '0', '0,07', '0', '0,02', '0,09'),
(533, 'gray matter', '2014', 0, 0, 419, 47, 0, 6.99, 'After a tragic accident, neurobiologist Dr. David Styles has become a recluse, rarely leaving his home, the Dread Hill House. One day, Samantha Everett, a street magician, appears at Dr. Style\'s doorstep just as he is seeking a new assistant.', '{\'minimum\': \'<strong>Минимальные:</strong><br><ul class=\"bb_ul\"><li><strong>ОС:</strong> Windows XP/Windows Vista/Windows 7/Windows 8<br></li><li><strong>Процессор:</strong> 1.8 GHz Processor or faster<br></li><li><strong>Оперативная память:</strong> 1 GB ОЗУ<br></li><li><strong>Видеокарта:</strong> DirectX 9.0 compatible 256 MB Graphics Card with Shader 2.0<br></li><li><strong>DirectX:</strong> Версии 9.0<br></li><li><strong>Место на диске:</strong> 6 GB</li></ul>\'}', '0,02', '0,09', '0', '0,02', '0,14'),
(534, 'might & magic heroes vii', '2015', 0, 33, 1438, 1665, 0, 33.99, 'Might &amp; Magic® Heroes® VII makes a triumphant return bringing you the essence of turn based strategy gaming. Set in a fantasy universe with RPG progression with a strong story narrative, you will embark on a journey that you will never forget!', '{\'minimum\': \'<strong>Минимальные:</strong><br><ul class=\"bb_ul\"><li><strong>ОС:</strong> Windows 7 SP1 or Windows 8/8.1 (64bit only)<br></li><li><strong>Процессор:</strong> Intel Core i5 660 3.3 GHz or AMD Phenom II X4 955 @ 3.2 GHz<br></li><li><strong>Оперативная память:</strong> 4 GB ОЗУ<br></li><li><strong>Видеокарта:</strong> nVidia GeForce GTX460 or AMD Radeon HD5850 (1024 MB VRAM)<br></li><li><strong>Дополнительно:</strong> Game contains Denuvo <a href=\"https://steamcommunity.com/linkfilter/?url=http://(https://www.denuvo.com/)\" target=\"_blank\" rel=\"noopener\" >(https://www.denuvo.com/)</a> anti-tamper technology.</li></ul>\', \'recommended\': \'<strong>Рекомендованные:</strong><br><ul class=\"bb_ul\"><li><strong>ОС:</strong> Windows 7 SP1 or Windows 8/8.1 (64bit only)<br></li><li><strong>Процессор:</strong> Intel Core i5 2400 @ 3.1 GHz or AMD FX-6100 @ 3.3 GHz<br></li><li><strong>Оперативная память:</strong> 6 GB ОЗУ<br></li><li><strong>Видеокарта:</strong> nVidia GeForce GTX670 or AMD Radeon HD7870 (2048 MB VRAM)<br></li><li><strong>Дополнительно:</strong> Game contains Denuvo <a href=\"https://steamcommunity.com/linkfilter/?url=http://(https://www.denuvo.com/)\" target=\"_blank\" rel=\"noopener\" >(https://www.denuvo.com/)</a> anti-tamper technology.</li></ul>\'}', '0', '0,08', '0', '0', '0,09'),
