(536, 'edna & harvey harveys new eyes', '2012', 0, 29, 1674, 162, 170, 15.99, 'From the creators of the award winning games “The Whispered World” and “Deponia” comes this extraordinary game Edna &amp; Harvey: Harvey\'s New Eyes.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong>Windows Vista/7<br>\\t</li><li><strong>Processor:</strong>2GHz (Single Core) or 1,8GHz (Dual Core)<br>\\t</li><li><strong>Memory:</strong>1536 MB RAM<br>\\t</li><li><strong>Graphics:</strong>ATI Radeon HD 3400 Series, Geforce 9400 Series with at least 256 MB VRAM<br>\\t</li><li><strong>Hard Drive:</strong>1100 MB HD space<br>\\t</li><li><strong>Sound:</strong>DirectX 9.0c compatible sound card with latest drivers</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong>Windows Vista/7/8<br>\\t</li><li><strong>Processor:</strong>2.6 GHz Dual Core CPU<br>\\t</li><li><strong>Memory:</strong>2 GB RAM<br>\\t</li><li><strong>Graphics:</strong>ATI Radeon HD 4500 Series, Geforce 9400 GT or higher<br>\\t</li><li><strong>Hard Drive:</strong>1100 MB HD space<br>\\t</li><li><strong>Sound:</strong>DirectX 9.0c compatible sound card with latest drivers</li></ul>\'}', '0', '0,07', '0', '0,01', '0,09'),
(537, 'cyberia', '2017', 0, 0, 12, 0, 0, 6.99, '11 incredible action sequences featuring realistic character interaction and challenging puzzle solvingTake control of outlaw computer hacker Zak as you infiltrate a secret terrorist base to steal the ultimate doomsday devicePilot several different vehicles, including a stealth fighter jet and a nanotech virus cleaner', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP / Vista / 7 / 8 / 10<br></li><li><strong>Processor:</strong> 1.8 GHz<br></li><li><strong>Memory:</strong> 512 MB RAM<br></li><li><strong>Graphics:</strong> 3D graphics card compatible with DirectX 9.0c<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 445 MB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Storage:</strong> 2 GB available space</li></ul>\'}', '0,05', '0,03', '0', '0,01', '0,09'),
(538, 'lara croft and the temple of osiris', '2014', 12, 40, 696, 538, 38, 14.99, 'Lara Croft and the Temple of Osiris is the sequel to the critically-acclaimed Lara Croft and the Guardian of Light, and the first-ever four-player co-op experience with Lara Croft.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista, Windows 7, Windows 8<br></li><li><strong>Processor:</strong> 2.0 GHz high end Dual Core CPU<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> AMD Radeon HD 6000 series or better / NVidia GeForce 500 series or better<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 5 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista, Windows 7, Windows 8<br></li><li><strong>Processor:</strong> Quad core CPU: AMD Phenom II X4 955 or Intel Core i5-750<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> AMD Radeon HD R7/ NVidia GTX 650<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 5 GB available space</li></ul>\'}', '0', '0,09', '0', '0,01', '0,1'),
(539, 'arslan the warriors of legend', '2016', 0, 41, 131, 52, 68, 49.99, 'An exciting collaboration between The Heroic Legend of Arslan anime and the action-infused Warriors series! Experience the grand historical fantasy with ARSLAN: THE WARRIORS OF LEGEND!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® 10, Windows® 8.1, Windows® 7, Windows Vista® (64bit)<br></li><li><strong>Processor:</strong> Core i7 870 2.8GHz or better<br></li><li><strong>Memory:</strong> 3 GB RAM<br></li><li><strong>Graphics:</strong> 640*480 pixel over, High Color<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 11 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c over<br></li><li><strong>Additional Notes:</strong> VRAM 1GB over, recommend XInput controller</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® 10, Windows® 8.1, Windows® 7, Windows Vista® (64bit)<br></li><li><strong>Processor:</strong> Core i7 2600 3.4GHz or better<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> 1980*1080 pixel over, True Color, 16:9 display<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 11 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c over<br></li><li><strong>Additional Notes:</strong> VRAM 2GB over, recommend XInput controller</li></ul>\'}', '0,03', '0,01', '0,09', '0,01', '0,15'),
(540, 'wildlife park 3', '2014', 0, 41, 192, 178, 0, 6.99, 'Do you have what it takes to be a zoo tycoon? You are responsible for your very own and unique zoo. Choose from numerous types of enclosures, park buildings and plants to design an environment appropriate to each species. Take home a part of wilderness with Wildlife Park 3!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 10/8/7<br></li><li><strong>Processor:</strong> 3 GHz Intel Pentium® D, AMD Athlon™64 3000+<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce 8600 GT, ATI Radeon X1800 or better (min. 256 MB Video- RAM, DirectX®9c, Shadermodel 2.0)<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 2 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 10/8/7<br></li><li><strong>Processor:</strong> Dualcore CPU (Intel E4300, AMD Athlon™ X2 3800+)<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce 8800 GTX, ATI Radeon 3870 or better<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 2 GB available space</li></ul>\'}', '0', '0,07', '0', '0,02', '0,08'),
(541, 'x rebirth', '2013', 0, 69, 2832, 4032, 1744, 24.99, 'In the distant future, the X universe faces a period of profound and irrevocable change. While the universe stumbles towards an uncertain future, countless adventures await as new enemies rise in search of power.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li>Requires a 64-bit processor and operating system<br></li><li><strong>OS:</strong> Windows 10 (64-bit), Windows 8 (64-bit), Windows 7 SP1 (64-bit), Vista SP2 (64-bit), XP SP3 (64-bit)<br></li><li><strong>Processor:</strong> Intel i-Series at 2GHz or AMD equivalent<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> Nvidia GT400 series with 512MB RAM or better, ATI 4870HD with 512MB RAM or better<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 8 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c Compatible Sound Card</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li>Requires a 64-bit processor and operating system<br></li><li><strong>OS:</strong> Windows 10 (64-bit), Windows 8 (64-bit), Windows 7 SP1 (64-bit)<br></li><li><strong>Processor:</strong> Intel i5 (Quad) or i7 at 2.5GHz or AMD equivalent<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> Nvidia GT500 series with 1GB RAM or better, ATI 5870HD with 1GB RAM or better<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 12 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c Compatible Sound Card</li></ul>\'}', '0', '0,08', '0', '0,01', '0,08'),
(542, 'exit', '2016', 0, 39, 26, 2, 0, 5.99, 'EXIT is a very challenging a puzzle game that requires pure logic rather than luck or dexterity. It includes 100 levels that will blow your mind. Are you READY?', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li>Requires a 64-bit processor and operating system<br></li><li><strong>OS:</strong> Windows 7, Windows 8, Windows 8.1, Windows 10 32/64bit<br></li><li><strong>Processor:</strong> Intel/AMD SSE2 2.0GHz<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> GPU with OpenGL 3.2 support e.g. Intel HD Graphics 4400 / GeForce 210 / AMD Radeon R5 M200 / HD 8500M / HD 8470D<br></li><li><strong>Storage:</strong> 700 MB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li>Requires a 64-bit processor and operating system<br></li><li><strong>OS:</strong> Windows 7, Windows 8, Windows 8.1, Windows 10 32/64bit<br></li><li><strong>Processor:</strong> Intel/AMD SSE2 2.0GHz<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> GPU with OpenGL 3.2 support e.g. AMD 6850 / NVIDIA GTX 550<br></li><li><strong>Storage:</strong> 700 MB available space</li></ul>\'}', '0,07', '0', '0', '0,01', '0,08'),
(543, 'crush', '2014', 0, 8, 24, 77, 0, 1.59, 'C-RUSH is an old school Shooter, with HD graphics.A new threat is coming from the space; the plasma insects. Exterminate the vermin!!Beat your own score and compare it with the other players !Key Features:- One ship with different positions to use- Different Gameplay according to the positions and shoots- A Schmup where you need...', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP SP2<br></li><li><strong>Processor:</strong> 2 Ghz<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> OpenGL 2.0 compatible graphics card and driver<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 200 MB available space<br></li><li><strong>Sound Card:</strong> DirectSound compatible sound card</li></ul>\'}', '0,07', '0', '0', '0,01', '0,08');
INSERT INTO `jeux` (`id_jeu`, `nom_jeu`, `annee`, `age_requis`, `nb_succes`, `nb_avis_pos`, `nb_avis_neg`, `temps_jeu_moyen`, `prix`, `description`, `configuration`, `ventes_AN`, `ventes_EU`, `ventes_JP`, `ventes_Autre`, `ventes_Global`) VALUES
(544, 'crush', '2014', 0, 8, 24, 77, 0, 1.59, 'C-RUSH is an old school Shooter, with HD graphics.A new threat is coming from the space; the plasma insects. Exterminate the vermin!!Beat your own score and compare it with the other players !Key Features:- One ship with different positions to use- Different Gameplay according to the positions and shoots- A Schmup where you need...', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP SP2<br></li><li><strong>Processor:</strong> 2 Ghz<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> OpenGL 2.0 compatible graphics card and driver<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 200 MB available space<br></li><li><strong>Sound Card:</strong> DirectSound compatible sound card</li></ul>\'}', '0,07', '0', '0', '0,01', '0,08'),
(545, 'crush', '2014', 0, 8, 24, 77, 0, 1.59, 'C-RUSH is an old school Shooter, with HD graphics.A new threat is coming from the space; the plasma insects. Exterminate the vermin!!Beat your own score and compare it with the other players !Key Features:- One ship with different positions to use- Different Gameplay according to the positions and shoots- A Schmup where you need...', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP SP2<br></li><li><strong>Processor:</strong> 2 Ghz<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> OpenGL 2.0 compatible graphics card and driver<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 200 MB available space<br></li><li><strong>Sound Card:</strong> DirectSound compatible sound card</li></ul>\'}', '0,07', '0', '0', '0,01', '0,08'),
(546, 'final fantasy vi', '2015', 12, 28, 884, 259, 0, 10.99, 'The highly rated and widely popular sixth instalment of the legendary FINAL FANTASY series comes to PC!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista / 7 / 8 / 8.1<br></li><li><strong>Processor:</strong> Pentium 4 2.4 GHz<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Storage:</strong> 950 MB available space<br></li><li><strong>Additional Notes:</strong> *Anti-aliasing FXAA should be switched on at <a href=\"http://steamcommunity.com/app/382900/discussions/0/487877107133276725/\" target=\"_blank\" rel=\"noreferrer\" >certain resolutions</a>. Running Final Fantasy VI with an unsupported controller plugged in, even as a secondary device, can lead the game to crash.</li></ul>\'}', '0', '0', '0,08', '0,01', '0,08'),
(547, 'puzzle chronicles', '2010', 0, 12, 16, 8, 0, 7.99, 'Enter the dark and savage lands of the Ashurin Empire as you battle to avenge the atrocities the Empire brought upon your tribesmen. On your heroic quest to topple the Empire you will fight fierce beasts and battle hardened warriors in this new Puzzle RPG hybrid game.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP/Vista<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Pentium 4 processor<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 512 MB (XP) / 1 GB (Vista)<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 8 GB of free space<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> DirectX 9.0c/Shader3.0, NVIDIA GeForce 6600 series or higher, or ATI Radeon X1600 or higher<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX 9.0c compatible sound cards<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX 9.0c \\t<br>\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0,08', '0', '0', '0,01', '0,1'),
(548, 'silent hunter iii', '2008', 0, 0, 685, 113, 0, 4.29, 'The king of submarine simulations returns with an all-new 3D engine, new crew command features, and more realistic WWII naval action than ever before. The movie-like graphics and simple, tension-filled gameplay make this the perfect game for the realism fanatic and the casual gamer.', '{\'minimum\': \'<ul>\\n\\t\\t\\t\\t\\t<li><strong>OS:</strong> Windows 2000 / XP(only)</li>\\n\\t\\t\\t\\t\\t<li><strong>Processor:</strong> Pentium&reg; III 1.4 GHz or AMD Athlon&trade; 1.4 GHz (Pentium 4 2.0 GHz or AMD Athlon 2.0 GHz recommended)</li>\\n\\t\\t\\t\\t\\t<li><strong>Memory:</strong> 512 MB</li>\\n\\t\\t\\t\\t\\t<li><strong>Graphics:</strong> 64 MB (128 MB video card recommended)(see supported list*)</li>\\n\\t\\t\\t\\t\\t<li><strong>DirectX Version:</strong> DirectX 9.0</li>\\n\\t\\t\\t\\t\\t<li><strong>Sound:</strong> Direct X 9.0 compliant PCI card</li>\\n\\t\\t\\t\\t\\t<li><strong>Hard Drive:</strong> 1.5 GB</li>\\n\\t\\t\\t\\t\\t<li><strong>*Supported Video Cards at Time of Release</strong> Nvidia&reg; GeForce&trade; 3/4/FX series (GeForce 4 MX NOT supported)ATI&reg; Radeon&reg; 8500/9000 families or newer<br>Laptop versions of these chipsets may work but are not supported. These chipsets are currently the only ones that will run this game.</li></ul>\'}', '0', '0,07', '0', '0,01', '0,08'),
(549, 'serious sam 3 bfe', '2011', 0, 62, 15574, 1977, 378, 29.99, 'Serious Sam 3: BFE is a prequel to the original indie fast action FPS and Game of the Year sensation - Serious Sam: The First Encounter!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP 32-bit (with service pack 2 or 3)<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Dual-core from Intel or AMD at 2.0 GHz<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1GB<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> nVidia GeForce 7800/7900/8600 series, ATI/AMD Radeon HD2600/3600 or 1800/X1900 series<br>\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 9.0c<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 4GB free hard drive space<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX9.0c Compatible Sound Card<br>\\t\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 64-bit<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Quad-core from Intel (i5/i7-series) or AMD (Phenom II) at 3.0 GHz<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 4GB<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> nVidia GeForce 480/580 GTX, ATI/AMD Radeon HD 5870/6970<br>\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 9.0c<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 4GB free hard drive space<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX9.0c Compatible Sound Card<br>\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0,01', '0,05', '0', '0,01', '0,08'),
(550, 'valkyrie drive bhikkhuni', '2017', 0, 50, 718, 100, 266, 22.99, 'VALKYRIE DRIVE -BHIKKHUNI- is the all-new all-action brawler from the creators of SENRAN KAGURA. The girls of Bhikkhuni are infected with the mysterious VR-Virus and the only way to control it is to fight.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista<br></li><li><strong>Processor:</strong> 1.8 GHz or equivalent<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> 512 MB VRAM or above<br></li><li><strong>Storage:</strong> 8 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 8/8.1/10<br></li><li><strong>Processor:</strong> Intel Core2 Duo E4500 | AMD Athlon 64 X2 4200+<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> GeForce 9500 GT (1 GB) | Radeon HD 4650 (1 GB)<br></li><li><strong>Storage:</strong> 8 GB available space</li></ul>\'}', '0', '0,01', '0,07', '0', '0,08'),
(551, 'the golf club', '2014', 0, 24, 638, 375, 0, 22.99, 'The Golf Club is a visually stunning golf simulation that features procedurally generated courses, a fully featured course editor, asynchronous online play and outstanding gameplay. Create and share courses with your friends and compete with both friends and rivals in this fresh take on golf.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista, 7, 8<br></li><li><strong>Processor:</strong> Intel Core 2 Duo or equivalent<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> DX11 compatible video card with 1GB video RAM<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 2 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c compatible</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista, 7, 8<br></li><li><strong>Processor:</strong> Intel Core i5 or equivalent<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> Nvidia 660 or AMD 7850 w/ 2GB<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 2 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c compatible</li></ul>\'}', '0,07', '0,02', '0', '0,01', '0,11'),
(552, 'mission runway', '2009', 0, 0, 14, 6, 0, 4.99, 'Do you have what it takes to design a fancy frock or a fashion flop? Compete in creative challenges for the once-in-a-lifetime opportunity to show your creations in a major runway event and become the ultimate fashion designer. Will you be asked to stay or leave Mission: Runway? Take on the fashion challenge?', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® XP/Vista<br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Pentium® III 1.4 GHz or greater<br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 512 MB RAM<br>\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 64 MB DirectX® 9 compliant video card -ATI Radeon 8500, Geforce 5200, Intel 945 or higher<br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 1.2 GB hard drive space<br>\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX 9 compatible sound card<br>\\t\\t\\t\\t\\t</li></ul>\'}', '0,07', '0,01', '0', '0,01', '0,08'),
(553, 'torchlight', '2009', 0, 66, 3825, 317, 1108, 10.99, 'Adventure awaits in the award-winning Action RPG debut from Runic Games! Explore the randomized depths of this boom town, collect loot, and level up to save Torchlight - and possibly the world.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP or later<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> x86-compatible 800MHz processor<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 512MB<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> DirectX-compatible 3D graphics with at least 64MB of addressable memory (such as an ATI Radeon 7200, NVIDIA GeForce 2, or Intel GMA 950)<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 9.0c<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 400MB<br>\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0', '0,06', '0', '0,02', '0,07'),
(554, 'again', '', 0, 0, 0, 0, 0, 0.00, '0', '0', '0,07', '0', '0', '0', '0,07'),
(555, 'simcity 4 deluxe edition', '2010', 0, 0, 3110, 959, 228, 9.99, 'SimCity 4 Deluxe Edition includes the bestselling SimCity 4 and the all-new SimCity 4 Rush Hour Expansion Pack. Create the most massive region of cities ever, with a farming town, bedroom community, high-tech commercial center, and industrial backbone.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> PIII 500 or equivalent <br>\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 256MB <br>\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 32MB supported Direct3D capable video card with DirectX 7.0 or greater<br>\\t\\t\\t\\t\\tcompatible driver<br>\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX 8.1<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 1.6GB<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Supported 3D Accelerator Hardware:</strong> SimCity 4 Deluxe / Rush Hour requires a 32MB 3D Direct3D chipset, and a display that is at least 800x600 in size, and supports 16 or 32-bit color. It is recommended to always install the latest certified drivers for all your hardware<br>\\t\\t\\t\\t\\t</li></ul>\\xa0<br>\\t\\t\\t\\t\\t<h2 class=\"bb_tag\">Supported Graphics Chipsets</h2>\\t\\t\\t\\t\\tCards with these chipsets are officially supported by the SimCity 4 hardware graphics driver:<br>\\t\\t\\t\\t\\tnVidia: <a href=\"https://steamcommunity.com/linkfilter/?url=http://www.nvidia.com\" target=\"_blank\" rel=\"noopener\" >http://www.nvidia.com</a> <br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>nVidia TNT2, TNT2 M64, &amp; TNT2 Ultra</strong><br>\\t\\t\\t\\t\\t</li><li><strong>nVidia GeForce SDR, GeForce DDR, GeForce Quadro, GeForce2 GTS, GeForce2 MX, GeForce2 GTS, GeForce3, GeForce4 MX, GeForce4 Ti 4200/4400/4600/4800 SE, and GeForceFX 5200/5600/5800/5900</strong><br>\\t\\t\\t\\t\\t</li></ul>ATI: <a href=\"https://steamcommunity.com/linkfilter/?url=http://www.ati.com\" target=\"_blank\" rel=\"noopener\" >http://www.ati.com</a> <br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>ATI Radeon 7000, 7200, 7500, 8500, 9000, 9200, 9500, 9600, 9700, 9800</strong><br>\\t\\t\\t\\t\\t</li><li><strong>Known Issues:</strong> Due to hardware limitations with the ATI Radeon series, some buildings and graphic effects will be temporarily turned off while scrolling. There is a known ATI driver defect that results in SimCity advisor animations dropping polygons. To fix this, please download ATI driver 7.79 or later (also referred to as CATALYST 02.4) from <a href=\"https://steamcommunity.com/linkfilter/?url=http://www.ati.com\" target=\"_blank\" rel=\"noopener\" >http://www.ati.com</a> on the Internet.<br>\\t\\t\\t\\t\\t</li></ul>Matrox: <a href=\"https://steamcommunity.com/linkfilter/?url=http://www.matrox.com\" target=\"_blank\" rel=\"noopener\" >http://www.matrox.com</a> <br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>Matrox G400, G450, G550, Parhelia</strong><br>\\t\\t\\t\\t\\t</li></ul>SiS: <a href=\"https://steamcommunity.com/linkfilter/?url=http://www.sis.com\" target=\"_blank\" rel=\"noopener\" >http://www.sis.com</a> <br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>SiS 315, Xabre 400</strong><br>\\t\\t\\t\\t\\t</li></ul><strong>Software Mode: </strong>SimCity 4 also provides a software-based graphics driver which will work with most video cards. 32MB of video memory is recommended. The graphics mode driver can be selected from the Graphics Options panel in the game, or may be run from the command line using the switch -d:Software. The following video chipsets will run the game properly in software mode:<br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>PowerVR KYRO, KYRO II</strong><br>\\t\\t\\t\\t\\t</li><li><strong>Trident Blade 64</strong><br>\\t\\t\\t\\t\\t</li></ul>\'}', '0', '0,06', '0', '0,01', '0,07'),
(556, 'still life', '2011', 0, 0, 431, 98, 13, 5.59, 'Still Life 2 also now available!', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® XP/Vista/7<br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 1GHz CPU <br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 512MB<br>\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space:</strong> 1.2GB\\t<br>\\t\\t\\t\\t\\t</li><li><strong>Video Card:</strong> DirectX compatible graphics card with 128MB memory <br>\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 9.0c<br>\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> Sound card with DirectX 9.0c support<br>\\t\\t\\t\\t\\t</li></ul>\'}', '0,05', '0,02', '0', '0', '0,07'),
(557, 'goodbye deponia', '2013', 0, 50, 1324, 163, 239, 16.99, 'More chaos, more destruction, more Rufus. Not one, not two, but three Rufuses cause all kinds of crazy mayhem in the long-awaited adventure comedy Goodbye Deponia!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista/7/8<br></li><li><strong>Processor:</strong> 2.5 GHz Single Core Processor or 2 GHz Dual Core Processor<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> OpenGL 2.0 compatible with 256 MB RAM (Shared Memory is not recommended)<br></li><li><strong>Storage:</strong> 3 GB available space<br></li><li><strong>Additional Notes:</strong> Mouse</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista/7/8<br></li><li><strong>Processor:</strong> 2.5 GHz Single Core Processor or 2 GHz Dual Core Processor<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> OpenGL 2.0 compatible with 512 MB RAM (Shared Memory is not recommended)<br></li><li><strong>Storage:</strong> 3 GB available space<br></li><li><strong>Additional Notes:</strong> Mouse</li></ul>\'}', '0', '0,06', '0', '0,01', '0,07'),
(558, 'damage inc pacific squadron wwii', '2012', 0, 36, 6, 6, 0, 29.99, 'Take to the skies in one of over 30 accurately represented aircraft and defend the Pacific Theatre from invading enemy forces.', '{\'minimum\': \'<p><strong>Minimum:</strong></p>\\n<ul>\\n\\t<li><strong>OS:</strong>Windows XP (SP2)</li>\\n\\t<li><strong>Processor:</strong>Intel Core 2 Duo 2.0GHz or AMD Athlon X2 4000+</li>\\n\\t<li><strong>Memory:</strong>1 GB RAM</li>\\n\\t<li><strong>Graphics:</strong>NVIDIA GeForce 7800 or ATI Radeon HD 2600 Pro, 256MB, Shader Model 3.0+ Graphics Card</li>\\n\\t<li><strong>DirectX&reg;:</strong>9.0c</li>\\n\\t<li><strong>Hard Drive:</strong>4 GB HD space</li>\\n\\t<li><strong>Sound:</strong>DirectX 9.0c-compatible Sound Card</li>\\n\\t<li><strong>Other Requirements:</strong>Broadband Internet connection</li>\\n</ul>\', \'recommended\': \'<p><strong>Recommended:</strong></p>\\n<ul>\\n\\t<li><strong>Memory:</strong>2 GB RAM</li>\\n</ul>\'}', '0,07', '0', '0', '0,01', '0,07'),
(559, 'mugen souls z', '2016', 0, 50, 53, 14, 0, 14.99, 'Chou-Chou and the gang return in this brand-new S-RPG sequel with a new story and even cuter, super-powerful, godly action and adventure! Lady Chou-Chou must rely on the abilities of an all-new ultimate goddess, Syrma, as she tries to stop this ancient threat to her world.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP<br></li><li><strong>Processor:</strong> 2.13GHz Intel Core2 Duo or equivalent<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> DirectX 9.0c compatible graphics card with 512Mb RAM and support for v3 shaders<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 6 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c compatible sound card</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 or later<br></li><li><strong>Processor:</strong> 3GHz Intel i3 or equivalent<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> DirectX 9.0c compatible graphics card with 1GB RAM and support for v3 shaders<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 6 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c compatible sound card</li></ul>\'}', '0,02', '0,01', '0,04', '0,01', '0,07'),
(560, 'rugby world cup 2015', '2015', 0, 20, 9, 21, 0, 22.99, 'Experience the passion of rugby in the official 2015 Rugby World Cup video game. Choose from among the 20 teams competing in the World Cup and take part in the most prestigious rugby competition to win the Webb Ellis Cup.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® XP, Vista, 7, 8.1, 10<br></li><li><strong>Processor:</strong> Intel™ Core 2 Duo or equivalent<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> Video card with 1GB video RAM<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 3 GB available space<br></li><li><strong>Additional Notes:</strong> A PC-compatible gamepad is required.</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® Vista, 7, 8.1, 10<br></li><li><strong>Processor:</strong> Intel™ Core i5 or equivalent<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> Nvidia® GeForce 660 or AMD® Radeon™ 7850 with 2GB video memory<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 3 GB available space<br></li><li><strong>Additional Notes:</strong> A PC-compatible gamepad is required.</li></ul>\'}', '0', '0,21', '0', '0,03', '0,25'),
(561, 'guilty gear xrd revelator', '2016', 0, 42, 2163, 151, 1474, 22.99, 'Astonishing 3D cell animations and overwhelming content volume, the next-generation fighting game &quot;GUILTY GEAR Xrd -REVELATOR-&quot; is now out on Steam! Total cast of 23 unique characters, and tons of game modes, get ready to ROCK!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 / 8.1 / 10 (32bit/64bit)<br></li><li><strong>Processor:</strong> Intel Core i5 @ 2.0 GHz<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> Nvidia GeForce GTX 560 / Radeon HD 7770<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 12 GB available space</li></ul>\'}', '0,03', '0,02', '0,07', '0,01', '0,14'),
(562, 'fable the lost chapters', '2011', 0, 0, 4384, 364, 494, 6.99, 'Each person you aid, each flower you crush, and each creature you slay will change this world forever. Fable: Who will you be?', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP or later<br>\\t\\t\\t\\t</li><li><strong>Processor:</strong> 1.4 GHz equivalent or greater<br>\\t\\t\\t\\t</li><li><strong>Memory:</strong> 256MB<br>\\t\\t\\t\\t</li><li><strong>Hard Disk Space:</strong> 3GB of available hard disk space\\t<br>\\t\\t\\t\\t</li><li><strong>Video Card:</strong> 64 MB shader-capable video card<br>\\t\\t\\t\\t</li><li><strong>Sound:</strong> Sound card and either a set of speakers or a set of headphones are required for audio\\t<br>\\t\\t\\t\\t</li></ul>\'}', '0,01', '0,05', '0', '0,01', '0,07'),
(563, 'hearts of iron iii', '2009', 0, 0, 3298, 992, 809, 7.99, 'Hearts of Iron III lets you play the most engaging conflict in world history, World War 2, on all fronts as any country and through multiple different scenarios. Guide your nation to glory between 1936 and 1948 and wage war, conduct diplomacy and build your industry in the most detailed World War 2 game ever made.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>Operating System: </strong>Microsoft® Windows® 2000/XP/Vista<br> </li><li><strong>Processor: </strong>Intel Pentium IV 2.4 GHz or AMD 3500+ <br> </li><li><strong>Memory: </strong>2 GB of RAM<br> </li><li><strong>Hard Disk Space: </strong>2 GB<br> </li><li><strong>Video Card: </strong>NVIDIA GeForce 8800 or ATI Radeon X1900 videocard<br> </li><li><strong>Sound: </strong>Direct X-compatible sound card<br> </li><li><strong>DirectX®: </strong>Direct X 9.0<br> </li></ul>\'}', '0,01', '0,04', '0', '0,01', '0,07'),
(564, 'drake of the 99 dragons', '2018', 0, 0, 21, 12, 7, 5.19, 'The 99 Dragons Clan has been murdered. Even worse, the ancient artifact they guard, stolen. With its power, one can trap the souls of the living and resurrect those who have crossed over.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP SP2 or newer<br></li><li><strong>Processor:</strong> Pentium 3 @ 600 MHz Processor<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> Graphics card: DX9 (shader model 3.0)<br></li><li><strong>DirectX:</strong> Version 8.1<br></li><li><strong>Storage:</strong> 2 GB available space<br></li><li><strong>Sound Card:</strong> DirectX Compatible</li></ul>\'}', '0,05', '0,01', '0', '0', '0,07'),
(565, 'cut the rope', '2013', 0, 0, 49, 5, 0, 3.99, 'A mysterious package has arrived, and the little monster inside has only one request… CANDY! Use your mouse to cut the ropes and release delicious bundles of candy into Om Nom\'s mouth. As you keep your new companion\'s sweet tooth satisfied, be sure to collect shiny gold stars to unlock new levels.', '{\'minimum\': \'<p><strong>Minimum:</strong></p>\\n<ul>\\n\\t<li><strong>OS:</strong>XP</li>\\n\\t<li><strong>Processor:</strong>1 GHz</li>\\n\\t<li><strong>Memory:</strong>512 MB RAM</li>\\n\\t<li><strong>Graphics:</strong>supports Shader Model 1.1</li>\\n\\t<li><strong>Hard Drive:</strong>150 MB HD space</li>\\n\\t<li><strong>Sound:</strong>optional</li>\\n</ul>\'}', '0,06', '0', '0', '0,01', '0,07'),
(566, 'port royale 3', '2012', 0, 64, 479, 214, 64, 9.99, 'Develop a successful trading company, lead your ships in naval battles and force your opponents to their knees!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong>Windowx XP / Vista / 7<br>\\t</li><li><strong>Processor:</strong>Dualcore CPU<br>\\t</li><li><strong>Memory:</strong>2 GB RAM<br>\\t</li><li><strong>Graphics:</strong>Shader Model 2.0 PCIe (Geforce 7 Series, Radeon X2000-Series)<br>\\t</li><li><strong>DirectX®:</strong>dx90c<br>\\t</li><li><strong>Hard Drive:</strong>3 GB HD space<br>\\t</li><li><strong>Other Requirements:</strong>Broadband Internet connection</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong>Windows 7<br>\\t</li><li><strong>Processor:</strong>Quadcore CPU<br>\\t</li><li><strong>Memory:</strong>4 GB RAM<br>\\t</li><li><strong>Graphics:</strong>Shader Model 3.0 PCIe, DirectX 10<br>\\t</li><li><strong>DirectX®:</strong>dx10<br>\\t</li><li><strong>Hard Drive:</strong>3 GB HD space<br>\\t</li><li><strong>Other Requirements:</strong>Broadband Internet connection</li></ul>\'}', '0,12', '0', '0', '0,01', '0,14'),
(567, 'circuit breakers', '2015', 0, 19, 48, 30, 0, 4.99, 'Talented and ferocious weapon experts needed to eliminate a dangerous mechanical menace that threatens the existence of humanity. Up to six positions available. Benefits include traveling the world to eliminate robots.', '{\'minimum\': \'<strong>Minimalne:</strong><br><ul class=\"bb_ul\"><li><strong>System operacyjny:</strong> Windows XP<br></li><li><strong>Procesor:</strong> Core 2 Duo @ 2.5GHz or equivalent<br></li><li><strong>Pamięć:</strong> 1 GB RAM<br></li><li><strong>Karta graficzna:</strong> GeForce 8600 GTS or Radeon 3850 or equivalent<br></li><li><strong>DirectX:</strong> Wersja 9.0c<br></li><li><strong>Sieć:</strong> Szerokopasmowe połączenie internetowe<br></li><li><strong>Miejsce na dysku:</strong> 80 MB dostępnej przestrzeni</li></ul>\'}', '0,04', '0,03', '0', '0', '0,07'),
(568, 'sprint cars road to knoxville', '2008', 0, 0, 25, 24, 0, 4.99, 'Buckle up. You\'re going for a ride. Race at speeds over 140 MPH on dirt, on the proving grounds for today\'s top professional drivers. Shoulder to shoulder sprint car racing makes for spectacular crashes, and white-knuckle driving. Start out as a small town star and work your way up through the ranks to become a national legend.', '{\'minimum\': \'<strong>Minimum: </strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>Supported OS: </strong> Microsoft® Windows® 2000/XP/Vista<br>\\t\\t\\t\\t\\t</li><li><strong>Processor: </strong> Intel Pentium III 933 MHz or compatible<br>\\t\\t\\t\\t\\t</li><li><strong>Graphics: </strong> DirectX compatible video card <br>\\t\\t\\t\\t\\t</li><li><strong>Sound: </strong> DirectX compatible sound card <br>\\t\\t\\t\\t\\t</li><li><strong>DirectX Version: </strong>DirectX 9.0<br>\\t\\t\\t\\t\\t</li><li><strong>Memory: </strong> 256 MB RAM<br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive: </strong> 700 MB free hard disk space</li></ul>\'}', '0,03', '0,03', '0', '0,01', '0,07'),
(569, 'enemy front', '2014', 0, 45, 2213, 1307, 116, 15.99, 'ENEMY FRONT is the first truly modern WW2 FPS, featuring stunning visuals, open-ended levels and a richly interactive combat experience that breaks out of the standard model of highly linear scripted FPS experiences, giving the player full freedom to own their playing style.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP, Vista or Windows 7, with the latest Service Pack<br></li><li><strong>Processor:</strong> Intel Core 2 Duo at 2Ghz, or AMD Athlon 64 x2 2Ghz, or better<br></li><li><strong>Memory:</strong> 3 GB RAM<br></li><li><strong>Graphics:</strong> NVidia 8800GT with 512Mb RAM or better<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 10 GB available space</li></ul>\'}', '0,03', '0,08', '0', '0,01', '0,12'),
(570, 'lifeline', '2017', 0, 15, 75, 34, 0, 2.79, 'Help Taylor make life or death decisions, and face the consequences together.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP/Windows Vista/Windows 7/Windows 8/Windows 10<br></li><li><strong>Processor:</strong> 1.0 GHz<br></li><li><strong>Memory:</strong> 1024 MB RAM<br></li><li><strong>DirectX:</strong> Version 9.0<br></li><li><strong>Storage:</strong> 18 MB available space</li></ul>\'}', '0,03', '0,03', '0', '0,01', '0,07'),
(571, 'secret files tunguska', '2009', 0, 0, 135, 32, 0, 7.99, 'Unravel one of the greatest mysteries of our time! On the 30th June 1908 an explosion with the combined energy of 2000 Hiroshima bombs rocked the region of Tunguska in Central Siberia and felled over 6,000 square km of trees. The explosion could be heard from as far as 1,000km away.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 500 MHz Intel Pentium III or AMD Equivalent CPU<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 128 MB RAM<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 16 MB DirectX compatible graphics card<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 2 GB hard disk space<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX compatible sound card<br>\\t\\t\\t\\t\\t</li></ul>\'}', '0,09', '0,07', '0', '0,02', '0,17'),
(572, 'grand ages medieval', '2015', 0, 50, 705, 902, 684, 14.99, 'Rise from the humble role of a simple mayor governing a small settlement and rule over all of Europe.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista<br></li><li><strong>Processor:</strong> Intel® Core™2 Duo Processor E8000 Series or similar<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> DirectX 10 compatible, 1 GB RAM, Geforce GTS450 or similar<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 5 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c compatible</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 / 8 / 10<br></li><li><strong>Processor:</strong> Intel® i5 3 GHz or similar / better<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> DirectX 11 compatible, 2 GB RAM, Geforce GTX 650ti or similar / better<br></li><li><strong>DirectX:</strong> Version 11</li></ul>\'}', '0', '0,09', '0,01', '0,01', '0,12'),
(573, 'obscure', '2014', 0, 19, 685, 55, 0, 4.99, 'For some time now, Leafmore High School has been the setting for unexplained disappearances. In this survival horror game, you take control of a group of 5 American students. With your friends, you try to unravel the mysterious happenings at this unremarkable-looking school. The night will be long and survival not will not be easy...', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP<br></li><li><strong>Processor:</strong> Pentium III 1 GHz<br></li><li><strong>Memory:</strong> 256 MB RAM<br></li><li><strong>Graphics:</strong> DirectX 9.0c compatible 3D card<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 4 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c compatible sound card<br></li><li><strong>Additional Notes:</strong> Cooperative mode (2 players): gamepad required.</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Seven<br></li><li><strong>Processor:</strong> Pentium IV 2 GHz<br></li><li><strong>Memory:</strong> 512 MB RAM<br></li><li><strong>Graphics:</strong> DirectX 9.0c compatible 3D card<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 4 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c compatible sound card<br></li><li><strong>Additional Notes:</strong> Cooperative mode (2 players): gamepad required.</li></ul>\'}', '0,06', '0,04', '0', '0,01', '0,11'),
(574, 'god hand', '2019', 0, 0, 11, 1, 0, 0.00, 'You are the guardian of the town. To protect the village from endless monsters, Remove the monster to maintain the power source.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 or newer<br></li><li><strong>Processor:</strong> Intel i5-4590 / AMD FX 8350 equivalent or greater<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce® GTX 970 / AMD Radeon™ R9 290 equivalent or greater<br></li><li><strong>Storage:</strong> 1 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 10<br></li><li><strong>Processor:</strong> Intel i7-6700<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce® GTX 1070<br></li><li><strong>Storage:</strong> 4 GB available space</li></ul>\'}', '0', '0', '0,07', '0', '0,07'),
(575, 'the book of unwritten tales 2', '2015', 0, 51, 562, 47, 0, 24.99, 'Every world needs its heroes. However unlikely they may seem. Join Wilbur, Ivo, Nate and Critter in another classic point-and-click adventure in the wicked world of Aventásia. Help them fulfill their destiny. A destiny as yet unwritten.', '{\'minimum\': \'<strong>Minimale\\xa0:</strong><br><ul class=\"bb_ul\"><li><strong>Système d\\\'exploitation\\xa0:</strong> Windows XP SP3/Vista/7/8<br></li><li><strong>Processeur\\xa0:</strong> 2.0 GHz CPU<br></li><li><strong>Mémoire vive\\xa0:</strong> 2 GB de mémoire<br></li><li><strong>Graphiques\\xa0:</strong> DirectX 9c compatible graphic card with 512 MB RAM and PixelShader 3.0<br></li><li><strong>DirectX\\xa0:</strong> Version 9.0c<br></li><li><strong>Espace disque\\xa0:</strong> 13 GB d\\\'espace disque disponible<br></li><li><strong>Carte son\\xa0:</strong> DirectX 9.0c compatible</li></ul>\'}', '0', '0,07', '0', '0,01', '0,08'),
(576, 'full spectrum warrior ten hammers', '2007', 0, 0, 76, 38, 1, 4.99, 'Sequel to the critically acclaimed, squad-based/real-time tactical combat game, Full Spectrum Warrior: Ten Hammers delivers the most authentic and realistic infantry combat experience ever. As Squad Leader, coordinate the actions of multiple infantry squads, leading them through over 12 levels of intense action.', '{\'minimum\': \'<strong>Minimum: </strong>Windows 2000/XP (only), AMD Athlon XP or Pentium III 1.5 GHz, 256 MB RAM, DirectX 9.0b-compatible graphics card from NVIDIA® GeForce® 3 and higher (excluding GeForce® 4MX) or ATI® Radeon® 8500 and higher, DirectX 9.0c-compatible sound card, DirectX 9.0c (included), 2.56 GB Free Hard Drive Space, MS Compatible mouse, Broadband Internet Connection (for multiplayer)<br>\\t\\t\\t\\t\\t<strong>Recommended: </strong>Windows XP, AMD Athlon 64; or Pentium 4 2.8GHz+; 1 GB RAM, DirectX 9.0c-compatible graphics card from NVIDIA® (GeForce® 6600 and above), DirectX 9.0c-compatible sound card - Sound Blaster® X-Fi™ series preferred\'}', '0,06', '0,03', '0', '0,01', '0,12'),
(577, 'broken sword 5 the serpents curse', '2013', 0, 35, 1465, 206, 184, 18.99, 'From multi-award winning Revolution Software comes the latest explosive episode in this classic series. Playing as intrepid American George Stobbart and sassy French journalist Nico Collard, you find yourself on the trail of a stolen painting – and a murderous conspiracy.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 10 / 8 / 7 / Vista<br></li><li><strong>Processor:</strong> 1.4 GHz<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> 256 MB<br></li><li><strong>Storage:</strong> 7 GB available space</li></ul>\'}', '0', '0,07', '0', '0,01', '0,07'),
