(579, 'spy fox in dry cereal', '', 0, 0, 0, 0, 0, 0.00, '0', '0', '0,06', '0', '0', '0', '0,06'),
(580, 'song of the deep', '2016', 0, 10, 507, 108, 306, 10.99, 'From the creators of Ratchet &amp; Clank, Song of the Deep is a metroidvania-style action-adventure game following a young girl’s quest into the unknown to find her missing father. It combines underwater discovery, skill, and suspense with a powerful story.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> 64-bit Windows 7 or higher<br></li><li><strong>Processor:</strong> 4 CPUs, &gt;= 2.0 Ghz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> 1GB VRAM or higher<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 3 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> 64-bit Windows 7 or higher<br></li><li><strong>Processor:</strong> 4 CPUs, &gt;= 2.0 Ghz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> 1GB VRAM or higher<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 3 GB available space</li></ul>\'}', '0,1', '0', '0', '0,01', '0,12'),
(581, 'the next big thing', '2011', 0, 0, 352, 59, 1, 6.99, 'The Next Big Thing is a great adventure game in high definition, loaded with laughs, tributes, mysteries and wacky puzzles!', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Microsoft Windows XP SP2, Vista SP1 or 7 <br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel/AMD 2.0GHZ equivalent, or higher<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1GB (XP)/2GB (Vista/7)<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space:</strong> 8GB<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Video Card:</strong> : 256 MB 100% DirectX 9 compatible, ATI Radeon X800/Intel GMA 3000/Nvidia GeForce 6800 or Higher*<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 9.0<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX 9 compatible<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Additional:</strong> INTERNET CONNECTION REQUIRED FOR GAME ACTIVATION. *SIS AND VIA/S3G Graphics Controllers Not Supported<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0', '0,05', '0', '0,01', '0,06'),
(582, 'valentino rossi the game', '2016', 0, 35, 214, 61, 0, 15.49, 'The most complete MotoGP™ game ever! Join Valentino Rossi’s VR|46 Riders Academy and train with him in order to become the new champion of the 2016 MotoGP™ season!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® 7 SP1 / Windows® 8 / Windows® 8.1 / Windows® 10<br></li><li><strong>Processor:</strong> Intel i5 2500K 3.3GHz / AMD Phenom II X4 850<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> GeForce GT 640 / Radeon HD 6670 1GB*<br></li><li><strong>DirectX:</strong> Version 10<br></li><li><strong>Storage:</strong> 20 GB available space<br></li><li><strong>Sound Card:</strong> DirectX compatible<br></li><li><strong>Additional Notes:</strong> *Laptop versions of graphics cards may work but are not officially supported.</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® 7 SP1 64-Bit / Windows® 8 64-Bit / Windows® 8.1 64-Bit / Windows® 10<br></li><li><strong>Processor:</strong> Intel Core i5 4670K 3.4 GHz / AMD FX-9590 4.7 GHz<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> GeForce GTX 970 / AMD Radeon R9 390 4GB*<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Sound Card:</strong> DirectX compatible<br></li><li><strong>Additional Notes:</strong> *Laptop versions of graphics cards may work but are not officially supported.</li></ul>\'}', '0,01', '0,08', '0', '0,01', '0,09'),
(583, 'giants citizen kabuto', '2016', 0, 0, 36, 0, 0, 6.99, 'Before man climbed down from the trees to shop in megastores and drink cappuccino, before the Earth wadded itself into a ball, there was the Island. A fragment from a long-lost planet. Upon the surface of this paradise wandered Kabuto the giant. Little does he know, it was home to others before him.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows (XP, Vista, 7, 8, 10)<br></li><li><strong>Processor:</strong> 1 GHz Processor (1.4 GHz recommended)<br></li><li><strong>Memory:</strong> 256 MB RAM<br></li><li><strong>Graphics:</strong> NVidia or ATI/AMD 3D graphics card compatible with DirectX 7 (compatible with DirectX 9 recommended)<br></li><li><strong>Storage:</strong> 1100 MB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>Storage:</strong> 1500 MB available space</li></ul>\'}', '0,03', '0,02', '0', '0,01', '0,06'),
(584, 'zero escape zero time dilemma', '2016', 0, 33, 1382, 128, 1448, 15.49, 'Nine participants awaken, trapped in an underground facility. To escape, they must play a game with deadly consequences. Who will live, and who will die? The choice is yours.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7<br></li><li><strong>Processor:</strong> Intel Core i3-530 CPU 2.93 GHz or better<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX650 1GB or AMD HD 7700 1GB(DirectX 11 graphic card required)<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 4 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c compatible sound card</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7<br></li><li><strong>Processor:</strong> Intel Core i5-3570K CPU 3.40GHz<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX650 1GB or AMD HD 7700 1GB(DirectX 11 graphic card required)<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 4 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c compatible sound card</li></ul>\'}', '0,07', '0', '0,03', '0,02', '0,12'),
(585, 'stalker call of pripyat', '2010', 0, 0, 10172, 470, 1969, 12.99, 'S.T.A.L.K.E.R.: Call of Pripyat is the direct sequel of the S.T.A.L.K.E.R.: Shadow of Chernobyl. As a Major Alexander Degtyarev you should investigate the crash of the governmental helicopters around the Zone and find out, what happened there.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>Supported OS: </strong>Microsoft® Windows® XP(Service Pack 2)/Microsoft® Windows® 2000 SP4 <br></li><li><strong>Processor: </strong>Intel Pentium 4 2.0 Ghz / AMD XP 2200+ <br></li><li><strong>Graphics: </strong>128 MB DirectX® 8.0 compatible card / nVIDIA® GeForce™ 5700 / ATI Radeon® 9600 <br></li><li><strong>Memory: </strong>768 MB RAM <br></li><li><strong>Sound: </strong>DirectX® 9.0 compatible sound card <br></li><li><strong>Hard Drive: </strong>6 GB free hard disc space </li></ul>\', \'recommended\': \'<ul class=\"bb_ul\"><li><strong>Supported OS: </strong>Microsoft® Windows® XP/Vista (SP1) <br></li><li><strong>Processor: </strong>Intel Core 2 Duo E6400 / AMD 64 X2 4200+ <br></li><li><strong>Graphics: </strong>256 MB DirectX® 9.0c compatible card* / nVIDIA® GeForce™ 8800 GT / ATI Radeon® HD 2900 XT <br></li><li><strong>Memory: </strong>2 GB RAM <br></li><li><strong>Sound: </strong>DirectX® 9.0 compatible sound card <br></li><li><strong>Hard Drive: </strong>10 GB free hard disc space </li></ul>\'}', '0', '0,05', '0', '0,01', '0,06'),
(586, 'worms blast', '2011', 0, 0, 102, 101, 23, 5.59, 'Fall in line for fast, furious fire fights with Worms™ Blast. Your mission: launch your worm marine into hostile waters and blast your way to survival through intense puzzle action! Take the big chunk of puzzle-styled gameplay and slice into 60 fun-sized missions.', '{\'minimum\': \'<strong>Minimum:</strong> A 100% Windows XP/Vista/7 compatible computer system\'}', '0,05', '0,01', '0', '0', '0,06'),
(587, 'ducktales remastered', '2013', 0, 20, 3198, 523, 240, 11.99, 'DuckTales: Remastered is a beautiful hand-crafted reimagining of one of the most cherished 8-bit titles of all time. Go back to one of the golden ages of gaming, now refined with a level of detail that will please the most hardened devoted Disney or retro Capcom fan alike.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows®XP™ SP2, Windows®Vista™ or Windows®7<br></li><li><strong>Processor:</strong> Intel™ Pentium 4 2.4 ghz with Hyper Threading<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA® Geforce 9600GT, AMD® Radeon™ HD 3870 or higher (it must be able to manage Pixel Shader 3.0) with at least 512MB of display memory.<br></li><li><strong>Storage:</strong> 1 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows®XP™ SP2, Windows®Vista™ or Windows®7<br></li><li><strong>Processor:</strong> Intel™ Core 2 Duo / AMD™ Athlon 64 X2 or higher.<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA® GeForce™ 200 series or higher, AMD® Radeon™ HD5000 series or higher (it must be able to manage Pixel Shader 3.0) with at least 512MB of display memory.<br></li><li><strong>Storage:</strong> 2 GB available space</li></ul>\'}', '0,09', '0,05', '0', '0,01', '0,17'),
(588, 'dragon rage', '2016', 0, 17, 120, 36, 0, 4.99, 'Fast-paced destruction! Tear the #!@$ out of a mountain-top village as the King sends out his royal army to try to stop you and protect his kingdom. The more villagers you devour, the stronger you get. Fill your belly and enter Rampage Mode where you can unleash mass destruction!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP or later<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>DirectX:</strong> Version 9.0<br></li><li><strong>Storage:</strong> 100 MB available space<br></li><li><strong>Additional Notes:</strong> 60fps!</li></ul>\'}', '0,03', '0,02', '0', '0,01', '0,06');
INSERT INTO `jeux` (`id_jeu`, `nom_jeu`, `annee`, `age_requis`, `nb_succes`, `nb_avis_pos`, `nb_avis_neg`, `temps_jeu_moyen`, `prix`, `description`, `configuration`, `ventes_AN`, `ventes_EU`, `ventes_JP`, `ventes_Autre`, `ventes_Global`) VALUES
(589, 'stalker shadow of chernobyl', '2007', 0, 0, 11039, 570, 493, 9.99, 'S.T.A.L.K.E.R.: Shadow of Chernobyl tells a story about survival in the Zone – a very dangerous place, where you fear not only the radiation, anomalies and deadly creatures, but other S.T.A.L.K.E.R.s, who have their own goals and wishes.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>Supported OS: </strong>Microsoft® Windows® XP(Service Pack 2)/Microsoft® Windows® 2000 SP4 <br></li><li><strong>Processor: </strong>Intel Pentium 4 2.0 Ghz / AMD XP 2200+ <br></li><li><strong>Graphics: </strong>128 MB DirectX® 8.0 compatible card / nVIDIA® GeForce™ 5700 / ATI Radeon® 9600 <br></li><li><strong>Memory: </strong>512 MB RAM <br></li><li><strong>Sound: </strong>DirectX® 9.0 compatible sound card <br></li><li><strong>Hard Drive: </strong>6 GB free hard disc space </li></ul>\', \'recommended\': \'<ul class=\"bb_ul\"><li><strong>Supported OS: </strong>Microsoft® Windows® XP/Vista (SP1) <br></li><li><strong>Processor: </strong>Intel Core 2 Duo E6400 / AMD 64 X2 4200+ <br></li><li><strong>Graphics: </strong>256 MB DirectX® 9.0c compatible card* / nVIDIA® GeForce™ 8800 GT / ATI Radeon® HD 2900 XT <br></li><li><strong>Memory: </strong>2 GB RAM <br></li><li><strong>Sound: </strong>DirectX® 9.0 compatible sound card <br></li><li><strong>Hard Drive: </strong>10 GB free hard disc space </li></ul>\'}', '0,01', '0,04', '0', '0,01', '0,06'),
(590, 'nights of azure', '2017', 0, 49, 348, 152, 60, 24.99, 'Save the world or the life of one girl... I decide my destiny! The world was once ruled by the Nightｌord. In that world lived a Saint, destined to become a sacrifice to the Nightｌord, and a Holy Knight, with the power to use Servans. Take your Servans and fight accross &quot;The Land Without Night&quot; for the one you love!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® 7, Windows® 8.1, Windows® 10 (64bit required)<br></li><li><strong>Processor:</strong> Core i5 2.6GHz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX550Ti<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 6 GB available space<br></li><li><strong>Sound Card:</strong> On board<br></li><li><strong>Additional Notes:</strong> Graphics: 960x540</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® 7, Windows® 8.1, Windows® 10 (64bit required)<br></li><li><strong>Processor:</strong> Core i7 3.4GHz<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX960<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 6 GB available space<br></li><li><strong>Sound Card:</strong> On board<br></li><li><strong>Additional Notes:</strong> Graphics: 1920x1080</li></ul>\'}', '0,03', '0,02', '0', '0,01', '0,06'),
(591, 'gothic 3', '2009', 0, 0, 2962, 728, 1401, 8.99, 'A nameless hero becomes a legend! Myrtana, a world in upheaval: overrun by orcs from the dark lands in the north, King Rhobar is defending Vengard, the former stronghold of the humans, with his last troop of followers.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>Supported OS: </strong>Windows XP/2000/XP 64-Bit/Vista<br>\\t\\t\\t\\t\\t</li><li><strong>Processor: </strong>Intel Pentium 4 or AMD CPU 2 GHz or equivalent<br>\\t\\t\\t\\t\\t</li><li><strong>Memory: </strong>1024 MB Ram or higher <br>\\t\\t\\t\\t\\t</li><li><strong>Graphics: </strong>3D graphics card with 128 MB Ram and Shader 1.4<br>\\t\\t\\t\\t\\t</li><li><strong>Sound: </strong>DirectX 8.1 compatible<br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive: </strong>4.6 GB</li></ul>\'}', '0', '0,05', '0', '0,01', '0,06'),
(592, 'mx vs atv supercross encore', '2015', 0, 29, 282, 280, 0, 24.99, 'Rip, jump and scrub your way to victory with over 35 tracks in this vastly extended version! Only the Encore edition features the brand new Rhythm Racing mode, extra outdoor Nationals tracks, and exclusive Waypoint races in open world maps.', '{\'minimum\': \'<strong>最低配置:</strong><br><ul class=\"bb_ul\"><li><strong>操作系统:</strong> Windows® Vista, Windows® 7, Windows® 8, Windows® 10<br></li><li><strong>处理器:</strong> Intel® Core™ 2 Duo @ 1.8Ghz / AMD Athlon 64 X2 equivalent<br></li><li><strong>内存:</strong> 2 GB RAM<br></li><li><strong>图形:</strong> DirectX 10 compatible graphics card like Intel HD 3000, NVIDIA GeForce GTS 240 (1GB VRAM) or ATI Radeon HD 4600 (1GB VRAM)<br></li><li><strong>DirectX 版本:</strong> 9.0c<br></li><li><strong>存储空间:</strong> 需要 5 GB 可用空间<br></li><li><strong>附注事项:</strong> Recommended: Xbox 360 Controller | AMD Crossfire™ and NVIDIA SLI is not supported</li></ul>\'}', '0,02', '0,05', '0', '0,01', '0,08'),
(593, 'handball 16', '2015', 0, 25, 37, 37, 0, 29.99, 'Play with all your favourite players in THE handball simulation. Use all the real handball moves and tactics and challenge other players online.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows®7 / Windows®8 / Windows®10 64 bits<br></li><li><strong>Processor:</strong> AMD Phenom™ 9850 @2.5 GHz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA® GeForce® 8800 GT / AMD Radeon™ 6570<br></li><li><strong>DirectX:</strong> Version 9.0<br></li><li><strong>Storage:</strong> 9 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows®7 / Windows®8 / Windows®10 64 bits<br></li><li><strong>Processor:</strong> Intel® Core i5 4570 @3.2 GHz<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA® GeForce® 750Ti / AMD Radeon™ R7 265<br></li><li><strong>DirectX:</strong> Version 9.0<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 9 GB available space</li></ul>\'}', '0', '0,1', '0', '0,02', '0,12'),
(594, 'airline tycoon 2', '2011', 0, 0, 61, 386, 0, 6.99, 'Run a modern airline, design unique airplanes and grow a run-down carrier into a globally recognized company that passengers practically beg to fly', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP / Vista / 7<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 3 GHz Intel Pentium D / AMD Athlon 64 3000+<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1 GB<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space:</strong> \\t<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Video Card:</strong> Nvidia Geforce 8600 GT / ATI Radeon X 1800<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 9.0c<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX-compatible<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0', '0,04', '0', '0,01', '0,05'),
(595, '7 wonders treasures of seven', '2008', 0, 0, 57, 21, 0, 6.99, 'It\'s time to build nine of the most intriguing structures throughout history! Match runes to break blocks and uncover the lock and keystone for each round. Rotate the cube face to move your keystone along the pathways you\'ve created to reach each level\'s lock and conquer all six sides!', '{\'minimum\': \'<ul> \\n\\t\\t\\t\\t\\t<li><strong>Supported OS: </strong>Windows XP/Vista</li> \\n\\t\\t\\t\\t\\t<li><strong>Processor: </strong>Pentium III 1GHz Processor</li> \\n\\t\\t\\t\\t\\t<li><strong>Memory: </strong>256MB RAM</li> \\n\\t\\t\\t\\t\\t<li><strong>DirectX version: </strong>DirectX 8.1 or higher</li> \\n\\t\\t\\t\\t\\t<li><strong>Graphics Card: </strong>DirectX Compatible 16 or 32-bit Video Card with 64MB VRAM</li> \\n\\t\\t\\t\\t\\t<li><strong>Sound Card: </strong>DirectSound-compatible sound card</li> \\n\\t\\t\\t\\t\\t<li><strong>Hard Drive Space: </strong> 100MB free HD space</li> </ul>\'}', '0,02', '0,03', '0', '0,01', '0,05'),
(596, 'virtual villagers a new home', '2008', 0, 0, 20, 7, 0, 5.99, 'Care for and nurture a tribe of little people by teaching them the basics of survival. They need to become farmers, builders, scientists, parents and make decisions about unpredictable \'island events\'! Guide their day-to-day lives and help them explore and restore their new home.', '{\'minimum\': \'<ul>\\n\\t\\t\\t\\t\\t<li><strong>Supported OS: </strong>Windows 2000/XP/Vista</li>\\n\\t\\t\\t\\t\\t<li><strong>Processor: </strong>Pentium III 500</li>\\n\\t\\t\\t\\t\\t<li><strong>Memory: </strong>96 MB </li>\\n\\t\\t\\t\\t\\t<li><strong>Graphics: </strong>16MB of VRAM</li>\\n\\t\\t\\t\\t\\t<li><strong>DirectX Version: </strong>DirectX 7.0 or later</li>\\n\\t\\t\\t\\t\\t<li><strong>Hard Drive: </strong>200 MB</li></ul>\'}', '0,04', '0,01', '0', '0', '0,05'),
(597, 'vertigo', '2016', 0, 0, 178, 34, 0, 10.99, 'Vertigo is a first person story-based shooter for the HTC Vive. Explore the sprawling underground facilities of Planck Interdimensional Energy Solutions\' Quantum Reactor, filled with dark secrets, adorable drones, and parallel universes.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 or higher<br></li><li><strong>Processor:</strong> Intel i5 4690k<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> NVidia 970 or AMD equivalent<br></li><li><strong>Storage:</strong> 2 GB available space<br></li><li><strong>Additional Notes:</strong> Requires an HTC Vive VR headset to play</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 or higher<br></li><li><strong>Processor:</strong> Intel i5 4690k<br></li><li><strong>Graphics:</strong> NVidia 980ti<br></li><li><strong>Storage:</strong> 2 GB available space<br></li><li><strong>Additional Notes:</strong> Requires an HTC Vive VR headset to play</li></ul>\'}', '0,05', '0', '0', '0', '0,05'),
(598, 'goosebumps the game', '2015', 0, 40, 108, 17, 0, 6.99, 'The walk home from school today is going to be a lot spookier than usual… Your sleepy neighborhood’s been overrun by monsters! Werewolves prowl the woods, Gnomes roam underfoot, and scarecrows walk at midnight. But these aren’t ordinary monsters—they’re R.L.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista or Windows 7<br></li><li><strong>Processor:</strong> Intel Pentium 4 2.4 ghz with Hyper Threading<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> Intel HD Graphics<br></li><li><strong>DirectX:</strong> Version 9.0<br></li><li><strong>Storage:</strong> 600 MB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 or Windows 8<br></li><li><strong>Processor:</strong> Indel Core 2 Duo / AMD Athlon 64 x2 or higher<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> VIDIA® GeForce™ 200 series or higher, AMD® Radeon™ HD5000 series or higher<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 600 MB available space</li></ul>\'}', '0,05', '0', '0', '0,01', '0,05'),
(599, 'samantha swift and the hidden roses of athena', '2008', 0, 0, 30, 23, 0, 5.99, 'On a quest to recover the Scepter of Zeus for The Museum of Lost Secrets, archeologist and adventurer Samantha Swift stumbles upon one of the greatest archeological finds of all time! Unfortunately, she also runs into greedy treasure hunter Ravena Stryker.', '{\'minimum\': \'<ul> \\n\\t\\t\\t\\t\\t<li><strong>OS:</strong> Windows Vista/XP</li> \\n\\t\\t\\t\\t\\t<li><strong>Processor:</strong> Processor Speed: 800MHz</li> \\n\\t\\t\\t\\t\\t<li><strong>Memory:</strong> 256MB RAM</li> \\n\\t\\t\\t\\t\\t<li><strong>Graphics:</strong> 64 MB Video Card</li> \\n\\t\\t\\t\\t\\t<li><strong>DirectX Version:</strong> DirectX 8.1</li> \\n\\t\\t\\t\\t\\t<li><strong>Sound Card:</strong> Sound Card</li> </ul>\'}', '0,04', '0,01', '0', '0', '0,05'),
(600, 'nobunagas ambition sphere of influence', '2015', 0, 0, 380, 77, 0, 49.99, 'Become a Daimyo of the Warring States period of Japanese history in NOBUNAGA\'S AMBITION, a historical simulation game of conquest and domination. It is the 30th anniversary of this series and this current release, NOBUNAGA\'S AMBITION: Sphere of Influence, is the crown of the series.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® 7, Windows® 8, Windows® 8.1<br></li><li><strong>Processor:</strong> Pentium®4 1.6GHz<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> VRAM 128MB over<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 7 GB available space<br></li><li><strong>Sound Card:</strong> 48GHz/16bit<br></li><li><strong>Additional Notes:</strong> Shader model: Version 3.0, 1024 x 768 or 1280 x 720 minimum display resolution</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® 7, Windows® 8, Windows® 8.1<br></li><li><strong>Processor:</strong> Core2 Duo 2.0GHz<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> VRAM 512MB over<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 7 GB available space<br></li><li><strong>Sound Card:</strong> 48GHz/16bit<br></li><li><strong>Additional Notes:</strong> Shader model: Version 3.0, 1024 x 768 or 1280 x 720 minimum display resolution</li></ul>\'}', '0,03', '0', '0,05', '0,01', '0,09'),
(601, 'chaos;child', '2019', 0, 34, 232, 5, 0, 27.79, 'From the creators of the critically acclaimed STEINS;GATE comes a sensational new visual novel: CHAOS;CHILD. Set in Shibuya in 2015, a group of high school students who survived an earthquake six years ago find themselves at the center of a new series of bizarre murders in the city.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows: 7/8.1/10 (64-bit)<br></li><li><strong>Processor:</strong> Intel Core i5<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> Intel HD Graphics Series (With 1GB memory allocation)<br></li><li><strong>DirectX:</strong> Version 9.0<br></li><li><strong>Storage:</strong> 17 GB available space<br></li><li><strong>Sound Card:</strong> Direct Sound compatible sound device.<br></li><li><strong>Additional Notes:</strong> Minimum resolution: 1280x720 (Recommended: 1920x1080)</li></ul>\'}', '0', '0', '0,07', '0', '0,07'),
(602, 'dodonpachi resurrection', '2016', 0, 100, 410, 16, 51, 22.99, 'The legendary bullet-hell shoot-’em-up series has come to Steam! DoDonPachi is ressurected after a Blissful Death with enough modes to satisfy the beginner and the expert player alike. Tonight we dine in bullet hell!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7/8/8.1/10<br></li><li><strong>Processor:</strong> Intel Core i3 2GHz or better<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> Intel HD Graphics 5000, Geforce 9500GT, Radeon HD 3650 or above<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 2500 MB available space<br></li><li><strong>Sound Card:</strong> DirectSound compatible</li></ul>\'}', '0', '0,05', '0', '0,01', '0,05'),
(603, 'myst iv revelation', '2018', 0, 0, 12, 7, 0, 11.39, 'In Myst IV: Revelation, the next chapter in the greatest adventure saga of all time, you\'ll travel through environments pulsing with life to unearth a treacherous scheme involving two of Myst\'s most sinister villains.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> 7 / 8 / 10<br></li><li><strong>Processor:</strong> 1.8 GHz Processor<br></li><li><strong>Memory:</strong> 512 MB RAM<br></li><li><strong>Graphics:</strong> 32 MB 3D graphics card compatible with DirectX 9<br></li><li><strong>DirectX:</strong> Version 9.0<br></li><li><strong>Storage:</strong> 7172 MB available space<br></li><li><strong>Sound Card:</strong> DirectX 9 compliant audio device<br></li><li><strong>Additional Notes:</strong> Peripherals: Mouse, Keyboard</li></ul>\'}', '0,05', '0,01', '0', '0', '0,06'),
(604, 'cities in motion', '2011', 0, 47, 605, 179, 1, 14.99, 'Manage transportation for commuters in four of the world\'s greatest cities - Vienna, Helsinki, Berlin, and Amsterdam', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Microsoft Windows XP/Vista/7<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 2 GHz Dual Core or higher<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2 GB RAM<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space:</strong> 2 GB<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Video Card:</strong> NVIDIA GeForce 8800/ATI Radeon HD 3850 or higher (integrated video cards not supported), 512 MB RAM, OpenGL 3.0<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0', '0,04', '0', '0,01', '0,05'),
(605, 'stranger of sword city', '', 0, 0, 0, 0, 0, 0.00, '0', '0', '0,02', '0,02', '0', '0,01', '0,05'),
(606, 'earth defense force 41 the shadow of new despair', '2016', 12, 51, 4325, 267, 915, 15.49, 'It\'s a fight for the future of the planet between the Ravagers, a merciless swarm of alien invaders, and the Earth Defense Force (EDF) in this third-person shooter.Play as four different classes in over 80 missions with a range of 800 weapons at your disposal.Co-op play supported.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 64bit, Windows 8.1 64bit Windows 10 64bit<br></li><li><strong>Processor:</strong> 3 GHz 2 Core<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> AMD Radeon HD 7870 / NVIDIA GeForce GTX 660\\u3000（2GB Model or higher）<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 8 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 11 sound device<br></li><li><strong>Additional Notes:</strong> XInput Controller</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 64bit, Windows 8.1 64bit Windows 10 64bit<br></li><li><strong>Processor:</strong> 3.2GHz 4Core<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> AMD Radeon HD 7970 / NVIDIA GeForce GTX 760\\u3000（3GB Model or higher）<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 8 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 11 sound device<br></li><li><strong>Additional Notes:</strong> XInput Controller</li></ul>\'}', '0,02', '0,02', '0', '0,01', '0,05'),
(607, 'assetto corsa', '2014', 0, 709, 15277, 2337, 3107, 15.49, 'Assetto Corsa v1.16 introduces the new &quot;Laguna Seca&quot; laser-scanned track, 7 new cars among which the eagerly awaited Alfa Romeo Giulia Quadrifoglio! Check the changelog for further info!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 Sp1 - 8 - 8.1 - 10<br></li><li><strong>Processor:</strong> AMD Athlon X2 2.8 GHZ, Intel Core 2 Duo 2.4 GHZ<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> DirectX 10.1 (e.g. AMD Radeon HD 6450, Nvidia GeForce GT 460)<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 15 GB available space<br></li><li><strong>Sound Card:</strong> Integrated</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 Sp1 - 8 - 8.1 - 10<br></li><li><strong>Processor:</strong> AMD Six-Core CPU, Intel Quad-Core CPU<br></li><li><strong>Memory:</strong> 6 GB RAM<br></li><li><strong>Graphics:</strong> DirectX 11 (e.g. AMD Radeon 290x, Nvidia GeForce GTX 970)<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 30 GB available space<br></li><li><strong>Sound Card:</strong> Integrated</li></ul>\'}', '0', '0,05', '0', '0,01', '0,06'),
(608, 'men of war assault squad', '2011', 0, 110, 2881, 416, 292, 7.19, 'Men of War: Assault Squad features a completely new cooperative skirmish game mode with access to five different nations (Russia, Germany, USA, Commonwealth and, for the first time ever in the Men of War series, Japan) as well as increased realism and accessibility.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP/Vista/7<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 2.6GHz Processor or higher<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1GB or higher<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> DX9c compatible GPU <br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DX9c<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 4GB<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> any OS compatible<br>\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0,01', '0,03', '0', '0,01', '0,05'),
(609, 'expendable', '2018', 0, 0, 5, 2, 0, 2.89, 'Somewhere in the future a hostile alien race conquers most of the galaxy. Scientists developed the “Millennium Soldier” project by cloning two super-soldiers. Armed with blasters they will battle scores of monsters, robots and boss aliens to save us and get a well-earned reward.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® XP / Vista<br></li><li><strong>Processor:</strong> Intel® Pentium III™ 1 GHz or equivalent Processor<br></li><li><strong>Memory:</strong> 256 MB RAM<br></li><li><strong>Graphics:</strong> 3D graphics card compatible<br></li><li><strong>DirectX:</strong> Version 7.0<br></li><li><strong>Storage:</strong> 500 MB available space<br></li><li><strong>Sound Card:</strong> 3DFX Card</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® 7/8/10 with latest service packs<br></li><li><strong>Processor:</strong> Intel® Core™ i5 1.4 GHz or equivalent<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> 3D graphics card compatible<br></li><li><strong>DirectX:</strong> Version 9.0<br></li><li><strong>Storage:</strong> 500 MB available space<br></li><li><strong>Sound Card:</strong> 3DFX Card</li></ul>\'}', '0,03', '0,02', '0', '0', '0,05'),
(610, 'steins;gate 0', '2018', 0, 28, 1301, 53, 0, 27.79, 'If you can\'t save the one you love… How can you save humanity? Sequel to the visual novel cult classic. Experience an alternate worldline of STEINS;GATE.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows: 7/8.1/10<br></li><li><strong>Processor:</strong> Intel Core i5<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> Intel HD Graphics Series (With 1GB memory allocation)<br></li><li><strong>DirectX:</strong> Version 9.0<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 15 GB available space<br></li><li><strong>Sound Card:</strong> Direct Sound compatible sound device.<br></li><li><strong>Additional Notes:</strong> Minimum resolution: 1280x720 (Recommended: 1920x1080)</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows: 7/8.1/10 (64-bit)<br></li><li><strong>Processor:</strong> Core i3 (Sandy Bridge or better)<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> Geforce (VRAM 1GB or better)<br></li><li><strong>DirectX:</strong> Version 9.0<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 15 GB available space<br></li><li><strong>Sound Card:</strong> Direct Sound compatible sound device.<br></li><li><strong>Additional Notes:</strong> Minimum resolution: 1280x720 (Recommended: 1920x1080)</li></ul>\'}', '0', '0', '0,13', '0', '0,13'),
(611, 'the technomancer', '2016', 0, 40, 1232, 565, 67, 23.99, 'The Technomancer is a sci-fi RPG that offers players plenty of dynamic combat action based on 4 skill trees dedicated to 3 combat styles and the destructive electrical powers of the Technomancers.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 / 8 / 10 (64-bit versions only)<br></li><li><strong>Processor:</strong> AMD FX-4100 X4 (3,6 GHz)/Intel Core i5-2500 (3,3 GHz)<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> 1 GB, DirectX 11, AMD Radeon HD 6950/NVIDIA GeForce GTX 560<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 11 GB available space<br></li><li><strong>Sound Card:</strong> DirectX compatible<br></li><li><strong>Additional Notes:</strong> Internet connection required for game activation</li></ul>\'}', '0,02', '0,05', '0', '0,01', '0,08'),
(612, 'arx fatalis', '2007', 0, 0, 671, 106, 11, 2.99, 'This critically acclaimed first-person RPG takes the player on an amazing journey into the fantasy world of Arx. The game mixes intelligent story with immersive and actual medieval surroundings. Arx Fatalis allows the player to feel that all his actions have a direct consequence on those around him.', '{\'minimum\': \'<strong>Minimum:</strong> Windows XP, 500 MHz Pentium ® III or compatible, 64 MB RAM , DirectX 8 or higher, DirectX 8 compatible sound- and graphics card with 16 MB, 750 MB fixed disks<br>\\t\\t\\t\\t\\t<strong>Recommended:</strong> 900 MHz Pentium ® III or compatible, 256 MB RAM , DirectX 8 or higher, DirectX 8 compatible sound- and graphics card with 32MB, 750 MB fixed disks\'}', '0,04', '0,01', '0', '0', '0,05'),
(613, 'pro cycling manager 2016', '2016', 0, 47, 186, 123, 0, 14.99, 'Become the sports manager of a professional cycling team and take part in a great 2016 season that will let you travel the world in over 200 cycling events.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> WINDOWS VISTA/WINDOWS 7/WINDOWS 8/WINDOWS 10<br></li><li><strong>Processor:</strong> AMD/INTEL DUAL-CORE 2.2 GHZ<br></li><li><strong>Memory:</strong> 3072 MB RAM<br></li><li><strong>Graphics:</strong> 256 MB 100% DIRECTX 9 AND SHADERS 3.0 COMPATIBLE ATI RADEON HD 2600 XT/INTEL HD 3000/NVIDIA GEFORCE 8600 GTS OR HIGHER<br></li><li><strong>DirectX:</strong> Version 9.0<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 11 GB available space<br></li><li><strong>Sound Card:</strong> DIRECTX 9 COMPATIBLE<br></li><li><strong>Additional Notes:</strong> INTERNET CONNECTION REQUIRED FOR GAME ACTIVATION AND ONLINE GAME - WINDOWS XP NON SUPPORTED</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> WINDOWS VISTA/WINDOWS 7/WINDOWS 8/WINDOWS 10<br></li><li><strong>Processor:</strong> AMD/INTEL DUAL-CORE 3.0 GHZ<br></li><li><strong>Memory:</strong> 4096 MB RAM<br></li><li><strong>Graphics:</strong> 1024 MB 100% DIRECTX 9 AND SHADERS 3.0 COMPATIBLE AMD RADEON HD 6850/NVIDIA GEFORCE GTX 460 OR HIGHER<br></li><li><strong>DirectX:</strong> Version 9.0<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 11 GB available space<br></li><li><strong>Sound Card:</strong> DIRECTX 9 COMPATIBLE<br></li><li><strong>Additional Notes:</strong> INTERNET CONNECTION REQUIRED FOR GAME ACTIVATION AND ONLINE GAME - WINDOWS XP NON SUPPORTED</li></ul>\'}', '0', '0,07', '0', '0,01', '0,08'),
(614, 'worms reloaded', '2010', 0, 61, 2478, 430, 327, 14.99, 'Ten years on from Worms™ Armageddon and the turn-based comic mayhem continues in Worms™ Reloaded, an all-new edition available for PC through Steam.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP, Vista, 7<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 1.25GHz AMD Athlon or Intel equivalent <br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1GB <br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 128MB Video Card (GeForce4 or equivalent card)<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX® 9 or above<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 2063MB<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX® 9.0c-compliant sound card<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Other Requirements:</strong> Internet connection required<br>\\t\\t\\t\\t\\t\\t\\t\\t </li></ul>\'}', '0', '0,04', '0', '0,01', '0,05'),
(615, 'far cry', '2008', 0, 0, 3099, 609, 126, 8.59, 'A tropical paradise seethes with hidden evil in Far Cry®, a cunningly detailed action shooter that pushes the boundaries of combat to shocking new levels. Freelance mariner Jack Carver is cursing the day he ever came to this island.', '{\'minimum\': \'<strong>Minimum: </strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>Supported OS:</strong> Windows® 2000/XP (only)<br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> AMD Athlon™ 1 GHz or Pentium® III 1 GHz<br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 256 MB<br>\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 64 MB DirectX® 9.0b-compliant graphics card (see supported list*)<br>\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX 9.0b compliant PCI card (Sound Blaster Audigy series recommended)<br>\\t\\t\\t\\t\\t</li><li><strong>DirectX:</strong> DirectX 9.0b or higher<br>\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space:</strong> 4 GB <br>\\t\\t\\t\\t\\t</li><li><strong>Multiplay:</strong> Broadband with 64 Kbps upstream (512 Kbps upstream to host 8 players) <br>\\t\\t\\t\\t\\t</li><li><strong>Mouse/Keyboard:</strong> Windows compatible mouse and keyboard required </li></ul>\', \'recommended\': \'<strong>Recommended: </strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>Supported OS:</strong> Windows 2000/XP (only)<br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> AMD Athlon 2-3 GHz or Pentium 4 2-3 GHz<br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 512-1024 MB<br>\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> Sound Blaster® Audigy® series (see supported list*)<br>\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 128 MB GeForce™ 4 128 MB to GeForce FX 5950; ATI Radeon 9500-9800 XT<br>\\t\\t\\t\\t\\t</li><li><strong>*Supported video cards at time of retail release:</strong> NVIDIA GeForce 2/3/4/FX families ( NVIDIA based cards must have ForceWare drivers 53.03 or later; GeForce 2 and GeForce 4 MX cards do not support all graphics features). ATI Radeon 8500/9000 families (ATI Radeon 9500-9800 XT recommended; ATI-based cards must have Catalyst drivers 3.9 or higher). Laptop models of the listed cards are not fully supported. For an up-to-date list of supported chipsets, video cards, and operating systems, please visit the FAQ for this game at: <a href=\"https://steamcommunity.com/linkfilter/?url=http://support.ubi.com\" target=\"_blank\" rel=\"noopener\" >http://support.ubi.com</a>.</li></ul>\'}', '0', '0,04', '0', '0,01', '0,05'),
(616, 'ship simulator extremes', '2010', 0, 0, 676, 794, 0, 14.99, 'VSTEP and Paradox are proud to announce the next installment of the acclaimed Ship Simulator series. With over 550K copies sold, the series returns to take you into the most extreme conditions on earth… Ever wonder how it feels to sail a half-million-ton supertanker through the perfect storm?', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP (Min. service pack 2), Windows Vista or Windows 7. 32 and 64 bits OS supported<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 3 Ghz P4 Intel or AMD equivalent processor<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2GB (Windows XP) or 3GB (Vista or Windows 7)<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space:</strong> 3.5 GB<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Video Card:</strong> Geforce 8800GT or ATI Radeon 4850 with 256MB ram (At least Shader model 3.0)<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX compatible<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 9.0c\\t<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0', '0,04', '0', '0,01', '0,05'),
(617, 'vr soccer 96', '2018', 0, 0, 1, 0, 0, 7.19, 'Feel the soccer once again.The first football game to utilize 3D graphics; also known as Actua SoccerCreate your own team and customize it to suit your preferencesPlay with up to 15 of your friends!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP or Windows Vista<br></li><li><strong>Processor:</strong> 1.8 GHz Processor<br></li><li><strong>Memory:</strong> 512 MB RAM<br></li><li><strong>Graphics:</strong> 3D graphics card compatible with DirectX 7<br></li><li><strong>DirectX:</strong> Version 7.0<br></li><li><strong>Storage:</strong> 162.4 MB available space<br></li><li><strong>Additional Notes:</strong> Please be advised that Windows 10 operating system will receive frequent hardware driver and software updates following its release; this may affect game compatibility</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> 3D graphics card compatible with DirectX 9<br></li><li><strong>DirectX:</strong> Version 9.0</li></ul>\'}', '0,03', '0,02', '0', '0', '0,05'),
(618, 'saints row gat out of hell', '2015', 0, 45, 5203, 1843, 180, 10.99, 'Join Johnny Gat &amp; Kinzie Kensington as you tear apart Hell in a quest to save the Boss’ soul. Historical icons, old friends, older enemies, a talking gun, a full length musical number &amp; a whole lot more shenanigans await!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista (x86 or x64)<br></li><li><strong>Processor:</strong> Intel Core 2 Quad Q6600 | AMD Athlon II x3<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GTX 260 | AMD Radeon HD 5800 series<br></li><li><strong>DirectX:</strong> Version 10<br></li><li><strong>Storage:</strong> 7 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 (x86 or x64)<br></li><li><strong>Processor:</strong> Intel i3 2100T | AMD Phenom II x4 or higher<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GTX 560 | AMD Radeon HD 6800 series or higher<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 7 GB available space</li></ul>\'}', '0', '0,04', '0', '0,01', '0,05'),
(619, 'company of heroes', '2006', 0, 0, 2526, 287, 1475, 0.00, 'Delivering a visceral WWII gaming experience, Company of Heroes redefines RTS by bringing the sacrifice of heroic soldiers, war-ravaged environments, and dynamic battlefields to life. Please visit the &quot;Company of Heroes - Legacy Edition&quot; page for additional user reviews.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® XP or Vista<br></li><li><strong>Processor:</strong> 2.0 Ghz Intel Pentium IV or equivalent or AMD Athlon XP or equivalent<br></li><li><strong>Memory:</strong> 512 MB RAM<br></li><li><strong>Graphics:</strong> DirectX 9.0c compatible 64MB video card with Pixel Shader 1.1 support or equivalent and latest manufacturer drivers<br></li><li><strong>Storage:</strong> 1 GB available space<br></li><li><strong>Sound Card:</strong> DirectX® 9.0c compatible 16-bit<br></li><li><strong>Additional Notes:</strong> Supported Video Cards: NVIDIA: NVIDIA GeForce 3 series or better with latest manufacturer drivers (excluding the GeForce 4 MX series), ATI: ATI Radeon 9500 series or better with latest manufacturer drivers.</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® XP or Vista<br></li><li><strong>Processor:</strong> 3.0 Ghz Intel Pentium IV or equivalent<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> 256 MB NVIDIA GeForce 6800 series or better<br></li><li><strong>Sound Card:</strong> DirectX® 9.0c compatible 16-bit</li></ul>\'}', '0', '0,04', '0', '0,01', '0,05'),
(620, 'silent hunter wolves of the pacific', '2009', 0, 0, 234, 128, 134, 8.59, 'Hunt, hide and kill as you take command of U.S. submarines and crews and navigate the treacherous waters of the Pacific during WWII. Silent Hunter, the industry-leading naval warfare simulation franchise for over a decade, returns to its roots with next-generation graphical realism, immersive gameplay, innovative crew evolution and more...', '{\'minimum\': \'<strong>Minimum: </strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>Supported OS: </strong>Windows® XP/Vista Only <br>\\t\\t\\t\\t\\t</li><li><strong>Processor: </strong>2GHz Pentium 4 or AMD Athlon (4 3GHz Pentium or AMD Athlon recommended) <br>\\t\\t\\t\\t\\t</li><li><strong>Memory: </strong>1 GB (2 GB recommended) <br>\\t\\t\\t\\t\\t</li><li><strong>Graphics: </strong>128 MB RAM DirectX® 9-compliant, video card capable of rendering Pixel Shader 2.0 (256 MB RAM recommended) (see supported list*)<br>\\t\\t\\t\\t\\t</li><li><strong>DirectX Version: </strong>DirectX 9.0c or later (included) <br>\\t\\t\\t\\t\\t</li><li><strong>Sound: </strong>DirectX 9 -compliant sound card <br>\\t\\t\\t\\t\\t</li><li><strong>Network: </strong>128 kbps upstream or faster (512 kbps upstream or faster needed to host online games)<br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive: </strong>6 GB<br>\\t\\t\\t\\t\\t</li><li>*Supported Video Cards: ATI® RADEON® 9600/9700/9800, X300 to X850, X1300 to X1800NVIDIA® GeForce™ 6200/6600/6800/7800</li></ul>\'}', '0', '0,04', '0', '0,01', '0,05'),
(621, 'xblaze code embryo', '2016', 0, 39, 42, 6, 0, 14.99, 'Set 150 years before the events of BlazBlue: Calamity Trigger, XBlaze Code: Embryo is a visual novel that follows Touya Kagari, a high school student whose world is turned upside down when he is attacked by a seemingly otherworldly being and saved by a mysterious girl named Es.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 / 8 / 8.1<br></li><li><strong>Processor:</strong> Intel Core2 Duo<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> nVidia GeForce 7900 GT or better / AMD Radeon X1900 / nVidia GeForce GT 620 (Windows 8.1)<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 7 GB available space<br></li><li><strong>Sound Card:</strong> Direct Sound<br></li><li><strong>Additional Notes:</strong> Compatibility with Xbox 360 Controller</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 / 8 / 8.1<br></li><li><strong>Processor:</strong> Intel Core i5 / i7<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> nVidia GeForce 8800 GT or better / AMD Radeon HD3700 / nVidia GeForce GT 650 (Windows 8.1)<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 7 GB available space<br></li><li><strong>Sound Card:</strong> Direct Sound<br></li><li><strong>Additional Notes:</strong> Compatibility with Xbox 360 Controller</li></ul>\'}', '0,05', '0', '0,02', '0,01', '0,08'),
(622, 'mighty no 9', '2016', 0, 70, 1367, 1389, 28, 15.99, 'Mighty No. 9 is a 2D Side-scrolling Action game that takes the best elements from 8 and 16-bit classics that you know and love and transforms them with modern tech, fresh mechanics, and fan input into something fresh and amazing!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 64-bit or newer<br></li><li><strong>Processor:</strong> Intel Core 2 Quad @ 2.8 GHz or AMD Phenom X4<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> Radeon HD 7770 or Nvidia GeForce GTX 550 Ti<br></li><li><strong>Storage:</strong> 2 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 64-bit or newer<br></li><li><strong>Processor:</strong> Intel Core i5 @ 3.3 GHz or AMD Phenom II X6<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> Radeon HD 7950 or Nvidia GeForce GTX 660 Ti<br></li><li><strong>Storage:</strong> 2 GB available space</li></ul>\'}', '0,06', '0,01', '0', '0,01', '0,08'),
(623, 'the king of fighters 2002 unlimited match', '2015', 0, 12, 903, 78, 0, 10.99, 'KOF 2002 UM is the 2nd title in the UM Series and a fully upgraded ver. of KOF 2002, a masterpiece of the KOF Series deserving its place of honor alongside KOF ’98. Based on THE NESTS CHRONICLES, 2002 UM includes the most characters of any title in the KOF Series, and fighting game history as well!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP<br></li><li><strong>Processor:</strong> Intel Pentium 4 1.8GHz dual core<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> Onboard graphics chipset with 256MB video RAM<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 1 GB available space<br></li><li><strong>Sound Card:</strong> DirectSound</li></ul>\'}', '0', '0', '0,04', '0', '0,04'),
(624, 'runaway a twist of fate', '2011', 0, 0, 191, 34, 0, 6.99, 'Runaway: A Twist of Fate is the adventure game of the year! Featuring a production worthy of a big 2D animated movie, Runaway follows a story full of twists and turns, and packed with comical highlights. All in all, you will be confronted with more than 200 mysteries and puzzles to keep your brain running through a big adventure that you...', '{\'minimum\': \'<ul>\\n\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>OS:</strong> Windows XP SP2/Vista SP1/Windows 7\\n\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>Processor:</strong> Celeron 1.7GHZ/Duron 1.6GHZ\\n\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>Memory:</strong> 768 MB (XP)/1GB (Vista/7)\\n\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>Hard Disk Space:</strong> 8 GB\\t\\n\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>Video Card:</strong> 256 MB 100% DirectX 9 Compatible (1280x720 MINIMUM) ATI Radeon 9800/Intel GMA 3000/Nvidia GeForce FX 5900 or Higher*\\n\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>DirectX&reg;:</strong> DirectX 9\\n\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>Sound:</strong> DirectX 9 Compatible\\n\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>*SIS AND VIA/S3G Graphics Controllers Non-Supported\\t\\n\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</ul>\'}', '0', '0,06', '0', '0,01', '0,06'),
(625, 'rugby challenge 3', '2016', 0, 50, 47, 34, 0, 39.95, 'Rugby Challenge 3 features Rugby Sevens, Over 11 Competitions, Be a Pro Mode plus more. Create custom players and teams then shared online across all platforms using the all new FanHub. Sporting great licenses such as the All Blacks, Wallabies, Springboks and England!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7/8/10<br></li><li><strong>Processor:</strong> Intel 2.2 GHz Dual-Core or AMD 2.5 GHz Dual-Core<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> Radeon HD 6670 or NVIDIA Geforce GT530 with Min 1GB Memory<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 8 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c compatible</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7/8/10<br></li><li><strong>Processor:</strong> Intel or AMD Quad-Core<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> Radeon HD 7790 or NVIDIA GeForce GTX 650 with minimum 2GB Memory<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 8 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c compatible</li></ul>\'}', '0', '0,1', '0', '0,02', '0,11'),
(626, 'praetorians', '2014', 0, 0, 337, 98, 1, 3.99, 'Praetorians is set amidst the political machinations of an emerging Roman Empire. You will be transported back to the dusty battlefields of Egypt, the combat theaters of Gaul and finally to the heart of the Empire itself, Italy in the crusade to become Emperor.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP<br></li><li><strong>Processor:</strong> 1 GHz Processor<br></li><li><strong>Memory:</strong> 256 MB RAM<br></li><li><strong>Graphics:</strong> 3D graphics card compatible with DirectX 7<br></li><li><strong>DirectX:</strong> Version 7.0<br></li><li><strong>Storage:</strong> 500 MB available space<br></li><li><strong>Sound Card:</strong> DirectX 9 compatible sound</li></ul>\'}', '0', '0,04', '0', '0', '0,04'),
(627, 'il2 sturmovik 1946', '2008', 0, 0, 1287, 185, 1812, 8.69, 'Il-2 1946 includes all of the original IL-2 series content: IL-2 Sturmovik™: Forgotten Battles, Ace Expansion Pack, Pacific Fighters™ and alternate histry campaigns of year 1946. What was years ago began as a one-aircraft study sim is now an astonishing anthology, with a whopping 229 flyable aircraft and over 300 aircraft total!', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® XP/2000 (only)<br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Pentium® III or AMD Athlon™ 1 GHz (Pentium 4 2.4 GHz recommended)<br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 512 MB (1 GB recommended)<br>\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> DirectX® 9 compliant with 64 MB RAM (128 recommended)(see supported list*)<br>\\t\\t\\t\\t\\t</li><li><strong>DirectX Version:</strong> DirectX 9.0 or higher<br>\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX 9 compliant<br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 1.1+ GB<br>\\t\\t\\t\\t\\t</li><li><strong>Multiplay:</strong> Broadband Internet connection<br>\\t\\t\\t\\t\\t</li><li><strong>* Supported Video Cards at Time of Release:</strong> ATI® Radeon™ 7000/8000/9000/X families, NVIDIA® GeForce™ 256/2/3/4/FX/6 families, Matrox Parhelia™, Intel® GMA 925X/915P/915G chipsets<br>\\t\\t\\t\\t\\t</li><li>(Laptop models of these cards not fully supported.)<br>These chipsets are the only ones that will run this game. Additional chipsets may be supported after release. For an up-to-date list of supported chipsets, please visit the FAQ for this game on our support website at: <a href=\"https://steamcommunity.com/linkfilter/?url=http://support.ubi.com\" target=\"_blank\" rel=\"noopener\" >http://support.ubi.com</a></li></ul>\'}', '0', '0,04', '0', '0,01', '0,04'),
(628, 'sébastien loeb rally evo', '2016', 0, 25, 272, 269, 0, 14.99, 'Sébastien Loeb Rally EVO brings off-road racing to a whole new level of simulation and engagement. It will enable you to drive the best rally cars from the past up to the present day in the most exciting off-road events across the globe.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 Ultimate 64 bit / Windows 8 / Windows 8.1 / Windows 10<br></li><li><strong>Processor:</strong> Intel Core2 Quad Q6600 @ 2.40GHz / AMD A6-3670K 2,7 GHz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> Gigabyte GF GTX 660Ti / Radeon R9 270X<br></li><li><strong>DirectX:</strong> Version 10<br></li><li><strong>Storage:</strong> 30 GB available space<br></li><li><strong>Sound Card:</strong> DirectX compatible<br></li><li><strong>Additional Notes:</strong> These limits are temporary and are subject to change at any time</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 / Windows 8 / Windows Pro 8.1 / Windows 10<br></li><li><strong>Processor:</strong> Intel Core i5-4690K 3.5GHz / AMD FX-6300 Six-Core<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 960 / Radeon R9 290<br></li><li><strong>DirectX:</strong> Version 11</li></ul>\'}', '0', '0,05', '0', '0,01', '0,05');
INSERT INTO `jeux` (`id_jeu`, `nom_jeu`, `annee`, `age_requis`, `nb_succes`, `nb_avis_pos`, `nb_avis_neg`, `temps_jeu_moyen`, `prix`, `description`, `configuration`, `ventes_AN`, `ventes_EU`, `ventes_JP`, `ventes_Autre`, `ventes_Global`) VALUES
(629, 'rogue trooper', '2007', 0, 0, 248, 15, 0, 6.99, 'Nu Earth: a poisoned planet where endless war rages between the Norts and the Southers. A futile struggle on a hostile planet with no end in sight. But there are tales of a lone warrior. A man who knows no allegiance, the Rogue Trooper!', '{\'minimum\': \'<p><strong>Minimum: </strong>IBM PC or 100% compatible, Microsoft Windows XP or 2000, Intel Pentium 4 or equivalent, 256MB RAM, 100% DirectX 9.0c-compatible 64MB 3D Accelerated Card supporting v1.1 pixel and vertex shaders, Windows XP- or 2000-compatible sound card (100% DirectX 9.0c-compatible), 3GB free disk space, 100% Windows XP- or 2000-compatible mouse and keyboard</p>\\r\\n\\t\\t\\t\\t\\t<p><strong>Recommended: </strong>Intel Pentium 4 2.0GHz or equivalent, 512MB RAM, 100% DirectX 9.0c-compatible 128MB 3D Accelerated Card supporting v2.0 pixel and vertex shaders, Windows XP- or 2000-compatible sound card (100% DirectX 9.0c-compatible), 3GB free disk space</p>\'}', '0,03', '0,02', '0', '0,01', '0,06'),
(630, 'painkiller hell & damnation', '2012', 0, 107, 2240, 679, 189, 17.99, 'Evil has returned! Demonic powers are manifesting themselves as a myriad of dark creatures, fighting over the fates of imprisoned souls caught in Purgatory.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP SP3, Windows Vista/7 <br>\\t</li><li><strong>Processor:</strong> Intel Core 2 Duo @ 2Ghz / AMD Athlon 64 X2 equivalent<br>\\t</li><li><strong>Memory:</strong> 2 GB RAM<br>\\t</li><li><strong>Graphics:</strong> NVIDIA GeForce 8600 / ATI Radeon HD 2600XT (256 MB) <br>\\t</li><li><strong>DirectX®:</strong> 9.0c<br>\\t</li><li><strong>Hard Drive:</strong> 5 GB HD space<br>\\t</li><li><strong>Sound:</strong> DirectX Compatible </li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista/7 <br>\\t</li><li><strong>Processor:</strong> 2.4 GHz Quad Core processor <br>\\t</li><li><strong>Memory:</strong> 3 GB RAM<br>\\t</li><li><strong>Graphics:</strong> NVIDIA GeForce 9800 GTX/ATI Radeon HD 4850 (512+ MB) <br>\\t</li><li><strong>DirectX®:</strong> 9.0c<br>\\t</li><li><strong>Hard Drive:</strong> 5 GB HD space<br>\\t</li><li><strong>Sound:</strong> DirectX Compatible </li></ul>\'}', '0,02', '0,03', '0', '0,01', '0,06'),
(631, 'corpse party book of shadows', '2018', 18, 33, 96, 5, 0, 12.99, 'An anthology series that serves as a Corpse Party sequel, prequel, midquel, and alternate universe tale all in one. Rejoin old friends for a deeper dive into the haunted halls of Heavenly Host Elementary...', '{\'minimum\': \'<strong>最低配置:</strong><br><ul class=\"bb_ul\"><li><strong>操作系统:</strong> Windows XP/Windows Vista/Windows 7/Windows 8/Windows 10<br></li><li><strong>处理器:</strong> 1.5 GHz<br></li><li><strong>内存:</strong> 512 MB RAM<br></li><li><strong>图形:</strong> 64 MB VRAM, 3D accelerator compatible w/ DirectX 9.0c<br></li><li><strong>DirectX 版本:</strong> 9.0c<br></li><li><strong>存储空间:</strong> 需要 6 GB 可用空间<br></li><li><strong>声卡:</strong> Compatible with DirectX 9.0c</li></ul>\'}', '0', '0', '0,04', '0', '0,04'),
(632, 'mechanic escape', '2014', 0, 33, 656, 99, 283, 4.49, 'In a world oppressed by ruthless machines, a stronghold full of die-hard TV-sets resists the persecution. Your lost friends and the lack of resources drive you to take action against the extinction. Brave the dangers and go find your comrades to rescue your species!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP (x86 - x64)<br></li><li><strong>Processor:</strong> 1.4GHz Processor<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> Any graphic card since 2004<br></li><li><strong>DirectX:</strong> Version 9.0<br></li><li><strong>Storage:</strong> 2 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 / 8 (x86 - x64)<br></li><li><strong>Processor:</strong> 2.0GHz Processor<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> Any graphic card since 2006<br></li><li><strong>DirectX:</strong> Version 9.0<br></li><li><strong>Storage:</strong> 2 GB available space</li></ul>\'}', '0', '0', '0,04', '0', '0,04'),
(633, 'port royale 2', '2009', 0, 0, 174, 95, 203, 2.99, 'The Caribbean in the 17th Century - Trade with over 60 towns, create your own production facilities, expand your trading empire and influence the development of the New World. As pirates and military fleets threaten your trade convoys, you\'ll need escort ships.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP / Vista<br>\\t\\t\\t\\t</li><li><strong>Processor:</strong> Pentium III (or compatible) with 700MHz (or higher)<br>\\t\\t\\t\\t</li><li><strong>Memory:</strong> 128 MB RAM (for Windows 98SE or ME), 256 MB RAM (for Windows 2000, or XP)<br>\\t\\t\\t\\t</li><li><strong>Graphics:</strong> DirectX-8 compatible Graphic Card<br>\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX 9<br>\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 700MB of free space<br>\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX-8 compatible Sound Card<br>\\t\\t\\t\\t</li></ul>\'}', '0', '0,03', '0', '0,01', '0,04'),
(634, 'company of heroes tales of valor', '2009', 0, 0, 1337, 101, 226, 9.99, 'Company of Heroes®: Tales of Valor™ is the expansion to the Game of the Year winner and highest rated real time strategy franchise Company of Heroes®. Featuring new campaigns to overcome, units to command, and battlefields to conquer, Company of Heroes®: Tales of Valor™ delivers evolved gameplay mechanics and 3 episodic adventures...', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® XP or Vista <br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> SSE capable processor, 2.0 Ghz Intel Pentium IV or equivalent or AMD Athlon XP or equivalent. <br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 512 MB RAM. 1GB MB RAM required for Vista <br>\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> DirectX 9.0c compatible 64MB video card with Pixel Shader 1.1 support or equivalent and latest manufacturer drivers <br>\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX® 9.0c compatible 16-bit sound card </li></ul>\'}', '0', '0,03', '0', '0,01', '0,04'),
(635, 'farm frenzy 3', '2010', 0, 0, 7, 1, 0, 6.99, 'Manage five farms around the world and try your hand at penguin-breeding and jewelry-making in Farm Frenzy 3! Features 95 outrageously fun levels, 30 wacky animals and more upgrades than there are ears in a corn field!', '{\'minimum\': \'<ul>\\n\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>OS:</strong> Windows 98/ME/2000/XP/Vista</li>\\n\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>Processor:</strong> 700 MHz CPU</li>\\n\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>Memory:</strong> 1024 MB Ram</li>\\n\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>DirectX&reg;:</strong> 8</li>\\n\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>Hard Drive:</strong> 100 MB of free space</li>\\n\\t\\t\\t\\t\\t\\t\\t</ul>\\n\'}', '0', '0,05', '0', '0,01', '0,07'),
(636, 'nitroplus blasterz heroines infinite duel', '2016', 0, 51, 375, 46, 198, 14.99, 'The hit crossover 2D fighter finally makes its way to PC, updated to the latest arcade version for character balancing, added background animations and additional winning poses. It also includes all DLC from the console release, such as additional fighters Homura and Heart, in a single value package.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 / 8 / 8.1<br></li><li><strong>Processor:</strong> Intel Core2 Duo<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> nVidia GeForce 7900 GT or better / AMD Radeon X1900 / nVidia GeForce GT 620<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 5 GB available space<br></li><li><strong>Sound Card:</strong> Direct Sound</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 / 8 / 8.1 / 10<br></li><li><strong>Processor:</strong> Intel Core i5 / i7<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> nVidia GeForce 8800 GT or better / AMD Radeon HD3700 / nVidia GeForce GT 650<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 5 GB available space<br></li><li><strong>Sound Card:</strong> Direct Sound</li></ul>\'}', '0,01', '0', '0,03', '0', '0,05'),
(637, 'imperial glory', '2014', 0, 0, 600, 172, 72, 3.99, 'It is a time of war in Europe. Driven by new ideas of Enlightenment, the hearts of men and women across the continent are inflamed with dreams of freedom and glory. This is the moment for a military genius to forge himself a name to be remembered throughout all eternity. This is your moment.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP<br></li><li><strong>Processor:</strong> 1 GHz Processor<br></li><li><strong>Memory:</strong> 256 MB RAM<br></li><li><strong>Graphics:</strong> 3D graphics card compatible with DirectX 7<br></li><li><strong>DirectX:</strong> Version 7.0<br></li><li><strong>Storage:</strong> 2 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9 compatible sound</li></ul>\'}', '0', '0,04', '0', '0', '0,04'),
(638, 'company of heroes opposing fronts', '2007', 0, 0, 579, 52, 79, 9.99, 'The next chapter in the #1 rated RTS franchise thrusts players into a hellish war torn landscape to command two battle-hardened armies in relentless campaigns for honor and country. Players lead the tenacious British 2nd Army during the heroic World War II liberation of Caen, France, and command the German Panzer Elite as they struggle...', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>Supported OS:</strong> Windows® XP or Vista.<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 2.0Ghz Intel Pentium IV or equivalent or AMD Athlon XP or equivalent. SSE capable processor required.<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 512MB RAM; Vista users require 1GB of RAM to play the game<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> DirectX 9.0c compatible 64MB video card with Pixel Shader 1.1 support or equivalent and latest manufacturer drivers<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX® 9.0c compatible 16-bit sound card<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Input Devices:</strong> Keyboard, Mouse<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 9GB of uncompressed free hard drive space</li></ul><strong>Recommended:</strong><br>\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>Processor:</strong> 3.0Ghz Intel Pentium IV or equivalent<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1GB RAM<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 256MB NVIDIA GeForce 6800 series or better</li></ul><strong>Required for Multiplayer:</strong><br>\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>RAM:</strong> 1GB RAM required for Multiplayer and Skirmish<br>\\t\\t\\t\\t\\t\\t\\t</li><li>Internet (TCP/IP) and LAN (TCP/IP) play supported.<br>\\t\\t\\t\\t\\t\\t\\t</li><li>1 game license per computer.</li></ul>Internet connection required for single-player and multiplayer play\'}', '0,01', '0,03', '0', '0,01', '0,04'),
(639, 'men of war vietnam', '2011', 0, 22, 399, 247, 10, 5.59, 'The critically acclaimed series returns! Experience Vietnam from both sides of the war.', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP(SP1), Windows Vista or Windows 7<br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> P4 2.6GHz (Athlon 3000+)<br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1GB<br>\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space:</strong> 3 GB free hard disk space<br>\\t\\t\\t\\t\\t</li><li><strong>Video Card:</strong> GeForce 6600 (Radeon 1950) 128Mb<br>\\t\\t\\t\\t\\t</li><li><strong>CD ROM:</strong> PC DVD-ROM<br>\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>Processor:</strong> Core 2 Duo 2.33GHz (Athlon X2 5000+)<br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2GB<br>\\t\\t\\t\\t\\t</li><li><strong>Video Card:</strong> GeForce FX 8800 (Radeon HD3850) 256Mb<br>\\t\\t\\t\\t\\t</li></ul>\'}', '0', '0,03', '0', '0,01', '0,04'),
(640, 'shattered union', '2006', 0, 0, 39, 49, 0, 2.99, 'Following a great increase in terrorism, internal strife and ultimately, the nuclear destruction of Washington, D.C., the United States shatters into a half-dozen nation-states that descend into war. Take the helm of one of these newfound sovereignties (or the \'peacekeeping\' European Expeditionary Force) and struggle to reunify America...', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 98SE/2000/ME/XP with the latest updates<br></li><li><strong>Processor:</strong> Pentium III 800 MHz OR AMD Equivalent<br></li><li><strong>Memory:</strong> 128 MB RAM<br></li><li><strong>Graphics:</strong> 128 MB RAM that supports Vertex and Pixel Shading of 1.4 or higher<br></li><li><strong>DirectX:</strong> Version 9.0b<br></li><li><strong>Storage:</strong> 2 GB available space<br></li><li><strong>Additional Notes:</strong> Windows Vista and newer are not supported</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 98SE/2000/ME/XP with the latest updates<br></li><li><strong>Processor:</strong> Pentium 4 1.8 GHz OR AMD Athlon XP 1800+<br></li><li><strong>Memory:</strong> 256 MB RAM<br></li><li><strong>Graphics:</strong> 128 MB RAM that supports Vertex and Pixel Shading of 1.4 or higher<br></li><li><strong>DirectX:</strong> Version 9.0b<br></li><li><strong>Storage:</strong> 2 GB available space</li></ul>\'}', '0,03', '0,01', '0', '0', '0,04'),
(641, 'offroad drive', '2011', 0, 0, 286, 177, 0, 3.99, 'Off-Road Drive, the off-road racing simulation for PC, is the first game ever to deliver a true-to-life, off-road, extreme racing experience. Players will take part in The Russian trophy, Off-Road Trial, Thai Trophy and many other events through the worst driving conditions with a variety of natural obstacles like swamps, rocks, snow and...', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP/Vista/Windows 7<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Pentium IV 2 GHz<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1GB<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space:</strong> 8GB\\t<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Video Card:</strong> DirectX 9.0 compatible video card with 256 MB RAM<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX 9.0 compatible sound card<br>\\t\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br>\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP/Vista/Windows 7<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Core 2 Duo 3 GHz or AMD Athlon 64 X2 4200+<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2GB<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space:</strong> 8GB\\t<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Video Card:</strong> DirectX 9.0 compatible video card with 256 MB RAM<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX 9.0 compatible sound card<br>\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0', '0,03', '0', '0,01', '0,04'),
(642, 'city builder', '2017', 0, 0, 1, 1, 0, 7.19, 'An interactive puzzle game for all ages! City Builder combines two classic game mechanics in a fun, bouncy new game where players stack pipes, roads and power lines to form ever-larger cities, moving from one to the next across the planet’s continents.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7/10<br></li><li><strong>Processor:</strong> Dual Core CPU 1GHz<br></li><li><strong>Memory:</strong> 512 MB RAM<br></li><li><strong>Graphics:</strong> 256 MB<br></li><li><strong>Storage:</strong> 400 MB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 10<br></li><li><strong>Processor:</strong> Dual Core CPU 1.6GHz<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> 512 MB<br></li><li><strong>Storage:</strong> 600 MB available space</li></ul>\'}', '0,04', '0', '0', '0', '0,04'),
(643, 'city builder', '2017', 0, 0, 1, 1, 0, 7.19, 'An interactive puzzle game for all ages! City Builder combines two classic game mechanics in a fun, bouncy new game where players stack pipes, roads and power lines to form ever-larger cities, moving from one to the next across the planet’s continents.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7/10<br></li><li><strong>Processor:</strong> Dual Core CPU 1GHz<br></li><li><strong>Memory:</strong> 512 MB RAM<br></li><li><strong>Graphics:</strong> 256 MB<br></li><li><strong>Storage:</strong> 400 MB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 10<br></li><li><strong>Processor:</strong> Dual Core CPU 1.6GHz<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> 512 MB<br></li><li><strong>Storage:</strong> 600 MB available space</li></ul>\'}', '0,04', '0', '0', '0', '0,04'),
(644, 'clannad', '2015', 0, 22, 1900, 40, 188, 29.99, 'From the world renowned visual novel studio Key, the highly rated story of CLANNAD is now available on Steam! Improved visuals, achievement integration, and Dangopedia make this the best version of CLANNAD to date.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista or higher<br></li><li><strong>Processor:</strong> 1.2Ghz<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> 640x480<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 7 GB available space<br></li><li><strong>Sound Card:</strong> DirectSound-compatible sound card</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7/8.1/10<br></li><li><strong>Processor:</strong> 1.2Ghz<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> 1280x960<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 7 GB available space<br></li><li><strong>Sound Card:</strong> DirectSound-compatible sound card</li></ul>\'}', '0', '0', '0,14', '0', '0,14'),
(645, 'metal slug xx', '2019', 0, 34, 70, 69, 0, 15.49, 'METAL SLUG XX, the most recent installment in the famous run-and-gun action shooting series, returns to the battlefield on Steam with a plethora of brand new features!', '{\'minimum\': \'<strong>Mínimos:</strong><br><ul class=\"bb_ul\"><li>Requer um processador e sistema operacional de 64 bits<br></li><li><strong>SO:</strong> Win 7, 8.1, 10<br></li><li><strong>Processador:</strong> Intel: 4th Generation Core i3 Haswell or newer, AMD: A6-5400K Trinity<br></li><li><strong>Memória:</strong> 2 GB de RAM<br></li><li><strong>Placa de vídeo:</strong> Intel HD Graphics 500, Radeon HD 7000 or newer, GTX 560 or newer<br></li><li><strong>Outras observações:</strong> OpenGL 4.4</li></ul>\', \'recommended\': \'<strong>Recomendados:</strong><br><ul class=\"bb_ul\"><li>Requer um processador e sistema operacional de 64 bits<br></li><li><strong>SO:</strong> Win 10<br></li><li><strong>Processador:</strong> Intel: 4th Generation Core i3 Haswell or newer, AMD: AMD FX 8320<br></li><li><strong>Memória:</strong> 4 GB de RAM<br></li><li><strong>Placa de vídeo:</strong> GTX 560 or newer, R7 200 Series, GTX 560 or newer<br></li><li><strong>Outras observações:</strong> OpenGL 4.5</li></ul>\'}', '0,03', '0', '0', '0', '0,04'),
(646, 'dreamfall the longest journey', '2007', 0, 0, 588, 89, 20, 13.99, 'Dreamfall: The Longest Journey, winner of multiple E3 awards as the best game in its genre, is the continuation of a saga that began in the award-winning The Longest Journey, considered to be one of the finest adventure games ever made.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP (with service pack 2) only <br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Pentium 4 1.6 GHz or AMD Sempron 2800+ or higher required. Intel Pentium 4 2.5 GHz or AMD Athlon XP 3500+ Recommended <br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 512 MB RAM <br>\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 3D Hardware Accelerator Card Required: 100% DirectX 9.0c compatible 128 MB with latest drivers. <br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 7 GB free disk space <br>\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX 9.0c compatible sound </li></ul>\'}', '0,03', '0,01', '0', '0', '0,04'),
(647, 'supreme commander forged alliance', '2011', 0, 0, 4969, 174, 803, 8.99, 'The last days of man are at hand.. Two years after the Infinite War the once great warring nations now lie in ruins, and humanity’s hope for a brighter future is nothing but a bitter memory. A new, seemingly unstoppable enemy, supported by the zealots of The Order, now seeks to eradicate mankind: UEF, Aeon Loyalist, and Cybran alike.', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® XP Service Pack 2, Windows® Vista<br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 1.8 GHz processor <br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 512 MB RAM<br>\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space:</strong> 8GB available hard drive space\\t<br>\\t\\t\\t\\t\\t</li><li><strong>Video Card:</strong> 128 MB video RAM or greater, with DirectX 9 Vertex Shader / Pixel Shader 2.0 support (ATI 9600+, Nvidia 6200+)<br>\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® XP Service Pack 2, Windows® Vista<br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 3.0 GHz Intel or equivalent AMD processor or better<br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1 GB RAM or better<br>\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space:</strong> 8GB available hard drive space\\t<br>\\t\\t\\t\\t\\t</li><li><strong>Video Card:</strong> 256 MB video RAM, with DirectX 9 Vertex Shader / Pixel Shader 2.0 support (Nvidia 6800 or better)<br>\\t\\t\\t\\t\\t</li></ul>\'}', '0,01', '0,02', '0', '0,01', '0,04'),
(648, 'sid meiers railroads!', '', 0, 0, 0, 0, 0, 0.00, '0', '0', '0,01', '0,03', '0', '0,01', '0,04'),
(649, 'ballistic', '2017', 0, 0, 6, 2, 0, 6.97, 'Launch yourself like a bullet through 33 levels of intense physics-based combat and brutal platforming challenges in this unique and violent arcade-style adventure.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li>Requires a 64-bit processor and operating system<br></li><li><strong>OS:</strong> Windows 7 64-bit<br></li><li><strong>Processor:</strong> Quad-core Intel or AMD processor, 2.5 GHz or faster<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce 470 GTX or AMD Radeon 6870 HD series card or higher<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 9 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li>Requires a 64-bit processor and operating system<br></li><li><strong>OS:</strong> Windows 10 64-bit<br></li><li><strong>Processor:</strong> Intel Core i5 or AMD A8, 3.5 GHz or faster<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce 970 or AMD R9 390 or higher<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 9 GB available space</li></ul>\'}', '0,02', '0,01', '0', '0', '0,04'),
(650, 'caesar iv', '2016', 0, 0, 115, 96, 0, 7.99, 'Starting as governor of a newly formed province in the Roman Empire your goal is simple: advance up the empire\'s political ladder to become the next Caesar.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP / Vista / 7 / 8 / 10<br></li><li><strong>Processor:</strong> 1.8 GHz<br></li><li><strong>Memory:</strong> 512 MB RAM<br></li><li><strong>Graphics:</strong> DirectX 9.0c Compatible 3D Card w/256MB VRAM<br></li><li><strong>Storage:</strong> 2 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c Compatible<br></li><li><strong>Additional Notes:</strong> Official multiplayer servers are inactive, Caesar IV is available as single-player only.</li></ul>\'}', '0', '0,03', '0', '0,01', '0,04'),
(651, 'secret files 2 puritas cordis', '2009', 0, 0, 60, 17, 0, 7.99, 'The sequel to the award winning adventure hit Secret Files Tunguska. Famine in Africa, floods in Southeast Asia, economic crisis in Europe, and civil wars in South America, the world is on the brink of disaster.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 2000/XP/Vista<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Pentium III or 100% compatible processor<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 256 MB RAM<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> DirectX® 9 compatible AGP or PCI Express video card (at least 32 MB)<br>\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 9.0c<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 2 GB hard disk space<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX® 9 compatible 16 bit sound card (optional)<br>\\t\\t\\t\\t\\t</li></ul>\'}', '0', '0,07', '0', '0,01', '0,08'),
(652, 'apb reloaded', '2011', 0, 60, 20028, 11779, 3835, 0.00, 'The world’s first and premier Action MMO Third Person Shooter allows you to choose between two sides of the law. Play as Enforcer or Criminal, customize your gear for the task at hand and hit the streets and play how you want in a city filled with more action this side of a Hollywood blockbuster.', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong>Windows XP<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong>Intel Core 2 Duo E6420 (2.13GHz) or AMD Athlon x2 5800+ (3.0GHz)<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong>3 GB RAM<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong>GeForce 7800 with 256MB and support for Pixel Shader 3.0, or AMD equivalent<br>\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong>dx90c<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong>7 GB HD space<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Other Requirements:</strong>Broadband Internet connection<br>\\t\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br>\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong>Windows Vista 64-Bit / Windows 7 64-Bit<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong>2.4GHz Intel Core 2 Quad or equivalent AMD x4<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong>4 GB RAM<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong>GeForce 8800GT 512MB or AMD equivalent<br>\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong>dx90c<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong>7 GB HD space<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong>Dedicated sound card with hardware acceleration.<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Other Requirements:</strong>Broadband Internet connection<br>\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0,02', '0,01', '0', '0', '0,04'),
(653, 'railroad tycoon 3', '2007', 0, 0, 355, 153, 46, 5.99, 'Railroad Tycoon 3 features 25 scenarios challenging players to recreate magnificent feats of railroading history from around the world. Players can lay track (including tunnels and overpasses), pick from over 40 locomotives from early steams to modern bullets, choose to haul over 35 types of cargo in a dynamic economy, and participate in...', '{\'minimum\': \'<strong>Minimum: </strong>Windows 2000/XP (only), 400 mhz, 128 MB RAM, 1.2 GB Free Disk Space, 16 MB 3D Video Card, mouse, and keyboard, DirectX compatible sound card with speakers/headphones recommended.\'}', '0', '0,03', '0', '0,01', '0,04'),
(654, 'worms ultimate mayhem', '2011', 0, 38, 2188, 323, 689, 10.99, 'Load your weapons and experience a whole new dimension in destructive turn-based cartoon action!', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 / Vista / XP<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 3.0 GHz P4, Dual Core 2.0 (or higher) or AMD64X2 (or higher)<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2GB<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 512 MB NVIDIA GeForce 8400 / ATI Radeon HD 4650 or higher<br>\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 9.0c<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> At least 1.8 GB of Space<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX 9.0c compatible<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Other:</strong> Internet connection required<br>\\t\\t\\t\\t\\t\\t</li></ul><br>Note: In some instances, systems may require model specific drivers. If your system manufacturers no longer support hardware under this category, it may not be possible to run this title. Should this be the case, we are unable to assist you and recommend that you pursue support from your respective system manufacturer. This issue is most common in laptops and is prevalent with select products from most leading manufacturers.\'}', '0', '0,03', '0', '0', '0,04'),
(655, 'the night of the rabbit', '2013', 0, 17, 1700, 179, 96, 16.99, 'Lose yourself in a tale of magic and wonder, where anything is possible and where nothing is quite as it seems: join young Jerry and follow a peculiar white rabbit to the wondrous realm of Mousewood, a land where critters can speak and where mystery abounds.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong>Windows Vista/7<br>\\t</li><li><strong>Processor:</strong>2.5 GHz (Single Core) or 2 GHz (Dual Core)<br>\\t</li><li><strong>Memory:</strong>2 GB RAM<br>\\t</li><li><strong>Graphics:</strong>OpenGL 2.0 compatible with 256 MB RAM (Shared Memory is not recommended)<br>\\t</li><li><strong>DirectX®:</strong>9.0c<br>\\t</li><li><strong>Hard Drive:</strong>6 GB HD space<br>\\t</li><li><strong>Sound:</strong>DirectX compatible</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong>Windows Vista/7/8<br>\\t</li><li><strong>Processor:</strong>2.5 GHz (Single Core) or 2 GHz (Dual Core)<br>\\t</li><li><strong>Memory:</strong>4 GB RAM<br>\\t</li><li><strong>Graphics:</strong>OpenGL 2.0 compatible with 512 MB RAM (Shared Memory is not recommended)<br>\\t</li><li><strong>DirectX®:</strong>9.0c<br>\\t</li><li><strong>Hard Drive:</strong>6 GB HD space<br>\\t</li><li><strong>Sound:</strong>DirectX compatible</li></ul>\'}', '0', '0,03', '0', '0', '0,04'),
(656, 'world of goo', '2008', 0, 8, 3455, 237, 194, 6.99, 'World of Goo is a multiple award winning physics based puzzle / construction game made entirely by two guys.', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>Supported OS: </strong>Windows® XP or Vista<br>\\t\\t\\t\\t\\t</li><li><strong>Processor: </strong>1GHz or faster<br>\\t\\t\\t\\t\\t</li><li><strong>Memory: </strong>512+MB RAM<br>\\t\\t\\t\\t\\t</li><li><strong>Video: </strong>Any 3D graphics accelerator less than 5 years old<br>\\t\\t\\t\\t\\t</li><li><strong>DirectX® Version: </strong>9.0c <br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive: </strong>100MB </li></ul>\'}', '0', '0,03', '0', '0,01', '0,04'),
(657, 'stalker clear sky', '2008', 0, 0, 5550, 903, 716, 7.99, 'S.T.A.L.K.E.R.: Clear Sky – standalone prequel for the acclaimed S.T.A.L.K.E.R.: Shadow of Chernobyl, which tells you story about the Clear Sky group, that want to research the Zone and understand it better.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>Supported OS: </strong>Microsoft® Windows® XP(Service Pack 2)/Microsoft® Windows® 2000 SP4 <br></li><li><strong>Processor: </strong>Intel Pentium 4 2.0 Ghz / AMD XP 2200+ <br></li><li><strong>Graphics: </strong>128 MB DirectX® 8.0 compatible card / nVIDIA® GeForce™ 5700 / ATI Radeon® 9600 <br></li><li><strong>Memory: </strong>512 MB RAM <br></li><li><strong>Sound: </strong>DirectX® 9.0 compatible sound card <br></li><li><strong>Hard Drive: </strong>6 GB free hard disc space </li></ul>\', \'recommended\': \'<ul class=\"bb_ul\"><li><strong>Supported OS: </strong>Microsoft® Windows® XP/Vista (SP1) <br></li><li><strong>Processor: </strong>Intel Core 2 Duo E6400 / AMD 64 X2 4200+ <br></li><li><strong>Graphics: </strong>256 MB DirectX® 9.0c compatible card* / nVIDIA® GeForce™ 8800 GT / ATI Radeon® HD 2900 XT <br></li><li><strong>Memory: </strong>2 GB RAM <br></li><li><strong>Sound: </strong>DirectX® 9.0 compatible sound card <br></li><li><strong>Hard Drive: </strong>10 GB free hard disc space </li></ul>\'}', '0', '0,03', '0', '0,01', '0,04'),
(658, 'ray gigant', '2016', 0, 42, 40, 31, 0, 22.99, 'Ray Gigantis a unique dungeon crawler RPG which combines dungeon crawling adventure with Japanese visual novel like story telling. Players will first be introduced to the gripping tale of Ichiyawho is a young fighter shrouded in mystery.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 (32bit, 64bit)<br></li><li><strong>Processor:</strong> Intel Core i5 1.90 GHz or equivelant<br></li><li><strong>Memory:</strong> 6 GB RAM<br></li><li><strong>Graphics:</strong> Direct X 11 compatible graphics card with 1GB of ram or equivelant<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 6 GB available space<br></li><li><strong>Sound Card:</strong> Realtek High Definition Audio equivalent or better</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 8.1, Windows 10<br></li><li><strong>Processor:</strong> Intel Core i5 2.80 GHz or equivelant<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 750/AMD Radeon R7 equivalent or better<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 6 GB available space<br></li><li><strong>Sound Card:</strong> Realtek High Definition Audio equivalent or better</li></ul>\'}', '0', '0', '0,04', '0', '0,04'),
(659, 'darkstar one', '2008', 0, 0, 256, 59, 0, 6.99, 'Darkstar One offers a fantastic amount of freedom of choice. The story-based missions gradually lead you deeper into the galaxy to new races, new technologies and ever stronger opponents. Explore a vast array of solar systems in search of hidden artifacts of ancient races, essential objects for upgrading your ship--the Darkstar One.', '{\'minimum\': \'<strong>Minimum: </strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>Supported OS: </strong>Windows XP (32 bit)<br>\\t\\t\\t\\t\\t</li><li><strong>Processor: </strong>1.6 GHz Intel or AMD processor<br>\\t\\t\\t\\t\\t</li><li><strong>Memory: </strong>512 MB RAM<br>\\t\\t\\t\\t\\t</li><li><strong>Sound: </strong>DirectX compatible Sound Card<br>\\t\\t\\t\\t\\t</li><li><strong>Graphics: </strong> DirectX 9 compatible 128 MB graphics card with support for pixel/vertex shader 1.1 (GeForce 3 and above)<br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive: </strong>6 GB HD Space</li></ul><strong>Recommended: </strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>Supported OS: </strong>Windows XP with SP2<br>\\t\\t\\t\\t\\t</li><li><strong>Processor: </strong>3.0 GHz Intel or AMD processor<br>\\t\\t\\t\\t\\t</li><li><strong>Memory: </strong>1024 MB RAM<br>\\t\\t\\t\\t\\t</li><li><strong>Sound: </strong>DirectX compatible Sound Card<br>\\t\\t\\t\\t\\t</li><li><strong>Graphics: </strong> DirectX 9 compatible 256 MB graphics card with support for pixel/vertex shader 3.0 (GeForce 6/Radeon x1x00 and above)<br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive: </strong>7 GB HD Space</li></ul>\'}', '0', '0,03', '0', '0,01', '0,04'),
(660, 'clockwork empires', '2016', 0, 46, 348, 426, 470, 22.99, 'Take on the role of a Colonial Bureaucrat sent forth by the Clockwork Empire to build a Frontier Colony. Design houses &amp; workshops to feed the Ravenous Maw of Industry, manage a uniquely unruly population, avoid cannibalism &amp; monsters, and make Important Decisions for the glory of the Empire!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7, Operating System of The Lower Classes<br></li><li><strong>Processor:</strong> Intel i5 Processor or Equivalent (&quot;The Little Scrapper&quot; model)<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA or AMD card capable of supporting OpenGL 3.2 Core or Above. INTEL HD3000 AND HD4000 GRAPHICS CARDS ARE NOT SUPPORTED.<br></li><li><strong>DirectX:</strong> Version 9.0<br></li><li><strong>Storage:</strong> 4 GB available space<br></li><li><strong>Sound Card:</strong> Lord Palmerstoke\\\'s Sound-Reproducing &quot;Old-Timey&quot; Wax Cylinder Driver<br></li><li><strong>Additional Notes:</strong> INTEL HD3000 AND HD4000 GRAPHICS CARDS ARE NOT SUPPORTED. The Ministry for Video Game Drivers would like to remind you: true Patriots of the Empire always install their latest Graphics Card Drivers before Enjoying A Bracing Video Game, lest the Blackness Consume Us All.</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7, 64-Bit Version (By Appointment to Her Majesty)<br></li><li><strong>Processor:</strong> Intel i7 or above, fashioned of Stout Empire Tin and Burnished of Solid Pewter<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> A Big, Shiny NVIDIA or AMD Graphics Card With Lots of Fans Stuck to It. (Remember: More Fans Means More Steampunk!)<br></li><li><strong>DirectX:</strong> Version 9.0<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 8 GB available space<br></li><li><strong>Sound Card:</strong> &quot;His Masters\\\' Voice&quot; Novorusian All-Wailing Gramaphone Module and Borscht Dispensary<br></li><li><strong>Additional Notes:</strong> The Ministry for Growth and Monitoring encourages you to buy a Really Big Monitor.</li></ul>\'}', '0', '0,03', '0', '0', '0,04'),
(661, 'sins of a solar empire trinity', '2011', 0, 0, 428, 149, 145, 15.49, 'In Sins of a Solar Empire: Trinity, you are the leader of a civilization embroiled in a galactic war, fighting for the survival of your entire race against relentless foes.', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong>Windows 10 / 8.1 / 7 / Vista SP2 / XP SP3<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong>Intel Pentium 4 1.8 GHz or Equivalent<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong>512 MB RAM<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong>128 MB DirectX 9.0c Compatible Video Card w/Pixel Shader 2.0 Support<br>\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong>dx90c<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong>4 GB HD space<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong>DirectX 9.0c Compatible Sound Card<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Other Requirements:</strong>Broadband Internet connection, also to activate this game you must create a Stardock account while launching the game on Steam.<br>\\t\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br>\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong>Windows 10 / 8.1 / 7 / Vista SP2 / XP SP3<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong>Dual-Core Processor<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong>1 GB RAM<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong>256 MB DirectX 9.0c Compatible Video Card w/Pixel Shader 2.0 Support<br>\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong>dx90c<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong>4 GB HD space<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong>DirectX 9.0c Compatible Sound Card<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Other Requirements:</strong>Broadband Internet connection<br>\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0', '0,03', '0', '0,01', '0,04'),
(662, 'crazy machines', '2008', 0, 0, 98, 24, 0, 6.99, 'Turn the crank, rotate the gears, push the levers, Use the catapult, explode it, or fly it...From grilling sausages with a pulley, gears, rubberbands and a candle to firing a cannon with a basketball, these wacky brain-teasers will light up your imagination with creative and addictive fun.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Win 2000/XP/Vista <br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 800 MHz CPU <br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 128 MB RAM <br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> DirectX 8 compatible graphics card with 32 MB RAM (TNT 2 or comparable) <br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX Version:</strong> 8.1 or higher <br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 60 MB free disk space <br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound Card:</strong> DirectX 8 compatible soundcard <br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0,01', '0,04', '0', '0', '0,06'),
(663, 'aegis of earth protonovus assault', '2016', 0, 32, 17, 11, 0, 14.99, 'Aegis of Earth: Protonovus Assault is a frenetic and explosive new spin on action strategy gaming. Plan out and build up your defenses as hordes of hulking monstrosities bombard your heavily fortified city in an attempt to wipe you off the Earth for good!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 / 8 / 8.1<br></li><li><strong>Processor:</strong> Intel Core2 Duo<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> nVidia GeForce 7900 GT or better / AMD Radeon X1900 / nVidia GeForce GT 620 (Windows 8.1)<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 7 GB available space<br></li><li><strong>Sound Card:</strong> Direct Sound<br></li><li><strong>Additional Notes:</strong> Compatibility with Xbox 360 Controller</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 / 8 / 8.1<br></li><li><strong>Processor:</strong> Intel Core i5 / i7<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> nVidia GeForce 8800 GT or better / AMD Radeon HD3700 / nVidia GeForce GT 650 (Windows 8.1)<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 7 GB available space<br></li><li><strong>Sound Card:</strong> Direct Sound<br></li><li><strong>Additional Notes:</strong> Compatibility with Xbox 360 Controller</li></ul>\'}', '0,05', '0,02', '0', '0,01', '0,09'),
(664, 'a game of thrones genesis', '2011', 0, 75, 201, 420, 8, 6.99, 'Immerse yourself into the battles and intrigues between the Houses that shaped the Kingdom of Westeros and keep your spot on the Iron Throne by any means.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> WINDOWS XP SP2/VISTA SP1/WINDOWS 7<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> AMD/INTEL DUAL-CORE 2.2 GHZ<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1024 MB (XP) / 2048 MB (VISTA/7)<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 256 MB 100% DIRECTX 9 AND SHADERS 3.0 COMPATIBLE. ATI RADEON X1600 XT/INTEL HD/NVIDIA GEFORCE 6600 GT OR HIGHER<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 9<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 10 GB<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DIRECTX 9 COMPATIBLE<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Internet:</strong> INTERNET CONNECTION REQUIRED FOR ONLINE GAMING AND GAME ACTIVATION<br>\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0', '0,03', '0', '0,01', '0,04'),
(665, 'hotel giant 2', '2010', 0, 13, 66, 95, 0, 5.59, 'Following its international success, Hotel Giant is back and bigger than ever. In Hotel Giant 2 you will create the hotel of your dreams and manage prestigious locations around the world. Your goal is to attract as many guests as possible and make sure they are satisfied throughout their stay.', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 98, 2000, ME, XP, Vista, 7, 8 (Windows 95 and NT not supported)<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 1.5 GHz CPU<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 512 MB RAM<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> NVIDIA GeForce 5 series or above, ATI Radeon 9 series or above, with at least 256MB video memory<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 2 GB of free space<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX 9 compatible sound card<br>\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br>\\t\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 98, 2000, ME, XP or Vista, 7, 8 (Windows 95 and NT not supported)<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 2.5 GHz CPU<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 768 MB RAM or more<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> NVIDIA GeForce 5 series or above, ATI Radeon 9 series or above, with at least 256MB video memory<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 2 GB of free space<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX 9 compatible sound card<br>\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0', '0,03', '0', '0,01', '0,04'),
(666, 'assassins creed chronicles china', '2015', 0, 0, 1547, 570, 72, 8.59, 'The first entry in the Assassin’s Creed Chronicles saga takes place in China, 1526, as the Ming dynasty starts to crumble. You embody Shao Jun, the last remaining Assassin of the Chinese Brotherhood, returning to her homeland with a vendetta.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 SP1 or Windows 8 or Windows 8.1 (32/64bit versions)<br></li><li><strong>Processor:</strong> Intel Core 2 Duo E8200 @ 2.6 GHz or AMD Athlon II X2 240 @ 2.8 GHz<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> nVidia GeForce GTS450 or AMD Radeon HD5770 (1024MB VRAM with Shader Model 5.0)<br></li><li><strong>DirectX:</strong> Version 10<br></li><li><strong>Storage:</strong> 4 GB available space<br></li><li><strong>Sound Card:</strong> DirectX Compatible Sound Card with latest drivers<br></li><li><strong>Additional Notes:</strong> Video Drivers: nVidia GeForce 347.52 and AMD Catalyst Omega 14.12</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 SP1 or Windows 8 or Windows 8.1 (32/64bit versions)<br></li><li><strong>Processor:</strong> Intel Core i3 2105 @ 3.1 GHz or AMD Phenom II X4 955 @ 3.2 GHz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> nVidia GeForce GTX 470 or AMD Radeon HD5870 or better (1024MB VRAM with Shader Model 5.0)<br></li><li><strong>DirectX:</strong> Version 10<br></li><li><strong>Storage:</strong> 4 GB available space<br></li><li><strong>Sound Card:</strong> DirectX Compatible Sound Card with latest drivers<br></li><li><strong>Additional Notes:</strong> Video Drivers: nVidia GeForce 347.52 and AMD Catalyst Omega 14.12. Supported video cards at the time of release: nVidia GeForce GTS 450 or better, GTX 500, GTX 600, GTX 700 series; AMD Radeon HD5770 or better, Radeon HD6000, HD7000, R7 200, R9 200 series Note: Laptop versions of these cards may work but are NOT officially supported.</li></ul>\'}', '0', '0,03', '0', '0,01', '0,04');
INSERT INTO `jeux` (`id_jeu`, `nom_jeu`, `annee`, `age_requis`, `nb_succes`, `nb_avis_pos`, `nb_avis_neg`, `temps_jeu_moyen`, `prix`, `description`, `configuration`, `ventes_AN`, `ventes_EU`, `ventes_JP`, `ventes_Autre`, `ventes_Global`) VALUES
(667, 'might & magic x legacy', '2014', 0, 0, 1571, 780, 274, 20.99, 'After a decade, a Might &amp; Magic® RPG is back with both the unique core formula and a new set of improved and fine-tuned features. The best RPG of its class!In the wake of the spectacular events in Might &amp; Magic® Heroes® VI, you will play in a party of four adventurers entangled in intrigue and political machinations unfolding in...', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista SP2, Windows 7 SP1, Windows 8 (all 32/64 bit versions)<br></li><li><strong>Processor:</strong> Intel Core 2 Duo E7300 @ 2.6 GHz or AMD Athlon 64 X2 5200+ @ 2.7 GHz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> nVidia GeForce 8800GT or AMD Radeon HD3870 (512MB VRAM with Shader Model 4.0 or higher)<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 10 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c Compatible Sound Card with Latest Drivers<br></li><li><strong>Additional Notes:</strong> Using the Minimum Configuration, we strongly recommend to use minimal settings in order to not experience low framerate.</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista SP2, Windows 7 SP1, Windows 8 (64 bit versions)<br></li><li><strong>Processor:</strong> Intel Core 2 Quad @ 2.4 GHz or AMD Phenom x4 @ 2.3 GHz<br></li><li><strong>Memory:</strong> 6 GB RAM<br></li><li><strong>Graphics:</strong> nVidia GeForce GTX470 or AMD Radeon HD6870 (1024MB VRAM with Shader Model 5.0)<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 10 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c Compatible Sound Card with Latest Drivers</li></ul>\'}', '0', '0,03', '0', '0', '0,04'),
(668, 'supreme ruler cold war', '2011', 0, 0, 113, 62, 0, 6.99, 'Building on Supreme Ruler 2010 and 2020, BattleGoat Studios invites you to relive the tension and uncertainty of the Cold War. As the 1950’s approach, the Korean War looms, the Arms Race intensifies, the Berlin Crisis leads to the formation of NATO, and the world anticipates a new World War.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP/Vista/Windows 7<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Dual Core or greater Recommended<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1 GB RAM<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space:</strong> 1 GB Hard Drive Free <br>\\t\\t\\t\\t\\t\\t</li><li><strong>Video Card:</strong> Direct-X 9.0 Graphics with at least 32MB<br>\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 9.0<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> Direct-X Compatible Sound<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Additional:</strong> 3-button mouse, keyboard and speakers. Up to 16 players in Multiplayer over LAN or Internet<br>\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0', '0,03', '0', '0,01', '0,03'),
(669, 'the void', '2009', 0, 0, 581, 126, 27, 6.99, 'Only brought to life by scarce sparks of Color, the bleak, grey Void is a peculiar place. The player gets to explore it, get to know the Sisters, Brothers, and other weird creatures inhabiting it, and learn the ways of Color, harvesting it and drawing sigils that change the world around them.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP SP2 / Vista<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Pentium IV 2GHz<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 512 MB<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 128 MB DirectX® 9.0c compatible video card (e.g. NVIDIA® GeForce™ FX 5600 or ATi® Radeon™ 9600)<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 9.0c<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 6GB<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX® 9.0c compatible audio card<br>\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0', '0,03', '0', '0,01', '0,03'),
(670, 'sacra terra angelic night', '2015', 0, 0, 193, 29, 0, 1.99, 'Use your cunning to defeat the demons of the Seven Deadly Sins and rescue humanity from destruction!', '{\'minimum\': \'<strong>最低配備:</strong><br><ul class=\"bb_ul\"><li><strong>作業系統:</strong> Windows XP, Vista, 7, 8<br></li><li><strong>處理器:</strong> 1600 MHZ<br></li><li><strong>記憶體:</strong> 1024 MB 記憶體<br></li><li><strong>DirectX:</strong> 版本：9.0<br></li><li><strong>儲存空間:</strong> 600 MB 可用空間</li></ul>\'}', '0,01', '0,02', '0', '0,01', '0,03'),
(671, 'rugby league live 3', '2015', 0, 35, 78, 28, 0, 15.49, 'Rugby League enters the next-generation with Rugby League Live 3! Featuring an all new Be A Pro career mode and FanHub Player Sharing system, the game is a a must-have for any footy fan!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 or higher<br></li><li><strong>Processor:</strong> Pentium Dual-Core CPU E5700 @ 3.00Ghz/AMD Athlon II X2 250 Processor 3.01Ghz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> Radeon HD 6670 or NVIDIA Geforce GT530 with Min 1GB Memory<br></li><li><strong>DirectX:</strong> Version 10<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 6 GB available space<br></li><li><strong>Additional Notes:</strong> Controller Required</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 or higher<br></li><li><strong>Processor:</strong> Intel CoreTM i3-3210 CPU @ 3.20Ghz (4 Cpus) /AMD Phenom II X4 960T 3.0Ghz<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> Radeon HD 7790 or NVIDIA GeForce GTX 650 with minimum 2GB Memory<br></li><li><strong>DirectX:</strong> Version 10<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 6 GB available space<br></li><li><strong>Additional Notes:</strong> Controller Required</li></ul>\'}', '0', '0,09', '0', '0', '0,09'),
(672, 'the binding of isaac', '2011', 0, 99, 43227, 1923, 1849, 3.99, 'Now 20% More Evil with the Free Halloween update!', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP, Vista, 7<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 2.5 GHz<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1GB<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space:</strong> 50MB<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Video Card:</strong> Direct X9.0c Compatible Card<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX® 9.0c<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0', '0,03', '0', '0', '0,03'),
(673, 'earthworm jim 2', '2009', 0, 0, 47, 16, 0, 14.99, 'From Evil the Cat’s’Circus of the Scars’ to the planet of Meat, join Jim on a madcap chase across the galaxy. Saving cows, thwarting lawyers and outsmarting Psy-Crow are all in a day’s work for Jim. Are you up to the challenge? Can you handle the awesome new weapons? Excellent! Then stop reading this. Try it now!', '{\'minimum\': \'<ul>\\n\\t\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>OS:</strong> Windows</li>\\n\\t\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>Processor:</strong> Pentium 133 with 3D card. Pentium 166 without hardware acceleration.</li>\\n\\t\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>Memory:</strong> 8 MB</li>\\n\\t\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>Graphics:</strong> 256-color SVGA video graphic card</li>\\n\\t\\t\\t\\t\\t\\t\\t\\t</ul>\'}', '0,02', '0,01', '0', '0', '0,03'),
(674, 'mystery case files ravenhearst', '2010', 0, 0, 24, 1, 0, 6.99, 'Rumors surrounding the history of stately Ravenhearst Manor have circulated for decades. The recently acquired diary of Emma Ravenhearst may hold the key to unraveling the tale behind this unsettling place, yet the pages are missing.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 2000/XP/Vista<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 600 Mhz or better<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 128 MB RAM<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 6.0<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 91 MB of free space<br>\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0,01', '0,02', '0', '0,01', '0,03'),
(675, 'nancy drew alibi in ashes', '2011', 0, 0, 42, 7, 0, 5.19, 'Escape the Smoky Intrigue of a Hometown Inferno!', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® XP/Vista/7<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 1.5 GHZ or greater Pentium 4 or equivalent class CPU <br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 512MB of RAM<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 64 MB DirectX 9.0 compatible video card <br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 9.0<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 2 GB or more hard drive space<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> 16 bit DirectX compatible sound card<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0,03', '0', '0', '0', '0,03'),
(676, 'men of war', '2009', 0, 0, 1664, 257, 0, 3.99, 'Men of War is a stunning Real-Time Strategy game that takes place during the height of World War II. Intense battles span Europe and North Africa as gamers play as Soviet, Allied or German forces across 19 massive single-player missions.', '{\'minimum\': \'Minimum<br> <ul class=\"bb_ul\"><li><strong>Operating System: </strong>Microsoft® Windows® XP SP3 / Windows Vista SP1 — This product does not support Windows 95/98/ME/2000/NT or XP x64/Vista x64!<br> </li><li><strong>Processor: </strong>Intel® Pentium 4 3.0 GHz or AMD™ Athlon™ 64 3000+<br> </li><li><strong>Memory: </strong>XP – 1 GB RAM / Vista – 2 GB RAM<br> </li><li><strong>Hard Disk Space: </strong>6.5 GB + 1 GB Swap File<br> </li><li><strong>Video Card: </strong>3D Hardware Accelerator Card Required – 100% DirectX 9.0c compatible 128 MB Video Memory. ATI® Radeon® 9600 or Nvidia® GeForce® 5900<br> </li><li><strong>Sound Card: </strong>DirectX® 9.0c compatible sound card<br> </li><li><strong>DirectX® Version: </strong>DirectX® 9.0c<br> </li><li><strong>Network: </strong><br> <br>Internet(TCP/IP) or LAN play supported<br> <br>Internet play requires broadband connection and latest drivers<br> <br>LAN play requires network interface card with latest drivers<br> <br> </li></ul>\', \'recommended\': \'Recommended<br> <ul class=\"bb_ul\"><li><strong>Operating System: </strong>Microsoft® Windows® XP SP3 / Windows Vista SP1 — This product does not support Windows 95/98/ME/2000/NT or XP x64/Vista x64!<br> </li><li><strong>Processor: </strong>Intel® Core 2 Duo 2.33 GHz or AMD® Athlon® 4400+<br> </li><li><strong>Memory: </strong>2 GB RAM<br> </li><li><strong>Hard Disk Space: </strong>5.5 GB + 1 GB Swap File<br> </li><li><strong>Video Card: </strong>256 MB 3D Hardware Accelerator Card with Shader 3.0 support ** - ATI® Radeon® 2600 or Nvidia® GeForce® 8600<br> </li><li><strong>Sound Card: </strong>DirectX® 9.0c compatible sound card<br> </li><li><strong>DirectX® Version: </strong>DirectX® 9.0c<br> </li><li><strong>Network: </strong><br> <br>Internet(TCP/IP) or LAN play supported<br> <br>Internet play requires broadband connection and latest drivers<br> <br>LAN play requires network interface card with latest drivers<br> <br> </li></ul>** NOTICE: Some 3D accelerator cards with the chipset listed here may not be compatible with the 3D acceleration features utilized by Men of War. Please refer to your hardware manufacturer for 100% DirectX compatibility.<br> <br> Supported Chipsets: ATI Radeon 9600<br> , ATI Radeon 9700<br> , ATI Radeon X300<br> , ATI Radeon X600<br> , ATI Radeon X700<br> , ATI Radeon X800<br> , ATI Radeon X850<br> , ATI Radeon X1050<br> , ATI Radeon X1300<br> , ATI Radeon X1600<br> , ATI Radeon X1900<br> , ATI RADEON HD 2400<br> , ATI RADEON HD 2600<br> , ATI RADEON HD 2900<br> , ATI RADEON HD 3450<br> , ATI RADEON HD 3850<br> , ATI RADEON HD 3870<br> , ATI RADEON HD 4850<br> , NVIDIA GEFORCE 5900<br> , NVIDIA GEFORCE 6600<br> , NVIDIA GEFORCE 6800<br> , NVIDIA GEFORCE 7300<br> , NVIDIA GEFORCE 7600<br> , NVIDIA GEFORCE 7800<br> , NVIDIA GEFORCE 8400<br> , NVIDIA GEFORCE 8500<br> , NVIDIA GEFORCE 8600<br> , NVIDIA GEFORCE 8800<br> , NVIDIA GEFORCE 9600<br> , NVIDIA GEFORCE 260<br> , MOBILE CHIPSETS:<br> <br> Supported Mobile Chipsets: NVIDIA GEFORCE GO 7900<br> , NVIDIA GEFORCE GO 7950<br> and NVIDIA GEFORCE GO 8400\'}', '0,01', '0,02', '0', '0,01', '0,03'),
(677, 'captain morgane and the golden turtle', '2014', 0, 0, 83, 53, 0, 3.99, 'A place where pirates roamed the seas looking for treasure, and where one innocent 8 year old girl grew up to become the most famous Pirate of the Caribbean! From an early age, Morgane Castillo was a confident and feisty girl, playing with her friends and getting into scraps on Bounty Island.', '{\'minimum\': \'<strong>Минимальные:</strong><br><ul class=\"bb_ul\"><li><strong>ОС:</strong> Windows XP/Vista/Seven<br></li><li><strong>Процессор:</strong> Pentium 1.6 GHz<br></li><li><strong>Оперативная память:</strong> 512 MB ОЗУ<br></li><li><strong>Видеокарта:</strong> 64 MB Graphic Card DirectX 9-compatible<br></li><li><strong>DirectX:</strong> Версии 9.0<br></li><li><strong>Место на диске:</strong> 3 GB<br></li><li><strong>Звуковая карта:</strong> sound card DirectX 9-compatible<br></li><li><strong>Дополнительно:</strong> A mouse and a keyboard are required</li></ul>\', \'recommended\': \'<strong>Рекомендованные:</strong><br><ul class=\"bb_ul\"><li><strong>ОС:</strong> Windows XP/Vista/Seven<br></li><li><strong>Процессор:</strong> Pentium 2 GHz<br></li><li><strong>Оперативная память:</strong> 1024 MB ОЗУ<br></li><li><strong>Видеокарта:</strong> 128 MB Graphic Card DirectX 9-compatible<br></li><li><strong>DirectX:</strong> Версии 9.0<br></li><li><strong>Место на диске:</strong> 3 MB<br></li><li><strong>Звуковая карта:</strong> sound card DirectX 9-compatible<br></li><li><strong>Дополнительно:</strong> A mouse and a keyboard are required</li></ul>\'}', '0', '0,08', '0', '0,01', '0,1'),
(678, 'the inner world', '2013', 0, 23, 570, 51, 0, 11.99, 'The Inner World – A 2D-Point’n’Click Adventure Together with the help of the mysterious thief Laura, his best intentions and no clue whatsoever, Robert sets off on his adventure to discover the secret of the wind\'s disappearance. Will the young adventurer be able to save his world?', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Microsoft® Windows® XP, Windows Server 2008, Windows Vista® Home Premium, Business, Ultimate, or Enterprise (including 64 bit editions) with Service Pack 2, Windows 7, or Windows 8 Classic<br></li><li><strong>Processor:</strong> 2.33GHz or faster x86-compatible processor, or Intel Atom™ 1.6GHz or faster processor for netbook class devices<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Storage:</strong> 1400 MB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Microsoft® Windows® XP, Windows Server 2008, Windows Vista® Home Premium, Business, Ultimate, or Enterprise (including 64 bit editions) with Service Pack 2, Windows 7, or Windows 8 Classic<br></li><li><strong>Processor:</strong> 2.33GHz or faster x86-compatible processor, or Intel Atom™ 1.6GHz or faster processor for netbook class devices<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Storage:</strong> 1400 MB available space</li></ul>\'}', '0', '0,03', '0', '0', '0,03'),
(679, 'alter ego', '2010', 0, 0, 139, 59, 12, 7.19, 'When a series of gruesome murders shake a small town after a strange aristocrat dies and his body goes missing, rumors of a supernatural monster abound. In life Sir William was known to be a cruel and evil man, rumored to be the murderer behind many unsolved crimes.', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7/Vista/XP SP 2<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 2.5 GHz Single Core<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1 GB RAM<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 128 MB 3D Video Card (Geforce 6600/Radeon 9600 or better)<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 9.0c or higher<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 3 GB free hard drive space<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX sound card<br>\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0', '0,03', '0', '0,01', '0,03'),
(680, 'alter ego', '2010', 0, 0, 139, 59, 12, 7.19, 'When a series of gruesome murders shake a small town after a strange aristocrat dies and his body goes missing, rumors of a supernatural monster abound. In life Sir William was known to be a cruel and evil man, rumored to be the murderer behind many unsolved crimes.', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7/Vista/XP SP 2<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 2.5 GHz Single Core<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1 GB RAM<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 128 MB 3D Video Card (Geforce 6600/Radeon 9600 or better)<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 9.0c or higher<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 3 GB free hard drive space<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX sound card<br>\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0', '0,03', '0', '0,01', '0,03'),
(681, 'hearts of iron iv', '2016', 0, 92, 34711, 5251, 9413, 34.99, 'Victory is at your fingertips! Your ability to lead your nation is your supreme weapon, the strategy game Hearts of Iron IV lets you take command of any nation in World War II; the most engaging conflict in world history.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 64-bit or newer<br></li><li><strong>Processor:</strong> Intel Core 2 Quad Q9400 @ 2.66 GHz / AMD Athlon II X4 650 @ 3.20 GHz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> ATI Radeon HD 5850 or NVIDIA GeForce GTX470 with 1GB VRAM<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 2 GB available space<br></li><li><strong>Sound Card:</strong> Direct X- compatible soundcard.<br></li><li><strong>Additional Notes:</strong> Mouse and keyboard are required. / Latest available WHQL drivers from both manufacturers/ Internet Connection or LAN for multiplayer, Up to 32 other players in multiplayer mode.</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 64-bit or newer<br></li><li><strong>Processor:</strong> Intel Core i5 750 @ 2.66 GHz / AMD Phenom II X4 955 @ 3.20 GHz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> ATI Radeon HD 6950 or NVIDIA GeForce GTX570 with 2GB VRAM<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 2 GB available space<br></li><li><strong>Sound Card:</strong> Direct X- compatible soundcard.<br></li><li><strong>Additional Notes:</strong> Mouse and keyboard are required. / Latest available WHQL drivers from both manufacturers. / Internet Connection or LAN for multiplayer, Up to 32 other players in multiplayer mode.</li></ul>\'}', '0', '0,03', '0', '0', '0,03'),
(682, 'take on helicopters', '2011', 0, 0, 340, 260, 2, 11.99, 'The brand new helicopter game from independent developers Bohemia Interactive – creators of the award-winning military-Sim series Arma 2. Built upon over 10 years of experience in cutting-edge simulator development, Take On Helicopters immerses players within beautifully rich landscapes and an authentic flight model.', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong>Windows XP<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong>Intel Dual-Core 2.4 GHz or AMD Dual-Core Athlon 2.5 GHz or faster<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong>2 GB RAM<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong>NVIDIA GeForce 8800GT or ATI Radeon 4850 with Shader Model 3 and 512 MB VRAM or faster<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong>dx90c<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong>20 GB HD space<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong>DirectX 9.0c compatible audio-card<br>\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br>\\t\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong>Windows Vista, Windows 7<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong>Intel Dual-Core 3GHz or AMD Dual-Core Athlon 3GHz or faster<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong>4 GB RAM<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong>NVIDIA GeForce 9800GT or ATI Radeon 5850 with Shader Model 3 and 1024 MB VRAM or faster<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong>dx90c<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong>20 GB HD space<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong>DirectX 9.0c compatible audio-card<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Other Requirements:</strong>Broadband Internet connection<br>\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0', '0,02', '0', '0,01', '0,03'),
(683, 'knights of honor', '2009', 0, 0, 1018, 89, 35, 7.49, 'As King, it is your duty to lead your people in their struggle to raise your kingdom from its humble beginnings to a position of power and prestige. War, diplomacy and a burgeoning economy are the means by which you increase your power and expand your influence.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® XP, Windows® 2000 <br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 1 GHz Intel® Pentium® III or AMD® Athlon™ processor <br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 256 MB RAM <br>\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 16 MB video card with 1024x768 resolution <br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 1.2 GB free hard disk space plus space for saved games <br>\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX 9.x compatible sound card </li></ul>\'}', '0', '0,02', '0', '0,01', '0,03'),
(684, 'codename panzers cold war', '2009', 0, 0, 82, 56, 0, 13.99, 'Tempelhof, Berlin, dawn of 8th April 1949.A major armed conflict is brewing between the Western powers and the Soviet bloc. The Red Army has been growing ever stronger since the end of World War II. With the growth of their army the Soviets realize that they hold the advantage, and are only waiting for the right moment to attack.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>Operating System: </strong>Microsoft® Windows® XP SP2/Vista®<br>\\t\\t\\t\\t\\t</li><li><strong>Processor: </strong>Intel® Core™2 Duo 1.8 GHz or AMD Athlon™ X2 +4400 or faster<br>\\t\\t\\t\\t\\t</li><li><strong>Memory: </strong>XP 1 GB RAM - Vista 2GB RAM<br>\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space: </strong>5GB Available<br>\\t\\t\\t\\t\\t</li><li><strong>Video Card: </strong>ATI Radeon X800 or NVIDIA GeForce 6800 or faster<br>\\t\\t\\t\\t\\t</li><li><strong>Sound Card: </strong>DirectX 9.0c-compatible sound card<br> \\t\\t\\t</li><li><strong>DirectX® Version: </strong>9.0c compatible, 32 bits, multi-core<br> \\t\\t</li></ul>\'}', '0', '0,02', '0', '0,01', '0,03'),
(685, 'motorhead', '2015', 0, 0, 4, 17, 0, 3.99, 'The future of racing is here, and it\'s called MOTORHEAD. This game allows you to hop in one of 10 streamlined racers and test your skills on eight obstacle-filled courses that wind through urban, desert, and seaside terrain.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP or newer<br></li><li><strong>Graphics:</strong> Dedicated Video Graphics<br></li><li><strong>Storage:</strong> 600 MB available space</li></ul>\'}', '0,02', '0,01', '0', '0', '0,03'),
(686, 'shantae and the pirates curse', '2015', 0, 44, 1477, 99, 434, 14.99, 'Embark on an all-new adventure with Shantae, the hair-whipping belly dancing genie. After losing her magic, Shantae teams up with the nefarious pirate Risky Boots in order to save Sequin Land from a curse.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows®Vista™ or Windows®7<br></li><li><strong>Processor:</strong> Intel™ Pentium 4 2.4 ghz with Hyper Threading<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> Intel® HD Graphics<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 1 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows®7 or Windows®8<br></li><li><strong>Processor:</strong> Intel™ Core 2 Duo / AMD™ Athlon 64 X2 or higher<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA® GeForce™ 200 series or higher, AMD® Radeon™ HD5000 series or higher (it must be able to manage Pixel Shader 3.0) with at least 512MB of display memory.<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 2 GB available space</li></ul>\'}', '0', '0', '0,03', '0', '0,03'),
(687, 'braid', '2009', 0, 12, 6529, 386, 178, 10.99, 'Braid is a puzzle-platformer, drawn in a painterly style, where you can manipulate the flow of time in strange and unusual ways. From a house in the city, journey to a series of worlds and solve puzzles to rescue an abducted princess.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>Operating System: </strong>Microsoft® Windows® XP / Vista / 7 <br>\\t\\t\\t\\t\\t</li><li><strong>Processor: </strong>1.4GHz or faster <br>\\t\\t\\t\\t\\t</li><li><strong>Memory: </strong>768 MB or more <br>\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space: </strong>200 MB or more <br>\\t\\t\\t\\t\\t</li><li><strong>Video Card: </strong>Pixel Shader 2.0 <br>\\t\\t\\t\\t\\t</li><li><strong>DirectX® Version: </strong>DirectX® 9.0c <br>\\t\\t\\t\\t\\t</li><li><strong>Controller Support: </strong>Microsoft Xbox 360 Controller for Windows </li></ul>\'}', '0', '0,02', '0', '0,01', '0,03'),
(688, 'commander conquest of the americas', '2010', 0, 51, 60, 74, 0, 7.99, 'Combining elements from both trading and strategy games, Commander: Conquest of the Americas will appeal to a wide range of players. Players take charge of one of the many European powers aiming to conquer the New World.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 / Vista / XP<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 2.0 GHz Core Duo or equivalent<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2 GB RAM<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space:</strong> 4 GB<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Video Card:</strong> 256 MB of dedicated memory with support for pixel shader 3.0. NVIDIA 7800 or equivalent<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound Card:</strong> DirectX9 compatible<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Controller Support:</strong> 3-button mouse, keyboard and speakers<br>\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0', '0,02', '0', '0,01', '0,03'),
(689, 'worms', '2011', 0, 0, 319, 53, 2, 4.99, 'Throw a grenade down memory lane with the original and classic turn-based strategy game Worms™! Up to 4 teams of worms do battle over an ever-changing battlefield with falling weapon crates, crazed exploding sheep and more besides. Winner of many industry awards, find out what all the fuss was about.', '{\'minimum\': \'<strong>Minimum:</strong> A 100% Windows XP/Vista/7 compatible computer system\'}', '0', '0,04', '0', '0,01', '0,05'),
(690, 'jack keane', '2008', 0, 0, 46, 27, 0, 6.99, 'Colonial England. Under a certain amount of duress... Jack takes on a job, which will not only cause him a great deal of trouble, but also bring to light the answer to a mystery out of his distant past. A lack of money leads Jack to accept a charter to take a British secret agent to mysterious \'Tooth Island\'.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Microsoft Windows XP, Windows Vista<br></li><li><strong>Processor:</strong> Pentium IV 2 GHz / Athlon 2.4 GHz<br></li><li><strong>Memory:</strong> 512 MB RAM <br></li><li><strong>Graphics:</strong> DirectX 9.0c-compatible graphic card with 128 MB RAM (MX series and XGI Volari are not supported)<br></li><li><strong>Hard Drive:</strong> 1.5 GB hard-disk capacity <br></li><li><strong>Input Devices: </strong> DirectX 9.0c-compatible keyboard and mouse</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Microsoft Windows XP, Windows Vista <br></li><li><strong>Processor:</strong> Intel-/AMD-CPU with 3.0 GHz<br></li><li><strong>Memory:</strong> 1 GB RAM <br></li><li><strong>Graphics:</strong> DirectX 9.0c-compatible graphic card with 256 MB RAM <br></li><li><strong>Hard Drive:</strong> 1.5 GB hard-disk capacity<br></li><li><strong>Input Devices: </strong> DirectX 9.0c-compatible keyboard and mouse</li></ul>\'}', '0', '0,02', '0', '0', '0,03'),
(691, 'stellaris', '2016', 0, 95, 35327, 10036, 2729, 34.99, 'Explore a vast galaxy full of wonder! Paradox Development Studio, makers of the Crusader Kings and Europa Universalis series presents Stellaris, an evolution of the grand strategy genre with space exploration at its core.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® 7 SP1 64 Bit<br></li><li><strong>Processor:</strong> Intel® iCore™ i3-530 or AMD® FX-6350<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> Nvidia® GeForce™ GTX 460 or AMD® ATI Radeon™ HD 5870 (1GB VRAM), or AMD® Radeon™ RX Vega 11 or Intel® HD Graphics 4600<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 10 GB available space<br></li><li><strong>Sound Card:</strong> Direct X 9.0c- compatible sound card<br></li><li><strong>Additional Notes:</strong> Controller support: 3-button mouse, keyboard and speakers. Special multiplayer requirements: Internet Connection</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® 10 Home 64 Bit<br></li><li><strong>Processor:</strong> Intel® iCore™ i5-3570K or AMD® Ryzen™ 5 2400G<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> Nvidia® GeForce™ GTX 560 Ti (1GB VRAM)<br></li><li><strong>DirectX:</strong> Version 12<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 10 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c-compatible sound card<br></li><li><strong>Additional Notes:</strong> Controller support: 3-button mouse, keyboard and speakers. Special multiplayer requirements: Internet Connection</li></ul>\'}', '0', '0,03', '0', '0', '0,03'),
(692, 'syberia ii', '2011', 0, 0, 862, 156, 227, 9.99, 'Having searched Eastern and Western Europe for a missing heir, Kate Walker finally completed her long and arduous journey, obtaining the signature of Hans Voralberg and closing the automaton factory buyout. Mission accomplished?', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP/Vista/7/10<br>\\t\\t\\t\\t</li><li><strong>Processor:</strong> 1.5GHz CPU <br>\\t\\t\\t\\t</li><li><strong>Memory:</strong> 512MB<br>\\t\\t\\t\\t</li><li><strong>Hard Disk Space:</strong> 1.5GB<br>\\t\\t\\t\\t</li><li><strong>Video Card:</strong> DirectX compatible graphics card with 128 MB memory<br>\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 9.0c<br>\\t\\t\\t\\t</li><li><strong>Sound:</strong> Sound card with DirectX 9.0c support\\t<br>\\t\\t\\t</li></ul><ul class=\"bb_ul\"><li></li></ul>\'}', '0,02', '0,02', '0', '0', '0,05'),
(693, 'botanicula', '2012', 0, 53, 3524, 136, 16, 7.99, 'Humor-filled indie adventure game created by the makers of Machinarium and Samorost.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong>Microsoft® Windows® XP/Vista/7/8/10<br>\\t</li><li><strong>Processor:</strong>1.6 Ghz Processor<br>\\t</li><li><strong>Memory:</strong>1 GB RAM<br>\\t</li><li><strong>DirectX®:</strong>5.0<br>\\t</li><li><strong>Hard Drive:</strong>700 MB HD space</li></ul>\'}', '0', '0,02', '0', '0', '0,03'),
(694, 'cossacks european wars', '2011', 0, 0, 170, 66, 1, 3.99, 'This game is devoted to the key events of the XVII–XVIII centuries.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>Operating system:</strong>Windows® XP / Vista™ / Windows® 7 <br>\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 1.4 GHz CPU<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 512 MB <br>\\t\\t\\t\\t\\t\\t</li><li><strong>Hard disk space:</strong> 350MB <br>\\t\\t\\t\\t\\t\\t</li><li><strong>Video:</strong>Video Card with 64MB dedicated memory and DirectX 9 Compatible<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong>Sound card with DirectX 9.0 support<br>\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong>9.0 or higher<br>\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0', '0,02', '0', '0', '0,03'),
(695, 'magicka', '2011', 0, 88, 20912, 1964, 589, 7.99, 'Magicka is a satirical action-adventure game set in a rich fantasy world based on Norse mythology. The player assumes the role of a wizard from a sacred order tasked with stopping an evil sorcerer who has thrown the world into turmoil, his foul creations besieging the forces of good.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP/Vista/7 (32- or 64-bit)<br>\\t</li><li><strong>Processor:</strong> Intel® Pentium® IV 2.4 GHz or AMD 3500+<br>\\t</li><li><strong>Memory:</strong> 2 GB RAM<br>\\t</li><li><strong>Hard Disk Space:</strong> 2 GB Available Space<br>\\t</li><li><strong>Video Card:</strong> NVIDIA® GeForce 8800 or ATI Radeon® X1900 (Integrated Video Cards not recommended)<br>\\t</li><li><strong>DirectX®:</strong> DirectX 9<br>\\t</li><li><strong>Sound:</strong> DirectX-compatible sound card<br>\\t</li><li><strong>Additional:</strong> 3-button mouse, keyboard and speakers. DSL Internet connection for multiplayer. .NET 3.5 required</li></ul>\'}', '0', '0,02', '0', '0,01', '0,03'),
(696, 'x3 terran conflict', '2008', 0, 33, 1633, 272, 972, 15.99, 'It is the year 2938. The long wished-for encounter of the X Universe and the Earth holds both joy and sorrow for the people. Despite flourishing trade, the clash of the diverse races, cultures and life forms creates new tensions, mistrust and open conflict that need to be overcome!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 10 / 8 / 7 / Vista SP1 / XP SP2<br></li><li><strong>Processor:</strong> Pentium® IV or AMD® equivalent at 2.0 GHz<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> 256 MB 3D DirectX 9 Compatible video card (not onboard) with Pixel Shader 1.1 support<br></li><li><strong>Hard Drive:</strong> 10GB of free space<br></li><li><strong>Sound:</strong> Soundcard (Surround Sound support recommended)</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 10 / 8 / 7 / Vista SP1<br></li><li><strong>Processor:</strong> Intel® Core™ 2 Duo or AMD® equivalent at 2.0 GHz<br></li><li><strong>Memory:</strong> 3 GB RAM<br></li><li><strong>Graphics:</strong> 256 MB 3D DirectX 9 Compatible video card (not onboard) with Pixel Shader 3.0 support<br></li><li><strong>Hard Drive:</strong> 10GB of free space<br></li><li><strong>Sound:</strong> Soundcard (Surround Sound support recommended)</li></ul>\'}', '0', '0,02', '0', '0,01', '0,03'),
(697, 'rollercoaster tycoon 2 triple thrill pack', '2014', 0, 0, 2086, 336, 200, 6.99, 'This compilation includes the entire RollerCoaster Tycoon 2 series, with the original game as well as the Time Twister and Wacky Worlds expansions.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP or Windows Vista<br></li><li><strong>Processor:</strong> 1.8 GHz Processor<br></li><li><strong>Memory:</strong> 512 MB RAM<br></li><li><strong>Graphics:</strong> 3D graphics card compatible with DirectX 7<br></li><li><strong>DirectX:</strong> Version 7.0<br></li><li><strong>Storage:</strong> 2 GB available space</li></ul>\'}', '0', '0,02', '0', '0,01', '0,03'),
(698, 'xblaze lost memories', '2016', 0, 40, 12, 2, 0, 14.99, 'XBlaze Lost: Memories is a visual-novel game based in the BlazBlue universe and the sequel to XBlaze Code: Embryo!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 / 8 / 8.1<br></li><li><strong>Processor:</strong> Intel Core2 Duo<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> nVidia GeForce 7900 GT or better / AMD Radeon X1900 / nVidia GeForce GT 620 (Windows 8.1)<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 7 GB available space<br></li><li><strong>Sound Card:</strong> Direct Sound<br></li><li><strong>Additional Notes:</strong> Compatibility with Xbox 360 Controller</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 / 8 / 8.1<br></li><li><strong>Processor:</strong> Intel Core i5 / i7<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> nVidia GeForce 8800 GT or better / AMD Radeon HD3700 / nVidia GeForce GT 650 (Windows 8.1)<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 7 GB available space<br></li><li><strong>Sound Card:</strong> Direct Sound<br></li><li><strong>Additional Notes:</strong> Compatibility with Xbox 360 Controller</li></ul>\'}', '0,03', '0', '0', '0,01', '0,05'),
(699, 'lets sing 2016', '2016', 0, 37, 24, 20, 0, 18.99, 'Let\'s Sing 2016 brings a brand new generation of karaoke to your PC!Whether you\'re an experienced vocalist or a bathroom crooner, grab a mic and give it all you\'ve got with the 35 available hits, including Bruno Mars, Meghan Trainor, Calvin Harris, Sam Smith, Avicii, Maroon 5, John Legend...', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® 7<br></li><li><strong>Processor:</strong> AMD Phenom™ II X4 840 Processor 3.2 GHz AM3<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVidia GeForce GT 520 1GB<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 5 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® 7<br></li><li><strong>Processor:</strong> Intel® Core™ i5-2500 CPU @ 3.30GHz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVidia GeForce GTX 550Ti 1,5GB / ATI Radeon HD 6570 1GB<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 5 GB available space</li></ul>\'}', '0,02', '0', '0', '0,01', '0,03'),
(700, 'dungeon siege ii', '2005', 0, 0, 813, 343, 754, 4.99, 'It’s been a generation since you vanquished the evil that plagued the Land of Ehb, and now…a new menace has awakened. In Dungeon Siege II, the sequel to the best-selling RPG from Gas Powered Games, you will be called on to again wield sword and spell to save the world from a growing abomination many years in the making.', '{\'minimum\': \'<strong>Minimum</strong><br>\\t\\t\\t\\t\\t\\t\\t\\t\\t <ul class=\"bb_ul\"><li><strong>OS:</strong> Microsoft® Windows® XP SP1 or newer<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 1.0 GHz equivalent or higher processor<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 256 MB of system RAM<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> ATI Radeon™ series 7000 or better/Nvidia® Geforce series/Intel Extreme Graphics 82845, 82865, 82915<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 4 GB available hard disk space<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0', '0,02', '0', '0', '0,03'),
(701, 'judge dredd dredd vs death', '2009', 0, 0, 559, 79, 8, 5.59, 'Welcome to Mega-City One, a city of over 400 million people - every one of them a potential criminal. It is the third decade of the 22nd Century, unemployment is widespread, boredom is universal and only the Judges can prevent total anarchy. Empowered to dispense instant justice, they are Judge, Jury and Executioner all in one.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>Supported OS: </strong> Microsoft® Windows® XP/Vista<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Processor: </strong> Intel Pentium III or AMD Athlon 700MHz computer or equivalent<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics: </strong> 32MB graphics card that supports Transform and Lighting (GeForce 1, ATI Radeon 7500 or better)<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Sound: </strong> Windows compatible sound card <br>\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX Version: </strong>DirectX 9.0<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Memory: </strong> 128 MB RAM\\t\\t\\t<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive: </strong> 1.5 GB free hard disk space</li></ul>\'}', '0,02', '0,01', '0', '0', '0,05'),
(702, 'psychopass mandatory happiness', '2017', 0, 36, 39, 4, 0, 24.99, 'In a world where psychological states can be quantified, every choice has consequences, victims can become criminals, and the very nature of truth can warp and shift. Can detectives Nadeshiko Kugatachi and Takuma Tsurugi remain on the path of justice as they face the ugly truths of humanity?', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7/8.1/10<br></li><li><strong>Processor:</strong> Core i3 (Haswell)<br></li><li><strong>Memory:</strong> 3 GB RAM<br></li><li><strong>Graphics:</strong> VRAM 2GB (or Intel HD Graphics 4000)<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 3 GB available space<br></li><li><strong>Sound Card:</strong> DirectSound<br></li><li><strong>Additional Notes:</strong> Runs best on Skylake or better processors</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7/8.1/10<br></li><li><strong>Processor:</strong> Core i3 (Skylake)<br></li><li><strong>Memory:</strong> 3 GB RAM<br></li><li><strong>Graphics:</strong> VRAM 2GB (or Intel HD Graphics 4000)<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 3 GB available space<br></li><li><strong>Sound Card:</strong> DirectSound</li></ul>\'}', '0,02', '0,01', '0,01', '0', '0,05'),
(703, 'ghost pirates of vooju island', '2015', 0, 0, 27, 23, 94, 6.99, 'Mysterious Things are Happening on Vooju Island...', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® XP, Windows Vista®, Windows® 7, and Windows® 8<br></li><li><strong>Processor:</strong> 2.0 GHz Processor or faster<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> DirectX® 9.0 compatible or higher video card with 512MB of Video RAM<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 3 GB available space<br></li><li><strong>Sound Card:</strong> DirectX® compatible sound card</li></ul>\'}', '0', '0,02', '0', '0', '0,02'),
(704, 'tropico reloaded', '2009', 0, 0, 412, 60, 0, 5.99, 'TROPICO RELOADED is the ultimate game compilation for hobby-dictators and those dreaming of their own Caribbean island. Tropico combines real-time strategy and simulation elements with a healthy dose of political intrigue and Caribbean flair to create a unique and critically acclaimed game experience.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP, Windows Vista, Windows 7<br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 1.6 GHz<br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 256 MB<br>\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 128 MB DirectX® 9 graphics card<br>\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 9<br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 3 GB <br>\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX-compatible<br>\\t\\t\\t\\t\\t</li></ul>\'}', '0', '0,02', '0', '0', '0,02'),
(705, 'cold war', '2014', 0, 0, 117, 68, 0, 4.49, 'Steal weapons. Improvise gadgets. Evade capture. Uncover the conspiracy.The Story:On the run and fighting for your life, you are freelance journalist Matt Carter. Twelve hours after arriving in Moscow for a routine story, you\'ve been stripped of all possessions, beaten unconscious and thrown into the KGB\'s political prison.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 98/ME/2000/XP/7/8 (x86 and x64)<br></li><li><strong>Processor:</strong> 1.7 GHz CPU Processor<br></li><li><strong>Memory:</strong> 384 MB RAM<br></li><li><strong>Graphics:</strong> DirectX 9.0 compatible, NVIDIA GeForce 3 (NOT GeForce 4MX) / ATI Radeon 8500 or better with 64 MB Video memory card<br></li><li><strong>DirectX:</strong> Version 9.0<br></li><li><strong>Storage:</strong> 1 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c or better compatible sound card</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 98/ME/2000/XP/7/8 (x86 and x64)<br></li><li><strong>Processor:</strong> 2 GHz CPU Processor<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> DirectX 9.0 compatible with 256 MB VRAM (GeForce 4Ti or higher)<br></li><li><strong>DirectX:</strong> Version 9.0<br></li><li><strong>Storage:</strong> 1 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c or better compatible sound card</li></ul>\'}', '0,02', '0,01', '0', '0', '0,02'),
(706, 'bus simulator 16', '2016', 0, 30, 1415, 889, 273, 13.49, 'Get behind the wheel of 13 realistic city buses licensed by known city bus manufacturers such as Mercedes-Benz and MAN. Keep an eye on the traffic code and drive your passengers safely to their destinations through five characteristic city districts.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7/8/10 64 bit<br></li><li><strong>Processor:</strong> Intel Core i3 with 3.3 GHz / AMD Phenom II X4 96OT with 3.0 GHz or comparable processor<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> GeForce GTX 470 (1 GB VRAM) or comparable graphics card<br></li><li><strong>DirectX:</strong> Version 9.0<br></li><li><strong>Storage:</strong> 5 GB available space<br></li><li><strong>Additional Notes:</strong> List of unsupported graphic chips (excerpt): Intel HD 3000 / 4400 / 5500 / 6100; GeForce GT 240 / 630 / 730; GeForce GT 540M / 640M / 740M / 840M / 940M; Radeon R7 240; Radeon R9 M275; Intel Iris 6100</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7/8/10 64 bit<br></li><li><strong>Processor:</strong> Intel Core i5 with 3.40 GHz / AMD FX-8320E with 3.2 GHz or comparable processor<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> GeForce GTX 660 (2 GB VRAM) or comparable graphics card<br></li><li><strong>DirectX:</strong> Version 9.0<br></li><li><strong>Storage:</strong> 5 GB available space</li></ul>\'}', '0', '0,02', '0', '0', '0,02');
INSERT INTO `jeux` (`id_jeu`, `nom_jeu`, `annee`, `age_requis`, `nb_succes`, `nb_avis_pos`, `nb_avis_neg`, `temps_jeu_moyen`, `prix`, `description`, `configuration`, `ventes_AN`, `ventes_EU`, `ventes_JP`, `ventes_Autre`, `ventes_Global`) VALUES
(707, 'omega quintet', '2017', 0, 55, 80, 21, 0, 23.79, 'Humanity is in peril! A deadly phenomenon known as Blare threatens to consume all life on earth and is eating away at the minds of humans worldwide. No conventional forces can stop the Blare and it has rapidly spread worldwide. But in one city, a small population holds out against this deadly threat...', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 (64-bit)<br></li><li><strong>Processor:</strong> Intel Core 2 Quad 2.4GHz or comparable<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 650 or comparable<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 9 GB available space<br></li><li><strong>Sound Card:</strong> Windows compatible sound card</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 10<br></li><li><strong>Processor:</strong> Intel i5 3.3 GHz or comparable<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 960 or comparable<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 9 GB available space<br></li><li><strong>Sound Card:</strong> Windows compatible sound card</li></ul>\'}', '0', '0', '0,02', '0', '0,02'),
(708, 'demigod', '2011', 0, 0, 564, 212, 149, 7.19, 'Set in a magical world where gods walk among mortals, Demigod blends action, strategy and role-playing elements into a thrilling new experience.', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong>Windows 10 / 8 / 7 / Vista SP1 / XP SP3<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong>2.4 GHz Processor<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong>512 MB RAM<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong>128 MB DirectX 9.0c 3D Video Card<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong>dx90c<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong>8 GB HD space<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong>DirectX 9.0c Compatible<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Other Requirements:</strong>Broadband Internet connection, also to activate this game you must create a Stardock account while launching the game on Steam.<br>\\t\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br>\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong>Windows 10 / 8 / 7 / Vista SP1 / XP SP3<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong>3 GHz Processor<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong>1 GB RAM<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong>256 MB DirectX 9.0c 3D Video Card<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong>dx90c<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong>8 GB HD space<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong>DirectX 9.0c Compatible<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Other Requirements:</strong>Broadband Internet connection<br>\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0', '0,02', '0', '0', '0,02'),
(709, 'star trek online', '2012', 0, 0, 7639, 2391, 2514, 0.00, 'In Star Trek Online, the Star Trek universe appears for the first time on a truly massive scale. Players take the captain\'s chair as they command their own starship and crew. Explore strange new worlds, seek out new life and new civilizations, and boldly go where no one has gone before.', '{\'minimum\': \'<strong>Minimum</strong><br><strong>OS:</strong> Windows® Vista, 7, 8 or 10<br><strong>Processor:</strong> Core 2 Duo 1.8Ghz (or equivalent AMD CPU)<br><strong>Memory:</strong> 2GB RAM<br><strong>Graphics:</strong> NVidia GeForce 6600, ATI/AMD Radeon X1300, or Intel G965 Express (Direct3D Hardware Feature Level 10)<br><strong>DirectX:</strong> Version 10<br><strong>Network: </strong>Broadband Internet Connection<br><strong>Storage:</strong> 21GB<br><strong>Audio: </strong>DirectX 10 compatible sound chip or onboard audio capability with the latest sound drivers\', \'recommended\': \'<strong>Recommended</strong><br><strong>OS:</strong> Windows® 10<br><strong>Processor:</strong> Core i5-2xxx Quad Core or better<br><strong>Memory:</strong> 4GB RAM or better<br><strong>Graphics: </strong>NVidia GeForce GTX 4xx, ATI/AMD Radeon HD 5xxx, or Intel HD Graphics 4xxx (Direct3D Hardware Feature Level 11.0) or better<br><strong>DirectX:</strong> Version 11.0 or better<br><strong>Network:</strong> Broadband Internet Connection<br><strong>Storage:</strong> 21GB<br><strong>Audio:</strong> DirectX 10 compatible sound chip or onboard audio capability with the latest sound drivers\'}', '0', '0,02', '0', '0', '0,02'),
(710, 'europa universalis iii complete', '2009', 0, 0, 1191, 245, 736, 9.99, 'Europa Universalis III Complete includes the original Europa Universalis III as well as the expansions In Nomine and Napoleons Ambition Europa Universalis III delves deeply into the areas of exploration, trade, warfare and diplomacy.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® 2000 (with Service pack 1 or higher) or Windows® XP (Home/Professional/Media Edition) with Service Pack 2, or later Windows versions. <br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 1.9GHz Intel Pentium 4 or AMD Athlon processor or equivalent<br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 512MB RAM (1.0GB RAM is highly recommended) <br>\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 128MB Video Card with Hardware T&amp;L and support for Pixelshader 2.0 or better <br>\\t\\t\\t\\t\\t</li><li><strong>DirectX Version:</strong> DirectX9.0c <br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> At least 1GB of free hard drive space to accommodate game files and saved games. This does not include any space used by the Windows® swap file. <br>\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX7 compatible sound card </li></ul>\'}', '0', '0,02', '0', '0', '0,02'),
(711, 'tokyo xanadu ex', '', 0, 0, 0, 0, 0, 0.00, '0', '0', '0', '0', '0,02', '0', '0,02'),
(712, 'ceville', '2009', 0, 0, 83, 19, 0, 4.79, 'The mean cruel cold blooded tyrant Ceville ruthlessly rules the beautiful kingdom of Faeryanis. Or rather, he used to rule the beautiful kingdom of Faeryanis, until the brave people revolted against his regime and drove him out of the palace.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>Operating system: </strong>Windows® XP &amp; Vista <br>\\t\\t\\t\\t\\t</li><li><strong>Processor: </strong>CPU with 1,7GHz <br>\\t\\t\\t\\t\\t</li><li><strong>Memory: </strong>512MB <br>\\t\\t\\t\\t\\t</li><li><strong>Hard disk space: </strong>2GB <br>\\t\\t\\t\\t\\t</li><li><strong>Video: </strong>3D Graphic Card with 256 MB Ram <br>\\t\\t\\t\\t\\t</li><li><strong>DirectX® Version: </strong>9c </li></ul>\'}', '0', '0,02', '0', '0', '0,02'),
(713, 'gt legends', '2012', 0, 0, 201, 24, 0, 4.99, 'The golden age of motor sports has returned. Experience one of the world’s most exciting racing series in GT...', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong>Microsoft Windows XP/Vista/Seven<br>\\t</li><li><strong>Processor:</strong>1.3 GHz Intel Pentium III or AMD<br>\\t</li><li><strong>Memory:</strong>512 MB RAM<br>\\t</li><li><strong>Graphics:</strong>DX8.1 comp. video card/64 MB<br>\\t</li><li><strong>DirectX®:</strong>8.1<br>\\t</li><li><strong>Hard Drive:</strong>3 GB HD space<br>\\t</li><li><strong>Sound:</strong>DX8.1 comp. sound card</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>Processor:</strong>2 GHz Intel Pentium IV or AMD<br>\\t</li><li><strong>Memory:</strong>1 GB RAM<br>\\t</li><li><strong>Graphics:</strong>DX9.0c comp. video card/256 MB<br>\\t</li><li><strong>DirectX®:</strong>9.0c<br>\\t</li><li><strong>Hard Drive:</strong>3 GB HD space<br>\\t</li><li><strong>Sound:</strong>DX9.0 comp. sound card</li></ul>\'}', '0', '0,02', '0', '0', '0,02'),
(714, 'prison architect', '2015', 0, 18, 31687, 2286, 1472, 23.79, 'Build and Manage A Maximum Security Prison.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong>XP<br>\\t</li><li><strong>Processor:</strong>Intel Core2 Duo 2.4Ghz or Higher / AMD 3Ghz or Higher<br>\\t</li><li><strong>Memory:</strong>4 GB RAM<br>\\t</li><li><strong>Graphics:</strong>Nvidia 8600 / Radeon equivalent (2009 era)<br>\\t</li><li><strong>Hard Drive:</strong>300 MB HD space</li></ul>\'}', '0,01', '0,01', '0', '0', '0,02'),
(715, 'mount & blade', '2008', 0, 0, 3205, 291, 415, 7.99, 'Calradia is a land at war, offering great riches and even greater dangers to adventurers and mercenaries that flock to shed their blood on its soil. With courage and a strong sword, an unknown stranger can make a name as a warrior. Free-form sand-box gameplay.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 2000/XP/Vista <br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 512 MB of RAM <br>\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> Graphics card with at least 64 MB memory <br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 700 MB of hard disk space. </li></ul>\'}', '0', '0,02', '0', '0', '0,02'),
(716, 'sacred gold', '2008', 0, 0, 1489, 319, 337, 6.99, 'A shadow of evil has fallen on the kingdom of Ancaria. It is a time for champions - a time to journey into the perilous world of SACRED. Battle blood-thirsty orcs &amp; lumbering ogres... Destroy undead wizards &amp; rotting mummies... Slay hellish demons &amp; legendary dragons.', '{\'minimum\': \'<strong>Minimum: </strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>Supported OS: </strong>Windows 2000/XP <br>\\t\\t\\t\\t\\t</li><li><strong>Processor: </strong>Intel Pentium® III 800 MHz<br>\\t\\t\\t\\t\\t</li><li><strong>Memory: </strong>256 MB RAM<br>\\t\\t\\t\\t\\t</li><li><strong>Graphics: </strong>16 MB DirectX 8 compatible graphics card<br>\\t\\t\\t\\t\\t</li><li><strong>DirectX: </strong>DirectX® 9.0c<br>\\t\\t\\t\\t\\t</li><li><strong>Sound: </strong>DirectX compatible sound card<br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive: </strong>2 GB HD Space</li></ul>\', \'recommended\': \'<strong>Recommended: </strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>Processor: </strong>Intel Pentium® 4, AMD Athlon 1.4 GHz or higher<br>\\t\\t\\t\\t\\t</li><li><strong>Memory: </strong>512 MB RAM<br>\\t\\t\\t\\t\\t</li><li><strong>Graphics: </strong> 64 MB DirectX 9 compatible graphics card</li></ul>\'}', '0', '0,02', '0', '0', '0,02'),
