(718, 'order of war', '2009', 0, 0, 270, 98, 319, 5.99, 'October 22, 2009 - Update Wargaming.net has released free Downloadable Content for Order of War. The DLC will download automatically the next time you launch the game. This DLC contains all the formerly exclusive pre-order items which include: Heavy Bomber Squadrons - Addition of German Arado and Allied B-24 Marauder heavy bomber units...', '{\'minimum\': \'<strong>Minimum:</strong><br> \\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® XP SP2/Windows Vista SP1/Windows 7<br>\\t \\t\\t </li><li><strong>Processor:</strong> 3.0 GHz, DUO 2.0 GHz<br>\\t \\t\\t </li><li><strong>Memory:</strong> 2 GB<br>\\t \\t\\t </li><li><strong>Graphics:</strong> 256MB NVIDIA GeForce 7600/Radeon HD2400 <br>\\t\\t \\t\\t </li><li><strong>DirectX®:</strong> DirectX® 9.0c<br>\\t \\t\\t </li><li><strong>Hard Drive:</strong> 10 GB free space<br>\\t \\t\\t </li><li><strong>Sound:</strong> Sound card<br> \\t\\t </li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br> \\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® XP SP2/Windows Vista SP1/Windows 7<br>\\t \\t\\t </li><li><strong>Processor:</strong> DUO 3.2 GHz or better<br>\\t \\t\\t </li><li><strong>Memory:</strong> 3 GB or better<br>\\t \\t\\t </li><li><strong>Graphics:</strong> 512MB GeForce 9800/Radeon HD4850 or better <br>\\t\\t \\t\\t </li><li><strong>DirectX®:</strong> DirectX® 9.0c<br>\\t \\t\\t </li><li><strong>Hard Drive:</strong> 10 GB free space<br>\\t \\t\\t </li><li><strong>Sound:</strong> Sound card<br>\\t\\t\\t \\t\\t </li><li><strong>Note:</strong> Increased performance will be noticed on an Alienware Area 51® X58 Desktop<br> \\t\\t</li></ul>\'}', '0', '0,01', '0', '0', '0,02'),
(719, 'dragons lair', '2013', 0, 12, 312, 92, 0, 6.99, 'Haven\'t heard of Dragon\'s Lair?! Well, you play the heroic Dirk the Daring, a valiant knight on a quest to rescue the fair princess from the clutches of an evil dragon! Originally released in the summer of 1983, Dragon\'s Lair has solidified itself as a cultural icon in gaming.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong>Windows 8<br>\\t</li><li><strong>Processor:</strong>1.8 GHz dual core CPU<br>\\t</li><li><strong>Memory:</strong>2 GB RAM<br>\\t</li><li><strong>Graphics:</strong>256 MB GeForce 8800, Radeon 3850, or Intel HD 2000 Graphics<br>\\t</li><li><strong>DirectX®:</strong>9.0<br>\\t</li><li><strong>Hard Drive:</strong>2 GB HD space<br>\\t</li><li><strong>Sound:</strong>DirectX Compatible Sound Card</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong>Windows 10<br>\\t</li><li><strong>Processor:</strong>Intel Core i Series Processor<br>\\t</li><li><strong>Memory:</strong>2 GB RAM<br>\\t</li><li><strong>Graphics:</strong>512 MB GeForce 220, Radeon 4550, Intel HD 3000 Graphics<br>\\t</li><li><strong>DirectX®:</strong>9.0<br>\\t</li><li><strong>Hard Drive:</strong>2 GB HD space<br>\\t</li><li><strong>Sound:</strong>DirectX Compatible Sound Card</li></ul>\'}', '0,02', '0', '0', '0', '0,02'),
(720, 'dungeon defenders', '2011', 0, 114, 10693, 932, 1993, 9.99, 'Create a hero from one of four classes to save Etheria in this 4-player coop Tower Defense Action-RPG. Includes Steam exclusive Portal gun &amp; TF2 familiars!', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 1 Ghz Dual-Core CPU<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1 GB RAM<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space:</strong> 2GB<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Video Card:</strong> Graphics Card with Shader Model 3 support, 256 MB video memory<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 9.0c<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectSound-compatible sound device\\t<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 2Ghz Dual-Core CPU<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2GB RAM<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space:</strong> 2GB<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Video Card:</strong> Graphics Card with Shader Model 3 support, 512 MB video memory<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 9.0c<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectSound-compatible sound device<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Additional:</strong>\\t<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0,02', '0', '0', '0', '0,02'),
(721, 'rugby league team manager 2015', '2015', 0, 0, 34, 16, 0, 14.99, 'Rugby League Team Manager 2015 puts you, the player, in the heart of the action, of managing your own Rugby League club. The season is long, and the challenges aplenty, as you navigate your way through domestic campaigns and international competitions, within officially licensed leagues.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP/Vista/7/8/10<br></li><li><strong>Processor:</strong> 1 GHz<br></li><li><strong>Graphics:</strong> 2D or 3D Accelerator,<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 4 GB available space<br></li><li><strong>Sound Card:</strong> 9.0c compatible audio card DirectX®: 9.0c<br></li><li><strong>Additional Notes:</strong> 1024 x 768 or 1024 x 600 24-bit colour Display</li></ul>\'}', '0', '0,02', '0', '0', '0,02'),
(722, 'hellgate london', '2018', 0, 0, 672, 507, 0, 10.29, 'The return of a sensational game! Hellgate is an action RPG game you have been waiting for. Since its first release Hellgate won the hearts of thousands of fans and now it\'s time to bring back memories and dip into the near future of 2038. For all mankind!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP<br></li><li><strong>Processor:</strong> 2 Ghz<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce 6800+, ATI Radeon R300+<br></li><li><strong>DirectX:</strong> Version 9.0<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 8 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7, 9, 10<br></li><li><strong>Processor:</strong> 2.4 Ghz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce 9800+, ATI Radeon HD 5000+<br></li><li><strong>DirectX:</strong> Version 9.0<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 8 GB available space</li></ul>\'}', '0', '0,02', '0', '0', '0,02'),
(723, 'oil rush', '2012', 0, 40, 173, 170, 9, 5.59, 'Oil Rush is a naval strategy game that takes place in a world where nuclear war has melted the ice caps, changing the face of the planet forever. Oil Rush offers unique gameplay, avoiding micromanagement of every single unit, while still providing full control over all important aspects of strategy and economy.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> XP<br> </li><li><strong>Processor:</strong> 2 GHz<br> </li><li><strong>Memory:</strong> 1 GB RAM<br> </li><li><strong>Graphics:</strong> NVIDIA 9600 256 MB or Intel HD 4000<br> </li><li><strong>Hard Drive:</strong> 3 GB HD space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> 7<br> </li><li><strong>Processor:</strong> 2.5 GHz dual-core (Intel)<br> </li><li><strong>Memory:</strong> 2 GB RAM<br> </li><li><strong>Graphics:</strong> NVIDIA GTX 460 512 MB<br> </li><li><strong>Hard Drive:</strong> 3 GB HD space<br> </li><li><strong>Other Requirements:</strong> Broadband Internet connection</li></ul>\'}', '0', '0,02', '0', '0', '0,02'),
(724, 'demolition company gold edition', '2011', 0, 0, 144, 27, 0, 7.19, 'Demolition Company Gold Edition: the complete Demolition Company experience! Includes Demolition Company, the DLC Kit Pack PLUS brand new equipment, new missions and a HUGE new city district 4 times bigger than the old Demolition Company districts!', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP, Windows Vista or Windows 7<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 2 GHz Intel or equivalent AMD processor<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1G RAM<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> Nvidia Geforce 6800 Series, ATI Radeon X850, S3 Chrome 430 GT or better (min 256 MB VRAM)<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 1 GB Space Free<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> Soundcard required<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Other Requirements:</strong> <br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0', '0,02', '0', '0', '0,02'),
(725, 'anima gate of memories', '2016', 0, 25, 338, 151, 0, 14.99, 'Anima Gate of Memories is a third person action RPG that tells the story of two beings bound by an unwilling pact, an ancient monster and a girl who lost her past... Anima is mostly focused on combat and exploration, but it also has deep roleplaying elements.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP<br></li><li><strong>Processor:</strong> Dual Core processor<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> Compatible with DirectX9 with 512 MB RAM or better (NVIDIA GeForce GTX 460 / ATI Radeon HD 5850 )<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 6 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 or newer<br></li><li><strong>Processor:</strong> Quad core processor<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 6 GB available space</li></ul>\'}', '0', '0,02', '0', '0', '0,02'),
(726, 'rollercoaster tycoon world', '2016', 0, 30, 1182, 3585, 2577, 10.99, 'RollerCoaster Tycoon World™ is the newest installment in the legendary RCT franchise. This next-generation theme park simulation and building game includes fan-favorite features along with incredible new advancements!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li>Requires a 64-bit processor and operating system<br></li><li><strong>OS:</strong> Windows 7 (64-bit)<br></li><li><strong>Processor:</strong> Intel 2.3 Ghz Core i5 or AMD equivalent<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> GeForce GTX 460 or AMD equivalent<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 10 GB available space<br></li><li><strong>Additional Notes:</strong> Subject to Change</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li>Requires a 64-bit processor and operating system</li></ul>\'}', '0', '0,02', '0', '0', '0,02'),
(727, 'trapped dead', '2011', 0, 0, 258, 410, 142, 3.99, 'You and up to three friends fight to survive the Zombie outbreak in this game inspired by early \'80s horror films!', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® XP/Vista/7<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 2.0GHz CPU <br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1GB<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space:</strong> 2GB \\t<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Video Card:</strong> Graphics card supporting shader 3.0 (onboard chipsets are not supported)<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 9.0c<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> Sound card with DirectX 9.0c support<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0', '0,02', '0', '0', '0,02'),
(728, 'mount & blade warband', '2010', 0, 80, 75872, 2213, 7932, 14.99, 'In a land torn asunder by incessant warfare, it is time to assemble your own band of hardened warriors and enter the fray. Lead your men into battle, expand your realm, and claim the ultimate prize: the throne of Calradia!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® XP<br></li><li><strong>Processor:</strong> Intel Pentium 4 2.0 GHz or AMD 2.5 GHz<br></li><li><strong>Memory:</strong> 512MB RAM<br></li><li><strong>Graphics:</strong> 3D graphics card with 64MB RAM<br></li><li><strong>Hard Drive:</strong> 100 MB available space <br></li><li><strong>Sound:</strong> Standard audio</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP or greater<br></li><li><strong>Processor:</strong> Intel Core Duo 2.0 GHz or AMD Athlon 64 X2 3600+<br></li><li><strong>Memory:</strong> 1GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce FX 5200, ATI Radeon 9600, or better<br></li><li><strong>Hard Drive:</strong> 100MB available space<br></li><li><strong>Sound:</strong> Standard audio</li></ul>\'}', '0,01', '0,01', '0', '0', '0,02'),
(729, 'legend of kay anniversary', '2015', 0, 25, 134, 59, 0, 17.99, '10 years after its initial release, Legend of Kay - Anniversary is a thoroughly remastered version of the original game: high-resolution textures; new, more detailed character models; modern rendering techniques and crystal-clear surround sound give this great classic a new shine.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7/Windows 8.1 32 or 64 bit<br></li><li><strong>Processor:</strong> Dual Core Processor at 2.0+ GHz or better<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> 1024 MB NVidia or ATI graphics card<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 6 GB available space</li></ul>\'}', '0', '0,03', '0', '0', '0,03'),
(730, 'vietcong', '2018', 0, 0, 1, 19, 0, 3.99, 'Vietcong-survival-shooter in the first person with elements of survival, which is set in Vietnam, in the vicinity of My tho.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7/8/10<br></li><li><strong>Processor:</strong> Intel Dual-Core 2.1 GHz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> 1GB of VRAM Shader Model 3.0 and above<br></li><li><strong>DirectX:</strong> Version 10<br></li><li><strong>Storage:</strong> 5 GB available space<br></li><li><strong>Sound Card:</strong> DirectX®-compatible</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7/8/10<br></li><li><strong>Processor:</strong> Quad Core Processor<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> 2GB of VRAM Shader Model 3.0 and above<br></li><li><strong>Storage:</strong> 7 GB available space<br></li><li><strong>Sound Card:</strong> DirectX®-compatible</li></ul>\'}', '0', '0,02', '0', '0', '0,02'),
(731, 'crysis warhead', '2008', 0, 0, 1694, 312, 18, 7.99, 'Pulse-racing new installment from 2007\'s PC Game of the Year*: Play as Sergeant Sykes and experience a whole new side of the battle. A standard combat mission behind enemy lines becomes critical when you discover your enemies have captured something of vital importance to the ensuing war.', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>Supported OS: </strong>Microsoft Windows XP with Service Pack 2 or Microsoft Vista<br>\\t\\t\\t\\t\\t</li><li><strong>Processor: </strong>Intel Pentium 4 2.8 GHz (3.2 GHz for Vista), Intel Core 2.0 GHz (2.2 GHz for Vista), AMD Athlon 2800+ (3200+ for Vista) or better<br>\\t\\t\\t\\t\\t</li><li><strong>Memory: </strong>1.0 GB RAM (XP) or 1.5 GB RAM (Vista)<br>\\t\\t\\t\\t\\t</li><li><strong>Graphics: </strong>256 MB<br>\\t\\t\\t\\t\\t</li><li><strong>Video Card: </strong>NVIDIA GeForce 6800 GT, ATI Radeon 9800 Pro (Radeon X800 Pro for Vista) or better<br>\\t\\t\\t\\t\\t</li><li><strong>DirectX Version: </strong>DirectX 9.0c or 10<br>\\t\\t\\t\\t\\t</li><li><strong>Sound: </strong>DirectX 9.0c compatible<br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive: </strong>15GB</li></ul>\'}', '0', '0,02', '0', '0', '0,02'),
(732, 'warhammer 40,000 dawn of war soulstorm', '', 0, 0, 0, 0, 0, 0.00, '0', '0', '0', '0,02', '0', '0', '0,02'),
(733, 'commandos 3 destination berlin', '2007', 0, 0, 421, 265, 14, 3.99, 'Commandos 3: Destination Berlin is a game of real-time tactics that places you in command of an elite unit of Special Forces behind enemy lines in the European theater of World War II. From the shores of France to the heart of the Third Reich, strike fast from land or sea infiltrating hostile territories and conducting raids to disrupt...', '{\'minimum\': \'<strong>Operating System: </strong>Microsoft Windows 98SE/2000/XP (Admin rights required), Pentium III 700 Mhz (or Athlon(tm) equivalent) Windows 7 Service Pack 1 and above are unsupported at this time.<br><strong>Graphics: </strong>128 MB on Windows 98SE, 256 on Windows 2000/XP, 32 MB DirectX 9 compatible 3D Graphics card (nVidia GeForce or Ati Radeon Chipset), Windows 98SE/2000/XP-compatible sound card (100% DirectX 9-compatible)<br><strong>Hard Drive Space: </strong>2 GB free disk space<br><strong>Other: </strong>mouse and keyboard.<br><strong>Multiplayer Requirements:</strong> Pentium® III 1.0 GHz (or Athlon(tm) equivalent), 256 MB, 64 MB GeForce or ATI Radeon equivalent, LAN, ADSL or Cable Modem\', \'recommended\': \'Pentium® 4 2.0 GHz (or Athlon(tm) XP equivalent), 512 MB, 128 MB GeForce 4ti or ATI Radeon 9xxx equivalent\'}', '0', '0,02', '0', '0', '0,02'),
(734, 'azada', '2010', 0, 0, 8, 4, 0, 6.99, 'Trapped in a magical puzzle book, the adventurous Titus needs your help to release him from his spell. To do this, you must solve the tricky puzzles of Azada™. Crack the series of puzzles and fill in the missing pages of the enchanted book to free Titus from his prison. Loads of unique puzzles to solve.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 2000/XP/Vista<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 600 Mhz<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 128 MB<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> On-board graphics<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 6.0 or higher<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 65 MB<br>\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0', '0,02', '0', '0', '0,02'),
(735, 'hogs of war', '2015', 0, 0, 124, 63, 0, 3.99, 'Hogs of War is a turn-based tactical warfare game. Take turns controlling members of your squad of hogs to engage in combat with the opposition based on World War 1. With 3D graphics, vehicles, a career-based single-player mode, and voice-over (narration and for characters) by British comedian Rik Mayall.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP / Vista / 7 (Please note: doesn\\\'t work on Windows 8, Windows 10 or MAC)<br></li><li><strong>Processor:</strong> 1.8 GHz Processor<br></li><li><strong>Memory:</strong> 512 MB RAM<br></li><li><strong>Graphics:</strong> 3D graphics card<br></li><li><strong>DirectX:</strong> Version 9.0<br></li><li><strong>Storage:</strong> 1 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9 Compatible Sound Device<br></li><li><strong>Additional Notes:</strong> Mouse, Keyboard</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>Memory:</strong> 1 GB RAM</li></ul>\'}', '0,01', '0,01', '0', '0', '0,02'),
(736, 'mushihimesama', '2015', 0, 50, 790, 20, 82, 14.99, 'Battle huge &quot;Koju&quot; bugs in CAVE\'s beautiful fantasy shooter, Mushihimesama. Experience the thrill of bullet hell from the masters of the genre as you evade visually stunning shot patterns with thousands of bullets.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7/8/8.1/10<br></li><li><strong>Processor:</strong> Intel Core i3 2GHz or higher.<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> Intel HD Graphics 4000, Geforce 9500GT, Radeon HD 3650 or better<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 1500 MB available space<br></li><li><strong>Sound Card:</strong> DirectSound-compatible sound card</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>Storage:</strong> 2 GB available space</li></ul>\'}', '0', '0', '0,02', '0', '0,02'),
(737, 'the talos principle', '2014', 0, 40, 17237, 785, 230, 29.99, 'The Talos Principle is a first-person puzzle game in the tradition of philosophical science fiction. Made by Croteam and written by Tom Jubert (FTL, The Swapper) and Jonas Kyratzes (The Sea Will Claim Everything).', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7<br></li><li><strong>Processor:</strong> Dual-core 2.0 GHz<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> DirectX 11 class GPU with 1GB VRAM (nVidia GeForce 480 GTX, AMD Radeon HD 5870)<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 5 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 64-bit<br></li><li><strong>Processor:</strong> Quad-core 3.0 GHz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> AMD Fury or NVIDIA GTX 1070<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 8 GB available space</li></ul>\'}', '0', '0,02', '0', '0', '0,02'),
(738, 'blood bowl legendary edition', '2010', 0, 0, 675, 228, 284, 7.99, 'Inspired by the Warhammer Fantasy world, Blood Bowl is an ultra-violent combination of strategy and sports games. The Legendary Edition features 20 playable races, including 11 that are totally new, each offering its own game style! Make a competitive team, train it and buy the best equipment.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP SP3/ Vista SP1/ 7<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Pentium 4 2.4 GHZ/AthlonXP 2400+<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1GB (XP)/ 2GB (Vista/7)<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 128 MB 100% DirectX® 9 and shaders 2.0 compatible (NVIDIA GEFORCE 6600 / ATI RADEON X700 or higher) Not compatible with SLI. Intel, SIS and Via/S3G graphics controllers non-supported<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 9.0<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 5 GB<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX® 9 compatible<br>\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Multiplayer Requirements:</strong> Internet connection required for online gameplay.<br>\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0', '0,01', '0', '0', '0,02'),
(739, 'peggle nights', '2008', 0, 0, 368, 24, 237, 4.25, 'The sun has set at the Peggle Institute, but the bouncy delight has just begun! Join the Peggle Masters on a dreamtime adventure of alter egos and peg-tastic action. Stay up late to aim, shoot and clear orange pegs, and bask in Extreme Fever glory under the silver moon. Then, put your Peggle skills to the ultimate test in Challenge mode.', '{\'minimum\': \'<p><strong>Minimum:</strong></p> \\n\\t\\t\\t\\t\\t<ul> \\n\\t\\t\\t\\t\\t<li><strong>Supported OS: </strong>Windows® 2000/XP/Vista</li> \\n\\t\\t\\t\\t\\t<li><strong>Processor: </strong>700MHz</li> \\n\\t\\t\\t\\t\\t<li><strong>Memory: </strong>256MB RAM</li> \\n\\t\\t\\t\\t\\t<li><strong>Video: </strong>DirectX-compatible; 16MB</li> \\n\\t\\t\\t\\t\\t<li><strong>DirectX® Version: </strong>8</li> \\n\\t\\t\\t\\t\\t<li><strong>Sound: </strong>DirectX-compatible</li> \\n\\t\\t\\t\\t\\t<li><strong>Hard Drive: </strong>50+MB </li> </ul>\', \'recommended\': \'<p><strong>Recommended:</strong></p> \\n\\t\\t\\t\\t\\t<ul> \\n\\t\\t\\t\\t\\t<li><strong>Processor: </strong>1+GHz</li> \\n\\t\\t\\t\\t\\t<li><strong>Memory: </strong>512+MB RAM</li> \\n\\t\\t\\t\\t\\t<li><strong>Video: </strong>DirectX-compatible; 32+MB</li> \\n\\t\\t\\t\\t\\t<li><strong>DirectX® Version: </strong>9.0c+</li> </ul>\'}', '0', '0,01', '0', '0', '0,02'),
(740, 'aqua panic!', '', 0, 0, 0, 0, 0, 0.00, '0', '0', '0,01', '0,01', '0', '0', '0,02'),
(741, 'the longest journey', '2007', 0, 0, 1152, 102, 14, 5.99, 'The Longest Journey is an amazing graphical adventure, where the player controls the protagonist, April Ryan, on her journey between parallel universes.', '{\'minimum\': \'<strong>Minimum: </strong>Windows 2000/XP, Pentium 166 MMX , 32 MB RAM, Mouse and Keyboard, 640x480 SVGA high colour (16bit) video card with 2 MB RAM, Windows compatible sound device, 300 MB free hard drive space<br>\\t\\t\\t\\t\\t<strong>Recommended: </strong>Pentium II, 266 mhz, 64 MB RAM , 3d accelarator card ( Direct 3d compatible ) with 4 MB RAM, 1GB free hard drive space\'}', '0', '0,01', '0', '0', '0,02'),
(742, 'dungeons the dark lord', '2011', 0, 27, 65, 113, 3, 14.99, 'Exciting new features, including four-player multiplayer in four modes and the ability to play as some of the game’s popular bosses', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP SP2, Vista, 7<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 2.0 GHz Dual Core<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 3 GB<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space:</strong> 2 GB free HDD<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Video Card:</strong> 256 MB DirectX 9.0c Graphics card with Shader Model 3.0<br>\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 9.0c<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> Windows-compatible Soundcard\\t<br>\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0', '0,01', '0', '0', '0,02'),
(743, 'post mortem', '2011', 0, 0, 97, 87, 0, 5.59, 'After returning to the quiet streets of Paris to pursue a life of painting, Gus Macpherson could not escape his true art…', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>Operating system:</strong>Windows® XP / Vista™ / Windows® 7 <br>\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong>1.0 GHz CPU<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong>512 GB <br>\\t\\t\\t\\t\\t\\t</li><li><strong>Hard disk space:</strong>1GB <br>\\t\\t\\t\\t\\t\\t</li><li><strong>Video:</strong>Video Card with 64MB dedicated memory <br>\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong>Sound card with DirectX 9.0c support<br>\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong>9.0c<br>\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0', '0,01', '0', '0', '0,02'),
(744, 'this war of mine', '2014', 0, 42, 47258, 2571, 512, 14.99, 'In This War Of Mine you do not play as an elite soldier, rather a group of civilians trying to survive in a besieged city; struggling with lack of food, medicine and constant danger from snipers and hostile scavengers. The game provides an experience of war seen from an entirely new angle.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7/8/10<br></li><li><strong>Processor:</strong> Intel(R) Core(TM)2 Duo 2.4, AMD Athlon(TM) X2 2.8 Ghz<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> Geforce 9600 GS, Radeon HD4000, Shader Model 3.0, 512 MB<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Sound Card:</strong> DirectX compatible</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7/8/10<br></li><li><strong>Processor:</strong> Intel(R) Core(TM)2 Quad 2.7 Ghz, AMD Phenom(TM)II X4 3 Ghz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> GeForce GTX 260, Radeon HD 5770, 1024 MB, Shader Model 3.0<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Sound Card:</strong> DirectX compatible</li></ul>\'}', '0', '0,01', '0', '0', '0,02'),
(745, 'still life 2', '2011', 0, 0, 123, 155, 0, 5.59, 'Who is hiding behind Mr. X? Still Life 2 reveals the long-awaited ending of Still Life and spells a new investigation for Agent Victoria McPherson. In Fall 2008, Victoria is sent to Maine where Ellen Dunnigan\'s body has just been found.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® XP/Vista/7<br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 1.5GHz CPU <br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 512MB<br>\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space:</strong> 5GB\\t<br>\\t\\t\\t\\t\\t</li><li><strong>Video Card:</strong> DirectX compatible graphics card with 128MB memory <br>\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 9.0c<br>\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> Sound card with DirectX 9.0c support<br>\\t\\t\\t\\t\\t</li></ul>\'}', '0', '0,01', '0', '0', '0,02'),
(746, 'platypus', '2014', 0, 0, 280, 28, 260, 4.99, 'The vast continent-spanning city of Collosatropolis has finally reached the limits of its expansion. Tall buildings cover every available space. The air is thick with smoke and poisonous chemicals.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP/Vista/7/8<br></li><li><strong>Processor:</strong> Pentium® or AMD® 1.3 GHz<br></li><li><strong>Memory:</strong> 128 MB RAM<br></li><li><strong>Graphics:</strong> 32MB 3D Video Card</li></ul>\'}', '0,02', '0', '0', '0', '0,02'),
(747, 'command & conquer 4 tiberian twilight', '2010', 0, 0, 378, 1712, 160, 9.99, 'Behold disciples of Nod, for the end is soon upon us. Electronic Arts’ award-winning and best-selling Tiberium saga is coming to a powerful conclusion with Command &amp; Conquer 4, which will introduce a multitude of innovations to the classic fast and fluid Command &amp; Conquer gameplay, while retaining the core compulsions that fans...', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP SP3, Windows Vista SP1, or Windows 7<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Core 2 or better, AMD 64 X2 or better<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1 GB (1.5 GB Vista and Windows 7)<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> At least 10 GB of free space<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 256 MB (SM 3.0) - Nvidia GeForce 6800 or better, ATI Radeon X1600 or better<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX 9.0c compatible sound card<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> DirectX 9.0c\\t<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br>\\t\\t\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>Processor:</strong> Intel Core 2 Duo 2.6 GHz; AMD Athlon 64 X2 Dual-Core 5600+<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2GB<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 256 MB (SM 3.0) - Nvidia GeForce 8800 or better, ATI X1900 or better<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0', '0,01', '0', '0', '0,02'),
(748, 'farm frenzy', '2010', 0, 0, 19, 2, 0, 3.99, 'Slip into a pair of overalls and try your hand at running a farm! From tending to the fields where your cows graze to gathering eggs for sale at the town market, Farm Frenzy is as stimulating as the real thing-- only you won\'t have to experience the nasty smells!', '{\'minimum\': \'<ul>\\n\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>OS:</strong> Windows 2000/XP/Vista</li>\\n\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>Processor:</strong> 1000 MHz CPU</li>\\n\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>Memory:</strong> 256 MB Ram</li>\\n\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>DirectX&reg;:</strong> 8</li>\\n\\t\\t\\t\\t\\t\\t\\t\\t<li><strong>Hard Drive:</strong> 24 MB of free space</li>\\n\\t\\t\\t\\t\\t\\t\\t</ul>\'}', '0,01', '0', '0', '0', '0,02'),
(749, 'a vampyre story', '2014', 0, 0, 49, 35, 0, 14.99, 'Help Mona De Lafitte escape from Baron Shrowdy von Kiefer and return to Paris!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP / Windows Vista / Windows 7<br></li><li><strong>Processor:</strong> 1,6 Ghz<br></li><li><strong>Memory:</strong> 512 MB RAM<br></li><li><strong>Graphics:</strong> 256 MB RAM GeForce FX Generation or ATI Radeon 9500<br></li><li><strong>DirectX:</strong> Version 9.0<br></li><li><strong>Storage:</strong> 3 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.O compatible Soundcard</li></ul>\'}', '0', '0,01', '0', '0', '0,02'),
(750, 'the haunted hells reach', '2011', 0, 28, 507, 81, 285, 5.99, 'Winner of 2010′s Make Something Unreal contest, The Haunted: Hells Reach is a fast-paced horror game where your goal is to liberate cursed places and survive the assault of Hell.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP, Windows Vista or Windows 7<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel Pentium Core 2 Duo 2.4 GHz or AMD Athlon X2 2.8GHz<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2 GB RAM<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> Shader Model 3.0 graphics card with 256MB of memory (NVIDIA GeForce 7900GS, ATI Radeon 2000 series or higher)<br>\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 9<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 4GB of free hard drive space<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX compatible sound card<br>\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0,02', '0', '0', '0', '0,02'),
(751, 'assault suit leynos', '2016', 0, 35, 52, 22, 0, 19.99, 'A classic reawakens – Assault Suit Leynos is back and in high definition! Get ready for all-out robotic war as the fan-favourite Mega Drive classic is reworked with all new HD visuals for the ultimate alien-blasting experience!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 SP1 / 8 / 8.1 / 10 (64bit)<br></li><li><strong>Processor:</strong> Intel Core i5<br></li><li><strong>Memory:</strong> 6 GB RAM<br></li><li><strong>Graphics:</strong> GeForce 8xxx Series / Radeon HD 2xxx/HD 3xxx<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 5 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c compatible soundcard<br></li><li><strong>Additional Notes:</strong> Controllers supported, but must be activated in Options &gt; Config &gt; Controls menu on first boot (game will remember settings every time after that)</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 SP1 / 8 / 8.1 / 10 (64bit)<br></li><li><strong>Processor:</strong> Intel Core i7<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> GeForce 200 Series / Radeon HD 5xxx<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 5 GB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c compatible soundcard<br></li><li><strong>Additional Notes:</strong> Controllers supported, but must be activated in Options &gt; Config &gt; Controls menu on first boot (game will remember settings every time after that)</li></ul>\'}', '0,01', '0', '0', '0', '0,02'),
(752, 'contrast', '2013', 0, 22, 4028, 415, 91, 8.49, 'CONTRAST is a puzzle/platform game where you can move between a fantastic 3D world and a mysterious shadowy universe in 2D in the blink of an eye. Delve into a dreamlike and surreal 1920s world, inspired by the performance art world of vaudeville and film noir, and cradled by a smooth and sultry jazz ambiance.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> WINDOWS XP SP2/WINDOWS VISTA SP1/WINDOWS 7/WINDOWS 8<br></li><li><strong>Processor:</strong> AMD/INTEL DUAL-CORE 2.3 GHz<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> 512MB VRAM, COMPATIBLE DIRECTX 9.0C AND SHADER MODEL 3.0, AMD RADEON X2600 XT/NVIDIA GEFORCE 7900 GTX<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 4 GB available space<br></li><li><strong>Sound Card:</strong> DIRECTX 9 COMPATIBLE<br></li><li><strong>Additional Notes:</strong> The Original Soundtrack and the Programme (Artwork, Dev. Diary) will be placed in your CONTRAST folder in the Steam Directory: ...\\\\Steam\\\\SteamApps\\\\common\\\\Contrast\\\\CONTRAST_Programme-OST</li></ul>\'}', '0', '0,01', '0', '0', '0,02');
INSERT INTO `jeux` (`id_jeu`, `nom_jeu`, `annee`, `age_requis`, `nb_succes`, `nb_avis_pos`, `nb_avis_neg`, `temps_jeu_moyen`, `prix`, `description`, `configuration`, `ventes_AN`, `ventes_EU`, `ventes_JP`, `ventes_Autre`, `ventes_Global`) VALUES
(753, 'elven legacy', '2009', 0, 0, 76, 29, 27, 3.99, 'This sequel to Fantasy Wars continues its story after banishing the archdemon. The shadows of destruction begin to loom on the horizon once a human mage uncovers a dark and powerful secret dating back to the remote past of the Elven race.', '{\'minimum\': \'Minimum<br> <ul class=\"bb_ul\"><li><strong>Operating System: </strong>Microsoft® Windows® XP / Vista<br> </li><li><strong>Processor: </strong>Intel® Pentium® IV 1.5 GHz or AMD® 2000+ (single core)<br> </li><li><strong>Memory: </strong>512 MB RAM<br> </li><li><strong>Hard Disk Space: </strong>3 GB Available HDD Space<br> </li><li><strong>Video Card: </strong>NVIDIA® GeForce™ FX 5700 or ATI™ Radeon® 9600 and above Video Card<br> </li><li><strong>Sound Card: </strong>DirectX-compatible Sound Card<br> </li><li><strong>DirectX® Version: </strong>DirectX® Version 9.0c (4.09.0000.0904)<br> </li></ul>\', \'recommended\': \'Recommended<br> <ul class=\"bb_ul\"><li><strong>Operating System: </strong>Microsoft® Windows® XP / Vista<br> </li><li><strong>Processor: </strong>Intel® Pentium® IV 2.4 GHz or AMD 3500+ (single core)<br> </li><li><strong>Memory: </strong>1 GB RAM<br> </li><li><strong>Hard Disk Space: </strong>3 GB Available HDD Space<br> </li><li><strong>Video Card: </strong>NVIDIA® GeForce™ 6800 or ATI™ Radeon® X850XT<br> </li><li><strong>Sound Card: </strong>DirectX-compatible Sound Card<br> </li><li><strong>DirectX® Version: </strong>DirectX® Version 9.0c (4.09.0000.0904)<br> </li></ul>There is no guarantee that the game will function properly on notebook PCs.\'}', '0,01', '0', '0', '0', '0,02'),
(754, 'koihime enbu', '', 0, 0, 0, 0, 0, 0.00, '0', '0', '0', '0', '0,02', '0', '0,02'),
(755, 'truck racer', '2013', 0, 50, 127, 45, 0, 6.99, 'Take control of five tons of metal and power, and floor it until you reach the finish line!Drive fully destructible trucks in Championship, Time Attack, Elimination and Quick Race. Get rid of opponents trying to block your way and make a reputation for yourself!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® XP updated with the latest Service Pack<br></li><li><strong>Processor:</strong> Intel® Core 2 Duo or AMD Athlon X2™ 2.8GHz<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA® GeForce® 8800 series or ATI™ Radeon™ 4870<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 5 GB available space<br></li><li><strong>Additional Notes:</strong> Multiplayer modes require an active Internet connection</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® 7 or 8 updated with the latest Service Pack<br></li><li><strong>Processor:</strong> Intel® Core i5 2500 or AMD Phenom X4™ 965<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA® GeForce® 560 series or AMD Radeon™ HD 6850<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 5 GB available space<br></li><li><strong>Additional Notes:</strong> Multiplayer modes require an active Internet connection</li></ul>\'}', '0', '0,01', '0', '0', '0,02'),
(756, 'evil genius', '2009', 0, 0, 1847, 95, 287, 6.99, 'Everybody wants to rule the world! Achieve global power with EVIL GENIUS, the one and only complete world domination simulator. All the everyday tasks of the deliciously wicked mastermind are available to experience and master from building your ultra-secret base to developing spectacular super-weapons to carry out your nefarious master...', '{\'minimum\': \'<ul> \\r\\n\\t\\t\\t\\t\\t<li><strong>Supported OS:</strong> Microsoft Windows XP / Vista</li> \\r\\n\\t\\t\\t\\t\\t<li><strong>Processor:</strong> Pentium® III 800MHz processor</li> \\r\\n\\t\\t\\t\\t\\t<li><strong>Memory:</strong> 128MB RAM</li> \\r\\n\\t\\t\\t\\t\\t<li><strong>Graphics:</strong> GeForce2 16Mb or equivalent </li> \\r\\n\\t\\t\\t\\t\\t<li><strong>Hard Drive:</strong> 1.4 GB of free hard drive space</li> \\r\\n\\t\\t\\t\\t\\t<li><strong>Sound Card:</strong> Windows compatible sound card</li>\\r\\n\\t\\t\\t\\t\\t<li><strong>DirectX9®:</strong> DirectX 9.0c</li>\\r\\n\\t\\t\\t</ul>\'}', '0', '0,01', '0', '0', '0,02'),
(757, 'pillars of eternity', '2015', 0, 48, 11558, 1835, 1710, 22.99, 'Prepare to be enchanted by a world where the choices you make and the paths you choose shape your destiny. Obsidian Entertainment, the developer of Fallout: New Vegas™ and South Park: The Stick of Truth™, together with Paradox Interactive is proud to present Pillars of Eternity.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista 64-bit or newer<br></li><li><strong>Processor:</strong> Intel Core i3-2100T @ 2.50 GHz / AMD Phenom II X3 B73<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> ATI Radeon HD 4850 or NVIDIA GeForce 9600 GT<br></li><li><strong>Storage:</strong> 14 GB available space<br></li><li><strong>Sound Card:</strong> DirectX Compatible Sound Card</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista 64-bit or newer<br></li><li><strong>Processor:</strong> Intel Core i5-2400 @ 3.10 GHz / AMD Phenom II X6 1100T<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> Radeon HD 7700 or NVIDIA GeForce GTX 570<br></li><li><strong>Storage:</strong> 14 GB available space<br></li><li><strong>Sound Card:</strong> DirectX Compatible Sound Card</li></ul>\'}', '0', '0,01', '0', '0', '0,02'),
(758, 'worms wmd', '2016', 0, 29, 2132, 528, 424, 19.99, 'The worms are back in their most destructive game yet. With a gorgeous, hand-drawn 2D look, brand new weapons, the introduction of crafting, vehicles and buildings plus the return of some much-loved classic weapons and gameplay, Worms W.M.D is the best worms experience ever.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7/8.1/10 (32-bit versions)<br></li><li><strong>Processor:</strong> Intel Dual Core 6600 @ 2.4GHz<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> Intel 4400, GeForce GTX 280, AMD Radeon HD 7750<br></li><li><strong>DirectX:</strong> Version 11</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7/8.1/10 (64-bit versions)<br></li><li><strong>Processor:</strong> i5-2500k@3.3GHz, AMD FX 6300 3.5GHz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> GeForce GTX 750, AMD R7 370<br></li><li><strong>DirectX:</strong> Version 11</li></ul>\'}', '0,01', '0,01', '0', '0', '0,02'),
(759, 'sengoku', '2011', 0, 0, 205, 110, 112, 7.99, 'Use your power as a Feudal Lord to unite the land of the Rising Sun under your iron fist.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP, Vista, 7<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> Intel® Pentium® IV 2.4 GHz or AMD 3500+<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2 Gb RAM<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Disk Space:</strong> 2 GB Available HDD Space\\t<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Video Card:</strong> NVIDIA® GeForce 8800 or ATI Radeon® X1900<br>\\t\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 9.0c<br>\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> Direct X-compatible sound card\\t<br>\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0', '0,01', '0', '0', '0,02'),
(760, 'codename panzers phase two', '2016', 0, 0, 65, 7, 0, 13.99, 'Fight alongside your troops in the sweltering desert heat of the Sahara or in the blustery heights of the Italian Alps. Wield your strategic prowess to gain the upper hand by the light of day and exploit the dark shroud of night to launch surprise attacks. Tanks, planes, troops, weapons - the resources are at your command.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP / Vista / 7 / 8 / 10 32 or 64 bit<br></li><li><strong>Processor:</strong> Intel or AMD 1,0 GHz<br></li><li><strong>Memory:</strong> 256 MB RAM<br></li><li><strong>Graphics:</strong> 64MB 3D Video Card with Hardware T&amp;L<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 4 GB available space<br></li><li><strong>Sound Card:</strong> DirectX compatible</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP / Vista / 7 / 8 /10 32 or 64 bit<br></li><li><strong>Processor:</strong> Intel or AMD 2,0 GHz<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> 256MB 3D Video Card with Hardware T&amp;L<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 4 GB available space<br></li><li><strong>Sound Card:</strong> DirectX compatible card</li></ul>\'}', '0', '0,01', '0', '0', '0,01'),
(761, 'blitzkrieg 2 anthology', '2014', 0, 0, 444, 79, 132, 3.99, 'Return to the bloody battlefields of World War II in this epic sequel. Blitzkrieg 2 returns you to the gritty realism of WWII battles while pushing your focus into new, strategic opportunities during global war!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 98/ME/2000/XP<br></li><li><strong>Processor:</strong> 2,4GHz Pentium 4 / Athlon<br></li><li><strong>Memory:</strong> 512 MB RAM<br></li><li><strong>Graphics:</strong> 128 Мб Video card GeForce 4 / Radeon 9600<br></li><li><strong>DirectX:</strong> Version 9.0<br></li><li><strong>Storage:</strong> 2 GB available space</li></ul>\'}', '0', '0,01', '0', '0', '0,01'),
(762, 'battle worlds kronos', '2013', 0, 39, 159, 76, 34, 14.99, 'Battle Worlds: Kronos is a classic turn-based strategy game in the tradition of Battle Isle, Advance Wars and Panzer General. Have you ever wondered what games like that would look like today? Well, we did. As a result, we decided to develope Battle Worlds: Kronos.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista, 7 or 8<br></li><li><strong>Processor:</strong> 2.0 Ghz Dual-Core<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> DirectX 9c compatible with 256 MB RAM, Pixelshader 2.0<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 3 GB available space<br></li><li><strong>Sound Card:</strong> Integrated audio interface</li></ul>\'}', '0', '0,01', '0', '0', '0,01'),
(763, 'east india company', '2009', 0, 0, 45, 48, 0, 7.99, 'In East India Company, players will enjoy building the World\'s most powerful trading empire &amp; engaging in vigorous battles in both single player &amp; multiplayer modes, all within a breathtaking cinematic game environment.', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® XP<br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 1.6 GHz Intel Pentium processor or equivalent AMD Athlon processor<br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1GB<br>\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 128 MB DirectX 9.0c compatible or better video card with pixelshader 2.0<br>\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 9.0c<br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> approx. 6 GB<br>\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX 9.0c compatible sound card<br>\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows® XP/Vista<br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 2.0 GHz dual core processor<br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2GB<br>\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 512 MB DirectX 9.0c compatible or better video card with pixelshader 3.0<br>\\t\\t\\t\\t\\t</li><li><strong>DirectX®:</strong> 9.0c<br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> approx. 6 GB<br>\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX 9.0c compatible sound card<br>\\t\\t\\t\\t\\t</li></ul>\'}', '0,01', '0', '0', '0', '0,01'),
(764, 'theatre of war', '2010', 0, 0, 116, 86, 0, 2.79, 'Command a special task force composed of different kinds of units, including tanks, APCs, field guns, mortars, various infantry regiments and will also have an opportunity to call for artillery and air support.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP SP3<br></li><li><strong>Processor:</strong> 2 Ghz+ Pentium 4 or Athlon XP<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> A dedicated video card with full OpenGL 2.1 support (starting from GeForce 5700/Radeon 9600)<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 4 GB available space<br></li><li><strong>Additional Notes:</strong> The game is not guaranteed to run on integrated graphics and laptops</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> 64-bit Windows 7 and later<br></li><li><strong>Processor:</strong> 3 Ghz+ Intel or AMD chip<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> A dedicated video card with full OpenGL 2.1 support (starting from GeForce 5700/Radeon 9600)<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 4 GB available space<br></li><li><strong>Additional Notes:</strong> The game is not guaranteed to run on integrated graphics and laptops</li></ul>\'}', '0', '0,01', '0', '0', '0,01'),
(765, 'republique', '2015', 0, 26, 291, 84, 0, 7.19, 'Help a woman named Hope escape in a thrilling and topical stealth-action game that explores the perils of government surveillance in the Internet Age.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 64-Bit<br></li><li><strong>Processor:</strong> 2.0 GHz Dual Core<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GT 640 or AMD Radeon HD 7550 w/ 1024 MB<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 7 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 10<br></li><li><strong>Processor:</strong> 2.4 GHz Intel i5<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GTX 660 Ti or AMD Radeon HD 7870 w/ 2048 MB<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 7 GB available space</li></ul>\'}', '0', '0,01', '0,01', '0', '0,01'),
(766, 'homeworld remastered collection', '2015', 0, 34, 5377, 827, 353, 26.99, 'Experience the epic space strategy games that redefined the RTS genre. Control your fleet and build an armada across more than 30 single-player missions. Choose unit types, fleet formations and flight tactics for each strategic situation.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows Vista<br></li><li><strong>Processor:</strong> 2.2GHz Dual Core Processor<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce 8800 GTS (512MB) / ATI Radeon HD4800 (512MB)<br></li><li><strong>Storage:</strong> 20 GB available space<br></li><li><strong>Additional Notes:</strong> * Game engine uses OpenGL3.3 It is important that you get the latest drivers for your video card to ensure compatibility with this product.</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7<br></li><li><strong>Processor:</strong> 2.3 GHz Quad Core Processor<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce GTX 560 / ATI Radeon HD 5850 (1GB VRAM)<br></li><li><strong>Storage:</strong> 20 GB available space<br></li><li><strong>Additional Notes:</strong> * Game engine uses OpenGL3.3 It is important that you get the latest drivers for your video card to ensure compatibility with this product.</li></ul>\'}', '0', '0,01', '0', '0', '0,01'),
(767, 'carmageddon max damage', '2016', 18, 30, 1297, 406, 1360, 12.99, 'CARMAGEDDON: MAX DAMAGE is HERE! And it\'s the antidote to Racing Games.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Win 7 64-bit<br></li><li><strong>Processor:</strong> Intel i3-2100 3.1GHz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> 1Gb DirectX 11 (AMD HD 6000 series GPU or equivalent)<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 20 GB available space<br></li><li><strong>Sound Card:</strong> DirectX compatible<br></li><li><strong>Additional Notes:</strong> Laptop versions of graphics cards may work but are NOT officially supported.</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Win 7 64-bit<br></li><li><strong>Processor:</strong> Intel i5-3570 3.4GHz<br></li><li><strong>Memory:</strong> 8 GB RAM<br></li><li><strong>Graphics:</strong> 2Gb DirectX 11 (AMD HD 7800 series GPU or equivalent)<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 20 GB available space<br></li><li><strong>Sound Card:</strong> DirectX compatible<br></li><li><strong>Additional Notes:</strong> Laptop versions of graphics cards may work but are NOT officially supported.</li></ul>\'}', '0,01', '0,01', '0', '0', '0,01'),
(768, 'dokuro', '2014', 0, 31, 32, 8, 0, 6.99, 'This charming, chalk-art puzzler tests your wits and tugs at your hearstrings as the bony underdog Dokuro strives to solve and swashbuckle his way through the Dark Lord\'s castle to save the Princess.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP<br></li><li><strong>Processor:</strong> Intel Core2Duo<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> DirectX 9.0c compatible graphics card<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 200 MB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c compatible sound card</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7<br></li><li><strong>Processor:</strong> 2.3 GHz Quad Core<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> DirectX 9.0c compatible graphics card<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 300 MB available space<br></li><li><strong>Sound Card:</strong> DirectX 9.0c compatible sound card</li></ul>\'}', '0', '0', '0,01', '0', '0,01'),
(769, 'war for the overworld', '2015', 0, 141, 3948, 753, 471, 22.99, 'Tired of invading dungeons? It\'s time you built your own! War for the Overworld is a Dungeon Management Game that employs your favourite aspects of the RTS and God Game genres. Carve out your Dungeon and conquer the Overworld!', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 Service Pack 1 , Windows 8 , Windows 10<br>\\t</li><li><strong>Processor:</strong> Dual Core CPU @ 2.5GHz<br>\\t</li><li><strong>Memory:</strong> 4GB RAM<br>\\t</li><li><strong>Graphics:</strong> Nvidia GT450 512MB or better, ATI 4870HD 512MB or better<br>\\t</li><li><strong><a href=\"https://steamcommunity.com/linkfilter/?url=http://www.videocardbenchmark.net/\" target=\"_blank\" rel=\"noopener\" >G3D Mark</a></strong>: 1500<br>\\t</li><li><strong>Hard Drive:</strong> 7GB available space<br>\\t</li><li><strong>Sound:</strong> Speakers or headphones</li></ul><br><a href=\"https://steamcommunity.com/linkfilter/?url=http://brightrockgames.userecho.com/topics/1099-system-requirements/\" target=\"_blank\" rel=\"noopener\" >Full Knowledgebase Article</a>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 (64-bit) Service Pack 1, Windows 8 (64-bit), Windows 10 (64-bit)<br>\\t</li><li><strong>Processor:</strong> Quad Core CPU @ 2.5GHz<br>\\t</li><li><strong>Memory:</strong> 8GB RAM<br>\\t</li><li><strong>Graphics:</strong> Nvidia GTX 560 1GB RAM or better, Radeon 8950 HD 1GB or better<br>\\t</li><li><strong><a href=\"https://steamcommunity.com/linkfilter/?url=http://www.videocardbenchmark.net/\" target=\"_blank\" rel=\"noopener\" >G3D Mark</a></strong>: 3000<br>\\t</li><li><strong>Hard Drive:</strong> 10GB available space<br>\\t</li><li><strong>Sound:</strong> Speakers or headphones</li></ul><br><a href=\"https://steamcommunity.com/linkfilter/?url=http://brightrockgames.userecho.com/topics/1099-system-requirements/\" target=\"_blank\" rel=\"noopener\" >Full Knowledgebase Article</a>\'}', '0', '0,01', '0', '0', '0,01'),
(770, 'space hulk', '2013', 0, 28, 1292, 556, 87, 18.99, '&quot;WE ARE THE VANGUARD OF HONOUR. THE CUTTING EDGE OF THE BLOOD ANGELS. WE BRING DEATH.&quot;The legendary Space Hulk returns to Windows PC, Mac and Linux in this epic turn based strategy game. Set in the Warhammer 40,000 universe, an intriguing story of legendary battles and heroic actions unfolds.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP<br></li><li><strong>Processor:</strong> 2 GHz Dual Core<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce 8600 GT / ATI Radeon HD 2600 XT or greater<br></li><li><strong>DirectX:</strong> Version 9.0<br></li><li><strong>Storage:</strong> 4 GB available space<br></li><li><strong>Sound Card:</strong> DirectX Compatible</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7<br></li><li><strong>Processor:</strong> 2 GHz Dual Core<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> NVIDIA GeForce 9000 series / ATI Radeon HD 3000 series or greater<br></li><li><strong>DirectX:</strong> Version 9.0<br></li><li><strong>Network:</strong> Broadband Internet connection<br></li><li><strong>Storage:</strong> 4 GB available space<br></li><li><strong>Sound Card:</strong> DirectX Compatible</li></ul>\'}', '0', '0,01', '0', '0', '0,01'),
(771, 'survivor', '2019', 0, 0, 32, 9, 0, 0.00, 'Outwit, Outplay, Outcast.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 and up<br></li><li><strong>Processor:</strong> i5 2.0 ghz+<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> GeForce GTX 460 / ATI Radeon 6850 / Intel HD 5000+<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 1 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 and up<br></li><li><strong>Processor:</strong> i5 2.5 ghz+<br></li><li><strong>Memory:</strong> 6 GB RAM<br></li><li><strong>Graphics:</strong> GeForce GTX 660 / ATI Radeon 7850<br></li><li><strong>DirectX:</strong> Version 11<br></li><li><strong>Storage:</strong> 1 GB available space</li></ul>\'}', '0,01', '0', '0', '0', '0,01'),
(772, 'goat simulator', '2014', 0, 127, 45892, 5779, 309, 7.19, 'Goat Simulator is the latest in high-tech Goat Simulation technology.', '{\'minimum\': \'<strong>Minimalne:</strong><br><ul class=\"bb_ul\"><li><strong>System operacyjny:</strong> Windows Vista<br></li><li><strong>Procesor:</strong> 2.0 GHz Dual Core Processor<br></li><li><strong>Pamięć:</strong> 2 GB RAM<br></li><li><strong>Karta graficzna:</strong> Shader Model 3.0, 256 MB VRAM<br></li><li><strong>DirectX:</strong> Wersja 9.0c<br></li><li><strong>Miejsce na dysku:</strong> 2 GB dostępnej przestrzeni<br></li><li><strong>Karta dźwiękowa:</strong> DirectX 9.0c-compatible, 16-bit</li></ul>\', \'recommended\': \'<strong>Zalecane:</strong><br><ul class=\"bb_ul\"><li><strong>System operacyjny:</strong> Windows 7 or 8<br></li><li><strong>Procesor:</strong> 2.0 GHz Quad Core Processor<br></li><li><strong>Pamięć:</strong> 4 GB RAM<br></li><li><strong>Karta graficzna:</strong> Shader Model 3.0, 512 MB VRAM<br></li><li><strong>DirectX:</strong> Wersja 9.0c<br></li><li><strong>Miejsce na dysku:</strong> 2 GB dostępnej przestrzeni<br></li><li><strong>Karta dźwiękowa:</strong> DirectX 9.0c-compatible, 16-bit</li></ul>\'}', '0', '0,01', '0', '0', '0,01'),
(773, 'getsuei gakuen kou', '2015', 0, 33, 15, 2, 0, 18.99, 'Miracle collaboration work by Tomokazu Sugita, multi-talent voice-cast, and Toshimichi Mori, BLAZBLUE series producer! Please note that this game is only available in Japanese.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 / 8 / 8.1 Japanese version<br></li><li><strong>Processor:</strong> Intel Core2 Duo<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> nVidia GeForce 7900 GT/AMD Radeon X1900<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 4 GB available space<br></li><li><strong>Additional Notes:</strong> Display Resolution 1280×720 and above</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 / 8 / 8.1 Japanese version<br></li><li><strong>Processor:</strong> Intel Core i5/i7<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> nVidia GeForce 7900 GT/AMD Radeon X1900<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 4 GB available space<br></li><li><strong>Additional Notes:</strong> Display Resolution 1280×720 and above</li></ul>\'}', '0', '0', '0,01', '0', '0,01'),
(774, 'kings bounty armored princess', '2009', 0, 0, 482, 53, 1422, 7.99, 'King\'s Bounty: Armored Princess is a sequel to the critically acclaimed King’s Bounty: The Legend.', '{\'minimum\': \'<strong>Minimum:</strong><br>\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP/Vista<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 2.6GHz<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 1GB<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> nVidia GeForce 6600 with 128 MB or equivalent ATI<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 5.5 GB of free space<br>\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX-compatible soundcard<br>\\t\\t\\t\\t\\t\\t\\t</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br>\\t\\t\\t\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP/Vista <br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 3 GHz<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> 2 GB<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> nVidia GeForce 7950GT with 512 MB or equivalent ATI<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> 5.5 GB of free space<br>\\t\\t\\t\\t\\t\\t\\t\\t\\t</li><li><strong>Sound:</strong> DirectX-compatible soundcard<br>\\t\\t\\t\\t\\t\\t\\t\\t</li></ul>\'}', '0', '0,01', '0', '0', '0,01'),
(775, 'muvluv alternative', '2018', 0, 19, 252, 8, 0, 30.99, 'Playtime\'s over. Time for despair. Experience the definitive version of a masterpiece in the Muv-Luv trilogy\'s thrilling conclusion. Note: therapy not included.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> 1024x768<br></li><li><strong>Storage:</strong> 4 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 8.1, Windows 10<br></li><li><strong>Processor:</strong> Windows 8.1 / 10 Tablets - Intel Atom Z, Microsoft Surface Pro 4, Samsung Galaxy Book<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> 16:9 high resolution display<br></li><li><strong>Storage:</strong> 4 GB available space</li></ul>\'}', '0', '0', '0,01', '0', '0,01'),
(776, 'hospital tycoon', '2009', 0, 0, 175, 301, 119, 3.49, 'Develop your own hospital drama and manipulate the results to your best advantage! In charge of a rapidly expanding hospital, your job is to cure the patients with your army of doctors and nurses while successfully managing the facilities and taking care of everyone\'s needs.', '{\'minimum\': \'<strong>Minimum: </strong> <br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>Supported OS: </strong>Windows XP <br>\\t\\t\\t\\t\\t</li><li><strong>Processor: </strong>Pentium 4 @ 1.6 GHz or Athlon 1600+ <br>\\t\\t\\t\\t\\t</li><li><strong>System Memory: </strong>512MB RAM <br>\\t\\t\\t\\t\\t</li><li><strong>Video Card: </strong>GeForce 3 / Radeon 8500* <br>\\t\\t\\t\\t\\t</li><li><strong>Sound Card: </strong>DirectX Compatible Sound Card <br>\\t\\t\\t\\t\\t</li><li><strong>DirectX Version: </strong>DirectX 9.0c <br>\\t\\t\\t\\t\\t</li><li><strong>Hard Disk: </strong>750 MB Hard Drive Space </li></ul>*Supported Graphics Cards:<br> ATi Radeon 8500, 9000, 9100, 9200, 9500, 9600, 9700, 9800, X300, X600, X700, X800, X1300, X1600, X1800, X1900, X1950<br> nVidia Geforce 3-series, 4-series (Not MX), FX5200, FX5600 FX5700, FX5950, 6600, 6800, 7100, 7300, 7600, 7800, 7900, 7950, 8800. <br> Not compatible with all integrated sound/graphics solutions (inc. Laptops).\', \'recommended\': \'<strong>Recommended: </strong> <br>\\t\\t\\t\\t\\t<ul class=\"bb_ul\"><li><strong>Supported OS: </strong>XP/Vista <br>\\t\\t\\t\\t\\t</li><li><strong>Processor: </strong>Pentium 4 2.8Ghz or Athlon 2800+ or above <br>\\t\\t\\t\\t\\t</li><li><strong>System Memory: </strong>1GB RAM <br>\\t\\t\\t\\t\\t</li><li><strong>Video Card: </strong>GeForce 6600 / Radeon X1300 or above* <br>\\t\\t\\t\\t\\t</li><li><strong>Sound Card: </strong>DirectX Compatible Sound Card <br>\\t\\t\\t\\t\\t</li><li><strong>DirectX Version: </strong>DirectX 9.0c <br>\\t\\t\\t\\t\\t</li><li><strong>Hard Disk: </strong>1.5 GB Hard Drive Space </li></ul>\'}', '0', '0,01', '0', '0', '0,01'),
(777, 'summer athletics', '2009', 0, 0, 14, 10, 0, 15.99, 'Get ready, set, go! Summer Athletics brings the action and excitement of the 26 most popular summer sporting disciplines right into your living room! The charming 3D comic style and varying levels of difficulty makes Summer Athletics great fun for the whole family.', '{\'minimum\': \'<ul>\\n\\t <li><strong>OS:</strong> Windows 2000/XP/Vista</li>\\n\\t <li><strong>Processor:</strong> Pentium 1.4 GHz</li>\\n\\t <li><strong>Memory:</strong> 1024 MB RAM</li>\\n\\t <li><strong>Graphics:</strong> 100% DirectX 9.0c-compatible 3D Graphics Card with 256 MB Video RAM</li>\\n\\t <li><strong>DirectX®:</strong> DirectX 9.0c</li>\\n\\t <li><strong>Hard Drive:</strong> 4.7 GB Free Space</li>\\n </ul>\'}', '0', '0,01', '0', '0', '0,01'),
(778, 'spore galactic adventures', '2009', 0, 0, 1943, 453, 1905, 9.99, 'Take Your Creature From Zero To Galactic Hero Get out of your starship and turn your Spore creatures into legendary Space Captains. For the first time, beam down with your allies to take on action-packed, planetside adventures.', '{\'minimum\': \'<ul class=\"bb_ul\"><li><strong>Supported OS:</strong> Microsoft Windows XP Service Pack 2 &amp; Windows Vista Service Pack 1<br>\\t\\t\\t\\t\\t <br>\\t\\t\\t\\t\\t</li><li><strong>Processor:</strong> 2.0 GHz P4 Processor or equivalent <br>\\t\\t\\t\\t\\t</li><li><strong>Memory:</strong> (XP) 512MB (Vista) 768 MB <br>\\t\\t\\t\\t\\t</li><li><strong>Graphics:</strong> 128MB Video Card with support for Pixel Shader 2.0 <br>\\t\\t\\t\\t\\t</li><li><strong>Hard Drive:</strong> At least 2GB of hard disk space without creations <br>\\t\\t\\t\\t\\t</li><li><strong>DirectX9®:</strong> DirectX 9.0c<br>\\t\\t\\t\\t\\tFor computers using built-in graphics chipsets under Windows,<br>the game requires at least: <br>\\t\\t\\t\\t\\t</li><li>Intel Integrated Chipset, 945GM or above <br>\\t\\t\\t\\t\\t</li><li>2.6 GHz Pentium D CPU, or 1.8 GHz Core 2 Duo, or equivalent <br>\\t\\t\\t\\t\\t</li><li>768 MB RAM<br>\\t\\t\\t\\t\\t</li></ul>\'}', '0', '0,01', '0', '0', '0,01'),
(779, '15 days', '2015', 0, 0, 34, 67, 0, 8.99, 'A three-man activist group has set out to make the world a better place by stealing famous pieces of art in the world\'s most renowned museums, selling them to private collectors, and donating the money to charity.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP / Vista / 7 / 8 32 or 64 bit<br></li><li><strong>Processor:</strong> 1,6 GHz Intel or AMD<br></li><li><strong>Memory:</strong> 1 GB RAM<br></li><li><strong>Graphics:</strong> DirectX 9 compliant video card Shader Model 2 and 128 MB VRAM<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 4 GB available space<br></li><li><strong>Sound Card:</strong> DirectX compatible card</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP / Vista / 7 / 8 32 or 64 bit<br></li><li><strong>Processor:</strong> Intel Pentium 4 2.4 GHz or better<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> DirectX 9 compliant video card Shader Model 2 and 256 MB VRAM<br></li><li><strong>DirectX:</strong> Version 9.0c<br></li><li><strong>Storage:</strong> 4 GB available space<br></li><li><strong>Sound Card:</strong> DirectX compatible card</li></ul>\'}', '0', '0,01', '0', '0', '0,01'),
(780, 'teslagrad', '2013', 0, 36, 1581, 258, 449, 6.99, 'A journey begins... A treacherous tower... Unravel its mysteries!Discover the secrets kept in the long abandoned Tesla Tower!Magnetism and other electromagnetic powers will help you explore a non-linear world of beautiful hand-drawn environments, in a steampunk-inspired vision of old Europe.', '{\'minimum\': \'<strong>Minimum:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows XP (SP3)<br></li><li><strong>Processor:</strong> Dual Core 2GHz<br></li><li><strong>Memory:</strong> 2 GB RAM<br></li><li><strong>Graphics:</strong> Hardware Accelerated Graphics with dedicated memory<br></li><li><strong>Storage:</strong> 1 GB available space</li></ul>\', \'recommended\': \'<strong>Recommended:</strong><br><ul class=\"bb_ul\"><li><strong>OS:</strong> Windows 7 or higher<br></li><li><strong>Processor:</strong> Dual Core 4GHz<br></li><li><strong>Memory:</strong> 4 GB RAM<br></li><li><strong>Graphics:</strong> Hardware Accelerated Graphics with 1GB memory<br></li><li><strong>Storage:</strong> 1 GB available space</li></ul>\'}', '0', '0,01', '0', '0', '0,01');
